window.IDW_ITEMS_TR=window.IDW_ITEMS_TR||{};window.IDW_ITEMS_TR["da"]={"ICON-0001":{"nm":"Fodspor","de":"Et enkelt jordfarvet aftryk på gulvbrædderne. Nogen gik frem og tilbage længe, og trådte til sidst et skridt videre. Det, et fodspor indridser, er ikke tiden man blev, men netop det øjeblik man besluttede sig for at gå."},"ICON-0002":{"nm":"Lygte","de":"Når flammen når vægen, viger mørket stille, tomme for tomme. I den lille varme, der varmer fingerspidserne, skrev de gamle engang ønsker og lod dem flyde af sted. En lygte tændes ikke for at lyse, men for at holde en med selskab."},"ICON-0003":{"nm":"Sløjfe","de":"Med én enkelt knude bliver hjertet pænt pakket ind. Let at løse for den hånd, der giver, men langsom at løsne for den, der modtager. Det, en sløjfe binder, er ikke æsken, men den bankende forventning lige før den blev rakt frem."},"ICON-0004":{"nm":"Postkasse","de":"Den står ved gadehjørnet med sin røde mund åben. Selv i en tid, hvor håndskrevne breve er blevet sjældne, venter denne lille kasse trofast til det sidste på en hilsen fra nogen. En kærlig beholder, der lyser klarest i det øjeblik, den bliver tom."},"ICON-0005":{"nm":"Minikort over privatøen","de":"Foldet ligger den i lommen, udfoldet breder havet og bjergryggen sig side om side på et enkelt ark papir. For den, der ankommer for første gang, er hvert eneste hjørne endnu et uåbnet løfte. I det øjeblik det foldes ud, bliver selv en lille ø til en vid verden."},"ICON-0006":{"nm":"Mikrofon","de":"Den halve takt, hvor man samler vejret, lige før den første tone lyder. Fingerspidserne begynder at ryste, når man ved, at publikums blikke venter på ens eneste ord. En mikrofon forstærker ikke lyden, den bærer den skælven hele vejen igennem."},"ICON-0007":{"nm":"Ur","de":"Sekundviseren hviler aldrig, men ingen skynder dig på. Så mange nætter til debut, så mange minutter til scenen — på skiven kredser ventetid og forventning i samme tempo. At se på tiden er at trøste hjertet."},"ICON-0008":{"nm":"Notesbog","de":"Den ting med flest tomme felter af alle. Koreografiens spor, morgengryets forsætter, ord der aldrig blev sendt — alt samler sig her. I det øjeblik man slår den op, taler gårsdagens jeg stille til dagens jeg."},"ICON-0009":{"nm":"Stempel","de":"Fyldt med rødt stempelblæk og trykket fast én gang, indprentes et løfte tydeligt. Et aftryk, tungere end skrift, klarere end ord. For enden af hvert dokument betroede folk deres hjerte til dette lille stempel i stedet for et navn."},"ICON-0010":{"nm":"Underlag","de":"Den sænker sig selv så lavt som muligt for at bære noget andet oppe. Nederst, tavst og udholdende, så det, der hviler ovenpå, ikke vakler. Selv uden at skinne findes her den ømhed, der forhindrer sammenbrud."},"ICON-0011":{"nm":"Frimærke","de":"Et lille billede, man fugtede i hjørnet og trykkede fast. Den mest ærlige pris, sat på et hjerte sendt langt væk. Et firkantet landskab tager brevet i hånden og følger det tværs over havet."},"ICON-0012":{"nm":"Flagnål","de":"Stukket ned i kortet bliver den til et her nåede jeg til. Ikke en erobring, men en optegnelse, og en heppen for den, der kommer efter. Et mærke, der uden ord skubber en videre — se dette flag, og tag bare ét skridt mere."},"ICON-0013":{"nm":"Gren","de":"En gren, der én gang har bøjet sig, glemmer, hvordan man knækker. Hvert sted, den bøjede for vinden, sætter sig en hård, fast knast, og den gamle skov hvisker med vinden, at ægte styrke kommer fra sporene efter det, man har holdt ud."},"ICON-0014":{"nm":"Knap","de":"Den lukkes op og lukkes igen, om og om igen, mens den holder kraven samlet. En lille cirkel holder både morgenkulden og en pludselig rødmen tilbage i stilhed. Først når den knapper af med et klik, opdager man, hvor stor dens plads egentlig var."},"ICON-0015":{"nm":"Konvolut","de":"I det øjeblik dens mund forsegles, bliver den endelig til en hemmelighed. Kun modtageren ved, hvad der ligger indeni. Ét enkelt lag papir lagt mellem hjertet og verden — den tyndeste, mildeste dør af alle."},"ICON-0016":{"nm":"Æske","de":"Med sine fire lige hjørner rummer den alt med gavmildhed. Minder i flyttetiden, gaver til højtiderne, småting til hverdag. Bag det lukkede låg er der altid fyldt med nogens senere."},"ICON-0017":{"nm":"Håndtag","de":"Mellem døren og mennesket er det den, der først rækker hånden frem. Kun ved ét træk forbindes indenfor og udenfor endelig. Enhver beslutning om at gå ind eller ud griber først fat i denne kolde hånd."},"ICON-0018":{"nm":"Ske","de":"Med sin bugtede mund løfter den stille varm suppe op. Et redskab, der husker varmen fra den ske, moren pustede kold og rakte frem først. Ved bordet er den den blideste hånd, den der oftest rører læberne."},"ICON-0019":{"nm":"Tøfler","de":"I det øjeblik man træder over dørtærsklen, trækker fødderne vejret først. Lyden af aftenen, der luntende, skridt for skridt, lægger en klaprende dag bag sig. Et par, sat pænt i entréen, siger: Nu er du hjemme."},"ICON-0020":{"nm":"Nøgle","de":"Man lærer at åbne, før man lærer at låse. Et lille stykke metal, der varmes op i håndfladen, og som en dag standser stille foran en fremmed, ny dør. Den ting, der bevarer en bortdragendes varme længst af alt."},"ICON-0021":{"nm":"Glas","de":"Tomt er det sirligt, fyldt er det varmere end noget andet. I den klare klirren, når to løftes mod hinanden og stødes sammen, gemmer sig et tavst løfte. Et kar, født til at skinne, når det er to, snarere end ét."},"ICON-0022":{"nm":"Tallerken","de":"Inden for sin runde kant rummes en hel dags omhu. Tømt, tørret af og fyldt igen, hele livet igennem — den husholdningsting, der oftest skinner og oftest glemmes. Bordets scene er altid dækket ovenpå den."},"ICON-0023":{"nm":"Lampe","de":"Med ét enkelt afbryder skifter rummets udtryk. Er det klart, er det hverdag; er det dæmpet, er det trøst. Et enkelt lyspunkt, holdt tændt til det sidste for nogen, der kommer sent hjem, bliver verdens varmeste velkomst."},"ICON-0024":{"nm":"Teske","de":"En langsom omgang rundt i tevandet, og blad og vand siver ind i hinanden. En bevægelse uden hast, en lille venten, indtil duften breder sig. Én sølvhånd sænker eftermiddagens tempo med varme."},"ICON-0025":{"nm":"Bogmærke","de":"Et løfte, stille lagt der, hvor læsningen stoppede. Forsættet jeg stoppede her, så jeg kommer helt sikkert tilbage sover mellem siderne. Selvom historien lukkes, er hjertet tydeligt markeret ved den ene linje."},"ICON-0026":{"nm":"Pude","de":"Den tager tavst imod ryg og knæ, der har brug for noget at læne sig op ad. Den synker dybt og hæver sig langsomt igen, mens den opsuger dagens træthed. Den ting, der mest overbærende tillader den dovneste stilling."},"ICON-0027":{"nm":"Ramme","de":"En firkantet kant binder ét enkelt landskab til evigheden. Netop det øjeblik, der kom indenfor, falmer ikke, uanset hvor meget tid der går. Et kærligt valg, mindre om hvad man rummer, og mere om hvad man besluttede sig for at efterlade."},"ICON-0028":{"nm":"Kort","de":"I hver eneste fold hviler sporet af at være faret vild og finde vejen igen. Foldet ud kan man med fingerspidserne først vandre steder, man aldrig har besøgt. Ethvert eventyr begynder med det lille mod, det tager at folde dette ene ark ud."},"ICON-0029":{"nm":"Postkort","de":"Bagsiden er halvt foto, halvt tomt felt. Den, der er rejst langt væk, sender jeg har det godt med stedets landskab ved siden af. Det ærligste stykke papir af alle, hvor en hilsen ikke skammer sig selv uden konvolut."},"ICON-0030":{"nm":"Adgangskort","de":"I det øjeblik det hænges om halsen, træder man endelig ind i den indre verden. Mit navn skrevet på det lille kort tillader stille: her, dette er din plads. Ikke en tilladelse til at passere, men et bevis på at høre til et sted."},"ICON-0031":{"nm":"Bogstavet B","de":"Bogstavet, der oftest kaldes frem midt i et ord. Man må lukke læberne én gang og lade dem springe op, før lyden endelig kommer. Hverken begyndelse eller slutning, men en pålidelig anden plads, der holder rytmen."},"ICON-0032":{"nm":"Visitkort","de":"Rakt frem med begge hænder, modtaget med øjenkontakt. På et enkelt ark papir sammenpresses stille en persons hverdag og stolthed. I det smalle rum mellem navn og titel bosætter dagens første indtryk sig blidt."},"ICON-0033":{"nm":"Omslag","de":"Yderst på historien tager det først imod regn og blæst. Af at beskytte bogstaverne indeni slides dets egne hjørner først. Den korte forventning lige før man slår op begynder altid først med dette ene ark."},"ICON-0034":{"nm":"Lærebog","de":"Med understregninger og overstregningstusch er én persons kamp tæt indskrevet. Uoverskuelig som ny bog, men den bedste ven, når man er igennem den. Sporet af at lære det ukendte at kende ligger fint foldet på hver eneste side."},"ICON-0035":{"nm":"Dansepas","de":"Dette ene ark slår øvelokalets dør vidt op. Et rum fyldt med spejle, lyden af stampende fødder, de første otte takter man nogensinde lærer. Det er okay, hvis dansen stadig er kejtet — et lille stykke papir skubber stille til en skælvende ryg."},"ICON-0036":{"nm":"Ringbind","de":"Ark, der drev omkring løst, bliver samlet pænt på én rygrad og får endelig en orden. Med orden kommer en historie, og jo tykkere den bliver, desto kærligere er beviset på, at nogen har levet lige så meget, side for side."},"ICON-0037":{"nm":"Prøveark","de":"Fingerspidser, der ryster et øjeblik over de tomme linjer. Mere skræmmende end det forkerte svar er at stå ansigt til ansigt med det, man ikke ved. Når rettelsen er overstået, bliver der ved hver fejl stille en margen tilbage, hvor noget kan vokse næste gang."},"ICON-0038":{"nm":"Bogstavet A","de":"Den første lyd, der kun kommer, når munden åbnes vidt. Den står ofte forrest i rækken, allerforrest i et navn. Fordi alt, man begynder, starter med dette bogstav, er det altid lidt mere modigt."},"ICON-0039":{"nm":"Bogstavet D","de":"Med sin blødt buede ryg støtter det stille et ord op. Dets runde side hænger sirligt for enden af nogens navn. Ikke prangende, men savnet, hvis det manglede — en stille følgesvend blandt bogstaverne."},"ICON-0040":{"nm":"Øveark","de":"Det eneste papir i verden, hvor det er okay at fejle. Det lader en skrive den samme bevægelse, den samme sætning, snesevis af gange igen. For hvert krøllet, kasseret ark blev nogen med sikkerhed en lille smule bedre."},"ICON-0041":{"nm":"Kompositionsark","de":"Klokken to om natten vækker en enkelt nynnen én af søvnen. Blyanten tøver over nodelinjerne, fordi melodien er hurtigere end hånden. I hvert visket og genskrevet mærke vokser en endnu navnløs sang lidt efter lidt."},"ICON-0042":{"nm":"Adgangspas","de":"I det øjeblik det hænges om halsen, forvandles en almindelig gang til en anden verden. Kabler slynger sig gennem mørket som slanger, og bag scenen begynder en uhørlig nedtælling. Retten til at træde ind her taler dette ene stykke papir for på ens vegne."},"ICON-0043":{"nm":"Kontaktark","de":"I hvert lille felt står et andet udtryk frosset fast. Griner, kigger tilbage, lukker øjnene. Peger man sig gennem billede for billede, vender den dags bankende hjerte fra lukkerklikket tilbage til fingerspidserne. Selv at vælge ét enkelt billede er allerede en optegnelse."},"ICON-0044":{"nm":"Callsheet","de":"I morgen, hvornår, hvor og hvad. Et enkelt ark tegner på forhånd en dags rute op. Mellem felter tætpakket minut for minut følger nogen ordenen skrevet her og går skridt for skridt mod en drøm."},"ICON-0045":{"nm":"Mærkeseddel","de":"Bag prisskiltet hænger stille skaberens tid. Først med det korte snip, hvor man river det af, bliver det lille stykke papir endelig ens eget. Det, der bliver tilbage ved snittet, er duften af noget nyt og en håndfuld forventning."},"ICON-0046":{"nm":"Portfolio","de":"Vend forsiden om, og hele den tilbagelagte vej folder sig ud på én gang. Ved siden af et selvsikkert ark ligger genert det første, kejtede forsøg. Når man for første gang rækker sig selv frem til nogen, findes ingen mere ærlig introduktion end denne."},"ICON-0047":{"nm":"Planner","de":"Man skriver dagen i dag, tegner næste uge, og nu og da farver man en enkelt boks helt sort. Selv når intet går som planlagt, stopper hånden aldrig med at udfylde boksene. En lille ritual, næsten som at leve fremtiden igennem én gang på forhånd."},"ICON-0048":{"nm":"Playliste","de":"Mellem langsomme sange og hurtige takter stiller man sangene på række efter dagens sindsvejr. Tænker man sig, at nogens hele dag forløber præcis i denne rækkefølge, bliver selv stilheden mellem sangene mild."},"ICON-0049":{"nm":"Studiekort","de":"Et navn, et foto og nogle få tal. Et enkelt kort, der beviser tiden med at pendle mellem klasseværelse og øvelokale. På kortet, slidt i hjørnene af at gå ind og ud af lommen, sidder friske, uigenkaldelige hverdage indprentet."},"ICON-0050":{"nm":"Armbånd","de":"Kan du huske øjeblikket, hvor dagens farve blev bundet om håndleddet? Sloganerne råbt sammen, koncertnatten I blev våde i sammen. Selv når båndet slides og farven falmer, løsnes det ikke — fordi man ønsker at lade den sommer blive ved med at leve på håndleddet."},"ICON-0051":{"nm":"Armbind","de":"I det øjeblik det bindes om armen, lægger vægten af ansvar sig stille til. Mærket for den, der står forrest i rækken og forlader posten sidst. Ét stykke stof får nogen til at vokse en anelse mere."},"ICON-0052":{"nm":"Ring","de":"En enkelt linje, rundt og ubrudt. Fordi start og slutning mødes, ser folk her evighedens form. Fører man stille to hænder sammen, forbliver et løfte som en form, før ordene overhovedet kommer."},"ICON-0053":{"nm":"Medalje","de":"I det lille stykke metal fæstet på brystet er de udholdte dage indgraveret. Det, der skinner, er ikke metallet, men de utallige øvenætter gemt bagved. Det, der fylder først, før stoltheden, er af en eller anden grund taknemmelighed."},"ICON-0054":{"nm":"Forklæde","de":"Bind snoren om halsen, og begge hænder bliver fri. Et signal om at være klar til at fordybe sig i noget — mel eller maling, lige meget. Jo flere pletter der samler sig, desto dybere bliver den omsorg, man lagde i den dag."},"ICON-0055":{"nm":"Ørevarmer","de":"Pakket tæt om ørerne trækker lyden udenfor sig et skridt væk. På skolevejen i den bidende vind, et lille fristed man gemmer sig i, i det bløde indre. Vinterens varme begynder somme tider, netop sådan, fra ørespidserne."},"ICON-0056":{"nm":"Kostume","de":"Før tæppet går op, hænger et sæt tøj og holder vejret på bøjlen. I hver eneste søm er koreografien foldet ind. I det øjeblik armen føres igennem, bliver personen til en rolle, og scenen bliver dragtens andet lag hud."},"ICON-0057":{"nm":"Krone","de":"I det øjeblik den sættes på hovedet, retter en bøjet ryg sig af sig selv. Det gyldne skær hvisker om ansvar, før det hvisker om magt. Den kølige vægt mod panden fortæller det: jo mere strålende pladsen er, desto tungere er den."},"ICON-0058":{"nm":"Kappe","de":"Kastet om skuldrene flagrer vinden bag ryggen. Den følelse af, at et stykke stof følger med for hvert løb. Mindre et heltetegn, mere et barnehjertes ønske om blot at se sej ud."},"ICON-0059":{"nm":"Maske","de":"Dækker man ansigtet, bliver man tværtimod mere ærlig. Ligesom i de gamle gårdspil, hvor man lo og græd frit bag masken. Bag det skjulte udtryk siver den ægte stemme, man ellers holder tilbage, ud endnu højere."},"ICON-0060":{"nm":"Læbestift","de":"Vrid låget af, træk én streg, og en lille beslutsomhed rejser sig ved læberne. Sidste tjek foran spejlet, en rød linje malet ovenpå tvivlen. I det korte øjeblik farven lægges på, viger frygten stille til side."},"ICON-0061":{"nm":"Jakke","de":"Når skulderlinjen sidder helt rigtigt, bliver man en anelse stærkere. Smøg ærmerne op, og sindet er klar til arbejde; rejs kraven, og sindet er klar til at gå ud. Ét sæt tøj bestemmer stille dagens holdning."},"ICON-0062":{"nm":"Taekwondobælte","de":"Hver gang farven skifter et niveau, ændres også mængden af sved samlet under den. Morgenerne i dojangen, hvor man strammede knuden og bukkede dybt. Gennem fingerspidserne, der binder bæltet, samles et spredt sind igen."},"ICON-0063":{"nm":"Beskyttelsesbriller","de":"Sat foran øjnene bliver verden en tone klarere. Bag det runde skjold, der holder både vind og støv ude, skinner selv den almindelige vej, man altid går, af en eller anden grund som en startlinje."},"ICON-0064":{"nm":"Handske","de":"Tag den på hånden, og modet til at gribe fast om hvad som helst vokser frem. Fingre, der trak sig sammen af frygt for at tabe noget, folder sig endelig helt ud. Det, der beskyttes, er hånden, men det, der egentlig værnes om, er udfordringen, der venter derefter."},"ICON-0065":{"nm":"Mundbind","de":"Dækker man munden, taler øjnene desto mere. På en travl gade, den lille anonyme frihed man nyder bag et let skjul. Derfor spreder det smil, der bliver tilbage, når det hele til sidst tages af, sig endnu klarere."},"ICON-0066":{"nm":"Hat","de":"Sænk skyggen en anelse, og både sollys og blikke glider forbi. Under det lille tag på hovedet må man i dag i det mindste gerne gå med et afslappet ansigt. Den letteste forvandling begynder altid netop her."},"ICON-0067":{"nm":"Skjorte","de":"Et raslende lyd, og den nystrøgne krave dufter af morgen. Mens knapperne lukkes i orden fra toppen og ned, bliver et rodet sind pænt igen, felt for felt. Ét hvidt stykke tøj åbner dagens første sætning."},"ICON-0068":{"nm":"Tørklæde","de":"En omgang om halsen, og vindens passage lukkes. Mens enderne vipper let ved skuldrene, når kulden ikke længere helt ind. Et stykke stof lagt et sted mellem stil og varme."},"ICON-0069":{"nm":"Handsker","de":"Pakket helt om til fingerspidserne er selv det kolde ikke skræmmende. Vinterens lille luksus, hvor hænder man pustede varme på, langsomt bliver hyggelige af sig selv. Én taget af og rakt frem kan varme en andens hånd."},"ICON-0070":{"nm":"Erkendelsesmærker","de":"To tynde plader vender stille mod hinanden. Et par navne og nogle få numre — det er, hvad der lader nogen blive husket til det sidste. Koldt metal, og alligevel ligner det på en eller anden måde det varmeste løfte."},"ICON-0071":{"nm":"Griberring","de":"Før en finger igennem, og bekymringen for at tabe den forsvinder stille. En lille tryghed, der lader én holde og vifte rigeligt selv med én hånd. Når armen strækkes langt ud for at fange ét billede, støtter den stille håndfladen."},"ICON-0072":{"nm":"Blomsterkrans","de":"Sat på hovedet følger et favnfuld forår med. Blomster plukket på marken og flettet rundt lægger sig blidt om panden. Over det lyse smil på billedet dvæler en svag duft af græs længe."},"ICON-0073":{"nm":"Sovemaske","de":"Dækker man øjnene, viger både lys og larm på én gang. Uden syn er det eneste, man hører, sin egen vejrtrækning. Sluk verden en stund og træd ind i den indre stilhed, og en lille dør lukker stille bag ryggen."},"ICON-0074":{"nm":"Halstørklæde","de":"Én omgang, to omgange — for hver gang den vikles om halsen, blødgøres vinteren en smule. Et sted mellem uldtrådene er måske vævet et hjerte, nogen strikkede ind. Begraver man sig helt op til næsetippen, bliver verden straks hyggeligere."},"ICON-0075":{"nm":"Halvmaske","de":"Med kun den halve del af ansigtet skjult begynder maskeballets nat. De blottede læber smiler, de skjulte øjne rummer en hemmelighed. Det smalle mellemrum af næsten-at-vide-hvem sætter midnatsluften i sitren."},"ICON-0076":{"nm":"Baret","de":"Sat lidt på skrå tilføjer den stille stemning til en almindelig dag. Ét rundt, fladt stykke stof klæder skuldrene i en kunstners luft. Selv det korte øjeblik foran spejlet, hvor man vælger vinklen, er en fornøjelse."},"ICON-0077":{"nm":"Choker","de":"Tæt om halsen samler blikket sig naturligt opad. Ét tyndt bånd ændrer stemningen fuldstændigt. Lille, men tydeligt, som en lås der fylder dagens selvtillid op."},"ICON-0078":{"nm":"Parka","de":"Træk lynlåsen helt op, og selv snestormen viger et skridt. Stik hænderne dybt ind i det tykke indre, og hele verdens larm falder til ro. Et lille hus, der forbliver varmt selv i den barskeste vind."},"ICON-0079":{"nm":"Bukser","de":"Før fødderne igennem, luk om livet, og først da er man klar til at gå ud. For hvert skridt bevæger stoffet sig blødt med sin vævning. Et sted mellem komfort og sirlighed begynder dagen."},"ICON-0080":{"nm":"Piercing","de":"Selv at tilføje ét lille punkt kræver en smule mod. Ét glimtende stykke metal sætter et tydeligt punktum ved et almindeligt øre. Meget lille, men et lys der tydeligt afspejler et i dag, der er blevet anderledes."},"ICON-0081":{"nm":"Bølgeform","de":"For en tekniker høres en sang ikke — den ses. I de op- og nedadgående kamme på skærmen læser man, hvor vejrtrækningen skælvede den dag. En stemme, man ellers ikke kunne se, ligger som en bjergkæde og folder et helt nummers landskab ud."},"ICON-0082":{"nm":"Stemmeapparat","de":"Lige før koncerten stryger man de seks strenge igennem, én for én, og sætter forskudte toner tilbage på plads. Selv en halv grad forkert opdager publikum som spøgelser. At stemme så præcist, at ingen kan mærke det — det er ømheden rettet mod scenen."},"ICON-0083":{"nm":"Strop","de":"Viklet én gang om håndleddet løses bekymringen for at tabe noget stille op. Det mest skræmmende på scenen er at miste noget fra hånden, så med denne ene lille strop falder hjertet endelig til ro."},"ICON-0084":{"nm":"Bækken","de":"I det ene øjeblik, de støder sammen, sættes et tydeligt punktum på sangens sidste sætning. Den gyldne skive ved, hvordan man klinger kortest og efterlader det længste efterklang. Sådan skal en afslutning lukkes — lyst og klart."},"ICON-0085":{"nm":"Guitar","de":"Når fingrene glider over de seks strenge, bliver et trangt rum til en hel scene. Nogens første melodi, en søvnløs nats hviskede ord til sig selv — alt sammen trak vejret først inde i denne runde trækasse."},"ICON-0086":{"nm":"Lydsky","de":"I den ene ende af himlen klumper nodetegn sig sammen som vat og driver svævende af sted. Man siger, at når vinden fejer forbi én gang, falder der melodier i stedet for regndråber, så øens børn går ud og møder den uden så meget som en paraply."},"ICON-0087":{"nm":"Trin","de":"Scenens bevægelser er regnestykker, løst med tåspidserne. Ét skridt her, en halv takt der — det er okay at fejle, så tag det langsomt. Felterne, trådt hundredvis af gange og indprentet i kroppen, samles og fuldender endelig kortet over ét nummer."},"ICON-0088":{"nm":"Forstærker","de":"En kasse, der forvandler hvisken til brøl. Alligevel stopper hånden altid, lige før volumen skrues et hak op. At en mere præcis lyd, ikke en højere, når helt ud til den bageste række — det ved denne kasse."},"ICON-0089":{"nm":"Nodevat","de":"Når de bønnespirelignende nodehoveder samles til en vatklump, bliver den blød som en pude. Lægger man stille hovedet på den, siger rygtet — øens kærligste — at en næsten-uhørlig vuggevise strømmer frem."},"ICON-0090":{"nm":"Kassettebånd","de":"Tryk på tilbagespoling og — knirk — båndet spoler langsomt tilbage til den sommers første sang. Inde i den lille kasse, hvor en hel tidsalder er spolet op, sover tiden, man aldrig kan røre igen, fuldstændig urørt."},"ICON-0091":{"nm":"Stemmegaffel","de":"Slå let på den tvegrenede metalgren, og én referencetone fødes i luften. For denne lille skælven bøjer alle instrumenter stille hovedet i takt. Begyndelsen på hvad som helst kommer fra en vibration så sart som denne."},"ICON-0092":{"nm":"Bølgeformchip","de":"Et lydfragment fanges blidt inde i en chip på størrelse med en negl. En tilfældig udbrydning, aldrig optaget med vilje, latteren fra nogen man troede var forsvundet — heri lever og ånder de stadig, varme som altid."},"ICON-0093":{"nm":"LP","de":"Når nålen tager sit første skridt langs rillen, høres en svag, knitrende vejrtrækning først. Nogle elsker selv den lille støj så højt, at de aldrig, til det sidste, kan give slip på denne sorte skive."},"ICON-0094":{"nm":"Lomme","de":"Det, man værner mest om, gemmer man altid tættest på hjertet. En håndfladestor stofpose bliver en dag til en håndvarmer, en anden dag til en amulet, og endnu en dag til et gemmested for hemmeligheder."},"ICON-0095":{"nm":"Plaster","de":"På nætter, hvor øvelsen trækker ud, sætter der sig en lille medalje på hver hæl. Et plaster sat på for at sluge ordet det gør ondt — et stille løfte, ingen kender, om at danse igen i morgen, koste hvad det vil."},"ICON-0096":{"nm":"Hovedpude","de":"Stedet, hvor man til sidst lægger en hel dags scene fra sig, er trods alt dette ene bløde, firkantede stykke. Lægger man hovedet stille ned, dæmpes klapsalverne, der hang ved ørerne, langsomt, og natten falder endelig også over øen."},"ICON-0097":{"nm":"Klokke","de":"Ding — ét kort lyd, og nogen skubber døren op og træder ind. Et signal om, at en gæst er kommet, en hilsen om, at dagen er åbnet. Ét lille stykke metal tager sig hele dagen kun af at ringe velkomst."},"ICON-0098":{"nm":"Etui","de":"Jo mere dyrebar en ting er, desto stærkere et hus bygger man den. At hånden, der åbner og lukker, hver gang bliver forsigtig, skyldes, at det, der ligger indeni, ikke blot er en genstand, men et hjerte man ikke kan bære at miste."},"ICON-0099":{"nm":"Børste","de":"Stryger man med hver eneste børstehårs retning, viger støv, der har sat sig fast i krogene, stille. Fordi der findes en hånd, der ikke skyr selv de usynlige steder, møder rummet en ny morgen hver dag."},"ICON-0100":{"nm":"Skitse","de":"Linjerne før fuldendelse gider ikke skjule deres tøven. I hvert visket og gentegnet mærke forbliver, hvad de ønskede at blive, uden løgn. Jo mere kejtet begyndelsen er, desto ærligere er den."},"ICON-0101":{"nm":"Dukke","de":"Der findes væsener, der trøster, blot ved at blive holdt tavst i favnen. Den bomuldsbløde ven, der lå og rystede ved siden af puden de nætter, hænderne dirrede bag scenen – alle gemmer på sådan en et sted i hjertet."},"ICON-0102":{"nm":"Klokke","de":"Tempelklokken i bjergene ringer én gang og krydser en hel dal. Det er metallets hjerte, der længes efter at nå langt, langt bort, og græder langt ud, så lyden synker langsomt til ro i lytterens bryst."},"ICON-0103":{"nm":"Paraply","de":"Deler man én, bliver den ene skulder uvægerligt våd. Under paraplyen, der hælder en anelse til siden, er den våde skulder det klareste bevis på omsorg. En kort gåtur under samme tag bliver længe i hjertet."},"ICON-0104":{"nm":"Måtte","de":"Ruller man den ud på det bare gulv, bliver stedet straks til et øvelokale. Et sted, der tavst tager imod, når man ruller og falder – utallige bevægelser fandt her for første gang vej ind i kroppen."},"ICON-0105":{"nm":"Bjælde","de":"Ryst den blidt, og en klar, klingende lyd triller frem i hånden. Den lille, runde glæde, som børn i gamle dage bandt til kanten af deres regnbuestribede jakker og løb rundt på gårdspladsen med, vågner igen på din håndflade."},"ICON-0106":{"nm":"Legetøjsslange","de":"Dens lange, dinglende form forskrækker drilsk folk med et pludseligt sæt. Bange, på flugt, og til sidst bristende i latter – selv sådan et pus er i sidste ende en gren af omsorg for hinanden."},"ICON-0107":{"nm":"Legetøj","de":"Alle har en æske, de ikke rigtig kan få sig selv til at smide ud, selv som voksne. Deri ligger latteren fra de mest lysende dage stadig strammet op som en fjeder, der aldrig blev sluppet."},"ICON-0108":{"nm":"Spisebakke","de":"Fold benene ud, og ethvert sted bliver straks til familiens plads. Lyden af skeer, der klirrer, mens alle samles omkring den – det beskedne samspil er den varmeste sang blandt alle dagens toner."},"ICON-0109":{"nm":"Sæbe","de":"Den bliver lidt mindre for hver gang i hånden og gør stille nogen ren. At slide sig selv op for at vaske en anden – først længe efter at boblerne er falmet, viser det stille hjerte sig endelig."},"ICON-0110":{"nm":"Kam","de":"Ligesom den løsner sammenfiltret hår, tot for tot, bliver en rodet dag også gradvist ordnet. Ét kort strøg foran spejlet ordner ubemærket, ud over håret, selv hjertets fatning."},"ICON-0111":{"nm":"Fuglebur","de":"Der findes en fugl, der synger uden at flyve væk, selv med døren vidt åben. Et hjerte, der bliver ikke fordi det er fanget, men fordi det ønsker at blive – den fine forskel mærker dette bur før nogen anden."},"ICON-0112":{"nm":"Håndvarmer","de":"I vinterens ventekø uden for koncertstedet varmer en lille varme i lommen forsigtigt stivfrosne fingre op. En håndfladestor omsorg, som nogen rystede varm på forhånd, mens de tænkte på dig, der sad og frøs."},"ICON-0113":{"nm":"Lommetørklæde","de":"Et enkelt stykke stof, der tager imod både tårer og sved uden en lyd. Det lille broderi i hjørnet dvæler der smukt, som en sidste hilsen fra en, der rejste bort først, en påmindelse om ikke at glemme."},"ICON-0114":{"nm":"Spray","de":"Ét pift, og luftens væv skifter på et øjeblik. Tågen der breder sig over scenen, planten ved morgenvinduet – i disse fine dråber bliver de begge for et øjeblik til en anden verden og glitrer."},"ICON-0115":{"nm":"Duftstrimmel","de":"At vælge en duft ligner på underlig vis at vælge et minde. En enkelt tråd af duft, dryppet på spidsen af et tyndt stykke papir, fører sagte en årstid, man troede glemt, tilbage til næsen."},"ICON-0116":{"nm":"Spisebord","de":"I hver slidt årring i træet er antallet af måltider, man har delt sammen, stille indridset. De støjende aftener, de sene nætter tilbragt alene – dette firkantede bord tog dem alle imod uden et ord og fik patina af det."},"ICON-0117":{"nm":"Trådnøgle","de":"Trækker man forsigtigt i den ene ende, ruller den glat ud; ét sting, og den er samlet igen. At sy det knækkede sammen begynder altid stille, akkurat sådan, fra en enkelt tynd trevle tråd."},"ICON-0118":{"nm":"Regnfrakke","de":"Selv på øsende dage er det denne ene beklædning, der til sidst får en ud ad døren. Kun den, der kender glæden ved at soppe gennem regnen, bruger ikke vejret som undskyldning for at blive hjemme."},"ICON-0119":{"nm":"Snørepose","de":"Snører man munden rund, bliver det, der er indeni, endelig trygt. I én lille, medtaget pose vugger mønter, et minde fra en bestemt dag og ord, der aldrig helt blev sagt, sammen."},"ICON-0120":{"nm":"Bogreol","de":"Lader man fingeren glide langsomt hen over bøgernes rygrader, kan man mærke de svundne årstider ved fingerspidserne. At man ikke kan bære at kassere en udlæst bog, er fordi den, man var dengang, stadig bor der."},"ICON-0121":{"nm":"Bogstabel","de":"Læste bøger lægges ned på siden; ulæste bøger stables op ovenpå. Selv når løftet om engang at læse dem alle vipper en smule nær loftet, elsker man ligefrem den vippen og lægger i dag endnu et bind på."},"ICON-0122":{"nm":"Løbehjul","de":"Det kan føles, som om man bliver på stedet, uanset hvor ivrigt man løber, men de små fødder lærer først tæernes rytme. De gårsdage, der aldrig stoppede, samler sig, og en dag skinner de klart på en rigtig vej."},"ICON-0123":{"nm":"Betræk","de":"Så støvet ikke lægger sig, så solen ikke blegner det – selv det at dække til kræver omhu fra fingerspidserne. Jo mere man holder af noget, desto mere kærligt beskyttes det, der hvor man ikke ser."},"ICON-0124":{"nm":"Garn","de":"En enkelt tråd, der trillende rullede ud fra mormors skød. Den kan se sammenfiltret ud, men finder man enden og trækker forsigtigt, følger den ufejlbarligt efter. Sådan blev vinteraftenerne lange, maske for maske."},"ICON-0125":{"nm":"Necessaire","de":"Læbepomade, et hårelastik, et pænt sammenfoldet brev – ser lille ud, men deri gemmer sig en hel dags hjerte. Med lyden af lynlåsen, der lukkes, bliver alle de kære smådele på én gang trygge."},"ICON-0126":{"nm":"Armlæn","de":"En eftermiddag, hvor man faldt i søvn over en bog, en aften, hvor man gik frem og tilbage i telefon. På stedet, der får mere patina jo længere man sidder, har al den hvile, albuen husker, stille samlet sig en håndsbredde."},"ICON-0127":{"nm":"Pakke","de":"Indtil den bliver revet op, tilhører den endnu ingen. En forseglet pose bugner af uindfriede forventninger, så fingerspidserne, der griber om hjørnet, dirrer let. Det er glæden ved at åbne."},"ICON-0128":{"nm":"Gavepapir","de":"Et hjerte, der ankommer et skridt før gaven selv. Mens man folder hjørnerne til og binder en sløjfe om, folder modtagerens smilende ansigt sig allerede lyst ud i hænderne."},"ICON-0129":{"nm":"Gamepad","de":"Knapper, som tommelfingrene husker før hovedet gør. Tabte man, så bare ét spil mere – og det ene spil ender med at holde en oppe hele natten. Vægten, der passer perfekt i hånden, løfter stille aftenens eventyr."},"ICON-0130":{"nm":"Trafiksignal","de":"Rødt betyder stands lidt, grønt betyder nu må du gå. Med ét enkelt løfte flyder utallige veje uden at filtre sig sammen. At selv ventetid har sin tur, fortæller det blinkende lys venligt."},"ICON-0131":{"nm":"Pil","de":"Den venligste figur for den, der har mistet vejen. Når det er svært at vide, hvor man skal hen, gør én retning, som nogen har tegnet på forhånd, de standsede skridt faste igen."},"ICON-0132":{"nm":"Koordinater","de":"Med blot to tal kan man udpege ethvert sted i verden. Stedet, man aftalte at mødes, sandstranden, hvor en skat blev gravet ned. Så et løfte ikke skal fare vild, holder ét lille punkt fast til det sidste."},"ICON-0133":{"nm":"Flise","de":"Alene er den blot et firkantet stykke. I det øjeblik de lægger sig side om side, skulder ved skulder, bliver de til et gulv og en væg. Små ting samles og skaber et sted, hvor nogen trygt kan sætte foden."},"ICON-0134":{"nm":"Timeglas","de":"Når det øverste kammer tømmes, fyldes det nederste langsomt op. Ser man sandet risle blødt nedad, tror man, at tiden flyder. Vender man det, begynder det forfra – det er sandets venlige lille løgn."},"ICON-0135":{"nm":"Bold","de":"Kaster man den, kommer den tilbage; sparker man den, ruller den af sted. At være rund, at aldrig vide hvor den springer hen, er dens største charme. Midt på legepladsen begyndte latteren altid rundt fra netop denne lille kugle."},"ICON-0136":{"nm":"Kontakt","de":"Klik – tændt med ét tryk, slukket med ét tryk. Den lille lyd, man laver, når man træder ind i et mørkt værelse, deler en spredt dags begyndelse og afslutning i én klar streg."},"ICON-0137":{"nm":"Spørgsmålstegn","de":"At ikke kende svaret er intet at skamme sig over. Det er det kærkomne bevis på, at nysgerrigheden stadig lever. Når denne lille krog banker let på sindet, tager læringen for alvor sit første skridt."},"ICON-0138":{"nm":"Tændstik","de":"En enkelt pind, der stryger sig selv for at give ild videre. Den brænder kort og forsvinder stille, men i det korte øjeblik tændes et lys, og et ildsted varmes op. En lille gave bliver varmens første knap."},"ICON-0139":{"nm":"Skammel","de":"Stiller man sig blot op på den, når hånden selv den hylde, man ellers ikke kunne nå. At forlænge nogens højde et øjeblik. Her er et venligt sted, der ligger lavt og sagte løfter os højere."},"ICON-0140":{"nm":"Armbåndsur","de":"Det første, man spændte om håndleddet den dag, man besluttede sig for at træne. En lille træner, der tæller hjerteslag og skridt, banker let for at fortælle, at man i dag gik lidt længere end i går."},"ICON-0141":{"nm":"Alarm","de":"Den mest trofaste ven, forhadt hver eneste morgen. Fordi den kæmper i ens sted mod de fem minutters fristelse under dynen, hver gang, kommer man aldrig for sent til hverken aftaler eller drømme. Den irriterende lyd er i virkeligheden en heppen."},"ICON-0142":{"nm":"Kerne","de":"Det inderste, der bliver tilbage, når alt det ydre er skrællet af. Æblets kerne, hjertets sande følelse – uanset hvad, gemmer selve midten det hårdeste. Det ene punkt, der til sidst består, selv når det rystes."},"ICON-0143":{"nm":"Kuglepen","de":"Pletten, der sagte smittede af på håndkanten, før blækket nåede at tørre. Uanset om det skriver godt eller skidt, kræver det første strøg foran et hvidt ark altid en smule mod. Den er broen, hvorover tanken vandrer ud til fingerspidserne."},"ICON-0144":{"nm":"Pensel","de":"Når den mættet af blæk glider hen over hanjipapiret, bliver selv en tøvende dirren stående helt intakt. Bliver man grådig og haster med at skrive, opdages det med det samme. Penslen er den første til at kende ærligheden, der bor i fingerspidserne."},"ICON-0145":{"nm":"Talebobbel","de":"Stedet, der dukker rundt op over hovedet, før ordene når helt ud af munden. Den ene sætning, man ønsker at sige, holdes her. Er den tom, er den midt i at vælge, hvad den skal fyldes med."},"ICON-0146":{"nm":"Afkrydsningsfelt","de":"Tegner man to streger i det tomme felt, bliver hjertet så meget lettere. En lille medalje, man selv tildeler for en fuldført opgave. Ved dagens ende ser man på de udfyldte felter og beroliger sig selv med, at man også i dag har levet godt."},"ICON-0147":{"nm":"Tablet","de":"Billeder breder sig, og bogstaver flyder, hvor end fingrene rører. Lægger man den blot i skødet, tændes en hel verden lyst op. Let er den, men mulighederne, der gemmer sig indeni, er langtfra tynde."},"ICON-0148":{"nm":"Fjernbetjening","de":"Den har et medfødt talent for at gemme sig i sofaens sprækker. Magten til at skifte kanal tilhører altid den, der holder den. Familiens mindste og kæreste skænderi udspiller sig altid over denne ene håndsbredde."},"ICON-0149":{"nm":"Modvægt","de":"En vægt, der har sænket sig selv helt ned til bunden for at holde fast i det, der svajer. Uanset hvor meget toppen vakler, vælter det aldrig, hvis bunden er tung nok. Balance holder altid stand, der hvor man ikke ser den."},"ICON-0150":{"nm":"Puslespil","de":"Natten, hvor man famlede selv under sofaen efter den sidste manglende brik. Den lydløse nydelse i øjeblikket, hvor den passer helt præcist. Når de spredte ting finder deres plads, bliver billedet endelig fuldendt."},"ICON-0151":{"nm":"Lineal","de":"At måle længde er også en måde at holde et løfte på. For at én håndsbredde skal være ens for alle, står stregerne ærligt på række. Én lige streg kan endda glatte et skævt hjerte ud."},"ICON-0152":{"nm":"Lærred","de":"En tom, hvid flade er det mest skræmmende, og det mest spændende. Indtil den første prik er sat, kan den blive til hvad som helst. Tomhed er ikke en afslutning, men et andet navn for en begyndelse."},"ICON-0153":{"nm":"Kube","de":"Mere end én har våget en hel nat i forsøget på at få alle seks sider til at stemme. De ihærdige fingerspidser, der drejer og drejer igen. I det øjeblik de sammenblandede farver finder deres plads, falder et lille univers pænt i orden."},"ICON-0154":{"nm":"Håndholdt spilkonsol","de":"En lille skærm, som fætre og kusiner lagde hoveder sammen om i skoleferien. En eventyrverden, der passer akkurat i håndfladen. Blot én takt af opstartsmelodien, og hele den sommer strømmer tilbage."},"ICON-0155":{"nm":"Greb","de":"Fornemmelsen af, at den slutter tæt om hånden, når man griber fast, giver sagte selvtillid. Så man ikke glider, så man ikke mister taget. I det mest afgørende øjeblik er det forbindelsen, der binder hånd og redskab sammen til én solid enhed."},"ICON-0156":{"nm":"Fyldepen","de":"Mens man skriver med genopfyldt blæk, bliver selv håndskriften en anelse pænere. Man samler sindet til lyden af pennesplittens raspen og ligner stille den omhu, hvormed man langsomt begyndte den første linje i et håndskrevet brev."},"ICON-0157":{"nm":"Palet","de":"Blåt ved siden af rødt, grønt oven på gult. På denne lille plade, hvor farverne ligger pænt side om side, får et billede endelig sit udtryk. Ethvert eventyr med at blande og lægge lag på lag tager sit første skridt netop her."},"ICON-0158":{"nm":"Sæt","de":"Hver for sig er de almindelige, men samlet på række bliver de til én historie. Den tryghed, der ligger i, at intet mangler, og alt er på plads. At samle spredte ting på ét sted rummer en lille glæde ved fuldendelse."},"ICON-0159":{"nm":"Fjerbold","de":"Den bløde susen, fjerene laver, når den suser op efter et slag med ketsjeren. Den virker for let til at nå langt, men rammer man den med vilje, flyver den lige til banens fjerneste ende. Lethed er også en fuldgyldig form for styrke."},"ICON-0160":{"nm":"Antenne","de":"Den står tavst mod himlen for at fange usynlige signaler. Den tålmodighed, der til sidst trækker selv fjerne stemmer nærmere. På dage, hvor modtagelsen er dårlig, gør man den blot en smule mere klar ved at dreje vinklen let."},"ICON-0161":{"nm":"Stetoskop","de":"Den runde spids, kold mod brystet, og et åndedrag, der holdes stille et øjeblik. Samler man øret om én lille tromme, føres den ældste rytme af at være levende videre til fingerspidserne. Et redskab, hvor det at lytte kommer først."},"ICON-0162":{"nm":"Bonde","de":"En lille brik, der langsomt gik kun ét felt ad gangen. Alligevel kan den, i det øjeblik den når den fjerneste række, blive til hvad som helst. Det gamle skakbræt følger stille med i det ene træk, der med et klodset skridt vender hele spillet."},"ICON-0163":{"nm":"Controller","de":"Husker du de nætter, I strejfede rundt i universet med to tommelfingre? Grebet, medtaget af brug, som man i frustration smed fra sig efter et tab og lidt flov samlede op igen. Den længste, varmeste samtale, man delte tavst med nogen på den anden side af skærmen."},"ICON-0164":{"nm":"Konsol","de":"Tænder man for strømmen, lyder en lille opstartstone som en hilsen. Den firkantede boks, man tændte og slukkede under dynen hele ferien; barndommens allerførste eventyr begyndte altid i lyset fra denne skærm."},"ICON-0165":{"nm":"Tidslinje","de":"Venstre ende er begyndelsen, højre ende er en dag, der endnu ikke er kommet. Trækker man en enkelt prik hen et vilkårligt sted imellem, folder et øjeblik, man troede glemt, sig ud igen. Et sted, hvor tiden er lagt ned i én lige linje."},"ICON-0166":{"nm":"Prisme","de":"Tænk, at lyset, der virkede så rent, hele tiden gemte på syv farver. Hemmeligheden, der løses op til en regnbue, i det øjeblik den passerer et lille stykke glas. Jo mere ordentligt noget virker, desto flere farver ligger skjult indeni."},"ICON-0167":{"nm":"Golftee","de":"Et lille stativ til roligt at hvile bolden på. Jo længere man ønsker at sende noget af sted, desto mere behøver man først noget, der kan holde det fast. Denne lille pløk i græsset bærer det første skridt."},"ICON-0168":{"nm":"Strikkepind","de":"En maske, og så endnu en. Tabes blot én, må man trevle det hele op og begynde forfra. Halstørklædet, der langsomt blev længere i skødet gennem én vintersæson, stedet, hvor fingerspidsernes tålmodighed blev strikket til varme."},"ICON-0169":{"nm":"Melodilinje","de":"Ét vers, der sivede ud i en nynnen fra læberne, før teksten blev lagt ovenpå. I den tågede melodi, endnu uden ord, gemmer sig en sangs mest ærlige, første ansigt."},"ICON-0170":{"nm":"Radar","de":"Den sender et signal ud mod det mørke, den ikke kan se, og venter tavst på én enkelt prik, der vender tilbage. Tålmodigheden hos et rundt, grønt lys, der tror på, at noget er derude, selv når intet er synligt."},"ICON-0171":{"nm":"Rytmepad","de":"Bank, bank, giver man den et let slag, springer lys og lyd frem på én gang. Et sted, der får hænderne til at huske takten før hovedet gør. Den mindste, kæreste scene, udfoldet på håndfladen."},"ICON-0172":{"nm":"Maling","de":"De gamle malere formalede sten og jord for at få farve. Indigo fra planter, rødt fra jord. Selv i denne ene dråbe, der presses ud ved fingerspidserne i dag, strømmer den ældgamle omhu, hvormed man forsigtigt overførte naturen til et kar."},"ICON-0173":{"nm":"Streg","de":"Det, der først fødes i det øjeblik man beslutter sig for at forbinde prik til prik. Kort eller lang, buet eller lige, den er det enkleste spor, som ønsket om at komme et sted hen efterlader. Begyndelsen til ethvert billede."},"ICON-0174":{"nm":"Lukker","de":"Klik, dette ene korte glimt af mørke holder fast i en scene for evigt. Selv et udtryk, man næsten lod glide forbi i et blink, skærer den et lille stykke lys af og hærder det til et minde. Et lille blad."},"ICON-0175":{"nm":"Sikkerhedsline","de":"Linen, der bindes fast et skridt før den, der klatrer højt op. Den holder i ens sted fast i hjertet, der ængstes for at falde, og vogter usynligt ved siden af, et løftesbånd. Den er altid der bag ryggen."},"ICON-0176":{"nm":"Hængelås","de":"Den tunge jernlås, man spændte for forrådskammeret. Det handlede ikke om at spærre noget inde, men om ønsket om trygt at kunne efterlade noget kært. Selv i hånden, der låste, lå der omhu – det gamle hjems faste tryghed."},"ICON-0177":{"nm":"Vægt","de":"Bliver den ene side tungere, letter den anden sig af sig selv. I det øjeblik, hvor man tøver med, hvad og hvor meget man skal lægge på, lærer man retfærdighed. To arme, der vaklende lærer balance fra hinanden."},"ICON-0178":{"nm":"Kløver","de":"Selv det, der er fast sammenføjet, vil, følger man blot årerne, til sidst dele sig. Et lille redskab til at dele hvad som helst i to og kigge indeni. Nysgerrige fingerspidser, der længes efter at skille det sammensatte ad igen og se på ny."},"ICON-0179":{"nm":"Tæller","de":"Én, to, tre. En lille ven, der tavst tæller tallene i stedet for fingrene. Den forvandler den ængstelige bekymring for at glemme en optælling til ro, klik for klik – tællingens venlige følgesvend."},"ICON-0180":{"nm":"Markør","de":"En lille pil, der blinker et sted på skærmen og venter på den næste kommando. Selv mens man tøver, forlader den aldrig sin plads, lysspidsen, der stille vinker og siger: lad os begynde nu."},"ICON-0181":{"nm":"Klatregreb","de":"Det ene punkt, man griber fat i til sidst, lige før kræfterne slipper fingerspidserne helt. At der findes øjeblikke, man holder ud i blot på viljen til ikke at give slip, det fortæller den lille knast på væggen tavst."},"ICON-0182":{"nm":"Rullesten","de":"En sten, der har rullet længe i bækken og givet afkald på alle sine kanter. At blive rund er blot et andet navn for tid, der er slidt væk. Holder man den stille i hånden, kan man mærke den strømmende flods tålmodighed."},"ICON-0183":{"nm":"Våbenskjold","de":"Gamle slægter indgraverede dyr og stjerner på et enkelt banner for at gøre sig kendt. Et billede, der talte til hjertet, før ordene kunne. Et gammelt mærke, der omhyggeligt sammenpresser én persons stolthed i et lille felt."},"ICON-0184":{"nm":"Skjold","de":"At stille sig i vejen har altid handlet om den, der står bag én. Ved at tage imod de flyvende pile i sit sted vogtede den over nogens almindelige dag – en tung, men kærlig mur."},"ICON-0185":{"nm":"Genopstandelse","de":"Der findes et hjerte, der slukkes og tændes igen. Først efter at være faldet én gang lærer man endelig, hvordan man rejser sig igen. Et andet åndedrag, der stille vokser frem netop der, hvor man troede, alt var slut."},"ICON-0186":{"nm":"Bue","de":"Hånden, der vil sende noget langt af sted, trækker først strengen helt tilbage. At for at slippe noget, må man først holde det lige så tæt – det fortæller den stramt spændte bue stille uden ord."},"ICON-0187":{"nm":"Hjerte","de":"Ordene 'jeg kan lide dig' bliver ved med at krympe til en lille figur. Denne form, tegnet flygtigt på spidsen af en lightstick, eller mellem to fingre, der mødes. Hjertets mest almindelige og ærlige forkortelse."},"ICON-0188":{"nm":"Sky","de":"Den driver langsomt mod vinden og bliver til et nyt ansigt hver gang. Nu en kanin, nu bomuld – uden at holde fast i noget længe, lader den alt drive forbi, himlens letteste hjerte."},"ICON-0189":{"nm":"Labyrint","de":"Et sted, hvor man lærer at vende om foran en blind mur. Selv mens man vandrer vildt, vokser skridtene lidt efter lidt mod udgangen. Man må fare vild én gang for at få stedsans."},"ICON-0190":{"nm":"Tand","de":"Der var en skik med at kaste en mistet tand op på taget. En lille bøn om, at den nye tand måtte gro lige og ret. Et barndommens kærlige løfte om, at man må miste noget én gang, mens man vokser, for at få noget stærkere igen."},"ICON-0191":{"nm":"Planet","de":"En rund krop, der kredser om en stjerne uden nogensinde at forlade sin bane. Den kan se ensom ud, men dens tyngdekraft holder altid noget kredsende ved sin side. Blot stille at holde sin plads bliver til en hel verden."},"ICON-0192":{"nm":"Stjerne","de":"På nætter, hvor man havde mistet vejen, kiggede folk op mod det klareste punkt. Et lys, uopnåeligt fjernt, men som dog tydeligt peger retningen. Et løfte, der bliver desto fastere af at være langt væk."},"ICON-0193":{"nm":"Silhuet","de":"Står man med ryggen til lyset, bliver kun omridset af en person tilbage. En enkelt sort skikkelse, hvis navn og udtryk er visket ud. Et ufyldt sted, der netop fordi det er tomt, lader én forestille sig så meget mere."},"ICON-0194":{"nm":"Øre","de":"For at synge godt må man først lytte godt. Både takt og hjerte begynder i sidste ende med at lytte. En lille, rundt åbnet dør, hvor alle verdens lyde ankommer og dvæler først."},"ICON-0195":{"nm":"Efterårsblad","de":"Der findes blade, der skinner smukkest netop i det øjeblik, de falder. Letheden ved at brænde en hel sæsons grønt helt op i rødt og sagte lægge det fra sig. At selv en afslutning kan være så smuk, viser efteråret os."},"ICON-0196":{"nm":"Måne","de":"Der var nætter, hvor man samlede hænderne og ønskede sig noget under det runde høstlys. Et ansigt, der gentagne gange voksede og aftog, og aldrig var det samme to gange. En lanterne, der forandrer sig, men altid lyser op på samme sted."},"ICON-0197":{"nm":"Hjerteslag","de":"Selv på scenen er det i sidste ende dette hjerteslag, der er mest ærligt. Det stopper ikke, selvom det dirrer, og slår endnu hårdere, når det svulmer af følelser. En lille, rød tromme, der banker i ens sted den heppen, ordene aldrig nåede at fuldende."},"ICON-0198":{"nm":"Skygge","de":"En følgesvend, der aldrig falder fra, så længe der er lys. Den bliver mørkere jo lysere det er, og lysere jo mere overskyet det bliver – endnu et jeg, der har fulgt mig længst. Én person, der står ved min side selv på ensomme dage."},"ICON-0199":{"nm":"Hale","de":"Den logrer af sig selv, når man er glad, og krøller sig sagte sammen, når man er bange. Den ærlige lille spids, der aldrig helt kan skjule hjertet, selv om munden holdes tæt lukket. Den inderste følelse, som kroppen først lader sive ud."},"ICON-0200":{"nm":"Halebånd","de":"Et lille bånd, bundet for enden som en afslutning, ligesom et hårbånd. Hjertet, der knyttede knuden én gang til, stramt, for at intet skulle løsne sig. En kærlig afslutning, der samler og trøster de ting, der let spredes."},"ICON-0201":{"nm":"Pupil","de":"Man kan vælge sine ord, men man kan ikke skjule blikket i øjnene. Det er stedet hvor et afsløret hjerte lækker ud allerførst, inde i den sorte cirkel. Selv om man sluger ordene \"jeg kan lide dig\", skælver pupillerne allerede mod dig."},"ICON-0202":{"nm":"Hestesko","de":"Et stykke jern der blev stærkere, jo mere spidsen sled ned af lange ridt. Hængt op og ned over døren, sagde man, samlede al den lykke der kom og gik, sig deri. Det bærer stille en andens sikre hjemkomst."},"ICON-0203":{"nm":"Emblemsten","de":"Selv når regn og blæst sliber bogstaverne udviskede, kommer den indgraverede åre levende tilbage, når man følger den med fingerspidserne. Vægten af et hjerte der ikke ville glemmes. Sådan bærer en sten ét navn i lang tid."},"ICON-0204":{"nm":"Svømmehud","de":"Med blot en tynd hinde mellem tæerne lærer den at skubbe vandet til side. En lille åre naturen listede i hånden på en dårlig svømmer. Et ømt design der, langsomt men sikkert, får dig hele vejen over floden."},"ICON-0205":{"nm":"Glimmer","de":"Alle brokker sig over at det klæber til hænderne i flere dage, men på festdagen er det disse lyskorn, man griber efter først. Strø en håndfuld stjernestøv ud, og selv almindeligt papir glitrer, og dagen bliver noget særligt."},"ICON-0206":{"nm":"Klo","de":"Skovens dyr river jorden op med kloen og efterlader deres egen sti. Ikke en trussel, men et spor, en stille underskrift om at de gik forbi her. En skarp spids kan for nogen blive et ømt vejskilt."},"ICON-0207":{"nm":"Lyn","de":"I det korte øjeblik hvor himlen breder sine håndlinjer ud, når lyset frem før tordenen. Som om det beder dig trække vejret én gang, før den store lyd når dig. Frygt og forundring fødes altid sammen af det samme glimt."},"ICON-0208":{"nm":"Amulet","de":"En enkelt linje af et ønske, presset fast med tusch på rødt papir. Man troede, at lagt under puden ville den holde onde drømme på afstand. Et hjerte der beder for en andens tryghed er så varmt, selv i et enkelt tyndt ark papir."},"ICON-0209":{"nm":"Penselvinge","de":"Der findes øjeblikke hvor penselspidsen bliver en vinge. Den lethed, hvormed den glider hen over papiret, mens man trækker et enkelt strøg. At skrive er i sig selv en form for at flyve — det må den gamle hånd, der rev blæk, dunkelt have vidst."},"ICON-0210":{"nm":"Knogle","de":"Det der bliver tilbage, først efter alt kødet er smuldret bort. Den hvide ramme der holdt ud til det sidste, netop fordi den var hårdest. Et stille bevis, der i det mindste husker formen, selv når tiden tager alt andet med sig."},"ICON-0211":{"nm":"Næse","de":"Duft er den hurtigste genvej til minderne. Duften af olie i et festkøkken, den kolde luft en morgen efter den første sne — næsetippen opfatter det først, og hjertet følger et taktslag bagefter."},"ICON-0212":{"nm":"Toast","de":"Et travlt morgenmåltid, det hurtigste man kan gribe i hånden. Bid i den gyldenbrune overflade, og en hel dags mod knaser fra hinanden. Ting der ikke behøver være storslåede, men mættende, rejser et menneske på benene igen."},"ICON-0213":{"nm":"Småkage","de":"Den der har ventet længst foran ovnen, får det første bid. Varmen fra en netop bagt kant, en kort sødme. De der bages, mens man tænker på nogen, er mærkeligt nok altid de sødeste."},"ICON-0214":{"nm":"Snack","de":"En eftermiddag hvor øvelsen trækker ud, en lille pose trukket op fra bunden af tasken. Del den i to, og mætheden fordobles mærkeligt nok. En håndfuld ømhed der fylder hjertet, før den fylder sulten."},"ICON-0215":{"nm":"Kapsel","de":"Ingen kan vide det, før de vrider den op. Det der er inde i den runde skal, er altid den samme sitren i hjertet. Verdens mest ærlige spænding, hvor man køber og sælger en lille tilfældighed."},"ICON-0216":{"nm":"Dørhåndtag","de":"Stedet de utallige hænder, der åbner og lukker en dør, rører først. Hjemmets første goddag, der starter koldt og varmes op i håndfladen. Jo mere det bliver befamlet, jo mere bliver værelset langsomt til nogens hjem."},"ICON-0217":{"nm":"Gåtur","de":"Selv at gå uden et mål har sin grund. En tid til at rede filtrede tanker ud, tråd for tråd, i sine fodtrin. Kom tilbage fra en runde, og svaret er det samme, men hjertet alene er blevet en hel del lettere."},"ICON-0218":{"nm":"Scooter","de":"To hjul der skærer gennem de smalle stræder. Den er ikke hurtig, men den tager vinden fuldt på kroppen. Der er dage, hvor man bare vil køre en tur og mærke det forfriskende i dag, selvom man ikke når langt."},"ICON-0219":{"nm":"Sikkerhedsbøjle","de":"Før man stiger på, sænker en enkelt tværstang sig fast foran brystet. Et betryggende løfte, der holder ud sammen med dig gennem hele den skræmmende strækning. Den fortæller dig, koldt og uden et ord, at det er okay at holde godt fast."},"ICON-0220":{"nm":"Trappe","de":"Klatr et trin ad gangen, og før du ved af det, har udsigten ændret sig. Fodsålerne lærer først, at ingen højde nås i ét spring. Op- og nedstigningen i sig selv var, for nogen, en hel dags skridt."},"ICON-0221":{"nm":"Terrarium","de":"Det er ikke at fange en skov i glas, men at passe en hel verden med omhu. Et håndfladestort univers hvor mos breder sig og vanddråber dannes. Jo længere du kigger ind, jo langsommere farves hjertet grønt."},"ICON-0222":{"nm":"Podium","de":"Stig op på et sted en håndsbredde højere, og udsigten forandrer sig. Et sted hvor frygt og stolthed mødes i samme højde. Alt efter hvem der står der, bliver dette ene trin til en helt anden scene hver gang."},"ICON-0223":{"nm":"Fly","de":"I det øjeblik skyerne breder sig under fødderne, savner man endelig for alvor det sted, man forlod. Det er ikke at komme længere væk, men at verden bliver bredere. Selv en drøm opvokset på en lille ø krydser himlen sådan her."},"ICON-0224":{"nm":"Skateboard","de":"En ting man først kan ride på, når man har lært at falde. Hver gang knæet skrabes, ridses balancen lidt mere ind i kroppen. Ærlige fire hjul der ruller længere for hvert godt fald."},"ICON-0225":{"nm":"Pas","de":"Slår man forsiden op, er den fuld af tomme sider. Hvert stempel, der skal udfyldes, bliver et bevis på et liv, der er levet. En lille bog der ikke rummer, hvor langt du er nået, men muligheden for at kunne rejse hvor som helst."},"ICON-0226":{"nm":"Håndtegnet kort","de":"Det har hverken nøjagtig afstand eller målestok, men fordi vejen er tegnet i hånden, er der ingen frygt for at fare vild. Papir hvor stræder og butiksnavne varmt filtrer sig sammen. Vejledning med hjerte i er altid varmere end selve vejen."},"ICON-0227":{"nm":"Sceneplan","de":"Papir hvor hvert skridt på scenen er tegnet som en linje. Hvor man skal stoppe, hvor man skal dreje, lover pilene på forhånd. Selv en dans der ser fri ud, begynder faktisk fra dette ene ark."},"ICON-0228":{"nm":"Pladsanvisning","de":"I et fremmed rum er det første, man famler efter, ens egen plads. Den ene plads man endelig når frem til ved at følge række og nummer. Et enkelt ark papir sætter tusindvis af sitrende følelser pænt på plads, én efter én."},"ICON-0229":{"nm":"Strædekort","de":"Vejledning nogen har skrevet i hånden til dem, der let farer vild i de labyrintiske stræder. Den venlige håndskrift der fortæller, ved hvilket hjørne man skal dreje. Et kvarters gæstfrihed skrevet tydeligt ind i ét lille kort."},"ICON-0230":{"nm":"Adgangskort","de":"Først når man hænger dette kort om halsen, åbner døren til den indre verden sig. En lille tilladelse der giver adgang, og et stille bevis på, at man hører til her. Kun den, der kender tiden det tog at opnå det, kender dets vægt."},"ICON-0231":{"nm":"Dagsarmbånd","de":"Sæt det om håndleddet én gang, og du er medlem af den dag, indtil du river det af. Et enkelt papirbånd skiller inde fra ude og bliver et mærke for, at man har tilbragt den samme dag sammen. Selv efter det er knækket af, bliver sporet siddende længe."},"ICON-0232":{"nm":"Gæstemærke","de":"Med bare ét lille navneskilt klistret på brystet bliver et fremmed sted ens eget. Når ordet \"velkommen\" bæres frem på et enkelt ark papir, bliver selv en førstegangsbesøgende endelig en gæst."},"ICON-0233":{"nm":"Posterrør","de":"Et solidt rør der holder en sammenrullet plakat uden en eneste fold. Jo mere kostbart billedet er, jo mere lige og strakt skal den sendes af sted. Man kan ikke se ind i det, men det drager af sted og bærer på nogens omhu."},"ICON-0234":{"nm":"Mappeforside","de":"Den første side der omslutter en tyk bunke materialer. Ansigtet ens hånd rører før selve indholdet. Er forsiden pæn og ordentlig, ser sindet indeni også ordentligt ud — en øm begyndelse på en lille formalitet."},"ICON-0235":{"nm":"Postkort","de":"Man skriver en hilsen på et stykke fjern udsigt og sender det af sted. Når det når frem, er det hjerte man sendte, også blevet en smule ældet, og derved kærere. Den langsomme varme fra et håndskrevet brev, som en besked på en skærm aldrig helt kan indhente."},"ICON-0236":{"nm":"Gavemærke","de":"Et lille stykke papir bundet fast på en gave. Bare de to ord \"til dig\" fuldender allerede indpakningen. Verdens korteste brev, der ikke skriver, hvad man giver, men hvem man tænkte på."},"ICON-0237":{"nm":"Indpakningsmærkatrulle","de":"Hver gang man river et stykke af til brug, bliver afslutningen en del pænere. En lille knude der ordentligt holder fast i enden, der vil løsne sig. Det sidste håndgreb på en omhyggeligt pakket gave kommer altid fra dette sammenrullede bånd."},"ICON-0238":{"nm":"Klar brevlomme","de":"Et gennemsigtigt lag der pakker et håndskrevet brev ind, så det ikke falmer med årene. Bogstaverne forbliver synlige, men berøringens slid når dem aldrig. En usynlig film, der stille vogter over nogens kærlige hjerte."},"ICON-0239":{"nm":"Farvet vokssegl","de":"Det sidste punktum der lukker en kuvert — jo klarere farven, jo mindre lækker hjertet ud. Et løfte om, at ingen hånd har rørt den, før den brydes op. Selv en hemmelighed har brug for en så smuk knude."},"ICON-0240":{"nm":"Beskedbog","de":"En lille bog der binder korte sedler sammen. Hver side er et ord til at give videre til nogen. Samler man de ord op, man endnu ikke fik sagt, én efter én, vokser modet til engang helt sikkert at give dem videre."},"ICON-0241":{"nm":"Sammenklappeligt skilt","de":"Foldet ud siger det \"denne vej\", foldet sammen siger det \"det var det for i dag\". Med benene spredt ved indgangen til stræde, står det en hel dag for nogen, der er tilbøjelig til at fare vild. Den aften det foldes sammen, er for mig den kæreste hvile."},"ICON-0242":{"nm":"Postbånd","de":"Vikl et bundt postkort om livet, og hilsnerne der var ved at spredes, bliver endelig til ét knippe af hjerte. Et enkelt let bånd binder pænt sammen de ord, der skal nå fjerne steder, og vinker stille farvel til ryggen, der drager af sted."},"ICON-0243":{"nm":"Takkesedelbundt","de":"Fordi ordet \"tak\" bliver ved med at glide af tungen, skriver man det på et håndfladestort papir og binder det stille sammen. Jo tykkere bundtet vokser sig, jo tykkere vokser også, side om side, det hjerte man skylder nogen."},"ICON-0244":{"nm":"Heppeslogan-ark","de":"Et eksempelark hvor der står \"råb det sådan her\". En heppe der endnu ikke har fået en stemme lagt på, rummer kun en stille sitren, som et tomt nodeark der venter på det første taktslag."},"ICON-0245":{"nm":"Forindspilningsnotat","de":"En seddel der beder om at få reserveret en forindspilning, ligger altid i feltet klokken fem om morgenen. Det lille papir noterer stille ned, som forstod det alt, det hjerte der skærer i sin søvn for at sikre sig en plads."},"ICON-0246":{"nm":"Fansign-billet","de":"Et enkelt ark der afgør, hvilket nummer du får til at give din hilsen. At stille sig i kø er ikke at vente på sin tur, det er kortvarigt at låne et nummer, fordi man ikke kan sætte tal på, hvor højt man holder af nogen."},"ICON-0247":{"nm":"Kønummerarmbånd","de":"Et enkelt tal afgør, hvilken rækkefølge man stiller sig i i dag. Uanset om man er forrest eller bagerst, er de der bærer dette lille, lette bånd om håndleddet, i sidste ende ligesindede, samlet for at se den samme scene."},"ICON-0248":{"nm":"Fotokort-sorteringsskema","de":"Selvom det er det samme ansigt, er de alligevel alle forskellige, siger man og noterer dem opdelt felt for felt. Jo fyldigere skemaet bliver, jo mere ordentligt bliver hjertet, og det ene tomme felt, der er tilbage, får brystet til at banke af den spænding, man ønsker at fylde det med i dag."},"ICON-0249":{"nm":"Albumtjekliste","de":"Version, fotokort, ja selv om det er forseglet — en liste over kærlighed nedskrevet i tal. Man forestiller sig på forhånd stoltheden på den dag, alt er udfyldt, og tegner i dag igen en pæn lille cirkel på en linje."},"ICON-0250":{"nm":"Heppeguide-seddel","de":"Håndbevægelser, taktslaget man råber på, selv de steder man skal trække vejret. For at selv en førstegangsbesøgende hurtigt kan smelte sammen med den ene stemme, bliver den lille seddel en venlig guide, der vandrer fra hånd til hånd."},"ICON-0251":{"nm":"Privat notesblok","de":"Man udvælger kun de sætninger, man ikke vil vise nogen, og skriver dem her. At den side, der aldrig er blevet slået op, er den mest ærlige, det vogter denne blok tavst over, med omslaget holdt lukket."},"ICON-0252":{"nm":"Mærkedagsstempelark","de":"Man trykker, og endnu en dag bliver særlig. Med ét lille stempel banket ned på en almindelig dato, skriver \"i dag\" listigt sit navn ind på listen over dage, som er værd at huske."},"ICON-0253":{"nm":"Clipboard-hylster","de":"Selv når vinden blæser, selv når regnen slår ind, holder det urokkeligt fast i det fastklipsede papir, lige til det sidste. Jeg, der har taget det på mig at være boardets rustning, er de skrevne bogstavers pålidelige livvagt."},"ICON-0254":{"nm":"Filindeks","de":"For at man ikke skal fare vild i tykke dokumenter, stikker det en lille tunge frem og siger \"her\". Ét farverigt faneblad styrer hundrede sider med et enkelt blik."},"ICON-0255":{"nm":"Kategorifaneblad","de":"Dette i dette rum, det i det rum. Mit job er at rydde op i verdens rod, pænt og ordentligt, linje for linje. I det øjeblik et mærkat sættes på, finder de rodede ting endelig deres plads."},"ICON-0256":{"nm":"Mini-godkendelsesmappe","de":"I det øjeblik man banker et stempel ned, føles det på en eller anden måde som om man endelig er blevet voksen for alvor. Lille i størrelse, men med en rap autoritet — ét godkendelsesstempel, og det ophobede arbejde afsluttes lynhurtigt."},"ICON-0257":{"nm":"Klar dokumentlomme","de":"Gennemsigtig helt igennem, uden noget at skjule. Med vigtigt papir i favnen svøber den det ind i sin egen klare krop, af frygt for regn eller krøller, og bringer det hele vejen til mødestedet."},"ICON-0258":{"nm":"Fremmødebånd","de":"Kom, og endnu et felt fyldes ud. Når hver dags fodspor hober sig op på række langs båndet, bliver en usynlig flid endelig til et mønster, man kan se med det samme."},"ICON-0259":{"nm":"Fejlnotesbog","de":"At skrive ned det man tog fejl af, er ikke at samle skam sammen. For ikke at snuble to gange samme sted, er det at omskrive gårsdagens fejl til dagens guide."},"ICON-0260":{"nm":"Skemastempelplade","de":"Stempl én gang i en tom kalender, og en \"aftale\" bliver født. Magien ved at en dag bestemmes med ét sving af håndleddet — den magi er faktisk bare et andet navn for flittigheden ved at forberede sig i god tid."},"ICON-0261":{"nm":"Rygmærkat","de":"Navneskiltet på bøger der står med ryggen vendt mod hylden. De korte bogstaver skrevet på en smal ryg kalder med et vink på netop den bog, du ledte efter blandt hundredvis."},"ICON-0262":{"nm":"Fotobeskytter","de":"Bare hænder er ikke tilladt. Uden så meget som et fingeraftryk, lægger den forsigtigt sin egen krop over et dyrebart billede. Et kærligt hjerte holder sådan længe, længe, gennem en så forsigtig berøring."},"ICON-0263":{"nm":"Filmindeksark","de":"Sæt et nummer på hver filmstrimmel, og de spredte øjeblikke genvinder deres tur i historien. En lille guide der passer på minderne skrevet i lys, så de ikke bliver blandet sammen."},"ICON-0264":{"nm":"Fotolomme","de":"Et gennemsigtigt hjem hvor firkantede stykker lykke opbevares ét ad gangen. Uden bekymring for bulede hjørner skinner det kæreste ansigt pænt og ordentligt herinde gennem alle fire årstider."},"ICON-0265":{"nm":"Mini-fotokuvert","de":"Før varmen fra et lige fremkaldt billede overhovedet er kølet af, åbner en lille kuvert begge arme og tager imod det. Et enkelt billede der går ind gennem den håndfladestore åbning, bliver, før man ved af det, en skat i nogens taske."},"ICON-0266":{"nm":"Lenticular-hylster","de":"Min opgave er at beskytte, uden en eneste ridse, et vanskeligt billede hvis udtryk skifter, når man vipper det. Med alle de forskellige ansigter, ved hver eneste vinkel, der skal beskyttes, må jeg selv være mere end almindeligt flittig."},"ICON-0267":{"nm":"Billedudvalgsmærkat","de":"Hvilket af de fire billeder der er det bedste, peger mærkatet på i stedet for dig. Denne lille opgave med at skille det vellykkede fra det sjove, side om side, er hemmeligheden bag at nyde et minde to gange."},"ICON-0268":{"nm":"Fotostrimmelbånd","de":"Det vikler sig pænt om et smalt, langt firebilledeminde. Ved fast at omfavne den dags spredende latter i ét bundt, bærer det den sikkert helt ned i bunden af tasken."},"ICON-0269":{"nm":"Fotohjørnemærkat","de":"Når man sætter et billede fast i et album, en lille hånd der forsigtigt holder om alle fire hjørner. Så det ikke falder af, uden at man klistrer med lim overalt — finesse begynder netop sådan, fra hjørnerne."},"ICON-0270":{"nm":"Printjusteringsskema","de":"Lidt varmere, en anelse mindre lyst. Et enkelt skema hvor man pilfingrer med tallene, indtil netop den farve man kan lide, kommer frem, og stille forvandler et almindeligt billede til et kunstværk."},"ICON-0271":{"nm":"Kvitteringsclips","de":"Den bider fast, pænt og ordentligt, om de krøllede kvitteringer og slipper ikke. Med sin lille mund holder den styr på en dags udgifter med sikker hånd, så månedens opgørelse bliver en hel del lettere."},"ICON-0272":{"nm":"Reservationsbekræftelse","de":"Ved den ene linje \"din reservation er bekræftet\" falder sindet langsomt til ro. Et enkelt ark papir bliver beviset på et løfte og opbevarer sitringen, bid for bid, indtil den ventede dag."},"ICON-0273":{"nm":"Afleveringskvittering","de":"Et lille, men hæderligt bevis på, at man har sat det lånte tilbage på plads. I det øjeblik dette papir ligger i hånden, viskes en gæld, der lå og tyngede i et hjørne af hjertet, let ud."},"ICON-0274":{"nm":"Opbevaringsbilletholder","de":"Så du ikke mister billetten til at hente det, du har afleveret, holder jeg den godt fast for dig. For hvor et enkelt lille stykke papir befinder sig, kan afgøre, hvordan nogens dag ender."},"ICON-0275":{"nm":"Udlånsmærkathale","de":"Et lille mærke der vipper på hver eneste lånte genstand. Følg denne hale, og på et øjeblik åbenbares det, hvem der tog hvad, så selv mysteriet om en bortkommen ting hurtigt løses."},"ICON-0276":{"nm":"Kontrolliste","de":"Man sporer det over, ét for ét, med øjnene for at se, om der mangler noget. Når afkrydsningerne fylder sig op på række, opnår en usynlig grundighed endelig navnet tillid."},"ICON-0277":{"nm":"Regnskabskuvert","de":"Skriv pengene der kom ind og gik ud på kuverten, og de rodede tal falder roligt i række. Slutningen på et regnskab er altid denne lille seddel, der stille sætter det afsluttende punktum."},"ICON-0278":{"nm":"Fragtmærkat","de":"Med hvor det skal hen, og hvem det skal nå, skrevet på egen krop, drager det af sted. I det øjeblik dette mærkat sættes på, bliver kassen en rejsende med et mål og tager af sted med en sitren."},"ICON-0279":{"nm":"Modtagelsesbekræftelsesbånd","de":"Det binder ordene \"modtaget vel\" op i ét bånd og sender dem tilbage. Modtagerens lettelse og afsenderens ro griber stille hinandens hænder på denne lille snor."},"ICON-0280":{"nm":"Ordkortring","de":"Ordene, der ville gå tabt, hvis de spredtes som løse ark, strenger en lille ring sammen og holder fast. Blad om og om igen, og de engang fremmede ord bliver, før man ved af det, venner man har på tungen."},"ICON-0281":{"nm":"Udtalemærkebånd","de":"Man hænger et lille mærke på det sted, hvor tungespidsen bliver ved med at glide. Selv en fremmed lyd, der fór vild i munden, finder, før man ved af det, sin rette udtale ved at følge denne note. Den første side i tæmningen af en klodset lyd, lidt efter lidt."},"ICON-0282":{"nm":"Oversættelsessedelæske","de":"Små broer der krydser mellem ord og ord, ligger pænt foldet, én i hvert rum. Skriver man en hårdt udvalgt sætning ned og rækker den forsigtigt frem, kommer selv et hjerte, der ikke kunne nå igennem, nærmere med blot en enkelt seddel imellem."},"ICON-0283":{"nm":"Citatudklip","de":"En sætning der rammer hjertet lige i plet, holder kun ved, hvis man afskriver den i hånden. Klistrer man en linje klippet fra et hjørne af en bog op foran skrivebordet, holder de bogstaver stille en dag, der var ved at synke, oppe."},"ICON-0284":{"nm":"Notatindeks","de":"Farverige, små flag stukket ind, så man ikke skal fare vild i en tyk bog. Man kan kun vandre længere, hvis man kender stedet, man skal tilbage til — det fortæller de udstikkende faner stille fra mellem siderne."},"ICON-0285":{"nm":"Udenadslærebrik","de":"Et enkelt mærke banket ned ved siden af det, man har lært udenad. Fordi den er et lille anker, der holder fast i ting, der lige stikker forbi i hovedet og forsøger at forsvinde, bærer hvert sortfyldte felt stille sidste nats indsats med sig."},"ICON-0286":{"nm":"Quiz-kuvertpakke","de":"Før man river kuverten op, ved ingen, hvad der kommer ud. De få sekunder, hvor fingerspidserne pilfingrer ved det forseglede sted — et bundt af sitren hvor et enkelt spørgsmål ligger pænt foldet ind, forseglet sammen med selve hjertebanken."},"ICON-0287":{"nm":"Grammatikfanebog","de":"Regler læres ikke udenad med hovedet, men indøves i hånden. Fra den farvede fane på den side, man slår op oftest, til den blødt slidte notesbog — det slidte hjørne bliver til årringene af den tid, du har holdt ud."},"ICON-0288":{"nm":"Taleøvelsesskema","de":"Et enkelt skema for den, for hvem det sværeste i verden er at åbne munden. Følger man felterne ned med fingeren, finder selv de første ord, der skælvede i halsen, før man ved af det, sin egen stemme. For selv mod har sin tur."},"ICON-0289":{"nm":"Farveskitseark","de":"Farverne, endnu ufærdige, ligger groft henslængt og henter vejret. En tilstand der ikke er svaret, men stadig en mulighed — på dette ene, endnu upolerede ark, gynger der mere morgendag end noget andet."},"ICON-0290":{"nm":"Moodboardstykke","de":"Samler og klistrer man de spredte, enkeltvise indtryk sammen ét sted, træder en stemning, der ellers ikke ville lade sig gribe, svagt frem i sit omrids. En følelse der endnu ikke har et navn, den peger stykkerne stille på, lænet op ad hinanden."},"ICON-0291":{"nm":"Mønstereksempelbog","de":"Gitteret i et indpakningsklæde og flettet i en vinduessprosse er pænt ordnet, side for side, i ét bind. Der hvor det samme mønster gentages til det sidste, bor ikke dovenskab, men et løfte — det faste hjerte i at holde fast i én linje."},"ICON-0292":{"nm":"Kostumestofprøve","de":"Selv i det samme lys ligger struktur og skygge forskelligt i hver stofstump. Før man vælger scenekostume, er den nat, man tilbragte tvivlrådig med at stryge hen over det igen og igen med fingerspidserne, bevaret helt og fuldt i én lille prøve."},"ICON-0293":{"nm":"Logo-forbudsark","de":"Papir der først, tydeligt og ordentligt, skriver op det, man ikke må gøre. Inden for en kontur streget over med et rødt kryds, bliver friheden netop klarere, og der åbner sig, af alle steder, en ny vej lige der, hvor man troede, det var en blindgyde."},"ICON-0294":{"nm":"Farvereferencebrik","de":"En prøvestump lavet særskilt, fordi farve slet ikke lader sig forklare med ord. Den fanger et bestemt øjeblik, hvor solnedgangen var allerrødest, i en lille håndflade, så man præcist kan give den næste person \"netop denne farve\"."},"ICON-0295":{"nm":"Layoutskitsekort","de":"Et første udkast let tegnet op af, hvad der skal stå hvor. At bestemme placeringen er i sig selv at bestemme hjertet, så mellem de klodset spredte streger åbner helhedens balance langsomt øjnene."},"ICON-0296":{"nm":"Materialenotatplade","de":"Træ, jord, sten — navnene på de ting man kan røre ved, er skrevet tæt. En hemmelighed kun kendt af dem, der begynder med at læse strukturen med hånden først: hvad man bygger med, afgør allerede halvvejs, hvad det bliver til."},"ICON-0297":{"nm":"Kalkerpapir","de":"Man lægger tyndt papir over underskitsen og tegner stille langs linjerne. Mens man en tid låner en andens vej, lærer ens egen hånd den vej at kende, og mellem de kopierede streger vokser, før man ved af det, listigt ens egen streg frem."},"ICON-0298":{"nm":"Indgangsbånd","de":"Folk stiller sig i kø og går ind, følgende det bånd der er klistret langt hen ad gulvet. En enkelt linje der stille guider, så de opstemte skridt ikke filtres sammen — en usynlig, øm hånd der bærer sitringen, så den ikke bryder sammen."},"ICON-0299":{"nm":"Eventskilt","de":"Et skilt der står og holder ordene \"denne vej\" i stedet for en person. En lille venlighed rejst ved hvert vejkryds, så ingen farer vild, tager en førstegangsbesøgendes fremmede dag ved hånden og går stille den igennem."},"ICON-0300":{"nm":"Standnummermærkat","de":"Ét nummer tildelt hver stand fastslår tydeligt ejeren af den ene plads. Et lille tal, men fordi det er et løfte om, at \"her er din plads\", får man et sted at vende tilbage til på et fremmed eventområde."},"ICON-0301":{"nm":"Personaleaftale","de":"En enkelt underskrift efterladt der, hvor hjerter blev enige om at arbejde sammen. Det er blot ét tyndt stykke papir, men det bærer vægten af at vælge at stole på hinanden, og enhver hjælpende hånd ved arrangementet begynder lige her."},"ICON-0302":{"nm":"Prøvebillet-bundt","de":"En buttet bunke prøvebilletter, bundet så den ligger godt i én hånd. Jo mere man deler ud, jo mindre svinder den ind – tværtimod giver den flere og flere \"første gange\" til andre, et bundt af gavmildhed der bliver varmere, jo mere man rører ved det."},"ICON-0303":{"nm":"Kø-markeringsskilt","de":"Vent herfra, hvisker gulvet stille. Når hjerterne, der holder deres tur, samles, bliver selv en lang kø til et syn i sig selv, og ét lille mærke forvandler utålmodighed til ro."},"ICON-0304":{"nm":"Afhentningsmærke","de":"Et lille mærke der klikker let fast, dér hvor man henter det, man har forudbestilt. I samme øjeblik det ligger i hånden, glider den lette lettelse ned fra skuldrene – en knude hvor et længe ventet hjerte endelig tager form."},"ICON-0305":{"nm":"Mysterieboks-billet","de":"Glæden ved at vælge én uden at vide, hvad der er inden i. Ryst den, og hjertet banker først ved raslelyden indeni, og det korte øjeblik lige før den åbnes, bliver dagens mest forventningsfyldte stund."},"ICON-0306":{"nm":"Byttebekræftelses-mærkat","de":"Et lille rundt stempel der bekendtgør, at byttet er gået glat af. Det er det glatte punktum efterladt mellem hænderne, der gav og modtog, og når det først er trykket på, runder handlen sig endelig varmt af."},"ICON-0307":{"nm":"Forseglingsbånd","de":"En dyrebar æske vikles én gang rundt med et bånd og forsegles stille. En bøn om ikke at åbne den skødesløst, og den stilfærdigste høflighed ved at værdsætte det, den gemmer, lige så højt – alt sammen rummet i ét enkelt bånd."},"ICON-0308":{"nm":"Hemmelig besked-kapsel","de":"Et ord man ville sige, gemt sirligt væk inde i en lille beholder. Luk den tæt som at begrave en følelse, man ikke kunne sende, og et lille pengeskab i håndfladen våger over tiden, indtil den dag man åbner den igen."},"ICON-0309":{"nm":"Lille klippekort","de":"Et udklippet og opklæbet stykke bærer den dags stemning svagt med sig. Lettere end en dagbog og mere håndlavet end et foto – et håndfladestort ark holder fast i en dag, der ellers let ville glide gennem fingrene."},"ICON-0310":{"nm":"Første besøg-registreringsark","de":"Sitringen fra den dag, man første gang satte fod på denne ø, forbliver i én kort linje. Lige før det fremmede blev til fortrolighed, holder papiret den reneste første følelse i ens sted og bevarer den længe."},"ICON-0311":{"nm":"Minde-sorteringsskema","de":"Et skema hvor minder sorteres efter årsag og gren, skrevet ned ét ad gangen. Stables alle minder i én skuffe, bliver selv den kæreste dag begravet, så jo mere dyrebar den er, jo mere sirligt får den sin egen plads."},"ICON-0312":{"nm":"Talebobler-memochip","de":"Ordene man ville sige, svulmer runde som en ballon og svæver på papiret. Selv en linje, man ikke kunne sige højt, finder stille mod inden for den runde ramme – en lille varm passage, hvorigennem et hjerte kan slippe ud."},"ICON-0313":{"nm":"Dato-holder","de":"En lille holder der rejser dagens dato op, så den vender mod dig. Vælg én dag blandt dem, der strømmer forbi, og sæt den forrest og centralt, og selv en almindelig dato får en varme værd at fejre."},"ICON-0314":{"nm":"Samlernummer-mærke","de":"Et unikt nummer tildelt hver eneste ting, man holder af. At samle er at love at kalde netop den ting den eneste i sin art i verden, så tallet på det lille mærke bærer hjertets tydelige vægt."},"ICON-0315":{"nm":"Arkiv-lomme","de":"En tynd inderlomme man skyder hver længe gemt ting ind i, én ad gangen. At sætte noget blot ét lag væk fra lys og tid – at elske noget er, i sidste ende, at kunne bevare det godt."},"ICON-0316":{"nm":"Fotokort-toploader-rem","de":"En slank rem der lader dig hænge en toploader om halsen. Det er en måde at være fan på, at gå gennem dagen med sin favorit tæt ved brystet, og på denne ene tynde snor er en hel dags ømme følgeskab bundet fast."},"ICON-0317":{"nm":"Fotokort-standernål","de":"Med bare én lille nål rejser et fotokort sig oprejst på skrivebordet. Liggende ned er det blot et stykke papir, men rejst op bliver det til et ansigt, man møder øje mod øje, og skaber stille et sted, hvor blikket kan dvæle længe."},"ICON-0318":{"nm":"Holo-fotokort-film","de":"Et enkelt tyndt lag film, hvor regnbuer strømmer ned ved hver eneste vinkel. Et lag der fanger lidt lys, klæder et almindeligt kort i stjerneskær, en lille magi hvor et nyt udtryk vågner glitrende, hver gang man svipper med håndleddet."},"ICON-0319":{"nm":"Fotokort-beskyttelseshylster","de":"Ét tryk på hjørnet, og det føles, som om selve det hjerte, man holder af, bukker med. En klar rustning der tæt omfavner ét dyrebart ark – denne form for omsorg følger altid med, når man virkelig værdsætter noget."},"ICON-0320":{"nm":"Fotokort-sorteringsbakke","de":"En lavtsiddende bakke der lægger snesevis af fotokort ned pænt, korn for korn. Spredt ud er de blot en bunke, men lagt i rækker bliver de til en samling, og kærlighedens rækkefølge indridses med hver ordnende hånd."},"ICON-0321":{"nm":"Fotokort-bytte-kuvert","de":"Når man lægger et fotokort i en kuvert for at give det væk, tøver fingerspidserne et øjeblik. Det er ikke at sende det bort, men at bede det om at blive en andens favorit. I det øjeblik man folder klappen ned, skifter et lille bånd stille hænder."},"ICON-0322":{"nm":"Fotokort-pyntepen","de":"Det, der fylder det tomme rum, er ikke skrift, men følelse. Overalt hvor spidsen har været, spirer små hjerter og stjerner frem, og et almindeligt ark papir vågner som et heppekor uden sidestykke i verden. At pynte er blot et andet navn for tilståelse."},"ICON-0323":{"nm":"Fotokort-klipsering","de":"Klik, lyden af en klemme, der bider fast. Med den ene lille lås samles kort, der næsten var spredt, i én række. Selv rystet hele dagen i en taske, forbliver ikke et eneste hjørne skadet. Styrke er så stille som dette."},"ICON-0324":{"nm":"Fotokort-transportpung","de":"En vane har sat sig i hånden, der lyner den op og i. Gennem en pludselig byge, gennem en trængsel af mennesker, forbliver kun det indre tørt. At holde det, man elsker mest, på det dybeste sted – det er transportens ømme arbejde."},"ICON-0325":{"nm":"Fanmøde-armbåndssnor","de":"Én fan huskede længe, hvor varme personalets hænder var, da de bandt snoren om håndleddet. En enkelt knude markerer, at man hører til her i dag. Viklet to gange rundt, så den ikke går op, holder den snor en hel dags spænding på plads."},"ICON-0326":{"nm":"Adgangs-armbånd","de":"I selve det øjeblik man passerer indgangen, deler inde og ude sig endelig tydeligt. Båret hele dagen bliver det snart fortroligt mod huden, og når man tager det af, er der et tyndt mærke tilbage – som et bevis på det sted, man var."},"ICON-0327":{"nm":"Snakhjørne-chip","de":"Når snakhjørnet åbner, ruller en chip afsted. Hvem taler først, hvilket spørgsmål bliver trukket – den lille tilfældighed ændrer hele stemningen. Én chips lune er mere yndig end noget nedskrevet manuskript."},"ICON-0328":{"nm":"Signeringskø-billet","de":"Man stiller sig i kø med en nummereret seddel i hånden. Nummer 142. Mens man tæller de 141 foran, tæller hjertet allerede sin tur først. Ventetiden er lang, men takket være denne ene seddel bliver selv den tid en del af begejstringen."},"ICON-0329":{"nm":"High-touch-handske","de":"I det øjeblik håndfladerne mødes, modtager handsken den korte varme i ens sted. En hånd opvarmet hele dagen for et 0,5-sekunders møde. At selv stof ikke kan blokere netop den sitren, forstår enhver først da."},"ICON-0330":{"nm":"Minde-fotonål","de":"Klik, én lyd, og dagen bevares præcis som den var. Inde i rammen fastholdt af en nål bliver selv et akavet smil siden hen den mest savnede scene. At dokumentere er den ømmeste grådighed efter at holde fast i et øjeblik."},"ICON-0331":{"nm":"Sæderyg-sløjfemærke","de":"En lille sløjfe hængt på et sæderyg vugger, selvom der ikke er nogen vind. Et mærke nogen har bundet, et spor af, at der var et menneske her. Selv i den tomme stol efter forestillingen synes kun sløjfen stadig at huske takten."},"ICON-0332":{"nm":"Gavekontrol-etiket","de":"Et mærkat sættes på hver eneste gave. Er den sendt, er den tjekket, mangler der noget. Selv det at modtage nogens hjerte kræver husholdning, så denne lille etiket knytter omsorg til omsorg uden et eneste hul."},"ICON-0333":{"nm":"Minde-seddel","de":"Et ark papir skrevet for at gemme og gense i lang tid. Vejret den dag, sædenummeret, selv titlen på den sidste sang. Erindringen falmer, men kun denne seddel gør det ikke. Selv at gemme et minde kræver sin lille skabelon."},"ICON-0334":{"nm":"Heppehåndklæde-krog","de":"Sæt en krog på enden af et håndklæde, og det glider ikke ned fra skulderen. Mellem at tørre sved, svinge det over hovedet og slynge det tilbage om halsen – én lille forbindelse holder heppebevægelserne ubrudte."},"ICON-0335":{"nm":"Slogan-klemme","de":"Klemmer griber fast om begge ender af et slogan. Så selv med begge arme løftet højt folder bogstaverne sig ikke og flagrer ikke bort. Her er den mest trofaste birolle, der retter budskabet ud af syne."},"ICON-0336":{"nm":"Lyddæmpende pung","de":"Lynlåsen glider langsomt, lydløst. En stilhed designet, så ikke én eneste lyd slipper ud, hvor ro er lovet. Hensynsfuldhed er nogle gange det at gøre sig uhørlig, siger denne pung stille."},"ICON-0337":{"nm":"Klap-rytmechip","de":"Hver gang håndflader mødes, tæller chippen takten. Klap, klap, klap – spredte klap samles på et øjeblik til én rytme. Det trylleri, hvor tusindvis af klap bliver til ét åndedrag, hjælper en lille chip stille til."},"ICON-0338":{"nm":"Heppevejledning-mappe","de":"Slår man den op, står heppevejledningen skrevet trin for trin. Hvilken farve man løfter til hvilken linje, hvornår man skal råbe. Selv en førstegangsgæst bliver hurtigt en del af familien med denne ene mappe. En lille guide til at dele et løfte."},"ICON-0339":{"nm":"Sædevifte-snor","de":"Bind en snor til viftens håndtag, og den falder ikke, selv hvis den glipper af grebet. På en varm dag, når begge hænder frigøres til at heppe efter at have viftet, dingler den fra håndleddet. Én snor køler både varme og begejstring på én gang."},"ICON-0340":{"nm":"Glimmerfilm-stykke","de":"Fanger den lys, splintrer hvert stykke det i en anden vinkel. Læg den på håndfladen, og en lille regnbue skimrer, farverne lever med hvert lille rist. Måske er glimmer blot det at dele lys op i tusind bittesmå stykker."},"ICON-0341":{"nm":"Mini-bannerstang","de":"Fold den lille stang ud, og stoffet strammes af vinden. Løft den højt med begge hænder, og bogstaverne når helt ud over tilskuerrækkerne, fold den sammen, og den passer i et hjørne af tasken. Hjertets størrelse måles ikke af stangens længde."},"ICON-0342":{"nm":"Heppeklistermærke-pakke","de":"Hvert enkelt klistermærke er præget med en heppefrase. På en planlægger, på en telefon, på hjørnet af en bærbar – hvor end man klistrer dem, farves hverdagen af opbakning. Sådan efterlader et hjerte, der holder af noget, spor overalt."},"ICON-0343":{"nm":"Albumbeskyttelses-cover","de":"Hånden der pakker albummet ind i et cover, er forsigtig. Så hjørnerne ikke slides, så det ikke blegner i solen. Musik høres med ørerne, men dette ene ark huskes af hænderne. En rustning for hjertet, der vil holde det, man værdsætter, tæt på i lang tid."},"ICON-0344":{"nm":"Disk-lomme-ring","de":"Sæt diske i lommer og bind dem sammen med en ring, og de bliver til en pladebog. Raslelyden hver gang man bladrer et ark om, er dejlig. At samle spredt musik pænt i hånden – det er en samlers stille lykke."},"ICON-0345":{"nm":"Fanartikel-opbevaringsskillevæg","de":"Med bare én skillevæg finder fanartikler, der nær var blevet blandet sammen, deres plads. Her fotokort, der nøgleringe, ved siden af lyspinde. At organisere er at bygge huse til ting. I det øjeblik rummene deles, vender rod sig til orden."},"ICON-0346":{"nm":"Randompakke-forseglingssnor","de":"Bind munden på en randompakke fast med en snor, og ingens skæbne er afgjort endnu. Indtil man løsner den, er alle hovedpersonen i deres eget håb. Netop den sitren i fingerspidserne, der løsner forseglingen, er den glæde, denne snor har vogtet."},"ICON-0347":{"nm":"Fanartikel-sorteringsboks","de":"Ekstramaterialer stiller op efter type inde i en boks. Postkort med postkort, bogmærker med bogmærker. Se rummene blive tættere fyldt, som samlingen vokser, og al den tid man har brugt på at samle, kommer ind i synsfeltet på ét blik. At sortere er at føre en liste over minder."},"ICON-0348":{"nm":"Version-sorteringsetiket","de":"Der findes ting, der ser ens ud, men ikke er det. Én etiket skiller Version A fra Version B, førsteoplaget fra genoptrykket. Takket være et lille mærke forsvinder forvirringen, og et klart navneskilt sættes på samlerverdenen."},"ICON-0349":{"nm":"Førsteuges-salgstjekmemo","de":"Udgivelsesuge, og et enkelt tal får hjertet til at svaje. Afkrydsningsmærker skrevet sirligt på en notesblok. Saml et par dages optegnelser sammen, og det bliver et lille karakterbevis for opbakning. En omhyggelig vane med at oversætte et kært hjerte til tal."},"ICON-0350":{"nm":"Poster-fastgørelseshætte","de":"Sæt en hætte på enden af en sammenrullet plakat, og den forbliver stille udfoldet. Så den ikke krøller, mens man overvejer, om den skal hænges op eller rammes ind. En lille prop der holder ens yndlingsscene helt lige."},"ICON-0351":{"nm":"Foto-ståfod","de":"Et foto står på skrå på foden. I et hjørne af skrivebordet, i netop den rette vinkel til øjenhøjde. En opfindelse der får øjnene til at mødes, hver gang man går forbi. Den enkleste måde at bringe et elsket ansigt ind i hverdagens billede."},"ICON-0352":{"nm":"Øvetape-rulle","de":"Tape klæbes på gulvet for at markere, hvor man skal stå. Ét mærke, to mærker, præcis her. Ved at træde på de samme pletter snesevis af gange indridses bevægelserne i kroppen. Under en strålende scene ligger disse ærlige tapespor."},"ICON-0353":{"nm":"Scene-positionsnål","de":"En enkelt nål stukket ned i scenegulvet fortæller det næste skridt. Selv i mørket finder tåspidsen stedet først. En præcis vej man ikke kan se, et usynligt kort tegnet af utallige prøver."},"ICON-0354":{"nm":"Personale-øreprop","de":"Sæt ørepropperne i, og publikums brøl dæmpes ét lag, mens kun stemmen, der giver signalerne, forbliver klar. Personalet bag scenen hører altid to verdener på samme tid. Et lille redskab til at udsortere signalet midt i larmen."},"ICON-0355":{"nm":"Backstage-bøjlemærke","de":"Et navneskilt hænger på hver bøjle. Kostume 1, kostume 2, ekstranummer-kostume. Se på det skema, der lister skifterækkefølgen, og dagens optræden er tegnet op på forhånd i tøjets rækkefølge. En stille orden der tæmmer travlheden."},"ICON-0356":{"nm":"Rekvisit-kontrolmærke","de":"Før man går på scenen, fastgøres et mærke til hver eneste rekvisit. Mangler der noget, er alt i orden. Publikum ved det ikke, men denne lille kontrol forhindrer uheld. Bag en tilsyneladende fejlfri scene er der altid en omhyggelig hånd."},"ICON-0357":{"nm":"Cue-signalchip","de":"En cue-chip vandrer fra hånd til hånd. Nu, gå ind. Et øjeblik hvor timing gives videre uden et eneste ord. I mørket ved siden af scenen holder dette lille signal alle fra at miste takten."},"ICON-0358":{"nm":"Backstage-emblem","de":"Der er en dør, kun de, der bærer dette emblem, må passere. Bag scenen, hvor jubel høres gennem væggen. Et lille stykke stof deler den strålende forside fra den travle bagside. Mærket for dem, der bærer scenen oppe."},"ICON-0359":{"nm":"Prompter-skærmplade","de":"En skærmplade holder prompterens lys fra at sive ud til tilskuerrækkerne. Kun personen på scenen ser det, iagttagerne aner intet. En høflig vogter af scenens hemmelighed, der stille skjuler en hjælp, der ikke må opdages."},"ICON-0360":{"nm":"Backstage-spejlbetræk","de":"I omklædningsrummet efter forestillingen dækkes spejlet med et klæde. Glasset, der spejlede utallige udtryk hele dagen, lukker øjnene et øjeblik. Det, et sminkefrit, bart ansigt til sidst møder, er ikke spejlet, men den stille mørke."},"ICON-0361":{"nm":"Forhåndsoptagelse-armbånd","de":"Et lille bånd der, når det først er lukket, ikke går op, før det klippes over. For den ene ret til at komme ind til pladserne ved forhåndsoptagelsen tog nogen det første tog i den mørke daggry. Vægten om håndleddet bliver en hel dags spænding."},"ICON-0362":{"nm":"Optagelses-standbymærke","de":"Lige før det røde lys tændes, er det mit job at binde alles åndedrag sammen i én linje. I stilheden mens man venter på cue-signalet holder jeg stille ud til allersidst. I det øjeblik jeg trækkes af, går tæppet endelig op for selve udsendelsen."},"ICON-0363":{"nm":"Kameraposition-chip","de":"Ét lille mærke stemplet på gulvet fastlægger dygtigt seks kameraers bevægelser. Hvor man skal fanges for at se mest strålende ud, ved instruktøren allerede før prøven. En hånd der tegner det, der bliver inden i billedet, forud, udefra."},"ICON-0364":{"nm":"Lydtjek-mærkeseddel","de":"Man banker let, let på mikrofonen ud mod de tomme sæder. Er ekkoet langt, ét lag mere lydabsorberende materiale i loftet. Omhuen med at forfine lydens korn, mens publikum aldrig aner det, begynder stille fra denne lille mærkeseddel."},"ICON-0365":{"nm":"Besøgsstempel-bog","de":"Hver gang man besøger et sted, samler man endnu et stempel i et felt. I hvert udtværet blækmærke er den dags vejr og hjertebanken stemplet med. En helt udfyldt side bliver til et fodsporskort, ingen andre kan efterligne, kun mit eget."},"ICON-0366":{"nm":"TV-station-besøgssnor","de":"Uden denne snor åbner lobbygaten sig ikke. Båret om halsen, mens man går korridoren igennem skridt for skridt, kommer den verden, man indtil i går kun så på skærmen, langsomt tæt nok på til at røre."},"ICON-0367":{"nm":"Studio-overtræksko-pakke","de":"Studiogulve er altid kolde og glatte. Tag skoene af, tag tynde overtræksko på, og fodtrinene forsvinder stille. Kameraet fanger dansen, ikke fodtrinene, så at slette lyden er også en høflighed over for scenen."},"ICON-0368":{"nm":"Backstage-snackmærke","de":"Mellem prøve og selve udsendelsen kommer sulten mest ærligt. Et lille navneskilt på hver snack i omklædningsrummet fortæller, hvis den er. Den omsorg, det er at lægge ting til side, bærer én gennem den lange, lange dag til enden."},"ICON-0369":{"nm":"Gennemsyns-memobånd","de":"Man ser optagelsen igen og skriver. Et blik her, et halvt slag der. Den tætskrevne håndskrift er et hemmeligt brev til morgendagens jeg. Båndet klistret på enden er et stille løfte om at være en hånd bedre end i går."},"ICON-0370":{"nm":"Showcase-invitationsseddel","de":"Ét stykke papir kan for nogen betyde et helt års ventetid. En kort linje der inviterer til showcaset, født som verdens mindste invitation, der bærer selv sitren fra fingerspidser, der åbner kuverten."},"ICON-0371":{"nm":"Presse-halssnor","de":"Hængt om en journalists hals væver den sig gennem hjertet af lukkerklikkene. Fødder der iler travlt for at finde den bedste vinkel, og netop den hastighed bliver til passagen, der bærer scenens hede ud til den vide verden."},"ICON-0372":{"nm":"Sceneafslutning-rækkefølgeskema","de":"Så ingen falder ud af trit, selv i det øjeblik klapsalver vælder ned, skrives det, hvem der er først og hvem der er næst, i én linje. Den afsluttende hilsens opstilling arrangeres lige så omhyggeligt som selve den første entré."},"ICON-0373":{"nm":"Fotovæg-gulvmarkering","de":"Foran fotovæggen er stedet til tåspidserne indridset på forhånd. Bare ét skridt ved siden af, og logoet i baggrunden bliver skåret af. Hemmeligheden bag den position, hvor man fanges mest strålende, er stille markeret under fødderne."},"ICON-0374":{"nm":"Premiere-armbånd","de":"Et lille bånd fastgjort om håndleddet lige før biograflysene slukkes. Når tæppet går op, møder alle den samme scene for allerførste gang i det samme mørke. Et lille mærke for at have været der i det første øjeblik."},"ICON-0375":{"nm":"Minde-gardinstykke","de":"På den sidste forestillingsdag sænkede gardinet sig langsomt efter den sidste bukning. Et stykke klippet fra den bane og sat i en ramme. I stoffet hænger stadig lampernes hede og klapsalvernes dirren lunkent, endnu ikke afkølet."},"ICON-0376":{"nm":"Debutafsløring-stempel","de":"Et stempel indgraveret til den ene dag, man første gang viser sig for verden. Der findes ingen anden første afsløring, så selv det korte øjeblik, blækket tørrer, er en tid der aldrig vender tilbage."},"ICON-0377":{"nm":"Scene-øjebliks-kort","de":"Det mest strålende billede fra en scene, klippet ud og sat på et kort. Musikken og lyset er standset, men i det øjeblik det ligger i hånden, svulmer den dags jubel op igen ved ørerne. En lille magi hvor et fastfrosset billede vågner til live."},"ICON-0378":{"nm":"Slutpositur-memo","de":"En memo der tegner vinklen på fingerspidser og blik, som skal fryse i det øjeblik den sidste tone slutter. Kun den, der ved, at ét afsluttende billede kan påvirke dage, folder denne lille tegning omhyggeligt sammen."},"ICON-0379":{"nm":"Turné-bynål","de":"På kortet stikkes en nål ind for hver by, man har besøgt. Både Busans havbrise og Gwangjus middagssol sidder fast på disse små nålespidser. Forbind prikkerne stille, og man ser linjen af en lang rejse, der krydsede en hel sæson."},"ICON-0380":{"nm":"Sædesektion-klips","de":"Den deler titusindvis af sæder op i sektioner og viser vej. Så man ikke farer vild, så man ikke støder ind i nogen. Følg mig, og enhver når frem til sin plads. Orden er, i sidste ende, en lille venlighed for alle."},"ICON-0381":{"nm":"Indgangsport-mærke","de":"Ved porten går man igennem et tjek, én person ad gangen, i tur. Den sidste port der lukker en billet-holdende hånd og et bankende hjerte indenfor. I det øjeblik man passerer mig, ender den lange ventetid, og dagens forestilling begynder."},"ICON-0382":{"nm":"Armbånd-opbevaringskapsel","de":"Selvom farven falmer, forsegles netop den dags jubel som den var. Ude af stand til at kassere båndet fra håndleddet ruller man det sirligt sammen i en lille kapsel. Fordi selv et dyrebart minde fortjener ét lille rum at lægge sig ned i."},"ICON-0383":{"nm":"Udvekslingsstang","de":"Mellem fan og scene passerer noget fra hånd til hånd. Det kan være et brev, det kan være en lille gave. Jeg baner vejen, så det hjerte når sikkert frem, den travleste bro på stedet."},"ICON-0384":{"nm":"Forestillingsdato-segl","de":"Den dags dato stemples fast inde i et rundt segl og standser for evigt. Kalenderen blader videre, men kun denne lille cirkel bliver stående i netop den ene dag. Når det er en dag, man ikke vil glemme, forsegler folk altid noget."},"ICON-0385":{"nm":"Turné-tasklap","de":"En taske der har fulgt med på turné, får ét emblem mere for hver by. Stednavnene syet på stoffet bliver før man ved af det til et cv. Selv de slidte, flossede hjørner forbliver som bevis på at have været alle vegne sammen."},"ICON-0386":{"nm":"Billetskilt-snor","de":"Et skilt der vugger for enden af indgangskøen, dets spids bundet fast af en enkelt snor. Midt i synet af hænder der løfter billetter højt i en lang række markerer jeg stille hovedet af en procession, hvor spænding står i kø."},"ICON-0387":{"nm":"Ekstranummer-sløjfestykke","de":"Den nat hvor råbene efter et ekstranummer var højest, faldt et stykke af sløjfen, der pyntede scenen, af. Som en sang sunget længere, fordi det var synd at slutte, er der også i dette stykke en modvilje mod at gå knyttet fast."},"ICON-0388":{"nm":"Beskedkapsel-flaske","de":"Et enkelt ord foldet sirligt sammen inde i en glasflaske. Som en lille båd sat ud i håb om en dag at nå frem, bærer jeg et hjerte og driver langsomt hen over tiden. Indtil den dag den åbnes, sover løftet stille indeni."},"ICON-0389":{"nm":"Lille tilståelsesmærke","de":"Ord man ikke kunne få over sine læber, skrevet på et lille mærke og stukket stille ind. Håndskriften rystede, men kun oprigtigheden var tydelig. Der findes tidspunkter, hvor det mindste stykke papir rummer det største mod."},"ICON-0390":{"nm":"Anonym heppeseddel-boks","de":"Selv uden et navn skrevet, når hjertet frem. For hver seddel der lægges i boksen, hober endnu en anonym opbakning sig op, ét ark ad gangen. En samling af ansigtsløs ømhed, hvor kun varmen er tydelig, selv om man ikke ved, hvem der skrev."},"ICON-0391":{"nm":"Ønskefoldepapir","de":"Et firkantet stykke papir bliver til en trane, bliver til en stjerne, i takt med fingerspidserne. For hver fold lægges også ønsket et lag oveni. I en omhyggeligt foldet form bor en oprigtighed, der varer længere end ord."},"ICON-0392":{"nm":"Segllak","de":"Drys voksen ned og pres stemplet fast, og brevet er endelig forseglet. Præcis den gamle måde at befæste et hjerte på. Oven på den kølnende røde voks lukker en hemmelighed sig stille inde."},"ICON-0393":{"nm":"Gave-polstringspapir","de":"Af frygt for at gaven kan tage skade, omslutter det den blidt hele vejen rundt. I hver eneste krøllede fold siver en bøn om ikke at gå i stykker. Et omsorgsfuldt lag på et usynligt sted, som modtageren sandsynligvis vil overse uden at mærke det."},"ICON-0394":{"nm":"Farvet brevsnor","de":"Selv snoren, der binder et brev, har farve. Gult for opbakning, blåt for savn. Følelser ord ikke helt kan rumme vælges efter nuance og knyttes fast. Før man overhovedet løser den op, når hjertets temperatur allerede fingerspidserne først."},"ICON-0395":{"nm":"Håndskrift-dækbånd","de":"Et enkelt bånd der skjuler skriften helt frem til det øjeblik, den gives videre. Det vogter en tilståelse, ængstelig for at blive opdaget, helt til det allersidste sekund. Den oprigtighed der afsløres, når man løfter det en anelse, den sitrens vægt kender jeg nærmest af alle."},"ICON-0396":{"nm":"Heppefrase-chip","de":"På en nat hvor lyspindene bølger, er en enkelt sætning, der skal råbes med én stemme, indgraveret i chippen. Løftets ord der samler spredte hjerter i én linje. Når alle synger den sammen, skinner den sætning allerstærkest."},"ICON-0397":{"nm":"Slidt øvelokale-nøglering","de":"En nøglering der har åbnet og lukket øvelokalets dør hundredvis af gange. Malingen er skallet af, og ringen er blevet løs, men i den er sveden fra de mest kejtede tider blevet til brugsspor. At være slidt betyder, at man har blevet der netop så længe."},"ICON-0398":{"nm":"Scenesminkestift","de":"Scenesminke fuldendes først under lyset. Et stykke af den dybe farve. I sporet, der blev lagt fast, så det ikke tabte sig i sveden, hænger stadig omsorgen for at bære et udtryk helt ud til de fjerneste rækker."},"ICON-0399":{"nm":"Ørepropæske","de":"De små ørepropper der lod dig høre din egen stemme på scenen. Når forestillingen slutter, lægger man dem sirligt ned i æsken. Jo tættere noget bar musikken til én, jo mere omhyggeligt vil man passe på det."},"ICON-0400":{"nm":"Personligt skab-mærkat","de":"For enden af korridoren i bostedet er der et navneskilt på hvert skab. Den lille skrift, der fortæller, hvis plads det er, forvandler et fremmed rum til et hjem. At få sit eget rum er en øm tilladelse til at blive her."},"ICON-0401":{"nm":"Bærbar halsplejeflaske","de":"Mellem øveprøverne synker du langsomt en slurk lunkent vand. Halsen er et instrument, sangeren blot låner, så denne lille flaske, fyldt før vandet køler af, våger i forvejen over morgendagens første tone. Et ømt hjerte er altid så stille."},"ICON-0402":{"nm":"Skemapåmindelsesnål","de":"Over en dag proppet minut for minut peger en nål på den næste rude. Blandt de tætpakkede rækker er det kæreste den ene tomme rude. Tiden, hvor man må kigge ud ad vinduet, gemmer sig der, helt lille."},"ICON-0403":{"nm":"Tæppeklemme til det grønne værelse","de":"En eftermiddag, hvor du dysede hen mod en stol med sminken helt færdig, lagde nogen stille et tæppe om dine skuldre. Denne klemme, der bider fast, så det ikke gled af, holder stille fast i varmen fra den berøring, lige til du skal på scenen."},"ICON-0404":{"nm":"Lille parfumeprøve","de":"Dupper man den let på indersiden af håndleddet, blomstrer duften kun inden for en håndsbredde. Det gør ikke noget, at den ikke spreder sig langt. Et spor kun dem, der er kommet tæt på, opdager, mere hemmeligt af den grund - og derfor mere mig."},"ICON-0405":{"nm":"Vaskemærke til øvetøj","de":"Uanset hvor mange gange man vasker det, forsvinder svedlugten, der har sat sig dybt i stoffet, aldrig helt. Mens du folder øvetøjet, der er hængt til tørre i solen og er blevet dejligt blødt igen, tænker du: det mærke, der ikke går væk, er faktisk det mest ærlige spor."},"ICON-0406":{"nm":"Lysgelfilm","de":"Sæt et enkelt tyndt farvet filter i, og det hvide lys flyder ud i solnedgangsfarver; læg endnu et lag på, og daggryet sænker sig. Bag gardinet holder en hånd vejret, mens den klæder selv lyset på og vælger, hvilken årstid scenen skal farves i."},"ICON-0407":{"nm":"Linsehætte til spotlys","de":"Selv mens kameraet er slukket, åbner nogen denne lille hætte for at rengøre linsen. Til den næste scene, der endnu ikke er filmet. Over den tid, der aldrig fanges på skærmen, indstiller den travleste hånd fokus i forvejen."},"ICON-0408":{"nm":"Scenereflektorplade","de":"Der findes en plade, som ikke selv lyser, men som sender det modtagne lys tilbage mod et skygget ansigt. Midten af scenen er så strålende, fordi der ude i kanten er en arm, der tavst retter vinklen og kaster lyset tilbage."},"ICON-0409":{"nm":"Farvefilterhylster","de":"Sæt blåt lys i det gennemsigtige hylster, og hele tilskuerpladsen bliver til et hav; skift til rødt, og en solnedgang falder på samme sted. Magien i, at den samme scene bliver en anden årstid med bare én farve, begynder i dette ene tynde lag."},"ICON-0410":{"nm":"Lysnummernål","de":"Hvert af de utallige lys har et lille nummer. Hvilket der tændes, og hvilket der sover, aftenens forestilling er lagt til rette på forhånd efter rækkefølgen af disse tal. Bag det blændende tæppe ligger der altid en omhyggelig liste opslået."},"ICON-0411":{"nm":"Lysende tapemarkering","de":"På den mørklagte scenegulv oplyser fluorescerende tape stille det sted, hvor foden skal standse. Usynligt fra tilskuerpladsen, men den optrædendes tæer famler efter dette svage lys for at finde deres plads. Selv i mørket findes der en øm vejviser."},"ICON-0412":{"nm":"Skyggeblokerende plade","de":"En plade, der blokerer det lys, der siver ind, så en skygge falder skarpt. At håndtere mørket er, i sidste ende, at håndtere lyset, så hvad man skal vise, afgøres først af, hvad man stille vælger at skjule."},"ICON-0413":{"nm":"Lysstyrkemåler-chip","de":"En lille chip, der måler rummets lysstyrke, aflæser tal i din håndflade. For meget lys, eller for lidt, gør begge dele øjnene utilpas. Denne chip vogter i stilhed over den usynlige, rette grænse, hvor mennesket hviler mest behageligt."},"ICON-0414":{"nm":"Punktlysskærm","de":"En skærm monteret, så punktlyset ikke siver ud det forkerte sted. At samle lyset om kun én person er en øm form for opmærksomhed. I det øjeblik man træder ind i den runde lyskreds, ser verden et kort øjeblik kun på ét menneske."},"ICON-0415":{"nm":"Ørepropsæt","de":"Et par ørepropper, der slutter tæt om øret. Er størrelsen bare en anelse forkert, siver lyden ud, og i samme øjeblik mister man taktfastheden. En sang uden så meget som en hårs bredde vaklen på scenen begynder somme tider netop i dette lille stykke gummi."},"ICON-0416":{"nm":"Kabelvelcrostrop","de":"En velcrostrop, der samler forviklede ledninger i én ordentlig streng. Jo mindre nogen ser det, bag scenen, jo mere skinner ryddeligheden. Ordenen i én kabelbundt bærer stille sit lod af den lyd, der flyder urokkeligt derude foran."},"ICON-0417":{"nm":"Linjekontroletiket","de":"Navneskilte, håndskrevet på snesevis af ledninger, der fortæller, hvilket instrument der er hvilket. Kun når hver eneste ujævne bogstav i den skrift holder sin plads, kan lyde, der spillede hver for sig, endelig flyde sammen til én sang."},"ICON-0418":{"nm":"Lyddæmpende måtte","de":"En enkelt lyddæmpende måtte, der stille sluger både fodtrin og skælven. Den lægges dér, hvor stilhed virkelig er nødvendig. Den klareste lyd fødes somme tider først på dette stille gulv, hvor ingen støj overhovedet slipper ud."},"ICON-0419":{"nm":"Lydcheck-token","de":"En token, der bliver varm i hånden, mens lyden justeres inden forestillingen. Hver gang en mikrofon, en højttaler er tjekket, flyttes den til et nyt greb. Hovedscenens fuldkommenhed formes skridt for skridt i denne stille generalprøve."},"ICON-0420":{"nm":"Mikrofonhætte","de":"Fordi det er stedet, hvor så mange stemmer har rørt ved, rengør du med endnu mere omhu denne hætte, der omslutter mikrofonens spids. Det er et kar, der bærer en sang, så for sangeren er det som endnu en hånd. Mens du tørrer den af, tegner du allerede morgendagens første vers i tankerne."},"ICON-0421":{"nm":"Popfilterklemme","de":"Et tyndt net hængt mellem læber og mikrofon. Takket være den lille klemme, der holder skærmen på plads, bliver åndedrag, der ellers ville sive ru ud, snart glattet til en rund, blød stemme, der flyder frit."},"ICON-0422":{"nm":"Lydstativmærke","de":"Et lille mærke hængt op, så man ikke farer vild mellem hylder fyldt med udstyr i det bælgmørke bag scenen. Kilden til den strålende lyd, der fylder tilskuerpladsen, er altid ordnet omhyggeligt netop på sådan et dunkelt sted."},"ICON-0423":{"nm":"Højttalergitternål","de":"En nål, der fastholder højttalernettet solidt. Vinduet, hvor lyden slipper ud, er det første sted, støvet rammer, så et tyndt lag net vogter tonen. Alt, hvad der når øret, er beklædt med et usynligt lag beskyttelse."},"ICON-0424":{"nm":"Trinmarkeringsklistermærke","de":"Klistermærker sat prik for prik på gulvet til at markere bevægelserne. Hemmeligheden bag, at gruppedansen falder på plads som et knivsnit, ligger faktisk gemt lige under fødderne. Ovenpå utallige aftalte mærker, hvor snesevis af fødder træder på det samme punkt, spredes og samles igen."},"ICON-0425":{"nm":"Drejeøvelsesskive","de":"En øvelsesskive, der snurrer rundt og rundt på stedet. For at overvinde svimmelhed lærer man først at fæstne blikket på ét fast punkt. Uanset hvor hurtigt man drejer, mister man aldrig det ene punkt af syne - en balance, der langsomt indprentes i kroppen."},"ICON-0426":{"nm":"Knætaperulle","de":"En rulle tape, der vikles stramt om knæet. Led, der har sprunget og landet tusindvis af gange, forbliver tavse til sidst, men dette ene lag bærer stille den tavshed oppe. Bag en krop, der holder ud til det sidste, er der altid nogens omsorg."},"ICON-0427":{"nm":"Tåretningsplade","de":"En plade, der stiller tæernes vinkel pænt på plads. Man siger jo, at dansen fuldendes i tæerne snarere end i fingerspidserne. Snesevis af tæer strakt i samme retning samles og væver den magi, hvor mange ser ud som én."},"ICON-0428":{"nm":"Skridsikker øvelokalemåtte","de":"En skridsikker måtte lagt på øvelokalets gulv. For at kunne springe frit må man først være tryg. Kun på et gulv, hvor man kan rulle rundt uden frygt for at falde, blomstrer de dristigste, mest frygtløse bevægelser til sidst."},"ICON-0429":{"nm":"Bevægelsesopdelingskort","de":"Et kort, der deler koreografien op i små bidder, ét taktslag ad gangen. Uanset hvor svær en bevægelse er, deler man den op felt for felt, og pludselig følger man med. Den flydende, vandglatte bevægelse på scenen er skabt af netop sådanne opdelte, udenadlærte tegninger, samlet i ét."},"ICON-0430":{"nm":"Spejlgardinnål","de":"En nål, der holder det gardin på plads, som et øjeblik dækker øvelokalets spejl. Der er også brug for tid, hvor man danser alene ud fra kroppens fornemmelse, uden noget spejlbillede. Man ved, at i det øjeblik spejlet dækkes til, siver musikken endelig helt ind under huden."},"ICON-0431":{"nm":"Taktkuglerække","de":"Klik, for hvert taktslag skubber man en kugle videre med fingerspidsen og tæller takten. Håndgribeligt, ligesom en gammel talemetode. Takten, musikkens rygrad, sætter sig først for alvor fast i kroppen, når man lærer den gennem noget, man kan røre ved på denne måde."},"ICON-0432":{"nm":"Opvarmningssnor","de":"En kontrolsnor, der markerer, om kroppen er varmet grundigt op. Før den egentlige øvelse kommer der altid en rolig forberedelse først. Frem for at fortryde efter en skade lader det, at man binder en snor og langsomt vækker kroppen, én danse længere i sidste ende."},"ICON-0433":{"nm":"Kostumenummerklemme","de":"En klemme, der bider et nummer fast på hvert kostume, så de mange ikke bliver blandet sammen. Under et åndeløst hurtigt tøjskifte er selv ét ombyttet stykke tøj en katastrofe, så hvert stykkes tur er tydeligt markeret. Selv travlhed bliver elegant, når orden bærer den oppe."},"ICON-0434":{"nm":"Nålepude fra syrummet","de":"En nålepude placeret i et hjørne af syrummet. Her hviler den hånd, der tavst har lukket sprængte sømme og faldne knapper. Bag den fejlfrie pasform på scenen gemmer sig omhuen fra sting, der aldrig selv har set scenen."},"ICON-0435":{"nm":"Stofprøvering","de":"En ring, der samler ekstra stofstykker på én snor. Det samme stof lægges til side på forhånd, i tilfælde af at hovedkostumet skulle blive skadet. Denne lille forberedelse, gemt i håbet om, at intet går galt, redder scenekostumet netop i det øjeblik, det store uheld indtræffer."},"ICON-0436":{"nm":"Hurtigknappakke","de":"En pakke knapper, man straks kan sy i, når det haster. Lige før forestillingen, hvis en knap pludselig falder af, går der et sæt gennem hele sminkerummet. Denne lille, men uvurderligt pålidelige nødhjælpspakke lægger den korte, svimlende nødsituation til ro med det samme."},"ICON-0437":{"nm":"Scenebeltholder","de":"En holder, der fastholder scenekostumets bælte solidt. Så tøjet ikke går i uorden, uanset hvor voldsomt man springer og drejer. Den frihed, man nyder fuldt ud på scenen, kommer i sidste ende fra, at det usynlige er strammet omhyggeligt til."},"ICON-0438":{"nm":"Fjerkost","de":"Under lyset stikker selv den mindste fnug i øjnene, så man fejer forsigtigt hen over kostumet med en fjerkost. Lige før man sætter foden på scenen, hører den sidste ømme berøring, der glatter tøjet til, altid til denne bløde fjer."},"ICON-0439":{"nm":"Tøffelmærke til det grønne værelse","de":"Et navnemærke på hver tøffel i det grønne værelse. I et lille skilt, der fortæller, hvis den er, ligger stille lettelsen ved, at vi er samme hold. Det rum, hvor man tager skoene af og strækker fødderne, bliver det hyggeligste hjem bag scenen."},"ICON-0440":{"nm":"Stylingklemmeplade","de":"En klemmeplade, der holder hårlokker på plads, mens man ordner håret. Mens fingrene glatter tot efter tot, betror de kortvarigt håret, der vil sprede sig, til denne klemme. Ryddelighed er, i sidste ende, summen af netop sådanne små pauser."},"ICON-0441":{"nm":"Sikkerhedsnålekapsel","de":"En morgenstund, hvor en søm er sprunget - åbner man kapslens låg, ligger små, kolde sølvglimt pænt i række. En hånd, der holder kostumet fastest fra det usynlige indre - sikkerhedsnålen arbejder altid stille bag scenen."},"ICON-0442":{"nm":"Linserenseklud","de":"Puf, ét åndedrag, og tør rundt i cirkler, og den tågede verden bliver klar. Den korte flygtighed er så god, at man bliver ved med at tørre linsen af. Et lille stykke forårssol, der klarer nogens udsyn i deres sted."},"ICON-0443":{"nm":"Stativgummifødder","de":"Sæt gummi på de tre spidser, og gulvet skriger ikke mere. Mens de små punkter sluger vaklen, falder billedet på skærmen til ro, som om det var løgn. Stabilitet begynder altid stille lige under fødderne."},"ICON-0444":{"nm":"Kameraregnhætte","de":"Selv om regndråber pibler ned, fanger linsen verden tør. På en overskyet eftermiddag med udendørs optagelse trækkes en gennemsigtig regnfrakke blidt over kameraet. For det dyrebare skal, som man siger, svøbes ind, før det bliver vådt."},"ICON-0445":{"nm":"Optagelsesmarkeringstape","de":"Stå her, drej derhen - korte mærker i farver peger vejen ud, tydeligt, uden et ord. Selv når de rives af uden fortrydelse, når forestillingen er slut, husker de vante tæer det sted længe, længe efter."},"ICON-0446":{"nm":"Klipopdelingsklemme","de":"En lille klemme, der bider fat om papirer, der vil sprede sig, i én mundfuld. Klik, én klar lyd, og i går og i dag bindes pænt sammen. At ordne er en øm håndvane, hvor man stille holder fast i det, man nær havde mistet."},"ICON-0447":{"nm":"Hvidbalanceplade","de":"Hold en hvid plade op mod billedet, og farverne finder stille deres rette plads. Den gule solnedgang, den blå daggry, uden løgn. Én plade, der kender den sande hvide farve, får de øvrige farver til at tale ærligt."},"ICON-0448":{"nm":"Hukommelsesdåse","de":"Inde i en lille dåse af blik sover mindets chip trygt. Åbner man låget, klik, vælter forrige sæsons billeder ud i håndfladen. Erindringen hviler, kærligt gemt, i netop sådan en solid dåse."},"ICON-0449":{"nm":"Monitorhætte","de":"Vikl en sort skærm om monitoren, og reflekserne stopper brat. Selv ved et vindue oversvømmet af sollys mister skærmen ikke sin farve. For at se ordentligt må man først skærme mod strøstrejf lys, fortæller hætten stille."},"ICON-0450":{"nm":"Lydisoleringsnål til optagelser","de":"En lille nål, presset ind i dørspalten, skærer stille ekstern støj fra. Hverken skridt i gangen eller latter fra nabolokalet når så langt. For at fange en klar lyd må man først bygge stilheden op."},"ICON-0451":{"nm":"Sminkesvampepakke","de":"Et bundt bløde, buttede svampe lagt pænt oveni hinanden. Dupper man let pudder på med fingerspidserne, lysner ansigtet en nuance. Bag ethvert strålende smil på scenen gemmer sig netop disse bløde, milde berøringer."},"ICON-0452":{"nm":"Hårnåleetui","de":"Et pænt hjem for de små nåle, der så let bliver væk. Åbner man låget, byder rækker af sølv én velkommen. Spredte forsvinder de af syne, men samlet giver de tryghed - selv de mindste ting har brug for deres eget hjem."},"ICON-0453":{"nm":"Børste-UV-boks","de":"Pensler, der har båret farve hele dagen, tager et UV-bad inde i boksen. Mens usynligt lys vasker det gamle bort, bliver morgendagens børstespids blød som ny igen. Renlighed er også en fold af omhu."},"ICON-0454":{"nm":"Pudderkvastnet","de":"Runde kvaste henter stille vejret inde i netposen. Når luften strømmer gennem masken, holder blødheden længere. En veltørret kvast bærer allerede morgendagens glød i sig."},"ICON-0455":{"nm":"Hårsprayhætte","de":"Ét pift, og ikke en tot rører sig, selv i vind. En lille hætte, der holder en omhyggeligt stylet frisure hele natten. Klart lys vælter ned og splintres over det stramt fastholdte hår."},"ICON-0456":{"nm":"Læbepenselhætte","de":"En lille hætte, der blidt omslutter den tynde børstespids. Ryster den end frem og tilbage i en taske, holdes penslen lige og ren. Omsorgen for én lille pensel fuldender ét strøg farve på læberne."},"ICON-0457":{"nm":"Ventenummerspejl","de":"Et lille spejl hænger stille ved siden af det nummer, der kalder på ens tur. Lige inden man går på scenen, er det stedet, hvor man glatter én sidste ustyrlig hårtot til. Selv nervøsitet bliver en anelse lettere, når man spejler den én gang."},"ICON-0458":{"nm":"Håndledssvedbånd","de":"Et blødt bånd, der tørrer sveden fra panden med ét strøg af håndleddet. Jo voldsommere koreografien bliver, jo oftere griber hånden fat i det. En lille trøst om håndleddet, der bliver ved siden af én gennem hvert åndeløst øjeblik."},"ICON-0459":{"nm":"Rekvisittaskemærke","de":"Selv med ti ens tasker på række i sminkerummet, opstår der aldrig forvirring. Hver taske har et navneskilt, der tydeligt fortæller, hvem den tilhører. At skrive 'min' på noget er et lille, men ømt mærke."},"ICON-0460":{"nm":"Øvelokale-bookingnål","de":"Hvem skal bruge dette øvelokale i dag? En lille nål, sat fast på tavlen ved døren, deler stille tiden ud. Hjerter, der venter på deres tur, stiller sig roligt op i kø bag denne ene nål."},"ICON-0461":{"nm":"Vægursafskærmningsring","de":"Et gennemsigtigt låg sænker sig blidt over væguret og holder støvet ude. De tikkende visere sløres aldrig, og tiden flyder klart videre. Over det dyrebare er der altid brug for et usynligt lag beskyttelse."},"ICON-0462":{"nm":"Gulvbeskyttelsespude","de":"En tynd pude klæbet under en stolefod forhindrer træbunden i at blive ridset på forhånd. Trækkes stolen, ridser intet; flyttes den, efterlader den ikke et eneste mærke. At passe usynligt på gulvet er hemmeligheden bag, at det holder længe."},"ICON-0463":{"nm":"Ingen-drikkevarer-mærke","de":"Lad os lige sætte drikkevarerne fra os her, beder den lille chip venligt. For noder og udstyr har det svært, hvis de bliver våde. Selv et ord som 'forbudt' bliver til varm omtanke, når det bringes videre på denne måde."},"ICON-0464":{"nm":"Ventilationsknapmærkat","de":"Vil du skifte den indelukkede luft ud, så tryk her, viser en lille mærkat ved siden af knappen vejen. At kunne trække vejret frit begynder overraskende ofte stille med netop sådan et lille, ubetydeligt mærke."},"ICON-0465":{"nm":"Højttalergummifod","de":"En gummifod under højttaleren sluger stille den dumpe rystelse. Når bassen ikke længere spreder sig gennem gulvet, bliver lyden langt klarere. God klang bliver først ren, når den står på et solidt fodfæste."},"ICON-0466":{"nm":"Skabnummermagnet","de":"En lille talmagnet, der klapper fast på skabsdøren. Hvilket rum skal mine ting sove i i dag? Selv om pladsen skifter hver dag, bliver et skab straks mit med bare én magnet. Tilhørsforhold kommer fra et så let et mærke."},"ICON-0467":{"nm":"Spejlvisker","de":"Ét strøg hen over spejlet, og dugen forsvinder helt. Det øjeblik hvor mit slørede ansigt endelig træder tydeligt frem. For virkelig at se sig selv må man først stille tørre det uklare væk."},"ICON-0468":{"nm":"Dørstoppude","de":"En blød pude klemt ind i sprækken på en dør, der smækker hårdt. Den optager blidt både braget og en klemt hånd. En lille sikkerhed, der stikker et ømt lag ind mellem de rå sammenstød."},"ICON-0469":{"nm":"Kabeldækselblok","de":"Et solidt dæksel bygger sikkert en bro over kablerne, der krydser gulvet. Ingen fod snubler, ingen ledning trædes på. Én bloks tavse standhaftighed, der vogter vejen uden at spærre den."},"ICON-0470":{"nm":"Advarselskegle for vådt gulv","de":"En gul kegle står alene på det våde gulv og advarer i stilhed. Træd forsigtigt, træd langsomt. Bag den strålende scene står netop sådan en lille vagtpost, der tavst våger over hvert skridt."},"ICON-0471":{"nm":"Nødlysstav","de":"En enkelt lysstråle tændes med et klik i en gang uden strøm. Så man ikke farer vild selv i mørket, lægges nødlyset i hånden. Der findes med sikkerhed ting i verden, der skinner klarest i det mørkeste øjeblik."},"ICON-0472":{"nm":"Gelænderhætte","de":"En rund hætte trukket over enden af et trappegelænder omslutter blidt det skarpe hjørne. Selv et tilfældigt strøg med hånden gør ikke ondt. At dække det skarpe stille til er også en form for omtanke for nogen."},"ICON-0473":{"nm":"Scenekantpude","de":"En blød pude vikles om scenens kant. Så selv en tå, der rammer den i en voldsom koreografi, ikke bliver mørk og blå. Bag hver strålende bevægelse danser en usynlig beskyttelse med."},"ICON-0474":{"nm":"Gulvmarkeringsskive","de":"En rund skive lagt på gulvet siger stille: 'stå her.' Både den, der stiller sig i kø, og den, der leder efter sin plads, standser roligt ved dette ene punkt. Orden vokser ud af et lille mærke."},"ICON-0475":{"nm":"Lommelygtestrop","de":"Vikl snoren for enden af lommelygten én gang om håndleddet, så mister du aldrig lyset, selv i mørket. Begge hænder bliver frie uden frygt for at tabe den - en lille, men pålidelig løkke."},"ICON-0476":{"nm":"Afspærringssnor","de":"Kom venligst ikke længere ind end hertil, tegner en enkelt snor blidt en linje. En venlig grænse, der stille skiller det farlige fra det trygge. At holde nogen tilbage er også en måde at beskytte dem på."},"ICON-0477":{"nm":"Sikkerhedskontrolnål","de":"Ved hvert sted, kontrollen er afsluttet, efterlader en lille nål et 'tjekket'. Ét punkt, som et stempel fra et sind, der har set sig omkring alle vegne uden at overse noget. Sikkerhed er ikke noget stort, men summen af netop sådanne mærker, sat ét for ét."},"ICON-0478":{"nm":"Miniklaptræ","de":"Ved den friske smæld, der skærer det første taktslag, finder alle på settet vejret i samme øjeblik. Lille som den er, er startlinjen for enhver scene altid netop dette ene slag. Optagelsens forventningsfulde begyndelse åbner sig her."},"ICON-0479":{"nm":"Bordmikrofonhætte","de":"Et blødt overtræk trækkes blidt over mikrofonen på bordet. Selv et hårdt åndedrag når frem uden støj, blidt og rent. Det, der varmest omslutter en stemme, er netop dette lille, bløde lag."},"ICON-0480":{"nm":"Akustikpanelstykke","de":"Et stykke lydabsorberende panel sat i væggen samler stille ekkoerne op. Når lyden ikke længere rammer og spredes, samler sangen sig langt klarere. God klang begynder med omhyggeligt at forfine stilheden."},"ICON-0481":{"nm":"Hovedtelefonkrog","de":"At hænge hovedtelefonerne her er et lille løfte. Red ledningen ud og læg den pænt, så den næste straks kan gribe den og gå. Én krog bringer stille orden til en travl boks."},"ICON-0482":{"nm":"Optager-lysskilt","de":"I det øjeblik det røde lys tændes, går alle åndedrag i boksen i stå. Et signal, der stopper selv skridtene uden for døren. At indfange lyd begynder med at værne om netop denne dybe stilhed."},"ICON-0483":{"nm":"Plektreboks","de":"Plektre stukket ned i rum sorteret efter farve. Tykkelse og vægt former fingerspidsens vaner. Lige før scenen vokser den præcision, hvormed man griber den rette uden at se, netop herfra."},"ICON-0484":{"nm":"Kabelmærker","de":"For ikke at fare vild blandt snesevis af sammenfiltrede strenge på gulvet, må man skrive et navn på begge ender. Kun den, der har noteret, hvorfra og hvorhen, famler ikke i blinde, selv i mørket."},"ICON-0485":{"nm":"Mini-mixerknap","de":"Drej den blot en fingerbredde, og stemmens klangfarve forandres. Skru op, og den bliver ru; skru ned, og den drukner - det handler om at føle sig frem til netop det ene punkt derimellem. Den mest fintfølende berøring former den største forandring."},"ICON-0486":{"nm":"Stativlåsering","de":"Det, der bærer scenen oppe, er ikke det strålende lys, men denne lille ring. Mens den holder fast om vaklen med et solidt greb, holder den stille ud på sin post, usynlig for alles øjne."},"ICON-0487":{"nm":"Nedrivningsmærke til kulisser","de":"Selv at lægge alt det, man har rejst, forsigtigt ned igen følger en klar rækkefølge. Et enkelt ark, der noterer, hvor man skal løsne, og hvor man skal flytte hen. Hænderne, der tager ned, er lige så sikre som hænderne, der byggede op."},"ICON-0488":{"nm":"Hittegodskonvolutmærke","de":"Hver ting, nogen har tabt og efterladt, bærer sin egen historie. At lægge den i en lille konvolut og afvente ejerens navn er en ømhed, der et øjeblik også rummer den tabende persons hjerte."},"ICON-0489":{"nm":"Rengøringsrutemarkering","de":"Følger man pilene, der er trukket på gulvet, bliver alt tørret rent uden et eneste hul. Selv en kost har brug for en vej, så den ikke bare snurrer forgæves. Det mest skinnende sted findes for enden af de bedst optegnede fodspor."},"ICON-0490":{"nm":"Udgangsviserstav","de":"Når det sidste bifald klinger ud, åbner denne stav vejen. En hånd, der langsomt lader stadig oprømte hjerter strømme ud, uden at støde dem. Selv det at guide en afslutning rummer varm omtanke."},"ICON-0491":{"nm":"Tapeafklipskugle","de":"Ruller man rester, der er blevet til overs, sammen til en kugle, får de endnu en gang nytte. Ligesom en ende, der nær var blevet smidt ud, samles til en fast kugle, vokser en sparsommelig sjæl frem fra en lille fingerspids."},"ICON-0492":{"nm":"Sædenummerhætte","de":"Hver stol i salen skal have et nummer, så ingen farer vild. Én lille hætte, der tildeler en plads, forvandler en nytilkommens hjertebanken til rolig lettelse."},"ICON-0493":{"nm":"Affaldssorteringsnål","de":"En lille nål, der skiller papir og plastik og sætter dem hver sit sted. Blandet er det bare skrald, men adskilt bliver det en ressource, man kan bruge igen. At sortere er en øm handling, der giver tingene et andet liv."},"ICON-0494":{"nm":"Udstyrsafleveringsmærke","de":"Det, man har lånt, skal altid finde tilbage til sin plads. For hver fingerspids, der afleverer det med et mærke på, lægger sig endnu et lag tillid. Den, der afleverer pænt tilbage, låner også trygt næste gang."},"ICON-0495":{"nm":"Udtjekningsnøgle til det grønne værelse","de":"Man tager al dagens sminke og kostume af og afleverer til sidst denne nøgle. At lægge det tilbage på vej ud, som man fik på vej ind. Dagens begyndelse og afslutning holdes i samme hånd."},"ICON-0496":{"nm":"Cushion-svampeetui","de":"En blød svamp mister sin struktur, når den bliver presset flad. Det er derfor, den lægges omhyggeligt til hvile i ét rundt hjem. For at bevare blødhed længe må man først behandle den blidt."},"ICON-0497":{"nm":"Øjenskyggechip","de":"Ét punkt farve lagt på øjenlåget forandrer hele udtrykket. Nuancen, der sover i den lille chip, vågner først til live under lyset og giver blikket mod scenen dybde."},"ICON-0498":{"nm":"Rougepenselhætte","de":"Når børstespidsen bliver ødelagt, styrter farvegengivelsen med den. At sætte en lille hætte på for at beskytte dens struktur er den stille vane hos den, der vil holde gode redskaber tæt på sig i lang tid."},"ICON-0499":{"nm":"Slank læbefarvepalette","de":"En tyk palette fylder hele tasken. En hånd, der ved, at én tyndt afskåret stribe er nok. Det øjeblik, hvor at skære ned bliver selve kunsten at pakke godt."},"ICON-0500":{"nm":"Mascaraskærm","de":"Så vipper, rejst hår for hår, ikke tuder ud, beskytter en lille skærm blidt deres kurve. Det, der er løftet med omhu, skal også vogtes med omhu, minder tiden foran spejlet os om."},"ICON-0501":{"nm":"Vatpindsetui","de":"Et lille hjem, der holder de hvide vatpinde samlet, så de ikke spredes for alle vinde. En hånd, der altid holdes nær til den sidste finpudsning. Små forberedelser fylder hullerne ud på en stor scene."},"ICON-0502":{"nm":"Øjenvipbøjer-gummipuder","de":"Når gummiet hærder, gør det ondt at krølle vipperne. At have ekstra puder liggende klar kommer fra en ømhed, der tager selv de mindste smerter i betragtning."},"ICON-0503":{"nm":"Concealerpensel","de":"Med en fin børstespids viskes skyggerne forsigtigt væk. Det er at bringe lys til steder, lyset aldrig nåede. En hånd, der tilføjer lys frem for at dække fejl, giver et langt smukkere resultat."},"ICON-0504":{"nm":"Pudersigte","de":"Sigt det fine pudder én gang, og det lægger sig glat uden klumper. Besværet ved at sigte det én gang til. Omhu viser sig til syvende og sidst i den fingerspids, der tager ét skridt mere."},"ICON-0505":{"nm":"Pandehårs-rulleklemme","de":"En klemme, der ruller panden runde og holder den et øjeblik. Mens du venter, falder formen roligt på plads. Soigneringen blomstrer der, hvor man kan vente uden at forhaste sig."},"ICON-0506":{"nm":"Hårvoksske","de":"Voksen øses op med denne lille ske, før den nogensinde rører hænderne. Tilbageholdenheden i kun at tage præcis det, man behøver. En hånd, der ved at bruge uden overflod, skaber den mest naturlige struktur."},"ICON-0507":{"nm":"Krøllejernsmåtte","de":"Man kan ikke bare lægge et glohedt krøllejern fra sig hvor som helst. Én lille måtte beskytter både bordet og hænderne. Et sted, der håndterer varme, har altid brug for et sikkert hvilested."},"ICON-0508":{"nm":"Hårolie-prøveflaske","de":"Én dråbe er nok glans, så den puttes pænt ned i en lille prøveflaske og smutter i et hjørne af tasken. En lille flaske, frem for en stor, ender med at blive brugt langt oftere."},"ICON-0509":{"nm":"Børsterensningsrive","de":"Håret, der har viklet sig ind i børsten, redes langsomt ud med riven. At passe sine redskaber er et stille ritual, når arbejdet er gjort. En velplejet børste former i morgen den smukkeste struktur."},"ICON-0510":{"nm":"Hårelastik-spole","de":"Blot viklet rundt om en spole, og de er alle synlige på et øjeblik. Denne lille, ryddeligt oprullede bundt er en øm smule lethed, rakt frem til travle morgener, hvor hårelastikker plejede at trille i alle retninger."},"ICON-0511":{"nm":"Hårfarve-handskepakke","de":"Tynde handsker, der bæres, så hænderne, der påfører farven, ikke plettes. Et ønske om at møde det næste med rene hænder, selv efter arbejdet er gjort. Beskyttelse er blot et andet navn for den slags parathed."},"ICON-0512":{"nm":"Hårnetpose","de":"En lille pose til pænt at folde og opbevare nettet, der holder en frisure på plads. Jo mindre fylde en ting har, jo lettere mistes den, så en omtænksom hånd, der giver den et hjem, er en kærkommen ting."},"ICON-0513":{"nm":"Krølhårs-fixerpen","de":"En pen, der klapper genstridige krølhår pænt på plads igen. Det allersidste strøg, efter al den store styling er gjort. At gøre færdig er altid arbejdet med at berolige det mindste sted."},"ICON-0514":{"nm":"Parfume-duftprøvehætte","de":"Når man vælger en duft, holder man den ikke lige op til næsen. Dryp den på en lille hætte, og lad den drive gennem luften for at afsløre sin sande karakter. Også en duft er kun ærlig, når den lugtes på afstand."},"ICON-0515":{"nm":"Roll-on parfumeflaske","de":"En rund kugle ruller af sted og tegner duft hen over håndleddet. I modsætning til de gamle dup-flasker glider og breder en enkelt streg sig ud. Duften efterlader en anden historie for hver måde, den rører ved."},"ICON-0516":{"nm":"Bodymist-hætte","de":"En lille hætte, der holder på en duft, der spreder sig som tåge. At lukke og bevare det, der kun spredes, når det åbnes. Et lille hjerte, der sparer lidt, får den duft til at dvæle længere ved ens side."},"ICON-0517":{"nm":"Håndcreme-nøglering","de":"Sæt en ring på den lille creme, du smører på hænderne, og den følger med overalt. En følgesvend, der dingler og svajer uden på tasken, bliver en øm hilsen til tørre fingerspidser."},"ICON-0518":{"nm":"Badesvamp-krog","de":"Efter at have skummet godt op skal den tørres ordentligt. Netbolden, der hænger på en krog i badeværelsets hjørne, ryster vandet af sig og venter frisk på i morgen."},"ICON-0519":{"nm":"Massagebold-pose","de":"En lille pose til at bære den faste bold, der løsner spændte skuldre. En kort pause bag scenen, en tid til stille at ømme en stiv krop. Omsorg begynder altid med en selv."},"ICON-0520":{"nm":"Kølepatch-dåse","de":"En dåse, der samler plastre, som køler behageligt af, når de sættes på. Den nat en ophedet scene er slut, sover en lille trøst deri, som langsomt lægger en varm krop og et varmt hjerte til ro."},"ICON-0521":{"nm":"Neglolie-pen","de":"Tryk, gnid, glimt. Én dråbe er nok til tørre fingerspidser. Ingen overdådig kur er nødvendig; en blød glans, der breder sig fra spidsen af en lille pen, snor sig yndefuldt hen over neglene. Omsorg begynder med sådan én lille dråbe."},"ICON-0522":{"nm":"Duftpose-klemme","de":"En lille knude, der binder duft fast til papir. Hver gang man åbner skuffen, hilser en svag håndfuld, før hånden selv gør. En ømhed, der dvæler tæt på uden at ses—én klemme rummer stille en hel dags trøst."},"ICON-0523":{"nm":"Negletip-bakke","de":"En lille scene, der breder alle ti fingres farver ud på forhånd. Hvilken nuance passer til i dag? En stille audition udspiller sig på bakken. Det korte øjeblik at vælge er på en eller anden måde spændende, og fingerspidsens dag begynder her."},"ICON-0524":{"nm":"Neglebåndsskubber-hætte","de":"Der er ømhed selv i at skubbe tilbage. En enkelt neglerand, forsigtigt med den runde spids, aldrig i hast. En forhastet hånd overser altid noget, så orden er nærmere et sind, der ser langsomt efter."},"ICON-0525":{"nm":"Mini neglefil-polerer","de":"En ru side og en fin side, to ansigter holdt i én hånd. At file de skarpe kanter glatte er en lille ting, men fuldendelse kommer altid fra netop sådanne små strøg. Det sidste ord tilhører til syvende og sidst blødheden."},"ICON-0526":{"nm":"Negleklistermærke-ark","de":"Stjerner, blomster, hjerter—vælg blot det ene ark, der passer til dagens humør, og tryk det på. På et ark på række med små billeder på størrelse med negle glimter et enkelt klistermærke som en øm signatur efterladt på en fingerspids."},"ICON-0527":{"nm":"Gellampe-skærmplade","de":"En tynd skærm, der holder på lyset et øjeblik. Mens det hærder, hviler øjnene, og kun fingerspidserne hærdes stille. Selv ventetid har brug for en stribe skygge—i den uforhastede tid fuldendes dagens fingerspidser."},"ICON-0528":{"nm":"Negledekoration-dåse","de":"Glitrende stykker sover rum ved rum. Zirkoner, perler, stjernestøv—man løfter låget med spændingen ved at åbne et navnløst smykkeskrin. Hvilket lys skal lægges på neglene? Det øjeblik at vælge glimter mest."},"ICON-0529":{"nm":"Håndplejehandske-pakke","de":"En kort ferie, hænderne tager, mens du sover. Inde i handskerne bliver tør hud langsomt fugtig hen over natten. Omsorg er, til syvende og sidst, noget der sker uset, og om morgenen er fingerspidserne de første til at kende den ømhed."},"ICON-0530":{"nm":"Neglelakfjerner-pumpeflaske","de":"Ét tryk, præcis nok. En kølig duft trænger ind i vatten og visker gårsdagen rent væk fra neglene. Der er en rytme selv i at tømme, og ét pump rydder stille en plads til at male på ny."},"ICON-0531":{"nm":"Strasssten-pincet","de":"For at gribe en sten finere end en fingerspids kræves en endnu finere hånd. Pincettens spids flytter ét punkt uden en skælven; finhed er lige så meget redskabets del som hjertets. Ét lille lys finder sin plads."},"ICON-0532":{"nm":"Øreringsopbevaringsplade","de":"Så en enlig ørering aldrig igen bliver væk i en skuffe. Sæt hvert par fast på sin plads, og den travle morgens valg bliver meget lettere. At rydde op er en lille venlighed rakt til ens fremtidige jeg."},"ICON-0533":{"nm":"Ringstørrelsesmåler","de":"En lille bundt af ringe, der omsætter fingeromkredsen til et tal. At prøve hver størrelse én efter én ligner det at langsomt lære, hvad der passer én perfekt, at kende. Ligesom den lettelse, når noget sidder helt rigtigt."},"ICON-0534":{"nm":"Urremsstift","de":"Når urremmen løsner sig, fastholder denne ene lille stift tiden på håndleddet igen. Den dybest skjulte del holder længst—det ved et længe båret ur i stilhed."},"ICON-0535":{"nm":"Halskæde-rodefri plade","de":"Rum delt op, så tynde kæder ikke kan vikle sig ind i hinanden. En rodefri morgen begynder med de små skillevægge, delt fra aftenen før. Lethed er, til syvende og sidst, et sind bragt i orden, før hånden nogensinde når det."},"ICON-0536":{"nm":"Broche-baglås","de":"Jo mere strålende forsiden, jo mere tavs bagsiden. En lille lås, der solidt holder brochen fast i stoffet—bag ethvert synligt skær er der altid en navnløs hånd, der holder fast. Et sted, der er endnu mere pålideligt, fordi det ikke ses."},"ICON-0537":{"nm":"Solbrillepose","de":"Et blødt stof omslutter stille de linser, der stoppede sommerlyset. En lille pose, der skærmer ét par udsyn mod tasken skub og stød. Hjertet, der værner om noget, kommer altid som et sådant blødt lag."},"ICON-0538":{"nm":"Bæltehulstang","de":"Til en talje gået et hak mindre, eller en årstid gået et hak større. Punch blot ét hul mere, og bæltet passer kroppen igen. Det er altid mig, der ændrer sig, og stille at tilpasse sig mig er dette lille redskabs opgave."},"ICON-0539":{"nm":"Tørklæderingklemme","de":"En klemme, der samler et glidende tørklæde ét sted og holder det fast. Stilen, der blev ved med at løsne sig i vinden, finder endelig sin plads. Selv eleganse lener sig nogle gange op ad denne lille klemme, der ordner en dag, der næsten gik i opløsning."},"ICON-0540":{"nm":"Charm-ringesæt","de":"Et sæt små ringe til at hænge i siden af tasken kom sammen som ét sæt. Hjertet i at bære det, man elsker, tæt på sig—at hænge dagens humør på ét charm er et lille ritual, kun man selv kender, og det er på en eller anden måde en fornøjelse."},"ICON-0541":{"nm":"Fnuldfjerner","de":"Når en trøje ser ud til at ældes natten over med fnuller, rulles denne beholder blidt hen over den, og den bærer atter et nyt udtryk. Den lette summen, der løfter slidet væk, er på en eller anden måde betryggende. En elsket beklædningsgenstand vender sådan tilbage til live endnu en gang."},"ICON-0542":{"nm":"Duftkort til tøj","de":"Stik det dybt ind i skabet, og det fylder stille dagene med duft. Et brev skrevet i duft i stedet for ord—en side, der læses uden at blive udfoldet. Hver morgen man tager tøj ud, breder ømheden skrevet ned dagen før sig først."},"ICON-0543":{"nm":"Antistatisk nål","de":"På en vintermorgen, hvor nederdelen klæber sig til benene, løsner én nål det klæbende stille op. En lille fred, der beroliger selv usynlig friktion—når én lille irritation forsvinder, løber dagen langt mere smidigt."},"ICON-0544":{"nm":"Rejsetøjbørste","de":"Lige før man går ud ad døren, en stribe støv landet blødt på skulderen. Fold børsten ud, ét strøg, og førstehåndsindtrykket er atter soigneret. Afslutningen sker altid ved døren, og soignering fuldendes med det ene strøg."},"ICON-0545":{"nm":"Vaskeposelabel","de":"Bur det, der ikke må blandes, inde i et vaskenet, og en label skriver stille dets navn. Selv vasketøj har sin plads, og en plads følger med et lille mærke. En let sammenfiltret dags orden vokser fra dette lille navneskilt."},"ICON-0546":{"nm":"Pletfjernerpen","de":"Selv sporet en enkelt dråbe kaffe har efterladt på en skjorte glider stille væk, når man dupper på det. En pen, der ikke dækker en fejl, men forsigtigt visker den bort. Alle har brug for én chance til at starte dagen rent igen."},"ICON-0547":{"nm":"Skopudseklud","de":"Ét strøg med kluden, og læderet vinder sin glans tilbage. Jo længere skoene er blevet båret, jo dybere sætter glansen sig. Glansen er en belønning for den tid, man har gået sammen—skoene indgraverer stille de år på vristen."},"ICON-0548":{"nm":"Snøreendehætte","de":"En lille hætte fæstnet på enden af en løs snøre. Så du ikke ser væk før målstregen, forsegles enden fast. Én velbundet snøre sender ét skridt længere—en lille forholdsregel bliver modet til at løbe helt i mål."},"ICON-0549":{"nm":"Bøjle-navnechip","de":"Blandt ensartede bøjler fortæller denne ene lille chip stille \"min plads.\" En tavs guide, der letter morgenens travle forvirring—med mindre besvær med at lede føles dagens start også lettere."},"ICON-0550":{"nm":"Linsepincetdåse","de":"Der er tider, hvor man har brug for en spids mere præcis end en fingerspids. Pincetten, der løfter en lille linse uden en skælven, venter sin tur inde i dåsen. Præcision ligger altid stille parat, sovende indtil den kaldes, så vågen på et øjeblik."},"ICON-0551":{"nm":"Mini vatrondel-pakke","de":"En lille bundt med præcis nok til én gangs brug. Den skærer fylden ned i tasken, mens blødheden forbliver den samme. At pakke let er også en venlighed, og en let dag flytter ind i den plads, man har skåret fra."},"ICON-0552":{"nm":"Oliepapiretui","de":"Tryk skinnet, der har bredt sig hen over næsen midt på dagen, stille væk med ét tyndt ark. Papirerne, der sover i pæne rækker inde i etuiet—for det øjeblik man trækker ét ud, stopper enhver kort op og ser ømt på sig selv i spejlet."},"ICON-0553":{"nm":"Foldbar kam med spejl","de":"Foldet er den en håndflade; foldet ud er den spejl og kam. Et lille alt-i-én, der klarer en hurtig finpudsning fra et hjørne af tasken. Soignering er ikke storslået—den er nærmere et sind, der kan folde sig ud hvor som helst for ét hurtigt strøg."},"ICON-0554":{"nm":"Rejsebarberhætte","de":"Den lægger sikkert det skarpe blad til hvile i en rejsetaske. Takket være denne stumpe, men solide hætte, kommer selv fingre, der famler i en travl morgen, ikke til skade. At sørge for noget er altid at dække en fare et skridt i forvejen."},"ICON-0555":{"nm":"Læbepomade-ring","de":"Et lille skjold, der dingler fra en taskerem. Ingen bekymring om, at det ruller rundt i en lomme og knækker—tørre læber er altid inden for rækkevidde. At holde noget tæt på er, til syvende og sidst, et hjerte, der lægger det nødvendige nærmest muligt."},"ICON-0556":{"nm":"Håndsprit-holder","de":"Tryk med én hånd, og en håndfuld renlighed drypper ud. Hæng den ved døren, på bordet, hvor som helst, og vanen med rene hænder rykker lige så meget nærmere. En god vane er ikke storslået—den begynder inden for armslængde."},"ICON-0557":{"nm":"Slankt lommetørklædeetui","de":"En slank ramme, der rummer en håndfuld servietter. Uden at bule en lomme ud er den altid stille parat til en pludselig løbenæse eller tårer. Et ark til at give videre til nogen—jo slankere parathed, jo finere."},"ICON-0558":{"nm":"Mini mundskylsflaske","de":"På en dag, hvor man skal møde nogen efter at have spist stærk ramen, klarer denne lille flaske stille en hurtig opfriskning. Én mundfuld friskhed bliver nogle gange til stor selvtillid, der gør en tøvende hilsen langt lettere."},"ICON-0559":{"nm":"Glimmerpudder-chip","de":"Dyp det let på fingerspidsen, og læg det på kinden, og det breder sig som stjernestøv, der spredes under lysene. At en almindelig kind glimter på et øjeblik, er magien fra denne ene lille chip. Lys ankommer altid sådan her, på pudder dryssende på fingerspidsen."},"ICON-0560":{"nm":"Glitterdæmpende sticker","de":"Hvor det glimter for meget til at være behageligt, dæmper denne sticker let lyset. At tage ét lag pragt af er også en del af udsmykningen—den sagte tone, der bliver tilbage i det udtagne rum, bliver nogle gange en helt egen sansning."},"ICON-0561":{"nm":"Stenopsamlerpen","de":"En lille sten, der satte sig fast under foden mens man gik ned ad vejen. En pen, der med vilje bøjer sig ned for at samle den op. Hjertet, der stille samler op med en fingerspids det, man kunne være gået forbi—ømhed begynder altid med at stoppe op."},"ICON-0562":{"nm":"Løsvipperopbevaringsplade","de":"En lille plade til pænt at lægge løsvipper ned, én efter én. Selv efter de er taget af, forvildes deres yndefulde kurve aldrig. Den stille, ordentlige trøst ved opbevaring, der siger, at selv det, der lægges fra sig et øjeblik, husker sin plads."},"ICON-0563":{"nm":"Dobbeltøjenlågstape-skærehætte","de":"To blade mødes og skærer en knude over i ét snit. Jo renere snittet, jo pænere den næste knude. Fra en fingerspids, der binder godt og skærer godt, udfolder selv en frisk start sig langt lettere."},"ICON-0564":{"nm":"Ansigtskontur-tape","de":"Én stribe langs kæbelinjen, påført forsigtigt med tilbageholdt åndedræt. Kontur er ikke at tegne en linje, der ikke var der, men at pege på det sted, der allerede var smukt. Et strøg, der ømt følger den struktur, der altid var der."},"ICON-0565":{"nm":"Lysreflekterende pudder","de":"Et pudder, der drikker lys til fulde og giver det yndefuldt tilbage. Selvom det ikke skinner af sig selv, lyser det op ved at sprede modtaget lys i fine partikler. Ligesom at give videreformidlet ømhed videre til en anden, vokser glimtet, jo mere det deles."},"ICON-0566":{"nm":"Makeup-fikseringsblæser","de":"En blæsers vind, der holder et omhyggeligt makeup sammen til dagens ende. Så det ikke falder fra hinanden, så det ikke løber, køler og sætter det stille sig. Så et kærligt plejet ansigt forbliver klart, til scenetæppet falder."},"ICON-0567":{"nm":"Farvekorrigerende paletchip","de":"Små stykker, der beroliger og retter en misfarvet nuance op, rum for rum. Selv en farve, der flød alene, lysner endelig op med en passende farve ved sin side. Først når farve rækker hånd til farve, bliver det til ét klart billede."},"ICON-0568":{"nm":"Halstørklædepakke","de":"Bind det om halsen, og den kolde luft i et daggryets øvelokale blødgøres betragteligt. Varmt som en bedstemors hånd, der svøbte det om barnebarnets hals. Kulden kommer altid først til de tyndeste steder, så den omfavner nakken først."},"ICON-0569":{"nm":"Varmt øjenmaske-kuvert","de":"En lille kuvert til at opbevare en opvarmet øjenmaske. I det øjeblik man åbner klappen, siver en søvnig varme langsomt hen over øjenlågene. Et ømt ritual før søvnen, der forsegler en træt dag et øjeblik, for så at slippe den fri igen."},"ICON-0570":{"nm":"Bærbart luftfugterfilter","de":"En lille filtrerende membran, der giver fugt tilbage til et udtørret rum. Fra det usete indre filtrerer den stille det uklare fra. Fugten, der fylder rummet, er en klarhed bevaret af nogens usete anstrengelse."},"ICON-0571":{"nm":"Vitaminopbevaringsæske","de":"En æske, der deler en dags piller op, rum for rum. Trofast at tage dem er et løfte om også at stå på scenen i morgen. I hvert lille rum er en omsorg for én selv sat i pæn orden."},"ICON-0572":{"nm":"Sovepropetui","de":"Et hjem for ørepropperne, der en kort stund lukker verdens lyde ude. Selv stilheden har brug for pleje, så de ligger pænt inde i etuiet. En dybt sovet nat er det, der lader næste dags stemme vågne klar—det ved hvilen godt."},"ICON-0573":{"nm":"Kølehåndklæde-klemme","de":"En klemme, der bider fast på skulderen, så et nedkølet håndklæde ikke glider af. På en brandvarm dag bærer én stribe kølighed mod nakken en lang eftermiddag igennem. Selv en lille kølighed, holdt fast, dvæler længe."},"ICON-0574":{"nm":"Strækbold-pose","de":"En pose til at putte bolden tilbage i, som løsnede kroppen. At strække vidt ud og så samle sammen igen ligner et indåndedrag og et udåndedrag. Mellem udfoldelse og indsamling bliver både krop og sind langsomt fastere."},"ICON-0575":{"nm":"Kompressionsbind","de":"Et bind, der vikler sig rundt om en forstuvet ankel, gang på gang. Det er ikke at klemme, men stille at støtte. Jo mere overanstrengt et sted, jo mere har det brug for en hånd, der udholdende holder ved siden af, hvisker rullen mens den vikler sig."},"ICON-0576":{"nm":"Tilstandstjek-mærke","de":"Et mærke, man skriver dagens tilstand på i én linje og hænger op. At hænge det gode og det dårlige ærligt ud er et lille mod. Skriv dagens jeg i stedet for at lade som om alt er fint, og nogen vil læse den ene linje og stille tage sig af dig."},"ICON-0577":{"nm":"Skofriskerkapsel","de":"En duftkapsel, der puttes ned i skoen. En lille, sagte trøst rakt til fødder, der har vandret over scenen hele dagen. Den bedste duft til det sted, der har slidt mest—ømhed når helt ud til tæerne, uden at glemme noget."},"ICON-0578":{"nm":"Indlægssåle-størrelsestabel","de":"En tabel, hvor fodstørrelsen står tydeligt indgraveret selv på en indlægssål. Ét perfekt tilpasset par gør fodtrinene på scenen lette. At tage hver enkelt anderledes skridtlængde i betragtning—en god pasform er, til syvende og sidst, et hjerte, der ser dybt på den anden."},"ICON-0579":{"nm":"Skohorn-nøglering","de":"En nøglering med et skohorn formindsket til håndfladestørrelse. En lille omtanke, der gør det korte øjeblik, man tager sko på, glat. Fødder, der begiver sig ud på en vej, bærer altid, hængende ved siden af, nogens ømme hjælpende hånd."},"ICON-0580":{"nm":"Taskestøvbetræk","de":"Et klæde, der blidt dækker en kær taske mod støv. Selv når den ikke bruges, lægger det den stille til hvile og vogter dens overflade. De ting, hjertet dvæler ved, selvom hånden sjældent rører dem, bærer en sådan stille omsorg."},"ICON-0581":{"nm":"Stropjusteringsnål","de":"En nål, der får en løs strop til at sidde tæt på kroppen. For løst, og skulderen glider ud; for stramt, og vejrtrækningen bliver kort. I den lille justering af at finde det helt rigtige, finder både scenekostume og hjerte endelig ro."},"ICON-0582":{"nm":"Lynlåssmørepen","de":"Stryg den én gang hen over en stiv lynlås, og den glider blødt igen. Hvor forfriskende lyden er af noget fastklemt, der pludselig slipper fri. Det, der får et stoppet sted til at flyde igen, er én stribe glathed."},"ICON-0583":{"nm":"Sneakerrenser-spids","de":"En børstespids, der tørrer en jordbestøvet sneaker ren, punkt for punkt. Uden for scenen visker den omhyggeligt de usete spor af træning bort. Ser man skotåen blevet hvid igen, føles det, som om man i morgen kan løbe med et friskt sind."},"ICON-0584":{"nm":"Imprægneringsspray-hætte","de":"En imprægnerende hætte, der ruller regndråber til kugler og lader dem falde. At lægge ét lag på forhånd, så intet bliver gennemblødt, er en ømhed, der ser langt fremad. Fordi man kender regnvejrsdage, trækker man ét lag film over en klar dag i dag."},"ICON-0585":{"nm":"Læderbeskyttelsesklæde","de":"Et klæde lagt blidt over læder for at holde det fra at folde sig. Det vogter overfladen som en gammel hånd, der svøbte en foldeskærm ind i hanjipapir. Jo længere man vil holde noget tæt på, jo langsommere går man—at gøre noget mørt er blot et andet navn for den tid, man bruger på at passe det."},"ICON-0586":{"nm":"Kuffert-navnerem","de":"En navnerem, der lader dig genkende din egen blandt utallige tasker med et enkelt blik. Blandt bagage, der kredser rundt på transportbåndet, rækker den hånden op med ét enkelt bogstav. Uanset hvor langt man rejser, er ét navn trygheden ved at mødes igen."},"ICON-0587":{"nm":"Kompressionsposeklemme","de":"En klemme, der presser opsvulmet bagage flad og lukker den. Den er mindre tømt end omhyggeligt sammenfoldet. Fra fingerspidsen, der rydder husholdningen ordentligt op, bliver selv griskhed mindre, fortæller den fast presset bagage stille."},"ICON-0588":{"nm":"Rejsevaskemiddel-ark","de":"Et vaskemiddelark, der gør vasketøjet til vask i håndvasken med blot ét stykke. Det minder om den rejsendes visdom med at håndvaske tøj langt hjemmefra. At rejse let og alligevel pakke soignering med—en vejfarers gamle sindelag."},"ICON-0589":{"nm":"Nakkepudebetræk","de":"Et rent betræk, friskt trukket over puden, der støttede nakken. Et sted at læne sig op ad skal altid være rent, for at sindet kan falde til ro. At efterlade et sted blødt og klart, så nogen kan læne sig komfortabelt—gæstfrihed begynder der."},"ICON-0590":{"nm":"Bagagevægt-rem","de":"En rem, der løfter en taske op for at måle dens vægt. Før afrejsen holder man bagagens vægt i hånden på forhånd. Mellem det, man tager med, og det, man lader blive, et øjeblik hvor man også stille vejer hjertets vægt."},"ICON-0591":{"nm":"Skoposepar","de":"Et par poser, der rummer to sko side om side, venstre og højre. Let at miste hver for sig, betryggende sammen som et par. Ting, der altid følges ad, har en styrke til stille at vogte over hinanden."},"ICON-0592":{"nm":"Ekstra taskekrog","de":"På en dag, hvor én hånd ikke slår til, en lille krog til at hænge en taske på et øjeblik. Et ekstra rum til dage med mere bagage, end man umuligt kan bære. Blot det at have et sted at hænge den et øjeblik gør skuldrene langt lettere."},"ICON-0593":{"nm":"Rejseplan-chip","de":"Indgrav dagens rute tydeligt på én chip. Hvor man mødes, og hvor man flyder videre hen—en retningslinje trukket op i forvejen for fødder, der let farer vild. En vej, man rejser sammen, noteret rum for rum, farer sjældent vild."},"ICON-0594":{"nm":"Multiadapterhætte","de":"En hætte, der passer tæt selv i stikkontakterne i et fremmed land. Forskellig i form, men til sidst forbundet som ét. At forbinde ting, der kom fra forskellige steder—harmoni begynder stille med én lille omdannelse."},"ICON-0595":{"nm":"Rejsekort-etui","de":"Et gennemsigtigt ark, der beskytter kortet, hver gang det stryger forbi spærringen. Den daglige pendling, hvert eneste slidte tryk, indpakket yndefuldt. At selv en almindelig vej bliver til et minde, når den værnes om, det beviser dette tynde lag."},"ICON-0596":{"nm":"Billetklemme","de":"En klemme, der pænt holder fast i en billet, så hurtig til at krølle. Mister man en billet undervejs, ryster selv hjertet løs. Jo mindre papiret er, jo fastere holder man ved det—rejsens tryghed kommer netop fra det ene rum."},"ICON-0597":{"nm":"Skiftenotat-chip","de":"En lille chip med, hvor man skifter, noteret i én linje. Ved hver forvirrende skillevej åbner ét ord, skrevet ned i forvejen, vejen klart op. En note er et ømt vink, stille rakt til ens fremtidige jeg, der måske farer vild."},"ICON-0598":{"nm":"Gatepassermærke","de":"Et adgangsmærke, der stille genkendes, mens man går gennem porten. Selv en vej, der virkede spærret, glider op, når man bærer sin egen kvalifikation. At gå åbent igennem er at træde let ind i det næste rum uden et øjebliks tøven."},"ICON-0599":{"nm":"Taxikvitteringsholder","de":"Hver lille kvittering bærer det tydelige aftryk af en vej, man rejste den dag. Saml kvitteringerne, der trillede rundt i alle retninger, og sæt dem pænt sammen, og selv en ubemærkelsesværdig dag hober sig op, kvittering for kvittering, til en rigtig rejse."},"ICON-0600":{"nm":"Cykelrefleksbånd","de":"Et bånd, der fanger forbipasserende lys på en dunkel vej og glimter stille. Selvom det ikke skinner af sig selv, lyser det op ved nogen andens lys. At gøre sig synlig er en nattevejs ømme bøn om, at man dog må komme sikkert hjem."},"ICON-0601":{"nm":"Kuffertshjulcover","de":"Grunden til at kufferthjørnerne forbliver perfekte, selv efter tusindvis af omgange på lufthavnens transportbånd, er dette lille cover viklet om hjulene. Stedet der først møder den barskeste vej — at beskytte nogen i stilhed foregår altid der, hvor ingen lægger mærke til det."},"ICON-0602":{"nm":"Nakkestøttebetræk","de":"På en lang bustur trækker man et betræk over nakkestøtten og lener sig mod ruden. Den forrige passagers duft og gårsdagens træthed når aldrig helt herhen. At have et rent sted at hvile hovedet er en overraskende stor trøst på en fremmed vej."},"ICON-0603":{"nm":"Parkeringspladsnål","de":"\"Hvilken etage, hvilken plads var det nu?\" Enhver, der har vandret rundt i et tomt parkeringshus, ved hvor betryggende denne nål er. Et enkelt mærke sat fast i stedet for en hukommelse, der falmer, sætter vejen hjem på forhånd."},"ICON-0604":{"nm":"Nøglesnor til værelse","de":"Hvor let forsvinder et værelsesnøgle dog ikke. Træd den på en snor og hæng den om håndleddet, så glemmer man aldrig det ene værelse, der venter i aften. Selv i en fremmed by dingler den lille tryghed ved at have sin egen plads om håndleddet."},"ICON-0605":{"nm":"Dørskilt-chip","de":"Når prøven begynder, hænger man en chip på døren. Må ikke forstyrres — det betyder, at nu er tid til ren koncentration. Den dybe stilhed bag scenen bliver altid vogtet tavst af små signaler som dette."},"ICON-0606":{"nm":"Toilettaske","de":"Tandbørste, ansigtsrens, et håndklæde på størrelse med en håndflade. Uanset hvor man rejser hen, behøver man blot pakke denne taske, så bliver dagens start og slutning altid ordnet af de samme kendte hænder. En lille håndfuld husholdning, der gør en fremmed seng til noget velkendt."},"ICON-0607":{"nm":"Klemme til ekstra håndklæde","de":"Ved siden af håndvasken lå det ekstra håndklæde altid fugtigt uden noget sted at være. Klem det fast med en klemme og hæng det op, så finder det endelig sin plads. At give noget et sted at tørre — venlighed har ofte nøjagtig denne størrelse og form."},"ICON-0608":{"nm":"Pose til stikdåse","de":"Hver gang man åbnede tasken, lå opladerne filtret sammen i én klump. Rul hele stikdåsen sammen og læg den i posen, så bliver det hele mere ordentligt. At ledningerne løsnes betyder, at et lille hjørne af hjertet også løsner sig lidt, inden man tager afsted."},"ICON-0609":{"nm":"Sengenummer-mærkat","de":"Et nummerskilt på hver køjeseng i sovesalen. Med ét mærkat, der fortæller hvilken plads der er ens egen, bliver selv et fremmed nyt rum til ens hjem inden aftenen falder på. Begyndelsen er altid så lille som dette."},"ICON-0610":{"nm":"Mini-tørresnor","de":"Hæng begge ender fast mellem vindueskarmene, og det bliver en tørresnor. På en solrig dag svajer et par håndvaskede sokker bløde og luftige i vinden. Selv langt hjemmefra tørrer hverdagen sådan på en snor."},"ICON-0611":{"nm":"Tøffelmærke","de":"Når tøflerne hober sig op ved indgangen, kan man slet ikke se, hvis er hvis. Sæt et lille mærke på, og selv skoene genkender deres ejer. At leve tæt sammen med andre kræver netop denne slags venlige markeringer."},"ICON-0612":{"nm":"Morgenmadskupon-holder","de":"En holder til at putte morgenmadsbilletten i. På en sulten tidlig morgen lover denne ene seddel en dampende skål suppe. En dag på rejse åbner altid langsomt med ét varmt måltid."},"ICON-0613":{"nm":"Reflekterende ankelbånd","de":"Vikl det om anklen, og det kaster lys tilbage i mørket. På en aftentur vinker det tavst til en bil, der nærmer sig langvejs fra — \"her går der nogen.\" Sikkerhed skinner så beskedent som dette."},"ICON-0614":{"nm":"Låg til vådservietter","de":"Et låg, der passer præcist over åbningen på en pakke vådservietter. Hver serviet trækkes blødt ud, og resten tørrer ikke ind. Det virker ubetydeligt, men de ting man rører ved hver eneste dag, har altid en grund gemt i sig."},"ICON-0615":{"nm":"Rem til picnictæppe","de":"Rul tæppet sammen til en cirkel og bind det med en rem. Bredden ved Han-floden, kirsebærblomsternes skygge — i det øjeblik man breder det ud, bliver stedet vores. En rem, der bærer et håndfladestort stykke græsmark med sig overalt."},"ICON-0616":{"nm":"Etui til myggeplaster","de":"Et etui til at opbevare myggeplastre, en sommeraftens nødvendighed. Omtanken ved at have dem klar, før kløen begynder, ligger gemt i dette ene lille rum. Bagerste rækker på en udendørs scene bliver altid gjort trygge af sådanne små forholdsregler."},"ICON-0617":{"nm":"Krog til vandflaske","de":"En krog til at hægte vandflasken fast på tasken, når man går en tur. At have vand inden for rækkevidde, når tørsten melder sig, betyder, at man kan gå så meget længere. En lille forbindelse, der holder en gående i gang."},"ICON-0618":{"nm":"Sammenklappelig indkøbskurv","de":"Fold den ud, og det er en indkøbskurv; fold den sammen, og den passer i hånden. Perfekt til det knippe grøntsager, man er blevet glad for undervejs gennem markedets gader. Husholdningens klogskab er altid vokset mod mindre volumen, mod lettere at bære."},"ICON-0619":{"nm":"Vindklemme","de":"På en blæsende dag griber den fat i teltdugens flagrende kant og holder den fast. Én klemme presser det, der blev ved med at flagre løst, på plads. Det mest pålidelige udendørs er overraskende ofte noget på størrelse med en finger."},"ICON-0620":{"nm":"Solskærmsnål","de":"En nål, man sætter i ruden for at skråt afskærme sollyset. Når middagslyset bliver for skarpt, kaster den stille en håndfuld skygge. At lindre blænding kan for nogen være den kærligste berøring af alle."},"ICON-0621":{"nm":"Låg til nødfløjte","de":"Et låg, der dækker mundstykket på en nødfløjte. Så støv holdes ude, og den lyder i ét åndedrag, når det virkelig gælder. Nogle ting giver ro blot ved at være i nærheden, selv mens man håber, man aldrig får brug for dem."},"ICON-0622":{"nm":"Paraplyspids-hætte","de":"En lille hætte, der trækkes over paraplyens spids. Når den skarpe spids gøres sløv, kommer hverken personen ved siden af eller ens egen taske til skade. Regnvejrsmanerer begynder stille med at pakke en skarp ende blødt og rundt ind."},"ICON-0623":{"nm":"Pose til regnfrakke","de":"En pose til at rulle den sammenfoldede regnfrakke ind i og gemme væk. Den venter tavst i et hjørne af tasken, indtil næste skybrud kommer. Forberedelse er, når alt kommer til alt, en flig af hjertet, der pakker det ned, man måske aldrig får brug for."},"ICON-0624":{"nm":"Vandtætte skoovertræk","de":"Træk dem over skoene, og regnvandet kan ikke længere trænge ind. Selv på en skoletur i monsunregn holder sokkerne sig tørre. En dag, hvor man ikke bliver våd til tæerne, forandrer humøret langt mere, end man skulle tro."},"ICON-0625":{"nm":"Anti-glidepude til sne","de":"Klæb den under skoene, og isglatte veje føles langt mindre skræmmende. Den vinter man skyndte sig hen over snedækkede gyder, holdt denne pude en fast og stille hånd under en, så man ikke gled. Den pålidelige styrke gemt under forsigtige skridt."},"ICON-0626":{"nm":"Kølende halsring","de":"Vikl den om halsen, og en sval fornemmelse ligger stille og roligt. Sommerens klogskab i at bære en stribe kølighed om nakken selv i den brændende hundedagevarme. Man lærer år for år at tåle varmen lidt mere fintfølende."},"ICON-0627":{"nm":"Stander til håndventilator","de":"En stander til at stille en håndventilator op på. Når begge hænder bliver fri, kan man både vende siderne og skrive i stedet for at vifte. Et lille pust vind gør en lang sommer ved skrivebordet lige akkurat til at holde ud."},"ICON-0628":{"nm":"Pose til varmepude","de":"En pose til at bære en varmepude i. Når man stikker de kolde fingerspidser i lommen for at varme dem, ligger en lille varme allerede der og venter. Vinterens ærinder klares på denne ene håndfuld varme."},"ICON-0629":{"nm":"Etui til ørevarmere","de":"Et etui til at opbevare ørevarmere i. Et sted at gemme dem omhyggeligt, indtil næste kulde ankommer. De ting man ikke helt kan smide ud, når årstiderne skifter, bærer en stille tro på den vinter, man vil møde igen."},"ICON-0630":{"nm":"UV-sensorchip","de":"Hold den forsigtigt op mod lyset, og chippen viser dagens UV-styrke i farve. Den gør endelig sollysets usynlige styrke synlig. Man fæstner sig så at sige et lille øje til at læse himlen med om håndleddet."},"ICON-0631":{"nm":"Gyde-stempeltavle","de":"En tavle man fylder ved at samle stempler fra hver butik langs gyden. For hvert felt der stemples, tegner et kort over kvarteret sig klarere i hjertet. Minder samlet til fods forbliver som disse spor af blæk."},"ICON-0632":{"nm":"Rejsenåletavle","de":"En lille tavle, hvor man sætter en nål for hvert sted man har besøgt. Efterhånden som prikkerne bliver flere, udvides ens verdens omkreds med dem. Hver nål er et spor, der stille siger: \"Jeg var her.\""},"ICON-0633":{"nm":"Lille kompassnor","de":"Hvor længe man end vandrer, forbliver nord alene altid på sin plads. Det lille kompas, der hænger ved brystet, ordner først og stille det svajende hjerte, når man overhovedet ikke ved, hvilken vej man skal gå."},"ICON-0634":{"nm":"Vejvisningsring","de":"Sedlerne man skrev, mens man ledte efter vejen, tres på en ring. \"Drej til venstre ved den røde postkasse.\" Nogens klodsede håndskrift guider stille en fremmed gyde. En vej efterladt på papir falmer sjældent."},"ICON-0635":{"nm":"Vartegns-klistermærkebog","de":"En bog man fylder med ét klistermærke købt ved hvert rejsemål. Tårne, broer, gamle fæstningsmure hober sig op side for side. At samle på steder man har besøgt ligner at røre ved den tid man har levet igennem, med fingerspidserne igen."},"ICON-0636":{"nm":"Metro-skiftechip","de":"En chip man holder fast i hånden på skiftestationen, hvor linjerne deler sig. Det korte øjeblik hvor man vælger, hvor man skal skifte, kan nogle gange vende hele dagens retning. Med ét lille valg viser byen et andet ansigt."},"ICON-0637":{"nm":"Kvarter-eventyrkort","de":"\"I dag, helt hen til bageren i dette kvarter.\" Træk ét kort, og dagens mål er fastsat. Selv en velkendt gyde man går forbi hver dag, bliver en ny vej, når en mission dukker op. Et kort der minder om, at eventyret ikke er langt væk."},"ICON-0638":{"nm":"Visitkortholder til butikker","de":"En holder til at gemme visitkortene, man fik fra sine yndlingsbutikker. Det lækre spisested, den venlige indehaver — de samles ét felt ad gangen. At blive knyttet til en by begynder med små papirlapper som disse."},"ICON-0639":{"nm":"Ruteafslutnings-badgetavle","de":"En tavle hvor man optjener et badge for at gennemføre en gåtur til ende. Belønningen for at gå hele vejen bliver til et rundt stykke metal, man beholder i hånden. Den stolthed kun den, der har gået hele vejen, kender, står tydeligt præget her."},"ICON-0640":{"nm":"Taskelås-nøglering","de":"En lille kombineret lås og nøglering, man fæster på taskens lynlås. Den vogter det dyrebare tæt, mens den klirrer let ved taskens kant. En rejsendes ret kloge ledsager, hvor sikkerhed og pynt bliver ét."},"ICON-0641":{"nm":"Tabsikringsmærke","de":"Den ligger sammenkrøbet i taskens dybeste mørke, og i det øjeblik alle har givet op, blinker den svagt. \"Her er jeg.\" Lyden af noget man troede tabt, der vender tilbage til fingerspidserne. Nok så lille, men den bliver hos sin ejer til det sidste."},"ICON-0642":{"nm":"Lynlåslåsering","de":"Klik — når den én gang er lukket, kan ingen almindelig hånd åbne den. En stædighed der stopper en hastig negl og en snigende finger lige godt. Sikkerhed minder én om, med sin tunge vægt, at det er okay at være lidt stiv en gang imellem."},"ICON-0643":{"nm":"Tyverisikringsklokkesnor","de":"En usynlig portvagt der holder varerne på hylden fra at forlade butikken før betaling. Når en ærlig hånd strejfer forbi, forbliver den tavs til sidst. En klokke der ikke ringer, er den mest fredelige klokke af alle."},"ICON-0644":{"nm":"Kontaktafdækningsmærkat","de":"Den lægger stille et lag hen over navnet og nummeret skrevet på en pakke. Hvem der bor der, hvor den skal hen — kun modtageren behøver at vide det. At skjule godt er også en slags venlighed, siger den, mens den tavst holder sin plads."},"ICON-0645":{"nm":"Pasomslagsbånd","de":"En fremmed lufthavn, snesevis af identiske omslag der kredser på transportbåndet i morgengryet. Blandt dem vinker det \"denne vej\" i en farve kun du kender. En lille kappe iklædt dokumentet, der begiver sig ud på en lang rejse. Selv når omslaget slides, forbliver rejsen lys."},"ICON-0646":{"nm":"Kontantsorteringspose","de":"Sedler til venstre, mønter til højre, nødpenge i et rum ingen kender. Det er det første sted en hånd frisk fra markedet søger hen. Selv en filtret dag finder sin plads herinde, ordentligt og med en klirren."},"ICON-0647":{"nm":"Sikkerhedsforseglingsmærkat","de":"Riv den én gang af, og et mærke bliver siddende. En lille, ærlig samvittighed der aldrig helt kan skjule \"nogen har åbnet mig.\" Under enhver kasse, der ankom forseglet og uskadt, ligger denne vens urokkelige tavshed."},"ICON-0648":{"nm":"Nødkontaktchip","de":"Et vildfarent barns lomme, det inderste af en computertaske, enden af en hundesnor. Selv når øjeblikket ikke kan tale, råber den nummeret tydeligt op i dets sted. Én lille chip rummer et helt \"tag mig med hjem.\""},"ICON-0649":{"nm":"Selfiestang-fjernbetjeningshætte","de":"Gruppebilleder hvor der altid manglede armlængde til at få alle med. Nu skal blot et tryk på knappen for enden til, så kommer hele familien med i én ramme. I det øjeblik alle smiler, trykker jeg stille på udløseren og springer selv ind i billedet."},"ICON-0650":{"nm":"Snor til objektivpose","de":"En snor der holder ekstra objektiver tæt, så de ikke støder mod hinanden i tasken. Fordi ét stykke glas er ét landskab, ryster man ikke den vægt tankeløst. En fotografs omhu er bundet ind i hver eneste knude."},"ICON-0651":{"nm":"Filteretuiring","de":"Ét tyndt ark forvandler den samme himmel til et andet lys. Et sted hvor disse små trylleformularer opbevares pænt i en rund rede. Hver gang man åbner etuiet, flagrer fingerspidserne et øjeblik — hvilken solnedgang skal jeg fange i dag?"},"ICON-0652":{"nm":"Stativpose","de":"Sammenfoldet et håndsbred, udfoldet tre stabile ben. Man ruller forsigtigt den ven sammen, der vil holde scenen fast i stedet for de rystende hænder. Jo tungere udstyret er, desto blødere er den klud, det fortjener at ligge på."},"ICON-0653":{"nm":"Kamerarem-pude","de":"Går man hele dagen, kommer det øjeblik hvor kameraet trykker tungt på skulderen. Da tager én lille pude stille en del af vægten. En lille, blød trøst lagt på skulderen, der går langt for ét godt billede."},"ICON-0654":{"nm":"Hukommelseskort-sorteringsmærke","de":"På nætter hvor man ikke kan huske, hvilket kort der gemmer hundredvis af minder, viser farvede mærker vej. Forårsrejsen i blåt, den første koncert i gult. En lille, kærlig bibliotekar der giver selv minder deres egne hylder."},"ICON-0655":{"nm":"Ladekabelrulle","de":"Før kablerne når at optræde med en knudeforestilling i tasken, rulles de sammen og lægges pænt til hvile. Ordner man én ledning, løsner en tråd af hjertet sig på en eller anden måde med. Det sammenrullede syn er fredfyldt bare at betragte."},"ICON-0656":{"nm":"Fotosikkerhedskopi-mærkat","de":"\"De billeder — fik jeg sikkerhedskopieret dem?\" En lille note der svarer på forhånd på den uro, der pludselig melder sig sent om aftenen. Jo mere dyrebart øjeblikket er, desto mere skal det leve mindst to steder, skriver mærkatet tydeligt."},"ICON-0657":{"nm":"Kompositionsrammetavle","de":"Se verden gennem det firkantede vindue, og man ser med det samme, hvad man skal have med, og hvad man skal lade være ude. Et godt billede handler ikke om at tilføje mere, men om at fjerne godt — det tomme rammeviser én dette først."},"ICON-0658":{"nm":"Møntpung-charm","de":"Den dingler ved taskens kant og rummer nogle få mønter. Det lille skattekammer der åbnes først foran en automat, foran en dampende boller-bod. Den klirrende lyd er lydeffekten af en lille lykke."},"ICON-0659":{"nm":"Kvitteringsspyd","de":"Papirlapper man næsten smed ud, spiddes én for én. Hvad man spiste og købte i dag — kvitteringen er en mere ærlig dagbog end nogen husholdningsbog. Samler man en måneds værd, bliver det til en ganske tyk optegnelse over livet."},"ICON-0660":{"nm":"Markedskurv-mærke","de":"Den hænger på håndleddet på vej til markedet og strejfer boderne sammen med en. En tofu, et bundt forårsløg, endda den venlighed der følger med i tilgift. Den tager al den vægt uden at brokke sig. En ven der er mere begejstret for at blive fyldt end tømt."},"ICON-0661":{"nm":"Souvenirmagnet-tavle","de":"Vælg én ved hvert rejsemål og sæt den på køleskabet, og køkkenet bliver til et lille verdenskort. Byerne man har besøgt hænger side om side og hvisker \"lad os tage af sted igen.\" Selv almindeligt stål har kraften til at holde fast på minder."},"ICON-0662":{"nm":"Regionsstempelbog","de":"Ét stempel per side, gyderne man har gået, vågner igen til live i blæk. De røde mærker samlet på rejser rundt i hele landet er et kort over ens fodspor. Jo færre tomme felter, desto mere vinker den næste rejse stille."},"ICON-0663":{"nm":"Indpakningssnor-rulle","de":"Lang, lang tålmodighed der spoler sig ud i det uendelige for at binde blot én gaveæske. Den giver kun en pæn knude til de hænder, der ved hvornår de skal klippe. Sammenrullet venter den tavst på næste tur."},"ICON-0664":{"nm":"Gavepolstringspose","de":"Den omslutter et skrøbeligt hjerte i en blød favntag. Selv i et rystende pakkerum holder den blødt og fast stand — \"det er okay, jeg holder om dig.\" Den vogter på forhånd endda det lyse smil hos den, der åbner æsken."},"ICON-0665":{"nm":"Prismærkeafdækning","de":"En lille venlig hvid løgn der stille dækker prisen på en gave. \"Du behøver ikke vide hvor meget — tag bare hjertet,\" siger den og sætter sig blødt ned over prismærket. Det er ikke at skjule, men at få det hjerte til at skinne endnu klarere."},"ICON-0666":{"nm":"Mini-indkøbsvognchip","de":"Man kan ikke trille en rigtig indkøbsvogn, men denne lille ven, der dingler fra fingerspidsen, rummer al spændingen ved en tur i supermarkedet. Nok så lille, men den sitren af \"hvad skal jeg købe i dag?\" vejer ikke mindre end den ægte vare."},"ICON-0667":{"nm":"Selvlysende skoklemme","de":"Et glimt ved spidsen af en løbesko på aftentur, der sender en forbikørende bil signalet \"her går der nogen.\" Det første lille lys der kommer én i møde i en mørk gyde. Sikkerhed begynder altid stille ved tæerne."},"ICON-0668":{"nm":"Mini-lommelygtehætte","de":"Sæt den over lommelygtens hoved, og lyset spreder sig længere og blødere. En lille tryllekunstner der maler en stjerneklynge på et mørkt teltloft. På nætter hvor mørket er lidt uhyggeligt, findes der ingen bedre ven."},"ICON-0669":{"nm":"Hjemkomstknap","de":"Tryk hårdt på den, og linjen \"jeg er kommet godt hjem\" flyver af sted til familien langt væk. I stedet for lyden af en gadedør sent om aftenen bringer én lille knap nyheden. Nogen falder i søvn mens de venter på dette signal."},"ICON-0670":{"nm":"Refleksklistermærke-rulle","de":"Klip et felt af og sæt det på tasken, cyklen, paraplyen, og aftenvejen bliver langt mindre farlig. En syvsover der vågner strålende, i det øjeblik den møder et forlys. Sammenrullet venter den på, at det næste mørke skal komme."},"ICON-0671":{"nm":"Nødtaxikort","de":"Stik det i et rum i tegnebogen, og selv et tomt stoppested sent om aftenen føles mindre uoverskueligt. Et nummer, en linje adresse skrevet som et løfte — \"jeg kører dig hjem.\" Hvem skulle tro, at ordet nødsituation kunne være så betryggende."},"ICON-0672":{"nm":"Nattevejskort-bånd","de":"Man går de sparsomt oplyste gader med det viklet om håndleddet. Hvilken gyde der er lys, hvor det bliver mørkt — det hvisker stille genvejen som kun natten kender. Et bånd, der binder sig ved ens side, så man aldrig mister retningen i mørket."},"ICON-0673":{"nm":"Tryghedsalarmpose","de":"Trækker man i den i en nødsituation, skriger den højt nok til at forskrække hele gyden. Resten af tiden gemmer den sig stille i posen og sparer på stemmen til dét ene øjeblik. Det største skrig gemt i den mindste taske."},"ICON-0674":{"nm":"Dørlys-nøglering","de":"Farvel til nætter, hvor man famlede efter nøglehullet for enden af den mørke gang. Den hænger ved døren og byder den hjemvendende hånd velkommen med et rundt lysskær. \"Godt klaret, du er hjemme,\" siger nøgleringen først."},"ICON-0675":{"nm":"Hjemkomstnote til overnatningssted","de":"\"Husk paraplyen, sluk lyset når du går.\" En kort påmindelse på køleskabet vogter det tomme værelse. En lille seddel til den, der skal vende tilbage. Venligheden gemt i ét stykke papir følger stille med helt til døren."},"ICON-0676":{"nm":"Kabelredekam","de":"Den reder forsigtigt filtrede ledninger glatte og lige, som når man børster hår. Kabeljunglen bag skrivebordet bliver ordentlig efter blot nogle få strøg. Det er ikke kun hår, der kan blive filtret, minder kammen stille om."},"ICON-0677":{"nm":"Penneholder-skillerum","de":"Blyanter her, overstregningstusser der, saks i sidste rum. Den deler en lille landsby op inde i én krukke og giver hver pen sin plads. Med rum behøver hånden ikke længere lede. Begyndelsen på lidt orden på skrivebordet."},"ICON-0678":{"nm":"Skærmnoteklemme","de":"Den hænger på siden af skærmen og holder \"dagens gøremål\" lige i øjenhøjde. En lille opslagstavle set forfra, ingen chance for at glemme. Én klemme fanger stille et sind, der bliver ved med at ville udskyde."},"ICON-0679":{"nm":"Skuffesorteringsbakke","de":"Clips og elastikker, tegnestifter og viskelæder. Den giver hver lille stamme i skuffen sit eget værelse. Når hånden når ind i inddelte rum, mindskes tiden brugt på at lede, og et hjørne af hjertet føles lettere."},"ICON-0680":{"nm":"Støvbørsterør","de":"Selv ét støvkorn på et objektiv bliver til en enorm plet på et billede. Derfor venter børsten altid pænt og klar inde i sit rør. En flittig fingerspids der vogter en renlighed, ingen nogensinde bemærker."},"ICON-0681":{"nm":"Skrivebordsmåtte-hjørne","de":"Et håndsbred blødhed lagt i ét hjørne af skrivebordet. Penne ruller ikke ned, og i stedet for koldt glas støtter en varm struktur håndleddet. En venlig flade der byder sin plads først frem, så en lang nats skrift forbliver stabil."},"ICON-0682":{"nm":"Museledningsholder","de":"Filtres ledningen, filtres hjertet også et sted. En berøring der på forhånd fanger en løs tråd og lægger den pænt ned. Næsten ubemærket ordner den stille skrivebordets struktur — en lille, flittig pyntning."},"ICON-0683":{"nm":"Ladestander","de":"Rejs en apparat, der har ligget fladt, skråt op, og skærmen møder endelig blikket. Selv ventetiden mens den lader bliver til en ordentlig stund. At støtte noget er at give selv en ting, der hviler, en ordentlig holdning."},"ICON-0684":{"nm":"Lille skraldespandsmærkat","de":"Selv den mindste spand får sit eget navn. Én linje, \"smid det her,\" kalder en stille orden frem på et rodet skrivebord. Et mærkat er, når alt kommer til alt, en lille hilsen der fortæller en ting: din anvendelse er her."},"ICON-0685":{"nm":"Opslagstavlenål","de":"Den presser et stykke papir fast på tavlen. At betro væggen en følelse man ikke vil glemme et øjeblik. Dagens beslutsomhed, der hænger for enden af nålen, svajer let i brisen og griber fat i en, hver gang man går forbi."},"ICON-0686":{"nm":"Etiketramme-chip","de":"Én firkantet kant forvandler almindelig skrift til én tydelig sætning. En chip der pakker en pæn værdighed omkring lettilgængeligt sprede noter. Ikke at spærre inde, men at omfavne vigtige ord, så de ikke går tabt."},"ICON-0687":{"nm":"Gennemsigtigt skuffehåndtag","de":"Sæt et håndtag på en gennemsigtig skuffe, og man kan se, hvad der ligger i den, uden at åbne den tankeløst. Et håndsbred afstand — synlig, men ikke nærmet. Selv gennemsigtighed har brug for gode manerer, hvisker skuffen sådan."},"ICON-0688":{"nm":"Låglåseklemme","de":"Lad den stå åben, og duften og farven forsvinder stille. Med én lille klemme der bider låget fast, forbliver gårsdagens farve helt intakt til i morgen. At lukke er i virkeligheden arbejdet med at beskytte det, man holder af."},"ICON-0689":{"nm":"Fugtabsorberholder","de":"En lille vagtpost der hader fugt og tavst holder sin post. At have tør luft tæt på er den første betingelse for lang tids opbevaring, minder denne pæne holder stille om. Sådan bevares tørheden."},"ICON-0690":{"nm":"Opbevaringskurv-mærke","de":"Et lille navneskilt på hver kurv. Bestem hvilket rum der huser hvad, og tiden brugt på at lede bliver lige med det samme til hviletid. At rydde op er en venlig note, man rækker sig selv i fremtiden på forhånd."},"ICON-0691":{"nm":"Mini-skillevæg","de":"En lille skillevæg der på et øjeblik rejser et hyggeligt lille rum på skrivebordet. Med denne ene plade opstår et stille hjørne, der vender let ryggen til verden. Et snugt sted helt for sig selv, hvor koncentrationen kan slå sig ned."},"ICON-0692":{"nm":"Poseholder","de":"En holder der stille støtter ryggen på poser, der bliver ved med at vælte. Bare det, at de står pænt i række, gør det langt lettere at vælge den rette. At stille noget lige op er at tage hensyn til den næste hånd på forhånd."},"ICON-0693":{"nm":"Tomrumsmarkør-chip","de":"En chip der bevidst markerer tomhed. At efterlade en plads, der skal fyldes, er også ganske afgjort en plan. Et tomrum er ikke dovenskab, men et håndsbred margin, høfligt efterladt åbent for noget, der snart ankommer."},"ICON-0694":{"nm":"Tandbørstehætte","de":"Man bliver mere kræsen med den børste, der rører munden. Én lille hætte der holder selv ét støvkorn ude. At passe på en usynlig renlighed er netop den lille omsorg, der åbner hver morgen frisk."},"ICON-0695":{"nm":"Sæbeholdernet","de":"Et net der løfter sæben forsigtigt, så den ikke bliver blød af at ligge i vand. Princippet om, at man holder længere ved at lade vandet løbe af — det beviser dette tavst hver eneste dag fra badeværelsets laveste, mindste plads."},"ICON-0696":{"nm":"Shampoopumpe-klemme","de":"Den holder pumpehovedet stille fast, så ét tryk kun giver præcis den rette mængde. Vanen med at spare er grundlaget for en husholdning, der rækker langt. Én lille klemme holder venligt overforbrug i skak."},"ICON-0697":{"nm":"Barbermaskinekrog-hætte","de":"Skarpe ting får deres eget lille hus. Sæt barbermaskinen i hætten og hæng den op, så løber både fugt og fare af sammen. At håndtere skarphed forsigtigt er, når alt kommer til alt, også en måde at passe på sig selv."},"ICON-0698":{"nm":"Bruserhåndklæde-ring","de":"Et langt håndklæde danner en løkke og når helt ind til ryggen, hånden ikke kunne nå. Langs den ene struktur, hvor skummet glider, spreder en venlig varme sig gennem hele badeværelset — varmen fra selv at kunne vaske sin egen ryg."},"ICON-0699":{"nm":"Afløbssi-pakke","de":"Ét lille net der lader vandet løbe igennem og holder på resterne. På et sted ingen ser, forhindrer den stille tilstopning. De ting der arbejder på det laveste sted, holder husets flow i gang, minder afløbet én om uden et ord."},"ICON-0700":{"nm":"Sugekrogtavle","de":"Den skaber et nyt sted på væggen uden at slå et eneste søm i. Tryk den fast på og træk den af igen, og ikke engang et spor bliver tilbage. Kunsten at blive et stykke tid og forlade uden mærker — sugekoppen kender denne lette høflighed godt."},"ICON-0701":{"nm":"Badetøffelmærke","de":"Et par sat pænt op foran dørtærsklen. Omsorgen fra et hjem, hvor man tager skoene af, følger omhyggeligt helt hen til badeværelsesdøren. Et navneskilt udpeger stille og roligt stedet for denne lille velkomst, der varmer kolde tæer."},"ICON-0702":{"nm":"Mini skyllekop","de":"En lille, rund kop, der rummer en mundfuld til tandbørstningen. I det korte øjeblik, man skyller munden, tager den stille imod dagens begyndelse og afslutning. Ikke prangende, men ved din side hver dag – enkelhed er den husholdning, der varer længst."},"ICON-0703":{"nm":"Støvekostovertræk","de":"Et overtræk trukket over fjerene på en kost, der samler støv op, som strøg man det blidt. Ligesom en fugl, der pænt folder vingerne sammen, når den ikke flyver, forbliver et redskab, der kender sin hvileplads, ved din side i lang tid."},"ICON-0704":{"nm":"Fnugrulle-refill","de":"Riv ét lag af, og en frisk, ren overflade springer frem nedenunder. De klæbrige, indre blade der samler fnug og hår. I en rund refill, der fyldes op igen, når den er brugt, ligger dyden af flittig gentagelse viklet."},"ICON-0705":{"nm":"Kludeklemme","de":"En klemme, der bider fast om kluden i stedet for din hånd. Den holder en håndsbred afstand mellem det kolde gulv og dine fingre. Ét håndtag, der tager det beskidte arbejde på sig, gør den hårde rengøring langt lettere."},"ICON-0706":{"nm":"Sprækkebørstehætte","de":"En lille hætte, der beskytter den bløde spids på en tynd børste lavet til at grave sig ind i smalle sprækker. Et hjerte, der passer selv de kroge, hænder ikke når. Den, der renser de usynlige steder, gør hjemmets favn en håndsbred bredere."},"ICON-0707":{"nm":"Sprayflaskeetiket","de":"Et lille navneskilt, der sidder blidt på skulderen af en sprayflaske. Om indholdet er rent vand eller sæbe, fortæller den tydeligt i én linje. En etiket, der fjerner forvirringen på forhånd, er en driftig husholdersks gamle vane."},"ICON-0708":{"nm":"Toiletpapir-refillbånd","de":"Et bånd, der sætter en ny rulle på den tomme plads og binder den fast. Det enkleste greb, der samler det, som blev afbrudt. Nogens hjerte, der fylder op, før det slipper op, ligger viklet rundt i denne lille sløjfe."},"ICON-0709":{"nm":"Rengøringshandskekrog","de":"En krog, der hænger de våde handsker til tørre, lige efter det våde arbejde er slut. Den giver de flittige hænder et sted at hvile en stund. Mens fugten langsomt tørrer, trækker en kort pause vejret inden næste opgave."},"ICON-0710":{"nm":"Kostophængsstift","de":"Hæng kosten på hovedet, og børsterne holder sig lige i stedet for at bøje. En stilling, der venter oprejst på den næste gård. Et lille, men solidt sted, der hjælper den med at bevare sin form, selv efter arbejdet er gjort."},"ICON-0711":{"nm":"Skraldeposeclips","de":"Den bider fast om posens åbning og forsegler den tæt, så intet siver ud. Ét greb, der lukker enden ordentligt, gør oprydningen langt renere. Afslutningen begynder, når alt kommer til alt, med at lukke godt til."},"ICON-0712":{"nm":"Tøjklemmekurv","de":"En kurv, hvor tøjklemmer, der let bliver væk, når de spredes, alle bor sammen. Den giver de små ting et fælles hjem at blive i. Saml fingerspidsernes små soldater ét sted, så kan du finde dem med det samme, når du har brug for dem."},"ICON-0713":{"nm":"Sokkeparringsring","de":"En ensom sok forsvinder altid stille et sted hen. Bind hvert par sammen med en ring, før du vasker, og selv efter de er tørret bløde og luftige, skilles de to ikke ad. Sortering er et lille løfte, indgået på forhånd, mod at forsvinde."},"ICON-0714":{"nm":"Vaskeboldpose","de":"Den ruller rundt og rundt inde i maskinen og banker det indgroede snavs i tøjet vågent. En rytme, der stryger vasketøjet med sin runde krop. Midt i det brusende vand bærer den vasketøjets gamle instinkt – banken – viklet ind i en pose."},"ICON-0715":{"nm":"Uldvaskemålehætte","de":"Sarte klæder får en lige så sart mængde. En målehætte, der afmåler præcis ét låg fuldt af uldvaskemiddel. I én lille markering ligger den forsigtige hånd, der behandler uld. At mindske overskuddet er også omsorg."},"ICON-0716":{"nm":"Stofreparationslap","de":"En lille lap, der lægges blidt over et slidt sted. Fingerspidsens hjerte, der passer et flosset sted i stedet for skødesløst at kaste det væk. I hvert stoppede mærke bevares smukt mønstret af de år, tøjet har gennemlevet sammen med dig."},"ICON-0717":{"nm":"Tørrestativstift","de":"En stift, der stille holder tørrestativet nede, så vasketøjet ikke blæser af sted. Selv på dage, hvor tøjet bølger i solen, hjælper den med at holde stand midt i svajet. Rollen som én lille, men pålidelig modvægt."},"ICON-0718":{"nm":"Undertøjsvaskenetmærke","de":"Sart undertøj vaskes for sig selv inde i et net. Et net, der pakker de bløde ting tæt ind mod det brusende vand. Én lille pose med mærkat minder os om, at det også er husholdning forsigtigt at beskytte det skrøbelige."},"ICON-0719":{"nm":"Vaskemiddel-skekrog","de":"Hæng vaskemiddelskeen pænt på væggen. Ikke mere besvær med at tabe den i tromlen og gøre hånden våd. Den ordentlige vane med altid at have det samme redskab på samme sted holdes fast i denne lille krog."},"ICON-0720":{"nm":"Tørresnorsstopper","de":"Den bider fast om tørresnorens ende, så selv tynget af tungt vasketøj glider den ikke løs. Den sidste knude, der holder ud til det sidste, så en stram line ikke synker. En solid afslutning hviler på denne."},"ICON-0721":{"nm":"Pudebetræksmærke","de":"Stedet din kind rører først hver nat, med et tommelfingernegle-stort mærke syet ind på indersiden. Hvem læser mon den bittesmå tekst med vasketemperaturen? Alligevel er det den nærmeste vejledning af alle, der våger ved siden af et sovende ansigt."},"ICON-0722":{"nm":"Dyneklemme","de":"En nat med vinduet åbent løber dynen ikke sin vej, selv når brisen kommer ind. For en klemme med munden lukket tæt holder fast i hjørnet. En tavs hånd, der holder kanten i stedet for den sovende."},"ICON-0723":{"nm":"Natlysskærm","de":"\"Når lyset når øjnene, glider søvnen væk.\" Med én skærm, som nogen stille har stillet op, træder lyset tilbage og fugter kun svagt sengens fodende. En lille skillevæg, der låner en håndsbred mørke."},"ICON-0724":{"nm":"Sengekantslomme","de":"Forestil dig den sprække mellem madras og væg, din hånd aldrig kunne nå. Fjernbetjeningen, der rullede væk, og brillerne med, samles her nu. En lomme, sengen stille folder ud, for at gribe de ting, du næsten mistede."},"ICON-0725":{"nm":"Brilleopbevaringsbakke","de":"Tag linserne af, og verden udviskes blødt, og en lav skål opfanger dette korte øjeblik af værgeløshed. Om morgenen, selv uden famlende fingre, venter brillerne altid på samme sted."},"ICON-0726":{"nm":"Vækkeurholder","de":"Klokken seks om morgenen, oven på det solide fodstykke, hvor den mest forhadte lyd runger. Fast og ustandseligt bærer den uret og åbner til sidst nogens dag. Den bærer, uden et ord, det barske løfte om at vågne."},"ICON-0727":{"nm":"Sengegavlkabelholder","de":"Ladekablet, der plejede at glide ned bag sengegavlen, falder ikke længere til gulvet. For en lille holder griber stille om ledningens ende. Inden for armslængde – et greb, der har ryddet op i nattens rute."},"ICON-0728":{"nm":"Pyjamasopbevaringsbånd","de":"Et bånd, der vikles én gang om de pænt sammenlagte pyjamas og binder dem sammen. Selv en blødhed, der let bliver rodet, har brug for pli. For den, jeg bliver i morgen aften, ruller den, jeg er i dag, dem sirligt sammen – en lille forberedelse."},"ICON-0729":{"nm":"Duftkortholder","de":"Sæt et duftsat kort skråt op, og ligesom man vender en side, vender du årstiden med næsen. Fra lavendel til citrus – det bliver en dagbog for den dag, nedskrevet i duft."},"ICON-0730":{"nm":"Nøgleskålpude","de":"Et hjørne ved entredøren, hvor nøglerne plejede at falde med et klirr. En skål foret med en blød pude sluger den skarpe lyd. Et lille underlag modtager stille den hjemvendtes første bevægelse."},"ICON-0731":{"nm":"Paraplydrypbæger","de":"Regnvand drypper langsomt fra spidsen af paraplyen, du bar med ind. Ét bæger opfanger denne dryp så ordentligt, at nogen på forhånd har forudset og standset den lille pøl, der ellers ville have bredt sig ud over gulvet."},"ICON-0732":{"nm":"Mundbindskrogbrik","de":"En tommelfingernegle-stor brik siddende på væggen ved døren. Som det sidste ritual, før man går ud, hænger mundbindet her. En lille hukommelsesanordning, der holder øjenhøjde ved døren, så du ikke glemmer, hvad du skal have med."},"ICON-0733":{"nm":"Pakkeknivsskede","de":"Et beskyttende overtræk trukket over bladet, der åbner pakker. Det dækker stille over risikoen for et snitsår, gemt bag glæden ved at pakke ud. En umærkelig omtanke, der trygt åbner enden på ventetiden."},"ICON-0734":{"nm":"Skobørstestativ","de":"Stedet hvor skobørsten hviler, stadig fugtig efter sin skrubning. Selv med fugt tilbageholdt forbliver gulvet tørt. Selv et redskab, der skaber renlighed, har brug for et sted at hvile, minder det lille stativ os om."},"ICON-0735":{"nm":"Besøgstavle","de":"\"Kom lige forbi et øjeblik.\" En kort linje efterladt på entreens memotavle. Et lille torv, hvor folk, der lige har mistet hinanden, deler på tværs af tid. På ét stykke papir lægger en hilsen, en anmodning og et hjerte sig oven på hinanden."},"ICON-0736":{"nm":"Dørsprækkerulle","de":"Trækket, der sivede ind gennem den fingerbrede sprække under døren. En sammenrullet stopper spærrer stille denne passage. Den holder ét ekstra lag varme tilbage i rummet, som ellers ville være sivet umærkeligt ud."},"ICON-0737":{"nm":"Dørstoppercharm","de":"Et lille charm, der støtter foden af en helt åben dør, så den ikke smækker i igen. Den holder tungt og stabilt for brisen og fodtrinnene, der passerer. En venlig stædighed, der holder døren åben."},"ICON-0738":{"nm":"Entrélyskontaktcover","de":"Entrékontakten, du famlede efter sent om aftenen. Et selvlysende cover markerer stille sin plads i mørket. Så din hånd ikke farer vild – en lille guide, der lyser først, før lyset tændes."},"ICON-0739":{"nm":"Kopunderlag","de":"I det øjeblik en kop stillet på bordet begynder at glide, griber ét underlag blidt om dens fod. Et underlag, der roligt holder sin plads, uden at efterlade så meget som ét mærke, selv når vanddråber samler sig."},"ICON-0740":{"nm":"Bilduftclips","de":"En lille duftclips hængende inde i bilen. Ridende på blæsten fra ventilationen fylder en svag duft langsomt det trange rum. En venlig trøst på førersædet, der varmer selv kedsomheden ved et rødt lys med duft."},"ICON-0741":{"nm":"Sikkerhedsselecover","de":"Et blødt overtræk trukket over selen, der krydser din skulder. Den ru fornemmelse mod nakken glider væk. Selv en rem beregnet til sikkerhed kan tilføjes venlighed, siger dette håndsbrede stykke stof."},"ICON-0742":{"nm":"Parkeringsnummerskærm","de":"En skærm, der stille dækker skiltet, som viser din plads i en underjordisk parkeringskælder, før du tager et billede. Alle har information, de hellere vil holde for sig selv. Ét lag omhyggeligt visket bort fra en scene af hverdagsliv."},"ICON-0743":{"nm":"Cykelklokkehætte","de":"Ring-ring. Den klare hilsen, cyklen sender ved gadehjørnet. En hætte over klokken bevarer den lyd, selv i regnvejr. Ved ét lille klingende slag smiler folk og træder til side."},"ICON-0744":{"nm":"Styrgrebsring","de":"En ring, der blødt omslutter styrets fornemmelse i din håndflade. Selv efter lang tids greb og kørsel bliver hænderne ikke følelsesløse. Jo længere vejen er, desto mere forkorter komforten der, hvor du holder fast, den afstand."},"ICON-0745":{"nm":"Hjelmnavnemærkat","de":"Et navnemærkat på indersiden af en hjelm. Blandt identiske sikkerhedshjelme råber det stille \"denne er min\". Det mest personlige mærke, indridset oven på den hårdhed, der beskytter dit hoved."},"ICON-0746":{"nm":"Hjulrefleksdop","de":"En dop, der først begynder sit arbejde, når solen går ned. Den fanger forbipasserende lys og kaster det klart tilbage fra hjulet. I mørket sender den med lys det lille signal \"her er nogen\"."},"ICON-0747":{"nm":"Bilnøglepose","de":"En bilnøgle, der plejede at blive ridset, når den stødte mod andre nøgler i lommen. En blød pose omslutter denne overflade tæt. Ønsket om, at noget man holder hver dag, skal holde længe uden ridser, ligger gemt heri."},"ICON-0748":{"nm":"Sugekopshyldepin","de":"En sugekops-hyldepin, der klæber sig fast til væggen uden et eneste søm. Selv en væg, du ikke vil sætte mærker i, får ét ekstra opbevaringsrum. Kunsten at hænge sit hjem op i et rum, man kun låner – uden at efterlade spor."},"ICON-0749":{"nm":"Krogplade uden boring","de":"Forestil dig at kunne hænge noget op uden at bore hul i væggen. En krogplade uden boring tager stille lette ting på sig. Ønsket om ikke at skade et lånt rum ligger smukt gemt i én lille krog."},"ICON-0750":{"nm":"Magnetisk organiseringsskinne","de":"Lyden af metal, der klikker på plads med et lille klik. Fej de små redskaber, der ligger spredt overalt, sammen med en magnet, og en kaotisk arbejdsbænk retter sig op i en pæn række – en lille tilfredsstillelse følger med."},"ICON-0751":{"nm":"Sprækkeopbevaringsstang","de":"Forestil dig den smalle, glemte sprække mellem køleskabet og væggen. En tynd stang fylder dette mellemrum med nytte. En sparsommelig idé, der henter opbevaring frem fra et rum, man anså for ubrugeligt."},"ICON-0752":{"nm":"Klæbepudeark","de":"Et klæbepudeark, der, når det først er sat fast, let bærer selv tunge ting. Riv det af, og der er, forbløffende nok, ikke ét eneste mærke tilbage. En stille, stædig styrke, der bærer vægt fra et sted, ingen ser."},"ICON-0753":{"nm":"Dørkrogsdop","de":"En krogdop, der bare hænges let over toppen af en dør. Tasker og håndklæder dingler lige ved hånden. En krog, født uden et eneste søm, tilføjer ét ekstra åndehul til et trangt rum."},"ICON-0754":{"nm":"Kabelvægclips","de":"En clips, der samler ledninger, der hang løst ned ad væggen, i én pæn linje. Nøglet bag skrivebordet retter sig ud til en ren streg. Usynlig oprydning gør selv luften i rummet lettere."},"ICON-0755":{"nm":"Lampefodspude","de":"En pude, du lægger blidt under foden af en gulvlampe. Den efterlader ingen ridser på skrivebordet og dæmper selv den fineste rysten. Selv at rejse et lys begynder med et gulv, der ikke vakler."},"ICON-0756":{"nm":"Skridsikker klæbeplade","de":"Måtten, der stille sneg sig væk under fødderne, standser endelig på sin plads, for klæbepladen bider fast i gulvet. Et umærkeligt sikkerhedsnet, der stille rydder det nærsnubl-øjeblik af vejen, før det sker."},"ICON-0757":{"nm":"Præcisionsskruetrækkerhætte","de":"\"Den her lille skrue vil bare ikke løsne sig.\" En hætte sat over spidsen af en præcisionsskruetrækker beskytter bladet. Fingerspidsernes mest fintfølende redskab, der åbner den håndfladestore verden inde i en maskine."},"ICON-0758":{"nm":"Unbrakonøglering","de":"En ring, der samler flere unbrakonøgler på én løkke. Metallet, opstillet efter størrelse, folder sig ud som en vifte med et sus. Den ordnede rytme i en hånd, der på ét greb vælger netop den, den skal bruge."},"ICON-0759":{"nm":"Mini-målebåndscharm","de":"Et charm fastgjort til et mini-målebånd, der lige passer i håndfladen. Det dingler fra en nøglering og følger med overalt. En lille ven, der på stedet måler og svarer på enhver længde, der pludselig vækker din nysgerrighed."},"ICON-0760":{"nm":"Skruesorteringsboks","de":"En sorteringsboks, hvor uens skruer hver finder deres eget rum. Selv de små dele, der før rullede rundt i en bunke, får orden. Hånden, der lærer at rydde op først, før noget som helst repareres."},"ICON-0761":{"nm":"Limdyssehætte","de":"Lukket størkner jeg ikke, åben tørrer jeg ud – jeg lever i det rum imellem. For hver dråbe, der falder, bliver noget itugået et sted samlet igen. Ét lille låg vogter stille grænsen mellem stilstand og flow."},"ICON-0762":{"nm":"Vaterpas-nøglering","de":"En håndfladestor ærlighed, der dingler for enden af et nøgleknippe. Det er altid denne lille boble, der først opdager en skæv hylde. Jeg bærer i lommen en ven, der stille fortæller mig, at verden hælder en anelse."},"ICON-0763":{"nm":"Pincetspidshætte","de":"Jo skarpere en ting er, desto mere har den brug for en klædning, der dæmper den. Dæk spidserne blidt til, og hverken hånd eller dele kommer til skade. Den første høflighed i at håndtere noget skarpt er stille at dække dens spids – og denne lille hætte påtager sig den venlighed."},"ICON-0764":{"nm":"Lille skæremåtte","de":"En plade, hvis ar heler af sig selv, selv efter tusindvis af knivsstrøg. Den næste opgave lægges igen oven på snittet, og igen heler det. En stille bund, der giver af sin egen krop, dag efter dag, for at andet kan skæres rent."},"ICON-0765":{"nm":"Reservedelspose","de":"En pose, der snører munden sammen, så en enkelt skrue, en enkelt fjeder aldrig forsvinder for evigt. De små ting, der er tilbage efter en reparation, venter stille her på deres næste tur. Det er altid sådanne beskedne rum, der forhindrer, at noget går tabt."},"ICON-0766":{"nm":"Snackposeclips","de":"At holde en åbnet pose sprød handler i sidste ende om ét bestemt greb. Et lille løfte om ikke at give den chancen for at blive blød. Vanen med at klemme enden ordentligt sammen redder morgendagens snack."},"ICON-0767":{"nm":"Vingummi-portionsbæger","de":"For at dele én pose mellem flere må man først dele retfærdigt. Hjertet, der øser den samme mængde i hvert lille bæger. At dele, tror jeg, begynder med præcis den samme mængde, så ingen føler sig glemt."},"ICON-0768":{"nm":"Chokoladefolierest","de":"Sølvet, der pakkede sødmen ind, krøller let sammen mellem fingrene. Glat det ud, og det glimter et øjeblik; fold det, og det bliver et minde. Et stykke lys, der først bliver smukkest, når alt er spist – kig lige en gang til, før du smider det ud."},"ICON-0769":{"nm":"Snacketiketbånd","de":"Hvad der er i, hvor længe det holder sig – jeg taler på den tavse poses vegne. I det øjeblik ét bånd sættes på, får selv en snack et navn og et løfte. Sortering er, i grunden, den mest ømme form for hukommelse."},"ICON-0770":{"nm":"Sliksorteringsboks","de":"Læg ikke de sure og de søde i samme rum. Arbejdet med at dele dem op på forhånd, så hånden ikke tøver. Når de små bokse stiller sig på række, fordobles glæden ved at vælge stille og roligt."},"ICON-0771":{"nm":"Småkagepolstringspapir","de":"Tyndt papir stukket ind mellem småkager, så de ikke bliver stødt undervejs. Jo mere skrøbeligt noget er, desto mere blidt et følgeskab har det brug for. Somme tider beskytter blødhed bedre end hårdhed."},"ICON-0772":{"nm":"Donutæskesnor","de":"Én kryds-knude tager ansvaret for kagens sikre rejse inde i æsken. Den bliver et håndtag, et segl og et tegn på spændt forventning. Det øjeblik denne snor løsnes, er nogens fødselsdag."},"ICON-0773":{"nm":"Brødposeklemme","de":"Vrid mig én gang, fold, og sæt mig på, så bevares brødets blødhed helt til i morgen tidlig. En lille, stædig insisteren på at holde luften ude. At bevare noget blødt i lang tid er altid opgaven for noget fast."},"ICON-0774":{"nm":"Snackbyttemærke","de":"Din del til mig, min del til dig. Husker du spændingen ved at skrive navne på små mærker og bytte snacks den dag? Papiret, der hæftes på et delende hjerte, har altid en vens navn skrevet tydeligt på sig."},"ICON-0775":{"nm":"Sugerørsprop","de":"Når du holder en pause mellem to slurke, lukker du mig til. Så intet spildes, så det ikke bliver koldt, så det venter stille lige der. Opgaven for en lille prop, der vogter åbningen, indtil læberne vender tilbage."},"ICON-0776":{"nm":"Termokrusnavnering","de":"En lille ring, der siger \"denne er min\" blandt en række termokrus stående side om side. Én farve, og forvekslingen smelter stille væk. Én ring er nok til tydeligt at markere, hvad der er dit."},"ICON-0777":{"nm":"Kopholderomslag","de":"Et enkelt lag bølgepap, der stille smutter ind mellem en varm kop og din håndflade. En omsorg puttet ind, så du ikke brænder dig eller mister grebet. At værne om mellemrummet er netop det, der fuldender en tryg kop."},"ICON-0778":{"nm":"Isbakkeetiket","de":"Der findes folk, der skriver datoen på hvert hold is, de laver. Med troen på, at selv kulde har en orden. Ét lille mærkat lader tiden i fryseren strømme ærligt, tur efter tur."},"ICON-0779":{"nm":"Tepose-tang","de":"Mens man vogter trækketiden, løfter man den op i netop det rette øjeblik. Den fingerfærdige berøring, der ved, hvornår den skal standse, før det bliver for kraftigt. En tes dybde afgøres mindre af, hvor længe den trækker, og mere af, hvornår man tager den op."},"ICON-0780":{"nm":"Drypfilterholder","de":"Den holder filteret oppe og står tavst, så det varme vand kan sive langsomt igennem. Den ved godt, at hastværk gør duften tynd. Selv arbejdet med at bære tålmodighed kræver en urokkelig holdning."},"ICON-0781":{"nm":"Flaskerem","de":"En rem, der hænger vandflasken om håndleddet eller skulderen, så den følger med på turen. En måde at have følgeskab på, der altid holder den nær, uden at man behøver huske den bevidst. Nogle gange er en lille bindning den kærligste måde ikke at glemme på."},"ICON-0782":{"nm":"Dåselågscover","de":"Den dækker åbningen på en halvdrukken dåse for at holde støv ude og forhindre den i at gå flad. En lille hat, der tager ansvaret for friskheden indtil næste slurk. Selv i handlingen med stille at dække noget, der kortvarigt er åbnet, ligger der omsorg."},"ICON-0783":{"nm":"Drikkevarekuponholder","de":"Den gratis tiende kop – den holder om stempelkortet, så det løfte ikke går tabt. Så dagene, fyldt ind ét felt ad gangen, ikke krølles. I denne holder samler sig de flittige fodspor fra en stamgæst, der er kommet igen og igen."},"ICON-0784":{"nm":"Madkassebånd","de":"Et bånd, der omfavner madkassen én gang rundt, så låget ikke springer op. En lille tryghed for, at suppen ikke løber ud i tasken. Den sikre rejse frem til frokost er i varetægt hos denne stramme, ene omgang."},"ICON-0785":{"nm":"Tilbehørsbægersæt","de":"Giv hver tilbehørsret sin egen plads, og smagene blander sig ikke. Kimchi for sig, grønt for sig, hver især tydelig. De rum, disse små bægre skaber, er madkassens orden – og en ømhed oven på kokkens håndelag."},"ICON-0786":{"nm":"Spisepindeetui","de":"Et lille hjem, der holder rent og bærer spisepindene, som har delt alle dagens tre måltider. En stille ledsager, der bevarer sin orden selv inde i en skoletaske. Omsorgen ved at have dem med er, i sidste ende, det, der skaber et velordnet måltid."},"ICON-0787":{"nm":"Sovseflaskeetiket","de":"Soja eller eddike? Den giver klarhed til flasken, du plejede at forveksle. I det øjeblik én linje sættes på, forsvinder fingerspidsernes tøven. Farten i et travlt køkken skabes stille af netop sådanne små mærker."},"ICON-0788":{"nm":"Gimbap-rulleark","de":"Et tyndt ark tang, der ruller ris og fyld sammen til én krop. Det skal pakkes stramt, så det ikke falder fra hinanden, når det skæres. Spændingen ved en morgen på skovtur kommer rullet rundt ud fra netop dette ene lag."},"ICON-0789":{"nm":"Pindeholderbæger","de":"Stil spyd og tandstikkere op ét sted, og hånden famler ikke, når øjeblikket kommer. At give selv de spidse ting et hjem for sig selv. Orden er, i sidste ende, en lille venlighed for den næste hånd, der rækker ind."},"ICON-0790":{"nm":"Kølepose-cover","de":"Man pakker kølepakken ind i endnu et lag for at holde på kulden lidt længere. Samtidig forhindrer det tasken i at blive våd af kondens. At bevare kølen til det sidste er altid arbejdet for dette tykke, ene lag."},"ICON-0791":{"nm":"Madkasseskillevæg","de":"En lille mur rejst, så ris og tilbehør ikke krænker hinandens plads. Freden i ét rum, hvor suppen ikke vandrer på tværs. En madkasse delt op i felter rummer, uforfalsket, den omtænksomme omsorg fra den, der lavede den."},"ICON-0792":{"nm":"Måltidsrækkefølgekort","de":"Suppe først eller ris først? Et kort, der stille antyder dagens forløb. En venlig vejledning, der siger, det smager bedre spist i rækkefølge. Den fortæller stille, at selv et måltid har et forløb, ligesom en historie."},"ICON-0793":{"nm":"Målebægersticker","de":"En lille sticker ved siden af skalaen peger præcist på \"her til\". Et mærke, der på ét slag rammer den mængde, du altid var i tvivl om. Præcision udspringer af netop sådan en lille guidelinje."},"ICON-0794":{"nm":"Silikonelåghåndtag","de":"Et lille håndtag, der lader dig løfte et varmt låg uden at brænde fingrene. Det låner stille modet til at åbne en dampende gryde. Sikkerhed kommer altid fra at have et greb klar på forhånd."},"ICON-0795":{"nm":"Mini-klemmeophæng","de":"En lille klemme, der giver en plads til viskestykker og poser, som ikke havde noget sted at hænge. Den forvandler et rodet stykke væg til et ordentligt syn. Én vane med at hænge ting op gør køkkenet så meget lettere."},"ICON-0796":{"nm":"Oliebørstehætte","de":"Dæk spidsen på oliebørsten til, og både støv og hærdning går udenom. En hat, der bevarer den blødhed til næste ret. En lille omsorg for sine redskaber bevarer, i sidste ende, smagen i lang tid."},"ICON-0797":{"nm":"Saltske-krukke","de":"En lille ske, der bor gemt inde i saltkrukken. Den øser præcisionen af én knivsspids frem, omhyggeligt, hver gang. Den fingerfærdige smag ved at krydre er netop så meget hjerte, som denne lille ske husker."},"ICON-0798":{"nm":"Timermagnetplade","de":"Klæbet til køleskabsdøren tæller den 3 minutter til nudlerne og måler 30 sekunder til øvelsen. Med én magnet dvæler tiden, der ellers ville glide forbi, foran øjnene. En flittig lille cirkel, der kortvarigt fastholder det forbipasserende øjeblik på væggen."},"ICON-0799":{"nm":"Grydehåndtagscover","de":"Et lag, der omslutter håndtaget, så du ikke griber det ophedede med bare hænder. Et lille skjold, der stiller sig mellem varmen og din håndflade. At bære trygt begynder altid med denne bløde omfavnelse."},"ICON-0800":{"nm":"Skærebrætgummifod","de":"Når jeg lægges under, glider skærebrættet ikke længere. Et stykke gummi, der holder stand nedefra, hver gang skærearbejdet vakler. Stabilitet er arbejdet med at bide fast dér, hvor ingen ser det."},"ICON-0801":{"nm":"Ovnhandskeklemme","de":"Stedet hvor den hånd, der ustandseligt rørte sig foran ilden, endelig får lov at hvile et øjeblik. Fastgør den flagrende ovnhandske på væggen, og et kort åndedrag begynder inden næste måltid. At rydde op er, når alt kommer til alt, bare et andet ord for ømhed."},"ICON-0802":{"nm":"Kaffepindeholder","de":"Ved siden af disken, et sted hvor tynde pinde læner sig skulder mod skulder, stablet pænt op. Klar til at tegne en spiral i nogens morgenkop, stillet på række som et kor lige før det synger sammen."},"ICON-0803":{"nm":"Underkopssæt-bånd","de":"Et bånd der stille opfanger den lille klirren, når et glas rører bordet. Bind de runde underkopper sammen, og velkomsten til gæsterne er klar. Gæstfrihed begynder altid, som her, i de mindste ting først."},"ICON-0804":{"nm":"Sirupsetiket","de":"Et enkelt navn på flasken. Sød, kraftig - det ene korte ord gør en travl morgen en smule mere ordnet. En etiket er papir, hvorpå et lille løfte skrives ned i forvejen."},"ICON-0805":{"nm":"Dessertpindekrukke","de":"En krukke hvor de spidse pinde, der spidder en frugtbid, bor sammen. Før de plantes som flag på en dessertanretning, venter de her stille på deres tur. Selv sødme har sin orden."},"ICON-0806":{"nm":"Rørepindemanchet","de":"En papirfrakke der tæt omslutter en håndfuld rørepinde. Den opsuger den fugt, en kold drik afgiver, og holder fingerspidserne, der holder glasset, tørre. Usynlig omsorg kommer altid fra kanterne."},"ICON-0807":{"nm":"Takeaway-bærehåndtag","de":"Når to hænder ikke slår til, bærer et lille håndtag kopperne for dig. Det holder den indpakkede varme, så ikke en dråbe spildes, og følger den varme helt til nogens gadehjørne."},"ICON-0808":{"nm":"Cafébuzzerhylster","de":"En frakke der stille omslutter ventetiden, indtil buzzeren summer. Den vogter den lysende ventenummer i cafeens hjørne og rummer også den spænding, der siger, at dit nummer snart bliver kaldt."},"ICON-0809":{"nm":"Stempelkuponring","de":"Papir hvor ti udfyldte felter giver en kop gratis. For hvert stempel der tilføjes, vokser navnet 'stamgæst' også en smule. En beskeden lille glæde, trukket på en lille ring."},"ICON-0810":{"nm":"Kaffebønneprøvepose","de":"En pose der rummer en håndfuld bønner og byder duften velkommen først. Syrligheden og sødmen, der stryger forbi næsen - den første fornemmelse afgør en kops skæbne. Duft ankommer altid hurtigere end nogen forklaring."},"ICON-0811":{"nm":"Køleskabsetiketmagnet","de":"Et lille magnetisk navneskilt, der klikker fast på køleskabsdøren. Skriv ned, hvad der kom ind og hvornår, og selv en tilbehørsret, der næsten var glemt, genvinder sin tur. Husholdning er kunsten at fastholde en flydende hukommelse."},"ICON-0812":{"nm":"Opbevaringsdatochip","de":"Et lille stykke, der tydeligt indprenter den dag, noget blev pakket ned. Et lille vidne, der stille fortæller, at selv dage senere er dette stadig fint. Friskhed bevares af fingerspidser, der husker datoen."},"ICON-0813":{"nm":"Portionsbeholderbånd","de":"Et bånd der omfavner en opdelt beholders talje hele vejen rundt. Det holder det klaprende låg tæt lukket og bevarer en lille orden i køleskabet. At binde noget sammen minder om arbejdet med at få hjertet i orden."},"ICON-0814":{"nm":"Farvet posestrimmelklemme","de":"Farverige klemmer, der bider fast om en poses åbning. Rød for stærkt, gul for sødt - hånden ved det bare fra farven. Køkkenets trafiklys viser vejen, sådan her, uden et ord."},"ICON-0815":{"nm":"Fryseposemærke","de":"Et navneskilt lagt blidt oven på noget frosset. Det trøster den rimdækkede pose, så den ikke glemmer, hvad den engang var. En lille hilsen sendt til ingredienser, der er gået i vinterhi."},"ICON-0816":{"nm":"Grøntsagsnet","de":"Et løst net der gavmildt tager imod jordede grøntsager. Bedstemors køkken vidste for længst, at rum til at ånde er det, der lader dem holde længere. Udluftning er en øm margin, skænket til grøntsagerne."},"ICON-0817":{"nm":"Flaskelågsorteringshætte","de":"En sorteringshætte, der parrer låg med hinanden, et efter et, efter størrelse. At finde en tabt makker igen er ømmere, end man skulle tro. Sæt et sammenpassende par til hinanden, og køkkenet falder også i bedre orden."},"ICON-0818":{"nm":"Æggebakkeetiket","de":"Et mærke pænt tildelt hver af de ti små reder. Husholdningens visdom, der siger: brug de ældste æg først. Selv et enkelt spejlæg om morgenen bærer hjertet i at passe på rækkefølgen."},"ICON-0819":{"nm":"Resterklistermærke","de":"Skriv 'det her er mit!' og sæt det fast, og selv køleskabet finder et øjebliks fred. En sød lille krigserklæring, der på forhånd udpeger ejeren af natmaden. Familien ruller videre, også i dag, på den slags små bagateltraktater."},"ICON-0820":{"nm":"Bestikholderbrik","de":"En lille brik, der blidt løfter ske og spisepinde, så de ikke rører bordet direkte. Denne lille pænhed hæver umærkeligt et måltids stil. Bordskik gror, ubemærket, netop på sådanne steder."},"ICON-0821":{"nm":"Servietholdering","de":"En ring der stille glider på og holder fast i en serviet, der ellers ville flyve i vinden. Den samler det hvide papir, som venter sin tur til at foldes ud, og indprenter tydeligt en lille orden på bordet."},"ICON-0822":{"nm":"Bordmåttehjørnebeslag","de":"Et stykke der blidt trykker ned og glatter en måttes løftede hjørne. Bordet lærer hver dag, at først når den ene ende holdes fast, ligger det hele lige. Selv et hjørne bærer sin del af ansvaret."},"ICON-0823":{"nm":"Lille krydderibakke","de":"En lille bakke der holder en skål sojasovs og en knivspids salt side om side. Bordets rummelige favn, der giver selv et tilbehør sin egen plads. Koreansk mad uddybes i det hjerte, der passer på de små ekstra ting."},"ICON-0824":{"nm":"Bordnummerbrik","de":"Tallet der bliver råbt op som 'bord så-og-så!' på en travl restaurant. Det tildeler ventetiden en rækkefølge og bevarer retfærdighed for alle. Hvad denne ene brik bærer, er et lille løfte og en varm skål, der snart kommer."},"ICON-0825":{"nm":"Vandglasmærkebånd","de":"Et bånd viklet om et vandglas, der stille fortæller, hvis det er. Et lille flag der markerer din plads blandt ens glas. Ved et fælles bord holder sådan en omtanke unødige forvekslinger på afstand."},"ICON-0826":{"nm":"Anretningstallerken-sorteringsnål","de":"En nål der sorterer de anretningstallerkener, man tager mad på, efter farve. Den trækker venligt en grænse mellem dit og mit og gør glæden ved at dele endnu renere. Del varmen, men hold hygiejnen i orden."},"ICON-0827":{"nm":"Menukortskærm","de":"Tiden brugt på at overveje, gemt bag et åbent menukort. Selv den korte tøven over, hvad man skal spise, er i virkeligheden en del af måltidet. Hvad skal det være i dag - den skærmer stille om den lille spænding."},"ICON-0828":{"nm":"Bordkortholder","de":"Et lille stativ, der holder et navneskilt oprejst. Uanset om det er til et arrangement eller en fest, kundgør det tydeligt, at her er din plads. Gæstfrihed fuldendes først i det øjeblik, et navn bliver kaldt."},"ICON-0829":{"nm":"Muffinmanchet","de":"En papirfrakke der tæt omslutter en nybagt muffins buttede midje. Den holder den varme krop, så den ikke glider ud af hånden, og bevarer varmen trofast helt til det øjeblik, man tager den første bid. Selv dessert har brug for en frakke."},"ICON-0830":{"nm":"Sprøjteposehætte","de":"En prop der holder spidsen af en flødesprøjtepose tæt lukket. Den forsegler munden fast, så ikke en dråbe siver ud, mens den hviler. Den lille blomst øverst på en kage blomstrer ud af netop denne tilbageholdenhed."},"ICON-0831":{"nm":"Kageudstikkersæt","de":"Et rundt sæt forme, der skærer dej ud i stjerner og bjørne. Det samme mel vågner til dusinvis af udtryk gennem fingerspidser. Uanset hvad man bager, er det altid hengivenhed, der først rører dejen."},"ICON-0832":{"nm":"Dejskrabervedhæng","de":"En flad hånd der sparsommeligt samler dejen sammen og deler den rent. Den flid, der også passer på håndfulden, der sidder fast i skålen, afgør et brøds volumen. Bagning er en sparsommelig hånds arbejde."},"ICON-0833":{"nm":"Måleskeholder","de":"Et bræt der lægger måleskeer pænt på række, uden at vippe - en lille teske, en halv spiseske. Én præcis skefuld sætter smagens balance lige. Bag udtrykket 'en sikker hånd' gemmer sig i virkeligheden en omhyggelig afmåling."},"ICON-0834":{"nm":"Ovnhandskekrog","de":"En krog til at hænge den ovnhandske op, der stod vagt foran en varm ovn. Den tykke hånd, der afværgede forbrændinger, forbliver også i hvile inden for rækkevidde. Sikkerhed begynder altid med det, der bliver på sin faste plads."},"ICON-0835":{"nm":"Afkølingsristklemme","de":"En tang der pænt bider fast om risten, hvor nybagte sager køler af. Den holder dem, så de ikke flytter sig, mens dampen slipper ud, og venter sammen med dem på, at sprødheden bliver fuldendt. Selv afkøling kræver en håndfuld tålmodighed."},"ICON-0836":{"nm":"Kagetopperpind","de":"En pind der lader de fem bogstaver 'Tillykke' trone øverst på en kage. Lige før lysene slukkes, oplyser dette lille flag en persons dag allermest. Fejring ses bedst, når den rejses højt."},"ICON-0837":{"nm":"Flormelis-strødåse","de":"En dåse der rummer et sidste let dryp. Det lægger sig som hvid sne over en nybagt dessert og gør en almindelig skive til en lille gave. Det sidste strøg kommer fra den letteste hånd."},"ICON-0838":{"nm":"Trekantet gimbap-etiket","de":"Pil folien af i rækkefølgen 1, 2, 3, og laveren vender sprødt tilbage på trekanten. En enkelt linje, der lader dig genkende en trofast ven fra døgnkiosken ved daggry med et enkelt blik. De sultne nætter efter sen lektielæsning klæber lige her."},"ICON-0839":{"nm":"Nudelbægerlågholder","de":"En støtte der stille trykker ned, så låget ikke løftes under de 3 minutters ventetid. Den tager pladsen for de spisepinde, man engang lagde ovenpå for at holde på dampen. Det korte øjeblik, mens nudlerne trækker, er nataftensmadens mest spændende stund."},"ICON-0840":{"nm":"Spydpindehætte","de":"En lille hætte der griber fast om enden af et spyd. Den værner om, at det er let at bide i, uden en dråbe sovs på hånden. Glæden ved snacks foran en bunsik-bod fuldendes altid af den slags små ting."},"ICON-0841":{"nm":"Plastikposehåndtag","de":"Hægt det på fingrene, og plastikken knirker svagt. Vægten af indkøbene hælder til den ene side, og turen hjem efterlader et rødt mærke i håndfladen. I den lette lyd hænger og svajer en hel dags husholdning, tung."},"ICON-0842":{"nm":"Kvitteringsklemme","de":"Fold en langt udrullet kvittering på midten og klik den fast, og dagens forbrug bliver en pæn lille bundt. Mens det blækduftende papir stables lag på lag, falder også husholdningens små minder i pæn orden."},"ICON-0843":{"nm":"Mikrobølgemærke","de":"Før pling-lyden lyder, tæller mærket stille tiden, der skal opvarmes. En lille vejledning der noterer, hvor mange minutter og sekunder, og navnet på det, der skal varmes. Selv hjertet, der venter sin tur til at blive varmt, har den slags mærker."},"ICON-0844":{"nm":"Rabatmærkerulle","de":"Hver gang man river et felt af, kilder en klistret lille knirken fingerspidserne. Når de røde tal ruller ud på række, bliver nogens indkøbskurv lidt lettere. En rulle med lidt venlighed, sammenrullet og ventende."},"ICON-0845":{"nm":"Sovseposering","de":"Noget syrligt springer i mundvigen, og en almindelig dag bliver en anelse sødere. Når posen, der hænger fra en rund ring, svajer for hvert skridt, følger en lille sødme mig hele dagen i lommen."},"ICON-0846":{"nm":"Kioskkurvbrik","de":"Grib fat, og plastikken bøjer let. En butik oplyst sent om aftenen, dyb nok til at rumme et par trekantede gimbap og en drik. Et venligt kar med plads til netop ét måltid, hvor man ikke er ensom, selv alene."},"ICON-0847":{"nm":"Makronæskebånd","de":"Et enkelt bånd omfavner stille æsken, så de farverige makroner ikke rykker sig. Enhver, der har modtaget en gave, ved med fingerspidserne, at spændingen lige før sløjfen løsnes, i grunden er det sødeste."},"ICON-0848":{"nm":"Frugtnetklemme","de":"Saml nettets åbning og klem den til, og duften af æbler siver blidt gennem masken. En lille hånd der holder dem, så de ikke triller ud. En stemmeløs, øm opfordring til at spise dem snart, før de bliver bløde."},"ICON-0849":{"nm":"Syltetøjslågsklud","de":"Det bringer mormors sommerkøkken i tanke, hvor hun dækkede glaslåg med en rund klud og bandt dem fast med et gummibånd. Et enkelt ternet stykke stof forsegler den søde tid og hengivenhed, mens syltetøjet modner. En sikker hånd gemmes sådan, tildækket."},"ICON-0850":{"nm":"Kageposesnørebånd","de":"Læg nybagte kager i cellofan og sno lukkebåndet til, og duften af smør trænger helt ud til sløjfens ender. Hånden der rækker noget hjemmelavet til en anden, ryster altid en anelse. En knude der binder hjertet med."},"ICON-0851":{"nm":"Chokoladeskillevæg","de":"Felt for felt tildeler den en plads, så chokoladerne ikke rører hinanden. Så de ikke smelter, så de ikke knuses. Det, en lille skillevæg vogter helt til det sidste, er i sidste ende ét helt stykke hjerte, der skal gives videre til nogen."},"ICON-0852":{"nm":"Tegave-etiket","de":"Øverst på etiketten viklet om tebrevet står et navn, skrevet tydeligt i hånden. Det lille stykke papir hvisker i forvejen, at brygningen bringer duften af græs op sammen med dampen. En kop der varmer hænderne, endnu før man drikker."},"ICON-0853":{"nm":"Slikflaskehalskæde","de":"En halskæde lavet ved at vikle en snor om halsen på en flaske fuld af farvestrålende slik. For hvert skridt triller en lyd som små perler indeni. En stolt skat fra barndommen, hvor sødme blev båret om halsen."},"ICON-0854":{"nm":"Gaveskevedhæng","de":"Med et lille vedhæng hængende for enden af skaftet bliver en almindelig ske pludselig til en gave. En let, klar klirren for hver skefuld. En lille pynt der tilføjer et strejf af finesse til det hjerte, man giver."},"ICON-0855":{"nm":"Takkemærke til snack","de":"Ønsket om at give lidt tilbage for det, man har fået. Et takkemærke hængt blidt på en snackpose. I stedet for det 'tak' man ikke helt nåede at sige, glider en lille hilsen stille fra hånd til hånd."},"ICON-0856":{"nm":"Washitape-prøvering","de":"Mønstre klippet af og sat fast, et håndsbred ad gangen, står på række i en lille strimmel. Mens man langsomt vælger, hvilken farve man kan lide, med fingerspidserne, farver selve tanken om at pynte dagen i mange nuancer. En prøverække, hvor selv at overveje er en glæde."},"ICON-0857":{"nm":"Pincethætte til klistermærker","de":"Sæt en hætte på pincettens spidse ende, og selv et neglestort klistermærke tager ingen skade. En præcis hånd der blidt løfter hjørner, fingrene aldrig kunne nå. At håndtere det, man holder af, følges altid af en smule varsomhed."},"ICON-0858":{"nm":"Dagbogshjørneforsegling","de":"Sæt segl på dagbogens fire hjørner, og de flagrende sider falder til ro som ved et trylleslag. Fornemmelsen af papir presset blidt sammen, en lille ritual der pænt forsegler dagen i dag. Optegnelser bliver stærke, begyndende fra hjørnerne."},"ICON-0859":{"nm":"Hulleguideplade","de":"En plade der på forhånd viser, hvor der skal hulles. Følg prikkelinjen stille, og der bliver ingen skævhed. Hjertet der tager sig tid til at sigte en ekstra gang uden at haste - præcision kommer altid stille fra den ene lille pause."},"ICON-0860":{"nm":"Papiraffaldsbakke","de":"Papirsmuler tilbage fra saksearbejdet samler sig lydløst i bakken. Et kort tilholdssted for de små stumper, så skrivebordet ikke bliver rodet. Håndarbejdets efterslæb ryddes op på, netop sådan, uden en lyd."},"ICON-0861":{"nm":"Farvet stempelpude","de":"Tryk let på puden og løft, og farven breder sig fugtigt på fingerspidserne. Rød, gul, blå - en lille regnbue der følger med et enkelt stempelaftryk. Et blødt lille sted til at plante farve, prik for prik, på hvidt papir."},"ICON-0862":{"nm":"Dekorationstaperulle","de":"Mønstret der ruller ud, rundt og rundt, fortsætter uden ende. Riv et stykke af og sæt det fast, og blomster springer ud på et før så jævnt sted. En rulle med lidt magi, sammenrullet og ventende, der bliver smukkere, jo mere hånden bevæger sig."},"ICON-0863":{"nm":"Temastempelhætte","de":"En lille hat der tæt omslutter stempelhovedet, så blækket ikke tørrer ud. Den holder stille vagt, så det næste aftryk forbliver skarpt. En farve, der er godt opbevaret, blomstrer lige så levende på det næste ark papir."},"ICON-0864":{"nm":"Dekorhullemaskine-affald","de":"De små stykker, hulmaskinen slipper med et lille klik. Konfetti af farvet papir, klippet ud som stjerner og hjerter og kronblade, samler sig i en blød bunke i håndfladen. Små juveler for smukke til at kassere, så man ender med at klistre dem fast et sted igen."},"ICON-0865":{"nm":"Trådspolemærkering","de":"En lille etiket med navnet på hver farvede tråd skrevet på hver spole. Et ømt mærke der peger på dens plads, før den bliver viklet ind i hinanden. Sammenfiltret tråd, og hjertet med, bliver langt lettere at rede ud med bare ét navneskilt."},"ICON-0866":{"nm":"Nålebogsomslag","de":"Et blødt omslag til den filtsidede bog, hvor nåle sidder tæt sammen. Slå den op, og syredskaberne ligger pænt på række og byder mig velkommen. Et lille bind der ømt lægger de spidse ting til hvile, så fingerspidserne ikke kommer til skade."},"ICON-0867":{"nm":"Stofprøvering","de":"Grov eller blød - den langsomme tid hvor man med fingerspidserne, en efter en, føler stoffets struktur for at vælge. Blandt de stofstykker, der er samlet pænt efter farve, venter stoffet stille på at blive rørt først, før det bliver til et klædningsstykke."},"ICON-0868":{"nm":"Broderiringlås","de":"Sæt stoffet i den runde ring og stram til, og det bliver spændt som et trommeskind. Et lille signal om, at man er klar til at brodere sting for sting. Det, ringen holder fast, er ikke stoffet, men det koncentrerede hjerte."},"ICON-0869":{"nm":"Knapsorteringskapsel","de":"Knapper der plejede at trille rundt, sætter sig nu pænt til rette efter farve i hvert kapselrum. Husholdningens visdom med at dele dem op i små portioner, så ingen bliver væk. Selv at samle spredte ting kræver denne mængde hengivenhed."},"ICON-0870":{"nm":"Skrædderkridtholder","de":"En holder der griber komfortabelt om skrædderkridt, den slags der tegner linjer på stof. Den støtter fast noget, der let knækker. Den rolige første beslutsomhed før saksen tages op - at den første linje skal være lige, for at klædningsstykket også bliver det."},"ICON-0871":{"nm":"Knappenålsglas","de":"Inde i det klare glas klirrer og rasler synålene mod hinanden. Hold det op mod lyset, og et lille glimt samler sig på hver nåls spids. Et sikkert lille kar der samler på ét sted, og lægger blidt til hvile, det, som er farligt, når det er spredt."},"ICON-0872":{"nm":"Lappebåndsrulle","de":"En magisk strimmel der stille klæber fast, når man stryger den over et rift. Uden et eneste sting heler et slidt klædningsstykke stille. Hjertet der lappede og blev ved med at bære frem for at smide væk, ligger sammenrullet, lag på lag, inde i den runde rulle."},"ICON-0873":{"nm":"Patchskabelonpapir","de":"Et ark skabelonpapir med patch-formen tegnet på forhånd. En prikket linje viser venligt saksen den vej, den skal gå. At tegne omridset af det, man ønsker at lave, først - spændingen begynder altid fra denne svage underskitse."},"ICON-0874":{"nm":"Vandfarveglaskopshætte","de":"Sæt den på glassets åbning, og ikke en dråbe spildes, uanset hvor meget det farvede vand skvulper. Den dækker selv bekymringen om, at det uklare skyllevand skulle brede sig ud over skrivebordet. En stille prop der tavst vogter det sted, hvor man maler."},"ICON-0875":{"nm":"Pastelbeskyttelsesbånd","de":"Vikl et bånd om en pastelstift, der efterlader et hvidligt pulverspor, og fingrene bliver mindre snavsede. Papir der blidt omslutter den bløde farve, så den ikke smuldrer. Jo blødere den er, jo mere ømt må man holde den, for at den også farver blidt på papiret."},"ICON-0876":{"nm":"Farveblyantforlængerhætte","de":"Sæt en hætte på enden af en nedslidt farveblyant, og en stump bliver lang igen. Hjertet der ikke let smider noget væk, bare fordi det er blevet kort. Fra fingerspidser der bruger den helt til enden, fuldendes tegningens farve dybere helt ned til det sidste felt."},"ICON-0877":{"nm":"Penselskyllekopskrog","de":"Hæng skyllekoppen på en krog, og vanddråberne, der er faldet fra penslen, siver ned. Før man maler næste farve, den korte, klare stilhed ved at skylle penslen. Selv i den lyd af noget, der bliver rent, flyder en stille rytme."},"ICON-0878":{"nm":"Paletknivshætte","de":"En lille hætte der tæt dækker bladet på kniven, der breder og skraber maling ud. Den holder stille vagt, så den skarpe spids ikke bliver sløv. Teksturen af tykt påført farve fødes af netop dette ene velplejede æg."},"ICON-0879":{"nm":"Lærredsklemme","de":"En solid klemme der trækker lærredsstoffet stramt over rammen og holder det fast. Bid hårdt til, og maleoverfladen strækkes tromleglat. Kun med en grund, der ikke vakler, kan penselstrøgene, der løber hen over den, blive helt frie."},"ICON-0880":{"nm":"Tegnebrætrem","de":"Sving remmen over skulderen, og brættet følger med på ryggen. Slå sig ned hvor som helst, og det bliver ens helt eget atelier. Et lille atelier båret på ryggen, der let drager ud på jagt efter et motiv at tegne."},"ICON-0881":{"nm":"Akrylmalingtube","de":"Tilføj en dråbe vand mere, og det bliver daggry; en mindre, og det bliver midnat. Den samme blå åbner en ny himmel hver gang ved fingerspidserne. I det øjeblik man klemmer en tube ud, breder dagens sindsfarve sig ud over papiret."},"ICON-0882":{"nm":"Farveovergangsprøveark","de":"At en solnedgang ikke bliver rød på én gang, det vidste dette papir først. Små trin der krydser fra det lyse til det dybe. Øjet vandrer langsomt imellem dem og følger stille den tid, hvor farven modnes."},"ICON-0883":{"nm":"Hæklenålshætte","de":"Et fingerbøl-lille skjold, man sætter på, før garnet graver sig ind i fingeren. En hånd der længe har øvet sig i strikning, ved det. Kun ved at forblive uskadt kan man føre det ømt helt til den sidste maske."},"ICON-0884":{"nm":"Strikkemarkørring","de":"Ét mærke, og hvor langt man er nået, bliver klart igen. Trygheden ved aldrig at skulle tælle den samme maske to gange. Hjertet, ligeledes, mister først ikke vejen, når man blidt markerer stedet, man er kommet fra."},"ICON-0885":{"nm":"Rækketællervedhæng","de":"Et stille bevis på en færdig omgang hober sig op, felt for felt. Selv arbejde, der virkede uendeligt, er, når det tælles én ad gangen, pludselig forbi det halve. Et lille regnskab bærer dagens hjerte helt til enden."},"ICON-0886":{"nm":"Trådendeordensnål","de":"Lad en løs trådende ligge, og der er ingen, der ved, hvor den næste knude vil filtre sig sammen. En berøring der på forhånd ordner et sted, ingen vil se. Ømhed rører sig oftest, netop sådan, først på steder, der ikke er synlige."},"ICON-0887":{"nm":"Knudeøvelsessnor","de":"En overhåndsknude, en sløjfeknude, en ringknude. Man binder og løsner den samme snor, indtil hånden husker formen udenad. Når klodsede fingerspidser en nat pludselig bliver smidige, er den ene snor den første til at vide det."},"ICON-0888":{"nm":"Garnetiketbånd","de":"En lille strimmel der noterer tykkelse og farve på hvert garnnøgle. Det er en vane født af nætter brugt forgæves på at lede efter samme garn, først efter det slap op. En optegnelse er en øm besked til ens fremtidige jeg."},"ICON-0889":{"nm":"Maskemåler","de":"Hvor mange masker der går på 10 centimeter - det lille tal fastsætter størrelsen på et helt klædningsstykke. At et håndfladestort stykke rummer målene for det hele er, når man løfter det, en ganske tung ting."},"ICON-0890":{"nm":"Knaphulsmarkør","de":"Før man syr en knap på, sætter man først en enkelt prik, hvor hullet skal laves. Takket være det snart forsvindende mærke bliver kanten ikke skæv. Hengivenhed forbliver oftest stille på et sted, der aldrig bliver set."},"ICON-0891":{"nm":"Lille kvastløkke","de":"Som kvasten for enden af en norigae skaber en lille løkke svaj. Øjet dvæler altid ved det, der hænger og stille bølger. En struktur der blidt vågner til live, hver gang vinden passerer forbi."},"ICON-0892":{"nm":"Mini malingsflaske","de":"Det handler ikke om at spare, men om at bruge malingen præcist - det er den rette måde at håndtere den på. En farve hvor én dråbe er nok, afmålt med en hånd holdt ved siden af den lille flaske. Mådehold kommer af at lægge begæret fra sig, bare denne ene gang."},"ICON-0893":{"nm":"Lille sandpapirsstift","de":"Man begynder på den grove side og bevæger sig gradvist mod den fine. Der findes ingen overflade nogen steder, der bliver glat med ét strøg. Fra fingerspidser der sænker kornet et trin ad gangen, bliver et engang ru sted langsomt blødt."},"ICON-0894":{"nm":"Modelklemmestativ","de":"Hold en limet del i hånden, og der sidder fingeraftryk tilbage. Klem den blidt fast i en klemme, og hænderne bliver fri, mens tørringen stille fuldføres af sig selv. Selv ventetid bliver lettere, når nogen støtter den for en."},"ICON-0895":{"nm":"Limunderlag","de":"Lad en dråbe lim falde på skrivebordet, og sporet bliver siddende længe. Vanen med at lægge en enkelt plade under først. Halvdelen af arbejdet begynder måske netop af det ønske om ikke at tilsvine stedet."},"ICON-0896":{"nm":"Delesorteringsbakke","de":"Bland dusinvis af ens formede dele sammen, og samlingen bliver hurtigt et labyrint. Berøringen, der deler dem op i hvert rum, forkorter på forhånd den tid, man ellers ville have brugt på at fare vild. At rydde op er en venlighed rakt til ens fremtidige jeg."},"ICON-0897":{"nm":"Samlerækkefølgechip","de":"En lille chip der noterer, hvilken nummereret del der skal sættes i først. Følg rækkefølgen, og det falder ikke let fra hinanden. En model, og enhver dag bygget op skridt for forsigtigt skridt, bliver solid på netop det stille løfte."},"ICON-0898":{"nm":"Mini penselkrog","de":"Læg en brugt pensel ned, og hårene bliver presset og bøjet. Et sted at hænge den på hovedet for at dræne fugten af. De, der holder deres redskaber tæt på sig gennem lang tid, er, om noget, travlere og mere ømme, efter arbejdet er slut."},"ICON-0899":{"nm":"Modelsprue-affaldskrukke","de":"En krukke hvor afklip fra rammen stille samles. De virker kasserede, men bliver en dag til en lille detalje igen. At selv resterne har deres tur, ved krukken, tavst ventende."},"ICON-0900":{"nm":"Finish-sprayhætte","de":"Det sidste lag, sprayet for tæt på, løber bare lige ned. Fra en armslængdes afstand, let, let. At påføre glans er måske også en øvelse i at lægge hjertets begær fra sig, bare denne ene gang."},"ICON-0901":{"nm":"Blyantmine-etui","de":"Den tynde blyantmine knækker alt for let i lommen. Lagt sirligt til hvile i et lille rør går ikke én eneste stift til spilde. At holde orden er, når alt kommer til alt, et stille hjertelag, der på forhånd passer på morgendagens mig."},"ICON-0902":{"nm":"Viskelæderhylster","de":"En lille papirkjole, som viskelæderet er iført. Jo sortere den bliver af fingeraftryk, desto flere spor af rettelser har den samlet. At viske ud er også en øm tilladelse til, at det er helt i orden at vende tilbage til begyndelsen."},"ICON-0903":{"nm":"Pennespidsrør","de":"En pennespids revner, når den tørrer ud, og bøjer, hvis den støder mod noget. Et lille rør, hvor den kan hvile for sig selv, bevarer skriftens fine tekstur i lang tid. Et redskab, der behandles nænsomt, glider til sidst nænsomt tilbage som tak."},"ICON-0904":{"nm":"Fyldepenneblæk-prøve","de":"Blæk, man prøver dråbe for dråbe. En farve, man troede var petroleumsblå, bliver til et dybt hav på papiret. Farve er altid noget, man må møde i virkeligheden — den farve, man forestiller sig i tankerne, rammer så tit forbi."},"ICON-0905":{"nm":"Bogmærkenåle-dåse","de":"Et lille flag, man forsigtigt stikker ind der, hvor man holdt op med at læse. Næste gang bogen slås op, står gårsdagens jeg og vinker og venter. Selv det sted, man standsede ved, bliver et løfte — sådan er dette lille mærkes ømme gerning."},"ICON-0906":{"nm":"Notesflag-pakke","de":"River man ét blad løs og sætter det fast, begynder historien igen præcis dér. Når de små flag stiller op på siden af bogen, samles spredte tanker lag for lag til ét eneste kort."},"ICON-0907":{"nm":"Clips-samlemagnet","de":"En lille magnet, der samler spredte clips ind i én omgang. Jo mindre en ting er, desto lettere mistes den, så én samlende kraft redder stille et rodet skrivebord. Selv i tiltrækning findes der ømhed."},"ICON-0908":{"nm":"Blyanthætter-sæt","de":"Små hatte, der omslutter blyantspidsen og passer på tasken indeni. Alt spidst har det med at stikke noget, så der er brug for en hånd, der stille dækker det til. Så det ikke sløves, men heller ikke gør skade."},"ICON-0909":{"nm":"Navneskilt-klistermærke til skrivebordet","de":"I det øjeblik man skriver sit navn og sætter det på skrivebordet, bliver pladsen endelig én persons egen. Så snart selv en håndsbred plads får en ejer, ændrer selve holdningen, hvormed man sætter sit hjerte der, sig helt."},"ICON-0910":{"nm":"Håndtagshætte til sjippetov","de":"En hætte, man sætter på, før håndtagets ende slides og flækker. Rytmen fra et reb, der er svunget over tusind gange, husker håndfladen før hovedet. Et tempo, der er indprentet i kroppen, glemmes ikke let."},"ICON-0911":{"nm":"Yogaring-strop","de":"Man tager fat i ringen og åbner langsomt kroppen. Jo mere stroppen strammes, desto mere løsner de stive skuldre sig, lag for lag. At strække handler mindre om at trække med magt og mere om stille at vente, til kroppen åbner sig af sig selv."},"ICON-0912":{"nm":"Bordtennisbold-etui","de":"En hvid bold, så let at den ruller langt væk og bukker sammen i samme øjeblik, man træder på den. Ét lille etui beskytter den skrøbeligste bold indtil næste kamp. Styrke kommer ofte af at blive omsluttet blidt."},"ICON-0913":{"nm":"Badmintongreb-tape","de":"Et lag, der nænsomt vikles om et håndtag, som svedten gør glat. På et velviklet greb bliver ketsjeren en del af hånden selv. Hemmeligheden bag at slå med fornemmelse frem for kraft gemmer sig i dette tynde ene lag."},"ICON-0914":{"nm":"Lille pointbrik","de":"Et point, så endnu et. Man flytter de små brikker og bygger pointene op, lag for lag. Når regnestykket bliver synligt, bliver kampen tydeligere, og modet til at indhente den ene points forskel spirer stille frem."},"ICON-0915":{"nm":"Skoretnings-clips","de":"Pænt anbragte skotæer vender altid samme vej. En hånd, der drejer dem let til rette, hver gang skoene tages af. Én lille smule orden gør morgendagens skridt så meget lettere."},"ICON-0916":{"nm":"Fløjtesnor","de":"Hænger man en fløjte om halsen, får man retten til at sige stop. Synet af hele banen, der standser samlet ved ét kort stød. De hjerter, der tror på den lille lyd, samles og bliver til et løfte."},"ICON-0917":{"nm":"Boldpumpenål-etui","de":"Selv en flad bold bliver spændt igen med blot én tynd nål. Den nål, der ligger sirligt gemt i et lille rør, gør hele pumpen ubrugelig, i samme øjeblik den mistes. Når det allermindste betyder allermest."},"ICON-0918":{"nm":"Minikegle-markør","de":"Herfra til derhen — en lille kegle tegner en grænse, man ellers ikke kunne se. Uden en eneste streg stiller folk sig naturligt på række efter mærket. Orden gror stille frem af den slags små signaler."},"ICON-0919":{"nm":"Tokenpose","de":"En pose, der samler de klirrende tokens ét sted. Strammer man snoren til, spredes intet. At selv de mindste og mest ubetydelige ting først gør deres nytte, når de har et sted at ligge, viser posen uden et ord."},"ICON-0920":{"nm":"Kortblandemåtte","de":"På et glat bord vil kortene ikke rigtig blive siddende i hånden. Én måtte gør både blanding og optagning langt mere smidig. Selv i at lege godt findes der en øm forberedelse: først at jævne underlaget."},"ICON-0921":{"nm":"Hjørnebeskytter til spilleplade","de":"Når en spilleaften er forbi, tager en eller anden uden et ord først vare på spillepladens fire hjørner. For man ved, at en dyb fold gør næste omgang skæv. I fingerspidserne, der glatter kanterne ud, ligger ønsket om at lege sammen igen i morgen."},"ICON-0922":{"nm":"Terningebæger-låg","de":"Det korte øjeblik, hvor alle ryster, ruller og holder vejret sammen. Det er et lille loft, der forhindrer terningerne i at springe ud. Inde under låget trækker dagens held vejret et øjeblik, før det klaprer sig ud."},"ICON-0923":{"nm":"Spillebrik-opretter","de":"Jo mere opstemt nogen bliver af spillets fornemmelse, desto skævere bliver rækken. At skubbe brikkerne let på plads, når de hælder. At rette op er en hånd, der ømt tager imod nogens opstemte utålmodighed."},"ICON-0924":{"nm":"Pointbrikke-dåse","de":"Jo mere en dåse fyldes med brikker, desto varmere bliver spillet også. Når de runde point klaprer mod hinanden i håndfladen, glæder man sig over lyden, før man overhovedet tænker på sejr eller nederlag."},"ICON-0925":{"nm":"Turmarkør-ring","de":"En lille ring, der fortæller: nu er det din tur. I det øjeblik, man flytter den ét felt frem, samles alles blikke stille om mig. En ring, der drejer langsomt mellem venten og forventning."},"ICON-0926":{"nm":"Spillebrikstander","de":"Jo lettere en brik vælter, desto mere fast skal dens fodfæste være. Én stander holder den på plads, selv på en let vaklende plade. Det lille skal holde stand, for at det store ovenpå kan stå rank."},"ICON-0927":{"nm":"Regelbog-clips","de":"En regelbog, der ligger opslået, bladrer altid stille videre af sig selv. En klemme, der stille bider fast i én side, før vinden får bladet til at flygte. Reglerne skal holdes fast, for at legen kan følge helt til enden."},"ICON-0928":{"nm":"Plekterum-snor","de":"En guitarplekter smutter altid ud af fingrene lige i det mest opstemte parti. Én snor hængt fast til etuiet stopper den lille udebliven. Kun den, der har oplevet en aften, hvor musikken gik i stå, sætter pris på denne snor."},"ICON-0929":{"nm":"Rørblad-etui","de":"Et rørblad mister sin klang, i samme øjeblik det tørrer ud. Inde i det fugtige rør venter en tynd flig af siv på næste spil. Et sted, hvor man lægger vejret til hvile, før man puster vejret ind i det igen."},"ICON-0930":{"nm":"Strengevinder","de":"Slækker strengen, synker tonen stille med. At dreje håndtaget langsomt for at genvinde spændingen — omhu kommer altid fra håndleddets yderste led. En ren klang begynder på denne måde, i den mindste smule orden."},"ICON-0931":{"nm":"Instrumentklud","de":"Når spillet er slut, ligger der en let sved tilbage på instrumentet også. Ét strøg med en blød klud bringer glansen tilbage og lader dagens toner lægge sig roligt til ro. Et hjerte, der holder af noget, viser sig altid i afslutningen."},"ICON-0932":{"nm":"Stemmeskruedæksel","de":"Lades stemmeskruen bar, ruster den før man ved af det. Ét lille dæksel udsætter metallets årstider med et enkelt taktslag. Den, der først tager sig af de usynlige hjørner, spiller længst."},"ICON-0933":{"nm":"Nodestativ-clip-lampe","de":"Bag den mørke scene findes øjeblikke, hvor kun noderne skal lyse. En lille lampe, der klemmes fast på stativet og sender lyset stille nedad. En håndfuld belysning, der lyser vejen, så tonerne ikke farer vild."},"ICON-0934":{"nm":"Øvedæmper-hætte","de":"Morgentidlig øvning ligger altid i stille strid med naboens søvn. Sæt blot en hætte på, og en drønende lyd svinder ind til en hvisken. Der findes også musik, der vokser, mens den vogter over nogens søde søvn."},"ICON-0935":{"nm":"Trommepude-mærkat","de":"Små mærker klistret på trommepuden. Hvor man skal ramme for hvilken lyd — øjet lærer vejen, før hånden husker den udenad. Sådan indprentes takten langsomt i kroppen."},"ICON-0936":{"nm":"Melodi-notebrik","de":"En melodi, man nynner på, forsvinder hurtigt, hvis man ikke griber den. Nogle takter, hastigt noteret på en brik, vokser somme tider siden til en hel sang. Inspirationen vender altid tilbage til den hånd, der flittigt skriver ned."},"ICON-0937":{"nm":"Bogomslag-bånd","de":"Det er en plage, når en halvlæst bog folder sig ud af sig selv i tasken. Ét bånd binder siderne stille sammen, så de holder sig i ro. Et løfte om at folde tingene pænt sammen til det næste kapitel."},"ICON-0938":{"nm":"Sideholder-ring","de":"En dag, hvor man vil holde bogen opslået med den ene hånd og drikke varm kaffe med den anden. En ring, man sætter på fingeren, holder siderne i ens sted. En lille smule ro begynder med den slags små opfindelser."},"ICON-0939":{"nm":"Læsetimer-brik","de":"Man siger bare ét kapitel og sætter sig, og pludselig er natten dybt inde. Trykker man på brikken og sætter tiden, får selv læsningen et komma. Jo mere man elsker noget, desto mere har man brug for det ømme mod til at kunne stoppe."},"ICON-0940":{"nm":"Boghjørne-beskytter","de":"Jo mere man holder af en bog, desto mere slides dens hjørner umærkeligt først. Sætter man en hætte på, beskyttes omslagets hjørner rundt og helt. Det er en lille rustning, man stille lirker på plads, for et ønske om at have noget ved sin side i lang, lang tid."},"ICON-0941":{"nm":"Læsenote-bånd","de":"Der er øjeblikke, hvor én linje pludselig sætter sig tungt i brystet. Et indtryk, overført til et bånd, bliver liggende på siden som et bogmærke. Understregningens varme temperatur, kendt kun af den, der har læst."},"ICON-0942":{"nm":"Biblioteksafleveringsmærke","de":"Afleveringsdatoen kommer altid en dag for tidligt. Når datoen på mærket stille skubber en i ryggen, får selv den lånte bog en afskeds høflighed. For den næstes hænders skyld venter biblioteket sådan."},"ICON-0943":{"nm":"Boglampe-clips","de":"En nat, hvor man alene ligger vågen og læser ved siden af sovende familie. Ét lille lys, klemt fast på bogens kant, er nok. Man behøver ikke skubbe hele mørket væk — én side er nok til en stille stund."},"ICON-0944":{"nm":"Bogduft-kort","de":"Gamle bøger dufter af sollys og papir, blandet sammen. Et kort, der siges at rumme netop den duft i ét ark — slår man det op, vækkes en boghandelsgyde et kort øjeblik til live for næsen. Erindringen sætter også bogmærker med duft."},"ICON-0945":{"nm":"Læsemærke-nål","de":"Hvor langt var jeg nået? En lille nål, der visker det rådvilde spørgsmål ud. Sætter man den i den sidste sætning, farer morgendagens jeg ikke længere vild. Et ømt mærke, der husker det standsede sted i ens sted."},"ICON-0946":{"nm":"Telefonstrop-charm","de":"Med blot ét vedhæng på telefonremmen ser en person en smule anderledes ud. En yndlingsfarve, en yndlingsform. En lille smag, man holder i hånden, gynger dagens humør stille til."},"ICON-0947":{"nm":"Kameralinsehætte","de":"Rejsefotografiets skæbne hviler på én eneste linse. I det øjeblik man tager beskyttelseshætten af, er hjertet allerede klar til at trykke på udløseren. Et lille ritual, der åbner sit øje først af alt, før landskabet indfanges."},"ICON-0948":{"nm":"Opladerstik-prop","de":"Støv i tasken går altid efter opladerhullet først. Med blot én prop, der lukker den lille åbning, holder stikket sig rent i lang tid. Her findes en flid, der tager sig selv af de usynlige sprækker."},"ICON-0949":{"nm":"Telefonholder-popring","de":"At stille telefonen skråt op, blot for at se en video i ro. Folder man popringen bag på ud, får både hånd og skærm mere luft. Én lille rejst støtte strækker en aftenstund ud i mag."},"ICON-0950":{"nm":"Skærmtørreklud-patch","de":"En skærm fuld af fingeraftryk gør på en eller anden måde selv hjertet lidt sløret. Tørrer man den af med en patch, bliver verden skarp igen. Renlighed er somme tider blot ét kort strøg med en finger."},"ICON-0951":{"nm":"SIM-nål-etui","de":"SIM-nålen er et væsen, der kun forsvinder sporløst i det øjeblik, man virkelig har brug for den. Ligger den i ét rum i et etui, behøver man ikke længere lede hele huset igennem efter en hårnål. Lidt orden redder stille et presserende øjeblik."},"ICON-0952":{"nm":"Trådløs opladermåtte-mærkat","de":"En nat, hvor telefonen selv lades op, blot man lægger den stille på puden. Et påsat mærkat viser diskret det sted, hvor telefonen skal ligge. En usynlig strøm fylder lydløst en hel dags energi op."},"ICON-0953":{"nm":"Notifikationsdæk-mærkat","de":"Notifikationer, man ikke har lyst til at se, er lettere om hjertet, hvis de dækkes til. Ét mærkat lægger daggryets lille lysglimt til ro. Somme tider er det også en øm måde at passe på sig selv på, ikke at se."},"ICON-0954":{"nm":"Linsebeskyttelsesring","de":"Det splitsekund, hvor kameralinsen rammer gulvet, synker hjertet med et sæt. Én ring, spændt rundt om den, dæmper stille det lille fald. En kant, der først af alt omslutter det øje, der rummer minderne."},"ICON-0955":{"nm":"Kabelmærkat","de":"At omsider finde sit eget kabel frem fra en filtret, sammenviklet bunke. Ét mærke giver endelig opladerledningen sit eget navn. Et lille flag, der viser vej blandt de rodede ledninger."},"ICON-0956":{"nm":"Opladerpung","de":"Opladerne i rejsetasken ligger altid og skændes viklet ind i hinanden. Samler man dem pænt i ét rum i en pung, forsones de omsider. Kunsten at pakke ligger i ømt at kalde det spredte sammen på ét sted."},"ICON-0957":{"nm":"Stikdåse-label","de":"Hullerne i en stikdåse ser alle ens ud og forvirrer hver gang. Sætter man labels på og fastlægger, hvis plads det er, bliver en travl morgen langt lettere. Et lille navneskilt mindsker hverdagens små uenigheder."},"ICON-0958":{"nm":"Ledningsoprullerspole","de":"Rullet ud for at bruges, rullet op igen — ledningens sirlige dag. Rulles den lag for lag op på én spole, forsvinder filtringen fuldstændig. Den hånd, der lægger tingene tilbage på plads efter brug, gør morgendagen lettere."},"ICON-0959":{"nm":"Magnetstik-hætte","de":"Et magnetstik samler fint metalstøv, uden man opdager det. Dækker man det til med en hætte, klæber det klistrede støv sig ikke fast. En genstand, der er rørt af én ekstra omsorgsfuld hånd, holder ved siden af en længere."},"ICON-0960":{"nm":"Powerbank-bånd","de":"Ligger powerbank og kabel adskilt, forsvinder altid det ene af dem. Bindes de sammen med et bånd, bliver de to endelig et par. En lille knude, man stramt binder lige før man går ud, som siger: rejs sammen."},"ICON-0961":{"nm":"Stikkontakt-støvhætte","de":"Et tomt stikkontakthul lader støvet stille slå sig ned efter blot nogle dages tid. Vogter denne lille hætte stedet i dets sted, kan den næste oplader, der sættes i, trække sit første, rene åndedrag. En dørvogter, der sirligt vogter over den tomme tid."},"ICON-0962":{"nm":"Kabelfarvering","de":"En nat, vi famlede efter vores egne blandt sammenfiltrede ledninger, var der en, der sagde: lad os give dem farver. Blå er dig, gul er mig. Med bare én lille ring forveksler vi ikke længere hinanden. Sporet af et ømt løfte, der er blevet tilbage i et hjørne af øvelokalet."},"ICON-0963":{"nm":"Adapter-sorteringsbrik","de":"Runde ben og flade ben, 110 og 220. En brik, der stille har lært sig kontaktens forskellige ansigter fra land til land udenad. I et hjørne af kufferten på vej til den første scene på den anden side af havet lå der altid dette lille sorteringskort gemt."},"ICON-0964":{"nm":"Ørepropbakke","de":"Man siger, at øregangens dybde og bredde er forskellig fra person til person. At lægge stor, mellem og lille ved siden af hinanden og vælge det ene par, der passer præcis til ens eget øre. En øm procedure, hvor kroppen tilpasses først, før man overhovedet lytter til lyden."},"ICON-0965":{"nm":"Silikonering til cover","de":"Scenetøjet passes ned til hver eneste søm, mens covers hjørner altid rammer bart og ubeskyttet. Omslutter denne tynde silikonekant randen blidt, møder skærmen morgenen uskadt, selv en daggry hvor den gled ud af hånden."},"ICON-0966":{"nm":"Støjreducerings-mærkat","de":"Der er dage, hvor man vil slukke for verdens lyde et øjeblik. Dette lille mærkat, klistret på hovedtelefonens øre, er et tegn, der tænder stilheden. Et amulet, der bærer både tilskuernes jubel og metroens larm et stykke bort, blot indtil én sang er slut."},"ICON-0967":{"nm":"Ørekrog-sæt","de":"Danser man, løsner den ene øreprop sig altid først. Hænger man disse kroge på, der blidt omfavner øremuslingen, bliver musikken alene ved i ørerne til det sidste, selv midt i den vildeste koreografi. Det var en lille opdagelse, folkene i øvelokalet delte med hinanden."},"ICON-0968":{"nm":"Rengøringsbørste-hætte","de":"En lille hat, man sætter på, så støvet på børstespidsen ikke hvirvler op igen. At selv et redskab til rengøring har brug for rengøring — det vidste den hånd, der for længst plejede at stille kosten på hovedet efter fejningen."},"ICON-0969":{"nm":"Ladestation-bundpude","de":"At ladestationen blev ved med at glide rundt på skrivebordet, skyldtes, at den ingen fødder havde. Idet denne tynde pude på bunden overtager fødderns rolle, bliver enheden stille stående på sin plads og fylder sig lydløst op med kraft natten igennem."},"ICON-0970":{"nm":"Venstre-højre-markør","de":"Venstre L, højre R. Der sættes én ekstra prik, så man kan mærke forskellen selv famlende i mørket. Ønsket om aldrig én eneste gang at forveksle venstre og højre fod på scenen ligger uforfalsket indprentet i dette lille mærke."},"ICON-0971":{"nm":"Lydfordeler-jackhætte","de":"Det stik, hvorfra flere lyttede til én lydstrøm sammen, skal have sin ende lukket, mens det hviler. Så støvet ikke siver ind i kredsløbet. En lille, forsigtig hånd, der ønsker at lade den sang, man lyttede til sammen, strømme lige så klart næste gang."},"ICON-0972":{"nm":"Øretelefon-kabelopruller","de":"Som den gamle håndbevægelse, der snoede en trådnøgle, bliver øretelefonledningen sirlig, når den vikles rundt her. Det øjeblik, hvor musikken, der lå filtret og rullede rundt i tasken, bringes i orden. Morgendagens udrulning bliver så meget lettere."},"ICON-0973":{"nm":"Linsehætteholder-snor","de":"Hver gang man åbnede linsen, mistede hætten altid sit hjem. Bindes den til en snor og fastgøres ved kameraet, behøver man ikke længere famle forgæves i lommen. At man undgår at miste noget ved at binde det tæt ved sig, lærte hånden først af alle."},"ICON-0974":{"nm":"Hot shoe-dæksel-charm","de":"I den tomme hot shoe-plads oven på kameraet stikker man diskret et lille pynt ind. Netop dét vedhæng, som ikke har nogen funktion overhovedet, får det tunge, kejtede udstyr til, uden man opdager det, at se kært ud som ens eget. Kunsten at knytte sig til et redskab."},"ICON-0975":{"nm":"Stropspænde","de":"Hver gang taskestroppen skærer sig ind i skulderen, løsner og strammer man dette spænde en smule. Én bevægelse med fingrene for at vælge en længde, der passer til ens egen krop. At bære en byrde er også, når alt kommer til alt, en måde at passe på sig selv, fortæller spændet stille."},"ICON-0976":{"nm":"Filterstack-etui","de":"Et lille hjem, hvor glasstykker, der spalter lyset, lægges lag for lag til ro. Diset og klart, solnedgang og nat. Som en skuffe, hvor vejret er valgt og gemt på forhånd, åbner fotografen altid netop dette etui først, før han begiver sig ud på vejen."},"ICON-0977":{"nm":"Blæser-støvhætte","de":"En gummikugle, der puster luft ud for at jage støv væk, har selv en åbning, der er lige så svag over for støv. Mens den hviler, sætter man denne hætte på. Der er noget rørende ved et redskab, der renser andre, stille at lukke sin egen mund til først."},"ICON-0978":{"nm":"Udløserknap-cover","de":"At udløseren trykkes af sig selv i tasken, så der tages hundrede billeder af tom himmel, har alle prøvet mindst én gang. Dette lille cover, sat over knappen, forhindrer det spildte arbejde. En lille lås, der kun vil lade de øjeblikke blive tilbage, man virkelig ønsker at gemme."},"ICON-0979":{"nm":"Batterisorterings-mærkat","de":"Blandes brugte og fulde batterier i én lomme, ender det altid galt. Et farvet mærkat på hvert batteri rydder stille op i den forvirring. Rød er tom, grøn er pålidelig. Et tavst trafiklys, der holdes tændt på et location."},"ICON-0980":{"nm":"Kamerataske-inddeler","de":"Man deler tasken op i rum, så linse, kamerahus og ekstra batteri ikke støder mod hinanden. At sætte flere små værelser ind i én byrde. Hver plads har sin ejer, så intet mister sin plads, selv når det rystes."},"ICON-0981":{"nm":"Fotohandske-pude","de":"Vinteroptagelser udendørs — kun fingerspidsen, der trykker på udløseren, må ikke fryse. En handske med tyk pude i håndfladen og bevaret følesans i fingerspidserne. Feltets ømme kompromis, der forsøger at holde varme og præcision i samme hånd."},"ICON-0982":{"nm":"Tabletpen-spidsetui","de":"At selv en pennespids slides som en blyantmine, ved den, der længe har holdt en tablet i hånden. Dette lille rør, hvor ekstra spidser ligger og ruller samlet, er som fingerspidsens nødopsparing, fyldt op på forhånd til de linjer, der ikke må afbrydes."},"ICON-0983":{"nm":"Keycap-bakke","de":"Den dag man trak hver enkelt keycap af, vaskede dem og satte dem på igen, blev denne bakke til en lille vade. Synet af konsonanter og vokaler, der ligger felt for felt og tørrer af vandet. Der findes også omhu, man først kan se, når man en gang har skilt tingene ad."},"ICON-0984":{"nm":"Musefødder-pakke","de":"Hemmeligheden bag, at musen glider let hen over bordet, ligger i disse små fødder klistret på bunden. Et bundt, man skifter ud, når de er slidt. Sliddet fra de ting, der tavst bærer glatheden oppe fra et usynligt sted."},"ICON-0985":{"nm":"Bærbar-stander-gummi","de":"Den ligner en notesbog, men er i virkeligheden en gummistøtte, der løfter en bærbar. At hæve skærmen let op til øjenhøjde og rette den bøjede nakke ud. En omtanke, der retter kropsholdningen op, for den, der skriver og stirrer længe."},"ICON-0986":{"nm":"Webcam-dækskyder","de":"Man skubber linsen til med fingeren og skubber den åben igen. Ønsket om kun at blive set, når man selv vil vises. I denne ene lille skyder bor den store tryghed, der hedder privatliv. Lyden, når den lukker, virker på en eller anden måde solid og trygt."},"ICON-0987":{"nm":"USB-sorteringslabel","de":"Fem ens sorte pinde, og der er slet ingen måde at vide, hvad der ligger på hvilken. Sætter man et lille label på og giver dem et navn, bliver de først da en del af familien. Man skal have et navn at kalde på, for at det bliver let at finde."},"ICON-0988":{"nm":"Skrivebordsmåtte-hjørner","de":"Ruller skrivebordsmåttens hjørner sig hele tiden op, bliver selv håndskriften skæv. Denne lille del, der stille presser de fire hjørner ned, vogter den flade fred oven på bordet. Underlaget skal være roligt, for at fingerspidsen også kan blive det."},"ICON-0989":{"nm":"Hub-stander-clips","de":"En klemme, der stiller en hub, hvor mange ledninger mødes, skråt op ved skrivebordets kant. Synet af rodede ledninger, der samles i ét punkt og bringes i orden. Den fornemmelse for at binde det filtrede sammen til én streng lever her også."},"ICON-0990":{"nm":"Skærmrens-sprayhætte","de":"En lille prop, der lukker munden på den spray, som visker fingeraftryk væk fra skærmen. Den holdes altid tæt lukket, så væsken hverken lækker eller tørrer ud. At man må spare på selve rengøringsmidlet, for at kunne se klart — husholdningens beskedne rækkefølge."},"ICON-0991":{"nm":"Hukommelseskort-pung","de":"Flere dages sceneoptagelser sover stille på ét kort, ikke større end en neglespids. Mistes det, forsvinder hele den dag på en gang, så man samler det kært og gemmer det i en lille pung. Et hjem, der rummer den mindste og samtidig den største af erindringer."},"ICON-0992":{"nm":"Ekstern harddisk-label","de":"Fem sorte eksterne harddiske sover i skuffen med samme ansigt. At sætte labels på og give dem navne som 'den sommer' og 'ikke-udgivne klip'. Et arbejde, der fæster et klart register på en tåget erindring."},"ICON-0993":{"nm":"Backup-tjekbrik","de":"Om backuppen er færdig eller ej — netop den forskel gør hjertet urolig. Denne lille brik, stille sat ind ved det afsluttede sted, fortæller: 'her til er det trygt.' Trygheden kommer af at efterlade et mærke."},"ICON-0994":{"nm":"Cloud-notetoken","de":"En token, der sender én linje notat op til et lager, der svæver et sted i himlen. En lille magi, hvor teksten kommer og møder én, uanset hvor man tænder for den. Den nattehimmel, hvor man engang fløj en drage og skrev et ønske, synes nu stille at være sunket ned på ens håndflade."},"ICON-0995":{"nm":"USB-beskyttelseshætter-sæt","de":"Ruller stikket rundt i tasken med kontakten blottet, tager det uundgåeligt skade. Man sætter en lille hat på hver ende og samler dem som ét sæt. At lægge den ubrugte tid sirligt til hvile. Den stilleste forberedelse til den næste forbindelse."},"ICON-0996":{"nm":"Databox-bånd","de":"Et bånd, der omslutter og strammer helt om en enhed med kostbare data. Det viklet én omgang rundt og bindes fast, så intet støder mod hinanden i en rystende taske. Den hånd, der omhyggeligt bandt knuder på et bylt, lever videre uændret, selv i det digitale."},"ICON-0997":{"nm":"Filsorterings-tag","de":"Hober hundredvis af filer sig op uden navne, bliver det at søge til det at fare vild. I det øjeblik man sætter farverige tags på og åbner grene, opstår en sti gennem den rodede bunke. At holde orden viser sig, når alt kommer til alt, at være arbejdet med at anlægge en vej."},"ICON-0998":{"nm":"Adgangskode-hintkort","de":"Skriver man hele adgangskoden ned, er det farligt; skriver man slet ikke, glemmer man den. Derfor efterlader man kun en antydning, som kun man selv forstår. Som 'den by fra den første scene.' En klog og øm huskemetode, der skriver vejen ned, ikke svaret."},"ICON-0999":{"nm":"Opbevaringsdato-mærkat","de":"Skriver man ikke dagen ned, man lagde noget væk, bliver opbevaring hurtigt til glemsel. Et datomærkat på hver æske indprenter tydeligt et 'fra hvornår'. Det gamle forrådskammers hjerte, der noterede den dag, sojabønnepastaen blev lagt i, lever videre på dette lille stykke papir."},"ICON-1000":{"nm":"Mini ringlys-hætte","de":"En lille lampe, der udsender et rundt lys — en hætte, der dækker dens lyshul. Lyset lægges til hvile en stund, så linsen ikke ridses i tasken. At sirligt bevare mørket, før lyset tændes, er også en måde at værne om lysstyrken på."},"ICON-1001":{"nm":"Spændeskrue til holder","de":"Bare en omgang til. Den løse glipe forsvinder, og en tung ro sænker sig under din håndflade. Bag en scene, der ikke vakler, er der altid nogens ene snuptagsdrejning af håndleddet. Det, en lille skrue bærer oppe, er en usynlig soliditet."},"ICON-1002":{"nm":"On Air-mærkebrik","de":"I det øjeblik det røde lys tændes, rejser skridtene i gangen sig lydløst på tåspidserne. Foran ordene »On Air« holder alle vejret. At selv stilheden bag døren er et hjerte vendt mod nogen, er det, denne lille brik stille bekendtgør."},"ICON-1003":{"nm":"Chatnotesblok","de":"Med fingerspidserne griber du den heppen, der ellers ville glide forbi skærmen. Et øjeblik hvor hvert ord, der ellers ville flyde bort, bliver stående, tydeligt og rent, på papiret. At skrive ned er et sted, hvor ømheden ved at ville nå frem, selv sent, kan blive."},"ICON-1004":{"nm":"Lydløst tastaturcover","de":"Klokken to om natten, og lyden af tastetryk forsvinder, som var det løgn. En tynd film, der skal skåne åndedrættet hos en sovende værelseskammerat. Den stilleste omtanke begynder altid et lydløst sted."},"ICON-1005":{"nm":"Mikrofonarmklips","de":"Mellem læber og mikrofon, netop den afstand hvor sangen ikke vakler. Denne lille klips holder det løfte fast. Bagom scenen er der altid en hånd som denne, kommet i forvejen for at holde tingene stabile."},"ICON-1006":{"nm":"Baggrundsklemme","de":"Selv når vinden blæser, rører baggrundsstoffet sig ikke. For en lille kæbe, der bider fast om hjørnet, holder hele scenen på plads. Bag et urokkeligt billede er der altid nogen, et sted du ikke ser, der bider tænderne sammen."},"ICON-1007":{"nm":"Stream Deck-etiket","de":"Oven på snesevis af knapper holder små navneskilte hånden fra at fare vild. Én linje etiket sletter en fejl i den direkte udsendelse på forhånd. Fatning kommer fra de bogstaver, der blev skrevet ned, før nervøsiteten satte ind."},"ICON-1008":{"nm":"Tidsstempelknap","de":"Tryk den ned, og et lille flag plantes i tiden, der flyder forbi. Handlingen at stemple det nu, som aldrig vender tilbage. Kigger man tilbage langt senere, er det mærke blevet en dør ind til minderne."},"ICON-1009":{"nm":"Tagslæsernøglering","de":"Hold den nær, og med et bip vågner informationen. En lille følgesvend, der dingler fra nøgleringen og klirrer i lommen. En almindelig dag glider trygt videre gennem sådanne små signaltoner."},"ICON-1010":{"nm":"Smart-stikkontaktetiket","de":"Sæt navn på hver stikkontakt, og du vandrer ikke længere rundt i tvivl om, hvilken ledning der er hvilken. Hjertet i at give selv den usynlige elektricitet et navn. Orden er et andet ansigt, som ømhed kortvarigt låner og tager på."},"ICON-1011":{"nm":"Temperatur- og fugtsensorstander","de":"En vagtpost på størrelse med en håndflade, der tavst våger over rummets temperatur og fugtighed. Velvære åbner aldrig munden, men denne stander passer stille på din tilstand hvert eneste øjeblik. Sådan holdes trivsel i sikkerhed, stille og roligt."},"ICON-1012":{"nm":"Dørsensorhætte","de":"Et lille øje, der ikke går glip af det øjeblik, en dør sagte åbnes. Det giver lydløst besked om, at nogen er kommet hjem. Det, der vogter et tomt hus, er altid, som her, de tavse ting."},"ICON-1013":{"nm":"Fjernbetjeningsholder","de":"Fjernbetjeninger, der har rullet rundt hist og her, finder endelig deres egen plads. Et lille sted, der stille holder fast i det, der næsten gik tabt, en hånd der på forhånd risser løftet om at mødes igen."},"ICON-1014":{"nm":"Søvnapp-mønt","de":"For hver god nats søvn ruller endnu en rund belønning ind og lægger sig oveni. Selv søvn samles op, bid for bid, som øvelse, fortæller appen dig ømt. Verdens mindste præmie, rakt til dig, der hvilede godt."},"ICON-1015":{"nm":"Timerterningfod","de":"Mens tre minutter går stille og roligt, tæller terningen sin tid uden at vakle. Ét håndfladestort sted, der bærer den blidt oppe nedefra. Selv venten har brug for et gulv, den kan stå trygt på."},"ICON-1016":{"nm":"Notifikationslys-cover","de":"Så det ikke bliver for kraftigt, indhyller den lyset blødt i ét lag. En notifikation må gerne haste, men lad blot øjnene være i fred. Omtanke er et hjerte, der stille tager selv lysets styrke i betragtning."},"ICON-1017":{"nm":"Batteriskiftekort","de":"Når dette kort dukker op, betyder det, at det lille hjerte i apparatet skal skiftes. Et venligt vink om at sørge for det, før det stopper. Hemmeligheden bag et langt følgeskab ligger altid i en agtpågivenhed en takt i forvejen."},"ICON-1018":{"nm":"Joystickhættesæt","de":"Små hætter, der glider på, så tommelfingeren ikke skrider. Fornemmelsen i fingerspidsen bliver et hak klarere. Denne ene lille hætte kan endda afgøre sejr eller nederlag i et parti spillet med svedige hænder."},"ICON-1019":{"nm":"Dockingcover til konsol","de":"Den dækker sagte konsollens hvilested mod støv. For selv et kortvarigt sovende apparat har brug for et tæppe. Et omsorgsfuldt hjerte viser sig faktisk tydeligst, når noget slet ikke er i brug."},"ICON-1020":{"nm":"Bæreetui til håndholdt konsol","de":"Når du er på farten, skal den altid herind. En pose, der pakker den håndholdte konsol blødt ind i sin favn. Så den forbliver uberørt, selv når den bumper rundt i tasken; det kæreste bør altid pakkes ind én gang til."},"ICON-1021":{"nm":"Knapklistermærke-rulle","de":"Læg blot ét lille billede oven på en kedelig knap, og i samme øjeblik bliver den helt og fuldt din egen. Handlingen at sætte sit eget aftryk på et identisk apparat. Personlighed blomstrer altid stille frem fra sådanne ubetydelige steder."},"ICON-1022":{"nm":"Spilkassette-etui","de":"Et spil, du fortabte dig i hele natten, sover trygt inde i dette lille etui. Åbn låget igen, og den nat vågner op til live, uberørt. Minder rummes overraskende ofte i en æske ikke større end en håndflade."},"ICON-1023":{"nm":"Køleblæserstander","de":"Mens vinden køler varmen ned, holder et sted apparatet let hældende. Det giver en overophedet krop plads til at trække vejret. For at kunne løbe langt må man også vide, hvordan man stopper op et øjeblik og køler af."},"ICON-1024":{"nm":"Håndledsstrop-pin","de":"Slå den om håndleddet, og fastgør pinden, og uanset hvor voldsomme bevægelserne bliver, forlader controlleren ikke din side. Denne rem, der ser besværlig ud, er i virkeligheden trygheden, der lader dig boltre dig frit."},"ICON-1025":{"nm":"Analogpind-grebshætte","de":"Iklæd et nyt klæde over et greb, der er blevet blankt og glat af lang tids brug. Lad fornemmelsen, hånden kender, forblive urørt, og lad kun overfladen fremstå ny. Et øjeblik hvor fortrolighed og en lille sitren hviler side om side i én hånd."},"ICON-1026":{"nm":"Gemmeplads-etiket","de":"På hver gemmeplads skriver du tydeligt, hvis eventyr det er. Én linje etiket vogter tavst rejsen fra de seneste dage. Kære minder gør man klogt i at give et indgraveret navn, så de ikke bliver overskrevet."},"ICON-1027":{"nm":"Optageretui","de":"En maskine, der rummer lyd, bliver desto mere dyrebar for det, den bærer indeni. Du bærer den nænsomt puttet i en blød pose, der skærmer den mod stød. Nogens stemme kan ligge og sove derinde, så vær ekstra forsigtig."},"ICON-1028":{"nm":"Mikrofon-vindhætte","de":"Fej lyden af vinden væk, og lad kun stemmen tilbage. En luftig hætte, der lægges blidt over mikrofonen ved udendørs optagelser. En lille sigte, der udvælger kun oprigtigheden blandt den urolige larm."},"ICON-1029":{"nm":"Talememo-etiket","de":"Den her er en tekstlinje, der pludselig kom til; den her en nynnet melodi. Du sætter et farverigt navneskilt på hver talememo. De spredte brudstykker af inspiration finder omsider deres plads og stiller sig på række."},"ICON-1030":{"nm":"Samplingknap-brik","de":"Tryk den ned, og en lille flig af forudindspillet lyd springer frem. En regndråbe, klapsalver, nogens latter, verdens brudstykker vågner ved din fingerspids. Musik er det milde kor af sådanne små brikker."},"ICON-1031":{"nm":"Lydopsamlingskuvert","de":"Du samler nænsomt de lyde, du støder på undervejs, i denne kuvert. Vindens tekstur, endda stilheden i en gyde ved daggry. De materialer, der en dag bliver til en sang, samles altid så beskedent som dette."},"ICON-1032":{"nm":"Minitrefod","de":"Tre ben folder et lille scene ud oven på skrivebordet. I stedet for en rystende hånd står de fast og holder billedet på plads. Et skarpt enkelt billede bliver først til, tavst, fra tre stille stående ben."},"ICON-1033":{"nm":"Optagelsesfil-mærke","de":"Til hundredvis af lydfiler sætter du ét lille mærke ad gangen. Så du med et blik kan se, hvilken der var den første linje, der strømmede ud den dag. Et lille vejskilt, der hjælper dig med at finde spredte stemmer igen."},"ICON-1034":{"nm":"Bølgeform-klistermærkebånd","de":"Et bølgemønstret bånd formet efter selve lydens skikkelse. Vikl det om en notesbog eller et etui, og det er, som om musikken bliver synlig foran øjnene. En kærlig illusion, der gør det hørte til det sete."},"ICON-1035":{"nm":"Headset-krogpin","de":"Når øvelsen er slut, forbereder den stille et hvilested til det trætte headset. Én lille krog boret ind i skrivebordets kant. Et ryddeligt skrivebord er et sted, hvor man hænger morgendagens gejst op i forvejen."},"ICON-1036":{"nm":"Minigaveæskebånd","de":"Den sidste omgang viklet om en gaveæskes talje. Med dette ene bånd bliver hjertet endelig fuldendt. Omhu formidles ofte først fra hånden, der glatter ydersiden, mere end fra det, der ligger indeni."},"ICON-1037":{"nm":"Sløjfehale-hætte","de":"Pak omhyggeligt sløjfens ende ind og afslut den, så den ikke går op. Én detalje, der næppe fanger blikket, ændrer stille en gaves første indtryk. Når afslutningen er fin, når hjertet også fint frem."},"ICON-1038":{"nm":"Segllak","de":"Lad en varm dråbe falde med et lille plop for at forsegle kuverten. Som et gammelt brev, et tungt løfte om ikke at åbne det uden omtanke. Formalitet rummer somme tider netop sådan en varm vægt."},"ICON-1039":{"nm":"Takkekortholder","de":"Den holder et kort med takkeord opret, så det ikke krølles. Så hjertet står ranket, mens det bliver overrakt. Taknemmelighed bliver længere i hjertet, når selv dens form er sirlig."},"ICON-1040":{"nm":"Stjerneformet fyldpapir","de":"Papir klippet i stjerneform fylder blødt hullerne i en æske. Vatten fra et hjerte, der ønsker, intet må komme til skade, selv når det rystes. Selv i mørket inde i indpakningen svæver der, kan man sige, en lille stjerne."},"ICON-1041":{"nm":"Gaveliste-mærke","de":"Foran modtagerens tomme felt standser pennen længe. Ansigtet der dukker op, mens du skriver navnet, årstiderne I delte sammen. I det øjeblik den bindes fast, bliver dette lille stykke papir en hemmelighed, ingen kan læse, før den løses op."},"ICON-1042":{"nm":"Lykønskningsstempelring","de":"Tryk den ned, og en rund lykønskning trykkes tydeligt frem. Mens du venter det korte øjeblik på, at blækket tørrer, er hjertet, der forestiller sig, hvem den skal gives til, det varmeste. Hvis der er en fejl, er det, at man får lyst til at stemple én gang til."},"ICON-1043":{"nm":"Gavesnorspole","de":"Omhyggeligt viklet op, for så muntert at blive rullet ud igen ved nogens forventningsfulde fingerspidser. I det korte øjeblik af viklen og udrulning bliver et hjerte, bundet til tråden, endelig til en gave."},"ICON-1044":{"nm":"Knude-charm (ikke en blomst)","de":"Ikke en efterligning af en blomst, men en form hvor én enkelt tråd omfavner sig selv gang på gang og blomstrer af egen kraft. Tålmodigheden i de fingerspidser, der valgte knuder hele natten, er blevet tilbage som denne ene lille knop."},"ICON-1045":{"nm":"Lykkemønt-pose","de":"Hjertet i stille at putte et par mønter i lommen på en, der drager af sted på en lang rejse. Handlingen at fylde den ikke med vægt, men med ømhed. Klirren for hvert skridt træder i stedet for et ønske om, at rejsen må gå godt."},"ICON-1046":{"nm":"Ønskekapsel-charm","de":"Inde i en rund skal sover et sammenfoldet ønske trygt. At det skulle gå i opfyldelse, hvis man åbner den, er en løgn, men at ønsket forbliver levende for evigt, hvis man holder den ulukket, det er sandt."},"ICON-1047":{"nm":"Beskyttende knudesnor","de":"En snor flettet fast af fem farvede tråde, der vender ondt varsel tilbage bag din ryg. Som bedstemors hånd, der bandt en knude om håndleddet i barndommen, sidder nogens bøn fint fæstnet i hvert bundet sted."},"ICON-1048":{"nm":"Lille papirtrane-etui","de":"Et lille hjem, der holder blot én papirtrane i sikkerhed, ud af de tusind der skal foldes for at blive et ønske. For hvis blot den ene vinge krølles, opløses selv den hengivenhed, der blev lagt i den nat, sagte igen."},"ICON-1049":{"nm":"Glimmersten-pose","de":"Små glimtende korn faldet fra scenekostumet, et sted at feje op det, man ikke kan få sig selv til at smide væk. Selv den glans, der engang klæbede sig fast og fulgte dig i en hel uge, sover her lige så lydigt som i din håndflade."},"ICON-1050":{"nm":"Lykkevarsel-stempelbrik","de":"Et lille bidrag, du stille tilføjer, når du vælger en god dag. Ikke på spåkonens dørtrin, men på dit eget skrivebord, en flig af kærlig overtro, du sagte stempler, mens du ønsker, at kun gode ting må ske i dag."},"ICON-1051":{"nm":"Ønskearmbånd-kort","de":"Et enkelt stykke papir trykt i form af et armbånd, der rummer nogens stille bøn. Selv hvis det ikke kan spændes om håndleddet, kan du putte det dybt i pungen, og netop det hjerte forbliver bundet ved din side og går med dig altid."},"ICON-1052":{"nm":"Dørtrinssaltkrukke","de":"Groft salt hældt i en lille krukke, sat stille ved døren. En gammel regel, der vender onde ånder bort og kun byder venlige gæster velkommen. Hvert enkelt salte korn er en lille dørvogter, der våger over vores hjem."},"ICON-1053":{"nm":"Lykketal-skrabemærke","de":"Lige inden man skraber, er alle et kort øjeblik nummer ét. Dette mærke, der sagte tildækker det heldige tal, vogter det sidste sekund, hvor forventningen svulmer allermest. Selv hvis skrabende fingre skælver, lader det som ingenting og holder øjnene lukket."},"ICON-1054":{"nm":"Fødselsdagslys-opbevaringshætte","de":"Et omhyggeligt hjerte, der holder selv et engangs-tændt lys i sikkerhed helt frem til næste fødselsdag. Hvis sidste års ønske stadig ikke er gået i opfyldelse, kan du blot fortsætte med at ønske derfra i år, en øm form for regnskab."},"ICON-1055":{"nm":"Mærkedags-nedtællingsring","de":"En kæk lille ting, der putter en nedtællingsdag på din finger. Hver gang tallet for de resterende dage tikker ét hak ned, trækkes hjertet også ét hak nærmere. Den insisterer selv på, at den vil lyse, når den når 0."},"ICON-1056":{"nm":"Festhat-snor","de":"En tynd snor, der holder festhatten stramt fast på hovedet. Fødselaren selv klager snart over, at den strammer, og tager den af, men på billedet sidder den fast for evigt i det ene øjeblik. Det er opgave nok."},"ICON-1057":{"nm":"Lille kagepind","de":"Et lille mærke stukket ned i en kage på størrelse med to fingerled. Selv oven på en sødme, der forsvinder i én bid, rejser fejringen sig stolt og rank. Selv lille er en fødselsdag stadig en fødselsdag, og i dag er stjernen dig."},"ICON-1058":{"nm":"Konfettibombe-etiket","de":"Et papirkrus, der ikke smælder, men ser mest festlig ud af alle. I det øjeblik det klistres på, forvandles almindelig post til et brev sendt fra en fest. Mange lader det bare blive siddende, for ærgerlige til at rive det af."},"ICON-1059":{"nm":"Fotoophængsklemme","de":"Bange for at tabe minderne, der hænger langs snoren, holder jeg altid munden lukket fast i. Så længe et billede holdes fast i mit greb, kan end ikke brisen gennem vinduessprækken få de dage til at falde bort."},"ICON-1060":{"nm":"Datoballon-mærkat","de":"Et ballonformet mærke med et tal på. Sæt det på tøjet, og hele kvarteret ved, hvilken særlig dag det er i dag. Riv det af, og der bliver et mærke, og selv det svage mærke bliver endnu et minde."},"ICON-1061":{"nm":"Gavebytte-mærke","de":"Et drilsk mærke, der sagte forvirrer, hvilken hånd der modtog, og hvilken der gav. En lille, øm regel ved gavebyttebordet, der beder dig huske mindre hvem der gav den, mere hvad der blev udvekslet mellem jer."},"ICON-1062":{"nm":"Festbordnummer","de":"Et lille nummer rejst op ved hvert festbord. At fastlægge på forhånd, hvem der sidder hvor, så ingen føler sig akavet, rummer den varme visdom hos folk, der har holdt mange fester."},"ICON-1063":{"nm":"Dørhåndtag-gavepose","de":"En måde at give sit hjerte videre på uden at ringe på. Hæng den drilsk på dørhåndtaget og forsvind som på flugt, og det overraskede ansigt hos den, der finder den, bliver den største gave, der vender tilbage til giveren."},"ICON-1064":{"nm":"Hemmelig leverings-etiket","de":"Der står intet skrevet på forsiden. At holde afsenderen skjult til det sidste er denne etikets lille stolthed. Jo længere modtageren vender hovedet undrende og smiler, desto mere fuldkommen bliver dens hemmelige mission."},"ICON-1065":{"nm":"Dørklokke-memobrik","de":"En lille seddel, du sætter op i stedet, når du ikke kan mønstre modet til at banke på. En kort linje som »kom lige forbi« bliver hængende længere end en dørklokkes klang. For krøllet, kluntet håndskrift har sit eget ansigtsudtryk."},"ICON-1066":{"nm":"Hobbykniv-sikkerhedshætte","de":"Når hobbyknivens klinge tankeløst sigter mod en finger, stiller en lille helt sig sagte i vejen. Den vogter trygt fingerspidserne, forhastede af spænding over det nye, helt frem til det sidste snit."},"ICON-1067":{"nm":"Boblefolie-stykke","de":"Jeg blev født til at blive trykket på. Med den lille smæld af lyd løsner dagens spænding sig sagte. Somme tider bliver jeg selv elsket længere end den ting, jeg blev pakket omkring."},"ICON-1068":{"nm":"Ankomsttids-pin","de":"En pin, der stikker fast det klokkeslæt, den ankommer på. Selv en vag venten bliver langt lettere at holde ud, når den får ét enkelt koordinat. Hvor mange gange du kigger ud af entrédøren indtil da, er helt op til dig selv."},"ICON-1069":{"nm":"Pakkeboks-nøglering","de":"En lille følgesvend for den, der bliver ved med at glemme pakkeboksens kode. Den dingler på nøgleringen, og dens diskrete talent er at fremkalde et »nå ja, det var rigtigt« i det afgørende øjeblik."},"ICON-1070":{"nm":"Entrékurv-mærke","de":"Et navneskilt på kurven i hjørnet af entréen. På den står det tavse løfte: »læg den her«. Selv tomt er et sted, der venter på nogens omtanke, aldrig ensomt."},"ICON-1071":{"nm":"Adressedækkende klistermærke","de":"På en æske, du smider ud, lader du navnet blive, men visker adressen bort. Navnet må gerne alle kende; hvor du bor, forbliver din egen hemmelighed. I det øjeblik du river dette ene lag af og klæber det på, opstår en lille tryghed."},"ICON-1072":{"nm":"Snackdåse-etiket","de":"En etiket, der med ét blik fortæller, hvad der er i dåsen. Men fælden er, at bare det at skrive »snacks« på den giver en følelse af tryghed, selv uden at åbne låget. Etiketten kan dog ikke stå til ansvar for appetitten."},"ICON-1073":{"nm":"Lille halskædevedhæng","de":"En lille perle, der stille deler din kropsvarme under tøjet. Altid rørende ved et sted, ingen kan se, er den netop derfor så meget kærere. Den nærmeste ven, der vandrer med ved dit hjerte."},"ICON-1074":{"nm":"Potaftryks-stempelmåtte","de":"Tryk den mod poten, og en række små fodspor bliver tilbage. En daglig gåtursdagbog, der pænt noterer på papir, hvem der gik hvorhen. Det første blækplettede skridt er altid det klareste."},"ICON-1075":{"nm":"Pelsbørste-hætte","de":"En lille hætte, der pænt tager sig af det pels, der har viklet sig ind i børsten. I fældningstiden, hvor ét strøg samler en håndfuld, ville hele huset uden denne hætte blive til en dunet snefane. En flittig rengøringshjælp, der arbejder uden at gøre væsen af sig."},"ICON-1076":{"nm":"Hundeposeetui","de":"Et lille hjem, der pænt samler de poser, du skal have med på gåturen. Kun de, der har pakket i forvejen, går trygt og afslappet, det beviser dette etui tavst hver eneste dag. Det ene stykke, det bliver besværligt at glemme."},"ICON-1077":{"nm":"Navneskjulende mærke","de":"Et mærke, der drilsk skjuler det rigtige navn og kun lader kælenavnet stå tilbage. Der findes i verden en slags ømhed, man ikke ønsker at vise for hvem som helst. Det tilnavn, kun de indviede kender, gemmer sig blidt lige her."},"ICON-1078":{"nm":"Vandskål-underlag","de":"Lagt under vandskålen er jeg altid fugtig. Ved at opsuge de vanddråber, der sprøjter til alle sider i stedet, holder jeg gulvbrædderne tørre. Ingen roser mig, men jeg klager heller aldrig."},"ICON-1079":{"nm":"Stoppegarn til legetøj","de":"En bamse med bristet søm smides ikke ud, den syes sammen igen. For hvert sted, du fylder ud, sting for sting, bliver tiden tilbragt med den lille ven stærk igen. At reparere er, når alt kommer til alt, stille at udsætte et farvel."},"ICON-1080":{"nm":"Minde-fotohalskæde","de":"Hjertet i at bære det billede, hvor du smilede allerlysest, om halsen. Den dag på billedet bliver ikke opstillet og fastfrosset, men svinger med for hvert skridt og når helt frem til i dag. Det gode øjeblik holder aldrig op."},"ICON-1081":{"nm":"Humørfarve-brik","de":"Hvis også hjertet havde farver, hvilken farve ville din være i dag? I det øjeblik du vælger en brik og sætter den på skrivebordet, breder den følelse, ord ikke kunne rumme, sig stille ud. Solnedgangens glød eller morgengryets lys, begge dele er fint, for det er et lille spejl, der blidt afspejler dig, som du er den dag."},"ICON-1082":{"nm":"Dagens erindringskugle","de":"Når dagen lakker mod ende, samler dagen sig rund inde i kuglen. Både det, du klarede godt, og det, du klodsede med, ruller sammen og gemmer sig af vejen. Læg den i håndfladen, og gårsdagens dig føles en anelse varm, og klapper dig på ryggen for at have levet godt endnu en dag."},"ICON-1083":{"nm":"Rosseddel-krukke","de":"Gode ord spredes alt for let, så du folder dem sammen ét ad gangen og gemmer dem i denne krukke. Når ros samler sig som en duft, åbner du låget på nætter, hvor hjertet føles tomt. Tag en smule ømhed frem, som nogen har rakt dig, og læs den igen, og den dags varme vender tilbage til live."},"ICON-1084":{"nm":"Forsoningssløjfebånd","de":"Et sammenfiltret hjerte ligner en knude; selv at løse den kræver omhu. Når to mennesker griber hver sin ende af snoren og trækker langsomt, bliver det, uden man ved af det, til en smuk sløjfe. Forsoning er ikke at klippe over, men at binde igen, det fortæller denne snor stille."},"ICON-1085":{"nm":"Taknemmeligheds-mønt","de":"På dage hvor »tak« ikke vil løsne sig fra læberne, rækker du i stedet stille en mønt frem. Den hånd, der modtager den, læser hele dit hjerte i den lille vægt. En oprigtighed, der når frem før ordene, en varme båret over i en enkelt rund perle."},"ICON-1086":{"nm":"Pausemærke","de":"Selv et øvelokale, der har løbet hele dagen, har brug for én takt til at trække vejret i. Hæng dette mærke på døren, og tiden sænker farten et øjeblik. At en sang har brug for et pausetegn for at kunne trække vejret, det ved enhver, der har levet en åndeløs dag."},"ICON-1087":{"nm":"Skjult følelsesskuffe","de":"Der er dage, hvor man ikke kan lægge hele sit indre frem. På sådanne dage putter du både sorg og sitren stille ned i en lille skuffe i sindet og lukker den. Det er fint at lade dem ligge for nu, for en dag vil komme, hvor du langsomt kan åbne den og få ryddet op."},"ICON-1088":{"nm":"Smilemærke-rulle","de":"Riv én rude af, og et smilemærke sætter sig på fingerspidsen. Lidt munterhed sat blidt fast i hjørnet af en notesbog eller i en vens skab. Når en lille sol står op på papiret, bliver dagen for den, der finder den, en anelse lysere."},"ICON-1089":{"nm":"Hilseklokke-charm","de":"Ønsket om at nå frem til dig langt væk har samlet sig i én lille klokke. Ryst den, og en klar lyd bringer din hilsen i dit sted. På dage hvor du ikke kunne få dig selv til at spørge »går det godt«, rider denne lille klang på vinden og når frem først."},"ICON-1090":{"nm":"Forårsregn-omslagspin","de":"På regnfulde forårsdage bliver netop det, man holder mest af, allerlettest gennemblødt. Luk omslaget med denne pin, og regndråberne skråner af og forbi. Hjertet i at holde en dyrebar bog tæt indhyllet, det er, hvad en lille pin træder i stedet for."},"ICON-1091":{"nm":"Sommerkølende plaster","de":"Ét hurtigt tryk på håndryggen, udmattet af midsommervarmen. En kølig fornemmelse breder sig som mynte, og sveden letter en anelse. Den svale følelse af at ligge på den åbne veranda og vifte sig, efterlignes trofast af et papirark på størrelse med en håndflade."},"ICON-1092":{"nm":"Ternet efterårsstoflap","de":"En lap ternet stof, der minder om en efterårsmark. Det er sporet efter nogen, der omhyggeligt har lappet et slidt sted. Hjertet i at stoppe frem for at smide væk, små stofstykker samles og giver det slidte varme liv igen."},"ICON-1093":{"nm":"Vintervante-klips","de":"Vintervanter render af sted, en ad gangen, af en eller anden grund. Bind de to sammen med denne klips, og de kolde hænder farer ikke vild. Ønsket om ikke at miste dem har bosat sig i et lille stykke metal og holder de to sammen, side om side."},"ICON-1094":{"nm":"Vandtæt regntidsmærke","de":"I regntiden løber selv et navneskilt ud i regnen. Dette vandtætte mærke beskytter sin skrift selv under øsende regn. En linje, der forbliver klar, efter regnen har lagt sig, så det aldrig glemmes, hvis den er, helt til det sidste."},"ICON-1095":{"nm":"Første sne-opbevaringskrukke","de":"Den første sne forsvinder, i det øjeblik den rører hånden, så du gemte i det mindste den spænding i en krukke. Det, der er fanget i glasset, er ikke sne, men det hjerte, der bankede den dag. Ryst den, og en hel vinter hvirvler igen, og bærer dig tilbage til den morgen."},"ICON-1096":{"nm":"Højtidskonvolut-bånd","de":"Ét rødt bånd viklet om en højtidskonvolut. Alle ved, at kærligheden i den rakte hånd vejer tungere end det, der ligger indeni. Hjertet, der pakker velsignelser sammen med ønsker om et godt liv, ligger fint bundet inden i dette smalle bånd."},"ICON-1097":{"nm":"Picnic-servicebånd","de":"Bred tæppet ud og pak madkassen op, og vinden bliver ved med at løfte i låget. Snør servicet stramt sammen med dette bånd, og picnicken falder ikke i uorden. Hjertet i at beskytte det medbragte måltid til det sidste er rummet i ét lille bånd."},"ICON-1098":{"nm":"Sæsonduft-prøvekort","de":"Så du kan kende årstiden uden overhovedet at åbne den, er duften af den tid på året rummet i ét enkelt kort. Blomster om foråret, duften af tørre blade om efteråret. I det øjeblik den strejfer næsen, vender hele årstiden tilbage — »dette er aprils luft«."},"ICON-1099":{"nm":"Prisskilt-klembræt","de":"Dette ene klembræt lagde for evigt boden bekymring om prisskilte, der bliver ved med at flyve væk, til hvile. Det holder tallene fast og rækker dem ranke frem for kunden. En handels første hilsen begynder med én ærlig linje, der aldrig kommer skævt."},"ICON-1100":{"nm":"Åben-skilt vendeplade","de":"Vend denne plade om og hæng den ved døren, og butikken vågner endelig. Fra »gør klar« til »velkommen«. Et lille signal, der bebuder dagens begyndelse, det sted ejerens hånd rører først hver morgen."},"ICON-1101":{"nm":"Bonusstempelpude","de":"Fylder man alle ti felter, sker der på en eller anden måde noget godt. Hvert stempel er en stamkundes skridt, kærlighed der er samlet op gennem tiden. I hvert aftryk, presset til blækket tørrer, lever og ånder et lille løfte om at komme igen."},"ICON-1102":{"nm":"Håndtagshætte til papirspose","de":"En papirsposes håndtag er altid svagt over for vægten. Sæt denne hætte på, og den snor, der var ved at knække, bliver solid. Ønsket om at bringe det, der ligger deri, trygt hjem — en lille tilbehørsdel bærer denne rejse hele vejen igennem."},"ICON-1103":{"nm":"Byttepengebakke","de":"Denne bakke letter stille tøvenen ved at give byttepenge fra hånd til hånd. Lyden af mønter, der klirrer på plads. At give og modtage bliver varmere netop takket være denne runde lille hensyntagen."},"ICON-1104":{"nm":"Pointchip","de":"Dagens skridt samler sig pænt op i en enkelt chip. Et underligt regnestykke, hvor hjertet føles lettere, jo mere man samler. Glæden ved at fylde lidt efter lidt minder om fornøjelsen ved at se en tom krukke blive fuld, før man ved af det."},"ICON-1105":{"nm":"Hyldenummer-pin","de":"På hver hylde sidder kærligt et lille nummer fastgjort. En stille guide, der fortæller, hvor alting er. Hjertet i at markere pladsen på forhånd, så man ikke farer vild — selv orden kan bære en sådan varme."},"ICON-1106":{"nm":"Smagsprøve-spydkop","de":"En lille kop, der rækker en mundfuld frem på en pind. Selv en tøvende kunde åbner sagte sit hjerte ved denne ene bid. Gæstfriheden i at opfordre \"prøv lige en\" hænger fra spyddets spids og holder på førstegangsgæstens skridt."},"ICON-1107":{"nm":"Reservationsliste-holder","de":"Navnene på dagens gæster står pænt opstillet i denne holder. Et ømt løfte om, at selv ventetid har sin tur. At stille et enkelt stykke papir lige op bliver den første omhyggelige forberedelse til at byde nogens dag velkommen."},"ICON-1108":{"nm":"Fotosnor-klemme","de":"Spænd en snor op på væggen, og klip fotografier på den ét ad gangen. Smilende øjeblikke hænger side om side og tørrer som vasketøj. Hæng minderne, hvor solen falder ind, og hver gang man går forbi, blafrer den dags latter igen."},"ICON-1109":{"nm":"Lille hjørnetæppe","de":"Et lille tæppe lagt ved kanten af rummet. Et sted, der først breder varme ud på det kolde gulv. Det hjørne bare fødder rører først — der finder tæerne på den hjemvendte endelig ro og bliver dovent trætte."},"ICON-1110":{"nm":"Navneskiltsslør","de":"Et stykke stof, der sagte tildækker navneskiltet. At gemme navnet væk for en stund er også en form for hjemlig elegance. Et yndigt drapement over grænsen mellem inde og ude, hængt blødt op med ønsket om at hvile stille i dag."},"ICON-1111":{"nm":"Lysledning-klemme","de":"Denne klemme holder en dinglende lysledning pænt på plads. En hånd, der retter stien ud, så lyset ikke spredes. Glat en rodet ledning ud, når aftenen sænker sig, og både lyset i rummet og hjertet bliver roligere."},"ICON-1112":{"nm":"Plakat-magnethætte","de":"En lille magnethætte til at sætte en plakat op på væggen. Papiret holder sin plads uden et eneste hul fra en nål. Hånden, der behandler det, den holder af, er altid blid — og heri ligger hjertet i at passe på det, uden at det tager skade."},"ICON-1113":{"nm":"Gardinsnor med kvast","de":"En kvastsnor, der binder gardinet til den ene side. Den åbner en yndig vej for morgensolen til at komme ind. Træk én gang i den kvastede snor, og en lys dag strømmer ind i rummet og bliver."},"ICON-1114":{"nm":"Duftlys-etiket","de":"En lille etiket sat på et duftlys' fad. Den noterer omhyggeligt, hvilken duft der brænder, og hvornår det først blev tændt. At give en yndlingsduft et navn — den omhu gør luften i rummet endnu mere øm."},"ICON-1115":{"nm":"Gummifødder til hylde","de":"Fire gummifødder, der støtter en hylde, så den ikke vakler. Fra et usynligt sted bærer de vægten i stilhed. Små og lave og lette at overse, men det, der holder fast for neden, er det, der varer længst i sidste ende."},"ICON-1116":{"nm":"Retningspil-vedhæng","de":"For den, der tøver med, hvilken vej der skal gås, peger en enkelt pil stille retningen. En øm gestus, der siger: fortabe dig ikke. Takket være hjertet, nogen satte op ved hvert vejskel i forvejen, går man i dag videre uden at fare vild."},"ICON-1117":{"nm":"Ø-invitationens nøglesnor","de":"En nøglesnor lagt i hånden på den, der byder dig velkommen til øen. Tag imod den, og nu er du også familie her. Gæstfriheden i at byde en fremmed gæst velkommen ind i det varme indre er holdt fast i det lille løfte, der dingler for enden af snoren."},"ICON-1118":{"nm":"Nærheds-temperaturchip","de":"En enkelt chip fortæller listigt temperaturen mellem to mennesker. Om det stadig er et akavet blåt, eller om det for længst er blevet et varmt karmoisin. Hastigheden, hvormed kærlighed uddybes, er svær at måle, men håndfladen mærker den varme først."},"ICON-1119":{"nm":"Smagsprøveæske","de":"Når man endnu ikke ved, hvad nogen kan lide, samler man små smagsprøver i en æske og rækker den frem. I glæden ved at vælge vokser en smag langsomt frem. Hvilken bliver din — æsken er fuld af spændende muligheder."},"ICON-1120":{"nm":"Pasnings-reservationsnål","de":"Løftet om at passe på nogen sættes klart fast i denne ene nål. Skriv navn og tidspunkt ned, og hjertet farer ikke vild. Det ømme, skiftevis at passe hinandens børn, lever og ånder lige her."},"ICON-1121":{"nm":"Vækstkapsel","de":"Ligesom mærkerne fra målt højde stables op linje for linje på en dørkarm, forsegler denne kapsel stille gårsdagens dig. Åbn låget langt ude i fremtiden, og du vil vide det: hvor langt de engang så små skridt er gået."},"ICON-1122":{"nm":"Minde-bånd for første møde","de":"Skælven ved at holde hånd for første gang bindes sagte fast i et enkelt bånd. Knuden er der ikke for at blive løst op, men for at lade den dags varme fortsætte med at leve om håndleddet."},"ICON-1123":{"nm":"Mit Værelse-pynteetiket","de":"\"Her er min plads.\" I det øjeblik en lille etiket klistres på hjørnet af skrivebordet, ånder det engang fremmede værelse endelig og bliver til Mit Værelse. Et navneskilt er det første sted, hjertet lander."},"ICON-1124":{"nm":"Fortrolighedskrukke","de":"Ryst den, og en raslende klang ruller videre — lyden af, at to kommer et hak nærmere hinanden. Når krukken er ved at være fuld, vil bare det at kalde dit navn nok få latter til at komme og tage imod dig først."},"ICON-1125":{"nm":"Debut-forberedelsessegl","de":"Det sidste ark, der lukker konvolutten. Hertil er forberedelse; vend næste side, og det er scenen. Med fingerspidsen trykker praktikanten det fast og finder roen i vejrtrækningen. Endelig — nu begynder det."},"ICON-1126":{"nm":"Vand","de":"Det mest almindelige, og derfor det mest dyrebare. I et øvelokale i mørket ved daggry rejser en enkelt slurk et menneske, der var sunket sammen, op igen. En ømhed uden egen form, der siver ind i ethvert kar."},"ICON-1127":{"nm":"Klart vand","de":"En gennemsigtighed, der klart genspejler selv småstenene på bunden. En bjergkilde praler aldrig af sin egen renhed. Et hjerte uden noget at skjule er altid sådan — synligt helt ned til bunden."},"ICON-1128":{"nm":"Havvand","de":"I samme øjeblik det rører tungespidsen, skyller fjerne bølger ind. I en salt slurk er horisonten og mågerne og havnen, man forlod, smeltet sammen som ét. Havet forbliver altid tilbage i erindringen med en salt smag."},"ICON-1129":{"nm":"Is","de":"Den smelter langsomt bort i hånden og forsvinder, i takt med man holder om den. Selvom den ser hård ud, ved den, den til sidst vender tilbage til vand. Is er en flod, der har holdt vejret et øjeblik."},"ICON-1130":{"nm":"Snebold","de":"En fast presset klump flyver hvid gennem gyden. Klukkende latter og røde, kolde kinder. Vinterens hvideste legetøj, som den sagte trykker ned i børnenes hænder."},"ICON-1131":{"nm":"Jord","de":"Den favner frø, drikker regnvand og tager stille imod forbipasserende fodspor. En sort hud, der omfavner alt. Ved begyndelsen af alt, der vokser, findes denne ene håndfuld."},"ICON-1132":{"nm":"Frugtbar jord","de":"Stik fingrene dybt ned, og en sort fedme lægger sig blødt om dem. Hemmeligheden bag bedstemors køkkenhave, der var grøn hvert eneste år, lå lige her. Vel modnet jord hvisker om en rig høst med duften af gødning."},"ICON-1133":{"nm":"Ler","de":"I det øjeblik det optager fugt, tager det lydigt imod enhver form. Følger hånden, bliver det til en fugl, bliver det til en skål, en øm masse. Mens drejeskiven snurrer, begynder en håndfuld jord endelig at drømme."},"ICON-1134":{"nm":"Sand","de":"Fine korn, der siver væk mellem fingrene. Jo hårdere man holder fast, jo hurtigere strømmer de bort — de ligner stadig mere tiden selv. I en håndfuld strand ligger utallige gårsdage og sover."},"ICON-1135":{"nm":"Rullesten","de":"Sten, der er slidt runde ved åens bred. De er sporet efter vand, der har kærtegnet dem længe, længe, til de skarpe kanter forsvandt. Jo længere en sten har rullet, jo blidere lægger den sig i hånden."},"ICON-1136":{"nm":"Sten","de":"En klump lagt ligegyldigt ved vejkanten. Én sparker til den og går videre; en anden samler den stille op og bygger et tårn. Den samme sten bliver til en byrde eller et ønske, alt efter hjertet."},"ICON-1137":{"nm":"Flisesten","de":"En bred, flad sten, der krydser en gammel palads-gårdsplads. Hundredvis af års sko har trådt hen over den og slidt en fordybning midt på den. Hvert eneste skridt, nogen tager på den, tilføjer endnu et lag tid."},"ICON-1138":{"nm":"Kalksten","de":"Muslinger fra dengang, den var hav, hærdede lag på lag til en hvid sten. Læg den i en ovn, og den løses op til kalk, der maler mure kridhvide. Selvom den virker rolig, er den en sten, der rummer en hel æra i sig."},"ICON-1139":{"nm":"Kul","de":"En gammel skov, faldet i en sortsvedet søvn. Bregner fra hundredvis af millioner af år siden, presset fast sammen dybt under jorden. Tænd ild i det, og det længe begravede sollys blusser op til live igen."},"ICON-1140":{"nm":"Trækul","de":"Det holder på ilden, men sluger stille røgen. Træ presset sort i ovnen blomstrer tavst rødt på grillen. Jo mere tavs en ting er, jo længere holder den varmen."},"ICON-1141":{"nm":"Kvist","de":"En gren, der stille har bøjet sig fremfor at knække, kender kunsten at give efter. Ved hvert sted, der har udholdt en hård blæst, dannes en knast, og sand styrke er, i sidste ende, sporet efter at have bøjet godt."},"ICON-1142":{"nm":"Træstamme","de":"I de fældede årringe ligger hundrede forår og vintre stablet rundt i rundt. De år, et enkelt træ har levet, ligger nu hele der og venter stille på sin tur til at blive husets bjælke."},"ICON-1143":{"nm":"Tømmer","de":"Hver gang høvlen glider hen over det, blotlægges et duftende lag af årer. Mens det ru træ bliver glat, hober savsmuldet sig op på gulvet som gult sne. Den tilhuggende hånd vækker dets nytte."},"ICON-1144":{"nm":"Planke","de":"Den lægger gulv, tømrer en bænk, omslutter et hegn. Når de retvinklet skårne brædder samles, et efter et, rejser der sig endelig et sted for mennesker at bo. Almindelige ting hober sig op og bliver til et hjem."},"ICON-1145":{"nm":"Bambus","de":"Hul indeni, men opret over for vinden. Gamle lærde ønskede at ligne dens beslutsomhed — den brydes ved hvert led og skyder atter frem. Her står noget, der er så meget mere oprejst, netop fordi det er tomt."},"ICON-1146":{"nm":"Kork","de":"Tryk den ned, og slip, så svulmer den tilbage til sin oprindelige tykkelse. Se på denne struktur, let og alligevel sejlivet, og man forstår, at blødhed langtfra er svaghed. Fra flaskepropper til opslagstavler holder den stille tingene oppe."},"ICON-1147":{"nm":"Græs","de":"Trådt ned, rejser det sig igen med næste regn. En grøn stædighed, der dækker en hel mark uden et eneste navn. Undervurder ikke dets litenhed — det, der først bebuder foråret, er altid denne lave plads."},"ICON-1148":{"nm":"Halm","de":"Det, der bliver tilbage gyldent på marken efter høstens ende. Flettet blev den til tag, spredt ud blev den til et varmt leje. Hjertet, der, efter at have givet hvert eneste korn, dækker mennesket til det sidste."},"ICON-1149":{"nm":"Siv","de":"Når vinden strejfer forbi, hvisker og hvisker det, og hele flodbredden synger som ét. En stængel, der, hul indeni, græder desto længere. Sivet skammer sig ikke det mindste over, at netop dets svajen er dets sang."},"ICON-1150":{"nm":"Bomuld","de":"Når den modne kapsel springer op med et lille smæk, blomstrer en lille sky frem. Dette lette, bløde dun bliver til tråd og bliver til stof og varmer stille nogens skuldre på en kold vinternat."},"ICON-1151":{"nm":"Fåreuld","de":"Gnid den mod hånden, og en fedtethed bliver siddende, mens varmen roligt bliver. Kappen, fåret svøbte om sig selv for at udholde de kolde bjerge. Den klippede varme flytter nu videre ind i menneskets vinter."},"ICON-1152":{"nm":"Tråd","de":"Tynd, næsten usynlig, er det dog altid denne, der syr to faldne ender sammen igen. Svag som en enkelt streng, men flettet sammen bliver den til et helt stykke stof. I arbejdet med at forbinde betyder tykkelsen intet."},"ICON-1153":{"nm":"Stof","de":"Islæt og kæde krydser hinanden utallige gange og former en hel bredde. Det er resultatet af tråde, der ville rakne alene, men som holder fast i hinanden. At jo tættere vævningen, jo varmere den er, gælder også helt nøjagtigt mellem mennesker."},"ICON-1154":{"nm":"Læder","de":"Jo mere det bruges, jo mere trænger hændernes spor ind, og lidt efter lidt kommer det til at ligne sin ejer. Mens den oprindelige stivhed slides ind, dybnes farven, og strukturen blødgøres. Den glans, tiden har indridset, kan intet efterligne."},"ICON-1155":{"nm":"Fjer","de":"Så let, at man ikke mærker vægten, selv lagt i håndfladen. En enkelt tråd, der bærer erindringen om at have fløjet gennem himlen, netop som den var. Glem endelig ikke, at det letteste steg højest."},"ICON-1156":{"nm":"Muslingeskal","de":"Bedstemors ord om at holde den til øret dukker pludselig op. På dens indre regnbueskær er havet, man forlod, indridset som ét — så selv en tom skal bærer bruset fra en svunden tid."},"ICON-1157":{"nm":"Koral","de":"Hård som sten, men engang var den med sikkerhed en åndende koloni. I det langsomme hav bruger den hundredvis af år på at strække grenene ud. Den stærkeste gren gror først frem efter den længste ventetid."},"ICON-1158":{"nm":"Perle","de":"Ude af stand til at udholde irritationen fra et enkelt sandkorn, hyllede østersen det stille ind i lys. At runde smerten af på denne måde gør den så skinnende — en lille trøst, havet rækker frem."},"ICON-1159":{"nm":"Tang","de":"Et grønt bånd, der hænger glat ned over strandklipperne ved lavvande. Grib fat i det, og en fiskeagtig havlugt slår én i møde. Rodløs, med kroppen overladt til strømmen, passer havet stille sin have."},"ICON-1160":{"nm":"Nori","de":"Hold et sort ark kort hen over ilden, og det bliver grønt og spreder en ristet duft. Den morgen, hvor man rullede det om nykogt ris. Tyndt som det er, omfavner det rigeligt lykken i ét måltid."},"ICON-1161":{"nm":"Salt","de":"Jeg er den hvide krystal, havet lod blive tilbage i solen. En enkelt knivspids dybner en flad suppe, men glider hånden, dækker jeg over enhver smag. Kun en fingerspids, der kender den rette mængde, kan bruge mig ret."},"ICON-1162":{"nm":"Glasskår","de":"Først der, hvor det gik i stykker, bøjer det endelig lyset til en regnbue. Et talent, det aldrig kendte, mens det var helt. At selv noget knust har en del af sollys tilbage at give — det fortæller skåret, der ligger ved vinduet, stille."},"ICON-1163":{"nm":"Glas","de":"At være gennemsigtigt betyder ikke kun, at der intet er at skjule. Det har udslettet sin egen skikkelse for at lade lyset passere helt igennem. Selv i at ligge der usynligt findes der en kølig sirlighed, når en hånd rører det."},"ICON-1164":{"nm":"Glasflaske","de":"Den skal være tom indeni for at kunne rumme noget. Syltetøj, en håndfuld vilde blomster eller et sammenfoldet brev — dens navn skifter med det, der kommer ind. Et kar, der ikke frygter tomhed, er det mest gavmilde."},"ICON-1165":{"nm":"Tom flaske","de":"Jeg holder af stilheden, der indfinder sig, efter den sidste dråbe er drukket. Nogen smider mig væk; nogen skyller mig og sætter mig på vindueskarmen for at fylde mig med sollys. At finde brug igen, hvor noget er sluttet — det er de tømtes andet liv."},"ICON-1166":{"nm":"Papir","de":"Jeg ligger bredt ud, hvidt og parat til at nedskrive hvad som helst. Det er altid mig, der ser længst ind i hjertet på den, der tøver ved den første linje. Den blanke sides tålmodighed rækker et håndsbred dybere end blækket."},"ICON-1167":{"nm":"Gammelt papir","de":"Gulnet er ikke alderdom, men udholdenhed. I hver fold er varmen fra de hænder, der foldede det ud og læste, trængt ind. Gammelt papir skriver, for ikke at blive glemt, den forbiflydte tid ned i sin egen farve."},"ICON-1168":{"nm":"Blæk","de":"Det begynder som en enkelt dråbe, bliver til en sætning, og bliver, når det tørrer, tilbage som et løfte. Løbet ud, er det sporet af den dag, netop som det løb ud. Da mit job er at gøre ting uigenkaldelige, trykker folk mig ned én gang til, med omhu."},"ICON-1169":{"nm":"Jernmalm","de":"En sten, der sov en rød søvn under jorden. Først efter at have passeret gennem ild giver den endelig slip på jernet i sig. Hårdhed er ikke hård fra begyndelsen — det er et navn, den modtager, efter den har gennemgået heden."},"ICON-1170":{"nm":"Jernbarre","de":"Først da malmen havde udholdt ilden, kølede den af til én klump. Denne kolde, tunge form bliver til en bro, et sværd, en hakke. Fordi min brug endnu ikke er afgjort, kan jeg blive til hvad som helst."},"ICON-1171":{"nm":"Kobbermalm","de":"Jeg kom ud af jorden iklædt en grøn-æble-farvet rust. Smelt mig, og klokker ringer, statuer rejser sig, ledninger strømmer. Selv mens jeg sov i den bælgmørke jord, ventede jeg altid på min tur til at blive kaldt til noget."},"ICON-1172":{"nm":"Kobberbarre","de":"Får den lov at blive ved siden af længe nok, syr den selv en blå dragt til sig selv. Nogle kalder den farve en fejl, andre kærtegner den som årenes mønster. Det metal, der ikke skammer sig over sin skiftende farve, er det, der elskes længst."},"ICON-1173":{"nm":"Guldmalm","de":"Et enkelt korn, mødt ved at sigte flodsand igen og igen. Dyrebart ikke fordi det er sjældent, men fordi det aldrig forandrer sig. De gamle trykkede det i hånden som et pant og bad om at ligne et hjerte, der ikke ruster."},"ICON-1174":{"nm":"Guldbarre","de":"Den ligger som én klump, hverken falmet eller rustet. Den har hørt mest til menneskers grådighed, men selv begærer jeg intet. Blot en tung tavshed, tro alene mod opgaven at skinne."},"ICON-1175":{"nm":"Skrot","de":"Det er ikke udtjent — det venter på sin næste anvendelse. Brækkede søm og buttede dåser samles sammen og møder atter den hede ild. For mig betyder ordet \"kasseret\" blot: at hvile en stund."},"ICON-1176":{"nm":"Skrue","de":"Alene kan jeg intet udrette. Først når jeg drejes fast ind og binder to plader tæt sammen, spiller jeg endelig min rolle. Kunsten ved en lille krop, der holder på noget stort — selv i den strammende kraft ligger der omhu."},"ICON-1177":{"nm":"Søm","de":"Én gang banket i, viger jeg sjældent tilbage. Med hvert hammerslag er det, der dybnes, ikke et sår, men et løfte. Hvis det handler om at binde noget fast sammen, giver jeg gerne mit hoved."},"ICON-1178":{"nm":"Tandhjul","de":"Jeg skubber til naboens tænder og drejer sammen med den. Jeg prøver ikke at fare hurtigt af sted alene, men kender kunsten at følge tempoet ved siden af. Som et ur, hvis tid kun flyder, når tænderne griber ind i hinanden, tror jeg, at samhørighed i sig selv er bevægelse."},"ICON-1179":{"nm":"Fjeder","de":"Jo mere den presses, jo mere samler den kraften indeni til at vende tilbage. At bøje sig er ikke at give op, men en forberedelse til at rette sig ud igen. En lille spiral, der springer tilbage lige så meget, som den optog stødet — hvor smidighed i sig selv er styrke."},"ICON-1180":{"nm":"Ledning","de":"Udenpå en stille kappe, indeni en vej, der flyder uden hvile. Fra usynlige steder bærer den lys og lyd videre. Som en hånd, der stille forbinder ting bag scenen, er den en passage, der er så meget mere pålidelig, netop fordi den ikke ses."},"ICON-1181":{"nm":"Batteri","de":"Det samler en halv dags klare lys, bid for bid, inde i sin lille krop. Brugt op, fyld det bare igen, siger det, og opfatter aldrig tomhed som en afslutning. Det rummer en lille aften til at lyse op i nogens lange nat."},"ICON-1182":{"nm":"Elpære","de":"En enkelt tynd tråd gløder rød og skubber mørket tilbage. Den brænder ikke sin egen krop for at varme rummet, men for at lyse det op. Varmest i det øjeblik den tændes, og derfor lysest — en lille sol af et enkelt øjeblik."},"ICON-1183":{"nm":"Linse","de":"Den samler det spredte lys og sætter det skarpt i ét punkt. Den kalder stille både den fjerne stjerne og den lille skrift på håndfladen frem. Idet den hjælper synet, skjuler den selv sin egen skikkelse — en klar, rund kobler."},"ICON-1184":{"nm":"Gummi","de":"Trykket eller strakt vender det til sidst tilbage til sin plads. Selv de, der hånede det for at være blødt, vælger mig på en regnvejrsdag. Arbejdet med blidt at optage et hårdt stød — sejhed lever selv i denne blødhed."},"ICON-1185":{"nm":"Plaststykke","de":"Et lille stykke, brækket af fra hovedkroppen. Det var lige ved at blive smidt ud, men saml flere sammen, og det bliver til noget nyt igen. Ikke let fordi det er lille, men i stand til at nå langt, fordi det er let — en del af noget."},"ICON-1186":{"nm":"Reb","de":"Først når mange tråde snoes sammen, bliver det til én snor. Alene løsner det let, men flettet trækker det en båd og binder en byrde. En gammel knude af samarbejde, ru mod håndfladen, blevet sejere af at være snoet sammen."},"ICON-1187":{"nm":"Sejldug","de":"Den hader ikke vinden, men tager den fuldt til sig. Kun stram og bugnende sender den skibet langt, så selv modvind bliver til min styrke. Måden at gå fremad ved at omfavne fremfor at modsætte sig det voldsomme, lærte jeg ved havet."},"ICON-1188":{"nm":"Ankerfragment","de":"Det er blot et hjørne af et anker, men det husker den vægt fuldt ud. Dagene, hvor det greb fat i den dybe bund og standsede et skib. Selv nu, afbrækket, er det et tungt fragment, der kender vægten af at blive."},"ICON-1189":{"nm":"Skibssøm","de":"Et søm, der holdt et bølgende dæk fast, punkt for punkt. Selv rustet rødt af saltet slap det aldrig sin plads til det sidste. At holde fast i noget flydende kræver også vilje."},"ICON-1190":{"nm":"Vandtæt dug","de":"Den brokker sig ikke over arbejdet med at stoppe regnen. Den tager stille imod det, der vælter ned ovenfra, og holder det, der er nedenunder, tørt. Ikke prangende, men et solidt lag, der dækker nogens byrde, så den ikke bliver våd."},"ICON-1191":{"nm":"Farvestof","de":"Sivet stille ind i almindeligt bomuldsstof bliver det først til en farve. Indigo eller krap — mødre i gamle dage farvede deres fingerspidser, mens de klædte stoffet i farve. Selv i arbejdet med at synke ind og trænge igennem findes der en dybde, der næppe falmer."},"ICON-1192":{"nm":"Duftolie","de":"En enkelt dråbe, og en vid mark folder sig straks ud og fylder hele rummet. En gæst, der ankommer først, selvom den er usynlig for øjet. Et landskab, der rører næsen først, mens det lumsk trækker i sømmen på sovende minder."},"ICON-1193":{"nm":"Voks","de":"Modtager den varme, flyder den; køler den af, størkner den og holder sin form. Den bevæger sig mellem blødhed og fasthed og aftegner stille alt. Et ømt materiale, der forsegler, lukker og polerer — og skifter udtryk med temperaturen."},"ICON-1194":{"nm":"Stearinlys","de":"Det smelter langsomt sin egen krop for at oplyse et hjørne af mørket. Når det er brændt helt ned, er kun dets forkortede højde tilbage, men den tid, det varmede nogens nat, forsvinder aldrig. En opret væge, der kender kunsten at skinne, mens den bliver mindre."},"ICON-1195":{"nm":"Kompost","de":"Rådnende ting samles sammen og bliver til den mest frugtbare jord. Kasserede skaller og tørre, faldne blade bliver til forårets nye spirers måltid. På netop det sted, man troede var slut, finder næste liv stille sit første åndedrag."},"ICON-1196":{"nm":"Ris","de":"Der skal firs og otte berøringer af hånden til, før man kan holde ét korn i hånden. Fra plantning til tærskning er en bondes hele år rummet fuldt og helt i dette lille korn. En dampende skål ris er i sig selv nogens fire årstider."},"ICON-1197":{"nm":"Brune ris","de":"Kun det yderste skal er let pillet af, mens dens oprindelige farve er bevaret, som den var. At de bliver mere nøddeagtige, jo mere man tygger, er smagen af en ærlighed, der ikke har travlt. Kornets faste stædighed, der nægter at blive slebet glat og beholder sin ru struktur."},"ICON-1198":{"nm":"Hvede","de":"Den husker den gyldne mark, der bøjede hovedet samlet i vinden. Den bliver til brød og nudler og melboller og varmer borde alle vegne i verden. Et korn, der, netop fordi det er så almindeligt, har sivet desto dybere ind i menneskers liv."},"ICON-1199":{"nm":"Hvedemel","de":"Først efter at være blevet til et fint, hvidt pulver gør det sig endelig klar til at blive hvad som helst. Møder det vand, svulmer det op; møder det ild, bliver det mørt. Uden fastlagt form er det en mild grundmasse, der får den skikkelse, hænderne ælter det til."},"ICON-1200":{"nm":"Dej","de":"Mel og vand smelter sammen til én klump under håndfladen. Jo mere den æltes, jo mere sej bliver den; jo længere man venter, jo mere bugnende hæver den sig. Skynder man sig, bliver den sej, så tiden for hævning alene kan ikke fremskyndes, siger det gamle bageri."},"ICON-1201":{"nm":"Rasp","de":"Når du børster det fine, hvide støv af fingerspidserne, er ærmerne pludselig også blevet hvide. Som panering bliver det sprødt, og hobet sammen ligner det det første snefald. Det er det letteste spor et brød efterlader efter bagningen, men selv de mindste ting vokser sig nyttige."},"ICON-1202":{"nm":"Pasta","de":"I det øjeblik du spreder en håndfuld som en vifte i det kogende vand, krydser en fjern solskin ind i køkkenet. De lange strimler er en opgave for håndleddet, og al dente er tålmodigheden ved at vente, mens det stadig er en anelse for lidt kogt. Se den glans, der snor sig rundt og rundt om gaflen."},"ICON-1203":{"nm":"Instant nudler","de":"En pose luret op på komfuret ved daggry, al scenesminken tørret af. De tre minutter, det tager nudlerne at blive bløde, er dagens mest private tid. Spændingen køler af sammen med din ånde, mens du puster på dem, og bag dugede briller slutter dagen stille."},"ICON-1204":{"nm":"Riskage","de":"Først når risen har udstået morterens hamren, bliver den til riskage. Enkel, som injeolmi, som songpyeon – det samme korn får hundrede navne alt efter de hænder, der former det. Sat frem ved en fest taler den til hjertet før munden; den smager bedst, når den deles."},"ICON-1205":{"nm":"Suppe-riskager","de":"Skær en riskagerulle skråt over, og skiverne bliver runde som små mønter. Er det riskage, der flyder i den hvide bouillon, eller et rundt lille ønske? At tømme en skål nytårsmorgen lægger et år til din alder – en øm måde, dette lands måde at tælle på."},"ICON-1206":{"nm":"Kartoffel","de":"Bank jorden af, og et rundt ansigt kommer til syne. En rodknold, der voksede sig tavst tyk i vindene fra Gangwons skråninger – luftig når den dampes, sødlig når den steges. Selv på dage med tomme lommer fyldte den familiens maver ærligt."},"ICON-1207":{"nm":"Sød kartoffel","de":"Da tromlen med ristede søde kartofler dukkede op ved gyden, var det vinterens begyndelse. Fold stanniolen fra, og den gule damp varmer fingrene først; sødmen er rodens belønning for at have udstået kulden. Lige til at puste på, dele i to og dele varmen med."},"ICON-1208":{"nm":"Gulerod","de":"Et enkelt orange spyd, der borer sig lige ned gennem jorden. Man skulle tro, kun kaniner elskede den, men sauter den, og en skjult sødme vågner, kom den i suppen, og den tilføjer også farve. De gamle, der sagde, den var god for øjnene, havde stort set ret."},"ICON-1209":{"nm":"Daikon","de":"Én hvid, tung rod, og vintermaden er dækket. Isnende kold som dongchimi, forfriskende som radisesuppe, sprød som kkakdugi. Intet går til spilde – selv de grønne toppe tørres under tagskægget og gemmes som siraegi – en nøjsom grøntsag."},"ICON-1210":{"nm":"Løg","de":"Skræl skindet af, og en enkelt tåre triller ned. Det skarpe, sviende kød bliver sødt som en løgn, så snart det møder varm olie. Dens navn står skrevet på første linje i næsten enhver koreansk ret – den stille hovedrolleindehaver, der tavst lægger fundamentet for smagen."},"ICON-1211":{"nm":"Forårsløg","de":"Drys de tyndt snittede, hvide rødder og grønne toppe over bouillonen, og først da føles skålen virkelig færdig. Stil den tiloversblevne rod i et glas vand, og den skyder op igen – en lille vindueskarm-have for den huslige sjæl."},"ICON-1212":{"nm":"Hvidløg","de":"Seks fed samlet i en cirkel danner ét helt løg. Den skarpe rod, der, siges det, forvandlede en bjørn til en kvinde. Hak det med bladets flade, og duften blusser straks op; uden en håndfuld af det giver hverken kimchi eller gryderet nogen mening overhovedet."},"ICON-1213":{"nm":"Ingefær","de":"En lille, knudret rod som en samling knuder. Blot en enkelt skive dæmper den fiskede lugt og varmer en kold krop indefra. På nætter, hvor du stønnede af forkølelse, begyndte den varme kop, trukket med honning, med netop denne skarpe, prikkende smag."},"ICON-1214":{"nm":"Kinakål","de":"Salt de tætpakkede blade, og først da åbnes kimchiens første kapitel. Sent på efteråret hobede den sig op som bjerge i hver eneste gård. At hele familien samledes for at lave et fad var et løfte om at komme igennem den lange vinter sammen."},"ICON-1215":{"nm":"Hvidkål","de":"Skræl de runde, lagdelte blade af, ét ad gangen, og der er ingen ende – før du ved af det, falder sindet til ro. Blancheret er den mør, sauteret sødlig. Bag en jævn ydre skal gemmer denne grøntsag en uventet ømhed."},"ICON-1216":{"nm":"Icebergsalat","de":"Læg en skive kød i det hule blad, tilføj en klat ssamjang, og prop en fuld mundfuld i. Ved en rundkreds af mennesker, der pakker og spiser sammen, lader enhver stiltiende formaliteten falde – dette er intet mindre end det grønnes gæstfrihed."},"ICON-1217":{"nm":"Bladsalat","de":"Det første blad, der springer frem i et hjørne af haven. Pluk det, og det gror igen, og fylder bordet hele sommeren. Den friske, grønne duft – skyllet i koldt vand og pakket sammen med hånden – er for nogen hele smagen af hjemmet."},"ICON-1218":{"nm":"Spinat","de":"Den tegnefilmsgrønne, der gav et sus af styrke, når dåsen blev tømt. Blancheret svinder den ind til en håndfuld, men duften og kraften forbliver intakt. God, når den vendes med hånden, eller rørt i en skål misosuppe – en grøntsag, der aldrig bør tages let, blot fordi den er almindelig."},"ICON-1219":{"nm":"Bregneskud","de":"Knæk de sarte skud, som forårsbjerget skænker, kog dem, og tør dem så. Kun efter al det lange slid når de frem til forfaderbordet eller bibimbap-skålen. Lagdelt med omsorg for al den ulejlighed, det kræver, er den en dyrebar urt, bjerget opdrættede over én sæson."},"ICON-1220":{"nm":"Vilde bjergurter","de":"Tilsyneladende navnløse, og dog bærer hver sin egen duft – forårets gave. Bedstemors hænder ved med ét blik, hvilket blad på bjergstien er godt at spise. I én kurv med grønt følger en hel sæson med, duft og det hele."},"ICON-1221":{"nm":"Gråbynke","de":"Den bittert-duftende urt, der først bryder gennem den frosne jord. Formet til riskage går forårets lys lige i munden. Ved årets første måned troede man, at man kunne koge den til suppe og holde årets ulykke fra døren, så foråret kom altid med denne duft."},"ICON-1222":{"nm":"Perillablad","de":"Et enkelt blad er nok til at farve hele munden dybt med sin duft. Kombiner det med gylden, grillet flæskesteg, eller læg det lagvis i soja, og en skål ris forsvinder på et øjeblik. Denne særegne aroma føles kun rigtig ved dette lands bord."},"ICON-1223":{"nm":"Grøn peberfrugt","de":"En hul, grøn frugt, der knækker med et sprødt bid. Den svage bitterhed vækker en sløv appetit, og sauteret i olie bliver farven endnu klarere. Skåret fint og drysset ud gør den øjeblikkeligt enhver ret friskere."},"ICON-1224":{"nm":"Peberfrugt","de":"Rød, gul, orange – farver som lyskryds, der fylder en hel kurv. Bid i en rå, og den søde saft drypper ud; alene farven lyser bordet op. Ordsproget om, at en køn grøntsag også vækker appetitten, passer her helt præcist."},"ICON-1225":{"nm":"Tomat","de":"Den runde røde, evigt omdiskuteret – frugt eller grøntsag? Simret længe bliver smagen dybere; spist rå er den uforlignelig frisk. Den er frugten, der samler højsommerens sol mest ærligt, så ét bid sprænger en hel lys eftermiddag."},"ICON-1226":{"nm":"Agurk","de":"Den grønne, der køler sommerens hede mest forfriskende. Flyd den i kold suppe, og munden bliver sval og sprød; syltet som sobagi vågner sprødheden til live. På kvælende dage kan du endda skære den tyndt og lægge den over øjnene – kølig indeni og udenpå."},"ICON-1227":{"nm":"Græskar","de":"Den hænger rundt for enden af rankeen og fylder sig langsomt med sødme frem mod sen efterår. Simret blødt bliver den til en gul grød, der stiller maven; stegt bliver den til gylden jeon. Hængt op under tagskægget tjener den som et pålideligt spisekammer hele vinteren."},"ICON-1228":{"nm":"Courgette","de":"Den lysegrønne, der svulmer dag for dag i sommerhaven. Skåret i tern i sojabønnegryderet, stegt gylden som jeon – så mør, at den er skånsom selv for et lille barns mund. Almindelig, og netop derfor endnu mere velkommen: en fast gæst ved højsommerens bord."},"ICON-1229":{"nm":"Aubergine","de":"En aflang frugt, der skinner glinsende i violet. Suger den olie til sig, bliver den uendeligt blød, dampes den igennem, bliver strukturen fin som silke. Nøjsom af udseende, men den passer godt til hvad som helst – bordets milde birolle."},"ICON-1230":{"nm":"Majs","de":"Gule kerner på række, pænt side om side. En sommersnack dampet i gryden, pustet på og bidt i; også det velkomne tegn på, at markerne er modnet. Inde i det bløde bundt af silke er sødmen pakket helt til randen."},"ICON-1231":{"nm":"Sojabønne","de":"Små, hårde perler drikker vand natten over og svulmer op. Malet fint til sojamælk, gæret blødt til jang – det meste af dette lands proteinindtag begyndte lige her. Læg én bønne i jorden, og den vender tilbage som en hel plante."},"ICON-1232":{"nm":"Tofu","de":"Når sojabønner drikker vand, males og stivner, bliver de til en hvid blok med lige, skarpe kanter. Blød og ubeskeden insisterer den aldrig på sin egen farve i nogen suppe. Den falder sagte sammen selv ved en skes berøring – en mad, hvis dyd er selve enkelheden."},"ICON-1233":{"nm":"Adzukibønne","de":"Kog de små, røde perler grundigt igennem, og en dybt mørkerød sødme trækker kraftigt ud. På den længste nat drev en varm skål adzukigrød engang både kulden og onde ånder væk – den følelse bor der stadig i den. Lagvis gennem den dampede kage var den rødme intet mindre end hengivenhed."},"ICON-1234":{"nm":"Adzukibønnepasta","de":"Kogte adzukibønner, mast fint og reduceret igen og igen til en blød fyldning. En ske mellem brød, inde i riskage, oven på knust is – én tråd sødme varmer selv gamle minder. Al den lange tid, brugt på at si og reducere, bliver til selve sødmen."},"ICON-1235":{"nm":"Svamp","de":"Efter regnen klarer op, løfter den lydløst hovedet i skovens dunkle skygge. Jordens håndværk, der dyrker sin egen duft uden en eneste håndfuld sol. Tilsæt blot en knivspids til suppen, og en dyb umami trækker ud helt uden kød – en hemmelighed, skoven holder skjult."},"ICON-1236":{"nm":"Shiitakesvamp","de":"En brun paraply med hatten spredt vidt ud. Tørret helt igennem i solen bliver duften mangedoblet, så en enkelt tørret hat sagtens kan bære en hel gryde bouillon. En solid søjle ved det vegetariske bord og en gammel favorit hos den, der kender den dybe smag."},"ICON-1237":{"nm":"Matsutake","de":"Dybt i en efterårsfyrreskov løfter den kun forsigtigt hovedet ved siden af fyrretræerne. Den kan ikke dyrkes og skal findes til fods, hvilket gør dens duft desto mere kostbar. Let grillet med blot et strøg salt kommer et stykke skov ind i munden."},"ICON-1238":{"nm":"Kongeøstersvamp","de":"Riv den tykke stok op langs fibrene, og sejheden ligger lige i hånden. Den gror robust hele året rundt, så den aldrig er langt fra bordet. Grillet eller sauteret – i dens rundhåndede kød er en ubesværet mæthed pakket helt til randen."},"ICON-1239":{"nm":"Jordbær","de":"Yderst i et drivhus, der har udstået vinteren, modner den rødt allerførst. Ét bid er syrligt-sødt, ligesom tidligt forårs første hilsen. Læg blot ét, rundt bær oven på en kage, og selv en helt almindelig dag bliver næsten til en mærkedag."},"ICON-1240":{"nm":"Blåbær","de":"Pop den, og en klar syrlighed breder sig lyst gennem hele munden. Saml de små violette perler op, én ad gangen, og før du ved af det, er bakken tom; drys dem over hvid mælk, og en lille nattehimmel udfolder sig lige der."},"ICON-1241":{"nm":"Æble","de":"Bid i det, og efteråret splintres med et sprødt knæk. Den rødme, plantageskolens bedstemor tørrede af med forklædet og rakte frem, er en farve, der kun opstår ved længe at have rummet solskin. Jo hårdere den er, desto bedre ved den, hvordan den holder sig sød til sidste bid."},"ICON-1242":{"nm":"Pære","de":"Skræl skindet af, og fingerspidserne bliver kølige først. Forreste række på Chuseok-offerbordet – i det øjeblik den kølige, søde saft fylder munden, sætter en lille smule af efterårets natvind sig stille ved siden af dig."},"ICON-1243":{"nm":"Fersken","de":"Hvor hver ferskenblomst faldt, tager en dunet sommer form. Tryk let, og duften spreder sig først; i det øjeblik du bider i, følger hele sæsonen med ind i munden."},"ICON-1244":{"nm":"Vindruer","de":"Violette perler hænger som én klase og læner sig skulder mod skulder. Pop en, og det syrlige kommer først, det søde et halvt taktslag efter – som et ordentligt kor, sommerens sidste dage kalder frem."},"ICON-1245":{"nm":"Grønne vindruer","de":"Det lysegrønne lader solskinnet passere lige igennem, så en lampe tændes i hver eneste perle. Kernefri og ren forfriskning, en sødme helt uden overskud, som en frisk, første frase."},"ICON-1246":{"nm":"Citron","de":"Rids det gule skind med en negl, og duften vækker næsens spids med et smæk. Én dråbe, og læberne trækker sig sammen af sig selv, men for enden af den syrlighed er der et underligt hjørne, hvor hele dagen lysner."},"ICON-1247":{"nm":"Lime","de":"Mindre og mørkere grøn end en citron, denne lille frugt hilser først med sin skarpe, friske duft. Én skive vækker selv lunkent vand på et øjeblik – en lille, men sej håndfuld forfriskning."},"ICON-1248":{"nm":"Appelsin","de":"I det øjeblik du skræller den, sætter duften af solskin sig på fingrene. Læg en båd ad gangen i munden, og pop, pop – små balloner af sød saft brister, og det runde ruller endda humøret rundt."},"ICON-1249":{"nm":"Mandarin","de":"Husker du den smag – at pille dem med fødderne begravet under den varme dyne en vintersnat? Duften, der bredte sig fra under neglene, farvede hele værelset gult. Én pose er nok til et påskud for familien til at samles."},"ICON-1250":{"nm":"Banan","de":"Der var dage, hvor jeg klarede et måltid med den ene gule frugt, der trillede ud af tasken i et hjørne af øvelokalet ved en sulten daggry. Blød, sød og mættende – den mest kærlige nødløsning."},"ICON-1251":{"nm":"Ananas","de":"Du skal forbi et lag pigget skal, før det gule kød viser sig. Hold en bid i munden, og det sødt-syrlige stikker tungen, mens duften af et sydhav svæver om læberne."},"ICON-1252":{"nm":"Mango","de":"Del den modne frugt med hænderne, og en klæbrig, sød duft væder fingrene. Mens det dybe gule smelter og forsvinder i munden, glider en sød drøm forbi, som en kort sommermiddagslur."},"ICON-1253":{"nm":"Kokosnød","de":"Ryst den hårde skal, og du hører vand skvulpe indeni. Knæk den op – hvidt kød og kølig saft – en lille krukke, der rummer et fjernt hav helt for sig selv, gyngende indeni."},"ICON-1254":{"nm":"Dragefrugt","de":"Dens lyserøde, skælklædte ydre får dig først til at tøve, men del den, og det hvide indre er prikket med små sorte frø. Beskeden i smag, men prangende i klædedragt – en snu spilopmager, hvor det ydre og indre er stik modsatte."},"ICON-1255":{"nm":"Kiwi","de":"Skær det dunede brune over på midten, og en grøn juvel kommer til syne. Sæt en ske i tværsnittet, hvor sorte frø ligger som stjerner, og én syrlig mundfuld ryster søvnen af dig."},"ICON-1256":{"nm":"Kylling","de":"Læg den i en olieret pande, og den gyldne sydelyd steger først. Mild og mør glider den let ind ved ethvert bord – et fast indslag ved et ubesværet måltid."},"ICON-1257":{"nm":"Svinekød","de":"På grillen syder det, mens fedtet spytter og bruner. På de aftener med firmafester, hvor man proppede en fuld mundfuld ind, pakket i et salatblad med en klat ssamjang, varmer den fyldige smag hele bordet."},"ICON-1258":{"nm":"Oksekød","de":"Langs hver røde fiber er fedtet fint marmoreret og skinner. Læg det på en opvarmet stenplade, og duften fylder rummet først; i det øjeblik en skive kommer i munden, løsner dagens træthed sig stille."},"ICON-1259":{"nm":"Bacon","de":"På den morgenlige pande bliver det sprødt, mens fedtet danser. Alene den salte duft trækker selv de sent sovende familiemedlemmer, gnidende sig i øjnene, ind i køkkenet – et måltid, duften kalder til først."},"ICON-1260":{"nm":"Pølse","de":"De indridsede snit springer vidt op, mens saften bryder ud. Den røde blæksprutteform, der holdt sit hjørne af madkassen, var en lille luksus, barndommens frokostpauser nød."},"ICON-1261":{"nm":"Pepperoni","de":"En rund, stærk skive krøller sig sammen fra kanten oven på den varme ost. Samler der sig en smule olie, er det selve toppunktet for hele pizzaen – lille, men fyldig og intens i sin tilstedeværelse."},"ICON-1262":{"nm":"Burgerbøf","de":"Form den tykt, læg den på grillen, og den bruner fra kanten og indad. Læg grøntsager mellem en presset og grillet skive, og en mæthed, der passer i én hånd, er fuldendt."},"ICON-1263":{"nm":"Æg","de":"Knæk det op, og blommen glider ud som en rund, lille sol. Fint rørt i frisklavet ris, fint som den gule stribe inde i gimbap – det mest almindelige og derfor det mest kærlige protein."},"ICON-1264":{"nm":"Mælk","de":"En kold flaske stillet ved døren ved daggry – dagen begyndte ofte med den kølighed mod håndfladen. Damper, når den varmes, sødlig, når den køles – en hvidhed, der altid holder sig ved din side."},"ICON-1265":{"nm":"Ost","de":"En gul skive smuldrer langsomt sammen oven på det varme brød. Hjertet, der venter på det ene øjeblik, den trækker sig lang ud – jo mere den smelter, jo dybere og rigere bliver dens fylde."},"ICON-1266":{"nm":"Cheddarost","de":"Den dybe orange farve bebuder ved første blik en salt smag. Skær den tyndt ind i en toast, og umamien breder sig gennem hele munden – lige så tydelig i smag, som den er tydelig i farve."},"ICON-1267":{"nm":"Smør","de":"Læg en klump i en opvarmet pande, og den smelter væk, mens en fyldig damp stiger op. Smurt på brød, rørt i ris – en gul magi, der gør alt, den rører ved, en anelse blødere."},"ICON-1268":{"nm":"Flødeskum","de":"Jo mere du pisker, desto mere svulmer det tynde, hvide op til faste skyer. I det øjeblik du lægger en skefuld oven på en kage, lysner en helt almindelig eftermiddag som en lille fødselsdag."},"ICON-1269":{"nm":"Yoghurt","de":"Sæt skeen i, og det syrlige hvide løfter sig glat. Bland en frugtstump i, og morgenen bliver lettere; én kop, og maven falder roligt til ro – smagen af en blid begyndelse."},"ICON-1270":{"nm":"Makrel","de":"Læg den på grillristen, og fedtet knitrer, mens en røg, både fisket og fyldig, fylder køkkenet. De hænder, der pillede benene ud og lagde den over risen – den dybeste omsorg gemt i et helt almindeligt måltid."},"ICON-1271":{"nm":"Laks","de":"Lyserøde fibre ligger lagvis oven på hinanden. Serveret koldt løsnes den blødt i munden, grillet trænger fedtet igennem, fyldigt – en fast smag, der svømmede hjem imod et fjernt hav."},"ICON-1272":{"nm":"Tun","de":"Åbn dåselåget, og en salt duft stiger op med det samme. Der var tider i et lille lejet værelse om natten, hvor én dåse, rørt i ris eller pakket i tang, blev til et solidt måltid."},"ICON-1273":{"nm":"Torsk","de":"Det klare kød er så mildt, at kogningen straks trækker en forfriskende bouillon ud. En hvid fisk, der udstod den knivskarpe vind fra en vinterhavn – én varm skål suppe, og selv iskolde hænder tør langsomt op."},"ICON-1274":{"nm":"Reje","de":"Krøl ryggen rundt, og mens den koges, farves det grå rosa. Et sprødt pop af spændstighed og en fyldig duft – pil dem og spis dem én ad gangen, og pludselig er tallerkenen tom."},"ICON-1275":{"nm":"Krabbe","de":"At pille det hvide kød ud af den hårde skal er en lille tålmodighedsøvelse. Den bid, du til sidst putter i munden efter al den ulejlighed, er sødlig – et helt efterårshav, der kommer ind i munden."},"ICON-1276":{"nm":"Blæksprutte","de":"På grillen krøller den sig rund og sender en fyldig duft op. En sej mundfuld, dyppet i chilisauce, og det salte hav følger med."},"ICON-1277":{"nm":"Muslinger","de":"I den klare bouillon åbner de munden og giver stille deres duft fra sig. Mens det bobler og simrer, breder havets duft sig, og én slurp varmer og løsner en forkølet mave."},"ICON-1278":{"nm":"Fiskekage","de":"Dyp den på pinden i den varme bouillon, og dampen stiger krøllet op. Foran en gademadsvogn på en kold dag, hænder der holder bouillon i et papkrus og puster på det – en lille trøst, gyden rækker frem."},"ICON-1279":{"nm":"Kimchi","de":"Inde i krukken modner den langsomt og opbygger en sur, dyb duft. Riv den i stykker med hånden, læg den over frisklavet ris, og det er nok; smagen, der er forskellig fra hus til hus, er netop det hjems egen historie."},"ICON-1280":{"nm":"Syltet radise","de":"En gul skive knaser og brister muntert i munden. Den trofaste følgesvend ved siden af en rulle gimbap eller en tallerken snackmad – den sødt-syrlige smag skyller en fedtet mund frisk."},"ICON-1281":{"nm":"Syltede agurker","de":"Agurkerne holder vejret et øjeblik i salt og åbner så øjnene i eddike. For ikke at gå glip af det øjeblik, sprødheden vender tilbage, forlader glasset aldrig den solbeskinnede vindueskarm. Tiden, der langsomt sylter, henter smagen med sig."},"ICON-1282":{"nm":"Gochujang","de":"En rødme, der har udstået et helt år inde i krukken. Bag hedens skarphed gemmer sig sagte en sødme af sojabønner, så én ske løst i gryderetten gør den endelig til vores families eget ansigt. En dybde, gårdens jang-krukker har opdrættet på solskin."},"ICON-1283":{"nm":"Doenjang","de":"Meju-klumpen omfavnede sin skimmel og kom igennem en hel vinter. Den dybe smag er en balancegang på line mellem lige akkurat moden og overmoden – bedstemor kendte den grænse af én enkelt duft ved fingerspidserne. En smag, der bliver dybere, jo længere man venter."},"ICON-1284":{"nm":"Sojasovs","de":"Jo mørkere sojabønnerne bliver, desto dybere bliver deres indre. Én dråbe genopliver en grøn ret og giver en gryderet glans, så alle farver i køkkenet til sidst begynder fra denne varme brune. En umami hinsides det salte."},"ICON-1285":{"nm":"Chunjang","de":"Selv den samme sorthed har en anden struktur. Den sødt-salte eftersmag af at være stegt endnu en gang med karamel – rør den i nudler, og den sorte glans ryster appetitten vågen. Den første knap, der åbner for den kinesisk-koreanske wok-smag."},"ICON-1286":{"nm":"Karrypulver","de":"Et gult pulver, hvor mange krydderier blandes fredeligt i én ske. Opløs det i vand, og det bobler op og varmer hele huset – det bliver forsmagen på den mest mættende skål en regnvejrsaften."},"ICON-1287":{"nm":"Peber","de":"Kværnet hel bevarer duften liv; kværnet på forhånd forsvinder duften stille. Den sidste omgang kommer altid lige før, ilden slukkes – et lille punktum, den madlavende hånd sparsomt sætter."},"ICON-1288":{"nm":"Gochugaru","de":"Soltørrede chilier under efterårets lys fuldender endelig deres rødme. Om den males fint eller groft, afgør kimchiens karakter, så en kloges hånd kommer, i sidste ende, fra at vælge kornstørrelsen på dette pulver."},"ICON-1289":{"nm":"Salt","de":"At smage til handler om at nærme sig den underkryddede side, en knivspids ad gangen. Salt, der først er kommet i, kan ikke tages tilbage, så en erfaren hånd putter altid lidt mindre i til sidst og smager efter. Det, du holder tilbage, er din luft at ånde i."},"ICON-1290":{"nm":"Sukker","de":"Det formilder bitterhed og runder syrens skarpe kanter. Men sødmen må ikke afsløre sin egen tilstedeværelse, så jo bedre krydderiblandingen er, desto mere forsvinder sukkeret stille til sidst. En sødme, der ved, hvordan man gemmer sig."},"ICON-1291":{"nm":"Honning","de":"Et glas, bierne samlede ved at flyve tusindvis af gange på tværs af blomstermarken. Størkner den, genopliv den i et varmt vandbad; rør den i te, og den omslutter halsen mildt. En gylden skefuld af en hel sæson, kogt sammen til én."},"ICON-1292":{"nm":"Madolie","de":"Fordel en omgang i en opvarmet pande, og ingredienserne glemmer at hænge fast. Hældes den i for tidligt, brænder den på, for sent, klistrer det til, så det ene taktslag, netop som røgen begynder at stige, er stegningens gyldne regel. Man måler tidspunktet på lyden."},"ICON-1293":{"nm":"Olivenolie","de":"I den første koldpresnings grønne farve lever en græsagtig duft og en let skarphed side om side. Dryppet på til sidst frem for sat over ilden overlever duften helt til sidste bid, så det at lade den forblive uopvarmet er dens mest ærlige anvendelse."},"ICON-1294":{"nm":"Sesamolie","de":"Drys en enkelt dråbe til sidst, og de krydrede grøntsager erklærer sig endelig fuldendte. Dens fylde forsvinder let over flammen, så den er altid det punktum, der sagte tilføjes, når al madlavning er slut."},"ICON-1295":{"nm":"Vaniljestang","de":"Flæk en bælg og skrab de sorte frø ud, og desserten skifter dragt til duft. Ikke at smide den brugte bælg ud, men grave den ned i sukkeret – en gammel nøjsomhed, patissieren har arvet."},"ICON-1296":{"nm":"Kakao","de":"Hvidt frugtkød og bitre kerner inde i frugten. Kun efter gæring og soltørring bliver de endelig oversat til den sødme, vi kender. Før den bliver til chokolade, bærer den sit første, mest vilde ansigt."},"ICON-1297":{"nm":"Chokolade","de":"En kræsen natur, der smelter væk ved blot en hånds varme. Den skal størkne omkring 28 grader, for at det sprøde knæk og den blanke glans skal leve, så bag sødmen gemmer sig, overraskende nok, en kræsen regel om temperatur."},"ICON-1298":{"nm":"Kaffebønner","de":"Før den males, er en enkelt bønne nærmest en hård stilhed. Men møder den varmt vand, svulmer den op og udgyder sin duft, så morgenens allerførste signal altid begynder med denne lille bønne."},"ICON-1299":{"nm":"Teblade","de":"Bliv for længe i det varme vand, og den bliver besk; for kort, og den bliver flad. Stille at afmåle den tid, bladene tager at folde sig langsomt ud – at trække te er at måle ventetid med fingerspidserne."},"ICON-1300":{"nm":"Mynte","de":"Knus den, og bitterheden siver ud, så det er et sart blad, man altid skal håndtere varsomt. Klap let på den for at vække den sovende duft, og flyd den i et glas på en trykkende dag, og højsommeren synker et hak køligere."},"ICON-1301":{"nm":"Krydderurter","de":"Tilsæt dem med stilk og det hele, og duften bliver dyb - brug kun bladene, og den bliver klar. Tørret bliver den stærkere, frisk bliver den sprød, og køkkenets udtryk vokser lige så meget, som duftens spændvidde i ét bundt."},"ICON-1302":{"nm":"Kastanje","de":"Inde i den tornede skal gemmer sig et skinnende kød. Rids den og rist den, så revner den med et lille knæk og udsender en sød duft - varmen fra en pose ristede kastanjer i en kold vinterstræde føles næsten til at gribe om."},"ICON-1303":{"nm":"Jordnød","de":"Sprødheden fuldendes over ristningens ild. En lille kerne, man piller én ad gangen, til tiden går ubemærket - deles den siddende i kreds på gulvet, bliver historierne pillet med, lidt efter lidt."},"ICON-1304":{"nm":"Mandel","de":"Skoldes den let og pilles skallen af, bliver kernen endnu hvidere og blødere. Knust og malet bliver den som mælk, ristet hel bliver den sprød - forvandlingens spændvidde i én nød udvider konditorens fantasi til det yderste."},"ICON-1305":{"nm":"Sesamfrø","de":"Rystes de forsigtigt over svag varme, begynder de på et tidspunkt at hoppe med små smæld. Øjeblikket lige før den lyd stopper, er det mest duftende - at riste sesam viser sig at være noget, man i sidste ende gør med ørerne."},"ICON-1306":{"nm":"Sukkerrør","de":"Tygger man ét led, siver den søde saft ud sammen med en græsagtig duft. En stængel, der skal koges ind igen og igen, før den bliver den sødme, vi kender - sukkerets begyndelse er overraskende grøn og høj."},"ICON-1307":{"nm":"Råsukker","de":"En rå sødme, der har bevaret sin egen farve efter mindre raffinering. En svag, jordagtig dybde hænger stille ved, så hænder, der elsker ærligheden i noget, før det pudses glat, opsøger den med vilje."},"ICON-1308":{"nm":"Kakaobønner","de":"Frøene, lige taget ud af bælgen, er bitre og strenge. De må tåle nogle dages fermentering i stilhed, før duften folder sig ud, så sødmen er en lille pris, denne bønne modtager efter lang tålmodighed."},"ICON-1309":{"nm":"Kakaonibs","de":"I stumperne af knust, ristet bønne er der ikke ét korn sukker. Put dem i munden, og bitterheden kommer først, sprødheden følger sent efter, så man møder kakaoen mest ærligt, før sødmen."},"ICON-1310":{"nm":"Grønne kaffebønner","de":"Grønne perler, der endnu bærer en rå duft. Som de er, ligger aromaen i dyb søvn, så indtil de modtager ildens dåb, forbliver de stille en mulighed, der endnu ikke ved, hvad den bliver til."},"ICON-1311":{"nm":"Ristede kaffebønner","de":"På den brune overflade, hvor olien er sivet let ud, har duften samlet sig fuldt op. De skal males, før de køler af, for at duften forbliver hel, så en kops skæbne stille afgøres inden for få dage efter ristningen."},"ICON-1312":{"nm":"Vaniljestang","de":"Én stang duft farver en hel gryde mælk igennem. Stik selv den brugte bælg ned i sukkerkrukken, og få dage efter er alt sukkeret blevet duftende - en luksus uden en eneste del, der går til spilde."},"ICON-1313":{"nm":"Peber","de":"Duften af ét helt peberkorn falmer fra det øjeblik, det bliver malet. Derfor lader man det ligge helt på bordet og knuser det, når behovet opstår - friskhed spirer af et hjerte, der ikke udskyder tingene."},"ICON-1314":{"nm":"Hvid peber","de":"Kornet, glattere efter at have mistet sin skal, er mere dæmpet end skarpt. Født af omsorgen for ikke at efterlade en eneste sort prik i en hvid sauce - finheden ved en usynlig plads."},"ICON-1315":{"nm":"Kanel","de":"Trækker man ét stykke, breder en varm skarphed sig langsomt gennem teen. Tilsat helt frem for som pulver holder duften længere, så dybden i en vinterdrik kommer fra denne tørrede barks udholdenhed."},"ICON-1316":{"nm":"Nellike","de":"I én lille blomsterknop formet som et søm er duften tæt koncentreret. Tilsættes for mange, sluger den hele retten, så tilbageholdenheden ved blot ét korn stille bevarer smagens balance."},"ICON-1317":{"nm":"Muskatnød","de":"Man lader frøet forblive helt og river lidt af, når behovet opstår. Den har en natur, hvor duften hurtigt spredes, hvis den males på forhånd, så det sidste hurtige strøg gør en mælks aroma endnu dybere."},"ICON-1318":{"nm":"Kardemomme","de":"Knækker man den grønne bælg, vælter en kølig, klar duft ud indefra. Blot at knuse en bælg eller to ned i teen giver en almindelig kop, med ét, duften af et fjernt land."},"ICON-1319":{"nm":"Safran","de":"Røde tråde, knap tre samlet fra én eneste blomst. Opløst i varmt vand breder det gule lys sig langsomt, så kostbarhed også er vægten af den tid, der er brugt på at plukke dem for hånd, én for én."},"ICON-1320":{"nm":"Gurkemeje","de":"Rives roden fra jorden, farver den selv fingerspidserne gule. Den har en natur, hvor duften først vågner, når den sauteres let i olie, så karryens gyldne farve er en kulør, denne lille rod har trukket op over ilden."},"ICON-1321":{"nm":"Laurbærblad","de":"Bladet, de siger blev lagt på en sejrherres pande. Lad ét flyde i kogende vand, og gennem dampen stiger et gammelt stadions jubel et kort øjeblik op. Selv på dage, du ikke vandt, bliver det at trække duften ind en grøn trøst, der stille holder om dagens dig."},"ICON-1322":{"nm":"Kokosmælk","de":"Den hvide saft, der først flyder, når man knækker den hårde skal. I et hjørne af et marked i et varmt land stikker man et sugerør i og tager en slurk, og middagens tørst køler helt af. Den kølige, søde duft, der breder sig i munden, bringer troperne skygge med sig."},"ICON-1323":{"nm":"Kokosolie","de":"Størknet er den hvid som den første sne, opvarmet i håndfladen breder duften sig blødt ud. Ø-bedstemorens venlige husholdningsvisdom - som rakte den frem og sagde, at ét glas er nok fra top til tå - ligger helt bevaret i den runde beholder."},"ICON-1324":{"nm":"Tørret banan","de":"Ligger den nogle dage under solen, bliver det gule kød sejt og fyldigt. Bider man i et stykke ad gangen med omtanke, vender den klæbrige, søde duft fra en regnfuld høstsæson stille tilbage i munden. En langsomt modnet sødme rummer på den måde en årstid."},"ICON-1325":{"nm":"Tørret mango","de":"Det bløde frugtkød, koncentreret under solen, er genfødt som ravgul gelé. Sur, sød og sej - alle tre smage findes i ét stykke, så ruller man det langsomt i munden, bliver en hel eftermiddag lang af én pose."},"ICON-1326":{"nm":"Tørret ananas","de":"I modsætning til den tornede ydre er kødet indeni intenst gult og lyst. Tørret i solen koncentreres syrligheden, så blot én bid får mundvigene til at løfte sig af sig selv. Den friske eftersmag for enden af et stykke bliver hængende længe."},"ICON-1327":{"nm":"Kurv med tropiske frugter","de":"Friskplukkede farver smelter sammen i én kurv. Mangoens orange, bananens gult, ananassens guld - før man overhovedet rækker ud for at vælge, kommer sommeren først gennem næsetippen. En favnfuld, der lyser op i hjertet, blot man ser på den."},"ICON-1328":{"nm":"Tangbundt","de":"Havets hår, samlet på klipperne, når ebben har blottet dem. Lyden af bølger er filtret ind i den salte havduft, så lægges den stille i blød i koldt vand, driver en svagt fiskeagtig havlugt langsomt helt ind i køkkenet. En håndfuld breder et lille vadehav ud på bordet."},"ICON-1329":{"nm":"Tørrede havfrugter","de":"En håndfuld hav, tørret hårdt og stridt. Rives den efter fibrene med hånden, slippes den salte, brisende vind fra en gammel havn løs sammen med saltet. En gammel ven ved det varme bord, der uden videre får en til at drømme om en skål makgeolli."},"ICON-1330":{"nm":"Tørret blæksprutte","de":"Ti arme bredt pænt ud og tørret i solen. Ristes den let, til en sprød duft stiger op, rives den så af efter fibrene, stribe for stribe. Med den seje bid stiger et sent aftensnackfads værdighed et trin."},"ICON-1331":{"nm":"Saltet fisk","de":"Gravet ned i groft salt lærer fisken at udholde tiden. Én bid af dens dybt saltede kød tømmer en skål ris på et øjeblik - en kærlig hemmelighed, en kystbedstemor gav videre med sine fingerspidser."},"ICON-1332":{"nm":"Saltede rejer","de":"Små rejer modnes langsomt i salt og genfødes som dyb umami. I det øjeblik man tilsætter en skefuld i kinakålen ved kimchi-tid, breder den salte duft sig over hele gården. Netop den ene skefuld afgør årets kimchi-smag."},"ICON-1333":{"nm":"Ansjos","de":"En fingerstor krop bærer ansvaret for dybden i en hel gryde suppe. Barndommens køkken, hvor man snakkede løs, mens man trak hoveder og indvolde af - lille, men en taknemmelig fisk, der stod solidt midt i husholdningen."},"ICON-1334":{"nm":"Tang","de":"Et langt sort bånd, vokset dybt under havet. Læg det i koldt vand, og løft det forsigtigt op lige før det koger - et løfte, som suppekogere har holdt gennem generationer. Den dybe umami har aldrig, nogensinde, hastet."},"ICON-1335":{"nm":"Hijiki","de":"Den ru, knasende konsistens knalder let på tungen. Tangen, der farvede klipperne grønne om foråret - vendt med hænderne breder den et lille, friskt hav ud i et hjørne af bordet. Smagen af at tygge på foråret."},"ICON-1336":{"nm":"Perlemusling","de":"Et rundt lys, formet gennem lang tid mellem to solide skaller. Fra at forvandle ubehaget ved ét sandkorn til en juvel skyndte havet sig aldrig én eneste gang. Lægges den i håndfladen, følger vægten af den lange tålmodighed med."},"ICON-1337":{"nm":"Koralpynt","de":"Havets trægren, formet af bølgerne gennem hundreder af år. Rammes den af lys, breder den sig i lyserødt og orange, så blot ved at stå stille på en hylde farver den et helt værelse til en varm ø. Selv den ru struktur mod fingerspidserne føles kærkommen."},"ICON-1338":{"nm":"Muslingeknap","de":"Hvor muslingekødet forlod, blev den skinnende inderside skåret rund. Sys den på en jakkeflip, glimter en lille regnbue ved fingerspidsen, hver gang man knapper den. Havets sidste kærlige gave, givet, mens det gav alt og drog bort."},"ICON-1339":{"nm":"Glaskugle","de":"Rulles den i håndfladen, følger det fangne lys indeni glidende med. Fra de dage, hvor man sad på hug i stræderne og spillede kugler uden at lægge mærke til solen, der gik ned - lommen på det barn, der vandt én mere, var usædvanligt tung og stolt."},"ICON-1340":{"nm":"Enebærudskæring","de":"I hver udskåret åre siver en svag duft frem. Mennesker i gamle dage brændte dette træ for at samle et rastløst sind. Holder man stille ét stykke i hånden, stiger roen langsomt fra fingerspidserne."},"ICON-1341":{"nm":"Røgelse","de":"Én tynd stilk brænder langsomt og baner en vej opad. Følger man med øjnene den kurve, røgen tegner, sagtner selv et hjerte, der har hastet hele dagen, sine skridt og bliver stille stående dér."},"ICON-1342":{"nm":"Farveblomst","de":"Løses farven, gemt i kronbladene, op i en kogende gryde, farves det klare stof langsomt i den kulør. At låne, for en stund, den farve naturen på forhånd har malet - farvning var oprindelig en kærlig hilsen sendt til blomsten."},"ICON-1343":{"nm":"Indigofarve","de":"En dyb, mild blå, hentet ved at lade indigoplanten gære og gære igen. Hver gang stoffet dyppes og løftes op, skifter det langsomt farve fra himmelblåt til havblåt. En ventetidens farve, der først blomstrer, når man lægger utålmodigheden fra sig."},"ICON-1344":{"nm":"Skarlagenfarve","de":"Trækkes krapproden af, vågner en solnedgang, der har sovet i jorden, op inde i gryden. Det var den mest festlige, lyseste farve i landsbyen - den, der farvede den nye bruds nederkant smukt på bryllupsdagen."},"ICON-1345":{"nm":"Guldtråd","de":"Guld, trukket finere end et hår, spindes omhyggeligt tråd for tråd. Overalt, hvor det er broderet, holder det på lyset, så selv i et mørkt værelse med lampen slukket rejser mønstret sig alene, blødt og lysende."},"ICON-1346":{"nm":"Silke","de":"Tråden, en silkeorm har spundet ud, skal væves og væves igen, før den knap bliver til én bane. En berøring, der glider som forårsvand hen over håndryggen - et finkornet stof, som mennesker i gamle dage bar en hel årstid og opdrættede langsomt."},"ICON-1347":{"nm":"Perleknap","de":"Kun perlens indre lys blev udvalgt og formet rundt. Hver gang man knapper én på en jeogoris flip, bliver fingerspidserne kortvarigt elegante. Lille, men en sirlig perle, der stille løfter en dragts stil."},"ICON-1348":{"nm":"Kortfragment","de":"Ud over den flossede kant knækker en ukendt kystlinje brat af. De siger, kun den, der samler de resterende stykker, når frem til skatten - men måske var selve rejsen, viklet på jagt efter det i vinden, allerede skatten."},"ICON-1349":{"nm":"Gammelt søkort","de":"Sejlruter udvisket af saltvand og en falmet kompastegning. Følger man med fingerspidsen de linjer, en sømand tegnede efter stjernerne alene en kulsort nat, stiger en længst forsvundet ø langsomt frem igen på det gamle papir."},"ICON-1350":{"nm":"Flaskepost","de":"Inde i en glasflaske, skyllet i land af bølgerne, ligger ét sammenrullet ark papir. En hilsen - ingen ved fra hvem eller hvornår - har endelig nået en andens hånd. Med hjerte nok bliver selv havet sådan en langsom postbud."},"ICON-1351":{"nm":"Drivkasse","de":"Eventyret varer helt frem til det øjeblik, man vipper det saltvandssvulmede, stive låg op. Uanset om det, der venter indeni, er skat eller blot tomt sand, bringer en kasse, der er drevet langt, altid en ukendts historie med sig i land."},"ICON-1352":{"nm":"Lille nøgle","de":"Et slidt stykke jern, der lige akkurat passer i håndfladen. Selvom hvilken dør den åbner er glemt for længst, ligger en varm vægt tungt tilbage ved fingerspidserne - den slags, der får en til at tænke på at åbne, før man tænker på at låse."},"ICON-1353":{"nm":"Sølvmønt","de":"En rund sølvskive, hvis mønster er falmet af utallige tommelfingre. En enkelt mønt, der engang var nogens billet eller et trættende nattelejr - stryger man over dens kolde overflade, vækkes varmen fra en gammel handel svagt til live igen ved fingerspidserne."},"ICON-1354":{"nm":"Guldmønt","de":"Læg den i håndfladen, og den tunge vægt rører hjertet først. En enkelt mønt, der lyser gult i solen, ser ud til at love rigdom, hvis man beholder den - men det, der egentlig skinner klarest, er sitringen lige før den lander i hånden."},"ICON-1355":{"nm":"Kaptajnens segl","de":"Kaptajnens løfte, presset fast ned i rød voks. Ét enkelt mærke kunne rejse en ordre og udstikke en barsk kurs. Autoritet var i sidste ende blot ét lille, solidt stempel, som alle om bord på samme skib var enige om at tro på sammen."},"ICON-1356":{"nm":"Håndmikrofon","de":"I det øjeblik man griber den, fylder en mærkeligt betryggende vægt håndfladen. Uanset om man rækker en skælvende første hilsen frem eller endelig skyder en høj tone op - denne lille stang giver stille vinger til stemmen."},"ICON-1357":{"nm":"Trådløs mikrofon","de":"Da ledningen forsvandt, blev hele scenen bredere med ét. Løber man helt ud til bagerste række, afbrydes stemmen aldrig, som om nogen stille skubber en i ryggen og siger: løb og syng, så meget hjertet begærer."},"ICON-1358":{"nm":"Mikrofonstativ","de":"Stående solidt ved ens fødder venter den tavst på sangeren. Bliver begge hænder fri, breder sangen sig gennem hele kroppen i stedet for fingerspidserne. Der er en tydelig ynde i at holde ét sted til det sidste, siger denne stang stille."},"ICON-1359":{"nm":"Popfilter","de":"Ét rundt lag stof, der spærrer for mikrofonens forside. Det filtrerer blødt de barske åndedrag fra og lader kun den klare stemme slippe igennem. At gøre nogen hørt betyder at skærme stille fra et sted, der forbliver usynligt til det sidste."},"ICON-1360":{"nm":"In-ear-monitor","de":"Glider den snugt ind i øret, vender ens egen sang klart tilbage til live gennem tusinders brøl. Det mindste, mest hemmelige følgeskab, der holder én fra at miste takten på en scene oversvømmet af lys og lyd."},"ICON-1361":{"nm":"Hovedtelefoner","de":"I det øjeblik de dækker ørerne, krymper verden ét hak, og kun sangen står tilbage stor. Et rundt lille rum, ingen kan trænge ind i. Alene i hovedtelefonerne er man, mærkeligt nok, ikke alene."},"ICON-1362":{"nm":"Nodeblad","de":"Når de sorte prikker lægger sig stille ned på linjerne, begynder det tavse papir at holde på lyd. Skrift, man hører frem for læser. I det øjeblik man slår den op, trækker en sang, der stod stille, igen vejret."},"ICON-1363":{"nm":"Vokalnoder","de":"Ved hvert sted, man skal trække vejret, er der tegnet en lille cirkel. Ånd ind her, slip stille los dér. Et kærligt kort, der baner vejen, så stemmen ikke tager skade."},"ICON-1364":{"nm":"Klavernoder","de":"En side, hvor ti fingre spørger efter vejen på samme tid. Venstre hånd griber om rødderne, højre hånd tegner sangen. To hænder, der fortalte hver sin historie, folder sig til sidst sammen i den sidste takt."},"ICON-1365":{"nm":"Guitarakkordskema","de":"Fingrenes første fremmedsprog, dets allerførste ord, står skrevet her. Samler seks prikker sig til cirkler, ringer først da én tone ud. For hver nat med at trykke og trykke igen, gror der hård hud på spidserne."},"ICON-1366":{"nm":"Metronom","de":"Tik, tik - et urokkeligt skridt slår ved siden af. Løber hjertet i forvejen, holder den én tilbage langsomt, langsomt bagfra. For takt er i sidste ende et løfte om at gå sammen."},"ICON-1367":{"nm":"Stemmeapparat","de":"Glider nålen ind til midten, finder tonen først da sin plads. Det ene punkt, hverken for højt eller for lavt. At stemme er, viser det sig, dette: ikke længere at skælve, blot at falde stille til ro."},"ICON-1368":{"nm":"Klaviaturkort","de":"Bladres der én side ad gangen, vandrer tangenterne lige ind i håndfladen. Et lille univers med syv felter, fra C til H. Selv på nætter uden et rigtigt klaver gror sangen stille her."},"ICON-1369":{"nm":"Guitarplekter","de":"En lille, solid splint, klemt fast mellem tommel og pegefinger. Tabes den, forsvinder den for evigt under stolen, men i det øjeblik man holder den i hånden, ringer alle seks strenge ud på én gang."},"ICON-1370":{"nm":"Trommestikker","de":"Mødes de to stokke i luften, falder signalet netop dér. Én, to, tre, fire. Alles spredte hjerter begynder at banke i samme tempo, sat efter de fire slag."},"ICON-1371":{"nm":"Tamburin","de":"Ét slag, og en klar lyd spreder sig i alle retninger, som sollys der splintres i småstykker. Ser den let ud, er den det første slag, hånden griber efter, når stemningen begynder at dale. Lille er den, men ingen kan overse den."},"ICON-1372":{"nm":"Dansesneakers","de":"For fødder, der glider drejende hen over gulvet, bliver friktion et våben. I hver slidt sål er endnu en drejning, endnu en omgang, indridset. Den flotteste bevægelse begynder altid fra ét solidt par."},"ICON-1373":{"nm":"Knæbeskyttere","de":"Kun den, der utallige gange har knælet og rejst sig igen, kender taknemmeligheden ved dette ene tynde lag stof. Noget, der gør gulvet mindre skræmmende - mod er nogle gange viklet om knæene sådan her."},"ICON-1374":{"nm":"Håndledsbind","de":"Omslutter man leddet, der bøjer, på forhånd, bliver selv en anstrengt bevægelse en smule mere overbærende. Håndleddet er tavst og udholder alene, til det gør ondt. Denne lange stilhed tager ét lag over i stedet."},"ICON-1375":{"nm":"Ankelbeskytter","de":"For enden af et højt spring venter landingen, og for enden af den landing venter anklen. Det laveste sted, der tager imod hele kroppens vægt. Dette lille bånd våger stille over morgendagens træning."},"ICON-1376":{"nm":"Strækelastik","de":"Trækker man i den, spænder den imod og prøver at vende tilbage til sit udgangspunkt. Mens man udholder den modstand, bliver kroppen, uden man lægger mærke til det, lidt længere. At strække er i sidste ende et mærke, den udholdte tid har efterladt."},"ICON-1377":{"nm":"Yogamåtte","de":"I det øjeblik man ruller den ud, opstår der en jordlod på gulvet, akkurat stor nok til én person. Et lille territorium til at ligge ned, knæle og finde vejret. Dagens begyndelse og afslutning bindes stille sammen på dette ene stykke."},"ICON-1378":{"nm":"Foamroller","de":"Trykkes der fast på et knudret sted, gør det først ondt, men bliver hurtigt godt. At løsne det, der er stivnet, kræver altid lidt smerte. For krop såvel som sind skal presses én gang, før de kan slippe."},"ICON-1379":{"nm":"Håndvægt","de":"Man løfter den samme vægt og løfter den igen. Præcis én gang mere end i går, det er hele sagen. I en gentagelse uden noget prangende bliver armen tavst tykkere. Et jernstykke, der kun nogensinde er ærligt."},"ICON-1380":{"nm":"Kettlebell","de":"Ét håndtag svinger hele kroppen rundt. Når den runde vægt kredser i en bue, sættes balancen hos den, der holder fast, på prøve. For ikke at vakle må man først kende sit eget centrum."},"ICON-1381":{"nm":"Sjippetov","de":"Man springer over ét reb, der suser forbi under fødderne, og springer igen. Som den leg, man talte med vennerne i gården - jo højere tallene stiger, desto mere stakåndet og desto mere leende bliver man."},"ICON-1382":{"nm":"Løbesko","de":"Et par sko, hvis sande værdi man først kender, når man er ude på vejen. Skærer man gennem den tidlige morgenluft og løber den samme vej igen, står gårsdagens fjerne hjørne i dag lige for næsen. Fødderne husker afstanden."},"ICON-1383":{"nm":"Træningshåndklæde","de":"Har man tørret sveden af panden, ligger dagens indsats vædet ind i den, som en linje. Vaskes den, forsvinder sporet, men det, man har svedt, hober sig et sted op, ordentligt og stille. Den mest ærlige heppen tørrer altid ved siden af én."},"ICON-1384":{"nm":"Vandflaske","de":"Er den tom, fyldes den; er man tørstig, drikker man en slurk. Den enkle frem-og-tilbage-rejse bærer tavst dagen igennem. Som en spand, der hejses op og ned ved brønden, begynder dagen på ny fra handlingen at fylde op."},"ICON-1385":{"nm":"Proteinshake","de":"Rystes den godt, og synkes en slurk, fyldes den muskel, man sled i dag, op igen i morgen. Smagen er ikke prangende, men kroppen ved, at dette er restitutionens sprog. Vækst drikkes altid stille."},"ICON-1386":{"nm":"Energibar","de":"En enkelt bar, fladtrykt i lommen. Nødproviant, der fylder den tomme tid mellem måltider. Intet stort ved den, men denne lille bid gør, at man kan holde til én bevægelse mere om eftermiddagen."},"ICON-1387":{"nm":"Halstablet","de":"Rulles den rundt i munden, stryger kølig mynte blidt hen over en ru hals. På dage med meget snak, på nætter med megen sang - én lille drops klapper den ru vej blid. Der er tydeligvis også et formål med sødme."},"ICON-1388":{"nm":"Vokalte","de":"Varm damp varmer halsen, og med én slurk løsner spændingen i skuldrene sig langsomt op. En gammel kur, som ingefærteen, bedstemor plejede at brygge. En kærlig hilsen, sendt til stemmen, før man synger."},"ICON-1389":{"nm":"Honningvand","de":"Man rører langsomt en ske honning ud i lunkent vand. Netop den kop, de voksne plejede at røre sammen, når halsen føltes ru. Hverken medicin eller drik, blot en sødme, der stille kærtegner kroppen indefra."},"ICON-1390":{"nm":"Luftfugtertank","de":"En beholder, der slipper en lille tåge løs i rummet. På vinternætter, hvor tør luft river i halsen, deler den fugt ud, usynligt. At passe på nogen flyder som regel stille sådan her."},"ICON-1391":{"nm":"Hvilekupon","de":"Et enkelt stykke papir, der siger, det er okay at hvile. I det øjeblik man tager imod den, bliver byrden på sindet ét hak lettere. At standse op er også en form for øvelse - denne lille billet giver tilladelsen i stedet."},"ICON-1392":{"nm":"Øveskema","de":"Over den tid, der er skrevet ind felt for felt, lægger dagen sig ned, ordentligt. Sang om morgenen, koreografi om eftermiddagen, hvile om aftenen. Selv en uoverskuelig morgendag bliver, når den er inddelt med streger, noget, man kan gå igennem."},"ICON-1393":{"nm":"Fremmødestempel","de":"Man trykker et enkelt mærke fast ned for at vise, man kom igen i dag. Efterhånden som de let udtværede cirkler lægger sig op, felt for felt, er en flid, der virkede ubetydelig, blevet til en vej. Et lille bevis for hver dag."},"ICON-1394":{"nm":"Rosemærkat","de":"I stedet for at sige godt klaret, sætter man stille én stjerne på. Et glimt på størrelse med en fingernegl, men i det øjeblik det sætter sig i hjørnet af en notesbog, lyser hele dagen op. Ros er lille, men skinner mærkeligt længe."},"ICON-1395":{"nm":"Mentalnoter","de":"En side, hvor hjertet, der skælvede bag scenen, er løst op i ord. Skriver man ærligt selv om dagene, der ikke gik godt, føles det på en eller anden måde lettere et sted. Hjertet bliver stærkere, jo mere man kigger ind i det."},"ICON-1396":{"nm":"Visualiseringskort","de":"Lukker man øjnene og holder det, folder en scene sig stille ud i tankerne. At gå en runde på forhånd på et sted, man endnu ikke har stået. En rute, tegnet i forestillingen, ankommer ét skridt før de virkelige tæer."},"ICON-1397":{"nm":"Mimikspejl","de":"Foran spejlet smiler man, stivner, gør den samme grimasse mere end hundrede gange. Her lærer man, at både glæde og sorg kræver øvelse. For et udtryk er handlingen at skrive hjertet ud på ydersiden."},"ICON-1398":{"nm":"Koreografinoter","de":"En side, hvor vejen, fødder og arme skal bevæge sig ad, er kopieret over som tegninger. Ved hver ottendedel takt fortæller pile stille, hvor kroppen skal hen. Selv en bevægelse, der bare ikke ville huskes, tæmmes langsomt på denne side."},"ICON-1399":{"nm":"Koreografivideochip","de":"Hundredvis af bevægelser er gemt intakt i én lille chip. Kører man den igennem én gang til før søvn, bevæger fingerspidserne sig af sig selv langs den vej. Gentagelse er endnu en optegnelse, kopieret over gennem kroppen."},"ICON-1400":{"nm":"Scenebevægelsesskema","de":"Ét kort over scenen, set ovenfra. Hvem der mødes hvor og spredes hvorhen, er aftalt på forhånd med linjer og prikker. For at flere kan tegne ét billede sammen, må man først dele vejene ud."},"ICON-1401":{"nm":"Prøvepas","de":"Tilskuerpladserne er tomme, og lysene sover stadig. Dette ene pas lukker dig ind i den stilhed. Scenen når ingen ser på — og dér begynder tiden, hvor du møder dit mest ærlige jeg."},"ICON-1402":{"nm":"Stilbog","de":"Med hvilket humør skal jeg klæde mig i dag? Selv en enkelt skjorte har en stemning, der passer til den, fortæller denne bog stille. Jo flere sider du vender, desto mere samler en lille sans sig i de fingerspidser, der engang tøvede foran spejlet."},"ICON-1403":{"nm":"Hårspray","de":"Ét pust, og ikke engang vinden kan tankeløst rode det til. En lille ambition om at holde de få minutter på scenen fejlfrit på plads. Det perfekte øjeblik er altid fuldendt oven på sådan en beskeden stædighed."},"ICON-1404":{"nm":"Makeuppalet","de":"Tolv felter med farve er tolv forskellige stemninger. Med hvilket udtryk skal der synges i dag — fingerspidserne vælger først, og hjertet følger bagefter. I hvert felt, der tømmes, ligger de dage, der blev efterladt på scenen, stille gemt."},"ICON-1405":{"nm":"Kostumenål","de":"I det mest strålende øjeblik er der, netop på et sted man ikke ser, en lille nål der holder stoffet fast. Så det ikke glider, så det ikke går i uorden. Glansen på scenen står altid på nogens ubøjelighed."},"ICON-1406":{"nm":"Navnetavle","de":"I det øjeblik et navn fylder det engang tomme skilt, bliver et tåget løfte tydeligt. Hvem der skal stå på dette sted — én linje skrift afgør det. Et navn er den korteste og fasteste beslutsomhed."},"ICON-1407":{"nm":"Fanhilsenkort","de":"Modtageren er kun én person, men for den ene person er det hele verden. At presse flere nætters taknemmelighed ned i én kort hilsen. Selv på et stykke papir på størrelse med en håndflade kan hjertet flyde sådan over."},"ICON-1408":{"nm":"Autograføvelsesark","de":"I begyndelsen tegnes selv ens eget navn fremmed. Gennem daggry hvor det trækkes hundrede gange og finpudses tusind, indtil hånden husker bevægelsen før hjertet gør. Sådan bliver et navn til sidst en autograf."},"ICON-1409":{"nm":"Interviewspørgeark","de":"\"Hvad svarer jeg på det spørgsmål?\" Fingerspidserne, der holder papiret, ryster en smule. Det handler ikke om at udenadlære svar, men om at stille sin oprigtighed op i rækkefølge — for et interview, ligesom en tilståelse, er i sidste ende et spørgsmål om hjertets orden."},"ICON-1410":{"nm":"Ordbog til fremmedsprog","de":"Det mest slidte hjørne peger på det ord, der er blevet betragtet længst. Ligeså lang tid som det tager et fremmed lydtegn at slå rod på tungen, kommer afstanden til en verden, man aldrig har besøgt, en håndsbredde nærmere."},"ICON-1411":{"nm":"Udtalekort","de":"Det rullende 'r', det sivende 's'. Der findes daggry, der bruges på at vende kortene ét for ét og tæmme tungen. Ligeså tydelig som talen bliver, ligeså tydeligt bliver også ansigtet på den, man ønsker at nå med de ord."},"ICON-1412":{"nm":"Livetjekliste","de":"Mikrofon tændt, in-ears tjekket, koreografi gennemgået. For hvert felt der udfyldes, tømmes uroen i brystet et felt ad gangen. Før man går på scenen, er grundighed den stilleste form for mod."},"ICON-1413":{"nm":"Velværeplaster","de":"Der er et sted, der spreder varme i det øjeblik man sætter det på. En overanstrengt skulder, en stiv læg — en trøst på størrelse med en håndflade, der stille svarer på kroppens små signaler. At hvile godt er også en del af øvelsen."},"ICON-1414":{"nm":"Ispose","de":"Læg den stille på en hoven ankel. Først mens kulden langsomt trænger ind, forstår man endelig, hvor meget man har løbet i dag. Genopretning bag scenen kommer altid lydløst sådan her."},"ICON-1415":{"nm":"Førstehjælpspung","de":"Plaster, smertestillende, et lommespejl. Der kommer et øjeblik, hvor denne lille pung, fyldt med intetsigende ting, bliver den mest betryggende af alt. Omtanke pakket på forhånd skinner klarest foran en uventet krise."},"ICON-1416":{"nm":"Cue-kort","de":"Nogen løfter det diskret op bag kameraet. Den ene linje, man nær havde glemt, står skrevet der med tydelige bogstaver. Bag en udsendelse, der flyder uden hak, er der altid en hånd som denne, aldrig fanget på skærmen."},"ICON-1417":{"nm":"Missionskuvert","de":"Det mest hjertebankende øjeblik er lige før kuverten rives op. Uanset hvad der er inden i, den korte, spændende stund af endnu ikke at vide det. Underholdningsprogrammets charme lever helt og holdent i det ene forseglede øjeblik."},"ICON-1418":{"nm":"Navneskilt","de":"Et lille navn fæstnet ved brystet træder i stedet for det første goddag. Blandt mennesker, der endnu ikke kender hinanden, knækker ét navneskilt akavethedens is. Fra det øjeblik et navn kaldes, begynder et forhold."},"ICON-1419":{"nm":"Straffemærkat","de":"Ét mærke klasket på taberens pande får latteren til at bryde løs. For venligt til at kaldes en straf, så selv nederlaget bliver et kært minde på sigt. Et lille, ømt mærke lavet for at man kan grine sammen."},"ICON-1420":{"nm":"Tilfældigt straffekort","de":"Ingen ved det, før det trækkes. Ti omgange elefantsnabel, eller én runde aegyo. I det øjeblik man overlader hele sin skæbne til et enkelt stykke papir, er det latteren, der løsner sig først."},"ICON-1421":{"nm":"Hintkort","de":"Noget der ligner en hånd stille rakt frem mod et fastlåst sted. Det giver ikke hele svaret, men peger på vejen. Et godt hint er ikke facitlisten, men handlingen at stille overrække modet til at tænke én gang til."},"ICON-1422":{"nm":"Chancekort","de":"Én eneste mulighed for at vende et skævt spil på et øjeblik. Hvornår man trækker dette kort, afgør kampen. Held, der er sparet og sparet op, beviser først sin værdi i det mest afgørende øjeblik."},"ICON-1423":{"nm":"Timeout-kort","de":"Det er okay at stoppe et øjeblik, siger dette kort i dit sted. At turde række hånden op, når man har brug for et åndedrag — at stoppe er også en gyldig strategi, og at hvile godt er også en plads i færdigheden."},"ICON-1424":{"nm":"Grineknap","de":"Klik, og i samme øjeblik knappen trykkes, vælder en byge af klukkende, lys latter frem. En virkelig sjov scene beder om, at selv en lydeffekt lige hjælper til. En forsamlings varme opvarmes af netop sådan et lille puds."},"ICON-1425":{"nm":"Lydeffekt-fjernbetjening","de":"Én knap giver klapsalver, en anden buhråb. En troldmand, der former stemningen med blot fingerspidserne, sidder stille i kontrolrummet. Regi, der aldrig fanges på skærmen, er det, der får scenen til at ånde."},"ICON-1426":{"nm":"Klaptræ","de":"Klak, og med den skarpe lyd begynder en scene. Mellem snesevis af fejltagelser og ét eneste godkendt take tæller denne sorte tavle hvert øjeblik tydeligt op. Det er den første takt, optagelsen træder ind i."},"ICON-1427":{"nm":"Markeringstape","de":"I det øjeblik tåspidserne stille rører den linje, sænker lyset sig let ned, som om det havde ventet. Den ene plet, man har husket udenad til den er slidt — scenen fuldendes først af en lille farvet strimmel tegnet på gulvet."},"ICON-1428":{"nm":"Lysfilter","de":"Det samme ansigt forvandles helt af lysets farve. Daggry bor i et blåt filter, solnedgang i et rødt. Stemning er aldrig langt væk — den ligger stille foldet inde i et enkelt tyndt stykke farvet papir."},"ICON-1429":{"nm":"Kamerabatteri","de":"Så snart det røde lys begynder at blinke, bliver hjertet urolig først. For netop den bedste scene kommer altid ved 1 procent tilbage. Ét ekstra batteri i lommen bliver snart lettelsen ved at trække vejret ud."},"ICON-1430":{"nm":"Hukommelseskort","de":"En hel dags latter og sveddråber pakkes tæt sammen i en chip på størrelse med en negl. Så lille, at den let mistes, og netop derfor så meget mere dyrebar. Vægten af de minder, den rummer, kan aldrig måles i størrelse."},"ICON-1431":{"nm":"Polaroidfilm","de":"Klik, og så en stille venten. De få sekunder, hvor et ansigt langsomt dukker frem over den engang hvide flade, er underligt spændende. Selv et øjebliksbillede i hånden kræver nøjagtig én skefuld tålmodighed."},"ICON-1432":{"nm":"Photocardfilm","de":"Hvilket udtryk der bliver fremkaldt på dette ene ark, er en hemmelighed indtil selve trykøjeblikket. Det ansigt, der skal blive nogens favorit, fødes lige her. Ét lille stykke papir rummer så stort et hjerte."},"ICON-1433":{"nm":"Photocard-lomme","de":"Et photocard røres aldrig med bare hænder. Trykker man på ét hjørne, gør selv den dags smil ondt. At svøbe sin favorit omhyggeligt i et enkelt gennemsigtigt ark — selv det at værne om noget kræver så megen omhu."},"ICON-1434":{"nm":"Toploader","de":"Skub det ind mellem to stive plader, og ikke engang tiden kan tankeløst krølle det. Bøj ikke, fold ikke. At værne om noget dyrebart låner altid et lag hårdhed."},"ICON-1435":{"nm":"Klistermærkepakke","de":"Løsn dem ét for ét og sæt dem på dagbogens hjørne, på bagsiden af en bærbar. Med ét lille billede farves en farveløs dag i alle nuancer. Ønsket om at pynte det, der omgiver en, kender ingen alder."},"ICON-1436":{"nm":"Signaturpen","de":"Ved lyden af blæk, der hvisker hen over papir, bliver køen længere og længere. Over et album rakt frem af en dirrende hånd bliver et møde på blot få sekunder ved i lang tid. Hjertet krydser over langs pennens spids."},"ICON-1437":{"nm":"Signeret album","de":"Åbn omslaget, og en velkendt, buet signatur byder først velkommen. Et bånd knyttet gennem musik kommer en håndsbredde nærmere på papir. At gemme det er stille at holde det øjeblik stille."},"ICON-1438":{"nm":"Lyspind-batteri","de":"\"Tænd nu, kære.\" Hænderne har travlt med at skifte batterier lige før indgangen. Så mit ene lys ikke slukkes blandt titusindvis af andre — et lille batteri lyser den store nat helt op."},"ICON-1439":{"nm":"Lyspind-etui","de":"Pænt og uden en eneste ridse, gemt trygt selv til næste nats jubel. Selv når den ophedede plads er kølet helt af, bæres den omhyggeligt pakket hjem. Et hejaredskab har også sin egen plads, og der findes et hjerte, der passer på den plads."},"ICON-1440":{"nm":"Sloganbanner","de":"En sætning skrevet på langt stof folder sig ud tværs over tilskuerpladserne. I det øjeblik en hyldest, der var for svær at sige højt, åbner sig vidt, bliver én persons oprigtighed til alles råb. Det stof bliver selv til en stemme."},"ICON-1441":{"nm":"Minibanner","de":"En lille hyldest, der lige passer i håndfladen. Bannerne hængt langt væk tilhører alle, men denne her vifter kun ved kanten af dit eget skrivebord. Ved stille at svaje beviser den, at en lille størrelse ikke gør hjertet lille."},"ICON-1442":{"nm":"Fanbrev","de":"Jeg rettede modtagerens navn tre gange og slettede den første sætning syv. At fingerspidserne ryster lige før kuverten lukkes, er fordi hjertet er alt for ærligt. En oprigtighed tungere end et enkelt frimærke ligger foldet indeni."},"ICON-1443":{"nm":"Gavepapir","de":"Gavepapiret ved bedre end nogen, at det mest spændende sekund er det ene lige før det pakkes op. Selv vel vidende, at det er skæbnebestemt til snart at blive revet i stykker, svøber det sig i den fineste struktur, som om det efterlignede giverens hjerte."},"ICON-1444":{"nm":"Sløjfe","de":"Bindes den for stramt, strammer den, for løst, og den løsner sig, så at finde nøjagtig midtimellem er selve omhuen. I én sløjfe valgt af fingerspidserne rummes hjertets form. Gavens sidste linje skrives altid af sløjfen i stedet."},"ICON-1445":{"nm":"Takkekort","de":"Et tak sagt højt spredes for vinden, men skrevet med håndskrift bliver det længe. Handlingen at sende den modtagne venlighed tilbage, med lidt mere lagt oveni. Mens hver bogstav trykkes ned, fordobles hjertet i dybde."},"ICON-1446":{"nm":"Madkasse-kupon","de":"Med dette ene stykke papir løsner bekymringen for frokosten sig helt. Nykogt ris med dampen stigende, et måltid med tilbehør fyldt i hvert rum er lovet. Et lille amulet, der solidt vogter en sulten eftermiddag."},"ICON-1447":{"nm":"Snack-kupon","de":"Den er lavet til at trækkes frem klokken tre om eftermiddagen, når sulten sender et svagt signal. En kupon, der ved, at ét lille sødt løfter humøret en halv håndsbredde. Ikke nogen stor belønning, men den ankommer blidt lige i det øjeblik, man har brug for den."},"ICON-1448":{"nm":"Cafékupon","de":"En varm kop og en plads ved vinduet — det er alt, hvad denne kupon lover. Det virker som ingenting, men for nogen bliver den en lille pris for at have klaret dagen. En øm invitation, hvis duft ankommer et skridt i forvejen."},"ICON-1449":{"nm":"Rengøringsbillet til boligen","de":"Vinduerne slås vidt op, dynerne bankes ud, en dag hvor ikke engang et støvfnug slipper væk. Hvem vidste, at det at slippe for at gøre det selv kunne være sådan en luksus. Når rummet skinner, ordner hjertet sig stille også."},"ICON-1450":{"nm":"Reparationssæt","de":"En skruetrækker, tape, et par ukendte dele. Samlet virker det som om intet kan modstå det, men åbner man det, mangler der altid ét stykke. Alligevel en æske af selvtillid, der på en eller anden måde giver tryghed, blot ved at holde den."},"ICON-1451":{"nm":"Lykkebillet","de":"En blank billet uden plads og uden nummer. Pointen er netop, at hvad godt der kommer i dag, ikke står skrevet på den. At udfylde den tomme plads er op til den, der bærer den rundt i lommen."},"ICON-1452":{"nm":"Terning","de":"En ven, der bedst kender ordet retfærdighed. Den tager ingens parti og elsker alle seks sider lige højt. I det ene øjeblik den forlader håndfladen og ruller afsted, træder selv dygtighed og forbindelser midlertidigt til side for held."},"ICON-1453":{"nm":"Rejsebillet","de":"Et løfte om, at herfra til derhen er ét skridt nok. Et magisk stykke papir, der folder en lang vej lille sammen og gemmer den i lommen. På dage hvor man tøver med at tage af sted, findes der ingen bedre undskyldnings-blokering end denne."},"ICON-1454":{"nm":"Genforsøgsbillet","de":"I stedet for at række en hånd til den, der er faldet, en billet der stille skubber i ryggen og siger prøv igen. Den fortæller stilfærdigst af alt, at fejl ikke er en slutning, men et kort komma. Modet til én gang mere fyldes op her."},"ICON-1455":{"nm":"Hurtig-færdig-billet","de":"En øm snydekode, der springer lidt af ventetiden over. Hvem kan bebrejde et hjerte, der ikke engang kan holde ud i 3 minutter? Her findes en lidt fusk-agtig glæde, som at prikke timeglassets sand videre med en finger."},"ICON-1456":{"nm":"Produktionsbooster","de":"Samme hænder, samme tid, men dobbelt så meget resultat. Den snurrer muntert rundt på arbejdsbordet, som om den siger, spørg ikke om hemmeligheden. En lille anordning, der stille sætter vinger på to flittige, arbejdende hænder."},"ICON-1457":{"nm":"Fortrolighedsslik","de":"Selv akavethed, svær at løse med ord, smelter væk foran noget sødt. Et bånd, der bliver en håndsbredde tættere end i går, over ét stykke slik pakket ud sammen. En sød lille opdagelse: at sødme er farten, man knyttes tættere med."},"ICON-1458":{"nm":"Humørgele","de":"På en trist dag virker noget koldt og blødt som en genvej. Tag en bid, og et overskyet udtryk løsner sig stille. At reparere hjertet er af natur en dyrebar ting, så R-mærkningen er ikke sat på for ingenting."},"ICON-1459":{"nm":"Glimmerstøv","de":"Drys det let over noget almindeligt, og det bliver pludselig særligt. Dets sande jeg er blot glitrende støv, men i det øjeblik det lægger sig, ser verden lidt mere opstemt ud — hvor mærkeligt. Som et krydderi af lykke drysset ud over hverdagen."},"ICON-1460":{"nm":"Scenetape","de":"Stiller man sig på scenen, finder utallige lys dig alle på samme tid. Et lille X på gulvet markerer stedet uden ord. Det mest præcise fra et usynligt sted bærer til sidst den største scene oppe."},"ICON-1461":{"nm":"Kabelstrips","de":"En lille helt, der bringer roder ledninger i orden på et øjeblik. At den, når den først er strammet, ikke kan gøres om, er både dens svaghed og dens charme. Et must-have, som dem, der er seriøse med orden, stille sørger for at have ved hånden."},"ICON-1462":{"nm":"Reservekabel","de":"En genstand uden nogen tilstedeværelse, når man har den, men længtes intenst efter, når man ikke har. Sovende dybt i tasken bag scenen, vågner den brat op i det afgørende øjeblik. Den beviser ordet forberedthed med hele sit væsen."},"ICON-1463":{"nm":"Prøvetjekliste","de":"Et papir tætpakket felt for felt med koreografi, cues, selv kostumeskift. Mangler blot ét kryds her, synker nogens hjerte sammen. En perfekt scene hæver først sit tæppe, efter dette skema er fyldt helt ud."},"ICON-1464":{"nm":"Kulisseskilt","de":"Her er en café, der en gyde — følg pilene ind i en helt anden verden. En løgn malet på krydsfiner, men foran kameraet bliver den ægte. En ærlig vejviser, der har viet hele sit liv til at pege retningen."},"ICON-1465":{"nm":"Minitrofæ","de":"Et gyldent stykke, der på en eller anden måde får dig til at føle dig en håndsbredde højere, i det øjeblik du modtager det. Det skinner på skrivebordet og siger, at det er helt okay ikke at være nummer ét, at det ved alt om det, du har kæmpet for i dag. Den store trøst, en lille belønning kan give."},"ICON-1466":{"nm":"Rygsæk","de":"I det øjeblik den svinges på ryggen, føles det som om man kunne tage af sted hvor som helst. Der er måske ikke meget i den, men mulighed fylder den til randen. Eventyr begynder altid med handlingen at stramme disse skulderremme godt til."},"ICON-1467":{"nm":"Kompas","de":"At man ikke går i panik, selv når man farer vild, skyldes at nålens spids altid peger mod nord. Måden den vakler et stykke tid, før den til sidst finder sin plads, minder så meget om det menneskelige hjerte. Det er okay at fare vild, siger den med sin dirrende spids."},"ICON-1468":{"nm":"Notesbog","de":"Den første side er altid tom. Kun den, der holder pennen, ved hvad der skal skrives. Jeg venter blot på, at dagens tanker bliver til skrift og lægger sig stille ned over mig. R-mærkningen er vægten af en snart udfyldt mulighed."},"ICON-1469":{"nm":"Blyant","de":"At det er okay at tage fejl, er dette redskabs mest ømme side. Så længe viskelæderens venskab er ved siden af, kan man begynde forfra lige så mange gange, man vil. Den bliver kortere, jo mere den spidses, men kortheden er beviset på, hvor længe den blev elsket."},"ICON-1470":{"nm":"Film","de":"I det øjeblik lyset trænger igennem, indfanges den dags farve helt intakt. At et billede, når det først er passeret, aldrig kan gøres om, er både spændingen og charmen. Valget for dem, der bevidst vælger at huske et taktslag langsommere i en hurtig tidsalder."},"ICON-1471":{"nm":"Instantkamera","de":"Klik, og så en kort venten. Holder man det og ryster det let, bliver et sløret øjeblik gradvist skarpt. En lidt magisk maskine, der fanger netop dette sted, intakt, på et enkelt stykke papir."},"ICON-1472":{"nm":"Gammelt fotografi","de":"Hvor meget farven er falmet, viser hvor meget tid der er gået. Ved hvert slidt hjørne har nogens berøring dvælet. At det ældste billede rummer det klareste minde skyldes nok netop de berøringer."},"ICON-1473":{"nm":"Scrapbog","de":"Stumper for kære til at kasseres samler sig og samler sig til ét bind. En falmet biografbillet, et tørret kronblad, en kort notits. Rod for andres øjne, men for den, der åbner den, genopstår en hel årstid helt og holdent."},"ICON-1474":{"nm":"Skibsdagbog","de":"Dagens vind og bølger, og én linje fra hjertet. At skrive trofast selv på begivenhedsløse dage er sejladsens regel. Beviset på, at man nåede sikkert frem, står altid skrevet et sted i denne tykke optegnelse."},"ICON-1475":{"nm":"Kortfragment","de":"Det er blot ét hjørne af helheden, men uden det finder man aldrig vejen til sidst. Sikke en glæde, når en revet kant klikker perfekt sammen med et andet fragment. R-mærkningen har samme tilstedeværelse som puslespillets sidste brik."},"ICON-1476":{"nm":"Flaskepost","de":"Uden at vide, hvem der vil læse den, overgiver den sig stille til bølgerne. Den venter intet svar, ønsker blot at dette hjerte når frem et sted. Den langsomste, men mest romantiske måde at sende post på."},"ICON-1477":{"nm":"Terning","de":"Seks sider, der smiler rundt, som om de siger, dig igen? Samme form, men alligevel giver den et nyt svar for hvert kast — det er denne vens urokkelige lune. I det øjeblik den forlader hånden, overlader man kort valget til skæbnen."},"ICON-1478":{"nm":"Papirvindmølle","de":"Den vågner først til live, når vinden blæser. Ladet i fred er den blot papirvinger, men puster nogen på den, begynder den at snurre lystigt. Ikke at skamme sig over at modtage hjælp er denne lille blomsts visdom."},"ICON-1479":{"nm":"Picnickurv","de":"Løft låget, og duften af gimbap byder først velkommen. Grøn græsplæne, et udbredt tæppe, og hænder der deler mad med hænder. De dage, denne kurv blev fyldt, var mærkeligt nok altid under en klar himmel."},"ICON-1480":{"nm":"Vase","de":"Sæt blot én stilk i, og selve rummets luft forandrer sig. Når den er tom, er det dens rette pligt at vente tavst. Rummets mest beskedne scenografi, der stille sænker sin egen tilstedeværelse for at lade blomsten skinne desto mere."},"ICON-1481":{"nm":"Kronblad","de":"Når vinden tager ét med sig, bliver foråret så meget lettere. Det gamle træ i gården giver samme hilsen hvert år — at også det at falde er en del af det at blomstre. At sprede sig er ikke enden, men et brev afsendt på forhånd til det næste forår."},"ICON-1482":{"nm":"Rose","de":"At rejse tornene først er et løfte om ikke at blive rørt hensynsløst. Indeni gemmer sig det rødeste af hjerter. Nogen lagde stille én stilk ned for foden og gik, og skrev sit hjerte alene i farve i stedet for et navn."},"ICON-1483":{"nm":"Lilje","de":"Ved siden af det rene hvide porcelæn stod altid denne hvide blomst. Må dens duft rejse langt, men dens holdning aldrig vakle. På det sted, hvor den valgte renhed frem for pragt, vogter liljen tavst over ét mål af værdighed."},"ICON-1484":{"nm":"Tulipan","de":"At stå på række med hovedet let bøjet virker på en eller anden måde så velordnet. Blomsten, der tager sig af forårsbedets forreste række. Dens ærlighed ved at blomstre alle på én gang og falme alle på én gang farver den korte årstid dybest."},"ICON-1485":{"nm":"Hyacint","de":"På én stilk hænger den tætpakkede, små klokker. Ryst den, og der er ingen lyd, men duften klinger gennem rummet i stedet. Ved forårets tærskel, en øm luksus der udskifter hele rummets luft med blot én vase."},"ICON-1486":{"nm":"Frøpræparat","de":"En lille krop, hvor tiden er stoppet, inde i en glaskasse. Etiketten siger: 'Rismarker og damme, mest livlig dagen efter regn.' Først efter stilstanden bevares selv temperaturen ved vandkanten, hvor et væsen levede, som en optegnelse."},"ICON-1487":{"nm":"Firbenpræparat","de":"Selv som præparat kan kløgten ved at kappe halen og flygte ikke slettes. En lille gæst, der elskede solvarme stendiger. På notatet ved siden af står retningen på den solplet, den elskede at klatre op på, skrevet tydeligt."},"ICON-1488":{"nm":"Muldvarpeoptegnelse","de":"Dagbogen for den, der færdes under jorden, er skrevet i jordens struktur. Hvor den gravede, og hvor den standsede — et kort over usynlige stier. Selv tid levet med ryggen til lyset bliver, for nogen, den mest samvittighedsfulde optegnelse."},"ICON-1489":{"nm":"Muslingepræparat","de":"Et solidt mønster, som bølgerne har poleret og sendt afsted tusindvis af gange. Folkene ved vaden kunne se på blot skallens struktur, hvilket hav den kom fra. Formen på et hav, der engang levede og åndede, rummes intakt i et håndfladestort præparat."},"ICON-1490":{"nm":"Koralpræparat","de":"Dybt i havet vokser den knap en håndsbredde over hundredvis af år. Den ligner grene, men er i virkeligheden et hjem bygget sammen af utallige små liv. At det, der er langsommere, varer længere, beviser koralen i tavshed."},"ICON-1491":{"nm":"Aidong-spor","de":"Et fragment af en historie spredt et sted på øen. Et lille stykke papir peger stille på det næste skridt. Ethvert eventyr begynder til sidst med at samle sådanne beskedne spor op, siger den gamle vejviser."},"ICON-1492":{"nm":"Signaturbrik","de":"Når det spredte mønster finder sin plads, fuldendes endelig ét kendemærke. En brik indgraveret med nogens helt eget præg. Den skjuler sin betydning, indtil den passes sammen, og i det øjeblik den passer, bliver den endelig et navn."},"ICON-1493":{"nm":"Scenemindeskår","de":"Selv efter en sang er slut, bliver der efterladt eftervarme blandt tilskuerne. Trækkes den varme af og størkner, bliver den til sådan et lille skår. Spredte fragmenter af klapsalver og jubelråb, samlet stille, genopliver hele den nat."},"ICON-1494":{"nm":"Debutstempel","de":"Den dag ens navn blev kaldt op for første gang, blækmærket der blev stemplet på håndryggen. Selv omhuen ved forsigtigt at lade det tørre, så det ikke tværedes ud, var en del af startlinjen. Ét lille stempel gør en bestemt dag umulig at slette for altid."},"ICON-1495":{"nm":"Topidol-medalje","de":"En tyngde, der kun tillades den, der når den højeste plads. Men denne medalje er ikke tung på grund af metallet. Det er fordi vægten af de utallige hænder, der sammen fyldte scenen, samles intakt i ét punkt."},"ICON-1496":{"nm":"Lille nøgle","de":"Boligens første nøgle var altid til det inderste værelse. Et sted, hvor man lærte at åbne, før man lærte at låse. Den dag man rejser, dvæler varmen, en håndflade har efterladt, længe på det kolde metal."},"ICON-1497":{"nm":"Skattekiste","de":"Før den åbnes, ved ingen, hvad der er indeni. Netop den uvidenhed er skattekistens sande skat. I det korte øjeblik man løfter låget, vender enhver et øjeblik tilbage til barndommens hjertebanken."},"ICON-1498":{"nm":"Byggetegning","de":"Oven på linjer trukket felt for felt lever en bygning, der endnu ikke er rejst. At folde tegningen ud er at gå gennem morgendagen én gang på forhånd. Én velført linje bærer en morgendag, der ikke styrter sammen."},"ICON-1499":{"nm":"Opskriftskort","de":"På ét fingerslidt kort står bedstemors håndelag skrevet som mængder. Vage ord som 'en knivspids salt' er den mest præcise hemmelighed. Jo mere udvisket skriften bliver, desto tydeligere dukker det køkken op, hvor den ret engang simrede."},"ICON-1500":{"nm":"Anlægstilladelse","de":"Ét stykke papir forvandler en tom grund til 'et sted, man kan bruge'. En ny bygning havde altid først brug for landsbyens stempel. Tilladelse er, i sidste ende, et varmt segl, der siger, det er i orden at begynde noget her."},"ICON-1501":{"nm":"Havnetilladelse","de":"Før et skib kunne kaste anker, skulle det først have dette ene stykke papir. Havnens falmede segl er den første hilsen til dem, der kommer langvejsfra. Mellem afsked og ankomst åbner havnen altid sit hjerte med et enkelt ark papir."},"ICON-1502":{"nm":"Øborgerbevis","de":"Et lille bevis på, at man er blevet en del af øens familie. Når en ny nabo flyttede ind, føjede den gamle landsby deres navn til listen og delte varme riskager ud. Det er kun et stykke papir, men på det står den lyse velkomst skrevet: \"Nu er du en af os.\""},"ICON-1503":{"nm":"Loginavneskilt","de":"Med et enkelt navn hængt op ved døren bliver et tomt værelse endelig nogens hjem. Selv i de gamle gæsteværelser var det først et skilt med husherrens navn, der blev hængt op. Skiltet er lille, men i det bor varmen af \"her bor der nogen.\""},"ICON-1504":{"nm":"Fanfrimærke","de":"Selv omhuen ved at slikke det og trykke det godt fast var en del af ét helt brev. Handlingen med at fæstne en kær følelse til et lille stykke papir og sende den langt af sted. Selv i den digitale tidsalder sender nogen stadig deres hjerte med posten, med egne hænder."},"ICON-1505":{"nm":"Glitterø-badge","de":"Fæst det på kraven, og et lille lys følger dig, uanset hvor du går. Møder man en fremmed med samme badge på gaden, forstår man hinanden uden et ord. Glimtet er ingen pral, men et stille signal: \"Vi elsker den samme ø.\""},"ICON-1506":{"nm":"Arbejdsbænk","de":"En ridset bordplade vidner om de hænder, der har skabt flest ting. Stedet hvor noget blev repareret, samlet og finpudset. Mere end et rent skrivebord rummer en rodet arbejdsbænk i virkeligheden langt flere historier."},"ICON-1507":{"nm":"Opbevaringskasse","de":"Jo mere dyrebart noget er, desto hurtigere bestemmer man sig for dets plads. Også i gamle dage opbevarede man kostbare dokumenter for sig selv i kister af paulownietræ. At opbevare noget godt er, i sidste ende, at folde i dag pænt sammen til gavn for nogen i fremtiden."},"ICON-1508":{"nm":"Forrådskasse","de":"Når der er overflod, samler man sammen; når der er for lidt, tager man frem. Her ligger visdommen fra en tid, hvor et velfyldt forrådskammer betød et roligt sind. At samle på forråd er at række et kærligt måltid videre til sit fremtidige jeg, i god tid."},"ICON-1509":{"nm":"Køleboks","de":"En kiste fyldt med is holdt på kulden selv midt om sommeren. Det er, som om ishusets gamle visdom er blevet flyttet over i håndfladestørrelse. At holde noget koldt er at lade det friskeste øjeblik dvæle en smule længere."},"ICON-1510":{"nm":"Vandpumpe","de":"Sving håndtaget op og ned, og vandet dybt nede i jorden stiger til vejrs. En ærlig maskine, der først fossede, når en enkelt øse spædevand var hældt i. Ved brønden lærte man tidligt sandheden om, at man må give, før man kan modtage."},"ICON-1511":{"nm":"Vandrenser","de":"Et lille mirakel, hvor uklart vand bliver klarere, lag for lag. I gamle dage filtrerede man vand ved at lægge sand og trækul lagvis i lerkrukker. Klarhed er ikke noget, man får gratis; det er den omhu, der ligger i langsomt at filtrere."},"ICON-1512":{"nm":"Vandkandeholder","de":"I det øjeblik vandkanden får et sted at hvile, bliver blomsterbedets dag ordentlig. At bestemme, hvor et redskab skal hænge, er vanen hos en, der elsker sit arbejde. Når blot ét sted er fastsat, bliver hele gården en anelse mere ryddelig."},"ICON-1513":{"nm":"Fiskestangsholder","de":"Selvom man går, indtil bidet kommer, holder fiskestangen sin plads. Den tålmodige holdning hos den, der fisker årene væk ved floden, er fæstnet lige her. En holder er, i sidste ende, en støtte til at lægge sin utålmodighed fra sig et øjeblik."},"ICON-1514":{"nm":"Sankekurv","de":"Mors håndfuld, der bar en håndfuld vilde grønne planter og en enkelt markblomst hjem. Gennem sprækkerne i det flettede bambus siver duften af jord stille ud. Alt efter hvad man fylder den med, kan en tom kurv blive til både forår og efterår."},"ICON-1515":{"nm":"Morter og støder","de":"Dunk, dunk – når kornet blev stødt i en jævn takt, vågnede landsbyens dag. Et redskab hvis dunken engang fyldte gyderne på højtidsdage. At gøre det hårde blødt kræver den vedholdende rytme fra en arbejdende hånd."},"ICON-1516":{"nm":"Skærebræt","de":"Hvert mærke kniven efterlader, indridser historien om et måltid. Et ridset træbræt er et køkkens medalje for de flittigste hænder. At skære noget begynder altid med ønsket om at servere det med omhu."},"ICON-1517":{"nm":"Gryde","de":"Boblende kogelyd er mildere end nogen musik. I den sultne morgengry er de tre minutter, man venter på, at nudlerne bliver møre, den mest private trøst. Hele den runde bund varmes op af ønsket om at mætte nogen."},"ICON-1518":{"nm":"Stegepande","de":"Kunsten at stege noget færdigt på et øjeblik over ilden hviler på denne ene pande. Jo bedre indbrændt overfladen er, desto mindre klæber den, og desto mere skinner den. En vel brugt jernpande er i sig selv beviset på de år, køkkenet har levet."},"ICON-1519":{"nm":"Ovn","de":"Mens man lukker lågen og venter, sker der stille magi indeni. Tiden hvor dejen hæver, og farven modnes. Selv når man ikke kan se det, hvis man venter i tillid, åbner et varmt resultat lågen og træder ud."},"ICON-1520":{"nm":"Blender","de":"Læg selv noget hårdt heri, og på et øjeblik bliver det til en blød drik. En lille hvirvelstrøm, hvor forskellige ingredienser blandes, og en ny smag fødes. Harmoni er, i sidste ende, at hver enkelt giver lidt af sine egne kanter fra sig."},"ICON-1521":{"nm":"Piskeris","de":"Et enkelt sving med håndleddet fanger luften, og det tynde stivner, lige så hurtigt som man pisker. Mens boblerne rejser sig som toppe, er det ikke kun dejen, der hæver. Ønsket om at mætte nogen i dag hæver med lige så meget."},"ICON-1522":{"nm":"Kaffekværn","de":"Drej håndtaget over en håndfuld bønner, og duften brydes først løs mellem tænderne. Når armen begynder at værke, er kornene endelig fine nok, og den første slurk bliver lige så dyb som umagen. Omhu begynder altid ved håndleddet."},"ICON-1523":{"nm":"Kornmølle","de":"Kornet går ind mellem stenene og kommer ud som hvidt mel. Det gør ikke noget, hvis det ikke bliver fint første gang; man maler bare to gange til. Selv det at gøre det grove fint har sin orden, minder kornmøllen os tavst om."},"ICON-1524":{"nm":"Savbænk","de":"Når en træstamme kommer op, læser saven først årerne. Man styrer uden om knasterne og skærer kun langs den lige linje, så brættet ikke slår sig. At skære træ er, i sidste ende, at brede ordentligt og jævnt ud den tid, et enkelt træ har levet."},"ICON-1525":{"nm":"Symaskine","de":"Rrrrr – lyden af nålen, der bider sig fast i stoffet og løber af sted, fylder den sene aften. En enkelt søm samler to stykker til én krop, og i hver skjulte sting inde i en scenedragt er nogens søvnløse timer solidt syet fast."},"ICON-1526":{"nm":"Farvebord","de":"Dyp det hvide stof og løft det op igen: først er det lysegrønt, men i mødet med luften bliver det endelig blåt. Den farve, siges det, kommer først frem, når indigoen er trukket tre gange. At selve ventetiden bliver til farve, lærte jeg først foran dette farvebord."},"ICON-1527":{"nm":"Kamerastativ","de":"I det øjeblik de tre ben spredes og rører jorden, går den vaklende verden i stå. Et billede, der ville have rystet i hånden, bliver skarpt på løftet fra disse tre punkter. For at se længe på noget må man først vide, hvordan man står stille."},"ICON-1528":{"nm":"Lysstativ","de":"Sæt et lys øverst på en enkelt stang, og ethvert sted i rummet bliver en lille scene. Vrid vinklen en smule, og skyggerne bliver længere, mens udtrykkene vågner til live. Det sletter ikke mørket, men sætter selv mørket blidt på sin plads."},"ICON-1529":{"nm":"Mikrofonstativ","de":"I det øjeblik højden er indstillet, er afstanden mellem mund og sang fastlagt. Slip taget med hænderne, og stemmen bliver alligevel stående der. Først på en scene, hvor begge hænder er fri, begynder sangen, der synges med hele kroppen, for alvor."},"ICON-1530":{"nm":"Nodestativ","de":"Når det åbne ark læner sig på skrå, stiller noderne op i rækker ved musikerens øjenhøjde. Selv når næste takt kommer med en enkelt håndbevægelse, vakler stativet ikke. Bag nogens spil er der altid en tavs plads."},"ICON-1531":{"nm":"Køkkenhave","de":"Vend jorden og lav furer, og små linjer af løfte opstår på marken. De første dage efter frøet er sat, ser der ud til at ske intet, men en morgen presser spæde kimblade jorden til side. Det er et syn, kun den, der har ventet, kan se."},"ICON-1532":{"nm":"Frugtbar køkkenhave","de":"Samme frø, men i denne jord bliver bladene dobbelt så store. Stik en finger ned, og mørk, blød muld følger med helt op under neglen. At gro godt var, i sidste ende, det arbejde den usynlige jord stille udførte under fødderne."},"ICON-1533":{"nm":"Drivhus","de":"Under et glasloft strømmer årstiderne en anelse langsommere. Selv når rimfrost falder udenfor, er der indenfor fugtigt af højsommerens luft. For de ting, der er svage over for kulden, har nogen stille fanget solskinnet i taget."},"ICON-1534":{"nm":"Krydderurtebed","de":"Stryg fingerspidserne hen over bladene, og duften hilser først. Basilikum, rosmarin, mynte – nævn hvert navn, og en anden duft klæber sig til fingrene. Ét lille bed forvandler hele køkkenet med varme."},"ICON-1535":{"nm":"Frugthave","de":"Om foråret bøjer grenene sig under blomsterskyggen, om efteråret under frugtens vægt. Klatr op ad stigen, pluk ét og bid i det, og et helt års solskin, gemt som sødme, springer ud i munden. Det er, som om træet giver et menneske et svar."},"ICON-1536":{"nm":"Svampestamme","de":"Bor huller i en fældet stamme og plant sporerne, og det døde træ opdrætter noget nyt igen. Nogle dage senere, den morgen hattene spirer frem i klaser, begynder en ny tilværelse stille dér, hvor man troede, alt var slut."},"ICON-1537":{"nm":"Bikube","de":"Hold øret tæt til, og man hører en lav, flittig summen indeni. Tusindvis af vingeslag samles til knap en enkelt skefuld sødme. En dags slid, fløjet fra blomstermark til blomstermark, ligger og hviler her, klæbrig og gylden."},"ICON-1538":{"nm":"Hønsehus","de":"Før morgengryet raslede de først, dem der sad på vagerne. Stik hånden ned i det varme halm, og man griber et æg, der stadig holder på varmen. Stedet, der først bebuder morgenen, dækker også først morgenbordet."},"ICON-1539":{"nm":"Græsgang","de":"En bred mark, hvor duften af græs blander sig med duften af sol. Over rygge, der langsomt tygger drøv bag hegnet, glider skyernes skygger forbi. Her, hvor intet haster, flyder selv tiden langsomt af sted, som var den ved at græsse."},"ICON-1540":{"nm":"Osteværksted","de":"Nymalket mælk hærder langsomt gennem koagulering og modning. Vent nogle måneder på en hylde, kølig som en grotte, og dyb smag siver ind i den hvide masse. Ost er et navn, der kun gives til mælk, som ikke har hastet."},"ICON-1541":{"nm":"Tofuværksted","de":"Læg bønnerne i blød, mal dem og kog dem, og den rå bønnemælk bliver nøddeagtig. En enkelt dråbe nigari samler det spredte til blød tofu, og presset stille sammen, tager den kvadratisk form. Her er en hånd, der trøster et spredt sind til en form."},"ICON-1542":{"nm":"Jangdok-krukketerrasse","de":"I et solrigt hjørne af gården samles lave lerkrukker tæt om hinanden og soler sig. Løft et låg, og duften af gammel tid vælter frem. Smagen af den pasta, bedstemor lagde ned, er i virkeligheden at spise årene, en skefuld ad gangen."},"ICON-1543":{"nm":"Mølle","de":"Når stenene drejer med et rumlende drøn, løsner kornet sig til mel. Hvidt støv driver gennem sollyset, mens folk, der venter på at ælte et fad riskager, venter på deres tur. Landsbyens festdag så altid ud til at begynde ved denne tærskel."},"ICON-1544":{"nm":"Bageri","de":"Gennem sprækken i ovnlågen siver duften af smør og sukker ud. Når den hævede dej bliver gylden, sænker fodtrin, der går forbi butikken, ubevidst farten. Et enkelt friskbagt brød rummer en ømhed, ingen kan modstå."},"ICON-1545":{"nm":"Snackvogn","de":"Presenningen flagrer i vinden, og tteokbokki-suppen simrer ned. En aften med at sluge suppe af papkrus til et enkelt fiskekagespyd, et sted der smelter kulde og sult væk på én gang. En lille trøst placeret for enden af gyden."},"ICON-1546":{"nm":"Vestligt køkken","de":"Panden bliver varm, og olivenolien hvæser. Med et enkelt sving af varmen kan en sauce enten binde eller brænde på. Her, hvor selv balancen af farver på tallerkenen vejes nøje, bliver et måltid til en omhyggeligt iscenesat forestilling."},"ICON-1547":{"nm":"Kinesisk køkken","de":"Over kraftig ild snurrer woken rundt, som dansede den. I det korte øjeblik, flammerne slår op, lukkes ingrediensernes duft helt inde. Hurtigt og hedt – tøver man, går det tabt i netop det åndedrag, hvor den kinesiske madlavnings hemmelighed gemmer sig."},"ICON-1548":{"nm":"Café","de":"Skub døren op, og duften af kaffebønner og stille musik hilser først. En plads ved vinduet, en kølnende latte, en åben notesbog. For at lade dig få vejret i en travl dag har byen gemt små rum som dette hist og her."},"ICON-1549":{"nm":"Dessertbutik","de":"Bag glasmontren står farverige kager på række og venter på kunder. I det øjeblik gaffelspidsen skærer gennem cremen, løfter mundvigene sig først. En lille, sød recept, der gør selv en trist dag til at holde ud, med bare ét stykke."},"ICON-1550":{"nm":"Slagterbutik","de":"Under det røde lys ligger kødet pænt langs fibrene. Ved et enkelt ord – \"denne er god i dag\" – glider kniven i præcis den rette tykkelse. Aftensbordets mæthed begynder stille med denne hånd, der holder samme plads hver eneste dag."},"ICON-1551":{"nm":"Fiskebord","de":"Et arbejdsbord, hvor morgengryets fiskelugt blandes med isens kulde. Skæl flyver, og hænderne bliver følelsesløse, men øjet, der udvælger det friskeste, standser aldrig. Her finder det, der lige er kommet op af havet, sin vej til bordet."},"ICON-1552":{"nm":"Saltpande","de":"Lås havvandet inde, og solen og vinden klarer resten. Vent nogle dage på, at vandet tørrer, og hvide krystaller spirer på bunden som stjerner. En håndfuld salthed er i virkeligheden en gave, havet og himlen langsomt har skabt sammen."},"ICON-1553":{"nm":"Tangtørrestativ","de":"På en lang line hænger tang og tare side om side og vugger i vinden. Det, der er tungt af havvand, mørkner til dyb grøn, mens det tørrer. Havets mest nøjsomme smag, skabt sammen af sol og saltvind, hænger her."},"ICON-1554":{"nm":"Lille bådebro","de":"Træplanker, halvt sunket i vandet, gynger let under fødderne. Netop det rette sted at fortøje én lille båd. Både det at drage langt bort og det at vende trygt hjem begynder og ender ved denne ene plads."},"ICON-1555":{"nm":"Havnepakhus","de":"Åbn den træport, der er garvet af havvind, og net, tønder og reb er stablet helt op til loftet. Last på vej ud på en lang rejse og last, der lige er ankommet, hviler et øjeblik under samme tag. Et sted som en transitstation, hvor afsked og hjemkomst kort strejfer hinanden."},"ICON-1556":{"nm":"Fyrtårn","de":"Først når nattehavet bliver mørkest, begynder det endelig sit arbejde. Lyset, der drejer rundt, skærer gennem tågen og siger: \"Her er der en vej.\" En høj vagtpost, der for nogens trygge hjemkomst nægter til det sidste at falde i søvn."},"ICON-1557":{"nm":"Skibsværft","de":"Rejs kølen og fæstn spanterne, og skelettet af et skib tager form. På en plads, hvor hamre klinger dagen lang, drømmer et skib, der endnu ikke kender vandets smag, om sin første rejse. Et sted, der først bliver stærkt for at kunne drage af sted."},"ICON-1558":{"nm":"Indspilningsboks","de":"Når døren lukkes, forsvinder al lyd udefra på et øjeblik. Alt man hører gennem hovedtelefonerne er ens eget åndedrag og takten. I dette lille rums stilhed fødes endelig en stemme, der frit må ryste."},"ICON-1559":{"nm":"Musiklokale","de":"Harmonier, der siver ud gennem dørsprækken, fylder gangen. Nogen følger tonerækken, nogen tæller takten. Et sted hvor kejtede lyde og modne lyde godt må blandes, et venligt klasseværelse, hvor hver sang tager sine første skridt."},"ICON-1560":{"nm":"Klaverrum","de":"Åbn klaverlåget, og et fint lag støv ligger på de hvide tangenter. I det øjeblik fingrene rører dem, breder en klar klang sig gennem rummet. Findes der aftener, hvor man ikke er ensom, selv alene, skyldes det nok dette ene klaver."},"ICON-1561":{"nm":"Danserum","de":"Pres med tæerne, og gulvet skubber tilbage. Mens spejlene på de fire vægge kopierer den samme bevægelse fire gange, husker kroppen koreografien et halvt slag før rytmen. Rummet hvor sved og åndedræt dvæler længst; bevægelserne, der vokser op her, går ud på scenen."},"ICON-1562":{"nm":"Træningsrum","de":"Vægten lyver aldrig. Folk opsøger mig hver eneste morgengry, fordi de elsker den ærlighed – præcis så meget, som man løfter, tilskrives skuldrene. Det, der langsomt indridses i spejlet, er ikke muskler, men de timer, man holdt ud uden at give op."},"ICON-1563":{"nm":"Yogarum","de":"Træk vejret dybt ind, og det føles, som om trægulvet svulmer med. Et rum hvor man langsomt folder en dag, der kom farende, sammen; på en enkelt måtte vender enhver tilbage til tempoet i sit eget åndedræt. Selv et forhastet sind lægger sig ned her et øjeblik."},"ICON-1564":{"nm":"Sminkerum","de":"Lige inden man træder ud på scenen, bliver folk her kort til nogen anden. Når pærerne omkring spejlet varmer ansigtet jævnt, klæber skælven sig til spidsen af pudderkvasten og gemmer sig stille bag kraven. Stedet, hvor forvandlingen både begynder og slutter."},"ICON-1565":{"nm":"Kostumerum","de":"Før en enkelt sceneoutfit er færdig, bliver tøjet, der hænger her, taget på og af snesevis af gange. En mannequin, der drejer med hæftenåle stukket i, sømlinjer trukket op med kridt. Bag glimmeret er der altid sporet af nogens sytøj tilbage."},"ICON-1566":{"nm":"TV-kulisse","de":"Kun den ene side, kameraet viser, behøver at se ægte ud – det lærte jeg tidligt. Gå om bagom krydsfineret, og der er kun et tomt skelet. At bære facadens pragt er altid de usynlige lægters lod."},"ICON-1567":{"nm":"Fotostudie","de":"Det første trick er at kaste lys fra tre retninger for at slette skyggerne. Hovedlyset fremhæver ansigtet, fyldlyset skyggerne, baglyset hårets spidser. I det øjeblik lukkeren falder, fanger et enkelt hvidt baggrundstæppe dagens bedste smil."},"ICON-1568":{"nm":"Koncertsal","de":"I mørket under det høje loft bærer jeg altid det samme løfte: at når tæppet går op, holder selv de tomme sæder vejret som ét menneske. For netop det ene øjeblik, det første slag falder, står jeg stille tom hele året."},"ICON-1569":{"nm":"Fanmødebås","de":"Afstanden mellem hånd og hånd er nøjagtig ét skrivebord bred. En kort hilsen, en rystende autograf, et ord der aldrig helt blev sagt, passerer forbi på række. I denne lille bås mødes en kær følelse, der er plejet længe, ansigt til ansigt for første gang."},"ICON-1570":{"nm":"Seng","de":"Det var altid mig, der først tog imod dagens afslutning. Når de ben, der er tunge af øvelse, og selv skælven, der er tilbage bag scenen, endelig har lagt sig, begynder morgenen igen på lette tæer. Jeg siger godnat og holder dig tavst i mine arme."},"ICON-1571":{"nm":"Køjeseng","de":"Mellem øverste og nederste køje forbinder fem stigetrin to mennesker. Små stemmer delt, efter lyset er slukket, selvlysende stjerner klistret på loftet. Det trange værelse bliver bredest takket være de historier, der klatrer op og ned ad stigen hver nat."},"ICON-1572":{"nm":"Hylde","de":"Det man stiller op på mig, viser, hvem man er. Et modtaget brev, den første trofæ, en falmet billet ligger på række. Jeg er ikke møbler til at prale med, men et sted der stille udstiller de minder, man ikke kunne bære at smide ud."},"ICON-1573":{"nm":"Skrivebord","de":"Med sangteksthæftet åbnet trækkes nye linjer igen oven på de udviskede mærker. Papkrus stablet gennem natten og en enkelt melodi, netop reddet i land. Det langsomme arbejde med at flytte hjertet over i ord udspiller sig altid stille på denne flade overflade."},"ICON-1574":{"nm":"Stol","de":"\"Sæt dig lige et øjeblik\" er, mærkeligt nok, en øm ting at sige. Uanset hvor langt mødet trækker ud, eller hvor længe øvelsen varer, bærer ryglænet tavst en persons vægt. Jo længere nogen har stået op, desto mere byder de mig velkommen – det ved jeg."},"ICON-1575":{"nm":"Sofa","de":"For at forvandle det sene logi til en stue, er jeg alene nok. Klem jer sammen og se underholdning, og før længe er en af jer faldet i søvn mod armlænet. Den nedsunkne midterplads beviser det hjems varme."},"ICON-1576":{"nm":"Bord","de":"Sæt jer omkring, og ingen sidder for bordenden. Nykogt gryderet, lyden af skeer der klirrer, dagens hændelser samles alle i midten. Når en enkelt rund flade breder sig ud, sætter selv en spredt dag sig sammen igen om ét sted."},"ICON-1577":{"nm":"Klædeskab","de":"Hver gang årstiden skifter, vælter gamle historier ud indefra. Scenetøj og hverdagstøj skulder ved skulder, mens tøjet bag den lukkede dør venter på sin næste tur. Først når døren åbnes, bestemmes den dag, man skal have på i dag."},"ICON-1578":{"nm":"Spejl","de":"Både ros og fejl giver jeg tilbage med samme ærlighed. Stedet for det sidste eftersyn, før man træder ud på scenen; foran mig retter folk deres udtryk til og retter ryggen. Den mest ærlige ven siger aldrig et eneste ord."},"ICON-1579":{"nm":"Sminkebord","de":"I hver lille skuffe sover et andet ansigt. Ét glas til scenen, ét til hverdagen, ét gemt limited edition-glas. Sæt dig foran spejlet, og du begynder langsomt med at bestemme, hvem du bliver, når du træder ud ad døren i dag."},"ICON-1580":{"nm":"Tæppe","de":"Den følelse, bare fødder først møder, bestemmer rummets temperatur. Sporene efter at sidde rundt og spise snacks og rulle rundt bliver til nullermænd. Et møbel, der arbejder fra det laveste sted, og varmer det kolde gulv en håndsbredde varmere."},"ICON-1581":{"nm":"Gardin","de":"Hvor meget morgen, der skal lukkes ind, bestemmer jeg. Trækkes jeg let for, strømmer solskinnet langt ind; lukkes jeg helt til, bliver selv oversovsen tilgivelig. At stå mellem vindue og rum og stille regulere lysmængden er altid den opgave, der er betroet mig."},"ICON-1582":{"nm":"Lampe","de":"Det samme rum bliver til et helt andet tidspunkt af dagen alt efter lysets farve. Gult lys strækker aftenen lang, hvidt lys vækker morgengryet skarpt. En håndfladestor tryllekunstner, der med et enkelt tryk lumsk skifter dagens stemning."},"ICON-1583":{"nm":"Vægur","de":"Lyden af sekundviseren høres kun i et stille rum. Jo dybere øvelsen bliver, desto mere glemmer man mig, og pludselig kigger man op og opdager, at det allerede er blevet morgengry udenfor. Uden nogensinde at bebrejde den tid, der er gået, peger jeg blot tavst på næste tak."},"ICON-1584":{"nm":"Vase","de":"Selv når blomsterne visner, lader jeg ikke min plads stå tom. Et kar der en tid rummer en modtaget følelse; så længe der er en hånd, der skifter vandet, forbliver bordet lyst. Selv når jeg er tom, står jeg i formen af at vente på nogen."},"ICON-1585":{"nm":"Posterramme","de":"Selv det at hænge et elsket ansigt op på væggen kræver omhu. Et sted, solen ikke rører direkte, et enkelt søm sat helt i vater. Et ark papir, lagt varsomt bag glas, er det første, der hilser på mig, hver morgen jeg træder ind i rummet."},"ICON-1586":{"nm":"Photocard-tavle","de":"Om man skal ordne dem alfabetisk eller efter udgivelsesrækkefølge – netop det lykkelige dilemma er, hvor fandom begynder. Et enkelt tomt rum er pladsen til den favorit, man endnu ikke har mødt. Efterhånden som den fyldes ét kort ad gangen, bliver tavlen til min egen lille krønike."},"ICON-1587":{"nm":"Lightstick-holder","de":"Batteriet ud, håndtaget opad. Selv i vinklen, man læner og rejser den på skrå i, ligger der et vist kneb. Mens den venter på næste jubelråb, slukker stangen sit lys lige her og lægger kroppen pænt til ro. Kun ved at hvile godt tænder den endnu klarere."},"ICON-1588":{"nm":"Trofæhylde","de":"Forrest på rækken står den ældste. Fra den lille konkurrences statuette til den store scenes pokal stiller de op, ikke efter højde, men efter hjertets rækkefølge. Hver gang jeg pudser dem, klæber skælven fra den dag på scenen sig til fingerspidserne igen."},"ICON-1589":{"nm":"Picnickurv","de":"Løft låget, og duften af forårssol siver ud først. Gimbap, en termokande og et enkelt tæppe ligger stablet pænt, klar til at drage ud i det fri. Skridtene hos den, der bærer mig, bliver altid, af en eller anden grund, en håndsbredde lettere end sædvanligt."},"ICON-1590":{"nm":"Lille urtepotte","de":"En håndsbred vindueskarm er nok til mig. En lille grøn plante, der overbærende holder ud, selv når man ofte glemmer at vande den. I hjørnet af et travlt skrivebord folder jeg et blad mere ud hver dag og sender stille dagens hilsen."},"ICON-1591":{"nm":"Stor urtepotte","de":"Mens jeg vokser i højden, vokser mennesket med mig. Når de brede blade, der optager et hjørne af stuen, fanger solen og kaster skygge, kommer årstiden også lumsk ind i rummet. En glæde kun kendt af den, der ikke glemmer at vande."},"ICON-1592":{"nm":"Duftlyssæt","de":"I det øjeblik vægen tændes, sænker rummets luft sig et hak. Duften breder sig langsomt, varmer gårsdagens træthed op og sender den ud. Med en enkelt lille flamme afsluttes enden på en travl dag som et stille ritual."},"ICON-1593":{"nm":"Minikøleskab","de":"Åbn døren sent om aftenen, og en kold sodavandsdåse byder mig velkommen. En lille summende brummen gør det tomme logi en anelse mindre ensomt. Jeg kan ikke stå for en stor husholdning, men når det gælder en sulten morgengry, er der intet som mig."},"ICON-1594":{"nm":"Guldsmedenethat","de":"I det øjeblik man sætter den på hovedet, følger en sommermark med op på skuldrene. Det runde net filtrerer sollyset fint, og med hvert skridt vugger duften af græs blidt. En hat der hyller hele årstiden om sig, fin nok selv uden at fange en eneste guldsmed."},"ICON-1595":{"nm":"Sankenetpose","de":"Hængt ved hoften bliver den en følgesvend i indsamlingen. Stram åbningen let til, så det fangede ikke slipper ud igen – det første kneb lært ude på marken. En enkelt let stofpose favner nænsomt en dags høst."},"ICON-1596":{"nm":"Insektglas","de":"For en gæst, der kun bliver et øjeblik, betyder luftehuller mest – det ved jeg. En lille åndedrætsvej boret i låget, et enkelt græsblad lagt på bunden. At sende den tilbage til græsset, når observationen er slut, hører også med til parret."},"ICON-1597":{"nm":"Insektnåleæske","de":"Der ligger dygtighed selv i den ene vinkel, man stikker en nål skråt ind i. For dybt, og den knækker; for lavt, og den vakler, så man må dele kraften i fingerspidserne præcist. En æske der stille rummer omhuen hos den, der ønsker at se længe på et lille liv."},"ICON-1598":{"nm":"Terrarielåg","de":"At passe grænsen mellem inde og ude er mit job. Lukkes jeg for stramt, kvæles der; lades jeg for løst, farer man vild, så jeg efterlader altid en sprække som et kryds. At beskytte er tydeligvis noget andet end at spærre inde."},"ICON-1599":{"nm":"Sommerfuglefoderskål","de":"Læg vat gennemvædet i sukkervand i midten, og vingerne samles om det. Trikket er at holde den lavvandet og bred, i en dybde hvor små fødder ikke synker. Én enkelt skål samler stille de gæster, der lige stopper forbi en solrig have."},"ICON-1600":{"nm":"Insektlokkelampe","de":"Lad den lyse svagt i mørket, og små vinger samles og følger lyset. Hold lysstyrken dæmpet, pladsen langt fra mennesker. En yderst venlig lokkedue, der får den summende sommernat til at falde til ro."},"ICON-1601":{"nm":"Insektklistermærke","de":"Seks ben og et par følehorn – i en lap papir på størrelse med en negl sover et lille liv. Sæt det forsigtigt på hjørnet af en notesbog, og en håndsbred eng folder sig stille ud mellem siderne."},"ICON-1602":{"nm":"Indsamlingstilladelse","de":"Før sommerfuglenettet løftes, spørger den voksne først: hvor mange, og hvor langt. Dette ene lille mærke tegner en venlig streg mellem opstemt nysgerrighed og et løfte, der skal holdes."},"ICON-1603":{"nm":"Madingdåse","de":"Åbn låget, og en fiskeagtig, kølig morgenduft stiger op. Det, der lokker fisken, er måske ikke madingen, men et hjerte, der ved, hvordan man venter stille, til flåden dirrer."},"ICON-1604":{"nm":"Flådeetui","de":"Et lille skab, hvor flåder i alle farver ligger og sover, rum for rum. Nogle er en stille søs morgen, andre en voldsom strøms middag. Til hvert af vandets udtryk er den rette makker pænt lagt til side."},"ICON-1605":{"nm":"Fiskesnørespole","de":"Vikl ikke løs line om fingrene. Rul den pænt tilbage på dette runde redskab, og selv sammenfiltringerne løses stille op. Det minder om den hånd, der bringer orden i en dag, der er blevet slap."},"ICON-1606":{"nm":"Krogudtager","de":"Kun den, der har stukket sig selv ved at trække en fastsiddende krog ud med bare fingre, genkender dette redskab. En vej, der gør mindre ondt, både for det lille væsen og for mine fingerspidser. Hensyn begynder altid ved sådanne små detaljer."},"ICON-1607":{"nm":"Muslingespadecover","de":"Et enkelt lag, der omslutter spadebladet, lige gravet op af vaden. Så mudder og saltvand ikke gnaver æggen, lægger det stille et tyndt, blødt hvil mellem havet og redskabet."},"ICON-1608":{"nm":"Tidevandstabelkort","de":"Hvornår vandet kommer ind, og hvornår det trækker sig tilbage – et håndfladestort kort fortæller det stille. Et lille kalenderblad, som et menneske har skrevet ned, af det gamle løfte, månen og havet gav hinanden."},"ICON-1609":{"nm":"Akvariebørste","de":"Fej forsigtigt den grønne alge af glasvæggen, og lyset siver igen ind i den lille verden under vandet. At gøre nogens dag klarere flyder som regel lige så stille som dette."},"ICON-1610":{"nm":"Akvarietermochip","de":"Et enkelt tal blinker, og når det stopper ved den rette grad, falder fiskene endelig til ro. Et rum af varme, hverken for koldt eller for varmt. Omsorg når helt ud til de usynlige steder."},"ICON-1611":{"nm":"Havdyrobservationsrør","de":"En lille gæst, der opholder sig en stund i det klare rør. Tæl rygfinnen stille, og send den tilbage til havet. At observere er ikke at eje, men at låne for en lille stund."},"ICON-1612":{"nm":"Fossilbørste","de":"Det, der vækker stenens årer efter titusinder af år i søvn, er ikke en hammer, men en blød børstespids. Foran en tid, der ville smuldre, hvis man hastede, bliver forsigtighed den dybeste form for høflighed."},"ICON-1613":{"nm":"Udgravningsbørstehætte","de":"Når børstespidsen tørrer helt ud, falder end ikke jorden pænt fra hinanden. En lille hætte holder børstens ånde fugtig. En hånd, der passer på sine redskaber, tager udgravningens første skridt."},"ICON-1614":{"nm":"Lagprøveplade","de":"I en håndsbred jord ligger hundreder af år lagt lag på lag. Skovl den stille op på denne plade, og tidens mønstre, usynlige indtil nu, trækker deres linjer og stiger langsomt frem."},"ICON-1615":{"nm":"Knoglefragmentbakke","de":"Læg de spredte fragmenter rum for rum, og et liv, engang spredt for vinden, famler langsomt sig tilbage til sin plads. Genopbygning er arbejdet med kærligt at spørge efter en tabt orden."},"ICON-1616":{"nm":"Restaureringstape","de":"En tynd, enkelt strimmel, der samler det knuste sted. Den skjuler ikke arret, men omfavner og holder det ømt fast. Den beviser stille, at selv det, der gik i stykker, kan blive helt igen."},"ICON-1617":{"nm":"Udstillingsskiltcover","de":"Et enkelt ark, der forsigtigt dækker skiltet bag glasset, så det ikke falmer. Det bærer ønsket om, at den korte sætning om, hvem der levede, og hvor, kan læses klart selv langt ude i fremtiden."},"ICON-1618":{"nm":"Magasinmærke","de":"Et dybt rum, hvor skatte, der aldrig trådte frem i lyset, ligger og sover. Alt derinde bærer et lille navneskilt – så de aldrig glemmes, selv uden at stå på en oplyst plads."},"ICON-1619":{"nm":"Museumsdonationskuvert","de":"Nogen rækker uden ord det, de har samlet på gennem et helt liv, videre. Det, der ligger i denne kuvert, er ikke en ting, men et hjerte, man har båret på længe. At dele bliver den længst varende udstilling, der lyser på nogen."},"ICON-1620":{"nm":"Prøvenummerchip","de":"Lige på det sted, hvor man indsamlede det, tildeles stille et lille nummer. Hvornår, og hvor, man først mødte det. En opdagelse, der ikke bliver noteret, spredes snart som morgentåge."},"ICON-1621":{"nm":"Meteorskårflaske","de":"Et skår, der faldt hen over nathimlen, er fanget i en glasflaske. En enkelt lysstråle, der slukkedes, før man nåede at ønske sig noget, glimter nu stille igen i hånden."},"ICON-1622":{"nm":"Muslingevindspilssnor","de":"Træ muslinger, samlet en for en ved kysten, på en snor og hæng den under tagskægget. Hver gang vinden går forbi, med en klirrende raslen, følger den sommers hav stille med helt ind i huset."},"ICON-1623":{"nm":"Regnbuedråbe","de":"En enkelt dråbe, der samler sig og triller på en bladspids, efter regnen har lagt sig. I den runde form rummes hele himlen og alle syv farver i en cirkel. Somme tider bærer det mindste den bredeste udsigt."},"ICON-1624":{"nm":"Tågesamlerflaske","de":"Jeg tog en hel flaske daggrytåge med hjem fra bjergsiden. Griber man om den, er den kølig og dugget mælkehvid. En lille, øm griskhed efter at holde det, man ikke kan gribe fat i, tæt en stund."},"ICON-1625":{"nm":"Dugopsamlerkop","de":"En lille kop, der opfanger den dug, græsstråene har samlet dråbe for dråbe natten igennem. End ikke en hel mundfuld, men morgenens klareste, reneste del samler sig stille dér."},"ICON-1626":{"nm":"Brisebåndspin","de":"Et bånd, bundet i selve mønstret af den vind, der er gået forbi. Sæt det i håret, og for hvert skridt følger en mild brise, svajende blidt med. Forårsdagens lethed er stille fæstnet i en enkelt nål."},"ICON-1627":{"nm":"Bølgelydskapsel","de":"Hold den stille til øret, og bølgerne fra det fjerne hav skyller ind. Det er, som om nogen omhyggeligt har forseglet i en lille kapsel den lyd, man engang gemte i en konkylie som barn."},"ICON-1628":{"nm":"Sandstjernefragment","de":"Tag en håndfuld sand på nattestranden, og stjernesmuler blander sig imellem og glitrer. Om de faldt fra himlen, eller bølgerne har slebet dem fine, spørger ingen sig for om."},"ICON-1629":{"nm":"Ø-vejrlogchip","de":"Øens himmel skifter sind flere gange om dagen. Notér klart vejr, tåge og byger pænt ned på en lille chip, og du kan folde gårsdagens himmel ud igen i dag."},"ICON-1630":{"nm":"Klippetrappesæt","de":"Et trin, og så endnu et, til at gå op og ned ad den stejle skråning. Saml de spredte dele, og selv en klippe bliver en afslappet spadseretur. At anlægge en sti er at lægge nogens næste skridt til rette på forhånd."},"ICON-1631":{"nm":"Jordstimønsterrulle","de":"En rulle, der har taget selve strukturen af en blød jordsti. Rul den ud med en svup, og en landevej, der får dig til at ville gå barfodet, breder sig stille ud under fødderne."},"ICON-1632":{"nm":"Brostensmønsterchip","de":"Mønstret fra brostenene, der engang dækkede de gamle gyder, er bevaret helt i en lille chip. For hvert skridt, klik-klak, vender en gammel landsbys fodtrin tilbage til live under tæerne."},"ICON-1633":{"nm":"Strandhegnsstykke","de":"Et enkelt stykke af det lave hegn, sat op i sandet, så bølgerne ikke kan komme over. En lille, tavs grænsevogter, der står og trækker en venlig streg mellem havet og sandet."},"ICON-1634":{"nm":"Græsrestaureringslap","de":"Et stykke grønt, lagt forsigtigt over et sted, der er trådt bart. På få dage rækker græsstråene hånd til hinanden og fylder det tomme sted ud. Naturen ved altid selv, hvordan den heler."},"ICON-1635":{"nm":"Vandvejsmarkeringspæl","de":"En pæl, der på forhånd viser den vej, vandet skal løbe. Så regnvandet ikke famler og undrer sig over, hvor det skal hen, står en lille pind slået ned i jorden tavst selv på regnvejrsdage."},"ICON-1636":{"nm":"Lille brodel","de":"Et enkelt stykke af en lille bro, der forbinder åens to bredder. Mellem denne side og den anden begynder løftet om, at man altid kan krydse over, stille med denne ene lille del."},"ICON-1637":{"nm":"Udsigtsrækværkshætte","de":"På øens højeste sted, en enkelt afsluttende del, der omslutter enden af det gelænder. Den støtter og vogter stille det sted, som hænderne på dem, der er samlet for at se ud i det fjerne, oftest rører ved."},"ICON-1638":{"nm":"Bålfundament","de":"Før brænde lægges på, et sted, der holder gløderne, så de ikke spredes. Over det brænder nætterne, hvor man kiggede op på stjernerne og snakkede lystigt sammen, varmt i lang, lang tid."},"ICON-1639":{"nm":"Tapetprøverulle","de":"Et rums stemning begynder ved en enkelt væg. At rulle en lille rulle ud og vælge en farve er stille at tegne på forhånd, hvilken slags dage man ønsker at leve herfra."},"ICON-1640":{"nm":"Gulvprøvechip","de":"Mærk først med fingerspidserne følelsen af det gulv, de bare fødder skal røre. Varmt eller køligt – på denne ene lille chip hænger stille hyggen i de dage, man skal leve herfra."},"ICON-1641":{"nm":"Loftskrogsæt","de":"I det øjeblik man hænger en enkelt krog på bjælken, bliver det tomme loft et sted, der venter på nogen. En vindspil, eller en urtepotte? Denne lille jernkrog bærer vægten, men hvad der skal hænges op, er beboerens hjerte, der bestemmer."},"ICON-1642":{"nm":"Vinduestoningsfilm","de":"Middagslyset er for ærligt, så man klæder vinduet i et tyndt enkelt lag. Solskinnet kommer stadig ind, men kanterne blødgøres, og alt i rummet bliver mildt abrikosfarvet. Det er ikke afskærmning, men at få lyset til at brede sig kærligt."},"ICON-1643":{"nm":"Dørklokkecover","de":"Med den begrundelse, at selv klokken, en gæst trykker på, har brug for tøj, satte nogen et rundt cover på. Det holder regnen ude, holder støvet ude, og er frem for alt den lille, runde mund, der først af alle byder velkommen med ordene: \"Her bor der nogen.\""},"ICON-1644":{"nm":"Gæstebogsstativ","de":"Et stativ, opstillet så hver, der kommer, skriver sit navn og går videre. Før blækket tørrer, flyder en linje hilsener fra pennens spids. Når besøgendes fodtrin hober sig op linje for linje, bliver den tomme bog snart husets tykkeste album."},"ICON-1645":{"nm":"Møbelplaceringspin","de":"Skrivebordspladsen, man var i tvivl om, om skulle flyttes – en enkelt nål borer den fast i gulvet og beslutter. En lille søm, der stille holder møblets fødder på plads. Et sted, man én gang har valgt, bliver et sted, man knytter sig til, nikker trægulvet stille."},"ICON-1646":{"nm":"Opbevaringslabelramme","de":"Hvad der ligger hvor, kan skuffen aldrig sige. Så sættes et navneskilt ind i en firkantet ramme for at tale i dens sted. I det øjeblik et enkelt mærke finder sin plads, genvinder de rodede rum deres navne og falder til ro."},"ICON-1647":{"nm":"Rumdiffuserpind","de":"Duften, der fugter pindens spids, breder sig langsomt opad. Lavendel det ene øjeblik, en regnvasket eng det næste. Når en usynlig tråd af duft skifter rummets luft ud, løsner en dags træthed sig blidt fra skuldrene på den, der er kommet hjem."},"ICON-1648":{"nm":"Frøposeklemme","de":"De frø, der blev købt om foråret, men aldrig helt nåede at blive plantet, klemmes fast, pose og det hele, med en klemme. Slipper blot ét frø ud, bliver næste sæson en række kortere. Inde i den lille lukning sover næste års have hel og ubrudt."},"ICON-1649":{"nm":"Såbakke","de":"Fyld hvert rum med jord for at skabe det unge spirers første værelse. Ét liv per hul, nybegyndere, der vokser side om side i pæn række. Kig ind, og en morgen, hvor det grønne kalder op til navneopråb klynge for klynge, begynder på ny hver dag på bakken."},"ICON-1650":{"nm":"Vandingsmarkeringspin","de":"\"Jeg er tørstig.\" Da urtepotten ikke kan tale, sender et lille skilt, stukket ned i jorden, signalet i dens sted. Skifter farven, er det tid til at vande. Den mindste tolk mellem plante og menneske rummes helt i denne håndsbrede pind."},"ICON-1651":{"nm":"Plantestøttesnor","de":"En voksende stængel kan vakle under sin egen vægt, så man binder den forsigtigt til en pæl med en blød snor. Strammer man for meget, kan den ikke ånde; slækker man for meget, vælter den, så den bindende hånd har brug for netop den rette ømhed. Selv det at vokse op har brug for nogen ved sin side."},"ICON-1652":{"nm":"Insektnet","de":"Et fintvævet net standser stille de små munde, der er ude efter de sarte blade. Det lader vind og sollys passere og afviser kun det, der ville skade – en usynlig portvagt. Haven forbliver fredelig takket være omsorgen vævet ind i disse tætte masker."},"ICON-1653":{"nm":"Sollysmålerkort","de":"Hvor meget sol falder her? Man stiller et enkelt kort i blomsterbedet og spørger stille. Jo dybere farven bliver, desto mere lys er der fanget i dag. Dette lille stykke papir sorterer et sted til barnet, der elsker sol, og barnet, der har det bedre i skygge."},"ICON-1654":{"nm":"Jord-pH-teststrimmel","de":"Rør en teststrimmel mod jorden, og fra lyserødt til blåt tilstår jorden sit indre i farve. Hvor det hverken er for surt eller for bittert, ånder rødderne friest. Jordens usynlige sind læses ét felt ad gangen."},"ICON-1655":{"nm":"Høstkurvmærke","de":"Er dagens plukning salat eller cherrytomater? Man fæster et navneskilt på hver kurv. På en høstmorgen tyk af jordlugt og grøn duft bliver kurven, i det øjeblik mærket sættes på, den første markering på vejen til bordet."},"ICON-1656":{"nm":"Frøopbevaringsglas","de":"Man putter årets høstede frø i et glas og sender dem af sted til næste forår. Luk låget, og tiden holder stille en stund, mens de små korn venter deres tur i mørket. Det er et glas som et brev, sendt hen over en hel årstid."},"ICON-1657":{"nm":"Podetape","de":"Pres en afskåret gren og en ny gren sammen, vikl tape om dem, og langsomt bliver de to til én krop. Saften flyder igen over bruddet, såret heler lidt efter lidt. At forbinde er, i sidste ende, at acceptere hinandens årer."},"ICON-1658":{"nm":"Beskæresakshætte","de":"Man trækker en lille hat over den skarpe saksespids. Mens hånden, der tyndede grenene, hviler, holder bladet sig skarpt, og hånden holder sig uskadt. Med begrundelsen, at selv et fuldført redskab har brug for nattøj, putter haven omsorgsfuldt sine redskaber i seng."},"ICON-1659":{"nm":"Blomsterfrøsorterer","de":"Balsamin, portulakrose, aftenstjerne – frø forskellige i navn og farve får hver sit eget rum i et adskilt fag. Blandes de, ved man ikke, hvem der er hvem, når foråret kommer. De små skillerum i æsken skitserer på forhånd tegningen til en have, der endnu ikke blomstrer."},"ICON-1660":{"nm":"Urtepottehjul","de":"Sæt fire hjul på, og selv en tung urtepotte begiver sig ud for at følge solskinnet. Østvendt vindue om morgenen, skygge ved middagstid. Det grønne, engang fastlåst af sin vægt, triller af sted og jagter lyset hele dagen for at finde det aller bedste sted."},"ICON-1661":{"nm":"Slyngplantestyresnor","de":"En slyngtråd famler i den tomme luft uden at vide hvorhen, og snoren leder den stille ind på den rette vej. Op, og videre op. Giv den et sted at gribe fat, og planten tager, forunderligt nok, den hånd. Selv det at vokse op har brug for en vejleder."},"ICON-1662":{"nm":"Blomstersprogskortholder","de":"Kortet, sat ved siden af en blomst, bærer de ord, den blomst byder på. Hortensia siger oprigtighed, tusindfryd siger uskyld. Så en gåtur i blomsterbedet bliver en spadseretur, hvor man læser breve, låner en lille holder stille stemme til den tavse blomsts mund."},"ICON-1663":{"nm":"Haveskilthætte","de":"Af frygt for at vind og regn skal udviske skriften, sætter man en klar hætte over haveskiltet. \"Tomater her,\" \"basilikum her.\" Navne, der var ved at falme, forbliver skarpe, så haven, selv efter et helt år, ikke glemmer en eneste af sin familie."},"ICON-1664":{"nm":"Gødningsske","de":"Når man tilføjer næring til jorden, svider grådighed kun rødderne. Så én ske, netop så meget. Den lille ske øser den rette mængde op og minder dig om det – et hjerte, der dyrker godt, kommer altid fra fingerspidser, der kender måde."},"ICON-1665":{"nm":"Tågedyse","de":"Drej dysen, og vandstrålen spreder sig ned som tåge. Et sart blad, der plejede at blive pisket af en hård stråle, løfter blidt hovedet under dugagtige dråber. Det samme vand bliver en helt anden hilsen alt efter, hvordan det gives."},"ICON-1666":{"nm":"Fodermålebæger","de":"Et bæger, to bægre. Man måler en vens måltid med omhu, ikke gætteri. For meget, og de lader det stå tilbage; for lidt, og de bliver kede af det, så man regner sig frem til netop den rette mængde. Kærlighed kommer somme tider i skikkelse af omhyggelig afmåling."},"ICON-1667":{"nm":"Fældebørstecover","de":"I fældetiden omslutter et cover omhyggeligt den bløde dun, der har viklet sig fast i børsten. Sæt hætte på børsten efter pelspleje, og næste dag begynder frisk og blød igen. Glansen hos den, man deler hjem med, gror stille fra sådanne små ryddelser."},"ICON-1668":{"nm":"Klosakshætte","de":"Man sætter et lille låg over den skarpe spids på klosaksen, så det færdige redskab ikke ridser de andre ting i skuffen. Efter omsorgens tid er omme, fuldender det at putte redskabet til hvile hele omsorgens runde."},"ICON-1669":{"nm":"Halsbåndscharm","de":"Hæng en enkelt glitrende charm på halsbåndet, og den samme gamle gåtur bliver lidt mere særlig. Et lille smykke, der glimter i solen. Det behøver ikke være prangende – det er markering nok af, at denne lille en er et højt elsket medlem af nogens familie."},"ICON-1670":{"nm":"Kæledyrssundhedskort","de":"Spiste de godt i dag, gør noget ondt? Man skriver en linje om dagen om husfællens dag på kortet. Når tilstanden hos et familiemedlem, der ikke kan tale, bliver sat på skrift, bliver det omsorgsfulde hjerte også desto mere grundigt og trygt."},"ICON-1671":{"nm":"Sengepudecover","de":"Man klæder sengepuden i bløde, nye klæder. Træk det stof af, der er slidt fra at rulle rundt og gnubbe sig ind til, og duften af soltørret dun stiger op. At holde det sted, hvor de oftest ligger, renest af alt, er en daglig omhu for den, man deler hjem med."},"ICON-1672":{"nm":"Små hegnspinde","de":"Man trykker små pinde ned langs kanten af blomsterbedet for at rejse et lavt hegn. Ikke en streng \"kryds ikke\", men en venlig grænse, der siger, at her er, hvor blomsterne hører til. Med en linje at holde sig til kan de vokse trygt inden for den."},"ICON-1673":{"nm":"Venskabsgodbiddåse","de":"Selv en genert lille en spidser ører ved raslet fra denne dåse. Indeni ligger en håndfuld godbidder, der åbner hjertet. Fordi små løfter slår ord, når det gælder at komme tættere på, træder den klirrende lyd frem først."},"ICON-1674":{"nm":"Gåtursmærke","de":"Hvilken sti i dag, og hvor langt? Man knytter optegnelsen fast på mærket som en søm. Samlede fodtrin bliver et kort, og samlede kort bliver minder. Hver dag gået sammen hober sig pænt op på dette lille mærke."},"ICON-1675":{"nm":"Fuglefoderskål","de":"Sæt skålen på vindueskarmen, drys nogle korn hirse ud, og navnløse gæster flyver ind én efter én. Den bankende lyd af pikken, vingernes flagren. Det er et lille bord, hvor en skænket håndfuld hver morgen bringer en lille koncert."},"ICON-1676":{"nm":"Egernobservationskar","de":"Inde i det klare kar møder man et egerns runde øjne. Med kinderne stoppede fulde af agern, hovedet på skrå – sikke et syn. Over løftet om at kigge en stund og snart lade den gå, deler man et kort goddag med et lille stykke vildmark."},"ICON-1677":{"nm":"Fodaftryksgipsform","de":"Man hælder blødt gips ud for at aftrykke et lille fodspor. Mens man venter på, at det stivner, holder gårdens tid også pause en stund. Det håndsbrede fodmærke, der er dømt til at forsvinde, når de vokser, løfter den hvide form op som evighed og lægger det stille i begge hænder."},"ICON-1678":{"nm":"Natkikkertlinsehætte","de":"Man lukker en lille hætte over linsen, der kigger ind i natten. Så glasset, der har set stjerner og reder, venter på næste nat uden et støvfnug. Selv øjne, der ser mørket klart, har brug for et komma af hvile hen over dagen."},"ICON-1679":{"nm":"Redebeskyttelsesmærke","de":"Opdager man en rede mellem grenene, sætter man et mærke op i stedet for at komme nærmere. \"Her bor en fuglefamilie, vær venligst stille.\" At holde øje uden at trænge sig på – det ene ømme skridt tilbage er det, der gør reden tryggest af alt."},"ICON-1680":{"nm":"Dyrelydoptagerchip","de":"Sangen fra græstykningen, kvidderet under tagskægget, nattens insektlyde – man fanger dem ikke i chippen, snarere låner man dem en stund. En lille lydæske, der, afspillet igen, genopliver selv luften fra det øjeblik. Så alt, hvad der engang blev hørt, aldrig helt forsvinder."},"ICON-1681":{"nm":"Kikkertcover","de":"Lige før en fugl letter, holder skoven vejret et øjeblik. I den stilhed vogter et enkelt stykke stof, lagt over linsen, klarheden i det fjerne, urørt af selv et fingeraftryks smuds."},"ICON-1682":{"nm":"Skovstirem","de":"Hver gang man klatrer op ad den stejle skovsti, banker kameraet let mod brystet. Det dunkende hjerteslag og lukkerlyden svajer i samme takt, og denne ene rem holder de øjeblikke fast og trygt foran brystet."},"ICON-1683":{"nm":"Naturguidekort","de":"Selv et enkelt græsstrå har et navn, fortæller kortet stille. Når det, man plejede at gå forbi uden at vide, får en titel, begynder bjergstien pludselig at myldre venligt af kendte ansigter."},"ICON-1684":{"nm":"Sejlreparationslap","de":"Selv stof, der tager vinden fuldt på kroppen, bærer ar. Med én lille lap, lagt forsigtigt over det flængede sted, vinder sejlet igen retten til at favne det åbne hav."},"ICON-1685":{"nm":"Knobøvebræt","de":"Op, ned, en gang mere rundt – den rækkefølge, hænderne har lært udenad, bliver til et knob. På en nat, hvor stormen banker på dækket, binder netop den ene fremgangsmåde mennesket og skibet sammen som ét."},"ICON-1686":{"nm":"Ankerkædehætte","de":"Undervurdér ikke denne lille hat, sat over kædens ende. Rust gror i det skjulte indefra, så én hætte, der stiller sig imod havvinden, forlænger stille ankerets levetid."},"ICON-1687":{"nm":"Kursmærkeflag","de":"På en dag, hvor tågen er så tæt, at det, der ligger forude, viskes ud, taler et enkelt flag vejen i stedet. Et enkelt farvepunkt, der flagrer i vinden, løsner endelig de stivnede skuldre hos den vildfarne rorgænger."},"ICON-1688":{"nm":"Kahytsnøglering","de":"På det gyngende hav hænger en lille ring på den smalle kahytsdør. Så længe nøglen holder sin plads, er et rum at vende hjem til aldrig låst væk fra dig."},"ICON-1689":{"nm":"Vandtæt kortetui","de":"I regnen udvisker et papirkort først vejen. Mens ét ark forbliver tørt inde i det klare etui, mister selv en gennemblødt rejse aldrig helt sin retning."},"ICON-1690":{"nm":"Skibslampevege","de":"Olien, vægen langsomt suger til sig, blomstrer til sidst ud i flamme. Et enkelt lyspunkt på dækket, og ved den lille flimren rykker nathavets uendelige afstand ubemærket nærmere."},"ICON-1691":{"nm":"Nødsignalklæde","de":"På en afstand, ingen stemme kan nå, rejser den hånd, der vifter et rødt klæde højt, længere end ord. Dette ene stykke stof skærer gennem vinden og råber i ens sted, at nogen her er i live."},"ICON-1692":{"nm":"Havvindsretningspin","de":"Den, der ved, hvorfra vinden blæser, sætter kursen. På den ene retning, en lille pin stille peger, hviler skæbnen for hele dagens sejlads."},"ICON-1693":{"nm":"Foldespadecover","de":"Fold bladet sammen og dæk det til, og selv den flittige spade får hentet vejret en stund. Det sidste, den hånd, der har gravet al jorden op, gør, er at passe på morgendagens blad, så det ikke bliver sløvt."},"ICON-1694":{"nm":"Lommekompaskasse","de":"Nålen peger altid urokkeligt mod nord, men det, der beskytter den nål, er den solide kasse. Jo oftere man engang har mistet vejen, desto kærere plejer man en fornemmelse for retning."},"ICON-1695":{"nm":"Campingopvasknet","de":"Man hænger de opvaskede fade i nettet til tørre i morgensolen. En dag i lejren begynder med lyden af vand, der tørrer, og den lille detalje fylder teltet trygt op."},"ICON-1696":{"nm":"Campingtilladelseskort","de":"Tilladelse til at blive natten over på dette bjerg. I det øjeblik et enkelt stykke papir ligger i hånden, bliver selv den fremmede skov en stund din allierede og tager stille imod dit lille telt."},"ICON-1697":{"nm":"Stiflagsnor","de":"Bind et flag ved hvert vejskel, og vejen tilbage spredes ikke i mørket. Ét lille mærke, sat af den, der gik forud, skubber stille bagpå de skridt, der følger efter."},"ICON-1698":{"nm":"Vandtæt tændstikdåse","de":"En tændstik drukner ved én dråbe og falder for altid tavs. Forseglet i en dåse, hvor ikke en dråbe vand kan trænge ind, venter gnisten tør og stille, kun for den koldeste nat."},"ICON-1699":{"nm":"Bærbart vandfilter","de":"Selv vand, der var grumset nok til at give anledning til tvivl, klarer op, når det passerer dette filter. En lille anordning, der lægger tvivlen fra sig før tørsten – troen på, at man kan drikke, er i sig selv en slurk fred."},"ICON-1700":{"nm":"Nødtæppepakke","de":"Foldet passer det i håndfladen; udfoldet bliver det til én persons varme. Så ordet \"nødsituation\" vejer lidt mindre tungt, venter tæppet i et hjørne af tasken, altid klar til at blive varmt."},"ICON-1701":{"nm":"Natmarkeringsarmbånd","de":"På en bjergsti sunket i mørke lyser et enkelt håndled stille. Det lille bånd, der kundgør hinandens plads, binder dem, der vandrer sammen, kærligt med en usynlig snor."},"ICON-1702":{"nm":"Minehjelmmærkat","de":"Mærkaten på hjelmen er minearbejderens andet navneskilt. I den dybe tunnel, hvor selv lys er kostbart, genkender man varmt en kammerat på det lille billede, der fanges af lampeskæret."},"ICON-1703":{"nm":"Malmåre-markørnål","de":"Hvor en åre er fundet, sætter man stille en nål. Et enkelt punkt, der lyser alene i mørket, fortæller venligt den næste, der kommer, at grave herfra."},"ICON-1704":{"nm":"Revnemåler","de":"At måle revnen, der kløver væggen, er langsom, sej tålmodighed. Er den blevet en håndsbredde bredere siden i går? Det lille tal, linealen melder, fanger et sammenstyrt, før det sker."},"ICON-1705":{"nm":"Oldtidsmønster-aftrykspapir","de":"Man lægger papir hen over mønstret, der er indhugget i stenen, og banker blækket ganske forsigtigt. I det øjeblik et strøg fra tusind år tilbage stiger frem i sorte fibre, sætter aftrykket den svundne tid til bords over for en stund."},"ICON-1706":{"nm":"Oldtidsmøntetui","de":"Dette lille stykke metal, sovende og skånet for rust, rummer den sidste stemme fra en forsvundet nation. En hel tidsalder bor i én mønt, der langsomt ældes inde i det klare etui."},"ICON-1707":{"nm":"Krystalskår-holder","de":"Selv en krystal, der lukker lys inde i sig, har brug for noget at læne sig op ad. I det øjeblik den hviler stille på en lille holder, folder det skrøbelige sig endelig helt ud i sin glans."},"ICON-1708":{"nm":"Hulekort-fragment","de":"Et sønderrevet kort viser lumsk kun halvdelen af sin hemmelighed. Indtil den dag du finder det resterende stykke, holder dette ene ark resten af stien halvt skjult et sted i hulen."},"ICON-1709":{"nm":"Nedfiringskarabinhage","de":"For at overgive kroppen ned ad klippen må man først stole fuldt og helt på denne karabinhage. At hænge sin vægt på ét stykke koldt stål — tillid er af natur netop så tung en ting."},"ICON-1710":{"nm":"Udgravningstilladelse","de":"Et enkelt ark tydeligt stemplet med lov til at grave i jorden. For at vække det, der er begravet, må man først bede om tilladelse — udgravning lærer stille, at man begynder med høflighed."},"ICON-1711":{"nm":"Læskærmspakke","de":"Slår man den op med ryggen mod vinden, opstår en kvadratmeter stilhed midt på den blæsende slette. Bag dette ene lag skærmes en lille gnist, og den udmattede finder et øjebliks hvile."},"ICON-1712":{"nm":"Sandstorm-brilleovertræk","de":"Uanset hvor voldsomt sandet hvirvler, må synet i det mindste bevares til det sidste. Et tyndt overtræk på brillerne bliver til modet til at holde øjnene åbne og gå videre, selv gennem stormen."},"ICON-1713":{"nm":"Regnvejrsbakke","de":"Regnvandet drypper fra tæerne på den gæst, der er kommet. En bakke sat stille ved indgangen tager tavst og varmt imod fødder, der er blevet kolde og våde."},"ICON-1714":{"nm":"Hedebølge-kølemærke","de":"Et lille mærke, der forsigtigt afkøler middagens hede. Hængende fra tasken holder det på sin kølighed, og lige når sveden begynder at perle, skænker det dig en håndfuld skygge."},"ICON-1715":{"nm":"Håndvarmerbælte","de":"Et varmt bælte, der vikles én gang om taljen. Mens håndvarmerens varme breder sig op ad lænden, bliver selv den bitre midvintersslette lidt mere til at holde ud."},"ICON-1716":{"nm":"Fugtabsorberende pose","de":"Fugten gnaver lydløst i tingene. Mens en lille pose i æsken tavst opsuger fugten, bevarer de ting, man holder af, deres form, tørre og hele."},"ICON-1717":{"nm":"Mudder-skoovertræk","de":"Der er tider, hvor kun skoene skal forblive rene, selv når man vader gennem mudder. Dette tynde værn, der holder mudderet ude, gør skridtene, der krydser hjemmets dørtærskel, alle sammen lettere."},"ICON-1718":{"nm":"Havtåge-lygtehætte","de":"Når havtågen prøver at sluge lampen med hud og hår, samler denne hætte stille de spredte korn af lys. Selv i den diset morgengry nægter én havnelygte til det sidste at slukke."},"ICON-1719":{"nm":"Lynadvarselsnål","de":"Når mørke skyer hænger lavt, giver en enkelt nål først en advarsel. Ordet om at bøje sig lavt, før lynet slår ned — ydmyghed over for naturen er altid bedst lært på forhånd."},"ICON-1720":{"nm":"Opskriftsbogmærke","de":"Et lille bogmærke stukket mellem siderne i en åben kogebog. Når du famler dig tilbage til den linje, du mistede foran komfuret, vågner mors hjemmelavede smag også på den side."},"ICON-1721":{"nm":"Krydderi-doseringspind","de":"Mor sagde altid bare \"en knivspids\". Øjemål kunne aldrig være præcist, og alligevel svigtede hendes håndelag aldrig. Måler man salt med denne pind, ser man, at det, der havde modnet længere end noget mål, ikke var vurdering, men kærlighed."},"ICON-1722":{"nm":"Gæringslågsbånd","de":"Vidste du, at krukken også trækker vejret? Når dette bånd omslutter låget tæt, begynder inde og ude langsomt at tale sammen. Først efter de dage uden hastværk vinder ventetiden endelig navnet smag."},"ICON-1723":{"nm":"Modningsetiket-brik","de":"En lille brik med den dag, den blev lavet, skrevet pænt på. Skriften falmer, mens det indre kun bliver dybere. At notere det ned, som var det for at glemme det, og så en dag pludselig trække det frem igen — modning er sådan et løfte, der holdes."},"ICON-1724":{"nm":"Suppedørslag","de":"Klar suppe kommer først efter at være sigtet, og sigtet igen. Se dørslaget holde bidderne tilbage og kun lade essensen løbe igennem, og det gamle køkkens ordsprog — at dybde samler sig, der hvor man har taget noget fra — når dig gennem fingerspidserne."},"ICON-1725":{"nm":"Dejhævningsklæde","de":"Man lægger et klæde stille hen over dejen. Mens gæren flittigt hæver under det dæmpede mørke, lærer man for første gang ømheden hos de ting, der gror stille på steder, ingen ser."},"ICON-1726":{"nm":"Ingrediens-tilberedningsnål","de":"En lille nål, der spalter forårsløgets fibre og holder hvidløget fast. At tilberede er som en første hilsen til ingredienserne, så jo mere omhyggeligt man pudser af, jo lysere skinner aftensbordet med en tone mere."},"ICON-1727":{"nm":"Anretningstang","de":"Hvor den sidste mundfuld skal ligge på tallerkenen — det er i sidste ende denne tang, der bestemmer. I det korte øjeblik, en øvet hånd tøver et halvt taktslag i luften, bliver et måltid stille til et maleri."},"ICON-1728":{"nm":"Termo-madkassehylster","de":"Madpakken, der blev udleveret ved skoleporten, skulle holde sig varm, til frokostklokken ringede. Varmen, der holdes fast inde i dette hylster, køler ikke af, lige så dyb som hjertet hos den, der har stået ved komfuret siden daggry."},"ICON-1729":{"nm":"Middagsinvitationskort","de":"\"Kom og spis med os engang.\" Findes der noget venligere at sige? Uden noget stort løfte, blot det at sidde ved samme bord — den ældste invitation, koreansk kan tilbyde, ligger gemt i dette ene kort."},"ICON-1730":{"nm":"Bordreservationsbrik","de":"Man skriver sit navn og holder pladsen. Mens en lille brik en stund binder et tomt bord til nogen, nærmer det aftalte klokkeslæt sig langsomt, som fodtrin."},"ICON-1731":{"nm":"Smagsbedømmelseskort","de":"Ansigter, der tager en enkelt bid og alvorligt uddeler stjerner. Den ærlige linje, der er skrevet pænt på dette kort, er den varmeste brok, der findes, når næste ret skal blive endnu bedre."},"ICON-1732":{"nm":"Madkasse-taksigelsesbånd","de":"Man vikler et bånd om den rensede madkasse og sender den tilbage. Selv den, der aldrig fik sagt tak, binder i det mindste denne knude om den følelse, ord ikke kunne rumme."},"ICON-1733":{"nm":"Allergimærke","de":"Dette ene lille mærke våger stille over nogens bord. At angive tydeligt, hvad der er i, er endnu et navn for gæstfrihed — en omsorg, der rækker helt ind i det usynlige."},"ICON-1734":{"nm":"Smagsminde-ske","de":"Den smag, der blev hængende på tungespidsen, var i virkeligheden den dags stemning. Når en enkelt skefuld på et øjeblik bærer dig tilbage til et barndomskøkken, synes hukommelsen at være noget, hjertet, ikke maven, øser op og gemmer."},"ICON-1735":{"nm":"Dagens menu-mønt","de":"Hvad skal vi spise i dag. Foran verdens sværeste spørgsmål taber vi hver gang. Vender man denne mønt og overlader menuen til skæbnen, bliver hjertet, overraskende nok, let og glad."},"ICON-1736":{"nm":"Fælles bordklokke","de":"Ring klokken én gang, og familien, der var spredt i hvert sit værelse, samles ét sted. Den klokkelyd over det runde bord er den kæreste oversættelse af ordene \"det er klart, kom nu.\""},"ICON-1737":{"nm":"Dessertrækkefølgekort","de":"Det søde kommer altid til sidst. Dette kort holder det løfte, ingen ved hvem der gav. En lille, øm vært for bordet, der gemmer appetittens højdepunkt til den ene mundfuld dessert."},"ICON-1738":{"nm":"Prutte-mønt","de":"Midt på markedet støder \"giv mig lidt af\" og \"jeg taber allerede penge\" venligt sammen. Denne mønt er kvitteringen fra en gammel stamkunde, hvor prutteriet trods alt ender i latter."},"ICON-1739":{"nm":"Lagerkontrolnål","de":"Man skanner stille lagerhyldernes rækker, finder de tomme pladser og stikker en nål i. At vide, hvad der er tilbage, og hvad der er sluppet op — husholdningens store opgave begynder altid ved dette lille eftersyn."},"ICON-1740":{"nm":"Boddisk-rengøringsbørste","de":"Om aftenen, når markedet er slut, lægger lyden af at feje den tomme boddisk sig lavt over butikken. I fingerspidserne, der på forhånd tørrer stedet af til at fyldes igen i morgen, ligger en flid, der binder dagen pænt af."},"ICON-1741":{"nm":"Dagens anbefalingskort","de":"\"Det her er godt i dag.\" Et kort, indehaveren skjult rækker frem. I den anbefaling, der stille skubber til skulderen på en kunde i tvivl om, hvad han skal vælge, ligger en dags stolthed nydeligt gemt."},"ICON-1742":{"nm":"Stamkunde-stempelkort","de":"Fyld ti, og den ellevte er gratis. Dette kort, hvis stempelfelter fyldes op lidt efter lidt, er endnu et ansigt på ordet \"stamkunde\", for at komme ofte betyder i sidste ende, at man holder af det."},"ICON-1743":{"nm":"Byttebog-klemme","de":"En klemme, der samler og holder sammen på optegnelserne over ting, der er byttet og returneret. Jo mere der er gået frem og tilbage, desto tykkere bliver bogen, og med den tykkelse vokser også tilliden, der er bygget op med naboerne."},"ICON-1744":{"nm":"Solgt-mærke","de":"I det øjeblik dette mærke sættes på den allersidste, fyldes hjertet mærkeligt op. Det er en kort afsked, som et \"farvel\", til noget, der drager af sted til nogens bord, til et hjørne af et værelse."},"ICON-1745":{"nm":"Reservationskurv","de":"En kurv med dit navneskilt holder en plads på hylden. Denne ene plads, sat af på forhånd, siger stille til dig, mens du træder ind, \"jeg har ventet på dig hele tiden.\""},"ICON-1746":{"nm":"Indpakningsbordsmåtte","de":"Måtten, der ligger på indpakningsbordet, er en scene for travle hænder. I den korte tid, papiret foldes og snoren bindes pænt, glider en almindelig ting umærkeligt over til at blive nogens gave."},"ICON-1747":{"nm":"Besøgsseddel","de":"\"Jeg kommer forbi i morgen.\" En seddel skrevet i én linje og stukket ind i dørsprækken. Selv når man har misset hinandens ansigter, rejser løftet på et enkelt ark og ankommer før personen for at vente stille."},"ICON-1748":{"nm":"Nabogavekurv","de":"En kurv rakt over hegnet følges altid af undskyldningen \"jeg lavede lidt for meget\". Koreansk varme krydser sådan over på denne side og lader som ingenting under påskud af overflod."},"ICON-1749":{"nm":"Landsbynyhedskasse","de":"Landsbyens store og små nyheder ophober sig pænt inde i denne kasse. Hvem der lige er flyttet ind, og hvis hus der holder fest — nogle få ark papir samles for at bære kvarterets stille puls videre."},"ICON-1750":{"nm":"Taksigelsesstempel","de":"Man presser taknemmeligheden over, at nogen kom forbi, fast ned med et enkelt stempel. Dette ene blækmærke, der er sivet ud i papiret, bliver længere på sin plads end ordene \"jeg glemmer det ikke.\""},"ICON-1751":{"nm":"Venlighedsros-kort","de":"Et kort, hvorpå man stille skriver den venlighed, nogen viste i dag, og sender den tilbage. I en landsby, der gider sætte små ømheder på skrift, bliver det gode ved med at cirkulere rundt og komme tilbage."},"ICON-1752":{"nm":"Undskyldningsbrev-segl","de":"Som et rødt, modent æble kan et undskyld først gives, når det er modnet nok. Dette segl, presset fast på konvolutten, er mærket af det mod, der bar en svær undskyldning helt til vejs ende."},"ICON-1753":{"nm":"Fælles opgaveskema","de":"Et enkelt skema, opdelt i felter over, hvem der tager sig af hvad. At byrdefuldt arbejde bliver langt lettere, når navnene deles om det, ved enhver, der har arbejdet skulder ved skulder."},"ICON-1754":{"nm":"Nabosmagsbånd","de":"Man markerer stille, hvad en nabo kan lide, med farverige bånd. At huske nogens smag er den stilleste tilståelse af alle på, at man holder af dem, uden nogensinde at sige det."},"ICON-1755":{"nm":"Invitationsring til navneskilt","de":"En enkelt ring hængt på navneskiltet kundgør \"vi tager imod gæster i dag\". Det er et håndfladestort mærke, men på det hænger et hjerte, vidt åbent, færdig med forberedelserne til at byde nogen velkommen."},"ICON-1756":{"nm":"Festivalarmbånd","de":"Et falmet bånd, båret dagevis, for kært til at tage af. Først da det blev spændt om håndleddet, begyndte festivalen for alvor. Deri sover, bevaret helt, en dag, der aldrig helt sluttede, selv efter den var slut."},"ICON-1757":{"nm":"Fyrværkeribillet-etui","de":"Lige før nattehimlen brister, holder billetten i dette etui hårdt fast i det bankende hjerte. Det er et løfte, grebet, til håndfladen sveder, alt sammen for det ene øjeblik, den første raket springer ud med et smæld."},"ICON-1758":{"nm":"Måneskuefad","de":"Der var nætter, hvor det føltes, som havde man øst hele fuldmånen op i en skål. Lægger man frisk frugt og songpyeon smukt på dette fad og bukker for månen, når ét rundt hjerte helt ud til himlens rand."},"ICON-1759":{"nm":"Vinterfestival-vantenål","de":"Selv når hænderne stivner af kulde i sneen, bliver vanterne ved med at glide af håndleddene. Først når denne nål er spændt sikkert fast om ærmekanten, kan man endelig løbe rundt til vinterfestivalen efter hjertens lyst."},"ICON-1760":{"nm":"Forårsfrøkort","de":"Nogle få frø, sovende inde i kortet, venter hver sit forår. Graver man dem ned i jorden, spirer de ufejlbarligt, som et løfte — det synes, som om enhver begyndelse udspringer fra ét lille, fast punkt."},"ICON-1761":{"nm":"Sommerstrandstempel","de":"En bølge stempler sit mærke fast i sandet og trækker sig glidende tilbage. Vel vidende det snart bliver visket ud, efterlader den alligevel et lille mærke om, at nogen har været her. Sommeren stempler altid sådan én gang, klart, og driver så bort med den salte duft."},"ICON-1762":{"nm":"Efterårshøstbånd","de":"Hånden, der bandt kornaksene, binder til sidst et bånd nydeligt. En enkelt knude, der omhyggeligt samler et års sved. Selv mens markerne tømmes, sender efteråret endnu en hilsen, som en solnedgang, i sin smukkeste farve."},"ICON-1763":{"nm":"Fotoerindrings-talebobbel","de":"\"Tak fordi du kom helt herud.\" En hilsen, aldrig helt sagt højt, svulmer rund op på papiret. Et lille, rundt stykke hjerte, der stille låner en stemme til tavsheden, frosset fast i et fotografi."},"ICON-1764":{"nm":"Festivalkort-nål","de":"Et mærke, nogen har stukket i, så du ikke skal fare vild på den store plads. Selv når fødderne løber i forvejen mod folkemusikkens lyd, fører denne ene nål stille den vildfarne dig hen til det aftalte sted."},"ICON-1765":{"nm":"Albummasternøgle","de":"Det, der er låst inde, er ikke pladen, men tiden forseglet i den. Rystelsen fra den første optagelse, morgengryet ved den sidste mix. Drejer man nøglen langsomt, knirker døren op til det rum, kun skaberne selv kender."},"ICON-1766":{"nm":"Trackliste-kort","de":"Rækkefølgen af sange på ét ark er i virkeligheden hjertets rækkefølge. Hvor det brister i halsen, hvor man skal trække vejret — papiret ved det allerede. En spænding, der stiger, før man overhovedet har hørt den første tone."},"ICON-1767":{"nm":"Lydkontrolmærke","de":"Kun den, der har spolet den samme passage hundrede gange tilbage, sætter dette mærke på. Én gang mere, bare én gang til. Ved siden af godkendelsesstemplet gemmer sig en nat, hvor nogen tvivlede på sine egne ører til daggry."},"ICON-1768":{"nm":"Forudbestillingsmærkat","de":"Et løfte om at vente på noget, der endnu ikke engang findes i verden. I det øjeblik mærkaten sættes på, reserveres stille en tom plads under nogens navn. Selv en spændt ventetid har et nummer."},"ICON-1769":{"nm":"Førsteudgave-forseglingsmærkat","de":"Den minder om det gamle håndelag, der dækkede en krukke med hanji og forseglede den med klister. Et enkelt ark, der lover at bevare tingene, som de var fra begyndelsen. Vel vidende den forsvinder, i det øjeblik man river den af, bliver man ved med at se lidt længere på dens fald."},"ICON-1770":{"nm":"Comeback-kalenderbrik","de":"Lægger man én cirkel mere til kalenderen, bliver nætterne til den dag én rude kortere. Datoen for hjemkomsten står skarpt på den lille brik i hånden. For den, der venter, er tiden noget, man tæller sådan, med hånden."},"ICON-1771":{"nm":"Konceptfotolomme","de":"Før det næste koncept skubber farven fra dette ud, gemmer et klart ark dets struktur omhyggeligt væk. Så det ikke glemmes, når årstiden skifter, våger det stille over gårsdagens farve, hjørner og det hele."},"ICON-1772":{"nm":"Teaser-afsløringsmønt","de":"Lige før sløret trækkes fra, en lille mønt holdt i håndfladen. I det øjeblik man rækker den frem, åbner den låste første scene sig en håndsbredde ud mod verden. En afsløring er i sidste ende et spørgsmål om, hvem der rækker hånden frem først."},"ICON-1773":{"nm":"Pladeudstillingsholder","de":"I det øjeblik en lav holder løfter en plade en anelse, bliver en almindelig skive stjernen i udstillingen. En øm birolleindehaver, der bagfra, i stilhed, holder den vinkel, hvor lyset falder smukkest."},"ICON-1774":{"nm":"Debutshowcase-adgangskort","de":"Et enkelt adgangskort præget med ordene \"vises for allerførste gang\". Fra den lange gang bag scenen til det første bifald fra sæderne bærer dette kort dig over debutens skælvende tærskel."},"ICON-1775":{"nm":"Første scene-positionsbrik","de":"Man føler stille med tåspidsen efter brikken, klistret fast på gulvet. Ét felt, kroppen kender først, selv uden at se. I det øjeblik man rammer nøjagtigt det indøvede sted, bliver dirren i fingerspidserne endelig til en klar bevægelse."},"ICON-1776":{"nm":"Taksigelseskort","de":"Selv den almindelige sætning \"det er alt sammen jeres fortjeneste\" er ikke længere almindelig, når den er skrevet med en skælvende håndskrift. Nogle linjer noteret ned på forhånd, af frygt for at glemme dem i rørelse. Oprigtighed læner sig somme tider op ad et enkelt kort."},"ICON-1777":{"nm":"Profilfoto-bookingskema","de":"Et ark med datoen for at stå foran linsen skrevet pænt op. En tidsplan for langsomt at forberede det bedste ansigt. Jo flere felter der fyldes ud, desto længere bliver også nætterne foran spejlet."},"ICON-1778":{"nm":"Fanklub-tilmeldingsseddel","de":"En indgangsseddel, hvor man genert skriver sit navn og sit hjerte i én linje. At sige, man kan lide noget, er altid svært, men denne ene seddel staver ordene pænt ud i ens sted. Den første underskrift på at vælge at være sammen."},"ICON-1779":{"nm":"Debutgave-kontrolskema","de":"En hånd, der tjekker hver eneste, mens den forestiller sig modtageren. Er hjørnerne skadet, mangler der noget af hjertet? En gave er allerede elsket én gang, endnu før den overrækkes, og sætter sig i bevægelse."},"ICON-1780":{"nm":"Sceneafslutningsmærke","de":"Lige før tæppet falder, et mærke sat der, hvor den sidste positur bliver stående. Ikke et signal om enden, men snarere et lille punkt, der binder enden pænt af. Kun en scene, der er lukket godt, åbner den næste."},"ICON-1781":{"nm":"Interviewventenål","de":"En nål, der stille bevarer stilheden, før spørgsmålene begynder. I den korte tavshed, hvor man vælger svar i hovedet, siger dette lille mærke i ens sted venligt: \"Ikke endnu, men snart.\""},"ICON-1782":{"nm":"Debutminde-konvolut","de":"Som det gamle håndelag, der trykkede et dyrebart brev, konvolut og det hele, i hånden på en, der drog af sted, holder ét lag omhyggeligt optegnelsen fra en første scene. Den dag, langt ude i fremtiden, man åbner den, vælter selv dagens rystelse ud med den."},"ICON-1783":{"nm":"Sangånde-sugerør","de":"Øvelse i at sende vejrtrækningen langt ud, i én lang strøm, gennem det tynde rørs ende. Sang er i sidste ende velstyret åndedræt — dette lille sugerør fortæller det stille hver morgen. Vinden før lyden."},"ICON-1784":{"nm":"Taktøvelsesbrik","de":"Tik, tik, tik — verdens mest ærlige ven. Den holder dig tilbage, når du farer af sted, og skubber dig i ryggen, når du sakker bagud. At indprente takten i kroppen er som en lang samtale med denne solide brik."},"ICON-1785":{"nm":"Dansliniebånd","de":"Hvor fingerspidserne stopper, hvor skulderen åbner sig — man sporer bevægelsens linje stille med et enkelt bånd. En velafstukket danselinje forbliver lige og nydelig helt ud til de steder, sæderne ikke kan se."},"ICON-1786":{"nm":"Ansigtsudtrykskort","de":"Det ordsprog om, at selv det at smile skal læres. Et ark, der bid for bid noterer øjenkrogens vinkel og mundvigens højde. Det udtryk, spejlet ikke nåede at lære dig, fortæller dette kort venligt i dets sted."},"ICON-1787":{"nm":"Rapflow-memo","de":"\"Hvil lidt her, lad det vælte ud der\" — en memo, der på forhånd skitserer ordenes vandvej. Jo hurtigere passagen er, desto klarere skal åndedrættets sti være. I de skødesløst tegnede pile lever et vers' rytme og trækker vejret."},"ICON-1788":{"nm":"Stemmetemperatur-mærkat","de":"Stemmen har varme dage og kolde dage også. Et lille mærke, man vælger efter farve og sætter på for dagens klang. Ved skiftevis at varme og køle vågner lyden hver dag ved en lidt anden temperatur."},"ICON-1789":{"nm":"Hvilerutine-mønt","de":"En mønt trykket i hånden med ordene om, at også det at hvile godt er en færdighed. Rækker man den frem, kan man stoppe et øjeblik uden skyldfølelse. For den, der har løbet uden ophør, er stoppet det mest modige valg."},"ICON-1790":{"nm":"Vækstmålnål","de":"En lille nål stukket i med \"lad os prøve at nå hertil\". Selv om det ser fjernt ud, næsten uden for rækkevidde, vokser man et skridt nærmere det hver dag. Et mål er som et ømt løfte, der vinker langt borte fra."},"ICON-1791":{"nm":"Ugentlig evalueringskonvolut","de":"Man samler en uges sved og tårer pænt sammen i én konvolut og rækker den frem. Det, der lykkedes, og det, der skuffede, ligger side om side inde i den. At åbne den er en lille lektie, rakt til næste uges jeg."},"ICON-1792":{"nm":"Scenepynt-delæske","de":"Bag den funklende scene bor navnløse dele. Én skrue, én ring samles om at få stjernerne under loftet til at svæve. Åbner man æsken, er den fuld af den lille, tålmodige omhu, der tavst bærer al pragten oppe."},"ICON-1793":{"nm":"Kostumekonceptplade","de":"Ved at fæste stofstumper og farver på, én ad gangen, prøver man på forhånd en dragt, der endnu ikke findes i verden. Et scenekostume, fuldendt først på pladen. Fantasien går altid et skridt foran nålen."},"ICON-1794":{"nm":"Farvetilpasningsbrik","de":"Det samme tøj har et helt andet ansigt alt efter lyset. Hvilken farve smiler lysest sammen med den person, finder man ved at holde brikker op, én for én. At passe sammen er en opdagelse for enden af lang sammenligning."},"ICON-1795":{"nm":"Snørebåndsprøvetavle","de":"Det, der bærer et fast skridt på scenen, er overraskende nok et lille snørebånd. Så det ikke går op, men heller ikke strammer for meget. Den ømmeste af alle overvejelser, gjort på det laveste sted, ved at vælge blandt bånd lagt frem efter deres struktur."},"ICON-1796":{"nm":"Tilbehørskontrolkonvolut","de":"Jo mere noget funkler, desto mere iøjnefaldende viser en enkelt ridse sig. En hånd, der holder smykket fra konvolutten op mod lyset og gransker det omhyggeligt. Et hjerte, der ser de små ting igennem til det sidste, er det, der vogter scenen."},"ICON-1797":{"nm":"Hårfarveprøve","de":"En lille prøve til på forhånd at give håret en ny årstid. Farven, der lige akkurat farver én hårlok, hvisker stille om det næste koncepts førstehåndsindtryk. Forandring begynder altid et sted, håndfladestort."},"ICON-1798":{"nm":"Neglekoncept-kort","de":"Et ark, der på forhånd bestemmer de små billeder, der skal males på ti fingerspidser. Så konceptet aner sig svagt, selv i en enkelt håndbevægelse, klæder man selv den mindste detalje kærligt i en historie."},"ICON-1799":{"nm":"Stilskiftebillet","de":"\"Skal jeg blive en lidt anden mig i dag, end jeg var i går?\" — én billet, der gør netop den linje mulig. Hår, tøj eller stemning, denne billet åbner den spændende dør til et nyt udseende."},"ICON-1800":{"nm":"Størrelsesjusteringsmærke","de":"Et mærke, der omhyggeligt noterer, hvor der skal syes ind og lægges ud, indtil det sidder perfekt. Som det gamle håndelag, der syede et barns tøj sting for sting, gør denne lille justering scenen en håndsbredde mere behagelig."},"ICON-1801":{"nm":"Rå thumbnail-kort","de":"Et enkelt ark uden farve. Over de grove blyantstreger gætter det stille på, hvor den næste scene vil flyde hen. Mere spændende end det færdige værk er altid denne ufuldendte første linje, som det stille redigeringsrum minder os om."},"ICON-1802":{"nm":"Samtykkemærkat til filmoptagelse","de":"\"Må jeg godt være med her?\" I stedet for ord sætter du et lille rundt mærke på brystet. Et enkelt lille klistermærke skaber et venligt løfte mellem kameraet og hjertet."},"ICON-1803":{"nm":"Fotovæg-positionsnål","de":"En lille nål stukket ind i et hjørne af væggen. Den markerer på forhånd, hvem der skal stå hvor. Overalt hvor en nål er sat, standser et smil et øjeblik og bliver til et enkelt fotografi."},"ICON-1804":{"nm":"Klip-udvælgelsesbrik","de":"En finger, der peger på blot ét blandt hundredvis af billeder. I det øjeblik denne brik lægges ned, har alle de bortvalgte udtryk levet for netop dette ene billede. At vælge ligner altid en stille afsked."},"ICON-1805":{"nm":"Bag kulisserne-kuvert","de":"Alt, hvad der sker bag kameraet, gemmes her. Fold klappen sammen, og latter, fejltagelser og søvnige gab sover sammen. Det, man kommer til at holde mere af end selve programmet, er ofte det, der er gemt heri."},"ICON-1806":{"nm":"Redigeringsnote","de":"\"Et sekund mere her, og skru lidt ned for musikken.\" En seddel tætpakket med rødt blæk. Nogens kræsenhed justerer videoens åndedrag med et enkelt taktslag. Finpudsning vokser frem af disse små håndgreb."},"ICON-1807":{"nm":"Uploadplan-mærke","de":"Et lille mærke på en video, der klokken syv i morgen tidlig skal træde ud i verden helt af sig selv. Selv mens alle sover, holder løftet sig vågent. En tid, der er fastsat på forhånd, kender ikke til at komme for sent."},"ICON-1808":{"nm":"Thumbnail-rammeomslag","de":"Et omslag, der omslutter den bedst lykkedes første scene. Det folder omhyggeligt hjørnerne sammen, så hverken fingeraftryk eller støv kan nå dem. Indtil det vises, bevares førstehåndsindtrykket så sirligt."},"ICON-1809":{"nm":"Optagelseslængde-brik","de":"En lille brik, der vurderer, hvor mange minutter der blev filmet i dag. Langt er ikke nødvendigvis bedre, og kort er ikke nødvendigvis lettere. At kende den rette længde er redigeringens første knap."},"ICON-1810":{"nm":"Heppeslogan-korrekturark","de":"Et papir, man tjekker en gang til, inden man råber af fuld hals. Ét forkert bogstav, og tusind stemmer spredes. Bag heppekoret er der først gået en usynlig korrekturlæsende hånd forbi."},"ICON-1811":{"nm":"Fankunst-opbevaringslomme","de":"Et billede, nogen har tegnet natten igennem. Et klart lille hjem tilbydes, så det ikke bliver krøllet. Som om det, der er tegnet med hjertet, skal holdes med hjertet for at vare ved, omfavner lommen det uden et ord."},"ICON-1812":{"nm":"Fanbrev-sorteringssnor","de":"En snor, der ordner de ophobede breve pænt efter afsender. Med hver knude bringes en dags længsel i orden. Her er en hånd, der ikke lader et eneste brev glide forbi, selv om den ikke kan besvare dem alle."},"ICON-1813":{"nm":"Byttetilmelding til fanvarer","de":"\"Er der nogen, der vil bytte med mit?\" Et papir, du skriver dit nervøse hjerte på og rækker frem. Af den ene grund, at man kan lide det samme, bliver to fremmede venner et lille stykke tid."},"ICON-1814":{"nm":"Gruppeheppe-pladsbrik","de":"En brik, der tildeler pladser, hvor folk i ens farver skal sidde side om side. Når spredte hjerter samles i én sektion, begynder tilskuerpladserne at synge som ét enormt menneske."},"ICON-1815":{"nm":"Fødselsdagsreklame-kvittering","de":"En enkelt kvittering, man holder i hånden, efter at have sendt kærlighed op på en reklametavle. Det, der ikke står skrevet ved siden af beløbet, er den hengivenhed, der blev samlet natten igennem. Dette papir står tilbage som beviset på en fejring rettet mod netop ét menneske."},"ICON-1816":{"nm":"Meddelelsesbog-omslag","de":"Et omslag, der indhyller en bog samlet af mange menneskers håndskrift. Slå den op, og de forskellige hænder folder sig sammen i ét hjerte. Ydersiden er sirlig, men det indre er fuldt af en varm summen."},"ICON-1817":{"nm":"Fanklub-medlemsnål","de":"En lille nål, der kun gives til dem, der råber det samme navn. I det øjeblik den fæstnes på brystet, forvandles en ensom kærlighed til et løfte delt af mange. Fællesskab har en så rund form."},"ICON-1818":{"nm":"Online-heppetoken","de":"Et lyspunkt, som fjerne hænder vinker med på den anden side af skærmen. Afstanden er umådelig, men rytmen er den samme. Det er beviset på, at hejaråb altid når frem, selv fra usete pladser."},"ICON-1819":{"nm":"Slidt nøglestump","de":"Et hakket stykke metal. Ingen husker længere, hvilken dør det engang åbnede. Det, der overlever det aflåste sted, er altid den ubrugelige halvdel af en nøgle som denne."},"ICON-1820":{"nm":"Kort over hemmelig gang","de":"Et gammelt papir, der tegner en sti skjult bag vedbenden. Genveje kendes kun af dem, der kender dem. I det øjeblik det foldes ud, skifter den almindelige ø stille ansigt til en scene for eventyr."},"ICON-1821":{"nm":"Kodeknækker-kort","de":"Et kort, der fører sammenblandede, spredte bogstaver tilbage til deres rette plads. Når en linje falder på plads, vinker den næste hemmelighed. Selv en knude, der syntes uløselig, begynder trods alt med det første bogstav."},"ICON-1822":{"nm":"Forseglingssnor til æske","de":"En snor, bundet stramt, som om den siger: åbn ikke. Kun den, der bandt den, ved, hvad der sover inde i knuden. Ønsket om at løsne og ønsket om at beskytte er bundet side om side i denne ene snor."},"ICON-1823":{"nm":"Ruinpuslebrik","de":"Et lille fragment brækket af fra en gammel stenmur. Sæt det tilbage på plads, og en persons håndværk fra tusind år tilbage vender levende tilbage under fingerspidserne. At samle det spredte er arbejdet med at binde tiden sammen igen."},"ICON-1824":{"nm":"Ø-sagn-udklip","de":"Et papir, hvor gamle fortællinger, der svæver rundt på øen, er nedskrevet i hånden. Om de er sande eller ej, betyder næppe noget. En historie, der er vandret fra mund til mund, bliver i sig selv en årring på øen."},"ICON-1825":{"nm":"Skjult mærkesten","de":"En sten, der ser ud til at ligge tilfældigt ved vejkanten. Kun for et kyndigt øje peger den stille retningen ud. Jo dybere en hemmelighed man ønsker at begrave, jo mere jævnt et ansigt står den der med."},"ICON-1826":{"nm":"Gådekuvert","de":"Der står intet skrevet på ydersiden. Dette korte øjeblik lige før seglet brydes, er det mest spændende. Indtil svaret ligger i hånden, er alle muligheder stadig levende inde i kuverten."},"ICON-1827":{"nm":"Detektiv-lupdæksel","de":"Et lille hætte, der stille sættes over enden af forstørrelsesglasset. Når man ikke kigger igennem det, lader det linsen hvile. At se godt kræver, at man først passer godt på, en lektie detektiven lærer tidligt."},"ICON-1828":{"nm":"Ørundtursbus-billet","de":"En enkelt billet til at stige på bussen, der kører rundt om øen. Endestationen er igen udgangspunktet. På en vej, der vender tilbage til sit eget udspring, ser landskabet lidt nyt ud hver gang."},"ICON-1829":{"nm":"Cykeludlejningsmærke","de":"Et mærke, der hænger fra styret på en lånt cykel. En kort frihed tillades, indtil den afleveres tilbage. Når tiden med at skære gennem vinden er forbi, samler dette mærke stille løftet ind igen."},"ICON-1830":{"nm":"Ombordstigningsbillet til lille båd","de":"En ombordstigningsbillet til at gå om bord på en lille båd. På det svajende dæk kommer ø og ø nærmere hinanden. At krydse vandvejen bringer altid lidt spænding og lidt søsyge med sig sammen."},"ICON-1831":{"nm":"Trillebørshjul-split","de":"En split, der holder trillebørshjulet fast på plads. Dette ene lille stykke metal holder en tung last rullende. Den mindst iøjnefaldende del er ofte den, der tavst bærer den største vægt."},"ICON-1832":{"nm":"Kabelbane-token","de":"En rund token, der puttes i kabelbanen, der skærer gennem luften. I det øjeblik fødderne forlader jorden, samles hele øen i ét overblik. Jo højere man stiger, desto mere gavmildt bliver udsigten."},"ICON-1833":{"nm":"Varmluftballon-armbånd","de":"Et bånd, der bindes om håndleddet, før man stiger op i kurven. Når flammen svulmer og jorden fjerner sig, bliver hjertet lettere med. At stige til vejrs betyder at lægge sin vægt fra sig et øjeblik."},"ICON-1834":{"nm":"Vandtaxa-tilkaldelsesbrik","de":"En lille brik til at tilkalde en taxa, der kører hen over vandet. Løft hånden, og en båd nærmer sig, mens den skærer gennem strømmen. Det, der baner en vej selv dér, hvor ingen findes, er til syvende og sidst modet hos den, der kalder først."},"ICON-1835":{"nm":"Vandresti-indgangspas","de":"Et pas, man modtager ved den første port ind til bjerget. Herfra bestemmer tæerne vejen. Toppen kan være langt væk, men kun dem, der passerer indgangen, loves den udsigt."},"ICON-1836":{"nm":"Havneboks-nøgle","de":"En lille nøgle, der åbner en boks ved kajen. Med hænder, der er blevet lettere efter at have afleveret bagagen, ser man ud over havet. At have et sted at lægge tingene fra sig for en stund er at låne sig mod til at rejse langt."},"ICON-1837":{"nm":"Syltekrukke-låg","de":"Et krukkelåg, der lukker de syrlige ting inde. Skruet ordentligt fast bevarer sommerens agurker deres sprødhed helt til vinter. Hemmeligheden ved at besejre tiden begynder, viser det sig, med at lukke godt til."},"ICON-1838":{"nm":"Tørrenet-etiket","de":"Et navneskilt, der sættes på ting, der bredes ud til tørring på en sigte. Noter, hvad der blev lagt ud, og hvornår, og ventetiden falder ikke i uorden. Selv i solens og vindens tid må der findes noget, der hedder rækkefølge."},"ICON-1839":{"nm":"Røgflis-pose","de":"En pose med stykker af duftende træ. Åbn munden, og en duft som fra et lejrbål hilser på næsen først. En smag, der er uddybet af røg, åbner sig langsomt, kun for den, der ved, hvordan man venter."},"ICON-1840":{"nm":"Konserves-mærkat","de":"Et mærkat sat på en krukke, der ønsker den held gennem hele året. Datoen, den blev lavet, og omhuen står skrevet på den. Mad, der gemmes længe, følges altid med en lille note, der forsøger at huske dagens hjemmelavede smag."},"ICON-1841":{"nm":"Gæringsurs-mærke","de":"Gæring stoler ikke på uret. Den måler tiden med duft i stedet for minutviseren. I det øjeblik en syrlig duft når næsen, nikker mærket stille \"nu er det klar\". Selv ventetiden har sin egen skala af mærker."},"ICON-1842":{"nm":"Køleskabshylde-sorteringsnål","de":"Her står køleskabets lille trafikbetjent. Grøntsager øverst, tilbehør nederst, gårsdagens rester forrest. Sæt en enkelt nål, og den hånd, der altid famlede, når man åbnede lågen, kender snart vejen."},"ICON-1843":{"nm":"Madkasse-varmebånd","de":"Mor svøbte et bånd om madkassen, så varmen ikke skulle slippe væk inden middag. Løsn båndet, og under det dugkondenserede låg lå morgenens omsorg stadig varm og ventede på mig."},"ICON-1844":{"nm":"Modningsflaske til sauce","de":"God krydderi har aldrig travlt. Den giver stille sojasovs og hvidløg tid til at trænge ind i hinanden. I flaskens mørke uddybes smagen langsomt, og krukkealtanens langsomme visdom flytter ind i en lille flaske."},"ICON-1845":{"nm":"Sæsonsyltetøj-etiket","de":"Jordbær om foråret, abrikos om sommeren, figen om efteråret. Et enkelt mærkat skriver årstiden sirligt på glasset. Åbn låget midt om vinteren, og sidste års sollys smelter langsomt ud, en ske ad gangen."},"ICON-1846":{"nm":"Samlerbadge-tavle","de":"Du behøver ikke gide tælle, hvor mange du har samlet, for badgetavlen praler af det for dig. For hvert tomt felt, der fyldes, løftes skuldrene lidt. Dette er ikke et tal, men et spor stampet ud på tåspidserne."},"ICON-1847":{"nm":"Uopdaget plads-kort","de":"Et sted, man endnu ikke har mødt. Silhuetten på kortet rækker et løfte, dens omrids kun svagt tegnet. Tomt betyder snart fyldt, så forventningen venter altid på dig i form af et spørgsmålstegn."},"ICON-1848":{"nm":"Fuldført katalog-stempel","de":"Den lyd, når stemplet lander med et \"bum\" i det sidste felt. Luk katalogen, åbn håndfladen, og en plet rødt blæk klæber der som en medalje for fuldførelse. Den dybe lettelse, kun kendt af dem, der samlede helt til enden."},"ICON-1849":{"nm":"Sjældenheds-farvebrik","de":"Selv samme form fortæller en anden historie, når farven er anderledes. En enkelt brik trækker stille grænsen mellem det almindelige og det kostbare. En samlers blik dvæler altid længe foran den forskel i nuance."},"ICON-1850":{"nm":"Dubletbytteseddel","de":"Endnu en, igen. Den dag du samlede din tredje af noget, du allerede havde, rakte denne bytteseddel stille hånden frem. Som en venlig trøst om, at dubletter, hvis de holdes fast i stedet for at kasseres, en dag vender tilbage som noget kostbart."},"ICON-1851":{"nm":"Samlerkasse-nummerskilt","de":"Nummerér hver kasse, og pulterrummet bliver et lille bibliotek. Nummer 17 rummer forårets fund, nummer 23 det, der blev samlet op ved havet. Jeg er et stille register, der ordner spredte minder linje for linje."},"ICON-1852":{"nm":"Udstillingsguide til placering","de":"En udstilling bygges halvt af placering. Høje ting bagest, skinnende ting i midten. Følg guiden, flyt tingene med hånden, og den rodede hylde trækker snart vejret roligt som et lille galleri."},"ICON-1853":{"nm":"Støvekost til samlerobjekter","de":"Jo mere kært en ting er, jo bedre lægger støvet sig på den. Med børstens bløde spids, forsigtigt, fejer du selv skylden over ikke at have set på den i lang tid, med. Mens du gør rent, glimter de sovende minder et øjeblik igen."},"ICON-1854":{"nm":"Opbevaringsgrænse-udvidelsesseddel","de":"Samler man længe nok, bliver mangel på plads endda et lykkeligt problem. Den stille lettelse ved at se endnu en hylde tilføjet. Det er ikke grådighed, men beviset på, at der er så meget, man holder af."},"ICON-1855":{"nm":"Venneinvitationskode-kort","de":"At give denne kode videre er den venligste invitation af alle, der siger \"kom og leg med mig\". Hjertet, der ligger i nogle få cifre. Først når vennen, der modtog den, sætter foden på øen, begynder en historie kun for jer to."},"ICON-1856":{"nm":"Fælleslager-nøgle","de":"Lagerdøren åbnes aldrig alene. En lås, der kun drejer, når to hænder, dine og mine, mødes. Et fælles rum rummer altid et fælles løfte, hængende der i form af en nøgle."},"ICON-1857":{"nm":"Hittegods-anmeldelsesmærke","de":"Selv en tabt ting er kostbar for nogen. At skrive en enkelt linje, \"her er den\", og hænge den op. Mærket er en lille snor, der stille genforbinder et hjerte, der kortvarigt var faret vild, med sin ejer."},"ICON-1858":{"nm":"Hjælpe-anmodningsflag","de":"At bede om hjælp er ikke svaghed, men mod. Når flaget hejses, kommer nogen løbende et sted fra. Det, der spreder sig hurtigst på denne ø, er ikke rygter, men de hænder, der rækkes ud mod hinanden."},"ICON-1859":{"nm":"Nødkontakt-armbånd","de":"En lille tryghed viklet om håndleddet. Hvad end der sker, kommer nummeret skrevet her løbende hurtigere end nogen anden. En stille følgesvend, glemt i hverdagen, der bliver den mest pålidelige i nødens stund."},"ICON-1860":{"nm":"Rollefordelings-brik","de":"Hvem der handler ind, og hvem der laver mad: fordel brikkerne, og der er intet at skændes om. Det første skridt i at lave noget sammen begynder med venligt at fastsætte hver enkelts andel."},"ICON-1861":{"nm":"Samarbejdsskema","de":"Det, man aldrig ville turde forsøge alene, bliver muligt som ved et trylleslag, når mange samles. Efterhånden som navnene fylder skemaet ét ad gangen, mindskes de tomme felter, og latteren vokser. Samarbejde vokser stille frem mellem felterne."},"ICON-1862":{"nm":"Besøgsetikette-kort","de":"Når man træder ind i et andet hjem, bliver man forsigtig lige fra tæerne. Det, der står på kortet, er ikke store regler, kun små, varme løfter som \"sæt skoene pænt, og hils først\"."},"ICON-1863":{"nm":"Festafslutningsklokke","de":"Selv glæde behøver en ende, for at man kan glæde sig til den næste. Når klokken klinger, samler alle sammen deres ting med lidt trist mine. En fest, der ved, hvordan man tager pænt afsked, bliver længst i hjertet."},"ICON-1864":{"nm":"Madras-hjørnebånd","de":"Uanset hvor glat man breder sengetøjet ud, vil hjørnerne altid løsne sig. Takket være et bånd, der griber fast om alle fire hjørner, vågner sengen hver morgen lige så skarp som et hotelværelse."},"ICON-1865":{"nm":"Dynebetræk-knapsnor","de":"Jeg er knapsnoren, der holder dynens krave fast. Uanset hvor meget du vender og drejer dig om natten, holder jeg godt fast, så kraven ikke slipper væk. Sengetøj uden en eneste krølle, når du vågner, det er lønnen for mit natlige arbejde."},"ICON-1866":{"nm":"Topmadras-fastgørelsesklips","de":"Topmadrassen forsøger at glide af sted, så snart den får chancen. Hver gang bider klipsen hårdt fast i hjørnet og holder stillingen. En stille stædig én, der holder sengen i orden fra et usynligt hjørne."},"ICON-1867":{"nm":"Lagenfolde-glatter","de":"De fine folder, et lagen samler natten over, minder på en eller anden måde om hjertets krøller. Ligesom stof, der bliver glat med ét strøg af glatteren, ønsker jeg, at en rodet dag kunne stryges lige så blidt ud."},"ICON-1868":{"nm":"Madras-ventilationssokkel","de":"Selv en madras har brug for plads til at trække vejret. Når soklen åbner en luftvej nedenunder, siver fugten ud, og tørhed siver ind. God søvn begynder stille netop fra den luft, der bærer din ryg."},"ICON-1869":{"nm":"Dynebetræk-lynlåsflap","de":"Det midnatskaos, når fyldet bliver ved med at stikke ud, mens man skifter dynebetræk. Dæk lynlåsen med en flap en enkelt gang, og du vågner ikke af at hænge fast i den med foden. En stor fred, bragt af én lille flap."},"ICON-1870":{"nm":"Fyldklumpe-forebyggende pude","de":"Pudefyldet klumper snart sammen til den ene side og danner en lille bakke. Når puden stille holder mellemrummet ud, forbliver fladheden intakt til det sidste. Takket være den vender en næsten-ny bløthed tilbage hver eneste nat."},"ICON-1871":{"nm":"Elastikkrog til lagen","de":"Et lagen forsøger altid langsomt at glide af til den ene side. Hægt krogen fast i hjørnerne og træk det stramt, og det rokker sig ikke, uanset hvor meget du vender dig natten igennem. Stramhed bliver på den måde stille grundlaget for dyb søvn."},"ICON-1872":{"nm":"Pudebetræk-skiftemærke","de":"Når du pludselig ikke kan huske, om du vaskede pudebetrækket i dag, svarer et enkelt mærke klart. En rutine, du bliver ved med at glemme af bare at sove og sove igen, dette lille mærke husker flittigt i dit sted."},"ICON-1873":{"nm":"Drømmedagbog-bogmærke","de":"En drøm, der spredes mellem fingrene, i det øjeblik man vågner, fastholder bogmærket på den side, det markerede. Slå den op, og aftenens hav og himmel er der stadig, en lille bro lagt stille mellem søvn og skrift."},"ICON-1874":{"nm":"Hvid støj-strandsten","de":"En for stille nat vækker ofte i stedet for at berolige. Når stenen slipper en lyd som blid, rislende regn løs, sænker hjertet sig langsomt langs dens toner. En lille sten, der stille trøster stilheden."},"ICON-1875":{"nm":"Temperaturregistrerende søvnbrik","de":"Om panden er varm, eller tæerne er kolde, mens du sover, våger brikken stille ved din side. Takket være en natvagt, der blidt finder netop den rette temperatur til din krop, strømmer søvnen uafbrudt til daggry."},"ICON-1876":{"nm":"Mørklægningsgardin-klemme","de":"Morgensolen er så flittig, at den bliver ved med at presse sig gennem sprækken i gardinet. Bid begge ender godt fast med klemmen, og rummet bliver sort som midt om natten igen. En pålidelig medskyldig i endnu en lang sovemorgen."},"ICON-1877":{"nm":"Måneskin-projektorlampe","de":"Sluk lyset, og en måne stiger op over loftet. Det bløde skær, standeren kaster op, forvandler rummet til en lille nattehimmel. Følelsen af at falde i søvn med blikket rettet mod månen, holdt lige ved sengen."},"ICON-1878":{"nm":"Duftpose-krog til søvn","de":"En pose med lavendel og duften af græs svajer sagte ved sengekanten. Mens duften siver til næsen, løsnes skuldrene langsomt, og en enkelt duftpose kalder på søvnen før selv puden gør det."},"ICON-1879":{"nm":"Vuggevise-spilledåsenål","de":"Vind fjederen forsigtigt op, og en lille melodi folder sig ud. Vuggevisen, der drejer frem fra nålens spids, ligner til forveksling den rytme, bedstemor plejede at klappe din ryg med. Hver tone gør øjenlågene lidt tungere."},"ICON-1880":{"nm":"Fugtighedskop til planter","de":"Jeg er et krus, der dyrker planter i klart vand i stedet for jord. Ser man de fine rødder svæve i vandet, føles selv luften i rummet en anelse fugtigere. En lille grøn brønd, samlet oppe på skrivebordet."},"ICON-1881":{"nm":"Drømmefragment-samleflaske","de":"Drømme, spildt i søvne, har ingen form, og når man vågner, siver de ud mellem fingrene. At standse ét fragment, lige før det forsvinder, med flaskeproppen, og holde det fast til morgen, ønsket om at huske begynder et sted så småt som dette."},"ICON-1882":{"nm":"Sengebord-brillebakke","de":"I det øjeblik du tager brillerne af og lægger dem fra dig, synker mærkeligt nok en hel dags træthed med. Denne lille plads ved sengekanten er der for at tage imod netop den bevægelse. En bakke, der stille gør verden sløret, inden søvnen kommer."},"ICON-1883":{"nm":"Natbord-glasbrik","de":"Et enkelt rundt mærke, som et glas vand efterlader, kan virke ubetydeligt, men for natbordets træmaring bliver det et ar. En lille ring, sat på for at forhindre det. En omsorgsfuld sjæl arbejder altid stille på disse usynlige steder."},"ICON-1884":{"nm":"Dynefoldnings-kantretter","de":"Selv det at folde en dyne firkantet og pænt har sin egen struktur. Ret hjørnerne ind efter dette hjørnesættende redskab, og selv et rodet hjerte glattes ud én gang. Et ryddet sted er dagens mest sømmelige hilsen."},"ICON-1885":{"nm":"Sengebord-opladerledningskrog","de":"En krog hængt ved sengekanten, fordi jeg hadede, hvordan opladerledningen gled ned på gulvet natten igennem. Ledningen, der stille fyldes med kraft, mens du sover, venter fuldt opladet på dine fingerspidser om morgenen."},"ICON-1886":{"nm":"Sengebord-snackkurv","de":"En kurv, der samler yndlingssnacks inden for rækkevidde. Et venligt forberedelse, gjort i forudseenhed om en sent-om-natten sult. Den raslende lyd af at gribe en i mørket er af en eller anden grund varm om hjertet."},"ICON-1887":{"nm":"Sengelæsnings-bogstøtte","de":"En vinge, der forsigtigt holder den åbne bogside, så du ikke mister linjen, selv når søvnigheden ruller ind. Den ene side, du lukkede lige inden øjnene faldt i, venter på dig samme sted i morgen aften."},"ICON-1888":{"nm":"Sengebord-alarmurssokkel","de":"Selv vækkeuret, der vækker morgenen, har brug for et fast sted, der ikke vakler. Den runde stensokkel bærer dets vægt tungt og holder pladsen som et løfte, der ikke glider, selv når daggryet kommer."},"ICON-1889":{"nm":"Sovemaske-krog","de":"Et søm at hænge sovemasken på, så det stof, der har skærmet af for lys hele natten, kan trække vejret i løbet af dagen. At give et tørt sted til stof, der har gjort sin pligt: sådan siver en lille omsorg ind, pletfrit."},"ICON-1890":{"nm":"Sengebord-lommelygteklemme","de":"En klemme, der holder det lille lys, du behøver ved midnat, rettet mod den side, du ønsker. Klem lommelygten fast på sengekanten, og hånden, der famlede i mørket, bliver langt mere rolig. Et greb, der bestemmer lysets retning."},"ICON-1891":{"nm":"Skillevæggardin-opsnøringssnor","de":"En opsnøringssnor, der holder gardinet, som deler et fælles rum. Det er kun et tyndt stykke stof, men bag det ligger nogens private nat. En venlig grænse, der vogter hinandens søvn i et delt værelse."},"ICON-1892":{"nm":"Fællesstikkontakt-fordelerbræt","de":"Et træbræt lavet, så flere kan dele den ene stikkontakt. Det fordeler strømmen jævnt, så ingens nat forbliver mørk. At bo sammen begynder trods alt med at dele netop sådan noget småt."},"ICON-1893":{"nm":"Lysdæmpnings-hensynssten","de":"Når lyset er for skarpt, skubber du en sten hen i stedet for ord. \"Kan du ikke skrue lidt ned?\" Denne lille ting formidler den ene sætning for dig. Den mildeste anmodning i et delt værelse."},"ICON-1894":{"nm":"Opvågningstid-hensynstoken","de":"Et lille skilt givet videre til hånden på den, der står op først. Hvem der får mere morgensøvn, og hvem der vågner først, afgøres uden strid af denne token. Hjertet, der fastsætter turen til at give efter, med fingerspidserne."},"ICON-1895":{"nm":"Fælles bøjle-nummerring","de":"Nummerringe sat på bøjler, flere deler. Så ingen er i tvivl om, hvis plads der er hvis, skaber et lille tal stille orden. En venlig streg trukket i en hverdag, der let bliver rodet sammen."},"ICON-1896":{"nm":"Køjeseng-trinbeskytter","de":"Et dæksel, der sættes over trinnet, man kravler op ad til overkøjen. Så en bar fod, der rører det, hverken bliver kold eller glider, passer det på sikkerheden i det ene trin. Denne lille omtanke for enden af stigen bærer trygt drømmene deroppe."},"ICON-1897":{"nm":"Fælles toiletpapirholder-arm","de":"En armformet holder til at hænge det fælles badeværelses toiletpapir på. Den er placeret, så alle nemt kan trække et stykke med én hånd. Det kan virke ubetydeligt, men det er et greb, der glatter mange menneskers morgener."},"ICON-1898":{"nm":"Luftfrisker-turbrik","de":"En brik, der noterer, hvis tur det er at genopfylde luftfriskeren. Selv en svag tråd af duft er et løfte om at tage ansvar på skift. En god duft kommer ikke gratis; den blomstrer på nogens tur."},"ICON-1899":{"nm":"Fælles natlampe-håndtag","de":"Håndtaget på en natlampe, som flere tænder og slukker sammen. Den hånd, der var vågen længst, samler lyset ind til sidst. Et stille løfte mellem dem, der deler et værelse, om at dele et blidt skær."},"ICON-1900":{"nm":"Sofaarmlæn-glasholder","de":"Et rundt glasfordybning udskåret i sofaens armlæn. Man kan sætte glasset fra sig et øjeblik uden at bekymre sig om at spilde. Et hvilested behøver et sted til et glas, før hjertet endelig kan strække sig behageligt ud."},"ICON-1901":{"nm":"Lynlåsgreb til pudeindsats","de":"Et lille greb fastgjort på lynlåsen, der åbner og lukker pudens indsats. Én ring sparer besværet med at skifte betrækket. At tage sig af selv det usynlige indre — husholdningens ømhed gemmer sig altid netop dér."},"ICON-1902":{"nm":"Rygstøttekile til sofa","de":"En pude, der fylder hullet i ryglænet og støtter lænden. Den udfylder det tomme rum, så ryggen ikke gør ondt, selv efter lang tids siddende. Den behagelighed kroppen først genkender med et suk: \"ah, det er den,\" i det øjeblik du læner dig tilbage."},"ICON-1903":{"nm":"Hjørnebånd til sædehynde","de":"Et bånd, der griber hynden i hjørnerne — den som plejede at kravle af sted, hver gang man satte sig. Det fastgør den ét sted, så den ikke glider. Ordentlighed begynder netop i sådan en lille, stædig fastgørelse."},"ICON-1904":{"nm":"Sømbeskytter til pude","de":"Det første sted en pude slides er altid hjørnesømmen. En beskyttende strimmel viklet om det sted på forhånd, så den ikke sprænger. Et hjerte, der ønsker at beholde den længe, er lige så solidt som sømmen selv."},"ICON-1905":{"nm":"Fjernbetjeningslomme til sofasprække","de":"Fjernbetjeningen, der blev ved med at forsvinde mellem hynderne, har endelig fået sit eget hjem. En lille lomme presset ind i sofaens sprække. At vide, at det man troede var væk, altid er lige der, er en større tryghed, end man skulle tro."},"ICON-1906":{"nm":"Rullesnor til knætæppe","de":"En snor til at rulle og binde knætæppet sammen. Varmen, der spredes, når det ligger udfoldet, ryddes pænt væk til den næste nat. Sådan gemt kan selv varmen hentes frem og trækkes over igen i morgen."},"ICON-1907":{"nm":"Knap til fodskammelbetræk","de":"En knap, der fæstner betrækket på fodskamlen — det sted der slides hurtigst af fødder — så det let kan skiftes. Det ene klik lukker og forlænger stoffets levetid. Et hjerte, der ønsker at bruge tingene længe, er grundigt i de små detaljer."},"ICON-1908":{"nm":"Glidehætte til sofaben","de":"Selv en tung sofa må ikke ridse gulvet. En blød hætte trukket over de fire benender træder forsigtigt for at skåne trægulvet. Møbler, der er varsomme lige ned til tæerne, vinder på en eller anden måde mere kærlighed."},"ICON-1909":{"nm":"Holder til fjernbetjeninger","de":"En holder, der stiller op på række, side om side, de fjernbetjeninger der plejede at rulle og sprede sig i alle retninger. Når de lange og korte pinde står pænt på linje, sænker det alene rummets luft en tone i ro."},"ICON-1910":{"nm":"Ladekrog til controller","de":"En krog til at hænge og oplade controlleren efter en omgang livlig spil. Mens den hænger og stille genopfylder sin energi, hviler hænderne også et øjeblik. Denne korte pause forbereder solidt den næste runde."},"ICON-1911":{"nm":"Pose til spillebrikker","de":"En lille pose, der rummer brikker i alle farver. Brikkerne, der venter på næste runde inde i én pose, klaprer, hver gang man ryster den. Ved den lyd vågner spændingen \"en omgang til?\" som det første."},"ICON-1912":{"nm":"Terningebakke","de":"En bakke lavet netop til at kaste terninger i. Lykken, der plejede at hoppe af bordet og forsvinde, holder kanten nu indenfor. I det korte øjeblik, hvor de ruller og stopper, holder alles vejrtrækning et kort sekund inde sammen."},"ICON-1913":{"nm":"Kortspilbånd","de":"Et bånd, der binder et kortspil sammen, så det ikke spredes. Indtil kortene blandes, er den rækkefølge i sig selv et løfte. I bevægelsen, hvor man løsner båndet og breder kortene ud, begynder en omgangs historie først."},"ICON-1914":{"nm":"Kabelclips til konsol","de":"En klemme, der griber og reder de sammenfiltrede kabler bag konsollen. Den rydder stille op i rodet et sted, man næsten ikke kan se. Ordentlighed fuldendes altid stille, som her, bagfra."},"ICON-1915":{"nm":"Pointskive","de":"En lille skive, man drejer for at vise pointene. Klik, for hvert hak stiger tallet, og jubel følger med. Selv uden at regne i hovedet husker fingerspidserne dagens dyst først."},"ICON-1916":{"nm":"Standerfod til spillebræt","de":"En fod, der rejser brættet på skrå og indstiller vinklen, så alle siddende rundt om kan se brættet på ét blik. Så ingen behøver strække hals, breder den stille et retfærdigt udsyn ud for alle."},"ICON-1917":{"nm":"Lodtrækningsbæger til turrækkefølge","de":"Et bæger, man stikker hånden ned i for at trække lod om spillerækkefølgen. Den ene pind, man famler efter og griber, afgør, hvem der starter. I det korte øjeblik, hvor man læner sig lidt op ad held, dirrer alle sammen inde i det runde bæger."},"ICON-1918":{"nm":"Delefad til snacks","de":"Et delt fad til at servere snacks efter slags. Inddelt i rum kan man vælge sin favorit, uden at hænderne støder sammen. Omsorgen, der har talt dem man skal dele med, ligger i hvert rum."},"ICON-1919":{"nm":"Tehætte","de":"En hætte, der svøber tekandens skuldre for at bevare varmen. Den pakker den ind, så teen ikke køler af, mens den langsomt trækker. Fingerspidsens ønske om at servere en varm kop varm hele vejen til bunds."},"ICON-1920":{"nm":"Teposeholder","de":"En holder, hvor en færdigtrukket tepose løftes op og får lov at hvile lidt. Den opsamler selv den sidste dråbe, så intet spildes. Et sted, der giver selv et blad, der har gjort sit, en ordentlig afslutning."},"ICON-1921":{"nm":"Markeringsring til fælleskrus","de":"Seks ens krus på hylden i frokoststuen. I stedet for at spørge, hvis er hvis, satte vi ringe af forskellige farver på. Ét lille mærke binder stille seks mennesker, hver med sin egen smag, sammen ved samme bord."},"ICON-1922":{"nm":"Delekurv til popcorn","de":"Mens den går fra hånd til hånd, hilser den sprøde damp først. Hvis der er noget, der mærkeligt nok ikke bliver mindre, jo mere man tager ud i håndfulde, må det være følelsen af en aften delt siddende sammen."},"ICON-1923":{"nm":"Sukkertang med holder","de":"Et prik med tangen, og en kant af sukker falder i tekoppen. At se de hvide hjørner langsomt løse sig op og forsvinde — en uhastet skik for sødme, først lært ved bedstemors tebord."},"ICON-1924":{"nm":"Skridsikker bakkemåtte","de":"Selv hvis bakken vipper, holder kopperne deres plads. Som de ting altid gør, der stille holder fast nedefra, udholder måtten alene øjeblikket, hvor den næsten gled, og holder til sidst tæt."},"ICON-1925":{"nm":"Sugerørsstander","de":"Rejs sugerøret lige op, og hverken drikken eller sindet falder i uorden. På en eftermiddag hvor skrivebordet bliver ordentligt af blot én lille oprejsthed, holder koppen en lille søjle og bærer stille de dovne timer."},"ICON-1926":{"nm":"Kagesmuleopsamler","de":"Sprødt — i det øjeblik en kage smuldrer, samler de faldne stykker sig her. At tage imod selv sporene, som den lækreste bid har efterladt: bordets stille afslutning, kærlig helt ned til den sidste krumme."},"ICON-1927":{"nm":"Fotoline med klemmer","de":"Polaroider hænges én for én med klemmer på en snor spændt op som en tørresnor. Mens dagens smil vifter og tørrer i vinden, bliver et stykke væg til en lille, lys udstilling af minder."},"ICON-1928":{"nm":"Mindetrådsnelle","de":"En spole, hvor sammenfiltret tråd er redt ud og viklet pænt op. Ting, der er ført videre, knyttet sammen ved hvert brud. Hvis man langsomt spoler minder tilbage sådan, en omgang ad gangen, bliver en vej, man troede var blevet kortere, lang igen."},"ICON-1929":{"nm":"Sømhulsdæksel","de":"Et lille rundt dæksel, der skjuler et sømhul. Dæk stille selv det lille ar, der er tilbage efter det, der engang hang der, er taget ned, og væggen vender tilbage til et glat ansigt, som om intet var sket."},"ICON-1930":{"nm":"Indstikramme til gruppefoto","de":"Et gruppefoto af seks taget med skuldrene tæt sammen. I det øjeblik man skubber det ind i rammen, forsegles den dags latter og varme sammen. En ramme er den hånd, der stillest standser en forbipasserende dag."},"ICON-1931":{"nm":"Opslagstavle af kork","de":"En brun tavle tæt besat af tegnestiftmærker. Et løfte man ikke må glemme, en opmuntrende seddel nogen har sat op, dagens gøremål — alt sættes op lag på lag. En pålidelig væg ved skrivebordet, der husker i stedet for hovedet."},"ICON-1932":{"nm":"Knude til dørkrans","de":"Selv en krans hængt på døren kræver fingerfærdighed. Knuden skal bindes godt fast, så den ikke falder i den blæsende årstid. Det hjerte, der byder nogen velkommen, bliver altid først solidt et usynligt sted."},"ICON-1933":{"nm":"Pendulbetræk til vægur","de":"Et stofbetræk, der omslutter det tikkende pendul for at holde støv ude. Selv arbejdet med at måle tiden modtager omsorg på denne måde. Beskyt det skånsomt mod slid, så bliver vægurets plads ved vores side lidt længere."},"ICON-1934":{"nm":"Klistermærketavle","de":"Klistermærker, der plejede at sprede sig i hver skuffe, samles på én tavle og stiller op på række. En yndlingskarakter, en glitrende stjerne, et ark håndskrift. Når den lille glæde ved at samle bliver pænt ordnet, bliver selv sindet ordentligt."},"ICON-1935":{"nm":"Snor til flagguirlande","de":"En snor, der binder farverige flag sammen i én række. Fødselsdag eller velkomst — i det øjeblik snoren krydser loftet, forvandles et almindeligt rum til et festhus. At fejre er arbejdet med at samle og sy et brudt hjerte sammen igen."},"ICON-1936":{"nm":"Korkunderlag til elkedel","de":"Et enkelt stykke kork, der bærer den varme kedels bund. Så bordet ikke svides, tager det alene den varme til sig. En lille omtanke, der stille bærer den, så ingens varme efterlader et mærke."},"ICON-1937":{"nm":"Krummebakke til brødrister","de":"Krummerne, som det gyldenristede brød har tabt, triller ned på bakken. Bare træk den ud og ryst den — færdig. Den tager stiltiende imod den travle morgen og gør sig ren og klar igen til næste måltid."},"ICON-1938":{"nm":"Drejering til mikrobølgeovn","de":"På den roterende ring tegner tallerkenen langsomt en hel cirkel. Den omdrejning, drejet for at varme jævnt, vækker gårsdagens kolde ris til live igen som et måltid, der damper varmt."},"ICON-1939":{"nm":"Kogepladedæksel til mini-induktion","de":"Uanset hvor meget olien sprøjter til alle sider, forbliver pladen ren. Ét dæksel skiller den voldsomme varme fra hænderne. De ting, der usynligt stiller sig i vejen, holder køkkenet som et sted, hvor man ikke bliver svedet."},"ICON-1940":{"nm":"Dampventilhætte til riskoger","de":"Lyden af damp, der siver ud, ssss. Takket være en lille hætte, der forsigtigt slipper trykket ud, åbner nykogt ris låget med det blødeste ansigt. Der er ingen hast, når man lader den dampe færdig."},"ICON-1941":{"nm":"Standerholder til grydeske","de":"Stil den suppeomrørende ske lodret op. Et lille hjerte, der ønsker ikke at spilde en eneste plet på bordpladen. Køkkenets ordentlighed begynder altid fra sådan et ubemærket, ubetydeligt sted."},"ICON-1942":{"nm":"Silikonegreb til grydehank","de":"Sæt silikonen på en glohed grydehank, og hånden bliver ikke brændt. Ét lag, der lægger sig mellem varmen og håndfladen. Det vogter den, der laver varm mad, fra det allernærmeste sted."},"ICON-1943":{"nm":"Kalkfilter til elkedel","de":"Selv i vand, der koges hver dag, ophobes et svagt spor. Et fintmasket net filtrerer stille kalken fra og skænker kun en klar kop. En flittig hånd, der vogter tekoppens første slurk fra et usynligt sted."},"ICON-1944":{"nm":"Klemmeben til køkkenur","de":"Tre minutter mere, siger uret og bider sig fast i bordkanten med sine klemmeben. Mens nudlerne koger, står det spændt på sine små ben og tæller tikkende dagens mest ventede øjeblik."},"ICON-1945":{"nm":"Drypkop til bestik","de":"Vand siver ned fra lige skyllet bestik. Når drypkoppen stille samler den fugt, bliver bordet snart tørt. Renlighed er en kærlig flid, der tager sig af selv den sidste vanddråbe."},"ICON-1946":{"nm":"Opretstående tallerkenholder med rum","de":"Stil tallerkenerne lodret op, inddelt i rum. Fade, der plejede at ridse hinanden, når de blev stablet, får hver sin egen plads. Orden er, når alt kommer til alt, at give alle deres eget rum, hvor de ikke støder sammen."},"ICON-1947":{"nm":"Sammenparringsring til spisepinde","de":"Træd spisepinde, der er blevet alene uden deres mage, på ringen og par dem igen. For en enkelt pind mister hurtigt sin nytte, og denne lille ring bevarer ordenen i skuffen ved at binde dem side om side."},"ICON-1948":{"nm":"Koptræ","de":"Hæng kopperne én for én på en holder, der forgrener sig som grene. Mens fugten tørrer på hvert omvendt glas, står et hjørne af køkkenet stille som et lille, ordentligt træ."},"ICON-1949":{"nm":"Bestikbakke med håndtag","de":"En bakke, hvor ske, spisepinde og gaffel ligger side om side i rum. Tag fat i håndtaget og løft det hele ud, og bordækning bliver langt lettere. Ordenens æstetik lever også i skuffen, uden undtagelse."},"ICON-1950":{"nm":"Aftørringsplade til glas","de":"Sæt de vaskede glas på hovedet, og vanddråberne falder, dryp, dryp. Mens de langsomt tørrer ved et solbeskinnet vindue, genvinder glasset roligt sin oprindelige klarhed til den næste slurk."},"ICON-1951":{"nm":"Renselkam til gaffeltænder","de":"Dens fine tænder fejer sagte mad væk mellem gaffelens tænder. Takket være en hånd, der passer selv de smalleste sprækker, begynder næste måltid altid med en fejlfri, ren første bid."},"ICON-1952":{"nm":"Skridsikker filt til stabling","de":"Stabl skåle, og porcelænet klirrer skarpt mod hinanden. Ét stykke filt puttet imellem dæmper den friktion. Hemmeligheden bag et langt liv sammen ligger i at gøre hinanden lidt blødere."},"ICON-1953":{"nm":"Ophængssnor til teske","de":"Hæng den nydelige teske i løkken og fæst den på væggen. Aldrig begravet i en skuffe, glimter den inden for rækkevidde — et lille redskab, der stolt indtager sin retmæssige plads. Selv husholdningen har et hjem til alt."},"ICON-1954":{"nm":"Rumopdelt køleskabsbakke","de":"Del køleskabsrummet op i sektioner, og hver ingrediens får sit eget lille hus. Ting, der før blev rodet sammen og glemt, finder deres plads, og hver gang man åbner døren, ser man med det samme, hvad der er hvor."},"ICON-1955":{"nm":"Ståklemme til fryseposer","de":"Grib en halvtom frysepose med klemmen, og rejs den lige op. Så den ikke vælter og spilder, så den er let at finde næste gang. Selv i det kolde fryserum bor en flittig husholderskes snusfornuftige visdom."},"ICON-1956":{"nm":"Flaskelåg-strammer","de":"En flaske, der ikke er lukket helt til, mister snart sin brus. Det ene håndledsvrid, der strammer låget godt til, låser duften og kulsyren intakt inde til i morgen tidlig. Flid skinner i de små ting."},"ICON-1957":{"nm":"Skridsikker æggebakke","de":"En måtte, der vugger runde æg i rum, så de ikke ruller væk og knækker. Ønsket om at behandle det skrøbeligste med den største omhu sidder lille og ømt i ét hjørne af køleskabsdøren."},"ICON-1958":{"nm":"Udvidelsesbånd til køleskabslomme","de":"Stræk køleskabsdørens lomme en smule til siden og skab endnu et rum. For når husholdningen vokser, må dens plads vokse med. I færdigheden at udvide et trangt sted spejler sig en flittig husholderskes hjerte."},"ICON-1959":{"nm":"Trykdæksel til rester","de":"Et låg, der presses forsigtigt ned over resterne af tilbehør. Det vogter dem stille, så de ikke tørrer ud eller optager andre lugte. En omsorgsfuld hånd lægger omhyggeligt selv resten af ét måltid til side."},"ICON-1960":{"nm":"Retningsspjæld til kold luft","de":"Hvilken vej skal kulden strømme? Et lille spjæld fastlægger stille retningen. Skub den usynlige brises vej en smule med fingerspidsen, og kulden når selv det inderste, dybeste hjørne."},"ICON-1961":{"nm":"Fugtpude til grøntsagsskuffe","de":"I det mørkeste hjørne af køleskabets grøntsagsskuffe holder jeg tavst på fugten. Det lille mirakel, at gårsdagens visne blad bliver sprødt igen om morgenen. Selvom ingen lægger mærke til det, er friskheden altid mit ansvar."},"ICON-1962":{"nm":"Rullestop til dåser","de":"Klæbet stille fast til bordkanten griber den fat i foden af en dåse, der var ved at trille væk. En drik, der næsten væltede, et bord, der næsten skulle tørres af. Trygheden i husholdningen begynder ved sådan en lille, ubemærket kant."},"ICON-1963":{"nm":"Turnusskive til husholdningspligter","de":"I dag, hvem tager opvasken, hvem sorterer affaldet. Ét drej af pilen, og enhver strid glider glat væk. I et hus hvor fem lever tæt sammen, er det at skiftes den venligste form for fred."},"ICON-1964":{"nm":"Silikonebånd til familiekrus","de":"Fem næsten ens krus, og en morgen med undren over hvis er hvis. Sæt et håndledsbredt farvet bånd på, og det lille løfte \"den her er min\" bliver tydeligt og pryder morgenbordet med venlig orden."},"ICON-1965":{"nm":"Portionsring til skål","de":"På en travl dag bliver mærkerne inde i skålen en pålidelig ven. Ét rum til ris, ét til tilbehør. Hverken for lidt eller for meget — en venlig linje fortæller stille, nøjagtig hvor meget man skal spise i dag."},"ICON-1966":{"nm":"Delebøtte med tang til snacks","de":"Skub hele posen frem, og det sted hånden rørte, ligger tilbage, pinligt. Del ud én ad gangen med tangen, og først da bliver alles andel lige stor. Deling passer bedre til ordentlige hænder end til håndfulde."},"ICON-1967":{"nm":"Navneskiltholder til kedelvagt","de":"At koge vand faldt altid i de samme hænders lod. Siden vi begyndte at hænge navneskilte på skift på holderen ved kedlen, er en varm kop te blevet til hengivenhed brygget på skift."},"ICON-1968":{"nm":"Rentallerken-chip til pandeske","de":"Et lille \"lad intet blive tilbage\" hænger ved spidsen af pandeskeen. Det kan lyde som brok, men der er intet ondt i det — for ånden fra det gamle bord, hvor hvert måltid blev værdsat, bor her."},"ICON-1969":{"nm":"Krog til personlig bestikpose","de":"Bestik rasler ikke længere løst i skuffen. I det øjeblik hvert sæt kommer i sin egen pose og hænger på væggen, stiller fem familiemedlemmers pladser op side om side. En lille orden bærer hver dags fred."},"ICON-1970":{"nm":"Korkbrik til pladsmarkering","de":"Læg korkstykker på bordet, og det bliver klart, hvem der sidder hvor. Pladsen man altid tager, profilen man altid vender ansigtet mod. En fast plads er det stilleste bevis på ordene \"vi bor sammen.\""},"ICON-1971":{"nm":"Rullekrog til vagtforklæde","de":"Forklædet, der er færdigt efter opvasken, smides ikke bare et sted. Rullet sammen og hængt på krogen ligger det klar og frisk til næste morgens greb. Et hjerte, der tænker på den næste, bor i denne lille knude."},"ICON-1972":{"nm":"Foldepose til engangstøfler","de":"Den dag der kommer gæster, folder jeg mig ud, taske og det hele. De engangstøfler, der ligger pænt pakket indeni, byder nyankomne fødder velkommen med blødt polster. Gæstfrihed begynder altid stille i entréen."},"ICON-1973":{"nm":"Lomme til vatpindshaler","de":"Når vatpindene er brugt op, og kun papirhalerne er tilbage, samler jeg omhyggeligt deres ender. At give plads til selv det, der ellers ville blive kasseret. Jeg ved, hemmeligheden bag et pænt skrivebord er sådanne små venligheder."},"ICON-1974":{"nm":"Trådspolebundt til syæske","de":"Bind de farvede tråde sammen, så spolerne ikke ruller ud og filtrer sig. En falden knap, en løs manchet — dette ene bundt lapper dem i en fart. Håndsyning der stille redder aftenen før en vigtig dag."},"ICON-1975":{"nm":"Enkeltpakket sæbestykke","de":"Et pænt enkeltvis indpakket stykke sæbe ligger i hvert gæsteværelse. En håndfladestor krop vasker dagens støv væk med en enkelt håndfuld skum. Renlighed begynder altid på sådanne små steder."},"ICON-1976":{"nm":"Foldekapsel til badehætte","de":"Fold folderne sammen, og den passer lige i håndfladen; fold den ud, og den omslutter håret tæt. Så en styled frisure ikke bryder sammen ved ét bad. Dette ene lag vogter morgendagens ordentlighed."},"ICON-1977":{"nm":"Beskyttelseshylster til tandbørste","de":"Børstehårene er mere sarte, end man skulle tro. Ét hylster over spidserne holder selv taskens støv ude. At vogte de usynlige steder — det egentlige arbejde med hygiejne, lært på hver rejse."},"ICON-1978":{"nm":"Enkelttrækstang til vatrondeller","de":"Vatrondeller kommer kun pænt ud, når man tager dem én ad gangen. Vælter man dem hele ud, går der mere til spilde. \"Én ad gangen, med omhu\" — det er den stille regel oven på sminkebordet."},"ICON-1979":{"nm":"Mini-foldeskohorn","de":"Foldet er den i lommen, udfoldet ved hælen. Med sin lille krop er den stolt af at klare et temmelig stort job. Selv en morgen med oversovning var det altid mig, der lod dig tage skoene på uden at ødelægge dem."},"ICON-1980":{"nm":"Enkelttrådsnelle til tandtråd","de":"Vikl en tråd tandtråd pænt op, og klip præcis det af, du skal bruge, når tiden kommer. En snelle ikke større end en negl, men aldrig fraværende i arbejdet med at vogte et lyst smil. Selv et smil har usynlige forberedelser."},"ICON-1981":{"nm":"Låggreb til elkedel","de":"Så dampen fra kogende vand ikke brænder hånden, klipser jeg fast på låget. Et håndsbred mellem varmen og håndfladen. Den lille afstand varmer trygt en travl morgen for nogen."},"ICON-1982":{"nm":"Silikoneunderlag til strygejern","de":"Det farligste øjeblik er, når man kort slipper strygejernet midt i strygningen. Rejs det på silikonepuden, og hverken bord eller tøj bliver svedet. Arbejdet med at glatte folder afsluttes først oppe på underlaget."},"ICON-1983":{"nm":"Tyverisikret bøjlekrog","de":"Så et hængende stykke tøj ikke uforvarende glider af, holder krogen sin mund stædigt lukket. En lille vagtpost, der vogter det kærkomne stykke i skabet. At beskytte er en stille ting, ligesom dette."},"ICON-1984":{"nm":"Kalksi til elkedel","de":"Min opgave er stille at sile kalken fra, der flyder rundt i det kogende vand. Først når selv de usynlige bundfald er filtreret bort, bliver en kop te klar. Omhu spirer altid de steder, øjet ikke ser."},"ICON-1985":{"nm":"Skridsikker strimmel til bøjle","de":"En bøjle viklet med en skridsikker strimmel taber ikke engang let silke. Alle, der én gang har set et stykke tøj falde på gulvet og krølle, kender taknemmeligheden ved denne ene tynde linje."},"ICON-1986":{"nm":"Ledningsclips til strygejern","de":"En løs ledning snubler fødder og får nogen til at vakle. Ét håndgreb med klemmen binder den pænt sammen. At forebygge ulykker starter altid ved sådan en lille, ubetydelig oprydning."},"ICON-1987":{"nm":"Fordybning til kedelsokkel","de":"Jeg sætter kedlen tæt ned i min fordybning, så den ikke vakler. At være på sin rette plads er ensbetydende med tryghed. Der er en grund til, at det varme vand varmes op på samme sted hver morgen."},"ICON-1988":{"nm":"Klemmeben til bukseophæng","de":"Når klemmebenene bider sikkert fast i buksernes ben, danner der sig ikke én eneste fold. Et velstrøget sæt tøj behandles godt fra det øjeblik, det hænges op. Et pænt snit fuldendes inde i skabet."},"ICON-1989":{"nm":"Ophængskrog til hårtørrer","de":"Læg hårtørreren hvor som helst, og ledningen filtrer sig hurtigt. Hæng den på krogen, og vasken bliver bredere, morgendagen lettere. En ordentlig plads letter stille en travl dag."},"ICON-1990":{"nm":"Glasbrik til minibar","de":"Sæt den stille under glasset, og vanddråberne breder sig ikke ud over bordet. Omtanken i et enkelt glasunderlæg efterlader ingen rund plet. Renlighed er venligheden ved ikke at efterlade spor."},"ICON-1991":{"nm":"Forstyr-ikke-skilt til dør","de":"Et skilt hængt på dørhåndtaget hvisker stille \"hviler nu.\" At vogte ét pust af middagslur ved enden af en lang dag. Selv et komma i dagen skal nogen passe på med omhu."},"ICON-1992":{"nm":"Hætte til roomservice-knap","de":"Takket være hætten om knappen bliver den ikke trykket ved et uheld, selv om et klædeskørt strejfer den. Så man kun kalder tydeligt, når det virkelig er nødvendigt. Ét lille dæksel gør et travlt værelse en tand mere ordentligt."},"ICON-1993":{"nm":"Isklemmeben til minibar","de":"Tag is med bare hænder, og det er koldt og bliver ved med at glide. Klemmebenene tager sig sikkert af den opgave i stedet. Bag begyndelsen på et køligt glas gemmer sig en usynlig hjælpende hånd."},"ICON-1994":{"nm":"Nøglekortlæser til værelse","de":"Stik kortet i sprækken, og værelsets lys tændes med et klik. Jeg er kun en lille sprække, men jeg er den første gestus, der åbner et rum til at lægge dagens træthed fra sig i. Lyset tændes igen på det sted, man vender tilbage til."},"ICON-1995":{"nm":"Forseglingsring til flaskehals","de":"Hvis forseglingsringen om flaskens hals er intakt, betyder det, at ingen har rørt den endnu. Et lille løfte, der beviser, den er helt som ved starten. Tillid begynder med en ubrudt forsegling."},"ICON-1996":{"nm":"Standerholder til brochure","de":"Rejs brochuren på skrå, og forbipasserende blikke dvæler af sig selv. Den sømmelige holdning hos information, der venter på at blive åbnet. Blot ved at gøre den synlig gøres nogens vej en del lettere."},"ICON-1997":{"nm":"Flad oplukkerbrik til minibar","de":"I et hjørne af sin flade krop gemmer sig diskret et hak til at åbne kapsler med. Lille som den er, udfører den sin opgave upåklageligt. Den første kølige slurk af en flaske åbner altid med denne lille brik."},"ICON-1998":{"nm":"Dæksel til dæmperknap","de":"Drej forsigtigt på den betrukne knap, og rummets lysstyrke skifter langsomt. Klart, og så dæmpet. At vælge lyset ved sengetid er et ritual, der afslutter dagen med venlighed."},"ICON-1999":{"nm":"Hjulstopkile til kuffert","de":"Klem den let ind under hjulet, og kufferten ruller ikke af sted af sig selv. Selv på en skrånende perron holder bagagen sin plads. Trygheden på en afrejse styrkes af netop denne lille kile."},"ICON-2000":{"nm":"Pakkeplade til rejsetøj","de":"Fold den ud og læg skjorte eller bukser ovenpå, og de foldes skarpt og pænt. Så taskens indre ikke kollapser, så man kan træde ud uden krøller i den ankomne by. Velpakket bagage hjælper rejsen, allerede før man tager af sted."},"ICON-2001":{"nm":"Låseknap til pengeskab","de":"Drej knappen, og en lille slå glider indad. At betro sine kostbarheder væk er et løfte om at lade hjertet falde helt til ro, bare for én nat. Låsen står der ikke som uro, men som endnu et navn for tryghed."},"ICON-2002":{"nm":"Kuffertgrebsbetræk","de":"I hvert nusset, håndslidt sted er der indprentet en afsked. Grib fat i dette betræk, slidt lige så meget som de kilometer, det er blevet slæbt, og du forstår stille, at at rejse er, trods alt, et ord der rummer det at vende hjem."},"ICON-2003":{"nm":"Hængeklemme til rejsetaske","de":"Hæng posen op på håndvaskens kant, og det trange værelse vinder en håndsbredde. At orden i en taske begynder med én lille klemme, det ved hånden, der har rejst langt, allerede."},"ICON-2004":{"nm":"Opladerklemme til flerstik","de":"Saml flere kabler i én stikkontakt. På en nat, hvor man venter på, at opladningen bliver færdig, er der her en lille hånd, der ømt holder de spredte ledninger samlet ét sted."},"ICON-2005":{"nm":"Navneskilt-snor til kuffert","de":"Blandt ens ens sorte tasker lader én rem dig genkende din egen. At hænge et navn op er et ømt mærke om, at denne bagage har en vej tilbage til nogen."},"ICON-2006":{"nm":"Vægholder til opladerkabel","de":"En lille plade på væggen ved sengegærdet holder ladekablet pænt på plads. Den første nat i et fremmed værelse, når ét kendt lys tændes, bliver selv det sted et hjem for en stund."},"ICON-2007":{"nm":"Foldeben til bagagestativ","de":"Fold de sammenklappede ben ud, og tasken løfter sig en håndsbredde fra det støvede gulv. En kuffert, der stadig står upakket, rummer stille en uafsluttet rejse og venter på den næste morgen."},"ICON-2008":{"nm":"Nøglekortslot","de":"Kortet skal sættes i, for at lyset i værelset tændes. Et lys der kun skinner, mens man bor der — en rejsendes dag varmes af netop den lysstyrke, denne lille slot tillader."},"ICON-2009":{"nm":"Nøglekortsnor med løkke","de":"Hæng det ene kort om halsen, og begge hænder bliver fri. At binde bekymringen for at miste det til én snor er en lille snuhed, som rejsende med tung bagage har givet videre i generationer."},"ICON-2010":{"nm":"Ringeklokke til receptionen","de":"Tryk på den, og en klar klingende lyd runger et sted henne ved receptionen. For at det aldrig skal føles pinligt at bede om hjælp, ligger klokken altid venligt inden for én hånds rækkevidde."},"ICON-2011":{"nm":"Kø-nummerklemme til indtjekning","de":"Tag kønummersedlen, du fik i slutningen af rækken, og fastgør den. At selv ventetid har sin tur — orden gror af det lille løfte om stille at værne om hinandens tid."},"ICON-2012":{"nm":"Kvast til værelsesnøgle","de":"En kvast, der hænger fra nøglens ende, svajer let ved hvert skridt. Det hjerte, der lister et strejf af elegance ind i det nyttige, tilhører kun dem, der kender fingerspidsernes glæde."},"ICON-2013":{"nm":"Dørklokkeafdækning til receptionen","de":"Sæt afdækningen over dørklokken, og middagens stilhed forbliver ubrudt. En lille hensyntagen for at værne om nogens dybe søvn — selv stilhed er noget, nogen har skabt med omhu."},"ICON-2014":{"nm":"Dørskilt med værelsesnummer","de":"En seddel hængt på dørhåndtaget bærer værelsesnummeret tydeligt. Nogle få tal fastsætter det sted, jeg vender tilbage til i aften, og i en fremmed korridor bliver det et lille fyrtårn."},"ICON-2015":{"nm":"Magnetstribe til nøglekort","de":"Hold den sorte stribe mod dørens kant, og låsen glider stille op. En tid, hvor et usynligt signal åbner en dør — det, der engang føltes som magi, er nu blevet en hverdagsting i hulen af din hånd."},"ICON-2016":{"nm":"Stempelunderlag til indtjekning","de":"Hver gang stemplet falder, tager underlaget imod blækket jævnt. For at bekræftelsens ene aftryk skal stå tydeligt, findes der en hånd, der tavst støtter fra et usynligt sted."},"ICON-2017":{"nm":"Ophængsstang til bagagevogn","de":"Én stang på bagagevognen holder klædeposen oppe uden en fold. Til de ting, der bærer en tung dag i vores sted, får man lyst til nu og da at sige tak."},"ICON-2018":{"nm":"Kuffertgrebsskilt","de":"Hæng et lille skilt på kuffertens håndtag. Så længe navnefeltet står tomt, er der en snært af forventning tilbage — denne tasches næste rejsemål er endnu ikke bestemt."},"ICON-2019":{"nm":"Hjulkile til bagagevogn","de":"Sæt en kile under hjulet, så vognen ikke ruller på en skråning. Arbejdet med at værne om stilstand er til tider selve trygghedens andet ansigt."},"ICON-2020":{"nm":"Bagageremspænde","de":"Stram remmen godt til, så en taske, oppustet af rejsegods, ikke sprænges. Selv når vejen slutter, mindskes minderes fylde ikke, så spændet holder den vægt helt til sidst."},"ICON-2021":{"nm":"Krogbetræk til bagagevogn","de":"Betrækket over vognens krog efterlader ikke ét mærke på tøjet. Et hjerte, der forudser selv usynlige ridser — god gæstfrihed fuldendes netop i sådanne små ting."},"ICON-2022":{"nm":"Navneskiltslomme til kuffert","de":"En lille lomme på taskens side holder om et navneskilt. At skrive, hvem den tilhører, er som på forhånd at indskrive retten til at mødes igen, selv hvis den skulle blive væk."},"ICON-2023":{"nm":"Handskeklemme til bagagebæring","de":"Når man bærer tunge byrder, holder klemmen fast om handskerne, så de ikke glider af. At værne om hænderne og at udføre arbejdet godt udspringer, i sidste ende, af ét og samme hjerte."},"ICON-2024":{"nm":"Nettildækning til bagage","de":"Læg nettet over, og de små stykker bagage spredes ikke til alle sider. Hver stram lille maske sørger for, at intet småt tabes i den travle flytning."},"ICON-2025":{"nm":"Notatholder til bagagevogn","de":"En seddel stukket ind i vognens håndtag bærer værelsesnummeret. Vanen med at skrive ned, hvor man skal hen — jo travlere hænderne er, jo mere lener de sig stille på én linje skrift."},"ICON-2026":{"nm":"Fadhætte til serveringsbakke","de":"Løft den sølvfarvede hætte, og dampen stiger op med det samme. Hjertet, der dækker maden til, så den ikke bliver kold, er selve omsorgen — ønsket om at give varmen videre, netop som den er."},"ICON-2027":{"nm":"Forstyr ikke-skilt","de":"Hæng dette skilt på dørhåndtaget, og selv fodtrin i gangen bliver forsigtige. Den ene sætning »forstyr mig ikke« — hvile bliver først fuldkommen, når nogen vogter over den."},"ICON-2028":{"nm":"Servietring til roomservice","de":"Stik papirservietten gennem den runde ring for at give den en pæn form. Et måltids stilfuldhed begynder med denne lille løkke — omhu viser sig tydeligst i de mindste ting."},"ICON-2029":{"nm":"Skridsikker bakkemåtte","de":"Læg en måtte på bakken, og tallerkenerne glider ikke. At holde dem på plads selv i svaj — selv rolig stabilitet rummer nogens omhyggelige design."},"ICON-2030":{"nm":"Morgenmadsbestillingsskilt til dør","de":"Hæng morgenmadsbestillingsskiltet på dørhåndtaget, og morgendagens morgen er lovet på forhånd. At skrive det første måltid ned allerede i aften er endnu et ansigt på ømsindet forventning."},"ICON-2031":{"nm":"Bakkeben-stativ","de":"Fold bakkens ben ud, og selv oven på sengen bliver den et rigtigt bord. En morgenanretning modtaget der, hvor man ligger — et lille stativ forvandler et almindeligt værelse til et luksuriøst syn."},"ICON-2032":{"nm":"Tehætte","de":"Drap en hætte over tekanden, og vandets varme dvæler længe. Som de gamle nætter samlet om ildstedet kender ønsket om at bevare varme ingen tidsalder."},"ICON-2033":{"nm":"Rengøringsanmodningsskilt til dør","de":"Hæng rengøringsanmodningens hale på dørhåndtaget for at efterlade et tavst signal. En anmodning, der bæres videre uden at læberne åbnes — bag et pænt værelse ligger løftet om en usynlig hånd."},"ICON-2034":{"nm":"Krydderiholder til bakke","de":"Holderen griber fast, så krydderiflaskerne ikke vælter. At bevare smagens balance selv på en svajende bakke er den tavse opgave for denne ene lille fastgørelse."},"ICON-2035":{"nm":"Reservationsnotat-stativ","de":"Stil reservationssedlerne op, og rækkefølgen aflæses med ét blik. Så selv travle hænder ikke bliver forvirrede, er det et lille ordensredskab, der holder ét ark tydeligt oprejst."},"ICON-2036":{"nm":"Kort med nåle til seværdigheder","de":"Sæt nåle i kortet, og marker ét sted efter ét, du ønsker at besøge. Hver nål en spænding endnu ikke oplevet — rejsen begynder allerede i det øjeblik, kortet foldes ud."},"ICON-2037":{"nm":"Flagklemme til taxikald","de":"Når man tilkalder en taxi, rejser klemmen det lille flag lige op. Et signal flaget råber i stedet for en løftet hånd — også på gaden må et kald være tydeligt, før det når frem."},"ICON-2038":{"nm":"Ringegreb til concierge","de":"Tryk på grebet, og en klar klokketone når frem til conciergedisken. Et velkomstsignal, der siger, spørg om alt du vil — i en fremmed by det mest betryggende ene kald."},"ICON-2039":{"nm":"Klemmeplade til reservationsnummer","de":"Klem reservationsnummerets seddel fast på klembrættet, så den ses tydeligt. Så den lovede plads ikke forveksles, er det en lille flid, der pænt holder én linje tal på plads."},"ICON-2040":{"nm":"Displaystativ til turfoldere","de":"Sæt turfoldere frem, og en rejsendes hånd standser af sig selv. I hvert ark, man tager op ét ad gangen, ligger landskabet af veje endnu ikke rejst stille foldet sammen."},"ICON-2041":{"nm":"Stempelunderlag til vejkort","de":"Til de første skridt ind i indgangen holder den stempelæsken oven på kortet stabilt. Når blækket ikke tuder ud, forvirrer vejen heller ikke. Et sted der tavst bærer vægten, så en lille vejviser står oprejst."},"ICON-2042":{"nm":"Opbevaringsmærke til paraply","de":"En eftermiddag hvor regndråber duppede fra tagskægget, hænges ét nummer på hver paraply. Når den, der er vendt tilbage efter regnen, kommer for at hente sin egen, kalder mærket tydeligt det våde minde frem."},"ICON-2043":{"nm":"Klokkeholder til infodisk","de":"Ring den én gang, ding, og nogen kommer strålende løbende fra den anden side. Den lille klokke hængt i diskens hjørne er den venligste tolk, der bærer selv de ord videre, man ikke helt fik sagt."},"ICON-2044":{"nm":"Shampoo-dispensertud","de":"Åbn håndfladen og tryk let, og skummet blomstrer frem med et pift. Det ene tryk, mens duften spreder sig i hele badeværelset. Klokken, der vækker en søvnig morgen mildest, begynder lige her."},"ICON-2045":{"nm":"Afløbsbakke til sæbeholder","de":"En bakke, der stille lader vandet, samlet under sæben, løbe væk. Så den ikke bliver blød, ikke bliver mør. En lille, øm omtanke for at holde det, der slides lidt væk hver dag, en håndsbredde længere ved ens side."},"ICON-2046":{"nm":"Skefuld til badesalt","de":"Tag en skefuld pulver op og opløs det i varmt vand, og farve og duft breder sig langsomt ud. Mens du rører med håndleddet, bliver badekarret en lille sø, og en dags træthed synker stille i den."},"ICON-2047":{"nm":"Skumnetpose","de":"Fang et stykke sæbe i nettet og gnid det, og blødt skum fylder hele håndfladen. En stille alkymist i et hjørne af badeværelset, der forvandler det grove til det bløde."},"ICON-2048":{"nm":"Steriliseringshætte til tandbørste","de":"Ønsket om, at det, der rører munden, altid er rent. Én lille hætte, der blidt omslutter børstens spidser, tager sig af selv de usynlige steder. Renlighed er skabt af netop sådanne ophobede små ting."},"ICON-2049":{"nm":"Låg til vatpindsbeholder","de":"En beholder hvor hvide pinde ligger pænt på række, og et låg der runder sig hen over toppen. Åbn med et pop, luk med et klik. Et ømt punktum for badeværelsets orden, afsluttet med en lille lyd."},"ICON-2050":{"nm":"Dråbeflaske til badeolie","de":"Vip den let, og duftende olie falder dråbe for dråbe. Glansen og den svage duft, der breder sig i karret. For beskeden til at være luksus, for øm til at være hverdag — én eneste dråbe."},"ICON-2051":{"nm":"Rumdeler til amenity-bakke","de":"Hen over en bakke inddelt i rum finder små flasker hver sit sted. Ting der virker rodede spredt og ordentlige samlet. Én rumdeler holder ordenen i en travl morgen."},"ICON-2052":{"nm":"Timeglasholder til sauna","de":"Det er et ømt løfte om i det mindste at varme ryggen, mens sandet løber helt igennem. Når timeglasset, lænet skråt mod sin holder, tæller tiden dryppende af, hviler mennesket et øjeblik i den tætte damp, uden at være noget som helst."},"ICON-2053":{"nm":"Fåreøre-håndklæde til badstue","de":"Rul håndklædets ender og rejs dem spidse som fåreører, og ansigtet i spejlet blødgøres stille. Midt i den hede damp er det et lille ritual i badstuen, hvor alle et øjeblik vender tilbage til barndommen."},"ICON-2054":{"nm":"Vandøse til sauna","de":"Øs skeen fuld af vand og hæld det over de opvarmede sten — hvæs — og dampen skyder op mod loftet. I det øjeblik synker hele kroppen ned i en varm tåge, og gammel træthed løses langsomt op i sveddråber."},"ICON-2055":{"nm":"Temperaturstav til fodbad","de":"Dyp staven i vandet, og skalaen taler stille til dig. Hverken for varmt eller for koldt, netop den rette temperatur. Før tæerne dyppes i, er det den finger, der først spørger til vandets velbefindende."},"ICON-2056":{"nm":"Tang til badstuesten","de":"En nyopvarmet sten kan man ikke gribe med bare hænder. Når tangen griber fast og løfter, flyttes heden til sikker afstand. Forsigtighed er også en færdighed, siger badstuen stille."},"ICON-2057":{"nm":"Siddemåtte til badstue","de":"Læg én ud på det hede gulv, og stedet, ryggen rører ved, bliver langt blødere. En måtte, der ordløst tager imod en dag gennemvædet af sved. Hvile kommer, trods alt, fra den rette afstand til gulvet."},"ICON-2058":{"nm":"Saltpose til fodbad","de":"Hold en håndfuld groft salt, opløs det i varmt vand, og trætheden smelter væk fra tæerne og opad. Mens den salte damp omslutter læggene, standser en dag gennemvandret helt op til sidst."},"ICON-2059":{"nm":"Duftskål til badstuesten","de":"Drop et par dråber parfume på den opvarmede sten, og den varmede duft breder sig langsomt gennem badstuen. Luk øjnene, og er dette en skov eller en blomstereng? Den korteste rejse, taget gennem næsen."},"ICON-2060":{"nm":"Varmepudebetræk","de":"Et klæde, der omslutter den opvarmede pude tæt for at holde varmen længe. Ligesom et hjerte der krammer den tæt for at den ikke skal blive kold, holder varmen hvilende på maven dig med selskab hele natten."},"ICON-2061":{"nm":"Duftpinde til aromadiffuser","de":"Tynde pinde suger duften op og lader den langsomt drive gennem rummet. En svag duft, der siver ind med hvert åndedrag. Måden, et rum man opholder sig i, langsomt kommer til at ligne den persons duft."},"ICON-2062":{"nm":"Vinkelgreb til liggestol","de":"Drej grebet langsomt, og ryglænet lægger sig blidt tilbage. Lidt mod solen, lidt mod skyggen. At famle sig frem til den mest behagelige vinkel er en beregning helt ens egen."},"ICON-2063":{"nm":"Skridsikker kant til pool","de":"En skridsikker stribe, der løber hele vejen rundt langs vandkanten. Så små fødder, der plasker og løber henrykt afsted, kan standse i sikkerhed, er det en skjult mållinje for tryghed, lagt stille ude af syne."},"ICON-2064":{"nm":"Ventilløkke til badering","de":"En løkke omhyggeligt bundet fast til den lille prop, der holder på luften. Så proppen, når den er trukket ud af badedyret, ikke flyder væk på vandet. En visdom der forebygger et lille sommertab på forhånd."},"ICON-2065":{"nm":"Trinhætte til poolindgang","de":"En hætte der blødt omslutter enden af trappen, der fører ned i vandet. Så bare fodsåler ikke skrabes, polstrer den det første skridt ud i vandet. For enhver begyndelse bør altid være forsigtig."},"ICON-2066":{"nm":"Remløkke til liggestolshynde","de":"En løkke man hægter og binder remmen fast i, så hynden ikke glider af. Et lille løfte om at holde sin plads, selv når vinden blæser. Én knude fastholder eftermiddagens dovenskab lige der."},"ICON-2067":{"nm":"Drikkeholderplade til poolvilla","de":"En plade der lader et drikkeglas passe snugt ind ved poolens kant. Ét sted der ikke lader sig ryste selv af muntre plask. At sætte det kølige inden for rækkevidde strækker en sommereftermiddag langt ud."},"ICON-2068":{"nm":"Ophængsklemme til våd badedragt","de":"Tag den dryppende badedragt op og overlad den stille til vinden. Mens den tørrer i solen, står klemmen tavst og holder fast. En stille, øm ventetid til den næste badetur."},"ICON-2069":{"nm":"Fodvægt til parasolstang","de":"En tung vægt sat ved stangens fod, så parasollen ikke svajer i vinden. At skyggen bliver på ét sted længe, skyldes helt denne tyngde. Pålidelighed gemmer sig ofte det laveste sted."},"ICON-2070":{"nm":"Flydende temperaturchip til pool","de":"En lille chip, der flyder på vandet og stille melder temperaturen. Bliver rød hvis for koldt, blødt hvis netop rigtig. En sød lille spåkone, der aflæser vandets humør med én farve."},"ICON-2071":{"nm":"Kvast til teltlynlås","de":"Giv et lille ryk i kvasten hængt for enden af lynlåsen, og teltdøren glider stille op. Et greb der findes med det samme, selv når fingrene famler i mørket. Det leder dybe nattes komme og gå med omsorg."},"ICON-2072":{"nm":"Sommerfuglenål til teltsnor","de":"En nål der bider snoren fast i sommerfugleform. Stoffet der flagrede i vinden bliver endelig roligt. En campingnat vogtes stille af netop sådanne små, dygtige knuder."},"ICON-2073":{"nm":"Luftventil til glampingmåtte","de":"Sæt munden til og pust, pust, og måtten svulmer langsomt op. Fyld den helt og luk ventilen tæt, gulvet bliver polstret, og et sted at lægge kroppen under stjernehimlen er endelig fuldendt."},"ICON-2074":{"nm":"Loftskrog til telt","de":"En krog hængt fra teltets loft til at hænge lanterne eller lommetørklæde på. Husholdningens visdom, der sparsommeligt bruger selv det lille rum over hovedet. Det er som at hænge én stjerne op i loftet i stedet for himlen."},"ICON-2075":{"nm":"Rullebånd til sovepose","de":"Et bånd viklet og spændt fast, så den oprullede sovepose ikke går op. Et leje der bliver lille igen om morgenen. At gøre klar til at rejse er at folde gårsdagens varme pænt sammen."},"ICON-2076":{"nm":"Skostativplade til teltindgang","de":"En plade lagt ved teltets indgang til at holde skoene pænt på plads. Jord udenfor, rent indenfor. Med én tærskel deler den ømt inde fra ude — en lille høflighed ved camping."},"ICON-2077":{"nm":"Ophængskrog til glampinglanterne","de":"En bøjet krog til at hænge lanternen på. Hæng den her, og lyset breder sig rundt inde i teltdugen. Stedet hvor man hænger ét skær op i mørket, bliver vores stue i aften."},"ICON-2078":{"nm":"Rulleklemme til teltventilation","de":"En klemme der ruller ventilationsvinduet sammen og holder det fast. Åbn en smule for luftvejen, og luften inde i teltet bliver langt friskere. Én lille sprække skaber stille plads til at ånde hele natten."},"ICON-2079":{"nm":"Bundmåtte til telt","de":"En måtte lagt på teltets bund for at holde jord og fugt ude. Ét lag der breder et tørt leje ud selv over græsset. Så man forbliver i naturen uden at blive gennemblødt af den, lægger den stille en hjælpende hånd ved siden."},"ICON-2080":{"nm":"Låsering til vægtstang","de":"En ring spændt fast i hver ende af vægtstangen, så skiverne ikke glider af. En lille lås der fuldt ud stoler på løfterens vægt. Kun når trygheden holder fast, fornys grænsen endelig med ét hak."},"ICON-2081":{"nm":"Grebshætte til kettlebell","de":"I det sidste sæt, hvor jernet gnavede i håndfladen, forsvinder smerten med denne ene lille hætte. At holde fast til det sidste er sværere end at løfte vægten — det ved hånden først, i selve afslutningsøjeblikket."},"ICON-2082":{"nm":"Indsatskile til vægtskive","de":"Vakler skiven blot en anelse, styrter formen sammen, endnu før løftet begynder. En kile, drevet tyndt ind i sprækken, holder centrum uden en lyd. Fasthed begynder altid stille de usynlige steder."},"ICON-2083":{"nm":"Låseklemme til vægtstang","de":"Fingerspidserne der spænder låsen fast, må ikke tøve. Den ene lille klikkende låselyd bærer hele den næste bevægelse. Kroppen lærer først at sætte sin tillid til én klemme."},"ICON-2084":{"nm":"Farvechip til vægtskive","de":"En chip farvet forskelligt efter vægt — hånden genkender den først, selv uden at kunne læse tallet. Rød er tung, blå er let; at huske vægten på farve. Kroppen vurderer, overraskende nok, sin styrke gennem øjnene."},"ICON-2085":{"nm":"Gulvbeskytter til kettlebell","de":"Takket være underlaget, der udvider fladen mod gulvet, får parketten ingen buler. Træningens spor bør kun findes i sved og muskler. Et lille hjerte, der ikke vil efterlade sår helt ned til gulvet, ligger her."},"ICON-2086":{"nm":"Centermarkering på vægtstang","de":"Mærket ridset midt på stangen er referencepunktet for balance mellem venstre og højre. En hånd der griber præcist i midten halverer vaklen. I det øjeblik man ved, hvor centrum er, kan man endelig løfte trygt."},"ICON-2087":{"nm":"Opbevaringsstativ til vægtskiver","de":"Brugte skiver tilbage til deres plads. Synet af dem hængt pænt op efter vægt på stativet er en stille omtanke for den næste. En ordentlig plads er den mest pålidelige sikkerhedsforanstaltning, tror nogen."},"ICON-2088":{"nm":"Stopkant mod rullende vægtskiver","de":"Ulykken hvor en skive på gulvet triller af sted og rammer vristen, sker altid i ét uopmærksomt øjeblik. Stopkanten blokerer stille netop det øjeblik. Store ulykker kommer ikke fra store steder — de triller frem fra en lille sprække."},"ICON-2089":{"nm":"Ryglænshynde til bænk","de":"Er hynden, der støtter ryggen, for hård, bliver selv vejrtrækningen overfladisk. Den grænse mellem passende fast og passende blødt er et balancepunkt, kun den, der har siddet længe, kan finde frem med fingerspidserne."},"ICON-2090":{"nm":"Højdejusteringsstift til rack","de":"Med blot én stift, der bestemmer højden, passer stangen til enhvers skuldre. Mennesker af forskellig højde, der venligt deler samme redskab — ét lille justeringshul skaber netop den ømme ligestilling."},"ICON-2091":{"nm":"Trisseafdækning til træningsmaskine","de":"Inde i afdækningen omkring trissen drejer kablet rundt og rundt uden en lyd. En del der gemmer friktionen indeni og kun giver hånden det glatte. En god indretning afslører aldrig til sidst den slid, den selv har ydet."},"ICON-2092":{"nm":"Skridsikre fødder til bænk","de":"Skridsikre fødder monteret på alle fire benender holder bænken fast til gulvet. Kun når den ikke vakler, kan man lægge al sin kraft i med sindsro. Stabilitet begynder, trods alt, fra en lille friktion ved foden."},"ICON-2093":{"nm":"Opbevaringskrog til vægtstang på rack","de":"Krogen, hvor stangen hviler, må altid være i en højde inden for rækkevidde. Stedet hvor en træt arm til sidst stille lægger stangen fra sig — den håndsbred position lukker trygt dagens træning."},"ICON-2094":{"nm":"Vægtstiftgreb til træningsmaskine","de":"Grebet, man stikker stiften i for at vælge vægt, skal være glat, så neglene ikke lider skade. Selv i det korte øjeblik, man skifter vægt, mærker man en finish, der stille har taget hensyn til fingerspidserne."},"ICON-2095":{"nm":"Vinkellåsegreb til bænk","de":"Er grebet, der låser ryglænets vinkel, løst, falder formen umærkeligt sammen. Vissheden i det øjeblik, det fikseres med et klik. Hver morgen, når døren åbnes, tjekker driftslederen stille netop denne lyd først."},"ICON-2096":{"nm":"Sikkerhedsbjælke til rack","de":"I det værste øjeblik, hvor stangen forlader hænderne, tager sikkerhedsbjælken imod den vægt i stedet. Med en støtte, usynlig, altid ventende nedenunder, kan mennesket endelig presse helt til sin grænse."},"ICON-2097":{"nm":"Endehætte til maskinkabel","de":"Den lille hætte, der samler kablets ende, er den sidste knude mod udridsning. At binde trådene pænt sammen, så de ikke spredes — en finish' værdighed hviler altid i netop det upåagtede endepunkt."},"ICON-2098":{"nm":"Kridtpose","de":"En håndfuld hvidt pulver gnedet på hænderne for at udviske glidning. Usynlig som sminke bag scenen, men alligevel begynder stabiliteten i alle dagens bevægelser først i denne ene håndfuld. Forberedelse starter altid ved fingerspidserne."},"ICON-2099":{"nm":"Håndtrykstræner","de":"En lille klemme, der tavst gentager at gribe og slippe, opbygger håndens styrke. Gribestyrke vokser langsommere end de store muskler, så dette er også en øvelse i stille at lægge utålmodigheden fra sig."},"ICON-2100":{"nm":"Fingerspredebånd","de":"Et bånd sat mellem fingrene, der langsomt spredes udad. En hånd, der kun har brugt gribemusklerne, genvinder sin spredestyrke. Ligeså meget som det at gribe fast, kræver det at slippe stille også øvelse, siger hånden."},"ICON-2101":{"nm":"Kridtpulver-låg","de":"Er låget til pulverrøret bare en anelse løst, bliver hele tasken kridhvid indeni. Ét lille låg, der slutter helt tæt, forhindrer det lille uheld, før det sker. Det er altid proppen, der afgør, om det lykkes at holde styr på tingene."},"ICON-2102":{"nm":"Knæstøttebind","de":"Et bind viklet om knæet til støtte skal stoppe ved netop det rette tryk. Strammes det for meget, stoppes blodet, er det for løst, gør det ingen nytte, så en erfaren hånd afmåler stille den fine mellemting ud fra hukommelsen."},"ICON-2103":{"nm":"Elastisk modstandssnor","de":"Den elastiske snor, der strækkes og snapper tilbage, vækker sovende muskler uden en eneste vægtlod. Modstand behøver ikke være tung. Selv over for et blidt træk svarer kroppen altid ærligt."},"ICON-2104":{"nm":"Ankelvægtpose","de":"En sandpose spændt om anklen trækker hvert skridt tungt nedad. Læg lidt vægt til, og selv en almindelig gåtur bliver en rigtig træning. Det er en lille klogskab, der lister en smule anstrengelse ind i hverdagen."},"ICON-2105":{"nm":"Håndledsrulle","de":"En rulle, man langsomt vikler op for at løfte en vægt hængt på en snor. Håndleddet er det mindste og mest glemte led, og dette enkle redskab genopliver stille den glemte styrke."},"ICON-2106":{"nm":"Gribestyrkebold","de":"En gummibold, man knuger og slipper i hånden, holder træningen stille i gang selv ved skrivebordet. Styrke opbygget i ledige stunder holder længere end styrke hældt ud på én gang. Vedholdenhed vokser altid ud af den slags små ting."},"ICON-2107":{"nm":"Pulsbælte-spænde","de":"Er spændet på brystremmen blot en anelse skævt, springer tallene. Selv det at lytte til sit eget hjerte begynder med en fast lukning. Enhver måling starter i sidste ende med et tæt, sømløst greb."},"ICON-2108":{"nm":"Pulsklemme","de":"En klemme, der nænsomt bider om fingerspidsen, tæller stille pulsen. Sæt den på, find vejret, og hjertets rytme stiger tydeligt frem på en lille skærm. Kroppen fortæller altid sandheden om sin tilstand."},"ICON-2109":{"nm":"Etui til pulsurbånd","de":"Etuiet, der gemmer pulsuret, er lille, men kender sin egen familie. Jo lettere en lille enhed er at miste, jo mere har den brug for et hjem at vende hjem til. At passe godt på tingene er også en form for omsorg."},"ICON-2110":{"nm":"Tempoflagnål","de":"En lille flagnål, der markerer løberens mål. Ét punkt, sat på forhånd — \"kun hertil\" — bærer trætte fødder hele vejen i mål. Målstregen i hjertet er altid en, man selv planter."},"ICON-2111":{"nm":"Hjerteslag-lyshætte","de":"Et lille lys, der blinker stille i takt med hjerteslaget. Betragter man rytmen, mens det tændes og slukkes, fyldes hjertet på ny af, hvor rørende regelmæssigt det er at være i live."},"ICON-2112":{"nm":"Omgangstæller-perlesnor","de":"Man tæller sine gentagelser med perler, der skubbes over én ad gangen. Man behøver ikke huske tallet i hovedet — fingrene husker det for en. Overlader man tællingen til hænderne, kan sindet hvile fuldt og helt i bevægelsen."},"ICON-2113":{"nm":"Iltmætnings-klemmepude","de":"En klemmepude sat på fingerspidsen aflæser stille mængden af ilt i blodet. Når den usynlige dybde i vejrtrækningen stiger frem som et tal, indser man på ny, at at passe på kroppen i bund og grund handler om at se nøje efter."},"ICON-2114":{"nm":"Pulszone-farvebånd","de":"Et bånd, der inddeler træningsintensitet efter farve, fortæller med ét blik, hvor hårdt man arbejder lige nu. Blå er let, rød er grænsen. Farven bliver selv et venligt sprog — et stille løfte."},"ICON-2115":{"nm":"Målekapsel","de":"En lille geléagtig kapsel, der måler kroppens tilstand, rummer en hel dags information i én lille kugle. Uanset hvad der ligger inde i den klare skal, ligger ønsket om at kende sig selv lidt bedre gemt der også."},"ICON-2116":{"nm":"Håndklædekrog","de":"Den lille vane altid at hænge det på sin egen krog i stedet for bare at kaste det et sted skaber orden i hele rummet. Ligesom denne krog, der på forhånd sætter et sted af til håndklædet at vende tilbage til, skinner ryddelighed altid i de små ting."},"ICON-2117":{"nm":"Drikkedunkslåg-snor","de":"Den korte snor på drikkedunkens låg forhindrer uheldet, at låget triller væk. Klogskaben i at binde det, der let mistes, fast til kroppen — én lille snor tager stille en dags besvær med sig."},"ICON-2118":{"nm":"Foldevifteblad","de":"Et viftevinge, der rejser en brise, når den foldes helt ud. Ligesom de gamle vifter, der kølede sveden på varme dage, giver det enkleste redskab den mest svalende trøst. Et vindpust blomstrer altid frem fra fingerspidserne."},"ICON-2119":{"nm":"Kølehåndklædepose","de":"En lille pose, der rummer et håndklæde, som bliver koldt, når det fugtes. Ét stykke stof, der køler varmen, sover pænt der, indtil det lægger sig let ned om en træt nakke og stille fører middagens hede bort."},"ICON-2120":{"nm":"Drypskål","de":"En skål sat frem på forhånd for at fange stedet, hvor de samlede vanddråber vil falde. At skabe et sted til det, der drypper, i stedet for at bebrejde det for at løbe ned. Køkkenets venlighed lever altid videre sådan, uden en lyd."},"ICON-2121":{"nm":"Ventilatorretningsblad","de":"I det øjeblik en vind, der strømmede lige forfra, drejer let til siden langs et lille blad, får den lummervarme luft i øvelokalet endelig luft. At ændre strømmen har altid handlet om sådan en lille vinkel."},"ICON-2122":{"nm":"Pandebånd","de":"Bliver panden våd, når man vasker ansigt, går hele dagen af lave. Dette bånd, der løfter håret let op fra panden, giver personen foran spejlet fem tørre minutter. Man lægger først mærke til det, når det er væk."},"ICON-2123":{"nm":"Drikkekrusholder med klemme","de":"Når et krus vakler farligt på kanten af skrivebordet, holder denne klemme stille fast i den ene side. En dag, der gik uden at spilde, minder en enkelt slurk vand en om, skyldes nogen, der holdt kanten i ens sted."},"ICON-2124":{"nm":"Vinduesgreb til udluftning","de":"Et helt lukket vindue er indelukket, et vidt åbent er koldt. Dette grebshåndtag husker netop den rette sprække midt imellem. Udluftning er i sidste ende hjertets sag — at lade tingene stå tilpas åbne."},"ICON-2125":{"nm":"Korkhjørnebeskytter til blok","de":"Det er altid det skarpe hjørne, der gør ondt, når man støder mod det. Derfor skærer man et stykke kork til og sætter det på hvert hjørne. Et sted, der er svøbt blødt ind, gør nu ingens knæ ondt mere."},"ICON-2126":{"nm":"Bærestrop til bolster","de":"At flytte en lang pude er mere besværligt, end man skulle tro. Sæt én strop på, og den ligger lige i hånden. Kunsten at løfte noget tungt let afhænger af, hvor man sætter håndtaget."},"ICON-2127":{"nm":"Bæltespænde","de":"Der er dage, hvor man strammer taljen et hak mere, og dage, hvor man løsner et hak. Det, der ærligst kender dagens form, er dette lille spænde. Et stykke metal, der tavst noterer kroppens oprigtighed."},"ICON-2128":{"nm":"Kvartblok-støtte","de":"En blok skåret i fire dele holder gulvet fast oppe. Hverken for højt eller for lavt — netop den balance. Den viser tavst, at at støtte er at sænke sig selv for at løfte det, der er ovenpå."},"ICON-2129":{"nm":"Betræk til ægformet bolster","de":"Man klæder en æg-rund pude i en perfekt tilpasset dragt. Bliver den svedig, tager man den bare af og vasker den. Husholdningen ved, at jo mere noget rører huden hver dag, jo mere har det brug for et rent lag at skifte til."},"ICON-2130":{"nm":"Nivelleringskile til blokke","de":"Hælder gulvet blot en smule, vakler alt det, man møjsommeligt har stablet. Skub én tynd kile ind i sprækken, og verden genvinder sin vandrette linje. At rette op på noget kræver ingen store armbevægelser."},"ICON-2131":{"nm":"Stopknude til stropende","de":"Man binder en fast stopknude, så remmens ende ikke trevler op og hænger løs. En snor med pænt afsluttet ende holder længe. Én lille knude lærer, at det er sværere at afslutte end at begynde."},"ICON-2132":{"nm":"Sammenfoldelig knæpude","de":"Den skarpe smerte hver gang knæet møder et hårdt gulv. Én pude, der foldes ud og sammen, glider blidt ind mellem knæ og gulv. Det er en ømhed, der støtter en andens knæ i dets sted."},"ICON-2133":{"nm":"Skridsikker bundplade til blok","de":"Selv den mest solide blok er ubrugelig, hvis den glider. De fine riller skåret i bundpladen bider fast i gulvet. Hemmeligheden bag det, der står helt fast, gemmer sig altid på undersiden, hvor man ikke kan se den."},"ICON-2134":{"nm":"Klemme til rette stænger","de":"Man retter stængerne lige op og klemmer dem fast med en klemme. Den, der er vant til at rette ting op, kender den — den mærkelige lille tilfredshed, der vælder frem af at lægge det skæve pænt på linje."},"ICON-2135":{"nm":"Strop til baglår","de":"Når bagsiden af låret strammer, så et hyl slipper ud, rækker denne løkke ud efter tåspidserne, hånden ikke kan nå. Hvor man ikke kunne nå alene, bygger én enkelt snor en bro for benet."},"ICON-2136":{"nm":"Tåspredepude","de":"Selv tæer, der har været spærret inde i sko hele dagen, har brug for et pusterum. På en pude, der spreder dem fra hinanden, strækker foden sig for en gangs skyld. En aften, der løsner op, begyndende fra det fjerneste sted."},"ICON-2137":{"nm":"Vinkelmåler til holdning","de":"Med øjet alene kan man umuligt vurdere, hvor mange grader ens holdning er skæv. Når måleren stille fortæller vinklen, retter kroppen sig endelig op. En skala, der viser den hældning, man ikke selv kunne se."},"ICON-2138":{"nm":"Bækkenrettende kile","de":"En sløv eftermiddag, hvor bækkenet er stivnet skævt til den ene side. Man støtter en enkelt kile og finder langsomt centrum igen. Det handler ikke om at tvinge noget lige, men om at hjælpe det med at finde sin rette plads igen."},"ICON-2139":{"nm":"Skulderåbnende bæltespænde","de":"Et bånd, der stille retter sammensunkne skuldre ud. Strammes spændet, åbner en rundet ryg sig langsomt. Trækker man vejret dybt med skuldrene bredt slået ud, kommer først da den rette buk-holdning frem."},"ICON-2140":{"nm":"Rygstøttekile","de":"Lægger man sig ned på ryggen, tegner rygsøjlen sin naturlige kurve. En kile, der stille støtter den bue uden at gå imod den. Kunsten at hvile godt begynder med at anerkende den kurve, kroppen er født med."},"ICON-2141":{"nm":"Vristudstrækningskile","de":"At strække vristen manglede altid lidt af noget. Støtter man den rette kile, strækkes man frisk helt ned i den dybde, man ellers ikke kunne nå. En lille skråning, der hjælper en med at nå en smule længere."},"ICON-2142":{"nm":"Håndledsstøtte","de":"Når et håndled bøjet ved tastaturet begynder at prikke, glider støtten stille ind under det. De første til at passe på hænder, der arbejder længe, er ydmyge, lavtliggende ting som denne."},"ICON-2143":{"nm":"Håndledsbandage","de":"Før man løfter noget tungt, vikler man en bandage én gang om håndleddet. En tryghed, der vokser for hver omgang. Vanen med at binde om, før man kommer til skade, er den stille hemmelighed hos dem, der træner år efter år."},"ICON-2144":{"nm":"Armbånd-telefonlomme","de":"Hvor man skulle have telefonen under løbeturen, var altid en bekymring. Denne lomme spændt om underarmen tager den bekymring fra en. Løber man med en yndlingssang spændt fast til armen, føles vejen et godt stykke kortere."},"ICON-2145":{"nm":"Fjederhætte til håndtræner","de":"En hætte sat over enden af håndtrænerens fjeder, så den ikke stikker i håndfladen. Gennem alt det knugende og slippende holder denne lille prop freden mellem hånd og metal. En hensyn taget et sted, ingen ser."},"ICON-2146":{"nm":"Fingerbøl til handske","de":"Bedstemors sytrænede fingre havde altid et fingerbøl. Dette fingerbøl sat på enden af handsken beskytter fingerspidsen. Ønsket om at skåne hænder, der har arbejdet længe, er påfaldende ens, selv på tværs af generationer."},"ICON-2147":{"nm":"Pude til hård hud i håndfladen","de":"Den hårde hud på håndfladen er de fingeraftryk, anstrengelsen har efterladt. En pude lagt oven på den gør den næste gentagelse mulig. Ved at svøbe det hærdede sted ind igen, holder man endnu en gang fast."},"ICON-2148":{"nm":"Skridsikker tape til håndfladen","de":"Bliver håndfladen ved med at glide, mister man det, man kæmpede for at holde fast i. Vikler man den ru tape om, bliver hånd og redskab ét. Kraften til ikke at miste grebet kommer, overraskende nok, fra friktion."},"ICON-2149":{"nm":"Svedbånd til underarm","de":"Før sveden, der løb ned under træningen, når håndleddet, opsuger dette bånd på underarmen den først. At sveden intet er at skamme sig over, vidner en gennemblødt klud tavst om."},"ICON-2150":{"nm":"Tørrestativ til handsker","de":"Kastes de tilfældigt fra sig, bliver næste morgen en plage, men hænges de pænt op, tørrer brisen dem selv sarte og bløde natten over. Duften af nyvaskede, tørre handsker åbner morgendagen frisk og ny."},"ICON-2151":{"nm":"Lynlåstrækker til sportstøj","de":"Med drivvåde hænder kan man slet ikke få fat i en lillebitte lynlås. Sæt ét trækstykke på, og det går i ét ryk. En ubetydelig lille ring redder et helt hektisk minut."},"ICON-2152":{"nm":"Svedåndende ventilationslap","de":"Man sætter en ventilationslap på kroppens varmeste sted. Den indespærrede varme siver stille ud gennem lappen. Handlingen med at åbne ét lille åndehul lige midt i det kvælende."},"ICON-2153":{"nm":"Indlægssålslap","de":"Man skærer kun den slidte del ud af en gammel indlægssål og sætter et nyt stykke i. En hånd, der ikke smider det hele væk, men blot udskifter det, der gør ondt. En lille reparation under foden gør hele dagens gang lettere."},"ICON-2154":{"nm":"Strygemærke med nummer til sportstøj","de":"Man presser et rygnummer ind i tøjet med et strygejern. Mens varmen kølner, sætter tallet sig fast på stoffet. Startens stempel, som gør dem, der bærer samme nummer, til ét hold."},"ICON-2155":{"nm":"Forstærkningshætte til skotå","de":"En forstærkningshætte på tåen holder stille skæbnen stangen for den sko, hvis spids bliver ved med at støde mod ting. Det sted, der slides først, gøres mest solidt. Jo længere en sko skal holde, jo hårdere er den lige fra tåspidsen."},"ICON-2156":{"nm":"Snørebåndsknude til sportstøj","de":"I det øjeblik man trækker sportstøjets snørebånd om taljen til og binder det, slutter det løstsiddende tøj sig tæt om kroppen. Denne faste knude, der ikke går op, holder alting på plads gennem selv de vildeste bevægelser."},"ICON-2157":{"nm":"Skridsikkert bånd til ankelsokker","de":"Det besvær, når ankelsokken bliver ved med at rulle ned i skoen. Ét bånd holder den glidning fast. En sok, så lille man knap lagde mærke til den, holder endelig sin plads."},"ICON-2158":{"nm":"Svedpude til armhule i sportstøj","de":"En pude sat på forhånd, hvor sveden vælder mest frem. Bliver den gennemblødt, ses ikke et spor på tøjets yderside. De ting, der slider tavst i det skjulte, holder scenen ren og pæn."},"ICON-2159":{"nm":"Hælløkke til sko","de":"Har man taget skoen på, giver et lille træk i hælløkken foden lige ind på plads. Den korte bekvemmelighed, der sparer en for at skulle sidde på hug. På en travl morgen gør sådan en løkke stor nytte."},"ICON-2160":{"nm":"Hoved til massagepistol","de":"Man skifter hovedet ud alt efter, hvor man banker. Hver stram muskel har sin egen rette form. En aften, der vælger netop den rette trøstende styrke til skuldre, der har holdt dagen ud."},"ICON-2161":{"nm":"Opladerstation til massagepistol","de":"Selv den hånd, der skal løsne kroppen op hele dagen, vågner først, når den er ladet op. Mens det røde lys skifter til grønt, må man gerne hvile lidt. Når blinket stopper, kommer turen stille tilbage til igen at kæle for stive skuldre."},"ICON-2162":{"nm":"Styrkeskive til massagepistol","de":"Svagt, lidt mere, dertil. Mens man drejer skiven, forhandler fingerspidserne stille med sin egen krop. Dagens løfte — kun at blive så fast, som det gør ondt — står tydeligt skrevet mellem de små streger."},"ICON-2163":{"nm":"Holderring til vibrationsbold","de":"Selv en bold, der ruller godt, har brug for et sted at standse et øjeblik. Denne runde holder favner stille det hjerte, der vil trille afsted, og holder pladsen, til næste tur kommer. Hvile er også en del af træningen."},"ICON-2164":{"nm":"Håndtagshætte til akupressurstav","de":"Med blot én lille hætte sat på enden forsvinder smerten i håndfladen langsomt. Mellem hårdhed og hud er der altid brug for ét blødt lag. En ømhjertet håndsbredde, der først runder det sted af, som møder huden."},"ICON-2165":{"nm":"Pose til jordnøddeformet rulle","de":"En lille pose, der rummer en jordnøddeformet rulle. Triller den frem fra et hjørne af tasken, følger gårsdagens beslutning om endelig at passe lidt på kroppen med. En lille pose husker løftet."},"ICON-2166":{"nm":"Standerholder til fodrulle","de":"Vakler stedet, man betror sine fødder til, vakler afspændingen med. Denne stander, der holder rullen oppe, griber fast om gulvet og skaber et sted, hvor to trætte fødder kan læne sig trygt til. Tryghed kommer af det, der ikke vakler."},"ICON-2167":{"nm":"Prop til rullekerne","de":"En lille prop, der lukker en tom kerne. Det usynlige indre skal være fyldt, for at det ydre ikke falder fra hinanden. Det sted, ingen nogensinde ser, mens den ruller, holder denne stille del tavst oppe."},"ICON-2168":{"nm":"Endehætte til massagestav","de":"En hætte rundet af over enden af staven. Så den ikke slides, ikke ridses — at værne om spidsen er i sidste ende vejen til at have den ved sin side længe. Ønsket om at svøbe det sted, der først tager stødet, ind på den blødeste måde."},"ICON-2169":{"nm":"Tapeafskærer til rulle","de":"Trækker man til med én hånd, skæres tapen rent af. Der er også et lille kneb i at binde af og afslutte, og dette blad kender fornemmelsen af en pæn afslutning. En ren afslutning gør det næste lettere."},"ICON-2170":{"nm":"Klæbehætte til tapeende","de":"En hætte, der stille presser enden ned, så den ikke går op. Alle kan begynde, men at blive siddende fast helt til enden er altid svært. Denne lille hånd, der holder fast i det sidste stykke, tager stille ansvar for dagens afslutning."},"ICON-2171":{"nm":"Kompressionsærme til håndled","de":"Vikler man et lag om et overanstrengt håndled, kommer smerten et takt for sent. Ligesom en hånd, der stille holder ens egen, bliver kompression somme tider den kærligste beskyttelse. Det strammer ikke til — det holder oppe."},"ICON-2172":{"nm":"Spænde til ankelbandage","de":"Det korte klik, når spændet lukkes, beroliger sindet. Svøbes anklen fast ind, vokser der stille et mod frem, der siger, det nok er fint at tage et skridt mere. Én lille lyd bliver en solid begyndelse."},"ICON-2173":{"nm":"Spænde til knækompressionsrem","de":"Knæet bliver mere stabilt, jo mere man strammer remmen til. Må ikke gå op, men må heller ikke gøre ondt — et sted midt imellem findes netop det rette hak. Spændet glemmer aldrig det sted, hver gang."},"ICON-2174":{"nm":"Fingertapesaks","de":"En lille saks, der præcist klipper tapen viklet om et fingerled. Afrundet i spidsen, så den ikke sårer huden. Jo mere et redskab er tiltænkt omsorg, jo mere ømt slibes dets blad — det viser denne saks stille."},"ICON-2175":{"nm":"Oprullersnelle til kompressionsbind","de":"En snelle, der pænt ruller et løst kompressionsbind sammen igen. En hånd, der omhyggeligt ruller det brugte sammen, vil heller ikke have det viklet forkert næste gang. I hvert pænt viklet lag hviler dagens ryddelighed."},"ICON-2176":{"nm":"Rem til skinnebensbeskytter","de":"En rem, der binder puden fast, som beskytter forsiden af skinnebenet. Sindet, der først tjekker det sted, der nok bliver ramt, er i sig selv forberedelse. Går man ind på banen med benene bundet fast, mindskes frygten i hjertet med det halve."},"ICON-2177":{"nm":"Klemme til albuebandage","de":"En lille klemme, der bider fast, så bandagen ikke glider ned. Så ubetydelig som at tage fat i et stykke papir, men går den op, bliver alting løst. Én lille fastgørelse holder en hel dags tryghed fast."},"ICON-2178":{"nm":"Strækkeløkkegreb","de":"Griber man løkken og strækker kroppen lang, ser man fingerspidser, der når en håndsbredde længere end i går. Det er ikke kun musklerne, der strækkes, jo mere man trækker. Også et forhærdet sind udfolder sig lidt undervejs."},"ICON-2179":{"nm":"Tåspredeafstandsstykke","de":"Spredes tæerne, der har været spærret inde i sko hele dagen, fra hinanden, kommer der luft ind i det trange sted. Der findes ting i denne verden, som først bliver behagelige, når de har været adskilt en stund. Selv tåspidser har brug for plads til at trække vejret."},"ICON-2180":{"nm":"Kileplade til afspænding af læg","de":"Sættes den kileformet ind under læggene, løsnes benene stille op. Én skrå vinkel lader tavst en dags vægt sive bort. At læne sig let tilbage og ligge ned — det er somme tider den mest behagelige stilling af alle."},"ICON-2181":{"nm":"Nakkeafspændingsstøtte","de":"Man lægger nakken på og lukker øjnene et øjeblik. At det er i orden at lægge det tunge hoved fra sig et øjeblik, hvisker denne lille støtte sagte til skuldrene fra sit vante sted. Selv det at læne sig ind kræver mod."},"ICON-2182":{"nm":"Endehætte til strækkestang","de":"Én hætte, der dækker enden af en lang, udstrakt stang. Er spidsen blød, kan man trygt lade den røre ved hvad som helst. At runde hjørnerne af først, uanset hvem man rækker ud mod — sådan begynder omtanke altid, uden en lyd."},"ICON-2183":{"nm":"Akupressurpude med knopper","de":"Lægger man kroppen på de bulede knopper, siver dagen ud af hvert sted, der trykkes ind. I den grænseflade mellem smerte og lise, giver skuldre, der har været stive hele dagen, langsomt efter, som overgav de sig."},"ICON-2184":{"nm":"Afspændingstimeglas til vejrtrækning","de":"Et stille løfte om at trække vejret langt og roligt, indtil sandet er faldet til sidste korn. Den tynde sandstrøm tæller stille rytmen i ind- og udånding. Selv et travlt sind falder i ro et øjeblik undervejs."},"ICON-2185":{"nm":"Fodsåle-akupressurboldholder","de":"Man sætter en bold midt under fodsålen og trykker jævnt ned. Til fødder, der har båret hele kroppen oppe hele dagen, giver den lille holder stille sin plads, som sagde den, det er deres tur til at blive båret nu. Selv det, der bærer oppe, har tider, hvor det skal hvile."},"ICON-2186":{"nm":"Skulderafspændingssnor","de":"En løkkesnor, man hager over skulderen og trækker i. Strækker man snoren mod et stift sted, løsner det knudrede led sig et hak ad gangen. Det viser, at selv det at blive fri har brug for noget at holde i hånden."},"ICON-2187":{"nm":"Baneline-skive","de":"Ét rundt led af banelinen, der deler vandet op. En venlig grænse trukket over vandet, så man ikke støder ind i svømmeren ved siden af. Små skillevægge, der vogter hver enkelts bane, fører alle side om side hele vejen i mål."},"ICON-2188":{"nm":"Spændekrog til baneline","de":"En krog, der trækker banelinen stram og holder den. For løs, og den bøjer i bølgerne, for stram, og den knækker. At finde den rette spænding minder om at samle sig selv — man famler altid et sted midt imellem."},"ICON-2189":{"nm":"Farvehætte til baneline","de":"En lille hætte malet i en anden farve for hver bane. Et mærke malet på, så man kan genkende sin egen bane med ét blik, selv på afstand. At forhindre nogen i at fare vild med bare én farve — vejledning begynder grundlæggende med sådan en lille venlighed."},"ICON-2190":{"nm":"Ophængsbræt til baneline","de":"Et bræt til at hænge banelinerne pænt op, når de ikke bruges. I den hånd, der ordner linerne pænt til næste start, ligger stille et roligt ønske om at afslutte dagen godt."},"ICON-2191":{"nm":"Ruller-håndtag til baneline","de":"Man drejer håndtaget rundt og rundt for at rulle den langt udrullede line ind igen. At samle det, der er spredt, kræver altid tålmodighed. Én omgang, så endnu en — sådan fuldføres en afslutning langsomt, uden hastværk."},"ICON-2192":{"nm":"Knudeklemme til baneende","de":"En klemme, der bider fast, så knuden i enden af linen ikke går op. Den lader ikke engang det mindste stumpe ende glide bort. Der skal være en hånd, der passer på til det sidste, for at en lang line kan holde sin pæne form uden at flosse op."},"ICON-2193":{"nm":"Flydeperle til baneline","de":"Banelinens flydeperle, der bobler oppe på vandet. For ikke at synke har den taget en fuld mundfuld luft ind i sig. At en form for lethed kommer fra et tomrum fyldt med flid, viser det bølgende vand hver gang, den flyder op."},"ICON-2194":{"nm":"Banenummerflag","de":"Et lille flag, der viser banenummeret. Ét stykke stof, der flagrer i vinden, fortæller tydeligt: \"her er din plads.\" Et lille, men umiskendeligt vejskilt, der fører en lige ind på sin egen bane uden at fare vild."},"ICON-2195":{"nm":"Forbindelseskrog til baneline","de":"En krog, der samler den ene baneline med den næste. Med én enkelt krog, der binder en afbrudt vej sammen igen, fuldendes vandvejen endelig. At forbinde er i sidste ende arbejdet for et lille stykke metal, der stille rækker en hånd ud mellem det, der er kommet fra hinanden."},"ICON-2196":{"nm":"Fodplade til startblok","de":"Fodpladen på startlinjen tager hele vægten af det første spring. De 0,1 sekunder, hvor man skubber hårdt fra — den fasthed, tæerne presser mod, sætter hele løbet i gang. Enhver opstigning starter et sted, man kan stå fast."},"ICON-2197":{"nm":"Startgrebsstang","de":"Stangen, hænderne griber fast om, lige før startsignalet. Man må forankre det bankende hjerte et sted, ellers vakler starten. Bare det at have noget at holde fast i gør den næste bevægelse langt klarere og fastere."},"ICON-2198":{"nm":"Rygsvømningsflagline","de":"En flagline, der fortæller den, der svømmer med blikket mod loftet, at væggen nærmer sig. En venlighed, der på forhånd varsler det, man ikke kan se. Med ét signal, der omhyggeligt passer på ens ryg, bliver det sidste tag trygt."},"ICON-2199":{"nm":"Vendemurspude","de":"En blød pude lagt på væggen, hvor man skifter retning. Så det ikke gør ondt, selv når man rammer hårdt, polstrer den vendestedet blødt. På vejen tilbage ligger nogens stille omtanke altid lagt der først."},"ICON-2200":{"nm":"Målplade","de":"I det øjeblik fingerspidserne rører ved den, er alting slut. Slutningen på en lang, forpustet vej kommer i sidste ende an på dette ene lette tryk. At nå i mål er ikke noget stort — det er blot at ramme netop det rette sted, svarer pladen stille."},"ICON-2201":{"nm":"Rutsjebane-startstrimmel","de":"Alle holder vejret et øjeblik, når de står for enden af skråningen. Man overvinder den korte frygt og glider ned, og – plask – latteren bryder ud sammen med vandsprøjtet. En start begynder altid lige på den anden side af en lille smule frygt."},"ICON-2202":{"nm":"Vendemarkeringskegle","de":"Når man tøver ved en vejgren, er det denne lille spids, der taler først. Vend om her, siger den, fortab dig ikke. Nogen ser denne ene farve og finder sin retning igen og går videre."},"ICON-2203":{"nm":"Startblok-vinkelkile","de":"Det halve taktslag, hvor kroppen dukker sig lavest, lige før spranget. Der er en lille fodstøtte, som holder vinklen, så tæerne ikke glider. Ethvert øjeblik af at stige højt fødes af denne hældning."},"ICON-2204":{"nm":"Væghjørne-støddæmper","de":"Så det ikke gør ondt, selv hvis man støder ind i den under leg, har hjørnet givet afkald på sin skarphed og rundet sig af. Ønsket om, at du ikke skal komme til skade, er slebet og slebet og sidder nu fast på væggen. Den kærligste beskyttelse er som regel netop så stille."},"ICON-2205":{"nm":"Redningskrans-krog","de":"Til daglig er det bare et sted, hvor noget hænger. Men i det øjeblik nogen falder i vandet, er det lige her, den første hånd griber ud efter. Der findes en form for pålidelighed i denne verden, som er bedst, når den aldrig bliver brugt."},"ICON-2206":{"nm":"Redningskrogstang","de":"En lang arm, der lukker en uopnåelig afstand i ét træk. Når hånden ikke rækker, bliver denne krog en hånd i stedet. Redning er, i sidste ende, handlingen at række sine fingerspidser ud til nogen langt væk."},"ICON-2207":{"nm":"Poolside-bruserhoved","de":"»Husk at skylle af, inden du går i.« Som livredderens faste replik vælter en vandstråle ned over hovedet. Med ét koldt stænk triller dagens støv lige af."},"ICON-2208":{"nm":"Skridsikker gulvflise","de":"Fint ophøjede riller, så bare fødder ikke glider. Fra et usynligt sted holder de stille fodsålerne fast. Den sikreste sikkerhed gemmer sig altid de steder, der ikke gør væsen af sig."},"ICON-2209":{"nm":"Vanddybdeskilt","de":"Før man sætter foden i, fortæller tallet først dybden. Et sted, der ville skræmme, hvis man trådte ind uvidende, falder til ro i sindet, når man har læst det. Det, dette skilt gør, er at hjælpe med en lille smule forberedelse."},"ICON-2210":{"nm":"Sikkerhedsline med bøjer","de":"Farverige tove, der vipper på vandet og deler zonerne op. Hertil er det sikkert, lover bøjerne, mens de holder hinanden i hånden. Fordi der er en grænse, kan man endelig svømme frit med et roligt sind."},"ICON-2211":{"nm":"Desinfektionskar til fodbad","de":"Et lille kar, hvor bare fødder dvæler et øjeblik, før de går i vandet. Et kort ritual, hvor renheden vokser fra fødderne og opad, opbevares der. Renlighed begynder altid med denne ene omtankes skridt."},"ICON-2212":{"nm":"Advarselskegle for vådt gulv","de":"En enkelt gul kegle sagtner umærkeligt skridtene. »Her er vådt, pas på.« En omtanke rakt frem i farve i stedet for ord. Denne lille advarsel vogter stille over dagen for en, der næsten gled."},"ICON-2213":{"nm":"Førstehjælpsskab til væg","de":"Det hvide skab på væggen åbnes sjældent. Men i det øjeblik det gør, bliver det til nogens lettelse. En nødsituation venter altid stille på det allernærmeste sted."},"ICON-2214":{"nm":"Overflade-skimmernet","de":"Den løfter stille blade og støv, der driver på overfladen. Klarhed kommer ikke af sig selv, så en hånd må skumme det op én gang hver dag. Bag stille vand står et flittigt net."},"ICON-2215":{"nm":"Bundrenser-robotslange","de":"Selv en nat, hvor alle sover, kryber den langsomt af sted og famler sig hen over bunden. Den mest trofaste arbejder i de timer, ingen ser. Morgenens klarhed er det spor, denne slange har tegnet hele natten."},"ICON-2216":{"nm":"Klordoseringsbeholder","de":"Selv det at holde vandet klart har sin helt rette mængde. For meget bliver skarpt, for lidt bliver uklart – balancen imellem. En usynlig hånd stiller stille den skala hver dag."},"ICON-2217":{"nm":"Vandtestflaske","de":"Man samler en mundfuld vand i en lille flaske og spørger til dagens tilstand. For øjet ser det ens ud, men tal lyver ikke. Tryghed er noget, der bekræftes én gang om dagen, netop sådan her."},"ICON-2218":{"nm":"Skumrive til flydebrædder","de":"En lang rive, der samler brædder og flydende affald, som driver på vandet. En hånd, der river det spredte sammen, ligner på en eller anden måde hjertet. Selv rod bliver ordentligt, når det bliver fejet én gang."},"ICON-2219":{"nm":"Afløbsnet","de":"Et fintmasket net, der vogter passagen, hvor vandet løber ud. Det sorterer stille, hvad der skal slippes løs, og hvad der skal holdes tilbage. Selv at give slip på noget kræver et filter, fortæller dette lille net dig tavst."},"ICON-2220":{"nm":"Vandtemperatur-flyder","de":"En lille spejder, der vipper på vandet og aflæser temperaturen. Om det er koldt eller passende, fortæller den venligt, før kroppen rører det. Den første tryghed ved at gå i vandet begynder altid med denne flyder."},"ICON-2221":{"nm":"Poolovertræk-oprulningsstang","de":"Et håndtag, der ruller et bredt overtræk sammen og gemmer det til side. Et redskab, der ved, hvornår man skal brede ud, og hvornår man skal samle sammen, virker på en eller anden måde solidt. I hvileperioder er det, som om man dækker vandet til med en dyne."},"ICON-2222":{"nm":"Skimmerkurv","de":"Kurven, hvor affaldet, der har drevet på overfladen, til sidst samles. Fordi der findes et kar, der tager imod bundfaldet et usynligt sted, er vandet foroven altid klart. Bag renheden hober slidet sig op."},"ICON-2223":{"nm":"Badehætte-tørrestativ","de":"Man hænger en gennemblødt badehætte omvendt op. Mens den drypper dråbe for dråbe, trækker hætten langsomt vejret. At tørre er, i sidste ende, blot et andet navn for at vente."},"ICON-2224":{"nm":"Badedragt-skulderstrop-løkke","de":"En lille løkke, der holder stroppen fast, så den ikke glider ned fra skulderen. Fra et usynligt sted holder den stille styr på udseendet. Sirlighed fuldendes altid oven på så beskedne støtter som denne."},"ICON-2225":{"nm":"Badehætte-opbevaringspose","de":"En pose, hvor våde badehætter finder deres plads én for én. Et lille husly, der samler let-spredte ting i én favn. At rydde op er en øm vane, en måde at prøve ikke at miste noget på."},"ICON-2226":{"nm":"Badedragt-brystpude","de":"En enkelt pude anbragt stille inde i beklædningen. Usynlig udefra retter den alligevel sagte bærerens skuldre op. En vis tryghed fyldes stille ud indefra, ikke udefra."},"ICON-2227":{"nm":"Badehætte-navneskiltklemme","de":"En lille klemme, der fastgør et navneskilt på kanten af en badehætte. Blandt ting, der ligner hinanden, siger den klart: »den her er min«. Ét mærke, og forvekslingerne ophører med det samme."},"ICON-2228":{"nm":"Badedragt-lynlåsløkke","de":"»Kan du hjælpe med lynlåsen på ryggen?« Det sted, man ikke selv kan nå, trækker denne lille løkke op i stedet for en hånd. En øm rækkevidde, der hjælper med det sidste hak."},"ICON-2229":{"nm":"Badehætte-udretterplade","de":"Man retter en badehætte ud, der har vænnet sig til at krølle sammen, og støtter den op. En støtte, der stille hjælper det bulede med at genfinde sin form. Der skal være en hånd til at rette ud, for at noget kan blive fladt og pænt igen."},"ICON-2230":{"nm":"Badedragt-taljesnørelås","de":"En lås, der omslutter taljen passende og holder den, så den ikke glider ned. Hverken for stram eller for løs – lige netop dét mål af rethed. Komfort bor altid et sted derimellem."},"ICON-2231":{"nm":"Badehætte-vendeklemme","de":"En klemme, der griber en vrangvendt badehætte og retter den i ét greb. Fornøjelsen ved at vende det ombyttede rigtigt igen er ganske forfriskende. Den lille glæde ved at rydde op kommer fra netop sådan smådetaljer."},"ICON-2232":{"nm":"Svømmebræt-håndrem","de":"En rem, der vikler sig om hånden, så man ikke mister svømmebrættet. Selv når strømmen skubber til en, er det en stor trøst at have noget at holde fast i. Den spænding fra dagen, man først lærte at sparke, hænger stadig ved i denne rem."},"ICON-2233":{"nm":"Svømmebøje-stramrem","de":"En rem, der holder fast om bøjen, klemt fast mellem de to ben. Først når den ikke går op, kan man endelig koncentrere sig kun om formen. Oven på noget, der holdes godt fast, uddyber dagens træning sig håndsbred for håndsbred."},"ICON-2234":{"nm":"Svømmefinne-vægophæng","de":"Når svømmefinnerne hænger side om side på væggen, ligner de netop en flok ænder, der hviler ved vandkanten. Fødder, der har afsluttet deres svømmetur, ryster vandet af og venter på i morgen. Selv pausen er på en eller anden måde rund og sød."},"ICON-2235":{"nm":"Svømmebræt-hjørnehætte","de":"Én lille hætte trukket let over svømmebrættets hjørne. Så det ikke gør ondt ved stød, ikke bliver ødelagt ved slid, omslutter den kanten. Hemmeligheden bag at holde noget ved sin side længe ligger i at værne om det fra hjørnerne af."},"ICON-2236":{"nm":"Svømmefinne-opbevaringsnet","de":"Svømmefinner, der ligner svømmehud, soler sig inde i nettet. Som ænder, lige kommet op af vandet, der tørrer deres fjer, tørrer de langsomt i masken. En doven lur inden næste svømmetur."},"ICON-2237":{"nm":"Svømmebøje-mærkeseddel","de":"Man sætter et navneskilt på hver bøje for tydeligt at markere ejeren. Jo flere der deles om et sted, desto lettere falder sindet til ro, når det er klart, hvem der ejer hvad. Ét lille mærke skaber orden."},"ICON-2238":{"nm":"Svømmebræt-afdrypningsholder","de":"Et sted, der hælder skråt, så vandet, der har samlet sig i svømmebrættet, triller ned. Man må tømme det, man har taget til sig, for at blive let, fortæller holderen tavst. Det første skridt mod at tørre er at støtte tingene godt op."},"ICON-2239":{"nm":"Svømmefinne-remstrammer","de":"En lille del, der strammer svømmefinnens rem, så den passer tæt om foden. For løs, og den glider af; for stram, og den gør ondt – det sarte lille mellemrum. For at glide let af sted som en and med svømmefødder har man brug for netop denne fine margin."},"ICON-2240":{"nm":"Sparketakt-chip","de":"En lille chip, der angiver taktslaget, hver gang man sparker. Én, to, tre – når rytmen sætter sig i kroppen, bliver vandet før man ved af det til sang. Denne chip lærer sagte, at selv svømning har sin takt."},"ICON-2241":{"nm":"Pose til våd badedragt","de":"Inde i tasken, når man forlader poolen, er det altid mig, der først kræver en plads. Lad de andre ejendele give mig skæve blikke – hvad kan jeg gøre, det våde må holdes for sig, så vi alle sammen kan forblive tørre. Karantænerummet for fugt, det er den ømme post, jeg bestrider."},"ICON-2242":{"nm":"Vridebræt til vand","de":"Vand har den egenskab, at det lumsk smutter væk, når man presser det. Ét fast tryk, så endnu et – først når man lægger vægten på pladen, giver det op. For en, der aldrig havde brug for sin håndledsstyrke, findes der næppe en bedre scene end denne."},"ICON-2243":{"nm":"Skillevæg til svømmetaske","de":"Pakker man det hele i ét rum, smitter det våde og det tørre af på hinanden. Arbejdet med sagte at glide ind imellem og trække en stille streg. Hvis blot ét skillerum kan bringe fred, er forsoning måske overraskende enkelt."},"ICON-2244":{"nm":"Vandtæt skopose","de":"Den sluger sandede sko hele, uden så meget som at ændre en mine. Uanset hvad der sker indeni, forbliver ydersiden tør – det er den høflighed, vandtætheden overholder. En tavs pose er velkommen overalt."},"ICON-2245":{"nm":"Svømmetaske-afløbsprop","de":"Vrider man proppen om, løber dagen, der har samlet sig i taskens bund, straks ud. Oprydningen efter en god omgang leg afhænger altid af netop dette ene lille hul. Selv det at kunne lade noget løbe ud kræver sit design."},"ICON-2246":{"nm":"Vandopsugende måtte","de":"Den ligger stille foran indgangen og tager imod vandet fra hver fod, der kommer ind. Selvom ingen lægger mærke til det, ved gulvbrædderne det – heller ikke i dag gled nogen. I et tavst hjørne bor en tavs belønning."},"ICON-2247":{"nm":"Underkop til våd badehætte","de":"Når en aflagt badehætte mister sit sted at være, holder jeg den oppe. Selvom jeg kaldes en underkop, mens jeg gemmer dråber i stedet for mad, kan selv en holder holde hovedet højt, hvis arbejdet består i at give nogen et sted at være."},"ICON-2248":{"nm":"Håndklæde-tørreklemme","de":"Opgaven med at bide fast om et håndklæde oppe på tørresnoren. Min stolthed er en stædighed, der ikke slipper, uanset hvor meget vinden driller. Indtil det er tørt og blødt i solen, giver en hånd, der først har taget fat, aldrig slip først."},"ICON-2249":{"nm":"Ophæng til vandtæt pose","de":"I det øjeblik den hænger på krogen, får den vandrende pose endelig en adresse. Selvom det blot er at dingle og låne et lille stykke væg, findes der da noget så trygt som et sted, hvor man ikke behøver frygte at gå tabt?"},"ICON-2250":{"nm":"Rutsjebane-armbånd","de":"Den forventning, der har ventet stille på sin tur, er helt og holdent bundet fast i dette ene lille bånd. Først når det spændes fast om håndleddet, begynder rutsjebanekøen at bølge, så indgang er måske netop handlingen at binde et løfte om håndleddet."},"ICON-2251":{"nm":"Rutsjemåtte-stykke","de":"Folk løber muntert hen over den, uden at ane hullet under fødderne. Lagt ud for at ingen skal glide, afslører den først sin eksistens, når netop det ene stykke mangler. Der findes ganske mange ting i denne verden, som kun huskes gennem det tomrum, de efterlader."},"ICON-2252":{"nm":"Vandtæt nøglebånd til skab","de":"At vogte en skabsnøgle mod vandet er mit livslange job. Bundet om et håndled plasker jeg med, men holder alligevel netop den ene nøgle knastør. Mister man mig, kan man ikke engang finde sit tøj, så jeg er trods alt en tungtvejende embedsmand."},"ICON-2253":{"nm":"Rutsjebane-startsignal","de":"I det korte øjeblik, hvor rødt skifter til grønt, springer alles hjerter oppe på rutsjebanen i takt. Retten til at give tilladelse til start – hvem skulle tro, at et så lille signalpanel kunne rumme så stor en forventning."},"ICON-2254":{"nm":"Redningsvestspænde til doven flod","de":"Spændet, der holder fast om en krop, der driver af sted på den dovne flod. Først efter det klik slapper man endelig af og overgiver kroppen til strømmen. Tryghed begynder somme tider med et så lille lukketøj som dette."},"ICON-2255":{"nm":"Bølgebassin-signalflag","de":"Det fortæller alle på forhånd, hvornår bølgerne kommer. Flag oppe betyder jubel, flag nede betyder et øjeblik til at få vejret. Sjovt nok er det en enkelt stump stof, der holder takten ved det oprørte bassin."},"ICON-2256":{"nm":"Rutsjebane-nummerhalskæde","de":"Bær hvilken kø, du står i, om halsen, og der opstår ingen forveksling. Ét nummerskilt afgør, hvis tur det er – og orden, ser det ud til, begynder ofte med netop sådan en lille halskæde."},"ICON-2257":{"nm":"Optankningsmønt til armbånd","de":"Hold den let mod armbåndet, og optankningen er klaret. I en tidsalder, hvor man vandrer rundt i vandet uden kontanter eller kort, spiller denne lille mønt rollen som en hel tegnebog. Jo lettere håndleddet er, desto lettere er sindet."},"ICON-2258":{"nm":"Vandkanon-grebshætte","de":"Et vandkanon-greb er bedst, når man holder godt fast. Mangler blot én hætte, glemmer man både sigte og alt andet, mens den snurrer rundt i hånden – udfaldet af en midsommer vandkamp afhænger af denne ene lille afslutning."},"ICON-2259":{"nm":"Sandslot-tårnform","de":"Presser man vådt sand fast ned og vender den om, rejser der sig et lille tårn. Ingen forstår bedre end jeg det hjerte, der bliver ved med at bygge, selv vel vidende at det vil styrte sammen. For sandets bygmester er formen selve tegningen."},"ICON-2260":{"nm":"Sandrivetænder","de":"Trækker man den, som kæmmede man sandet, bliver der pæne furer tilbage. Vel vidende at bølgerne snart vil viske mønstret ud, tegner tænderne stadig flittigt sine linjer. Der er en egen skønhed i kærligt at skabe det, der er bestemt til at forsvinde."},"ICON-2261":{"nm":"Parasolfod-ankervægt","de":"Den holder stille stand ved foden, så parasollen ikke blæser væk i vinden. At bevare skyggen er ikke det prangende dugs opgave, men den tunge, solidt plantede vægts. Den usynlige tyngde er altid den mest pålidelige."},"ICON-2262":{"nm":"Sandsigte-håndtag","de":"Ryster man sandet gennem sigten, bliver kun muslingeskaller og små skatte tilbage i hånden. Man griber håndtaget og ryster løs – halvdelen af strandens skattejagt afgøres af netop denne ene sigte."},"ICON-2263":{"nm":"Muslingeformet sandform","de":"Fylder man den med vådt sand og banker let på den, blomstrer håndfladestore muslinger i rækker langs stranden. Man kan ikke spise en rigtig musling, men netop denne form kan alle skabe. En beskeden lille sommermagi."},"ICON-2264":{"nm":"Parasol-vinkeljusteringspind","de":"Hver gang solen flytter sig, må parasollen også dreje hovedet efter. Trækker man én pind ud og sætter den i igen, flytter skyggen sig ubemærket. Kunsten at undgå lyset ligger netop i denne lille vinkel."},"ICON-2265":{"nm":"Sandskovl-bladspidshætte","de":"Sætter man den over den skarpe skovlspids, er tasken sikker. Man lægger et øjeblik gravemodet til side, og med blot én hætte bliver den et mildt legetøj. At kunne skjule sin æg er også en form for omtanke."},"ICON-2266":{"nm":"Strandmåtte-hjørneklemme","de":"Når vinden prøver at løfte måttens hjørne, bider jeg fast. At holde ét sted på sandet er i sidste ende alle fire hjørners stædighed. En eftermiddag uden flagren er de små klemmers værk."},"ICON-2267":{"nm":"Parasol-skyggetøjkrog","de":"Hænger man den let på parasolstangen, tørrer våde klæder i skyggen. Ude af solen, ind i brisen – en provisorisk tørresnor sat op af netop én krog. Selv på stranden bor der visdom i husholdningen."},"ICON-2268":{"nm":"Vandtæt telefon-halspose","de":"Bærer man en telefon i favnen og om halsen, finder man modet til at tage billeder selv under vandet. At beskytte ønsket om at fange endnu ét billede, vandtæt og trygt. Som livvagt for minder er den ganske robust."},"ICON-2269":{"nm":"Vandtæt pose til vådt tøj","de":"Den tager uden knurren imod det skiftede, våde tøj i sin helhed. At lade ikke én dråbe røre resten af oppakningen er dens stolthed, så den holder munden lukket og vogter et hjørne af tasken. En ren afslutning begynder med mig."},"ICON-2270":{"nm":"Vandsandal-vristrem","de":"Den omslutter sagte vristen, så den bare sandal ikke glider af. Løb bare rundt på sandet, én rem, og man er tryg. En pålidelig følgesvend til skridtene, ubemærket, men altid ved siden af."},"ICON-2271":{"nm":"Vandtæt kortetui til hals","de":"Med billetter og kort i favnen hænger den om halsen og deltager i vandlegen. Plask løs, uden bekymring for at tabe noget, for den skærmer kortene med sin egen krop. Holdningen hos en trofast livvagt."},"ICON-2272":{"nm":"Anti-dug-klud til svømmebriller","de":"Tørrer man svømmebrillernes tildugede inderside af med kluden én gang, bliver verden under vandet klar igen. Én lille kludpose er selve nøglen, der åbner et sløret syn til klarhed."},"ICON-2273":{"nm":"Vådsandbørste","de":"Den fejer nænsomt selv sandet mellem tæerne bort. Den sidste hånd, der rydder op efter en glad tur gennem havet, lige ved døren. Én gang henover med børsten, og dagens sand siger endelig farvel."},"ICON-2274":{"nm":"Vandtæt lynlåspose til mønter","de":"Den låser nogle få mønter tæt inde bag lynlåsen. Våd eller ej, klirren lyder stadig det samme, så nødhjælpspengene til kiosken vogtes til det sidste. En lille pose, men en sparsommelig og dygtig én."},"ICON-2275":{"nm":"Håndklæderulle-snor","de":"Ruller man håndklædet sammen og binder det med én snor, hænger det lige på taskens rem. Frie hænder, håndklæde på skulderen. Hemmeligheden bag let oppakning til vandleg gemmer sig i denne lille bundt."},"ICON-2276":{"nm":"Vandtæt nøglering-hætte","de":"Den afsluttende knap på båndet, der vogter en nøgle mod vandet. Først når hætten klikker lukket, hopper man endelig trygt i poolen. Et lille, men fejlfrit punktum, der tager ansvar for lukningens afslutning."},"ICON-2277":{"nm":"Snorkel-mundstykke","de":"Bider man i det, åbner luftvejen sig, og havlandskabet træder helt tæt på. Et lille mundstykke, der lader dig trække vejret selv under vandet. Hvem skulle tro, at det at låne et åndedræt kunne være så spændende."},"ICON-2278":{"nm":"Anti-dug-pude til dykkermaske","de":"Dugger maskens inderside til, går synet under vandet også fløjten. Én lille pude holder den tåge stangen, så et klart udsyn er netop dette usynlige lags fortjeneste."},"ICON-2279":{"nm":"Svømmefinne-tåstrammer","de":"Den strammer finnens spids, så den sidder helt tæt om foden, uden slør, når man sparker vandet. For at kraften i ét eneste spark ikke skal lække væk, binder klippen stille en fast lille knude ved tåen."},"ICON-2280":{"nm":"Maskerem-overtræk","de":"Den omslutter blødt maskeremmen, så den ikke river i håret. Ét lag omtanke, der udsletter det stikkende øjeblik, hver gang man tager den af. Det, et lille overtræk passer på, er overraskende nok ømhed."},"ICON-2281":{"nm":"Snorkel-tømmeventilhætte","de":"Selv i handlingen at holde vejret er der en sprække, hvor vand stille siver ind. Én lille ventil leder sagte det tilbage ud igen og vogter pladsen til at indånde, helt til det sidste. Havet husker denne beskedne omhu med den største taknemmelighed."},"ICON-2282":{"nm":"Svømmefinne-opbevaringskrog","de":"Når finnerne hænger pænt på én krog, boret ind i væggen, sænker en rolig orden sig selv over det rodede udstyrsrum. At lægge tingene på deres plads er det stilleste løfte om det næste dyk."},"ICON-2283":{"nm":"Næsepude til dykkermaske","de":"Et enkelt stykke pude, der sagte presser om næsen. Takket være denne lille ømhed, der holder vandet ude, mister ansigtet ikke sit udtryk, selv i det kolde hav."},"ICON-2284":{"nm":"Snorkel-topbeskytter","de":"Beskytteren, der er rundet om snorkelens spids, skubber stille vandet tilbage, når bølgerne skyller over. Jo mere usynligt en del arbejder, desto dybere bærer den ét åndedrags sikkerhed."},"ICON-2285":{"nm":"Skridsikker strimmel til finnesål","de":"En slank strimmel klæbet fast på finnens sål. Den er den ene friktionslinje, tæerne holder fast i for ikke at glide på et vådt dæk. Sikkerhed begynder altid stille i så små teksturer som denne."},"ICON-2286":{"nm":"Iltflaske-ventildæksel","de":"En hætte, der dækker ventilen på en flaske fyldt til randen med luft. Så støv ikke kan lægge sig, så luftvejen ikke bliver tilsmudset. At dække til er at drage omsorg på forhånd, helt frem til den næste persons første åndedrag."},"ICON-2287":{"nm":"Regulator-mundstykkehætte","de":"Stedet, der rører læberne, skal altid være det reneste. Netop denne ene hætte over mundstykket vogter tavst åndedrættets port mod salt vind og sand."},"ICON-2288":{"nm":"Våddragt-lynlåstrækløkke","de":"En kort trækløkke fastgjort på våddragtens lynlås. Den er en omtanke, sat der, så selv hænder stivnet af koldt vand kan trække den op i ét hug. Selv at lukke tøjet bærer spor af nogens omhu."},"ICON-2289":{"nm":"Beskyttelseshætte til luftmåler","de":"Beskyttelseshætten, der omslutter glasset på måleren, som viser den resterende luft. For de tal må aldrig blive utydelige. Jo mere en skive aflæser selve livet, desto mere omhyggeligt tørres og dækkes den til."},"ICON-2290":{"nm":"Vægtbælte-spænde","de":"Mennesker binder vægt om taljen for at synke ned i dybden. I det øjeblik ét spænde låses op og i, samler valget mellem at stige og at synke sig stille ved fingerspidserne."},"ICON-2291":{"nm":"Dykkerlygte-håndledsrem","de":"I det bælgmørke vand holder én rem, bundet om håndleddet, fast om lygten. Slipper man taget, følger lyset alligevel med. At ikke miste et lille lys midt i mørket er derfor så trygt."},"ICON-2292":{"nm":"Ryddeklips til åndedrætsslange","de":"En lille klips, der samler forvirrede slanger ét sted. Forebygger man sammenfiltring i forvejen, famler hænderne ikke, selv i et presset øjeblik. At rydde op er en stille venlighed mod ens fremtidige selv."},"ICON-2293":{"nm":"Fingerforstærkning til dykkerhandske","de":"Forstærkningsstof lagt over hver fingerspids. Stederne, der trækker i reb og griber om klipper, slides naturligvis først, så et ekstra lag er lagt på for at tage imod netop det slid på forhånd."},"ICON-2294":{"nm":"Iltflaske-fodring","de":"Én fodring, der holder en tung flaske lodret. Den favner rundt om en vægt, der ellers kunne vælte, og skænker balance. At støtte er hjertet i at låne sin side ud, så noget ikke falder."},"ICON-2295":{"nm":"Surfbræt-finnehætte","de":"En hætte, der omslutter den skarpe spids på finnen under brættet. Så man ikke kommer til skade på sandet, lægger den bølgeskærende knivsæg til hvile et øjeblik. Under hvilen må enhver gerne blive sløv."},"ICON-2296":{"nm":"Padleåre-bladspidsbeskytter","de":"En beskyttelseshætte, der vogter padleårens bladspids. Den forhindrer skrammer fra sten i at forstyrre vandets flow. Værner man om spidsen, bærer ét eneste åretag én længere frem."},"ICON-2297":{"nm":"Kajakåre-greb","de":"Et greb viklet om stedet, hvor håndflade og åre mødes. Det polstrer blødt det sted, hvor vabler plejede at danne sig, så hænderne ikke kommer til at hade åren, selv mens man kæmper sig op mod strømmen."},"ICON-2298":{"nm":"Surfvoks-dåse","de":"En lille bliktin, der rummer en klump voks. Den magi, der fæstner fødderne til brættet, hentes altid frem fra netop dette håndfladestore skrin. Med én sirlig dåse begynder dagens forberedelse."},"ICON-2299":{"nm":"Leash-ankelstrammerløkke","de":"Løkken, der strammer leashen, som forbinder ankel og bræt. Én knude, der lover ikke at slippe dig, selv når en stor bølge fejer over. Forbindelse er et løfte om at holde fast, så man ikke driver for langt væk."},"ICON-2300":{"nm":"Paddleboard-luftprop","de":"Et bræt, der bliver fast, når det fyldes med luft, og proppen, der lukker det åndedrag inde. Åbner man den, folder det sig fladt sammen; lukker man den, står det oprejst på vandet. Én lille prop rummer en dag, der svulmer og synker sammen."},"ICON-2301":{"nm":"Kajaksædets pudestrop","de":"En strop, der binder puden fast til sædet. For ryggen og lænden, der padler siddende i lang tid, holder den blødheden på plads, så den ikke glider væk. Selv komfort har brug for en fast knude."},"ICON-2302":{"nm":"Surfbrættets næsekofanger","de":"En kofanger, der omslutter brættets stævn. Det er polstring lagt på næsen, hvor sammenstød er hyppige, så den ville sløves først. At lægge blødhed dér, hvor man går forrest, er et løfte om at bruge det længe."},"ICON-2303":{"nm":"Spænde til vandtæt taske","de":"Et spænde, du folder og lukker to, tre gange, så ikke én dråbe slipper ind. At holde dyrebare ting tørre kræver altid ét greb mere. Det ene faste stram bliver til tryghed."},"ICON-2304":{"nm":"Stykke af futsalmålnet","de":"Et enkelt stykke af nettet, der engang rystede målet. Det husker, tråd for tråd, jublen fra øjeblikket, da bolden fyldte det. Et mål boede i hver knude, og i hvert flossede sted lever den dags kamp stadig videre."},"ICON-2305":{"nm":"Fodboldpumpedyse","de":"En pumpedyse, der puster liv i en flad bold. Læderet, der rullede rundt, slapt og modløst, springer og hopper igen. At fylde den op er at rejse en standset leg på benene igen."},"ICON-2306":{"nm":"Hjørneflagsokkel","de":"En sokkel, der holder et flag oprejst i banens hjørne. Det er et lille mærke for grænsen, men med dét ene punkt får jordbanen endelig form af en arena."},"ICON-2307":{"nm":"Skinnebensbeskytterens rem","de":"En rem, der binder skinnebensbeskytteren fast til læggen. Den holder fast om stedet, der ofte rammes, så hvert skridt forbliver uden frygt selv i den hårde tumult."},"ICON-2308":{"nm":"Udskiftningsstift til fodboldstuds","de":"En stift til at skifte en slidt studs ud med en ny. De små tænder ved tåen, der griber fat i græsset. For ikke at glide må man somme tider bygge helt fra bunden af igen."},"ICON-2309":{"nm":"Ventilhætte til fodbold","de":"En lille ventilhætte, der forsegler boldens åndehul. Den vogter indgangen, så den luft, du har fyldt i, ikke slipper ud. At bevare spændingen ligner det at holde fast i sin skarphed indtil næste kamp."},"ICON-2310":{"nm":"Linjemarkeringskegle","de":"En kegle, der tegner streger på jorden og deler vejen. Herfra og til er vores side, derfra er modstanderens. Én lille kegle forvandler en rodet, tom grund til en legeplads med regler."},"ICON-2311":{"nm":"Støvbørste til futsalsko","de":"En børste, der fejer jorden og støvet, som sidder fast i futsalskoens riller. Når kampen er slut, har en dags jord samlet sig på skoene også. Den børstende hånd er en stille tak til de fødder, der løb så godt."},"ICON-2312":{"nm":"Målmandshandskebøjle","de":"En bøjle, der tørrer og holder målmandens handsker. Det er stedet, hvor de svedvåde hænder hviler en stund, lige så mange som de skud, de stoppede. Til næste kamp tørrer det våde, og det forhærdede hjerte løsner sig langsomt."},"ICON-2313":{"nm":"Nettekroge til basketkurv","de":"De små kroge, der hænger nettet fra ringen. På grund af dem laver bolden den bløde susen, når den passerer igennem. Den klare lyd af en scoring begynder faktisk ved disse små kroge."},"ICON-2314":{"nm":"Luftaftapningsværktøj til basketbold","de":"Et redskab, der slipper lidt luft ud af en alt for hård bold. For meget spænding gør hoppet vildt. At lette den, akkurat passende. En bold med god fornemmelse fødes altid af den rette balance."},"ICON-2315":{"nm":"Sensorpude til basketbræt","de":"En sensorpude fastgjort bag basketbrættet. Den aflæser øjeblikket, bolden rører ved, tydeligt, i tal. Selv det øjeblik øjet gik glip af, husker denne lille sans, så dommen bliver netop dét mere retfærdig."},"ICON-2316":{"nm":"Driblekegler","de":"Forhindringskegler stillet på række langs driblestien. Ved at sno sig frem og tilbage mellem dem vokser fodarbejdet. At stå i vejen er også en venlighed, der lærer, hvordan man slipper endnu bedre igennem."},"ICON-2317":{"nm":"Ventilbørste til basketbold","de":"En lille børste, der renser boldens ventilhul. Hvis støv tilstopper det, kan nålen ikke komme ind, så man renser fra den usynlige indgang først. Før man fylder, tømmer og tørrer man altid."},"ICON-2318":{"nm":"Fingertapesrulle","de":"En rulle tape viklet om fingrene. Den holder et forstuvet led fast og skænker modet til at gribe bolden igen. At forbinde et sår er en lille erklæring om, at man ikke vil stoppe."},"ICON-2319":{"nm":"Klemme til rygnummer","de":"En klemme, der fæstner rygnummeret til trøjen. I stedet for dit navn strejfer et tal banen. I det ene faste greb, så det ikke falder af, står det tydeligt skrevet, hvem der spiller i dag."},"ICON-2320":{"nm":"Skydeøvelsesring","de":"En målring monteret inde i kurven, der indsnævrer sigtet. Den formindsker stedet, bolden skal ramme, og træner én i at udholde forbier. Kast mod den smalle port længe nok, og fingerspidserne lærer stille og roligt præcision."},"ICON-2321":{"nm":"Sålerens til basketsko","de":"Før du træder ind på banen, bøjer du dig og tørrer sålerne først. Fordi du ikke vil efterlade det mindste glid på parketten. Sæt det første skridt med rene tæer, og dagens dig er lidt stærkere end i går."},"ICON-2322":{"nm":"Spændingsring til volleyballnet","de":"Spænding kan ikke ses. Først i det øjeblik ringen trækker snoren helt ud og standser, deler nettet banen i to med en hånds bredde af spænding. En balance holdt af en usynlig hånd vækker kampen."},"ICON-2323":{"nm":"Antennefikseringsclip","de":"Antennen, der bestandig svajede i vinden, står lige med ét klip. En lille ting, der holder en stor vaklen tilbage. Den hånd, der stille sikrer et enkelt kabel bag scenen, bevæger sig med netop lige så meget hjerte."},"ICON-2324":{"nm":"Liberovestbøjle","de":"Forsvarsspecialistens vest i en anden farve hænger på væggen og venter på næste kamp. Ikke prangende, men et navn, der bærer hele banen: liberoen. Der, på det laveste sted, findes de øjne, der ser længst."},"ICON-2325":{"nm":"Pose til knæbeskyttere","de":"Jo mere man ruller hen ad gulvet, desto oftere rammes knæene. Denne lille pose, der pænt gemmer beskytterne, ved: kun de, der først lærer at falde godt, flyver til sidst længst."},"ICON-2326":{"nm":"Trykmåler til volleyball","de":"Man kan ikke afgøre det med et lille tryk fra fingerspidsen. Målerens nål skælver svagt og peger på ét enkelt mærke. At måle en enkelt bolds ånde er kampens første knap. Af ærligt tryk fødes en ærlig bane."},"ICON-2327":{"nm":"Tape til dodgeball-linje","de":"En enkelt cirkel tegnet med tape i banens jordbund. Dens inderside og yderside deler et halvt døgns univers af fangeleg. Den hånd, der trak linjen, ved: regler er selve begyndelsen på leg."},"ICON-2328":{"nm":"Fløjteholder til dommer","de":"Når den skarpe fløjtelyd forstummer, lægges den stille tilbage på sin plads på holderen. Stedet, der hører dommerens åndedræt nærmest. Retfærdighed begynder altid med den lille opgave at holde sin plads."},"ICON-2329":{"nm":"Vægmål til opspilstræning","de":"I den tidlige morgen, hvor ingen kan modtage, løfter du fingerspidserne tusindvis af gange mod målet på væggen. Væggen er den mest overbærende holdkammerat. Bolden, den sender tilbage, rejser en træt dig op igen."},"ICON-2330":{"nm":"Målestang til nethøjde","de":"Er nettet blot en finger for lavt, går kampen skævt. I det øjeblik du løfter målestangen, bliver retfærdighed ikke et tal, men en daglig vane. Usynlig præcision vogter banen."},"ICON-2331":{"nm":"Vinkelstift til startblok","de":"Fra den knælende stilling, den vinkel, hvor tæerne møder blokken, dén ene grad afgør starten. Med en enkelt stift fikserer du blokken og finder roen i vejret. Startens holdning følger dig stille hele vejen til målstregen."},"ICON-2332":{"nm":"Banenummerflag","de":"Et lille flag plantet i hver bane vifter med sit nummer i vinden. Løb alle i samme retning, men hver har alligevel sin egen vej. Banen rummer side-om-side-lighed og forskellighed på samme tid."},"ICON-2333":{"nm":"Endeprop til stafetstok","de":"For det øjeblik den skal møde den sidste løbers hånd, runder endeproppen kanterne af. I en stafet er det mest dyrebare ikke hastighed, men den hånd, du rækker til den næste."},"ICON-2334":{"nm":"Ophæng til målebånd","de":"Man hænger målebåndet, der noterede resultaterne, på væggen, så det ikke filtrer sig. Stedet, hvor gårsdagens afstand og dagens hænger side om side. Fremgang ankommer altid først som en lille forskel i tal."},"ICON-2335":{"nm":"Kurvemarkeringskegle","de":"En lille kegle stillet på indersiden af kurven fortæller vejens hensigt. Skær ikke for langt ind, spred dig ikke for langt ud. Den, der runder godt, fører til sidst forrest."},"ICON-2336":{"nm":"Målsnorsclip","de":"Det bånd, der først skal røre et bryst, holder clipsen spændt og venter. En snor, der findes for at blive brudt. Den udholder vinden hele dagen for én persons ene sekund."},"ICON-2337":{"nm":"Startpistolhylster","de":"Indtil signalets knald runger, sover pistolmundingen under sit hylster. Et kar, der rummer startens lyd. Jo dybere stilheden er, desto længere bærer genlyden af det første skud."},"ICON-2338":{"nm":"Højdejusteringsstift til hækkeløb","de":"Hver gang du hæver højden et hak, flytter stiftens plads sig med. Og frygten vokser lige så meget. Alligevel vurderer fødderne et lidt højere sted hver gang og løber videre."},"ICON-2339":{"nm":"Omgangstæller","de":"Når du mister overblikket over, hvor mange omgange der er tilbage, drejer du tælleren et hak. Det lille klik af et faldende tal lægger kraft tilbage i benene. Hånden, der tæller den resterende distance, holder din pace."},"ICON-2340":{"nm":"Opbevaringsstativ til springstang","de":"En lang, svajende stang har brug for sit eget sted at hvile. Fordi det er et redskab, der må bøje for at springe, rejser man den med ekstra omhu. Velbevaret smidighed rummer det højeste spring."},"ICON-2341":{"nm":"Udjævningsrive til sandgrav","de":"Langsomt river du selv fodsporene, den forrige atlet efterlod, jævne. Sandgraven bliver flad igen, som var det første gang, hver eneste runde. Hånden, der udsletter spor for en andens spring, er der, stille og standhaftig."},"ICON-2342":{"nm":"Afstandsmarkeringsstrimmel til tilløb","de":"Et skridt for lidt går ikke, og et skridt for meget går heller ikke. Afstandsmarkeringen på jorden fortæller ærligt, hvor du skal plante foden. Et godt tilløb er ikke hovedløs grådighed, men roligt regnestykke."},"ICON-2343":{"nm":"Diskosgreb","de":"Glider fingrene, er kastet allerede kastet, før man overhovedet kaster det. Grebets ru struktur omkring diskosen holder rotationen i tømme. Timingen for slip begynder altid i fornemmelsen af holdet."},"ICON-2344":{"nm":"Vuggering til kuglestød","de":"En vuggering holder den tunge jernkugle stille, så den ikke ruller væk. En lille rede, der bevarer stilheden lige før kastet. Jo mere eksplosiv kraften er, desto fastere må dens hvilested være."},"ICON-2345":{"nm":"Spidsbeskytter til spyd","de":"En hætte trukket over den skarpe spydspids dækker den i blød tavshed. Når et redskab bestemt til at flyve langt ligger stille, tæmmes farlighed af omtanke. Sikkerhed lever selv i opbevaring."},"ICON-2346":{"nm":"Tværstangsholder til højdespring","de":"Så tværstangen ikke falder selv ved en let berøring, holder krogen den med en udsøgt balance. Stedet, der bærer ansvaret for den skælvende grænse mellem at klare den og ikke. Retfærdighed bor i de små detaljer."},"ICON-2347":{"nm":"Hjørneanker til landingsmåtte","de":"Løfter landingsmåttens hjørne sig, kommer nogen til skade. Ankeret presser alle fire hjørner fast ned. Så kroppen, der fløj højest, lander sikrest, støtter det den, usynligt."},"ICON-2348":{"nm":"Grænsetape til kastecirkel","de":"Grænsen for kaststedet trækkes med en enkelt stribe tape. Om man træder på den linje eller ej, lever eller dør en rekord. Den tynde, enkelte linje, hvor frihed og regler mødes, et løfte."},"ICON-2349":{"nm":"Gummifod til balancebom","de":"Så den smalle balancebom ikke vakler, bider gummifoden sig fast i gulvet. Den skælvfri balance, der udfolder sig ovenpå, er i sandhed skabt af den usynlige fasthed nedenunder."},"ICON-2350":{"nm":"Grebswikling til svingstang","de":"Så håndfladen ikke glider, vikler du en wikling om svingstangens greb. Hemmeligheden bag den snurrende rotation ligger ikke i pynt, men i en hårdt knyttet hånd. Sveden, der er faldet på måtten, ved det."},"ICON-2351":{"nm":"Højdelås til ringeremme","de":"Adskiller de to remmes højde sig blot en hånds bredde, bryder øvelsen sammen. Låsen holder tavst den balance. Kun oven på en præcist afstemt højde begynder den frie flugt endelig."},"ICON-2352":{"nm":"Håndtagsbetræk til bøjlehest","de":"Betrækket, der omslutter håndtaget, holder vabler på håndfladen på afstand. Under den snurrende, drejende øvelse findes en hånd, der har skrabet og heles utallige gange. Beskyttelse er et blidt løfte om den næste træning."},"ICON-2353":{"nm":"Afstandsstift til asymmetriske barrer","de":"Du indstiller afstanden mellem de to barrer præcist med en stift. Det tomme rum, kroppen skal krydse, bliver til selve scenen. Fingerspidserne ved det først: oven på en præcis afstand fødes det dristigste spring."},"ICON-2354":{"nm":"Fjederhætte til springbræt","de":"I det øjeblik du sparker fra brættet, skubber fjederen kroppen mod himlen. Hætten omslutter fast kraften fra det hop. Det korteste tilløb skaber den længste flugt gennem luften."},"ICON-2355":{"nm":"Magnesiumpose","de":"Det hvide pulver, du gnider på hænderne, er en lille talisman, der visker glidning bort. Det korte ritual at dyppe hånden i posen og ud igen dæmper frygten. Selv nervøsitet tæmmes til sidst ved fingerspidserne."},"ICON-2356":{"nm":"Håndledsbind til gymnastik","de":"At vikle bindet om håndleddet strammer samtidig hjertets snore. At holde et led, der ville vakle, fast på forhånd. Ét godt bundet håndled tillader stille en dristigere rotation."},"ICON-2357":{"nm":"Sikkerhedsring til trapez","de":"Lige før kroppen kastes ud i luften, bliver sikkerhedsringen en usynlig hånd. Først når frygten for at falde forsvinder, kan man flyve længst. Tillid fuldender flugten."},"ICON-2358":{"nm":"Opbevaringslåg til tennisbolddåse","de":"Under hætten, der forsegler dåsens åbning, sover nye bolde og holder på deres tryk. Det lille pop, når en dåse åbnes, vækker kampens spænding. En forsegling er et løfte, der bevarer friskhed."},"ICON-2359":{"nm":"Strengespændingsklemme","de":"Klemmen bider strengens spænding fast og slipper ikke helt til sidst. Fordi én strengs spænding afgør boldens rekyl. Den usynlige fornemmelse begynder ved denne lille klemme."},"ICON-2360":{"nm":"Linjekost til tennisbane","de":"Når kampen er slut, fejer man langsomt langs banens hvide streger. Fjern støvet, og linjerne bliver skarpe igen. At bane vejen for den næste kamp, den sidste omsorg, der holder banen i live."},"ICON-2361":{"nm":"Kantbeskyttelsestape til ketsjer","de":"Vikl den én gang rundt om ketsjerens kant, og selv hårde sammenstød tages rundt og blødt imod. Jeg ved, at kanten er det sted, der slides først. Fordi det er min opgave at overtage slitagen i dit sted, står jeg også i dag yderst."},"ICON-2362":{"nm":"Indendørs temperaturchip","de":"Den kolde morgenvind, der stryger ind, når døren åbnes, aflæser en håndfladestor chip før noget menneske. At fornemme det, før næsen selv fryser, det er den stilleste hilsen, der åbner dagen i en tom gymnastiksal."},"ICON-2363":{"nm":"Afsætsplade","de":"For atleten, der tøver med, hvor tåen skal sættes, er én streg trukket på jorden nok. Linjen, man ikke må overskride, bliver netop startlinjen for det længste spring, fortæller fodpladen tavst."},"ICON-2364":{"nm":"Ophæng til boldkurv","de":"Den rummer snesevis af bolde i én mundfuld uden at tabe en eneste. At samle det, der er spredt ud over banen, og række det videre til næste træning, en hånd, der stille og travlt arbejder i hjørnet, hænger her også i dag."},"ICON-2365":{"nm":"Endeprop til ketsjergreb","de":"I det øjeblik du klikker den fast på grebets ende, hviler ketsjeren endelig i din håndflade. Én lille prop skiller glidning fra tryghed. Kun når enden er ordentligt lukket, bliver det første sving fast."},"ICON-2366":{"nm":"Håndklædeklemme til banekant","de":"Selv når vinden blæser hårdt, holder den munden lukket og står fast ved banens kant, så det omhyggeligt vredne håndklæde ikke flyver væk. Selv i at værne om en kort pause for at trække vejret har nogens omhyggelige fingerspidser været på spil."},"ICON-2367":{"nm":"Fjerretterklemme til fjerbold","de":"Blot én forstyrret fjer, og flugten vakler. Ret forsigtigt den krøllede vinge ud, og fjerbolden gør sig klar til at flyve lige igen. At komme langt begynder altid med sådan en lille pleje."},"ICON-2368":{"nm":"Rørprop til fjerbolde","de":"Så fjerboldene, stillet på række indeni, ikke bliver bløde, skruer man rørets ende fast til. Jeg har set længe nok til at vide, at én smule fugt får en fjer til at synke sammen. At opbevare tingene godt er allerede en del af kampen."},"ICON-2369":{"nm":"Rullehvile til bordtennisbold","de":"Den lille bold, der kom trillende, henter vejret et øjeblik oven på mig. At holde den stille, så den ikke triller ned, er den rundeste form for omsorg, rakt ved siden af bordet."},"ICON-2370":{"nm":"Gummiruller til bordtennisbat","de":"Ruller man rulleren blidt hen over gummifladen, rejser gammelt støv sig, og klæbrigheden vender tilbage. Spinnet skal leve, for at bolden kan bue. Battets tilstand i dag vågner ved denne ene ømme berøring."},"ICON-2371":{"nm":"Målepind til nethøjde","de":"Er nettet blot en hånds bredde højere, ændrer kampens karakter sig. Dem, der til sidst nægter at stole på øjemål, henter mig frem. Retfærdighed, ser det ud til, kommer først fra en højde målt punktligt med linealen."},"ICON-2372":{"nm":"Hastighedssensorchip til fjerbold","de":"Farten på fjerbolden, der skærer gennem luften, udregner jeg stille. Når den engang usynlige fart lander som et klart tal, bliver trænerens næste ord netop dét klarere. Det er arbejdet med at gøre en fornemmelse til et faktum."},"ICON-2373":{"nm":"Opbevaringskapsel til bordtennisbold","de":"Lægger man en rund bold blidt ned i kapslen, trækker ridser og støv sig langt væk. I ønsket om, at den må være uskadt til næste kamp, ligger hjertet, der giver et helt lille rum bort."},"ICON-2374":{"nm":"Strengeophæng til badmintonketsjer","de":"Hænger man de løsnede strenge pænt op, famler den næste hånd i rækken ikke. At rydde op er, når alt kommer til alt, som en venlig seddel skrevet på forhånd til morgendagens dig. I dag letter i morgen."},"ICON-2375":{"nm":"Kanttape til bordtennisbat","de":"Kanten, hvor gummiet let løfter sig, omfavner jeg stille i én enkelt linje. Splitter randen, går selv boldens bane skæv. At vogte kanten bliver til sidst til at vogte ét point."},"ICON-2376":{"nm":"Varmepose til squashbold","de":"En kold bold hopper næsten ikke. Før kampen en pose, der varmer og holder den som en håndflade. Den lille varme, der gives videre til hånden, fastlægger på forhånd åndedrættet og rytmen i en runde."},"ICON-2377":{"nm":"Netklemme til lacrosseketsjer","de":"Når en netmaske stille begynder at løsne sig, bider jeg lydløst fast i dén ene maske. Nettet skal være stramt, for at bolden kan blive der. Her er hånden, der holder hele kampen sammen fra et usynligt sted."},"ICON-2378":{"nm":"Spidsbeskyttelsestape til squashketsjer","de":"Jo hårdere du svinger mod væggen, desto mere græder ketsjeren først fra spidsen. Omslut den grædende spids blidt, og den spiller med dig endnu en sæson. Den, der ved at skåne spidsen, holder til sidst ketsjeren længst."},"ICON-2379":{"nm":"Bladbeskytter til hockeystav","de":"Trækker man betrækket over det skarpe blad, falder ro over både tasken og fingerspidserne. At lulle noget farligt stille i søvn er den gamle høflighed, man først iagttager, når staven pakkes ned."},"ICON-2380":{"nm":"Poleringsklud til cricketbold","de":"Gnider man den røde bold med kluden, holder den ene side lyset som et spejl. Bowleren ved med fingerspidsernes fornemmelse, at bolden buer, når glansen lever. En stille strategi bor selv i omhyggelig polering."},"ICON-2381":{"nm":"Rørhætte til lacrossebolde","de":"Så de hårde bolde ikke ruller væk efter forgodtbefindende, skruer man rørets munding fast til. At samle det, der let spredes, ét sted, driftens grundregel er altid netop så lille."},"ICON-2382":{"nm":"Vægmålsstykke til squash","de":"Et lille mål indsat i væggen samler atletens vaklende blik i ét punkt. Det ene punkt, der fortæller, hvor man skal sigte, selv den brede væg indsnævres til en klar skydeskive foran dette lille stykke."},"ICON-2383":{"nm":"Grebshylster til hockeystav","de":"Flytter man grebet, hånden kender, over på en fremmed ny stav, bliver redskabet på et øjeblik ens eget. En lille muffe, der lader én tage fortroligheden lige på, dette er genvejen til at falde til."},"ICON-2384":{"nm":"Netophæng til feltmål","de":"Først når nettet hænges på målet, bliver et mål virkelig et mål. Det var altid nettet, der holdt til det sidste det korte øjeblik, en bold fyldte det. Ved stedet, der griber formen af det brusende jubel, er jeg der."},"ICON-2385":{"nm":"Skøjtebladbetræk","de":"Med bladet blottet kan man ikke stole på et eneste skridt uden for isen. Forlader du isen, så tag mig venligst på. At lulle skarphed stille i søvn er også en skik, skøjteløbere længe har holdt i hævd."},"ICON-2386":{"nm":"Snøreophæng til skøjtestøvler","de":"De lange snørebånd på de aflagte støvler hænger man pænt op, ét ad gangen. Snørebånd løst op, så de ikke filtrer sig, åbner glat den næste tur på isen. Dagens afslutning bliver netop dermed forberedelsen til i morgen."},"ICON-2387":{"nm":"Klud til skøjteblad","de":"På et blad, der lige har forladt isen, samler små dråber sig perlende. Tørrer man den fugt omhyggeligt af, går rusten uden om. At samle sporene, kulden efterlod, i stilhed, det er min dag."},"ICON-2388":{"nm":"Ankelpude til skøjtestøvle","de":"Vakler anklen blot én gang, bryder hele glidningen sammen. En pude, der omslutter den fast og holder fodfæstet. Den yndefulde balance på isen begynder altid først, usynligt."},"ICON-2389":{"nm":"Pose til skøjtebladguard","de":"Der findes en lille pose i et hjørne af tasken til at gemme bladguarden godt. Vanen med at pakke det nødvendige uden at glemme noget holder udstyret i live længe. En ordentlig taske er det første billede af en god glidning."},"ICON-2390":{"nm":"Indlægssålsklemme til skøjtestøvle","de":"Så indlægssålen inde i støvlen ikke stille skrider ud, holder den fast under foden. Går stedet, man træder på, skævt, går springet skævt med. Hånden, der griber det laveste sted, hjælper til sidst det højeste spring."},"ICON-2391":{"nm":"Låseløkke til skøjtebladbetræk","de":"Så betrækket ikke glider af, spænder man det fast med en løkke. Jeg ved, at løs beskyttelse til sidst slet ikke er beskyttelse. Én godt fastspændt løkke vogter det blad til det sidste."},"ICON-2392":{"nm":"Snørestrammer til skøjtestøvle","de":"Strammer man snørebåndet hårdt til og låser det med hætten, går det aldrig op igen. At snøre stramt uden mellemrum fra selve tåen, det er den solideste knude bundet, før det første skridt sættes på isen."},"ICON-2393":{"nm":"Tørreklud til skøjteblad","de":"Fra et blad, der lige har afsluttet en glidning, samler man stille den ophobede fugt. Jeg ved, at et blad efterladt vådt græder. Kun et blad tørret blødt tegner den næste kurve tydeligt på isen."},"ICON-2394":{"nm":"Grebshætte til skistav","de":"Omslutter man stavens grebende blidt, bliver den gribende håndflade dét mere behagelig. Kraften, der skærer gennem snefeltet, kommer til sidst fra netop det fast holdte sted. Én lille hætte bærer en lang nedfart hele vejen."},"ICON-2395":{"nm":"Bindingsstift til snowboard","de":"I det øjeblik den lille stift, der forbinder brættet og foden, glider ud, standser bjerget foran dig. Et stykke, man må se efter først, selvom det er svært at få øje på, denne faste forbindelse bliver til frihed på sneen."},"ICON-2396":{"nm":"Spidsbeskyttelsesklemme til ski","de":"Så den skarpe kant ikke ridser tasken indeni, bider man stille fast i spidsen. At berolige skarpheden til søvn er den milde afslutning, man rækker efter en god tur ned ad bjerget."},"ICON-2397":{"nm":"Næsebeskytter til snowboard","de":"Omslutter man brættets næse tæt, spredes selv et frontalt sammenstød blidt. At vogte tavst det sted, der rammes først, modet til at møde en stejl nedfart begynder lige her."},"ICON-2398":{"nm":"Spændebetræk til skistøvle","de":"Så spændet ikke tager skade af at støde mod den kolde sne, dækker man det stille til. Endnu en lås, der vogter selve lukkemekanismen, dette lille betræk forlænger snigende støvlens sæson en anelse."},"ICON-2399":{"nm":"Sikkerhedsline-løkke til snowboard","de":"Så brættet ikke kan flygte langt, selv når det slipper hånden, forbinder jeg ankel og bræt med én linje. Så du, selv om du taber grebet, aldrig taber det for altid, en stille løkke af tryghed hængt for enden af en lang line."},"ICON-2400":{"nm":"Skraberspids til skisål","de":"Den gamle voks, størknet fast på sålen, skraber man glat væk. Kun ved at fjerne det gamle helt vågner en ny glidning til live. En sål plejet med omhu åbner det næste snefelt endnu hurtigere."},"ICON-2401":{"nm":"Snowboard-næsebumper","de":"Før brættet skærer gennem sneen, er det næsetippen, der først rører verden. Hvert stød tages imod af denne lille gummiklump. Forrest, hvor den slides ned uden nogensinde at gøre væsen af sig – nogens nedkørsel glider hen over denne stumpe hengivenhed."},"ICON-2402":{"nm":"Skistav-kurvering","de":"Lige som stokken er ved at synke dybt ned i sneen, føler denne runde ring sig frem mod bunden i dens sted. En cirkel, der stille støtter et skridt, som næsten gled. Usynlig bliver den ved din side som en hånd, der holder dig fra at glide."},"ICON-2403":{"nm":"Kantvoks-børstehætte","de":"Når plejen er færdig, dækker den blidt børsten til, før pulveret tørrer. Den forsegler dagens blødhed, så ikke én eneste fiber kommer i uorden. Så når du åbner den igen, venter gårsdagens omhu der, akkurat som den var."},"ICON-2404":{"nm":"Ørevarmer-krog","de":"Kan du huske det? Ørevarmerne, der blev glemt et øjeblik ved siden af tasken, da foråret kom. Men den nat, hvor nyheden om det første snefald lyder, er de de første, der kaldes frem. Der findes et særligt sted at hænge årstiden, og denne krog glemmer aldrig det løfte."},"ICON-2405":{"nm":"Hvæssesten-etui","de":"For at hvæsse en kniv må man først væde stenen – en rækkefølge, der sidder i én som bedstemors håndelag. Selv et redskab, der tæmmer sløvhed, har brug for et sted at hvile, så dette lille hus favner stenen og venter på næste pleje."},"ICON-2406":{"nm":"Vokspose","de":"Selve stoffet, der skaber en strålende glidetur, ligger tæt pakket og sover indeni. En solid tyngde, der rummer en hærdet klump. Glideturen løses altid ud fra denne stille vægt og breder sig ud over snelandskabet."},"ICON-2407":{"nm":"Håndvarmer-posestrop","de":"På en vintergåtur er det stedet, fingrene først famler efter inde i lommen. Den giver et fast hjem til den lille varme, der tør frosne hænder op. Jo koldere dagen er, desto venligere bliver denne lille strop."},"ICON-2408":{"nm":"Slibesten-holder","de":"Vakler den, bliver kanten skæv, så den fæstner først sig selv fast. En holder, der aldrig rører sig, blot for at være ansvarlig for en andens præcision. Nogens lige knivæg står på denne stille standhaftighed."},"ICON-2409":{"nm":"Halsvarmer-clips","de":"På en kold, blæsende skolevej, i det øjeblik halsvarmeren begynder at glide ned – klik, fast på kraven. Selv varme må holde sin plads, før den for alvor kan varme. Én lille lyd holder fast i morgenens varme."},"ICON-2410":{"nm":"Voksejerns-cover","de":"Mens fladen, der har arbejdet så varmt, køler af, beskytter et enkelt stykke stof den stille mod støv. Ét redskab, der passer på et andet, som har forberedt glideturen. Sådan fortsætter omsorgen, stille og roligt."},"ICON-2411":{"nm":"Kantolie-penhætte","de":"Åbnes den én gang og tørrer ud, kan man ikke tegne næste streg. At lukke den er derfor det samme som at åbne den næste – denne lille hætte forsegler fugten ved spidsen og lover i forvejen morgendagens pennestrøg."},"ICON-2412":{"nm":"Pom-pom-top","de":"Hundredvis af tråde starter fra dette ene punkt og spredes samstemmigt i takt. Svingningens pragt begynder altid fra et fast bundet sted. Under scenen, den første knude, der får tilskuerpladserne til at bølge."},"ICON-2413":{"nm":"Lightstick-håndrem","de":"Efter to timers jubel, i det øjeblik du næsten taber din lightstick, bringer denne rem den tilbage i din hånd. Ønsket om ikke at miste den, selv når den falder. Den ømme bekymring skabte en løkke om dit håndled."},"ICON-2414":{"nm":"Tilskuerhynde-foldelås","de":"At springe op og sætte sig igen dusinvis af gange, mens man hepper. Imellem folder denne lille lås hynden pænt sammen og holder din plads. Selv i en opstemt menneskemængde findes der en hånd, der passer på nogens plads."},"ICON-2415":{"nm":"Bandana-løkke","de":"Den dag det samme mønster breder sig ud over alle pladser, binder ét stykke stof titusindvis af hjerter sammen i én farve. Det første punkt, hvor den bølge begynder, er denne lille løkke – stedet hvor en heppen, der var alene, bliver til et vi."},"ICON-2416":{"nm":"Klapper-halvdel","de":"Klapper man alene, er lyden lille; samlet på tilskuerpladserne bliver den til en bølge. Den ene halvdel, der mest ærligt kender sandheden om, at den kun klinger, når den møder en anden. I det øjeblik dit klap møder mit, vokser heppekoret."},"ICON-2417":{"nm":"Heppeskilt-hjørnehætte","de":"Den omslutter det skarpe hjørne blødt, så personen ved siden af ikke kommer til skade. Selv i inderlig svingen findes der hensyn til hinanden gemt indeni. Heppekoret bliver varmere, netop hvor det er så afrundet."},"ICON-2418":{"nm":"Bånd-flagstangholder","de":"Selv i det øjeblik flagren stopper, står stangen lige og venter på det næste brøl. Et sted, hvor den hviler stille et øjeblik, for at kunne svaje igen. Mellem det ene brøl og det næste, en kort stilhed hvor båndet får luft."},"ICON-2419":{"nm":"Heppevifte","de":"Så én persons råb kan nå helt ud til scenekanten, indsnævrer viftens form lydens vej. En mund, der altid grubler over, hvordan man formidler, mere end over hjertets størrelse. En form skabt af længslen efter at nå en smule længere."},"ICON-2420":{"nm":"Badge-nålehylster","de":"Før det fæstnes på brystet, og efter det tages af, begynder og ender badgets hvile her. Et lille hus, der trygt lægger den skarpe bagnål til ro. Selv et glimtende punkt har brug for et sted at ligge og hvile lidt."},"ICON-2421":{"nm":"Resultattavle-talbrik","de":"Den bærer omhuen fra en tid, hvor hvert mål blev skiftet ud i hånden. Før den digitale tidsalder blev udfaldet indgraveret ét rum ad gangen af menneskelige fingerspidser. En brik, hvor selv et enkelt tal rummede nogens spænding."},"ICON-2422":{"nm":"Taktiktavle-magnetbrik","de":"I trænerens fingerspor bytter forsvar og angreb plads. Ethvert billede i tankerne før kampen tegnes først i disse små prikkers forskydning. Udfaldet spilles én gang på forhånd ud på tavlen."},"ICON-2423":{"nm":"Resultattavle-solskærm","de":"Så de blændende tal ikke sløre en spillers udsyn, skærer skærmen lyset væk. Selv lysstyrke må somme tider skygges passende for at gøre sit arbejde. På det klareste sted, en skygge der arbejder allerstilleste."},"ICON-2424":{"nm":"Resultat-vendering","de":"Hver gang et blad vendes, skifter tallet, og jubelen stiger med det. Et spor fra den analoge tid, hvor resultater blev fornyet af en hånds fornemmelse. En tid, hvor hjertet vendte med, ved lyden af resultatet, der vendte."},"ICON-2425":{"nm":"Taktiktegne-penetui","de":"Enhver rute tegnet på whiteboardet i omklædningsrummet kommer fra denne pen. Et lille, solidt etui der rummer opgørets grundtegning. I stilheden før opgøret, stedet der bærer flest ord."},"ICON-2426":{"nm":"Point-klikker","de":"Hvert tryk lægger ét rum til, tallet stiger med et klart klik. Overlad tallene til fingrene, så kan hjertet vende sig helt mod spillet. En lille rytme, der letter byrden ved at tælle."},"ICON-2427":{"nm":"Resultattavle-kabeldæksel","de":"Bag det strålende lys ligger der altid sammenfiltrede, rodede ledninger. Arbejdet med pænt at dække det rod til. Kun når det usynlige holdes ordentligt, kan det synlige endelig stråle."},"ICON-2428":{"nm":"Taktiktavle-viskebørste","de":"Når én runde er slut, rydder den fladen for det næste billede. En ny strategi kan kun nogensinde begynde på et tomt sted. Viskebørsten er, i sandhed, det første penselstrøg i den næste plan."},"ICON-2429":{"nm":"Resultatflag-clips","de":"Den griber om et flag, der er ved at flyve væk i vinden, og slipper ikke. Så det flagrende stof holder sin plads. Selv arbejdet med at kundgøre resultater for verden har først brug for en hånd, der holder det fast."},"ICON-2430":{"nm":"Dommerfløjte-snorclips","de":"Ved ét fløjtestød standser kampen og flyder igen. En lille knude, der fæstner den autoritet fast om halsen. Indtil fløjten lyder, er det også denne clips' opgave at holde stilheden pænt bundet."},"ICON-2431":{"nm":"Målebånd-oprulning","de":"Den samler den udmålte længde tilbage ind i sig selv. At måle er, i sidste ende, gentagelsen af at rulle ud og rulle sammen. Et håndtag, der uden knurren hjælper med den enkle tur frem og tilbage, og som drejer hver gang bag ved præcisionen."},"ICON-2432":{"nm":"Dommerflag-foldeetui","de":"Flaget, der bestemt skilte inde fra ude, foldes pænt sammen og hviler, når kampen er slut. Selv det tydelige signal trækker vejret et øjeblik til det, der kommer næste gang. Selv beslutsomhed har sin stille hvile."},"ICON-2433":{"nm":"Stopur-hængeløkke","de":"Den hænger den flydende tid ét sted, ikke om håndleddet. Stille før målingen, så farende af sted i det øjeblik den kaldes – en station for tiden. Et lille hjem for sekunder, der holder vejret og venter på startsignalet."},"ICON-2434":{"nm":"Baneoptrækker-hjul","de":"Overalt hvor det ruller, står en klar, hvid sti tilbage. Reglernes grænser indridses sådan i jorden, én rund tur ad gangen. Før kampen begynder, hjulet der først sætter sit fodspor på banen."},"ICON-2435":{"nm":"Dommerkort-lomme","de":"I afgørelsens øjeblik sover kortet, der trækkes frem fra brystlommen, her. Ventesalen for en kendelse, der forbliver tavs helt til den vises frem. En lomme, altid klar og ventende, i håb om aldrig at blive taget i brug."},"ICON-2436":{"nm":"Vægtlod-holder","de":"Arbejdet med at veje er kun ærligt på et gulv uden rystelser. En holder, der bærer loddet, mens den selv byder sin egen krop fladt frem. Det første skridt mod nøjagtig måling begynder altid fra et roligt sted."},"ICON-2437":{"nm":"Startklikker","de":"Ved én enkelt lyd skubber alle fødder samtidig fra jorden. Starten er ganske kort, men hånden, der skaber den korthed, er roligere end nogen anden. En hånd, der løser startlinjens sitren med blot ét klik."},"ICON-2438":{"nm":"Banekegle-fod","de":"Navnet er ukendt, men opgaven er klar – den bærer tungt midten af en bane, der er som en scene. I midten, hvor alle skinner, er der altid ét usynligt ben, der stille holder stand."},"ICON-2439":{"nm":"Mavevejrtrækning-bæltespænde","de":"En god lyd kommer ikke fra halsen, men fra dyb vejrtrækning, og det er taljen, der ved det først. Et spænde, der lader din håndflade mærke maven svulme og synke. Sangens udgangspunkt ligger altid under netop dette ene åndedrag."},"ICON-2440":{"nm":"Åndedræts-fjerplade","de":"Når fjeren svajer ved din ånde, er det tegn på, at vejrtrækningen er jævn. Den giver mildt form til den usynlige ånde og lærer sangens grundlag. En øvelse, hvor man med øjnene lærer ånden før den første tone."},"ICON-2441":{"nm":"Indånding-timeglas","de":"Inde i glasset flyder sandet ned som et åndedrag. Træk vejret ind, hold en kort pause, pust langsomt ud – kornene tæller rytmen for dig. Betragt roligt det lydløse faldende sand et stykke tid, og pludselig falder din forstyrrede vejrtrækning i ro."},"ICON-2442":{"nm":"Stearinlys-øvestativ","de":"Tænd vægen, og stemmen skælver med i takt med den flakkende flamme. Nogen udskar dette sted med omhu, til at bære den lille skælven et øjeblik. Lige så tykt som voksen, der størknede og lagde sig i lag, samler her de nætter, man sang alene."},"ICON-2443":{"nm":"Mavetryk-hyndestrop","de":"I stedet for at lægge en hånd på maven presser en enkelt strop stille det sted. Den strammes, når åndedraget svulmer, og løsnes blidt, når det er helt tømt. En tavs lille følgesvend ved din side, der hjælper kroppen med først at huske rytmen."},"ICON-2444":{"nm":"Åndedræts-ballonhætte","de":"Pust ikke ballonen op på én gang. Langt, langsomt, skub den helt til enden. Mens du bider i hætten og lader luften ud, når luften helt ned i lungernes dybeste del. En sang flyver, i sidste ende, lige så langt som længden af den ånde, du holdt."},"ICON-2445":{"nm":"Åndedræts-greb","de":"Jo mere hjertet vakler, desto mere vil hånden gribe fat om noget. Tag fat i dette greb, og skuldrene glider ned, indåndingen bliver et håndsbredde længere. At lære at gribe er at lære at samle sig selv, det ved håndfladen først."},"ICON-2446":{"nm":"Mavemuskel-vibrationsløkke","de":"Hægt båndet på løkken, og en mild vibration breder sig til midten af maven. Kraft samler sig stille netop dér, hvor det ryster, når du ler højlydt. Et fast centrum vokser altid langsomt sådan, et sted ingen ser."},"ICON-2447":{"nm":"Indåndingstæller-skive","de":"Én, to, tre – hver gang skiven klikker et hak videre, indridses dybden af den ånde, du trak. Ét hak mere, og sangen holder én frase længere. På denne lille skive nedskrives stille den lungekapacitet, du opbyggede i dag."},"ICON-2448":{"nm":"Tungeøvelse-skeplade","de":"Stederne, hvor tungespidsen skal lande, er tydeligt afmærket på pladen. Hvordan man ruller, flikker og holder pause et øjeblik. Bag en glat, flydende udtale ligger utallige daggryr, hvor tungen lærte sin vej udenad, netop sådan."},"ICON-2449":{"nm":"Mundform-spejlclips","de":"Clipsen holder blidt fast i mundformen, der spejles i glasset. 'A' er rund, 'i' strækker sig lang til siderne. En stille lektion for kun dig og spejlet, hvor du finpudser lydens form, mens du ser dit eget ansigt lige i øjnene."},"ICON-2450":{"nm":"Udtale-korksæl","de":"En lille sæl udskåret i kork sidder i hjørnet af skrivebordet og lytter til udtalen. På nætter, hvor 'r'et bliver ved med at glide, og modet synker, siger sælens runde øjne stille: Det er okay, lad os prøve bare én gang til."},"ICON-2451":{"nm":"Sangtekst-åndedrætsnål","de":"Hvor i teksten man skal trække vejret – det fortæller denne nål først. Stik den fast for enden af en linje, og stedet bliver sangens milde pausetegn. For at synge frit har selv en sætning brug for et mellemrum til at få luft."},"ICON-2452":{"nm":"Diktionsøvelse-hagestøtte","de":"Blot ved at støtte hagen let, finder udtalen, der var ved at gå i opløsning, sin plads igen. Klar tale er ikke munden alene – den skabes af hage, hals og åndedræt sammen. Denne lille støtte hjælper stille med den vanskelige balance."},"ICON-2453":{"nm":"Vokal-mundformstativ","de":"A, e, i, o, u – en ramme, der viser, akkurat som de er, de baner, de fem vokaler tager ud af munden. Sæt den stille ved siden af spejlet, og form lydens skelet hver dag. Enhver sangs grundstruktur begynder, i sidste ende, fra netop disse fem vokaler."},"ICON-2454":{"nm":"Tungevridekort","de":"Et kort så indviklet, at tungen snubler undervejs, og latteren til sidst bryder ud. Det er helt i orden at tage fejl – at tage fejl er selve øvelsen. Hver gang du kommer forbi denne drilske sætning, vågner endnu en lyd klar og tydelig."},"ICON-2455":{"nm":"Læbeløsner-prop","de":"En opvarmning, der lader læberne dirre for at vække en stiv mund. Bid i proppen, og lad luften strømme langt ud, og de sovende læber løsnes bløde. Den mindste, venligste opvarmning til blidt at åbne den første frase."},"ICON-2456":{"nm":"Sangtekst-elastik","de":"Vikl et gummibånd om det stykke, der bliver ved med at drille dig. Hver gang du ser stedet om håndleddet, kommer dagens bjerg at bestige i tankerne. Jo sværere passagen er, desto oftere kigger du på den, desto længere bærer du den i hjertet."},"ICON-2457":{"nm":"Halstørklæde-krog","de":"Så halsen ikke bliver hæs i morgenluften ved årstidsskifte, hænges tørklædet fast på krogen. Kun fra en varmt indpakket hals løsnes en klar lyd endelig. At beskytte stemmen begynder altid med først at passe på halsen."},"ICON-2458":{"nm":"Stemmebånd-rullertip","de":"Når rullertippen langsomt ruller hen langs siden af halsen, vågner stemmebåndene, der har sovet hele natten, stille op. En let vibration løser den stive spænding, og den tøvende første tone blødgøres. En berøring, der varmer kroppen op før sang."},"ICON-2459":{"nm":"Nynne-kopunderlag","de":"Med lukkede læber, mumlende nynnende, hold en dampende varm kop med begge hænder, og halsen varmes med. En dyb nynnen breder sig rundt over underlaget. Sådan begynder en sang, fra én slurk lunken varme."},"ICON-2460":{"nm":"Halspastil-kapsel","de":"Til dage hvor halsen synker ru og kradsende, samles pastiller stille inde i kapslen. Rul én i munden lige før du går på scenen, og kølende mynte åbner den blokerede hals. Lidt trøst til nødstilfælde, opbevaret i en lille æske, kun din egen."},"ICON-2461":{"nm":"Damp-halspose","de":"Vikl posen, fint gennemtrukket af varm damp, om halsen, og de stive steder efter lang øvelse smelter blødt bort. Med samme hygge som et nybagt varmt håndklæde rækker den stille et taktslag hvile til trætte, sunkne stemmebånd."},"ICON-2462":{"nm":"Stemmehvile-timeglas","de":"Det stille løfte om ikke at tale i dag tælles roligt op af tynde korn. At lukke munden en stund og skåne stemmen. Den stilhed, som også er den bedste omsorg af alle, flyder langsomt her."},"ICON-2463":{"nm":"Opvarmnings-læbetrillprop","de":"En læbetrille, der bevæger sig op og ned ad tonerne, mens læberne flagrer let. Bid blidt i proppen, og den uregerlige dirren falder til ro og bliver langt jævnere. Et håndfladestort redskab, der blidt fastgør den første knap i stemmedannelsen."},"ICON-2464":{"nm":"Halsfugt-sprayhætte","de":"Så halsen ikke tørrer helt ud på en udtørret scene, trykkes hætten, og en fin tåge sprøjtes ud. Tag ét dybt åndedrag af den fugtede luft, og den udtørrede stemme genvinder sin klare glans."},"ICON-2465":{"nm":"Stemmeløsner-vibrationsbold","de":"Hold den fint dirrende bold stille i håndfladen, og vibrationen stiger blidt op ad armen til halsen. En rund, venlig opvarmningsven, der forsigtigt ryster stemmeorganerne, blevet stive af spænding, vågne."},"ICON-2466":{"nm":"Formationsmærke","de":"Ét lille mærke stukket fast ned i scenegulvet. Her er din plads, der henne er min. Når mange samles for at tegne ét fælles billede, holder det stille alle på plads – et usynligt løfte om, at ingen spredes."},"ICON-2467":{"nm":"Bevægelsesretning-pilechip","de":"En pilespids-formet chip peger tydeligt på retningen af næste skridt. Hvor der skal drejes, hvor der skal standses – gulvet fortæller det først, så man ikke farer vild. En bevægelsesbane er et kort, tæerne har lært udenad ved at træde det utallige gange."},"ICON-2468":{"nm":"Formationscenter-nål","de":"Det ene punkt, der stille bliver referencen, når mange samles. Om denne nål tegnes en rund cirkel, og formationen folder sig vidt ud. Selv spredte bevægelser finder deres orden, blot med ét midterpunkt."},"ICON-2469":{"nm":"Krydsningspunkt-kile","de":"Hvor to veje mødes ét sted, bankes en kile fast ned. Så de ikke støder sammen, så de ikke krydser og kolliderer. Selv i det åndeløse, flygtige øjeblik, de passerer hinanden, mister ingen deres vej."},"ICON-2470":{"nm":"Afgangsretning-flag","de":"Når den sidste tones eftermæle forsvinder, glider man stille ud i den retning, flaget peger. Det må ikke være mere ujævnt at gå ud end at komme ind. Selv scenens afslutning har en retning, aftalt på forhånd."},"ICON-2471":{"nm":"Afstandsmåler-clips","de":"Grib fast om målebåndets ende med clipsen, og ét spand, så endnu ét, bliver ufejlbarligt nøjagtigt. Selv afstanden mellem person og person tilpasses pænt, som var den målt med en lineal. Et smukt tableau fødes altid af netop sådanne omhyggelige fingerspidser."},"ICON-2472":{"nm":"Retningslinje-snorløkke","de":"Hægt snoren på løkken, og stram den ud i én linje, og den tynde streg bliver standarden, alle stiller sig lige efter. At en række ser så velordnet ud skyldes netop denne ene rette, usynlige linje."},"ICON-2473":{"nm":"Bevægelsesrute-prikbrik","de":"Brikker, der stille tegner en sti på gulvet med en prikket linje. Følg disse svage mærker, og du farer ikke vild selv i mørket. Mens prik forbindes med prik, samler spredte fodtrin sig til én sammenhængende strøm."},"ICON-2474":{"nm":"Positionstegnestift","de":"En tegnestift trykket fast ned i gulvet, så man ikke glemmer sin plads. Selv i det bælgmørke føler tæerne sig frem til den lille knop og finder den ufejlbarligt. Først når man standser præcis på det ene punkt, vælter lyset endelig ned ovenfra."},"ICON-2475":{"nm":"Halsisolerings-fokusbånd","de":"Svajer hagen med, ryster stemmen med og går i opløsning. For at mestre kun at bevæge halsen, mens hovedet holdes stille, vikles båndet på. Bag en bevægelse, der virkede helt fri, ligger denne stille øvelse i at adskille."},"ICON-2476":{"nm":"Skulderfiksering-hyndeclips","de":"Så skuldrene ikke hopper efter forgodtbefindende, holdes hynden stille fast med en clips. Så kroppen tydeligt skelner mellem, hvor den skal svaje, og hvor den skal stå stille. En afdæmpet linje fødes altid af netop sådanne små holdegreb."},"ICON-2477":{"nm":"Ribbenssensor-bæltespænde","de":"Bæltet aflæser stille den fine bevægelse af ribbenene, der spreder sig og trækker sig sammen igen. Spænd spændet, og åndedragets bevægelse føres tydeligt helt ud til fingerspidserne. Dyb, solid stemmedannelse udspringer fra denne usynlige bevægelse i knoglerne."},"ICON-2478":{"nm":"Hoftesving-pendul","de":"Pendulet svinger langsomt fra side til side og fortæller stille om den rytme, hofterne tegner. Hvordan kroppens centrum forskyder vægten, lærer et håndfladestort lod dig uden ord. At selv svajen har sin egen struktur."},"ICON-2479":{"nm":"Håndledsrotation-løkke","de":"Hægt løkken om håndleddet, og drej langsomt indad, så udad, og leddene, stive efter natten, løsnes bløde. For en bevægelse, der når levende helt ud til fingerspidserne, skal håndleddet først blive smidigt. Denne lille rotation åbner for et større udtryk."},"ICON-2480":{"nm":"Ankelmodstand-ringsnor","de":"Sæt ringen om anklen, og træk i snoren, og for hvert skridt du tager, fanges en mild modstand ved tæerne. Lige så tungt du træder, samler kraften sig stille i benene. Et fjerlet spring står altid på netop sådan en tung øvelse."},"ICON-2481":{"nm":"Kerne-fokussandsæk","de":"Først efter at have viklet den om maven finder man endelig ud af, hvor kroppens allermidte var. Mens vægten trækker i skuldrene, finder det vaklende centrum langsomt sin plads, og hvor den pakkes ud, står én oprejst holdning tilbage."},"ICON-2482":{"nm":"Rygsøjle-justeringshætte","de":"Når en lille hætte rører en ryg, der har levet krum hele dagen, føles det som om nogen forsigtigt retter skuldrene ud. Man kan sagtens klare sig krum, men at stå ret er en øm kunst, man må lære sig langsomt igen."},"ICON-2483":{"nm":"Muskelafslapning-tryklegeme","de":"Tryk hårdt på et sted, der har sat sig i knude, og først svier det, siden lindres det snart. Ligesom varmen fra bedstemors håndryg, der gned ryggen som barn, er det at løsne op at holde ud med lidt mere smerte, mens man bliver ved siden af."},"ICON-2484":{"nm":"Spejlvinkel-justeringsskrue","de":"Vrid det blot en håndflades bredde, og spejlet spejler et helt andet ansigt. Med én omdrejning af skruen skråner og retter verden sig op igen, så det ser ud til, at selv at møde sig selv kræver en stille sigten."},"ICON-2485":{"nm":"Spejlafdugning-tørrepude","de":"Foran et spejl sløret af varm damp mister mennesket et øjeblik sit eget ansigt. Én stryg hen over det, og ansigtet vender tilbage. Takket være denne berøring, der fjerner disen, møder jeg mig selv igen hver morgen."},"ICON-2486":{"nm":"Trebensstativ-fodgummi","de":"Ved stativets fodspids afgør ét neglestort stykke gummi billedets skæbne. Dets tag i gulvet dæmper rystelsen, så et roligt billede altid begynder stille fra en usynlig friktion."},"ICON-2487":{"nm":"Vinkelreference-gitterfilm","de":"De fine gitterlinjer på filmen er som støttehjul for øjet. Jo mere komposition sætter sig i hænderne, desto mere forsvinder linjerne stille, og kun fornemmelsen bliver tilbage. Sporene af det lærte bliver mere usynlige, jo mere modne de bliver."},"ICON-2488":{"nm":"Optagelsesstart-fodpedal","de":"For en person med begge hænder fulde af ting var den sidste finger altid tåen. Tryk let på den, og optagelsen begynder – bag scenen klares husholdningen dygtigt, helt ud til tåspidsen."},"ICON-2489":{"nm":"Lysretning-clips","de":"Hvor lyset falder, hviler i fingerspidserne på denne neglestore clips. Arbejdet med at flytte en skygge et håndsbred og fremhæve en kontur – over den bitte forskel tøver nogen længe og grundigt."},"ICON-2490":{"nm":"Videosammenligning-skærm","de":"Sæt i går og i dag side om side, og først da åbner forandringen munden. I det øjeblik skærmen glider ned, blotlægges den tid, der er krydset imellem, ærligt på skærmen."},"ICON-2491":{"nm":"Fjernbetjening-håndledsrem","de":"Vikl én snor om håndleddet, og hjertet, der bekymrede sig om at tabe den, slappes af. En lille sikkerhedsanordning gør faktisk hånden friere – et ømt paradoks, hvor det, der er bundet, giver sindet ro."},"ICON-2492":{"nm":"Objektivdæksel","de":"Mens kameraet hviler, lukker objektivet også stille sit øje. I en verden, hvor et enkelt støvfnug efterlader et ar på skærmen, er det at dække blidt til et ønske om at værne om det længe."},"ICON-2493":{"nm":"Mundvig-løftebånd","de":"Løft mundvigene en anelse, og et stift udtryk løsner sig langsomt op. Et smil er, i sidste ende, også en muskel – først låner man redskabets kraft, og en morgen smiler man lyst af egen kraft."},"ICON-2494":{"nm":"Kindmuskel-massagerulle","de":"Rul langsomt indersiden af kinden løs, og ordene flyder langt mere jævnt frem. En stille forberedelse, der blidt vækker ansigtet før sang. Varm udtrykket op, og det bliver varmere med."},"ICON-2495":{"nm":"Smilevinkel-målelære","de":"Kameraet ved, at selv et smil har sin rette vinkel. Måler man det frem og tilbage med målelæren, indser man til sidst: det smukkeste smil blomstrer fra en oprigtighed, der slet ikke kan måles."},"ICON-2496":{"nm":"Øjenbrynsbevægelse-clips","de":"Rør et øjenbryn blot 1 millimeter, og hjertets hele struktur skifter. En clips, der stille holder fast i udtrykkets mindste del – skuespil er fingerspidsernes arbejde med at tæmme netop sådan finhed."},"ICON-2497":{"nm":"Kindben-løftesticker","de":"Løft kindbenet en anelse og fæst det, og et sted, hvor lyset dvæler, opstår i ansigtet. Dybden, som ét neglestort klistermærke skaber – i scenemakeup gemmer sig usynlige hemmeligheder som denne."},"ICON-2498":{"nm":"Blinke-øjenklap","de":"Dæk det ene øje til, og hjertet samler sig helt i det øje, der er tilbage. At øve blink er, i sidste ende, at lære at skjule halvdelen med ynde. Der findes bestemt udtryk, der bliver tydeligere, netop fordi de er tildækket."},"ICON-2499":{"nm":"Mundform-formclips","de":"Ga, gya, geo… tilpas munden til formen, og den utydelige udtale bliver klar. At hver vokal er en holdning for ansigtet, indprenter man langsomt i kroppen foran spejlet."},"ICON-2500":{"nm":"Udtryks-opvarmningspose","de":"Lige før man går på scenen, en varm pose der blidt varmer ansigtet op. Ligesom kolde hænder gør et spil stift, gælder det samme for udtrykket. En lille sandhed bag scenen: selv et smil har brug for opvarmning."},"ICON-2501":{"nm":"Pandeglatter","de":"Bind et bånd om panden, og de dybt indgroede rynker glattes stille ud. En genstand der lader bekymringens furer hvile en stund. Under en glattet pande ser man lidt yngre ud."},"ICON-2502":{"nm":"Bladrefingerbøl","de":"En lille fingerbøl man tager på fingerspidsen, som vender siderne. Rytmen i at bladre gennem det tykke manuskript, side for side, bliver – uden man opdager det – historiens egen takt. Selv det at læse rummer en øm lille håndvane."},"ICON-2503":{"nm":"Følelsesfarveflag","de":"Glæde er gul, sorg er blå. Farvelæg hjertet og hejs et flag, og den usynlige følelse tager form, mens den blafrer i vinden. Følelser kan også tegnes frem med hånden på denne måde."},"ICON-2504":{"nm":"Replikbetoningsklemme","de":"'Læg vægten på dette ord,' fortæller klemmen stille. Den samme replik skifter hele sin betydning med en enkelt betoning, så den er en lille markør der holder fast i talens tyngdepunkt."},"ICON-2505":{"nm":"Læsekommablok","de":"En blok lagt ned for at sige: 'hvil et taktslag her.' Et komma i replikkerne er ikke en standsning, men et åndedrag taget ind før de næste ord. Den der hviler godt, taler til sidst godt."},"ICON-2506":{"nm":"Åndedrætsklipbånd","de":"Båndet stiger og synker langs klipsen og tegner åndedrættets længde foran øjnene. At se og følge taktslaget af ind- og udånding – sangens begyndelse åbner altid med at mestre åndedrættet."},"ICON-2507":{"nm":"Følelsesterningpose","de":"En terning triller ud af posen og bestemmer dagens følelse. Kommer glæde op, så prøv at være glad; kommer vrede, så prøv at være vred. Skuespiløvelse bliver en leg, hvor hjertet overlades til tilfældet."},"ICON-2508":{"nm":"Manuskript-skråstativ","de":"Læg manuskriptet på det skråtstillede stativ, og du behøver ikke bøje hovedet. Denne lille skråning, der holder dig i øjenhøjde, plejer stille en nakke stiv af lang øvelse."},"ICON-2509":{"nm":"Hviskeskærm","de":"Et mærke der siger: hvisk herfra. Sænk stemmen bag skærmen, og salen holder tværtimod vejret og lytter opmærksomt. Scenens ømme paradoks: jo blødere du taler, desto større når det ud."},"ICON-2510":{"nm":"Rollebytte-tokenæske","de":"Vend en token om, og rollen du spiller skifter. I dag hovedrollen, i morgen en ven der står ved siden af. På en ø hvor alle vokser sammen, kommer turen til at stå midt på scenen til alle, en efter en."},"ICON-2511":{"nm":"Blikfikseringsprik","de":"Hvil roligt blikket på en lille prik ved siden af kameraet. I det øjeblik et vaklende blik lander ét sted, vågner øjnene på skærmen tydeligt til live. Et fast blik begynder, når alt kommer til alt, med at stå stille."},"ICON-2512":{"nm":"Vinkelmåler-trekant","de":"Når et hjørne af billedet på en eller anden måde ser skævt ud, holder du trekanten op, og svaret viser sig. Arbejdet med at rette op på det skæve. Før du stoler på dine øjne, prøv at stole på linealen et øjeblik."},"ICON-2513":{"nm":"Øjenhøjde-linsestativ","de":"Sæt linsen i øjenhøjde med personen, og skærmen lyver mindre. Hverken oppefra eller nedefra – først når man møder hinanden med samme øjne, fanges et upyntet, sandt udtryk."},"ICON-2514":{"nm":"Blikledende pilfjer","de":"Blikket glider stille i den retning fjeren peger. En lille pil der forsigtigt leder seerens øjne. Et godt billede peger venligt på, hvor man skal se hen."},"ICON-2515":{"nm":"Optagelsesrute-gulvchip","de":"Træd på ét punkt af en rute indøvet til den er slidt ind, og næste plads ligger straks lige for hånden. Fodtrinene der vandrer scenen rundt, er en usynlig vej dannet ved at forbinde sådanne små markører, prikket ud over gulvet."},"ICON-2516":{"nm":"Kameraafstands-målebånd","de":"Mål afstanden mellem motiv og kamera med båndet. I en verden hvor et håndsbred skiller fjernt fra nært, bliver målebåndet en stille vagtpost der vogter grænsen mellem sløret og skarpt."},"ICON-2517":{"nm":"Hovedvipnings-guide","de":"Hvor meget skal hovedet vippes for at se mest ømt ud? Følg guiden, og du kommer stille til at vide det – vinklen på en vipning ligner til forveksling, hvor meget hjertet åbner sig."},"ICON-2518":{"nm":"Øjenkontakt-håndspejlklemme","de":"Sæt et håndspejl ved kameraet med klemmen, og du ser dine egne øjne, mens du møder dine. En lille anordning der forsigtigt bygger en bro af blikke mellem jeget i spejlet og dig på skærmen."},"ICON-2519":{"nm":"Optagelsesindikator-lampe","de":"Når lyset tændes, er det signalet om at optagelsen er i gang. Én lille lampe samler den ophidsede sets spænding i ét. Fra det øjeblik lyset er tændt, falder alles vejrtrækning i takt."},"ICON-2520":{"nm":"Reaktionsklokke-knap","de":"Tryk på knappen, og en klar klokke ringer skarpt og lyst. Som bifald der brister ud efter en god scene, ligger nogens varme ord om 'godt gjort' gemt inde i denne lille klokke."},"ICON-2521":{"nm":"Hurtigtræknings-lodkrukke","de":"Ryst den, og træpindene rasler og vækker stemningen først. Hvem der åbner scenen afgøres af ét knips med håndleddet – den udtrukne smiler flovt, de andre trækker vejret lettet. Selv at dele held har sine venlige regler."},"ICON-2522":{"nm":"Lydeffekt-rystebjælde","de":"Vip håndleddet en anelse, og klingeling – en tilskyndelse blander sig. Denne lille bjælde fylder hullet, før stilheden bliver akavet. Til at tælle latterens takt er denne altid et skridt foran."},"ICON-2523":{"nm":"Overraskelseskasse-låg","de":"Før det åbnes, kan ingen gætte hvad der er indeni. Det er dette lågs eneste opgave. Så skrig og latter kan bryde ud sammen i det øjeblik det springer op, hænger det spændingen på et enkelt hængsel."},"ICON-2524":{"nm":"Reaktionsfoldevifte","de":"Lyden af at slå den op bliver i sig selv et svar. Viftens ribben vifter i stedet den beundring der ikke nåede at blive sagt. Mellem bevægelserne at folde og folde ud går begejstring frem og tilbage, og en strime følelse svajer med vinden."},"ICON-2525":{"nm":"Straffe-rouletteskive","de":"Ingen ved på forhånd hvilket felt nålen stopper på. Jo langsommere hjulet drejer, desto hurtigere banker hjertet den modsatte vej – klik, og der hvor det stopper, er dagens tåbelige skæbne skrevet. Nogle sekunder hvor selv skælven er sjov."},"ICON-2526":{"nm":"Udråbstavle med talebobbel","de":"Løft den højt over hovedet, og 'Wow' rejser sig som bogstaver. Et enkelt stykke papir overhaler hjertet og råber det, munden ikke kunne følge med. For selv en reaktion har brug for lidt sceneinstruktion."},"ICON-2527":{"nm":"Frys-håndflag","de":"I det øjeblik flaget hejses, fryser alle fast, netop hvor de står. Et signal der låser selv vejrtrækningens lyd fast i et stillbillede. Når det sænkes igen, vælder den fastfrosne latter ud på én gang."},"ICON-2528":{"nm":"Vrøvlesvar-klemmebalje","de":"Jo mere tåbeligt svaret er, desto fastere klemmes det op og hænges frem. Når de forkerte svar, hængt på snoren, svajer i vinden, bliver det en scene hvor forbistringerne elskes højere end de rigtige svar. Et billede af en dag hvor det er helt i orden at tage fejl."},"ICON-2529":{"nm":"Holdningsrettende rygstøttekile","de":"I det øjeblik du læner ryggen mod den, famler den krumme rygsøjle sig stille frem mod sin egen vej. Én lille kile der bærer, uden et ord. God holdning, fortæller den blidt bagfra, bliver først bekvem, når nogen er der til at støtte den."},"ICON-2530":{"nm":"Bækkenjusterings-støtteblok","de":"En lille fasthed anbragt under fødderne, når tyngdepunktet vakler. Kroppens balance stiger, når alt kommer til alt, langsomt op fra gulvet. En navnløs birolle der bærer holdningen fra et usynligt sted."},"ICON-2531":{"nm":"Mavestrammende balancebold","de":"Sæt den mod maven og stram forsigtigt til, og det spredte centrum samler sig i ét punkt. Jo dybere du styrer vejrtrækningen, desto fastere bliver bolden, og kroppen generobrer, ånd for ånd, den akse den havde glemt."},"ICON-2532":{"nm":"Rygsøjlekurve-tjekliner","de":"Læg linealen langs ryggen, og den usynlige krumning viser sig på skalaen. At stå ret handler ikke om at udviske krumningen – det handler om at aflæse selv den lille bøjning med ømhed."},"ICON-2533":{"nm":"Skulderstrækkende elastikring","de":"Hægt den om skuldrene og træk langsomt, og det sammenkrøbne bryst åbner sig vidt. Elastikken hvisker altid: kom tilbage til din plads, og ryggen, krum en hel dags slid, retter sig lidt efter lidt ved det milde kald."},"ICON-2534":{"nm":"Kernemuskel-sandpose","de":"Bind den om taljen, og de tunge sandkorn vækker den sovende kerne. Selv en let bevægelse bliver på et øjeblik alvorlig foran denne vægt. Jo mere man holder ud, desto stærkere bliver man – hvert eneste korn fortæller det stille."},"ICON-2535":{"nm":"Halebensstøtte-pudemærke","de":"En pude der forsigtigt støtter under halebenet, med et lille mærke hængende fra enden. Et redskab som en øm lille seddel, skrevet og sat fast til en dag udmattet af langvarigt sidderi: 'Du kan læne dig her et øjeblik.'"},"ICON-2536":{"nm":"Lændestøtte-vinkeltrefod","de":"Stående støt på tre ben holder den stille vinklen som lænden kan læne sig imod. En støtte der stille glider ind i en holdning ved at bryde sammen. Til at holde fast i det der vakler, er tre punkter overraskende nok tilstrækkelige."},"ICON-2537":{"nm":"Hagetræk-holdningsklemme","de":"Træk hagen let ind og støt den, og halslinjen der var kommet ud af facon finder sin plads. Den fingerstore klemmes brok er på en eller anden måde øm. Hvordan man holder hovedet ret, det lærer dette lille redskab."},"ICON-2538":{"nm":"Fodtrin-stigebånd","de":"Båndet spredt ud på gulvet tegner, felt for felt, de ruder fødderne skal træde i. Træd ærligt felt for felt, og før du ved af det, er trinene ridset ind i kroppen. En vej bliver, jo mere man træder den, kun tydeligere."},"ICON-2539":{"nm":"Retningsskifte-konechip","de":"Stil den op, og den er en lille markør der siger 'drej her.' Den forærer et hjørne til fødder der kun nogensinde løb lige ud. Selv vejen der drejer ind, gemmer sin egen rytme."},"ICON-2540":{"nm":"Etbens-vippebræt","de":"I det øjeblik du stiller dig op på ét ben, vipper brættet en anelse. De få sekunder brugt på at kæmpe mod vaklen er balancens mest ærlige lektion. Tæerne der kæmper for ikke at falde, fortæller hele historien."},"ICON-2541":{"nm":"Reaktionshastigheds-blinklys","de":"I det øjeblik signalet tændes, kæmper hånd og øje om at være først. Det blinkende lys giver ikke plads til tøven. En hurtig hånd bevæger sig altid et halvt taktslag foran tanken."},"ICON-2542":{"nm":"Zigzag-fodmarkør","de":"Små prikker klistret skråt på gulvet, der leder fødderne til at danse i zigzag. Sværere end en lige linje er altid det forskudte. Vandr efter prikkerne, og de hurtige fodbevægelser modnes dygtigt."},"ICON-2543":{"nm":"Balance-line-flad stang","de":"Sæt fødderne på den slanke stang, og verden indsnævres til et enkelt reb. Som en linedanser der træder på luften, samler du hele din koncentration på en håndsbred plads. Balancen bliver, jo smallere den bliver, kun tydeligere."},"ICON-2544":{"nm":"Smidighedsarmbånd med studsbold","de":"Bær det på håndleddet, og en lille bold springer studsende tilbage. I øjeblikket at kaste og gribe indridses reaktionens hastighed i fingerspidserne. Hurtighed er, når alt kommer til alt, ikke at gå glip af det der kommer tilbage."},"ICON-2545":{"nm":"Fodhurtigheds-hulahopring","de":"Hægt den på foden og sving rundt, og hularingen bliver ved med at ægge lægmusklen. I det øjeblik man stopper, falder den, så foden vipper uden hvile. Mens man bevæger sig som i leg, modnes fodarbejdet hurtigt og smidigt."},"ICON-2546":{"nm":"Tåbalance-træsnurretop","de":"En top der snurrer på håndfladen, stopper død i det øjeblik den mister sit centrum. Som barndommens dage med at piske en top rundt i gården, er balance noget der kun kan stå, ved uophørligt at snurre."},"ICON-2547":{"nm":"Ankelbeskyttende strammesnor","de":"Vikl og stram om anklen, og det vaklende fodfæste bliver langt mere sikkert. Jo mere sårbart et sted, desto ømmere skal det holdes. En enkelt snor bliver trygheden i et enkelt skridt."},"ICON-2548":{"nm":"Knævarmende viklebånd","de":"Vikl det om et koldt knæ, og varmen siver ind mellem leddene. Et stift led bliver først smidigt, når det varmes op. Før man bevæger sig, den varmeste morgenhilsen man giver sin egen krop."},"ICON-2549":{"nm":"Muskelløsnende akupressurkugle","de":"Tryk fast på et sammenspændt sted, og kornene aer stille knuden. Den underlige trøst i, at det løsner sig, i takt med at det gør ondt. Selv stivhed en hånd ikke kunne nå, klapper denne lille kugle på i stedet."},"ICON-2550":{"nm":"Opvarmningsrækkefølge-hjul","de":"Væk kroppen fra det felt hjulet standser på. Hals, skuldre, ankler – overlad rækkefølgen til held, og hold hjertet let. Når leg blander sig i opvarmningen, smiler den stive krop stille først."},"ICON-2551":{"nm":"Ledvarmende varmepakning","de":"Læg en dampende varmepakning på leddene, og en lettelse som et varmt gulv om vinteren breder sig. Det er tiden hvor stive led løsnes i en døsig ro. Først når kroppen er varmet op, gør den sig langsomt klar til at bevæge sig."},"ICON-2552":{"nm":"Strækketrækkende håndtagsring","de":"Grib ringen og træk, og stive muskler strækkes langt ud. En stram samtale går mellem den holdende hånd og den udfoldende krop. Jo mere den strækkes, desto lettere vil morgendagens bevægelser føles."},"ICON-2553":{"nm":"Fodsålsstimulerende knopbræt","de":"Stå barfodet på knopperne, og de sovende fodsåler vågner med et sæt. Som den prikkende fornemmelse af at gå barfodet på en grusvej, stiger fornemmelsen af jorden op fra tæerne."},"ICON-2554":{"nm":"Skademeddelelses-magnetnål","de":"Skriv 'overanstreng dig ikke' og fæst det med et klik på pladen. Smertefulde minder falmer let, så du hænger det op foran øjnene med en magnet. Også omsorgen for kroppen begynder med en enkelt linje noteret ned."},"ICON-2555":{"nm":"Fasciløsnende knopstav","de":"Rul den knoppede stav langsomt, og den klæbende fascie løsnes et afsnit ad gangen. En berøring der forsigtigt skubber knuderne væk. En sammenspændt dag, udjævnet knude for knude på denne måde, bliver også meget lettere."},"ICON-2556":{"nm":"Gangline-gulvstrimmel","de":"Lagt lige ud på gulvet giver den fødderne en enkelt linje at følge. Selv en forpjusket gang retter stille sig op, når den lægges på denne linje. Tegn vejen, og fødderne farer ikke længere vild."},"ICON-2557":{"nm":"Skulderniveau-stang","de":"Lagt på tværs af skuldrene afslører den stille en balance vippet til den ene side. At være i vater betyder altid at sænke den ene side og hæve den anden. En enkelt stang peger blidt på en skæv vane."},"ICON-2558":{"nm":"Isse-balancelod","de":"For at loddet på issen ikke skal falde, må hele kroppen stå ret som en enkelt linje. Som det gamle syn af at gå med en vandkrukke balanceret på hovedet, sættes centeret fra det højeste punkt og ned."},"ICON-2559":{"nm":"Hagevinkel-støtte","de":"Støt hagen forsigtigt, og hovedet der bliver ved med at synke genvinder sin rette vinkel. En kort hvile lænet mod en enkelt støtte. En ret linje er først fuldendt, når nogen holder den oppe nedefra."},"ICON-2560":{"nm":"Skridtafstands-pæl","de":"Pælen slået ned i gulvet måler på forhånd, hvor fødderne skal lande. Ét skridt, hverken for bredt eller for smalt – den ærlige afstand. Gangens balance begynder stille ved denne lille markør."},"ICON-2561":{"nm":"Tåretnings-kile","de":"Det tøvende første skridt – tæerne vakler først over hvorhen. Når denne lille kile bestemmer retningen, læner hjertet sig blidt den vej med. At vælge sin vej er ikke en stor beslutning, men det håndsbred tæerne peger mod."},"ICON-2562":{"nm":"Rygopretningsbælte","de":"Den stemme der altid sagde 'ret ryggen, ret ryggen' synes at leve videre inde i dette bælte. Ret stille en krum dag op, og vægten der har hvilet på skuldrene bliver mærkeligt nok lidt lettere. Én god holdning rejser selv hjertet oprejst."},"ICON-2563":{"nm":"Vægtfordelings-fodplade","de":"Syv på venstre fod, tre på højre. Hvor man lægger vægten, afgør balancen. Fodpladen spørger stille – hvilken vej hælder du mod lige nu? At stå lige ret er i virkeligheden en uendelig justering."},"ICON-2564":{"nm":"Øjenhøjde-målstang","de":"Øjnene falder hele tiden ned mod tæerne. I de øjeblikke løfter en enkelt stang, rejst langt væk, langsomt blikket. At øve sig i at se langt er at øve sig i at nå langt, så i det øjeblik hovedet løftes, kommer selv et sted der virkede uopnåeligt, nærmere."},"ICON-2565":{"nm":"Bukkevinkel-kortklemme","de":"Femten grader, tredive grader, femogfyrre grader. Hjertet bukker lige så dybt som taljen folder sig. Vinklen skrevet på kortet er ikke bare et tal, men en lille skala der måler den oprigtighed man viser den anden."},"ICON-2566":{"nm":"Håndfoldnings-manerering","de":"Fold de to hænder pænt sammen, og et ophidset hjerte lægger sig roligt til ro ét sted. Denne lille ring fanger kærligt fingerspidser der ellers ikke vidste, hvor de skulle gøre af sig selv, og sætter stille hilsenens første holdning."},"ICON-2567":{"nm":"Rutepil-magnet","de":"Det en fortabt fod først kigger sig om efter, er en pil. En enkelt retning klikket fast med en magnet skærer tøven over og trækker blidt skridtene mod dér hvor man skal hen. Selv et vildfarent hjerte finder til sidst én retning."},"ICON-2568":{"nm":"Udgangsretnings-markørnål","de":"Vejen ud er sværere end vejen ind. Selv i mørket når lyset er slukket, peger denne klart lysende nål stille på den sidste rute. At man også skal gå godt af, hører med til scenen – det lærer man først til allersidst."},"ICON-2569":{"nm":"Formelt-buk-rækkefølgebånd","de":"Der var en tid, hvor rækkefølgen på hvem der bukkede først og hvem der bukkede sidst var tydelig. Bøj kroppen i den rækkefølge der står på båndet, og selv høflighed får en åre, og manerer får en strøm. Det er at holde hjertets rækkefølge."},"ICON-2570":{"nm":"Fodtrinsjusterings-magnetchip","de":"Falder én person ud af trit, vakler hele rækken. Som en chip der klikker fast, når tæerne rettes ind, betyder det at stå sammen, at man blidt afgiver sit eget skridt til den ved siden af. Fodtrin der falder i samme takt, er det mest trygge af alt."},"ICON-2571":{"nm":"Scenebuk-positionshestesko","de":"Selv en enkelt scenebuk har et sted at stå. Sæt fødderne på mærkerne, spredt rundt som en hestesko, og en første hilsen der blev ved med at gå skævt af nervøsitet finder endelig sin form. Kender man sin plads, lægger selv skælven sig lidt."},"ICON-2572":{"nm":"Taksigelses-håndtegnkort","de":"Taknemmelighed ord ikke kunne rumme helt, flyder ud gennem fingerspidserne. At tegne et hjerte, lægge en hånd på brystet – hvert enkelt håndtegn på kortet bliver en oversættelse af hjertet sat i bevægelse. Oprigtighed der længes efter at nå frem, har altid en form."},"ICON-2573":{"nm":"Kø-afstandskortpæl","de":"Selv det at stå i kø har en øm høflighed. Som en pæl der holder præcis et håndsbred til personen foran, begynder ventetid med den lille omtanke ikke at skubbe hinanden. At stå lidt fra hinanden er også omsorg."},"ICON-2574":{"nm":"Replikcue-vendering","de":"Når den næste replik bliver ved med at svæve på læberne, vender en finger stille et blad. De små papirer trukket på ringen presser roligt det bankende hjerte ned og folder rolig felten for hvad der skal siges næste ud. Nervøs som man er, brydes strømmen ikke."},"ICON-2575":{"nm":"Programrækkefølge-timeglas","de":"Se roligt på sandkornene der siler ned, og den næste rækkefølge falder stille på plads i sindet. Indtil det sidste korn falder, lærer dette lille glas dig at læse tiden med øjnene, uden at haste."},"ICON-2576":{"nm":"Mikrofongreb-øvestav","de":"Før det bliver en naturlig ting, vejer en tom stav tungt som tusind pund. Grebets vinkel, afstanden til munden, kraften i håndleddet – øvelse, at gribe og slippe utallige gange, blomstrer en dag pludselig ud i én naturlig bevægelse."},"ICON-2577":{"nm":"Udtalepind til tydelig tunge","de":"Ga, na, da, ra. Hold pinden i munden, og rul lydene rundt, indtil tungespidsen bliver klar. Et ord der krydser over, tydeligt og skarpt, er som en blomst der stille springer ud oven på hundredvis af sludrende, mumlende timer."},"ICON-2578":{"nm":"Cuetegn-håndflag","de":"Start, stop, hvil et taktslag. Et enkelt ordløst flag dirigerer scenens åndedræt. Fra en plads usynlig for salen holder en stille vinkende hånd hvert eneste taktslag uden et hul."},"ICON-2579":{"nm":"Sceneskifte-klokke","de":"En klar lille klingen, og scenen skifter. Som klokkelyden der bredte sig gennem et marked ved solnedgang, bærer denne lille klang et tøvende hjerte let over til næste indslag. Et skifte begynder altid med en lyd."},"ICON-2580":{"nm":"Talepustets taktpendul","de":"Træk vejret ind – én, to – og pust langsomt ud. Styr åndedrættet efter pendulet der svinger fra side til side, og ord der væltede for hurtigt frem finder snart deres takt igen. Talens fart var, når alt kommer til alt, åndedrættets fart."},"ICON-2581":{"nm":"Programmanuskript-foldeplade","de":"I én enkelt fold-og-fold-ud-bevægelse ligger hele dagens rækkefølge fuldt bevaret. I det øjeblik den slidte plade foldes ud, stiller et sind, forvirret over hvad der skal frem først, sig stille på række. Én udfoldning bringer orden i dagen."},"ICON-2582":{"nm":"Åndedrætstakt-timeglas","de":"Ind tre, hold fire, ud seks. Mens sandet flyder, flyder min vejrtrækning stille med. At tælle hvert åndedrag, ét for ét, er den ældste, kærligste måde at pleje et travlt selv på."},"ICON-2583":{"nm":"Meditationspudekvast","de":"Kvasten hængt fra pudens kant svajer stille uden en vind. Sæt dig i lotusstilling, og stilheden fra en gammel sjæl der beroligede sindet siddende på en træveranda, kommer blidt til din side, dvæler en stund, og går igen."},"ICON-2584":{"nm":"Åndedrætsroende håndklokkespil","de":"Når et enkelt vindpust passerer, klinger en klar lyd stille. Hængt som et vindspil under tagskægget slipper den én kølig, forfriskende dråbe ned over et sind der kogte af forvirring. Selv lyd har kraften til at afkøle."},"ICON-2585":{"nm":"Røgelsesrøg-opsamlingstallerken","de":"Røgen der bliver tilbage fra brændt røgelse, lægger sig langsomt ned på tallerkenen. Som duften der steg op foran bordet en helligdagsmorgen, dæmper en enkelt strime røg stille den urolige luft og fylder rummet med ro."},"ICON-2586":{"nm":"Ind-og-udåndingspendul","de":"Mit åndedræt bæres af et enkelt lod der langsomt stiger og synker igen. Svævende når jeg trækker vejret ind, synkende når jeg puster ud – på en dag hvor kroppen glemmer hvordan man ånder, lærer dette lille ur det hele forfra."},"ICON-2587":{"nm":"Meditationsklokke-kølle","de":"Slå klokken én gang, forsigtigt, og efterklangen breder sig langt ud. Som vindspilslyden der ringede gennem et bjergtempel, skyller det ene at lytte i stilhed, indtil klangen forsvinder helt ud i luften, ét hjørne af hjertet rent."},"ICON-2588":{"nm":"Åndedrætsvej-guidefjer","de":"Hold fjeren stille foran næsen, og åndedrættets usynlige vej bliver endelig synlig. En svag svajen betyder man ånder godt; stilhed betyder man har holdt vejret for længe. Det letteste kan somme tider være den mest ærlige vejviser."},"ICON-2589":{"nm":"Sindsberoligende rullesten","de":"Rullestenen i håndfladen er kold og glat. Som en sten der har rullet længe langs en flodbred, indtil den gav afkald på alle sine kanter, bliver de skarpe dele af et kogende sind gradvist rundslidt, mens fingrene bliver ved med at fingerere den."},"ICON-2590":{"nm":"Næseåndedræts-temperaturklemme","de":"Temperaturen ved næsespidsen fortæller stille åndedrættets dybde. Klemmen aflæser tavst luften der kommer kold ind og går varm ud, og viser tydeligt frem for øjnene den vejrtrækning man normalt ikke engang mærker. Selv åndedræt har et udtryk."},"ICON-2591":{"nm":"Humørvejr-klistermærketavle","de":"Er mit hjerte klart i dag, eller overskyet? I det øjeblik man vælger et lille klistermærke og trykker det fast på tavlen, bliver et humør, svært at sætte ord på, til en slags vejr og tager tydelig form. Hjertet har også brug for en vejrudsigt."},"ICON-2592":{"nm":"Følelsesfarve-håndstempel","de":"Glæde er gul, sorg er blå. Vælg en farve og tryk den fast ned på papiret, og hjertets nuance efterlades som et aftryk. Selv en følelse man ikke ved hvad man skal kalde, kommer farven først og genkender den stille."},"ICON-2593":{"nm":"Dagens-hjerte kronbladschip","de":"Læg forsigtigt hele dagens hjerte på et enkelt kronblad. Som azaleaer der drev afsted en forårsdag, spørger én chip, let og skør, stille ved enden af en falmende dag, hvordan du har haft det."},"ICON-2594":{"nm":"Heppe-talebobbelmagnet","de":"Ordene man vil sige, bliver ved med at svæve på læberne. I det øjeblik man trykker talebobbel-magneten fast, når et opmuntrende ord man ikke kunne sige højt, stille frem til nogens trætte dag. Sådan bliver hjertet formidlet."},"ICON-2595":{"nm":"Inderste-hjerte kuvertsegl","de":"Ord man ikke nåede at få frem, pakkes pænt ind i en kuvert og forsegles. Som en gammel sjæl der forseglede et brev med lim på fingerspidserne, holder ét segl det inderste hjerte trygt. Ventende stille på dagen hvor det skal tages frem og foldes ud."},"ICON-2596":{"nm":"Følelsestemperatur-blomsterknop","de":"En lukket knop, der møder varme, åbner sig ét forsigtigt lag ad gangen. Blomstrende idet hjertets temperatur stiger – hvor meget jeg er blevet varmet op i dag, ved denne blomst før ordene gør. Foråret kommer også til hjertet."},"ICON-2597":{"nm":"Selvros-håndspejlsrem","de":"Løft spejlet og mød stille dine egne øjne, spejlet i det. Det lille ansigt, hængt fra remmen, viser ikke dit ansigt, men gårsdagens dig, som fortjener et ord for at have holdt godt ud. Trøst var aldrig langt væk."},"ICON-2598":{"nm":"Humøransigts-stempelsæt","de":"Et strålende smil, tåreblanke øjne, en sur, truttende mund. Tryk udtryksstemplerne fast, og skriv hjertets dagbog. På en dag for overvældende til at sætte i skrift, taler et lille ansigt stille dagens humør i mit sted."},"ICON-2599":{"nm":"Følelsestrådring","de":"Uanset hvor sammenfiltret garnet er, viklet forsigtigt ud tråd for tråd, vender det til sidst tilbage til én enkelt tråd. Hæng forvirrede, kvælende følelser på ringen én ad gangen, og selv et hjerte man slet ikke kunne forstå, finder en tynd tråd at følge."},"ICON-2600":{"nm":"Søvnpose-duftsnor","de":"Fra duftposen hængt ved hovedgærdet spreder en mild urteduft sig stille. Som duften af bedstemor der lagde duftposer dybt i skabet, glider spændingen der har stået på højkant hele dagen, i søvn, mens du befamler snoren."},"ICON-2601":{"nm":"Søvnvendeplade","de":"En nat hvor du vendte og drejede dig og først faldt i søvn ved daggry. Vend liggestillingen forsigtigt, og gårsdagens uro glider stille over i morgenens friskhed. Hvile er også noget man øver sig på, siger denne lille plade uden et ord."},"ICON-2602":{"nm":"Måneskinsophæng til puden","de":"Et strejf lys, der sivede ind gennem gardinsprækken, hænges op ved pudekanten. En mat flod strømmer hen over det sovende ansigt, og selv en praktikants nætter, når mørket skræmte hende, blev endelig blidere. Det var den første lille trøst, hun nogensinde kendte."},"ICON-2603":{"nm":"Dagsform-knopchip","de":"Dagens tilstand er lukket som en blomsterknop. Tryk let på chippen, og den åbner sig langsomt – om du har sovet godt eller ej, det ved kroppen først. Selv den tøven, før den springer helt ud, er stille yndig."},"ICON-2604":{"nm":"Natlampens vægehætte","de":"\"Sluk ikke lyset.\" For den yngste, som var bange for mørket, satte nogen forsigtigt en hætte over vægen. Hverken for lyst eller for mørkt, et lille og ømt løfte om at våge blot indtil søvnen kommer."},"ICON-2605":{"nm":"Solsikkenål til morgenvækning","de":"Sæt den ved sengekanten, og den drejer stille hovedet, som en solsikke, mod den første solstråle. Selv på dage du ikke har lyst til at stå op, er der en grund til, at lyset kalder, og den fører morgenen i én retning."},"ICON-2606":{"nm":"Søvnurtebørste til pude","de":"Dyp børstespidsen i lavendel og kamille, og stryg den én gang hen over puden. Mens duften trænger ind i pudebetrækket, løsnes dagens spændinger langsomt ned fra dine skuldre. God søvn begynder med denne lille duft."},"ICON-2607":{"nm":"Dynehjørneklemme","de":"Ved daggry stikker tæerne bestandigt ud under dynen. Klem hjørnet fast med klemmen, og varmen kan ikke løbe sin vej hele natten. Det er en lille fastgørelse, sat i stedet for et \"sov godt\"."},"ICON-2608":{"nm":"Velværesten-kurv","de":"Én god ting om dagen, én håndfladestor sten. Jo tungere stenene samler sig i kurven, desto mere trygt vokser hjertet. At samle almindelige øjeblikke i hånden – sådan har lykken altid talt sig frem."},"ICON-2609":{"nm":"Forsætsstjerne-krukke","de":"Hver aften formes dagens forsæt til en stjerne og slippes ned i krukken. Når den bliver fyldt, bliver krukken en lille nattehimmel. Den engang tomme åbning ved det: løfter lyser først, når man samler dem."},"ICON-2610":{"nm":"Belønningsbolsje-ophæng","de":"Et bolsje du selv rækker dig efter en trættende dag. I det øjeblik du tager ét fra ophænget og putter det i munden, er det i orden, selv hvis ingen lægger mærke til det. En lille belønning er den mest ærlige opmuntring."},"ICON-2611":{"nm":"Klaret-i-dag-stempel","de":"Dyp den i blæk og tryk fast ned i notesbogen. \"Klaret i dag.\" En dag, der lykkedes, og en dag, der blot blev holdt ud, fylder det samme felt. Hver dag behøver ikke være perfekt – du skal bare ikke holde op med at trykke stemplet."},"ICON-2612":{"nm":"Hejaflags-sokkel","de":"Sæt den fast i jorden, og jo hårdere vinden blæser, desto kraftigere blafrer flaget. Selv det, der svajer, har brug for en hånd til at holde det oppe. Sådan holder hjertet, der hepper på nogen, fra neden."},"ICON-2613":{"nm":"Målfrø-plantekrukke","de":"Et mål reciteres ikke i ord, men graves ned i jorden. Mens du planter et frø, vander det og venter, forvandles utålmodigheden langsomt til rødder. Det, der gror i krukken, er ikke kun spiren."},"ICON-2614":{"nm":"Rosemærke-tavle","de":"Et klistermærke for hver god gerning. Jo mere farverig tavlen bliver, desto mere vender de dage, man skødesløst lod glide forbi, tilbage til live i farver. Som børn vidste vi det: ros bliver tydeligere, jo mere man klistrer den op."},"ICON-2615":{"nm":"Forsætsbånd-løkke","de":"En hånd, der trækker båndet gennem løkken og knytter en knude. Fast, så den ikke går op, men ikke for stramt. Et forsæt er netop som denne knude – strammes den for hårdt, brister den, er den for løs, glider den stille op."},"ICON-2616":{"nm":"Bedrifts-muslingechip","de":"Skriv en lille bedrift på en muslingeskal, du fandt ved stranden. Som et fragment, der er kommet så langt hertil, slebet og glattet af bølgerne, har din dag også rullet længe og skinner nu blankt. Alt, der udholder tiden, kommer til at stråle."},"ICON-2617":{"nm":"Belønningsmedalje-krog","de":"En hårdt vunden medalje hænges ikke i en skuffe, men i øjenhøjde. Vægten på krogen retter dine skuldre hver morgen. En belønning skal ikke gemmes væk, men hænges frem, så man kan se på den."},"ICON-2618":{"nm":"Dryp-kop til regnvejrsparaply","de":"Regntiden drypper ned af paraplyens spids. Sæt en kop under den, og entréen forbliver tør. Man kan ikke stoppe det, der styrter ned, men man kan bestemme, hvor det lander."},"ICON-2619":{"nm":"Varmekølepose","de":"Bag scenen midt om sommeren, en kølepose lagt let mod nakken. Den ophedede, stigende varme falder ét taktslag. \"Træk vejret.\" En hånd, der passer på mig før varmen gør, er betryggende."},"ICON-2620":{"nm":"Ventilatorvinge-klemme","de":"Selv voldsomt snurrende vinger falder stille til ro med en enkelt klemme. Jo kraftigere vinden er, desto mere har man brug for noget til at holde den fast. Hurtigt roterende ting bliver først sikre ved, hvem der holder dem stille."},"ICON-2621":{"nm":"Tørrestang til våde sko","de":"Regnvåde sko gør selv hjertet fugtigt hen over natten. Sæt stangen ind i dem, og til morgen er de tørre nok til at tage på igen. Det våde skal ikke smides ud, men tørres omhyggeligt."},"ICON-2622":{"nm":"Skraberist til gummistøvler","de":"Gummistøvler tilsølet med jord fra rismarken. Først når de er skrabet rene på pladen, træder du op på gulvet. At lade udenlivets mudder blive uden for døren, før man kommer ind – en gammel høflighed, der holder et hjem pænt."},"ICON-2623":{"nm":"Sommerflise-fodplade","de":"Bare fødder ved det først. Sætter du fodsålen mod flisen lagt på sommergulvet, viger middagsvarmen for en håndfuld køl. Selv én lille kulde gør en lang sæson til at holde ud."},"ICON-2624":{"nm":"Regnstopper til dørtærskel","de":"Blot en strimmel lagt på tærsklen, og regnvandet kan ikke længere trænge indenfor. En tynd streg, der skiller inde fra ude. Et sted, det er værd at værne om, klæder en snæver grænse bedre end en prægtig mur."},"ICON-2625":{"nm":"Myggespiral-tallerken","de":"En sommernat sættes myggespiralen på sin holder, og en skarp, men fortrolig røg stiger op. Som spiralen, der langsomt bliver mindre og mindre, dybner natten også langsomt. Det er duften fra de dage, hvor man lå på bænken og talte stjerner."},"ICON-2626":{"nm":"Køleærme-hægte","de":"Dæk armene, stukket af solen, med et køleærme. Fastgør det snugt til skjorteærmet med hægten, og selv arbejdet midt på dagen bliver til at holde ud. Køl er den lille venlighed at skygge et håndsbredt sted, hvor det rører."},"ICON-2627":{"nm":"Løvfejekost","de":"Fej de nedfaldne blade, der fylder haven, sammen i en bunke med håndkosten. En hel årstid rasler under fødderne. At rydde op i noget er også at tage kærlig afsked med det, man må lade gå."},"ICON-2628":{"nm":"Vinduesstøtte til udluftning","de":"Sæt en stang i det lummervarme værelse og hold vinduet på klem. Efterårsbrisen sniger sig ind og fører den gamle luft med sig ud. Udluftning er det lille åndehul, der stille bytter det, der har samlet sig indenfor, med det udenfor."},"ICON-2629":{"nm":"Agernpose-prop","de":"Fyld posen med agern, ligesom egernet, og luk munden med proppen. Fast, så ingen triller ud. Ønsket om at vogte det, man har samlet, er den gamle instinkt hos de små, der overvintrer."},"ICON-2630":{"nm":"Efterårsdyne-banker","de":"Hæng dynen, brugt hele sommeren, ud i haven og bank den kvikt med banketæppet. Duften af sollys spreder sig gennem støvet. At banke den gamle årstid ud, før man kan lægge den nye over sig – det husker håndleddet først."},"ICON-2631":{"nm":"Trækvindsnor til vindueskarm","de":"Stop den kolde træk, der siver ind gennem vinduessprækken, snugt med en enkelt snor. Én tynd streg vogter varmen i rummet til det sidste. En stor kulde begynder altid ved en lille sprække – det ved vinterforberedelsen."},"ICON-2632":{"nm":"Løvsi til tagrende","de":"En si lagt over tagrenden. Den filtrerer bladene rent fra og lader kun vandet løbe igennem. For at flyde uhindret må man bestemme, hvad der skal slippe igennem, og hvad der skal holdes tilbage, siger efterårets tagskæg."},"ICON-2633":{"nm":"Græsbundt-klemme","de":"Fastgør et bundt bendørt græs snugt med klemmen. En hånd, der binder de spredningsvillige sammen til ét. Selv hvor sommerens grønne helt er drænet ud, bevares nytten intakt, når man samler det."},"ICON-2634":{"nm":"Efterårsvind-temperaturpendul","de":"Når vinden blæser, svajer pendulet. På vidden af dets sving måler du, hvor dybt efteråret er blevet i dag. Temperatur er ikke et tal – den når først din hånd som noget, der svajer blidt."},"ICON-2635":{"nm":"Håndvarmerhylster til frakkelomme","de":"\"Kolde hænder.\" Håndvarmerhylsteret, gemt i frakkelommen, varmer stille de forfrosne fingre. Hjertet, der først tænker på en andens kulde, ligger altid stille inde i en lomme."},"ICON-2636":{"nm":"Kondensdryprand til vindue","de":"Randen opsamler stille de tårer, vintervinduet har fældet hele natten. En lille vandvej skabt af temperaturforskellen mellem inde og ude. Hvor forskellen er størst, flyder mest – det viser morgenvinduet hver dag."},"ICON-2637":{"nm":"Sikkerhedsnet til brændeovn","de":"Rejs et sikkerhedsnet foran den flammende ovn. Varmen tæt på, faren netop et håndsbredt væk. At holde ilden nær uden at brænde sig er den mest grundlæggende afstand i at passe på nogen."},"ICON-2638":{"nm":"Vinterdyne-holdeklemme","de":"Når den tykke vinterdyne bliver ved med at glide af, presser klemmen den ned og holder den på plads. Tung varme skal holdes fast for at gøre gavn. Vinternattens hygge vogtes så omhyggeligt."},"ICON-2639":{"nm":"Rudeskraber til rim","de":"Skrab rimen, der blomstrer hvidt på ruden ved daggry, af med skraberen. Det slørede udsyn klarner stribe for stribe. Selv det, der er frosset fast, kan til sidst skrabes af, fortæller vintermorgenens fingerspidser."},"ICON-2640":{"nm":"Termohylster til varmtvandsflaske","de":"Træk et hylster over flasken fyldt med varmt vand. Så den ikke skal køle af i nattens løb, svøbes varmen i endnu et lag. Måden at holde på varmen længe er, i sidste ende, at omfavne den omhyggeligt med noget."},"ICON-2641":{"nm":"Trykstang til dørtætningspapir","de":"Den skarpe blæst, der borede sig gennem dørsprækken, tøver i det øjeblik den møder dig. En enkelt stang, der presser papirskærmens kant fast ned. Rummets varme vogter endelig sine egne – vinteren varmes af en så lille stædighed."},"ICON-2642":{"nm":"Underlagstallerken til fodvarmer","de":"Den runde tallerken lagt under fodvarmeren. Den tager al varmen alene og efterlader ikke ét sodmærke på gulvet. Når nogens tæer varmes dvaske, ender min egen andel af dagen stille."},"ICON-2643":{"nm":"Ophæng til kondensklud","de":"Så kluden, der tørrede dråberne på ruden ved daggry, ikke mister sin plads, hænger en enkelt løkke på væggen og venter. Mere end at drikke sig mæt af fugt handler absorption i sin sande kerne om at vente tør igen til i morgen."},"ICON-2644":{"nm":"Tørrestativ til vintervanter","de":"Vanterne, færdige med en snebold-kamp, spreder fingrene vidt ud ved siden af radiatoren. Synet af dem, hængt på stativet, dampende svagt. Ved enden af en eftermiddag med rød næse er det vinterens mest fredfyldte vask."},"ICON-2645":{"nm":"Udskiftningsfjer til fjerkost","de":"Når fjerene slides ned, skiftes de ud med nye. Øjeblikket, hvor den støvjagende spids igen bliver dunet. At selv rengøringsredskaber har deres skiftende årstider – det fortæller denne lille udskiftning stille i din håndflade."},"ICON-2646":{"nm":"Vridehåndtag til gulvklud","de":"Et håndtag, monteret for at skåne dine håndled. Ét vrid, og kluden spytter selv vandet ud. Farvel til dagene med at kæmpe foran vaskebrættet. I husholdningen bliver en håndfuld knowhow til ren ømhed."},"ICON-2647":{"nm":"Udskifteligt hoved til gulvbørste","de":"Når gulvbørsten er helt slidt op, skiftes blot hovedet ud. Skaftet bliver, og det gør vægten, din hånd kender, også. I ting, man bruger længe, bor en lille, fast ømhed, der ikke vil smide det hele væk."},"ICON-2648":{"nm":"Refill-rulle til fnugrulle","de":"Efter at have revet det sidste ark af rullen af, føler man sig underligt tom. Det er da, man sætter en ny rulle i. Det er det udholdende, kærlige løfte om en refill, der lover at tage sig af selv én sweaterluv til det sidste."},"ICON-2649":{"nm":"Hjørneskraber til støv","de":"Selv i hjørner, kosten ikke kan nå, slår støvet stille sit hjem op. At pirke hjørnet rent med en tynd spids. Hjertet, der tager sig af selv det usynlige, er selve husholdningens stolthed."},"ICON-2650":{"nm":"Rensekam til kost","de":"Selv en fejende kost trænger til en hvilende berøring. Red det sammenfiltrede hår ud mellem børsterne med denne kam, og kosten, sin arbejdstørn fuldført, gør sig endelig klar til næste fejning."},"ICON-2651":{"nm":"Voksklud til trægulv","de":"Læg et lag voks langs gulvets årer, og træet mindes langsomt en glans, det længe havde glemt. Fødder der næsten glider, næsten ikke – en eftermiddag hvor hele huset smiler, blankt og tilfreds."},"ICON-2652":{"nm":"Dørspalte-støvekost","de":"Jeg jager det støv, der bor i dørsprækker. Hvad end der glider ind og hober sig op, hver gang døren svinger, fejer jeg det sammen med min tynde krop. Jo smallere og dybere sprækken er, desto sikrere kommer min tur."},"ICON-2653":{"nm":"Net-hætte til dørmåtte","de":"Så det støv, entrémåtten har opslugt, ikke siver ud igen, står en net-hætte som den sidste portvagt. Det støv, mudrede sko har hentet med fra verden udenfor, får kun lov at trænge lige hertil og ikke længere."},"ICON-2654":{"nm":"Kalkbørste til vandhane","de":"Den lille børste kredser rundt og fjerner kalken, der stille har lagt sig på vandhanens hals. Jo mere et sted røres af hænder hver dag, desto mere skal det skinne. Det er den badeværelsesskik, denne lille børste vogter."},"ICON-2655":{"nm":"Hårsi-hætte til afløb","de":"Jeg griber stille det hår, der drev mod afløbet. At afværge den lille katastrofe, en tilstopning, med en enkelt hætte. En rund, robust lille helts dag flyder stille forbi, altid under fødderne."},"ICON-2656":{"nm":"Fugeskraber til fliser","de":"Fugen, der er blevet mørk mellem de hvide fliser – skrab den forældede tid væk, forsigtigt, med spidsen. Når de smalle mellemrum bliver rene, trækker hele badeværelset vejret let, som var det nyt."},"ICON-2657":{"nm":"Rensepind til bruserhoved","de":"Prik de tilstoppede huller i bruserhovedet åbne med pindespidsen, og vandet, der kun havde sivet, strømmer atter friskt ud. Den triumferende lyd af morgenvand, når én lille tilstopning løsnes."},"ICON-2658":{"nm":"Opbevaringskop til toiletbørste","de":"Selv en toiletbørste er først hygiejnisk, når den hviler på et tørt sted. Sat pænt i en lille kop, der opsamler dryppet, venter den sin næste tur. Et redskabs værdighed viser sig ikke i brugen, men i opbevaringen."},"ICON-2659":{"nm":"Skimmelfjerner-svamp","de":"Skimlen, der har bredt sig sort i flisehjørnet – over for denne stædige gæst foreslår svampen høfligt en afgang. Én tørring, og badeværelset vender lysende tilbage til sin oprindelige hvidhed."},"ICON-2660":{"nm":"Dugtørrer til spejl","de":"Foran et spejl, blevet tåget efter et bad, trækker skraberen én streg, og dit klare ansigt vender tilbage. Øjeblikket, hvor du igen møder dagens udtryk, der lå gemt bag dampen et øjeblik."},"ICON-2661":{"nm":"Ophæng til badesandaler","de":"Hæng de våde sandaler på hovedet, og vandet drypper af, mens indersiden tørrer snugt. Så den næstes fødder ikke skal fryse. Et lille ophængs omsorg er altid ude ét skridt i forvejen for at tage imod."},"ICON-2662":{"nm":"Etui til neglebørste","de":"Selv den lille børste, der skrubber under neglene, har sit eget hjem. Puttet snugt ned i etuiet tørrer den fugtfri og dunet og venter på det næste håndvask. Renlighed begynder altid stille med at lægge tingene på plads."},"ICON-2663":{"nm":"Låg til tandbørste-steriliseringskop","de":"Selv en tandbørste, der møder munden to gange dagligt, trænger til et lille fristed. I det øjeblik steriliseringskoppens låg klikker i, vogtes ét mål renhed stille mod fugten, der driver rundt i badeværelset."},"ICON-2664":{"nm":"Rejsekapsel til vatpinde","de":"Så vatpindene i rejsetasken ikke knækker eller spredes, holder en kapsel dem stille og trygt samlet. Jo mindre en ting er, desto mere må man pakke den i forvejen, så man ikke bliver taget på sengen på en fremmed vej."},"ICON-2665":{"nm":"Åndeprøve-tavle","de":"Ånd \"ha\" ud i håndfladen, og hold den let mod minitavlen, og din ånde rører den og dugger den mælkehvid. Det sødeste bevis på, at jeg er levende her på en kold dag – denne lille tavle noterer det uden et ord."},"ICON-2666":{"nm":"Opbevaringshus til øreske","de":"Når en øreske rejser med i en taske, bliver spidsen let sløv. Derfor blev der lavet et lille hus til den. Indeni, hvor spidsen ikke tager skade selv når den bæres med, sover det fintfølende redskab trygt."},"ICON-2667":{"nm":"Foldeklemme til lommetørklæde","de":"Klemmen bider blidt om et lommetørklæde, foldet pænt i sine fire hjørner, og forhindrer det i at gå i uorden i tasken. Ét ark, sirligt foldet, byder på stille elegance, uanset hvornår du tager det frem."},"ICON-2668":{"nm":"Plaster-etui","de":"Den dag du skrubber knæet, åbner du etuiet, og plastre af enhver slags stiller sig på række og venter på dig. Ømheden ved at gøre stads selv af et lille sår. Et førstehjælpsskrin skal altid være inden for rækkevidde."},"ICON-2669":{"nm":"Håndflade-fingeraftrykstørrer","de":"Tør fingeraftrykkene af glasset, og sporene af de tøvende hænder forsvinder. En håndfladestor lille magi, hvor verden bag ruden, sløret ved hver berøring, atter bliver klar."},"ICON-2670":{"nm":"Sorteringsskillevæg til genbrug","de":"Papir denne vej, dåser den vej. En enkelt skillevæg deler en skæbne, der nær var blevet blandet sammen. Genbrugssortering er, i sidste ende, hjertet, der deler med omhu, og denne stramme afdeling trækker den første streg tydeligt."},"ICON-2671":{"nm":"Klistermærke-afskraber","de":"Selv et klistermærke, der sidder klæbrigt fast, overgiver sig stille foran mig. Før det flade skovlblad forsigtigt ind under et hjørne, og det løsner sig rent uden et eneste mærke – en triumferende afsked."},"ICON-2672":{"nm":"Skæretakker til maskeringstape","de":"Ingen grund til at lede efter en saks bare for at bruge maskeringstape. Hold den mod takkerne og træk, og den knækker rent af langs strukturen. Den lille, rappe bedste ven, som den scrapbog-elskende fingerspids holder mest af."},"ICON-2673":{"nm":"Klæbehjørne-beslag","de":"Et lille beslag, der holder et løftet hjørne fast indefra. Fra et usynligt sted vogter det tavst vinklen. Bag ting, der er lige på overfladen, findes der som regel en sådan skjult støtte."},"ICON-2674":{"nm":"Beskyttelsesrør til seal-ark","de":"Så de dyrebare seal-ark ikke krølles eller bliver fugtige, sover de i røret side om side med beskyttelsesfilmen. Ved siden af glæden ved at samle følger altid omsorgen for skånsomt at værne om det."},"ICON-2675":{"nm":"Rensebørste til stempel","de":"Børsten fejer blidt langs strukturen gennem det blækgennemvædede stempel og fjerner den gamle farve. Et lille, flittigt strøg, der rengør på forhånd, så det næste aftryk bliver skarpt."},"ICON-2676":{"nm":"Holdervinge til plastiklommer","de":"Så ringbindets indlægsark ikke glider og falder ud, griber vingerne fast om begge sider. Takket være at hvert ark bliver på sin plads, kommer fingerspidsen, der vender siderne, aldrig i uorden."},"ICON-2677":{"nm":"Opsamlingsskovl til pyntebrikker","de":"Skovl de spredte, småbitte pyntebrikker op i ét greb med den lille skovl. Når besværet ved at samle dem én for én forsvinder, bliver tiden brugt på at skabe noget med omhu langt mere glædesfyldt."},"ICON-2678":{"nm":"Fastholder til bogmærke-kvast","de":"Så kvasten for enden af bogmærket ikke løsner sig, binder en fastholder den stramt sammen. Selv en vejviser tilbage til en halvlæst side falder først til ro, når dens eget udseende er sirligt."},"ICON-2679":{"nm":"Hætteklemme til dekopen","de":"En klemme, der klemmer hætten fast, så dekopennens spids ikke tørrer ud. Den forhindrer uheldet, at en glemt, åben pen stivner, så farven altid flyder ud fugtig som første gang."},"ICON-2680":{"nm":"Udskifteligt skruebit","de":"Lad skruetrækkerens skaft blive, som det er, og skift kun spidsen for enden ud. Kryds eller lige, uden besvær. Den snedighed at klare mange opgaver med ét redskab er pakket stramt ind i denne lille spids."},"ICON-2681":{"nm":"Sandpapirsholder til hjørner","de":"Vikl den ru flade rundt om grebet, og håndfladen bliver selv et redskab. Svisj, svisj – for hver gang du skubber langs strukturen, rundes det ru hjørne af, og den sidste glathed genkender fingerspidsen altid."},"ICON-2682":{"nm":"Sorteringstragt til skruer","de":"De spredte skruer passerer den smalle hals og samles, rullende, ét sted. Lyden af de små ting, der har rullet rundt på bordet, og som finder deres plads – det føles, som om selv et rodet sind bliver bragt i orden."},"ICON-2683":{"nm":"Endekrog til målebånd","de":"Kroken for enden af målebåndet er den anden hånd for den, der arbejder alene. Hægt den fast på et hjørne, og båndet vakler ikke – og hånden, og hjertet, bliver lige så ærlige som den længde, du har målt."},"ICON-2684":{"nm":"Håndtagsbetræk til skruenøgle","de":"Et lag trukket over det kolde metalgreb. I det øjeblik du tager fat, møder en blød varme din hånd i stedet for kulden. Et redskab bliver længere ved din side, når det først tænker på den, der holder det."},"ICON-2685":{"nm":"Beskyttelseshætte til syl","de":"En lille kegle sættes over hver spids ende. Roen ved at famle i en skuffe uden at stikke sig – jo skarpere en ting er, desto mere omhyggeligt skal den svøbes ind, så ingen kommer til skade."},"ICON-2686":{"nm":"Afisoleringsblad","de":"Kun isoleringen skrælles tyndt af, og den indre tråd forbliver uskadt. I det øjeblik du forsigtigt løsner ét lag, og en kobbertråd glimter frem, ved en god klinge nøjagtigt, hvor den skal standse."},"ICON-2687":{"nm":"Rudetørrer til vaterpas","de":"Først når den ene boble stopper lige i midten, er det virkelig i vater. At tørre det lille vindue klart minder om den stille forberedelse med at få vejret til at falde til ro, før man trækker en streg."},"ICON-2688":{"nm":"Fingerbeskytter til sømslag","de":"Et lille hylster, der pakker fingeren tæt ind, mens den holder sømmet. Slå roligt til uden frygt, for selv hvis hammeren rammer forbi, går det, siger det – klart til at tage slaget i fingerens sted."},"ICON-2689":{"nm":"Skridsikker underlag til foderskål","de":"Et lag gummi, der holder skålen fra at skride på gulvet. Uden at skålen løber sin vej midt i et festmåltid, begynder måltidets ro fra et sted, der ikke vakler."},"ICON-2690":{"nm":"Ophæng til foderske","de":"Hæng foderskeen på væggen til let tørring. En lille orden, der møder hånden fra samme sted hvert måltid – at have en mund at tage sig af er en så øm ting."},"ICON-2691":{"nm":"Overløbsbakke til vandskål","de":"Den opsamler stille den mundfuld, der skvulpede over kanten af vandskålen. Takket være den brede bakke, der tager imod i forvejen, for at gulvet ikke skal blive vådt, forbliver gulvet altid tørt og snugt."},"ICON-2692":{"nm":"Godbidstang","de":"En tang, der griber præcis ét godbidstykke og rækker det frem. Selv foran en lille mund, der venter med snuden fremme, findes der en øm fingerspids ved deling, der aldrig kommer i uorden."},"ICON-2693":{"nm":"Rulleklemme til foderpose","de":"En lille klemme, der ruller munden på en åbnet foderpose sammen og bider fast. Med ét klik lukket standses fugten, og i morgen tidligt bevares en sprød håndfuld helt intakt."},"ICON-2694":{"nm":"Tudprop til vandflaske","de":"En prop, der passer snugt på vandflaskens tud. Dryp – de drivende dråber stopper, og randen tørrer. Det, der er lukket godt til, lækker ikke, men forbliver klart samlet i lang tid."},"ICON-2695":{"nm":"Målebæger til foderportion","de":"Mål nøjagtigt én kop af langs skalaen. Hverken for meget eller for lidt – i hånden, der retfærdigt afmåler dagens måltid, rummes en lille families dag i det rette mål."},"ICON-2696":{"nm":"Kant til foderspildmåtte","de":"En kant, der holder spildt foder fra at krydse ud over måtten. En enkelt let hævet kant samler snugt de krummer, der næsten var spredt for alle vinde."},"ICON-2697":{"nm":"Adskillelsesring til dobbeltskål","de":"En lille ring, der forsigtigt skiller to stablede skåle ad. Hånden, der har kæmpet med dem klæbet fast, bliver let igen. At skille godt ad er, viser det sig, også en øm omsorg."},"ICON-2698":{"nm":"Boldopsamlingstragt til haven","de":"En tragt, der samler boldene, der har trillet rundt i haven, ét sted. Efter en aften med boltren kommer hånden, der samler det spredte sammen her og der, naturligt i tankerne."},"ICON-2699":{"nm":"Hegnspælehætte","de":"Sæt en rund hætte på hver hegnspæl. Så spidserne ikke revner i blæst og regn, har et hjerte, der tager sig af og dækker selv den mindste ting, gennemsyret hele haven."},"ICON-2700":{"nm":"Foldekrog til legetunnel","de":"En krog til at folde den flittigt brugte legetunnel pænt sammen og hænge den op. Pak en dag tilsølet med jord godt væk og hæng den op, og en leg, der er ryddet pænt op, lover uden fejl en ny dag i morgen."},"ICON-2701":{"nm":"Trækrebshåndtag-pude","de":"En pude, der blødt omslutter et trækrebs håndtag. Uanset hvor hårdt du trækker, bliver din håndflade aldrig gnavet. Jo længere du holder fast, desto mere behageligt bliver det for hånden – takket være nogens lille omtanke."},"ICON-2702":{"nm":"Skyggedugsspænde","de":"Et spænde, der holder skyggedugen, spændt ud over gården, godt fast. Selv middagens svalhed skal holdes fast for at blive. Under skyggen, som spændet holder stram, strækker en doven eftermiddag sig ud og hviler."},"ICON-2703":{"nm":"Spadebladshylster","de":"Et hylster, du forsigtigt trækker over en gravespades blad. Lad den hvile efter en hård dags arbejde, så forbliver den skarp – klar til at møde næste forårs jord igen."},"ICON-2704":{"nm":"Boldrampe","de":"En enkelt rampe, hvor en bold ruller lystigt ned. Ned ad den let skrånende bakke løber bolden af sted i glæde. Én lille hældning skaber en hel dags fornøjelse."},"ICON-2705":{"nm":"Hegnslågens slåring","de":"En slåring, der låser hegnslågen. Den lille kliklyd, når den lukkes, giver ro i sindet. Én solidt lukket låge holder en lille gård tryg som en verden for sig selv."},"ICON-2706":{"nm":"Legeklokke-snor","de":"Ryst legeklokkesnoren blidt, og en klar lyd breder sig. Ding, ding – et engang stille rum vågner, og ved én lille klang spidser hele hjertet ører."},"ICON-2707":{"nm":"Urtepottebakke","de":"En skål, der stille opsamler vandet, der siver ned under en urtepotte. Den holder på overløbet, så vindueskarmen forbliver tør. Selv omsorg, når den flyder over, har brug for et sted at blive samlet op."},"ICON-2708":{"nm":"Priklespade til småplanter","de":"En lille spade til at flytte spæde planter ned i jorden og forsigtigt trykke dem på plads. Under fingerspidser, der omhyggeligt finder plads til hver spire, løfter et grønt forår hovedet selv i en håndfladestor haveplet."},"ICON-2709":{"nm":"Bedmarkeringsnål","de":"En markeringsnål, du skriver på og sætter i hver bed for at notere, hvad der er plantet. På jord, hvor intet endnu er spiret frem, husker ét lille navneskilt stille, hvad der skal gro."},"ICON-2710":{"nm":"Vandkandetud-si","de":"Et fint net sat på tuden af en vandkande. Vand, der før strømmede i én stråle, spredes nu i mange tråde som en blid støvregn. Kun en blød strøm skåner de spæde blade for skade."},"ICON-2711":{"nm":"Støttepindsklemme","de":"En klemme, der forsigtigt fæstner en vaklende stængel til dens støttepind. Bare lidt lånt støtte, indtil det stadig spæde kan stå oprejst selv – at vokse kræver en sådan støtte."},"ICON-2712":{"nm":"Frøposeklemme","de":"En klemme, der lukker en tilbageværende frøpose tæt. Klikket lukket slipper ikke et eneste korn ud. Et lille løfte til næste forår bor i dette ene klem."},"ICON-2713":{"nm":"Måleske til jord og gødning","de":"En lille ske til at tage netop den rette mængde jord og gødning. Hverken for meget eller for lidt – én afmålt ske. Kun med den nøjagtige mængde kan jorden endelig gøre sit arbejde."},"ICON-2714":{"nm":"Ophængskrog til urtepotte","de":"En ophængskrog, der lader en urtepotte svæve let i luften. Løftet op kommer det grønne en håndsbredde nærmere sol og vind. En lille have svæver op ved vinduet."},"ICON-2715":{"nm":"Spirebeskyttelsesnet","de":"Et dæknet, der blidt skærmer nyspirede skud. Indtil de stadig sarte blade kan tåle den første kulde og det stikkende sollys, er det mest skrøbelige det første, der får omsorg."},"ICON-2716":{"nm":"Plejekam-krog","de":"Et sted, hvor du banker løse hår af kammen og hænger den pænt op. Den ryddede, tomme kam venter på næste blide berøring. Ordentlighed begynder altid med den lille vane at passe på sine redskaber."},"ICON-2717":{"nm":"Skridsikker ring til fodbadekar","de":"En ring, der understøtter fodbadekarret, så det ikke glider. Med karret stabilt under sprættende små fødder vakler hverken de vaskende hænder eller det vaskede hjerte."},"ICON-2718":{"nm":"Snorekrog til gåtur","de":"En enkelt krog til at hænge gåturssnoren op ved entrédøren. Fra sin plads ved døren venter parathed til at drage af sted altid. I det øjeblik snoren tages ned, følger et forventningsfuldt lille skridt med."},"ICON-2719":{"nm":"Klobeskyttelseshætte","de":"En beskyttelseshætte, der skåner den sarte inderdel, mens kløerne klippes. Kun med en tryg grænse afmærket lige her kan hånden, der holder klipperen, forblive rolig og fast."},"ICON-2720":{"nm":"Badevandstermometerstrimmel","de":"En strimmel, der flyder i badevandet og viser dens temperatur. Den gamle vane med at dyppe en hånd ned for at mærke den rette varme flyder nu der, klart oversat til ét enkelt farvebånd."},"ICON-2721":{"nm":"Fnugrulle","de":"Ét hvidt hår på et sort outfit ser størst ud lige før scenen. Til lyden af rul-rul flyttes en dags smuds pænt over på det klæbende papir, strimmel for strimmel. Renlighed fuldendes sådan, ét stykke ad gangen, i takt med det, du river af."},"ICON-2722":{"nm":"Affaldsposetang til gåtur","de":"Ved enden af en gåtur kommer et ømt øjeblik med at bøje sig ned. Hold en pose i tangens spids, og hænderne forbliver rene, hjertet let. At gå sammen rummer en lille høflighed i at rydde op bagefter – og denne tang ved det først."},"ICON-2723":{"nm":"Dørmåttekant","de":"Kanten af dørmåtten er den velkomst, en fod møder først. Lad de våde tæer standse her én gang, og gulvet indenfor forbliver tørt. Det laveste sted af alle, der tavst tørrer og byder alle velkommen, som træder ind."},"ICON-2724":{"nm":"Plejeklokke-knudesnor","de":"Selv det at fæste én klokke har sin orden. Vikl snoren to gange rundt og før den igennem én gang, så følger en klar klang med hvert skridt. Pleje er, i sidste ende, hjertet, der aldrig springer denne lille afsluttende detalje over."},"ICON-2725":{"nm":"Dryppose til paraply","de":"I en lobby, efter regnen er stilnet af, dryppes gulvet plettet fra spidsen af en sammenfoldet paraply. Én pose opsamler dem stille, og ingens fødder glider. Omtanke bliver som regel tæt ved siden af, uden en lyd."},"ICON-2726":{"nm":"Taskeremme-klemme","de":"En taske hængt over en stol bliver ved med langsomt at glide ned. Klem den fast én gang med en remmeklemme, og begge hænder er fri for bekymring om, at den falder. Roen ved at gå ud begynder, når du kan glemme din bagage et stykke tid."},"ICON-2727":{"nm":"Håndvarmerpose af stof","de":"I en kold, blæsende gyde bærer en stofpose i lommen varme stille over i din håndflade. Et blødt lag, der pakker det varme ind og opvarmer det netop passende. Vinterens ømhed videregives altid gennem et enkelt stykke stof."},"ICON-2728":{"nm":"Foldespejlstander","de":"Fold det ud, og et lille spejl vipper til sin egen vinkel. Så du kan møde dit eget blik uden at holde det, står stativet i stedet for dig. Selv i det korte øjeblik, du retter på dig selv, er en pålidelig birolle ved din side."},"ICON-2729":{"nm":"Rejselåg til vådservietter","de":"Det første ark vådservietter var altid ved at tørre ud. Klik låget i, og selv det sidste ark forbliver fugtigt. At holde noget brugbart helt til enden – hemmeligheden bag en holdbar husholdning gemmer sig i sådanne små ting."},"ICON-2730":{"nm":"Møntrum-skillevæg til pung","de":"Når mønter spredes blandt sedlerne, bliver kassekøen altid hektisk. Én skillevæg samler de runde ting til den ene side, og fingerspidserne famler ikke længere. At rydde op er arbejdet med at give hver ting et sted og et navn."},"ICON-2731":{"nm":"Foldeetui til mundbind","de":"Foldet sammen krøller et mundbind ikke, selv i en taske. Et etui, der rent opbevarer et ark, du kort har taget af. Én øm vane med at gemme det pænt til næste gang er samlet her."},"ICON-2732":{"nm":"Tandbeskyttelseshætte til rejsekam","de":"Kammens tænder i en taske plejede ofte at flå i de andre ting. Sæt tandhætten på, og kammen er tryg, og tingene pakket ved siden af er også i behold. Enhver, der har passet på sine ting, ved, at ét lille lag beskyttelse holder begge sider trygge."},"ICON-2733":{"nm":"Skuffeopdelerklips","de":"Hver gang skuffen blev åbnet, væltede det sammenblandede indhold ud som et suk. Del den i rum med én klips, og de små ting finder endelig deres egen zone. En ryddelig skuffe ændrer stille humøret hver eneste morgen."},"ICON-2734":{"nm":"Møntstander","de":"Rejs én gammel mønt op, og den bliver i sig selv en lille udstilling. Standeren støtter den på skrå, så forsidens mønster træder tydeligt frem. At løfte tid, slidt af hænder, op i øjenhøjde – det er her, samlerglæden bliver dybere."},"ICON-2735":{"nm":"Øretelefonopruller","de":"Der var morgener, hvor halvdelen gik tabt til at rede sammenfiltrede øretelefonledninger ud. Vikl den pænt rundt om oprulleren, og næste gang du tager den frem, er den glat. Lidt oprydning bliver en stille gave, du sender videre til morgendagens dig."},"ICON-2736":{"nm":"Vægkrog til opladerkabel","de":"Et opladerkabel, der hang og slæbte på gulvet, blev hele tiden trådt på. Sæt én krog på væggen til at hænge det på, og skrivebordet føles langt rummeligere. At tæmme rod er ikke noget stort – det er en plads ikke større end et enkelt søm."},"ICON-2737":{"nm":"Fjernbetjeningsholder","de":"Fjernbetjeningen, der blev ved med at forsvinde ned i sofaens sprække, har endelig fået et hjem at vende hjem til. Stil den op i holderen, og der er ikke mere leden efter den, ikke mere at sidde på den. At have sin egen plads bliver en lille hvile, selv for en genstand."},"ICON-2738":{"nm":"Brilleklemme","de":"Aflagte briller gled altid stille et sted hen. Hægt et brillestel let fast i klemmen, og glassene rører aldrig gulvet. Ønsket om at møde morgendagen uden ridser er samlet i denne lille ophænger."},"ICON-2739":{"nm":"Nøglesorteringsklips","de":"Jo tungere et nøgleknippe bliver, desto mere udvisker det, hvilken nøgle der hører til hvilken dør. Bind dem sammen med en sorteringsklips, og fingerspidserne alene kender hver makker. En tavs guide, der stille bringer orden i de døre, du åbner og lukker hver dag."},"ICON-2740":{"nm":"Notatholderklips","de":"Nedskrevne notater plejede ofte at vælte om på skrivebordet. Når klipsen holder papiret oprejst, ser ordene dig lige i øjnene. En måde at lade den ene linje, du ikke må glemme, bo et sted, hvor den altid er synlig."},"ICON-2741":{"nm":"Penholder","de":"Hvor mange gange har du ikke bøjet ryggen for at samle en pen, der trillede væk? Stil den med spidsen ned i holderen, og afstanden til næste linje bliver en håndsbredde kortere. En lille venteplads, altid vågen ved siden af den, der skriver."},"ICON-2742":{"nm":"Timeglasfod med vendefunktion","de":"Når et timeglas er løbet ud, må nogen vende det, for at det kan leve igen. Foden griber det sidste korns øjeblik og drejer det glat oprejst igen. Berøringen, der skruer tiden tilbage til begyndelsen, hviler her, ovenpå et lille stykke træ."},"ICON-2743":{"nm":"Bagt kartoffel med smør","de":"Smør smelter langsomt hen over en kartoffel bagt i skrællen. Når det gyldne smelter ned med dampen, tager den let, luftige indmad stille imod den fyldige smag. Netop det øjeblik, hvor en rodfrugt med duft af jord bliver varmest af alle."},"ICON-2744":{"nm":"Grillet majs med smør","de":"De gule kerner, tæt pakket i rækker, knitrer på grillen. Lad en klat smør glide hen over dem, og den søde duft stiger op med det samme. Sommermarkens sødme bæres direkte over i én mundfuld."},"ICON-2745":{"nm":"Vaffel","de":"I hver lille firkant af gitteret venter sirup stille på at samle sig. Sprød udenpå, luftig indeni – tag en bid, og varm damp siver ud. De firkantede lommer er som et fad, der deler lidt lykke ud i portioner."},"ICON-2746":{"nm":"Pandekager","de":"Jeg husker den duft af dej, der hævede gyldent på panden. Hen over de runde kager, stablet lag på lag, synker smørret sammen og smelter bort. Et blødt fad, der kun stille tillades på en afslappet morgen."},"ICON-2747":{"nm":"Chokolade","de":"Hold et stykke i munden, og det løses langsomt op ved kropsvarme. Sødmen, der breder sig for enden af bitterheden, letter hjertets spænding en anelse. På en udmattende dag, et lille brunt stykke trøst, hentet frem fra lommen."},"ICON-2748":{"nm":"Jordbærkage","de":"Røde jordbær tronende på hvid flødeskum bebuder foråret først. Når gaflen deler det bløde snit, blomstrer en syrlig duft blidt frem. På en dag med noget at fejre, den ømme hovedperson placeret midt på bordet."},"ICON-2749":{"nm":"Ostekage","de":"Ét tungt stykke synker rigt sammen på tungen. Den salte eftersmag tager sødmen i hånden og kalder på endnu en bid, igen og igen. En dessert, som elskere af tæt fylde stille nyder."},"ICON-2750":{"nm":"Bananecookies","de":"Duften af mosede bananer modnes gyldent inde i ovnen. Tag en bid, og en blød sødme breder sig i hele munden. Det varme øjeblik, hvor en velmodnet frugt genfødes som en cookie."},"ICON-2751":{"nm":"Chokoladecookies","de":"Chokoladestykkerne i dejen smelter rigt, mens de bages. Bræk den mens den er varm, og en dyb brun farve smitter af på fingerspidserne. Sammen med et glas mælk bliver eftermiddagen en anelse mildere med sådan et stykke."},"ICON-2752":{"nm":"Kakaonibs-cookies","de":"Finthakkede kakaostykker knaser mellem dejen. En dyb, usødet bitterhed beroliger stille en voksen gane. En lidt alvorlig cookie, der holder fast i den rå duft, netop som den var, før forarbejdningen."},"ICON-2753":{"nm":"Osttoast","de":"Ost trækker sig lang som en tråd hen over gyldent ristet brød. Det sprøde udenpå og det fyldige indeni foldes sammen i én bid. Det enkleste, ømmeste måltid til at fylde en sen formiddag varm og mæt."},"ICON-2754":{"nm":"Sandwich","de":"Mellem to skiver brød er en dags omsorg pakket lag på lag. Bid i den, og de stablede smage siger alle goddag på én gang. Et lille spisebord på din håndflade, klar til at tages med hvor som helst."},"ICON-2755":{"nm":"French toast","de":"Brød, godt gennemblødt i æggemasse, bliver gyldent på panden. Kanterne, hævet med duften af smør, bliver sprøde først af alle. Dryp en stribe sirup over, og selv almindeligt brød bliver en helligdags luksus."},"ICON-2756":{"nm":"Svampe-ramen","de":"Svampens dybe duft stiger op med dampen over den kogende bouillon. Løft en sej hat op, og en jordagtig sødme breder sig i munden. En lidt speciel skål, der fylder dig med duft, før nudlerne overhovedet gør."},"ICON-2757":{"nm":"Stegte ramen-nudler","de":"På suppeløse nudler, vendt igennem, lægger en stærk sauce sig som et glinsende lag. Løft dem med spisepindene, og en fyldig, røget duft breder sig gennem dampen. Når du længes efter et hurtigt, rigt måltid, den mest pålidelige ven."},"ICON-2758":{"nm":"Ostet ramen","de":"Læg en skive ost over varme nudler, og den synker langsomt sammen og smelter ind. Den stærke bouillon møder en blød fyldighed, og kanterne bliver runde. En skål, der passer netop til en aften, hvor du vil dæmpe styrken en smule."},"ICON-2759":{"nm":"Karry-ramen","de":"En fyldig karryduft snor sig om nudlerne og sender gul damp op. Slurp en mundfuld, og en varm skarphed opvarmer dig indefra. Nudler i en munter variation, der tilføjer en let fremmed duft til en velkendt bouillon."},"ICON-2760":{"nm":"Skaldyrsramen","de":"Over en bouillon fuld af havets duft flyder rejer og muslinger fyldigt op til overfladen. En forfriskende, men dyb umami-smag siver ind mellem nudlerne. En lille tryllekunst, der bringer tidevandets duft i én skål, uden at du behøver rejse langt."},"ICON-2761":{"nm":"Gimbap med syltet radise","de":"Med gul syltet radise i midten og ris samlet rundt om binder ét ark tang det hele varmt sammen til én rulle. I daggryet før en skovtur, det mest ærlige måltid, født på et skærebræt."},"ICON-2762":{"nm":"Tunfiskgimbap","de":"I det øjeblik en ske tunfisk, vendt i mayonnaise, siver ind mellem risene, bliver et måltid varmt nok, selv under det sene nattelys fra en døgnkiosk. Trøsten, travle hænder gribertil oftest."},"ICON-2763":{"nm":"Frugtsalat","de":"Farver samlet fra sæsonen mødes for første gang i én skål. Hvordan rødt, grønt og gult går i spænd uden at skændes, viser frugten først, når den er skåret og samlet."},"ICON-2764":{"nm":"Kyllingesalat","de":"Let grillet kyllingebryst lagt pænt over grønne bladgrøntsager. På bordet hos en, der forbereder sig til morgendagens scene, står altid sådan en ordentlig tallerken."},"ICON-2765":{"nm":"Tomat-agurksalat","de":"Modne tomater og sprøde agurker vendt syrligt og friskt. På en middag tung af cikadesang, tag én pind fuld, og sommeren køler et taktslag ned indeni."},"ICON-2766":{"nm":"Grøn salat","de":"Skyl blade, lige plukket fra køkkenhaven, i koldt vand, og fingerspidserne vågner kølige. Øjeblikket, hvor den mest almindelige grøntsag indtager den grønneste, friskeste plads ved bordet."},"ICON-2767":{"nm":"Majssalat","de":"Hver gang et sødt korn springer med et smæk, folder en solbeskinnet midsommermark sig ud for øjnene. Selv i en salatskål glemmer den gule majs aldrig sit eget solskin til sidst."},"ICON-2768":{"nm":"Coleslaw","de":"Når snittet kål tager imod den sødsyrlige sauce, dæmpes sprødheden en anelse mildere. Dyden ved en tilbehørsret: sat ved siden af enhver hovedret kappes den aldrig om opmærksomheden, men gør blot sit."},"ICON-2769":{"nm":"Rejesalat med lime","de":"Pres lidt lime i, og rejens sødme vågner skarpere op. Én sur dråbe puster liv i hele tallerkenen – et lille, men afgørende sidste strøg."},"ICON-2770":{"nm":"Hamburgbøf","de":"En tykt formet kødfars steges gylden på en varm jernplade. Saften, der siver ud, i det øjeblik knivspidsen rører den – måltidet, der længst har været elsket mellem hjemmelavet mad og vestlig køkken."},"ICON-2771":{"nm":"Pizza","de":"Den ene bid, hvor osten trækker sig lang, sendes fra hånd til hånd blandt de mange, der sidder samlet. Først når en rund plade deles i skiver sammen, bliver en sammenkomst en rigtig sammenkomst."},"ICON-2772":{"nm":"Svampe-cremepasta","de":"Svampens dybe jordduft og flødens blødhed omslutter hver eneste nudelstreng. På en aften med stille regnlyd breder den fyldige duft sig langsomt helt ned til tallerkenens bund."},"ICON-2773":{"nm":"Rejepasta","de":"Fyldige rejer let sauteret i olivenolie og vendt sammen med nudlerne. Når havets saltethed møder nudlernes enkelhed, bliver en begivenhedsløs aften en anelse særlig."},"ICON-2774":{"nm":"Olivenoliepasta","de":"Hvidløg, olie og nudler – kun tre ting. At der findes en smag, der bliver klarere, jo mere man tager væk, beviser aglio e olio stille, uden et eneste overflødigt element."},"ICON-2775":{"nm":"Muslingepasta","de":"Bouillonen, muslingerne slipper, mens de åbner deres skaller, siver dybt ind i hver eneste streng. Duften af en slurk hvidvin dvæler længe på tallerkenen, som en forårsdag der ikke vil forsvinde."},"ICON-2776":{"nm":"Cremepasta","de":"Når fyldig fløde stille omslutter nudlerne, varmer et hjørne af hjertet fra allerførste bid. Trøsten, blødhed giver, bliver kun dybere på en blæsende dag."},"ICON-2777":{"nm":"Tomatpasta","de":"Længe simret tomatsauce breder sig rødt hen over nudlerne. Når sødme og syre langsomt reduceres og endelig finder balance, er den mest basale tallerken den mest pålidelige."},"ICON-2778":{"nm":"Omurice","de":"Blødt æg dækker varm ris som et tæppe, stoppet blidt ind. Skriv blot et navn på med ketchup, og den dags bord bliver et lille brev, nogen har rakt videre."},"ICON-2779":{"nm":"Grillet laks","de":"Grill den langsomt foran ilden, indtil skindet bliver sprødt. En strime damp stiger op, mens det lyserøde kød flager fra hinanden langs fibrene – tålmodighed bliver altid belønnet ærligt af laksen."},"ICON-2780":{"nm":"Bruschetta","de":"Læg hakket tomat og basilikum rundhåndet på sprødristet brød. Den lethed ved at tage det op med fingrene og bide en mundfuld åbner varmt en sammenkomsts første hilsen."},"ICON-2781":{"nm":"Mangosmoothie","de":"Blend en moden mango fint og bland den køligt med is. Når dråber perler på det gule glas, stiger en dorsk midsommereftermiddag helt op til sugerørets spids."},"ICON-2782":{"nm":"Lemonade","de":"Tilsæt friskpresset citron, sukker og koldt vand, og ryst det sammen i koppen. Når den gule syrlighed glider køligt ned gennem halsen, overgiver selv den rasende varme sig et øjeblik."},"ICON-2783":{"nm":"Jordbærmælk","de":"Rør moset jordbær ud i mælk, og en lyserød sky synker langsomt til bunds i glasset. Den barnlige spænding ved at flå køleskabsdøren op holdes hel og fuld i ét glas."},"ICON-2784":{"nm":"Bananemælk","de":"En drik, der allerede er en hel æras erindring blot i sin runde, krukkeformede skikkelse. Den gule erindring om at stikke et sugerør i på en bænk i badehuset vender varmt tilbage med hver slurk."},"ICON-2785":{"nm":"Blåbærmælk","de":"Put lilla bær i og knus dem, og den hvide mælk farves i en svag himmelblå tone. Den håndfuld lille frugt forvandler et helt glas til en helt ny farve."},"ICON-2786":{"nm":"Frugtjuice","de":"Pres flere frugter sammen, og det bliver en smag, intet enkelt navn kan indfange. En lille kor af sødmer, der blander sig og svulmer op, rigere sammen."},"ICON-2787":{"nm":"Kakao","de":"Ved et snedækket vindue omslutter du stille en varm krus med begge hænder. Et brunt krus med damp, der kruser sig opad, varmer dig langsomt, fra fingerspidserne til hjertet."},"ICON-2788":{"nm":"Kaffe","de":"Det er altid denne ene kop, der tænder lyset i øvelokalet ved daggry. Når den bitre duft stille skubber søvnigheden væk, begynder endnu en dags scene, stille, netop sådan."},"ICON-2789":{"nm":"Laksesushi","de":"Pres risen i hånden og afmål den sarte grænse mellem det faste og det bløde. I det øjeblik en tyndt skåret skive laks lægger sig blidt ovenpå, bliver én mundfuld fuldendelsen af en lille omhu."},"ICON-2790":{"nm":"Græskargrød","de":"Kog det gule græskar mørt, og mos det fint ned. Med hver skefuld smelter efterårssolen varmt i munden. Den grød, der først falder én ind, når man er syg."},"ICON-2791":{"nm":"Fiskekarry","de":"Fiskekød, let simret i krydderier, smuldrer mørt inde i karryen. Tilføj havets tekstur til en velkendt skål, og en almindelig aften begiver sig ud på en rejse en håndsbredde længere væk."},"ICON-2792":{"nm":"Friterede rejer","de":"Det korte øjeblik med at holde i halen, dyppe den i dej og lægge den i kogende olie, er hvor det afgøres. Rejer klædt i gyldent dej stråler klarest, spist før sprødheden når at køle af."},"ICON-2793":{"nm":"Friteret blæksprutte","de":"Runde ringe puster sig fyldige op i den varme olie. Den bid, hvor sprødhed omslutter sejhed, passer bedst under de gule lys ved en gadebod."},"ICON-2794":{"nm":"Grillet kylling","de":"Pensl med marinade og grill langsomt foran ilden, og skindet glinser af blank fedme. En ret, hvor smagen afgøres af blot én justering af ilden – den simpleste, og derfor så meget desto ærligere."},"ICON-2795":{"nm":"Svinekød stegt med kimchi","de":"Steg velmoden kimchi sammen med svinekød, og syrligheden modnes til sødme. En ret, der selv kalder på en skål hvid ris – den mest pålidelige makker ved et koreansk bord."},"ICON-2796":{"nm":"Stegt svinekød","de":"Steg hurtigt over høj varme, så ydersiden bliver sprødstegt. Når den fyldige olieduft fylder køkkenet, er aftenens menu allerede afgjort, uden flere spørgsmål."},"ICON-2797":{"nm":"Oksekød med stegte svampe","de":"Steg duftende svampe sammen med oksekød, og hver enkelt smag bliver dybere. Et ordentligt efterårsmåltid, hvor jord og mark stille tager hinanden i hånden på én tallerken."},"ICON-2798":{"nm":"Ostet dak-galbi","de":"Smelt rigeligt ost over stærk dak-galbi og træk det langt ud. Sid mange samlet omkring en varm jernplade, og selv den prikkende stærke smag opløses i latter."},"ICON-2799":{"nm":"Kimchigryde","de":"Jo ældre kimchien er, desto dybere og fyldigere bouillon giver den fra sig. Sæt jer ansigt til ansigt foran en boblende lergryde, og ordet »familie« varmes op igen."},"ICON-2800":{"nm":"Sojapastegryde","de":"Rør den duftende sojabønnepasta ud, tilsæt tofu og squash, og lad det simre roligt og jævnt. Den lyd, der bobler til allersidst i lergryden, er det sikreste tegn på, at du er kommet hjem."},"ICON-2801":{"nm":"Oksekød- og radisesuppe","de":"En halv dag brugt på stille at vente foran den lave flamme, indtil radisen bliver klar. Når en skefuld af den klare bouillon rører dine læber, mindes du datidens enkle bord uden pynt. Det stilfærdige er det, der bliver længst."},"ICON-2802":{"nm":"Muslingesuppe","de":"I det øjeblik muslingerne åbner sig, uddybes foråret inde i gryden. Når en håndfuld havduft stiger op med dampen, tegner der sig et billede af et daggrykøkken i en kystby. I hver åbnet skal samler der sig en salt smule af havet."},"ICON-2803":{"nm":"Kandiseret sødkartoffel","de":"På vej hjem fra skole, gule klumper der blev holdt i et papkrus som en håndvarmer. Bid i det gyldne ydre, og dampen stiger straks op indefra. Det sødt-karamelliserede skal og den varme kerne — vinterens mest ømme smag."},"ICON-2804":{"nm":"Stegt aubergine","de":"Det øjeblik hvor den violette farve møder olien og langsomt smelter hen. Grøntsagen man bebrejder for at være blød, tager i virkeligheden krydderiet bedre til sig end nogen anden. Tag én bid, og det bløde, gennemtrukne håndelag når dig først."},"ICON-2805":{"nm":"Sojasimrede kartofler","de":"En aften hvor en sød duft bredte sig gennem hele køkkenet, mens sojasovsen kogte ind. Hånden der fyldte et rum i madkassen med ét blankt, brunt stykke. En omhu der ikke står skrevet i nogen opskrift, gennemsyrer hvert lille stykke."},"ICON-2806":{"nm":"Syltede perillablade","de":"Arbejdet med at sylte hele sommerens duft og bære den med til vinterbordet. Løsn ét blad og læg det på risen, og den svundne årstid blomstrer op igen i munden. Mellem bladene, lagt lag på lag, sover det års solskin."},"ICON-2807":{"nm":"Frisk kinakålskimchi","de":"Hænder der ikke kunne vente til kimjang, ælter den sammen samme dag. Friskheden man kun kan nyde i det øjeblik, krydderiet lige er begyndt at trænge ind i de sprøde blade. Grønheden før gæringen er en luksus, der findes kun i dag."},"ICON-2808":{"nm":"Stegte svampe","de":"Ting der stille skød frem i skovens skygge, efter regnen klarede op. Mens de steges i perillaolie, forvandles jordduften til en sart, sprød aroma. Jo mere stille noget gror i mørket, desto dybere og rigere bliver dets duft."},"ICON-2809":{"nm":"Krydret spinat","de":"Bladgrønt der krymper til en lille håndfuld, når det skoldes, æltet sammen med fingerspidserne. Det beskedne volumen er forårsgrøntens dyd. Én grøn tallerken lukker en håndsbred mere forårssol ind ved bordet."},"ICON-2810":{"nm":"Krydret tang","de":"Glatte strimler lige trukket op af havet blandes med en syrlig chili-eddikedressing. En salt sprødhed springer ved hvert tyggetag. En ret der bærer bølgernes svajende konsistens lige ind i skålen."},"ICON-2811":{"nm":"Stegt courgette","de":"Der findes grøntsager, hvis sødme vokser, jo ældre de bliver. Skær den tyndt og steg den med saltede rejer, og selv den ellers uanselige courgette giver stille sin sødme til kende. En gul farve der smelter blødt hele vejen til det sidste i munden."},"ICON-2812":{"nm":"Stegt ris med kimchi","de":"Når den gamle kimchi er blevet dyb i smagen, møder den kold ris i én og samme pande. En skål der bliver mest mættende, når det, der er tilovers, forenes med det, der er tilovers. Den ømmeste redning under det sene nattelys i et etværelses lejlighed."},"ICON-2813":{"nm":"Kyllingecurry","de":"Når den gule sky dækker den hvide ris, lyser bordet op. Dengang krydderier var fremmede, var dette den første smag af den ydre verden, man blev fortrolig med. En søndagsfrokost hvor kyllingekødet smuldrede blødt og luftigt fra hinanden."},"ICON-2814":{"nm":"Stegt ris","de":"Resterne bagerst i køleskabet finder sammen i skøn forening i én pande. En gavmildhed der tager imod alt med åbne arme. At samle det spredte på ét sted — dér begynder det at holde hjem."},"ICON-2815":{"nm":"Bulgogi-risskål","de":"Kød marineret i en sød sovs glider blødt hen over den dampende ris. Når gæstebordets stjerneret synker ned i én hverdagsskål, bliver det særlige kun endnu ømmere."},"ICON-2816":{"nm":"Bibimbap","de":"Over løs, luftig ris sidder fem farverige namul i en rund kreds. I fingerspidserne der ordner farverne, strømmer en gammel sans for omhyggelig pleje. Harmoniens smag, der først fuldendes, når det hele røres sammen."},"ICON-2817":{"nm":"Stegt ris med rejer","de":"Buttede rejer træder frem i lyserødt mellem riskornene. Rør en håndfuld hav i, og selv et almindeligt måltid efterligner en fest. Sødmen der breder sig, i det øjeblik den knaser mellem tænderne, er altid kærkommen."},"ICON-2818":{"nm":"Krydret svinekød på ris","de":"Svinekød dybt gennemtrukket af krydret sovs møder den dampende ris. Skålen der først viste bunden ved frokosttid. Et måltids trøst der klapper og lindrer en travl dag."},"ICON-2819":{"nm":"Tun-mayo-ris","de":"Én dåse, en stribe mayonnaise og en skål varm ris. Ingredienserne er sparsomme, men trøsten er rigelig. Smagen af den aften, hvor man i smug rørte den sammen ved klasseværelsets bord efter selvstudiet."},"ICON-2820":{"nm":"Karryris","de":"En tyk, gylden farve fylder tallerkenen helt ud. Omhuen ved den lange omrøring, indtil kartofler og gulerødder bliver møre. Det bringer varmen fra den aften i tankerne, hvor hele familien kiggede ned i samme gryde."},"ICON-2821":{"nm":"Tang-bibimbap","de":"Havduftende strimler møder gochujang og røres rundt og rundt. Når den glatte, syrlige konsistens omslutter riskornene, folder havet, som en havdykker holdt vejret for at hente op, sig ud i én eneste skål."},"ICON-2822":{"nm":"Grillet makrel","de":"En sølvblank ryg steger gylden på grillen. Hånden der pillede benene fra og lagde kødet på risen. I ét stykke blårygget fisk gennemsyrer den stille kærlighed, der fodrede og opdrog."},"ICON-2823":{"nm":"Kartoffelpandekage","de":"Det man rev og stegte i et bjergkøkken i Gangwon på regnfulde dage. De sejge kanter og de sprøde ender lever side om side på én kage. Den dej der passer bedst til lyden af regn, der banker på ruden."},"ICON-2824":{"nm":"Kimchipandekage","de":"I det øjeblik den syrlige kimchi rammer den olierede pande, fyldes hele huset af en syde-lyd. En gylden rund der næsten af sig selv kalder på en skål makgeolli. En fast ret, der følges med lyden af regn under tagskægget."},"ICON-2825":{"nm":"Forårsløgspandekage","de":"Læg de spæde løg pænt ned, hæld dejen over og steg den langsomt. En kage der bevæger sig mellem det sprøde og det bløde. Nøjagtig som det kærlige syn af damp, der stiger fra en bod på markedsdagen."},"ICON-2826":{"nm":"Courgettepandekage","de":"Tyndt skåret courgette vendt i dej og stegt gylden. En lysegrøn cirkel der pænt holdt sit hjørne af offerbordet ved forfædrenes ritual. Den omhyggelige højtidelighed, der først falder på plads, når mange hænder har været om den."},"ICON-2827":{"nm":"Stegt blæksprutte","de":"Ben klædt i rød krydderi glimter og skinner blankt. Selv når sveden perler på panden af det stærke, kan spisepindene ikke standse. Den ene tallerken, hvor sved og glæde filtres sammen."},"ICON-2828":{"nm":"Tteokbokki","de":"Riskager og fiskekager synker dybt ned i en rød, indkogt gochujang-bouillon. Hele eftermiddagen fra snackbaren, hvor to delte for samlede mønter, ligger gemt deri. Erindringens smag, der får munden til at løbe i vand, blot man hører navnet."},"ICON-2829":{"nm":"Fiskekagesuppe","de":"En gadebod hvor fiskekager svajer i bouillonen, mens dampen dugger ruden hvid. Grib et spid, hæld lidt bouillon i et papkrus og drik det, og en kold vinternat bliver langt varmere."},"ICON-2830":{"nm":"Tofu med kimchi","de":"Ved siden af den bløde tofu sidder krydret stegt kimchi side om side. Koldt og varmt, mildt og stærkt smelter sammen på én tallerken. Et makkerpar der længe har vogtet over de voksnes nætter."},"ICON-2831":{"nm":"Stegte pølser med grønt","de":"Røde pølser og grøntsager syder sammen i en ketchup-farvet glans. Rummet der først blev tømt, da man åbnede madkassens låg til sportsdagen. Den dags farve forbliver altid lige klar, uanset hvor meget tid der går."},"ICON-2832":{"nm":"Sødkartoffellatte","de":"Findelt sødkartoffel opløses blødt i varm mælk. En hjemlig sødme skrevet med koreanske bogstaver på menutavlen. På en dag hvor fingerspidserne fryser, tag koppen med begge hænder, og varmen breder sig langsomt gennem den."},"ICON-2833":{"nm":"Mayonnaise","de":"En sovs der endnu ikke er nået frem til Glimmerøens køkken. Den bliver snart tegnet som et cremefarvet ikon. (under forberedelse)"}};